var t={1:{title:{en:"What is Psychology?",ka:"\u10E0\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0?",ru:"\u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F?",hy:"\u053B\u055E\u0576\u0579 \u0567 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:",az:"Psixologiya n\u0259dir?"},description:{en:"Introduction to the science of psychology, its history, and modern approaches.",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1, \u10DB\u10D8\u10E1\u10D8 \u10D8\u10E1\u10E2\u10DD\u10E0\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D7\u10D0\u10DC\u10D0\u10DB\u10D4\u10D3\u10E0\u10DD\u10D5\u10D4 \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10D5\u10D0\u10DA\u10D8.",ru:"\u0412\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0432 \u043D\u0430\u0443\u043A\u0443 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044E, \u0435\u0451 \u0438\u0441\u0442\u043E\u0440\u0438\u044E \u0438 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u044B.",hy:"\u0540\u0578\u10D2\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0561\u0576, \u0576\u0580\u0561 \u057A\u0561\u057F\u0574\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u056F\u056B\u0581 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u0576\u0565\u0580\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576:",az:"Psixologiya elmin\u0259, onun tarixin\u0259 v\u0259 m\xFCasir yana\u0448malar\u0131na giri\u015F."},keyTopics:{en:["Definition of Psychology","History of Psychology","Modern Perspectives","Research Methods"],ka:["\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10D0\u10E0\u10E2\u10D4\u10D1\u10D0","\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10D8\u10E1\u10E2\u10DD\u10E0\u10D8\u10D0","\u10D7\u10D0\u10DC\u10D0\u10DB\u10D4\u10D3\u10E0\u10DD\u10D5\u10D4 \u10DE\u10D4\u10E0\u10E1\u10DE\u10D4\u10E5\u10E2\u10D8\u10D5\u10D4\u10D1\u10D8","\u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10D4\u10D7\u10DD\u10D3\u10D4\u10D1\u10D8"],ru:["\u041E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438","\u0418\u0441\u0442\u043E\u0440\u0438\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438","\u0421\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u044B","\u041C\u0435\u0442\u043E\u0434\u044B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F"],hy:["\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057D\u0561\u0570\u0574\u0561\u0576\u0578\u0582\u0574\u0568","\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057A\u0561\u057F\u0574\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u053A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u056F\u056B\u0581 \u0570\u0565\u057C\u0561\u0576\u056F\u0561\u0580\u0576\u0565\u0580","\u0540\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0565\u0569\u0578\u0564\u0576\u0565\u0580"],az:["Psixologiyan\u0131n T\u0259rifi","Psixologiyan\u0131n Tarixi","M\xFCasir Perspektivl\u0259r","T\u0259dqiqat Metodlar\u0131"]},summary:{en:"Psychology is the scientific study of behavior and mental processes \u2014 examining how we think, feel, act, and interact with the world around us. The word derives from the Greek psyche (soul or mind) and logos (study), reflecting roots that stretch back to ancient philosophical debates about human nature. As a formal discipline, psychology began in 1879 when Wilhelm Wundt established the first psychology laboratory at the University of Leipzig, Germany, marking the shift from philosophical speculation to empirical investigation. William James soon founded the functionalist school in America with his landmark 1890 textbook, while Sigmund Freud developed psychoanalysis in Vienna, emphasizing the unconscious mind. Today, psychology encompasses six major theoretical perspectives: biological (genetics, brain chemistry, evolution), psychodynamic (unconscious motivations), behavioral (observable conditioning), cognitive (thinking, memory, problem-solving), humanistic (personal growth, free will), and sociocultural (cultural and social influences). The discipline pursues four primary goals \u2014 to describe, explain, predict, and influence behavior \u2014 and spans over 50 specialized subfields, making it one of the broadest and most versatile sciences.",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DB\u10D4\u10DC\u10E2\u10D0\u10DA\u10E3\u10E0\u10D8 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10E3\u10DA\u10D8 \u10E8\u10D4\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u2014 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10E4\u10D8\u10E5\u10E0\u10DD\u10D1\u10D7, \u10D5\u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D7, \u10D5\u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D7 \u10D3\u10D0 \u10D5\u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D7 \u10E1\u10D0\u10DB\u10E7\u10D0\u10E0\u10DD\u10E1\u10D7\u10D0\u10DC. \u10E1\u10D8\u10E2\u10E7\u10D5\u10D0 \u10DB\u10DD\u10DB\u10D3\u10D8\u10DC\u10D0\u10E0\u10D4\u10DD\u10D1\u10E1 \u10D1\u10D4\u10E0\u10EB\u10DC\u10E3\u10DA\u10D8\u10D3\u10D0\u10DC psyche (\u10E1\u10E3\u10DA\u10D8 \u10D0\u10DC \u10D2\u10DD\u10DC\u10D4\u10D1\u10D0) \u10D3\u10D0 logos (\u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0), \u10E0\u10D0\u10EA \u10D0\u10E1\u10D0\u10EE\u10D0\u10D5\u10E1 \u10E4\u10D4\u10E1\u10D5\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10DB\u10D8\u10D3\u10D8\u10E1 \u10E3\u10EB\u10D5\u10D4\u10DA\u10D4\u10E1\u10D8 \u10E4\u10D8\u10DA\u10DD\u10E1\u10DD\u10E4\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D4\u10D1\u10D0\u10E2\u10D4\u10D1\u10D8\u10E1\u10D9\u10D4\u10DC \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10E1 \u10D1\u10E3\u10DC\u10D4\u10D1\u10D0\u10D6\u10D4. \u10E0\u10DD\u10D2\u10DD\u10E0\u10EA \u10E4\u10DD\u10E0\u10DB\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D3\u10D8\u10E1\u10EA\u10D8\u10DE\u10DA\u10D8\u10DC\u10D0, \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10D3\u10D0\u10D8\u10EC\u10E7\u10DD 1879 \u10EC\u10D4\u10DA\u10E1, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10D5\u10D8\u10DA\u10F0\u10D4\u10DA\u10DB \u10D5\u10E3\u10DC\u10D3\u10E2\u10DB\u10D0 \u10D3\u10D0\u10D0\u10D0\u10E0\u10E1\u10D0 \u10DE\u10D8\u10E0\u10D5\u10D4\u10DA\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10DA\u10D0\u10D1\u10DD\u10E0\u10D0\u10E2\u10DD\u10E0\u10D8\u10D0 \u10DA\u10D0\u10D8\u10E4\u10EA\u10D8\u10D2\u10D8\u10E1 \u10E3\u10DC\u10D8\u10D5\u10D4\u10E0\u10E1\u10D8\u10E2\u10D4\u10E2\u10E8\u10D8, \u10D2\u10D4\u10E0\u10DB\u10D0\u10DC\u10D8\u10D0\u10E8\u10D8, \u10E0\u10D8\u10D7\u10D0\u10EA \u10D0\u10E6\u10D8\u10DC\u10D8\u10E8\u10DC\u10D0 \u10D2\u10D0\u10D3\u10D0\u10E1\u10D5\u10DA\u10D0 \u10E4\u10D8\u10DA\u10DD\u10E1\u10DD\u10E4\u10D8\u10E3\u10E0\u10D8 \u10E1\u10DE\u10D4\u10D9\u10E3\u10DA\u10D0\u10EA\u10D8\u10D8\u10D3\u10D0\u10DC \u10D4\u10DB\u10DE\u10D8\u10E0\u10D8\u10E3\u10DA \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10D6\u10D4. \u10E3\u10D8\u10DA\u10D8\u10D0\u10DB \u10EF\u10D4\u10D8\u10DB\u10E1\u10DB\u10D0 \u10DB\u10D0\u10DA\u10D4\u10D5\u10D4 \u10D3\u10D0\u10D0\u10D0\u10E0\u10E1\u10D0 \u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10DD\u10DC\u10D0\u10DA\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10E1\u10D9\u10DD\u10DA\u10D0 \u10D0\u10DB\u10D4\u10E0\u10D8\u10D9\u10D0\u10E8\u10D8 \u10D7\u10D0\u10D5\u10D8\u10E1\u10D8 1890 \u10EC\u10DA\u10D8\u10E1 \u10E1\u10D0\u10EE\u10D4\u10DA\u10DB\u10EB\u10E6\u10D5\u10D0\u10DC\u10D4\u10DA\u10DD\u10D7\u10D8, \u10EE\u10DD\u10DA\u10DD \u10D6\u10D8\u10D2\u10DB\u10E3\u10DC\u10D3 \u10E4\u10E0\u10DD\u10D8\u10D3\u10DB\u10D0 \u10D5\u10D4\u10DC\u10D0\u10E8\u10D8 \u10E8\u10D4\u10D8\u10DB\u10E3\u10E8\u10D0\u10D5\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10D6\u10D8, \u10EE\u10D0\u10D6\u10E1 \u10E3\u10E1\u10D5\u10D0\u10DB\u10D3\u10D0 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0 \u10D2\u10DD\u10DC\u10D4\u10D1\u10D0\u10E1. \u10D3\u10E6\u10D4\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D4\u10E5\u10D5\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D7\u10D4\u10DD\u10E0\u10D8\u10E3\u10DA \u10DE\u10D4\u10E0\u10E1\u10DE\u10D4\u10E5\u10E2\u10D8\u10D5\u10D0\u10E1: \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10E1, \u10E4\u10E1\u10D8\u10E5\u10DD\u10D3\u10D8\u10DC\u10D0\u10DB\u10D8\u10D9\u10E3\u10E0\u10E1, \u10D1\u10D8\u10F0\u10D4\u10D5\u10D8\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10E1, \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10E1, \u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10E1 \u10D3\u10D0 \u10E1\u10DD\u10EA\u10D8\u10DD\u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10E3\u10DA\u10E1. \u10D3\u10D8\u10E1\u10EA\u10D8\u10DE\u10DA\u10D8\u10DC\u10D0\u10E1 \u10D0\u10E5\u10D5\u10E1 \u10DD\u10D7\u10EE\u10D8 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10DB\u10D8\u10D6\u10D0\u10DC\u10D8 \u2014 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D0\u10E6\u10EC\u10D4\u10E0\u10D0, \u10D0\u10EE\u10E1\u10DC\u10D0, \u10EC\u10D8\u10DC\u10D0\u10E1\u10EC\u10D0\u10E0\u10DB\u10D4\u10E2\u10E7\u10D5\u10D4\u10DA\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0 \u2014 \u10D3\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 50-\u10D6\u10D4 \u10DB\u10D4\u10E2 \u10E1\u10DE\u10D4\u10EA\u10D8\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA \u10E5\u10D5\u10D4\u10E1\u10E4\u10D4\u10E0\u10DD\u10E1, \u10E0\u10D0\u10EA \u10DB\u10D0\u10E1 \u10D4\u10E0\u10D7-\u10D4\u10E0\u10D7 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10E4\u10D0\u10E0\u10D7\u10DD \u10D3\u10D0 \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10DB\u10EE\u10E0\u10D8\u10D5 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10D3 \u10D0\u10E5\u10EA\u10D4\u10D5\u10E1.",ru:"\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u2014 \u044D\u0442\u043E \u043D\u0430\u0443\u0447\u043D\u043E\u0435 \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0438 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432, \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435, \u043A\u0430\u043A \u043C\u044B \u0434\u0443\u043C\u0430\u0435\u043C, \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u043C, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u043C \u0438 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u043C \u0441 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u043C \u043C\u0438\u0440\u043E\u043C. \u0421\u043B\u043E\u0432\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u0433\u0440\u0435\u0447\u0435\u0441\u043A\u043E\u0433\u043E psyche (\u0434\u0443\u0448\u0430 \u0438\u043B\u0438 \u0440\u0430\u0437\u0443\u043C) \u0438 logos (\u0443\u0447\u0435\u043D\u0438\u0435), \u043E\u0442\u0440\u0430\u0436\u0430\u044F \u043A\u043E\u0440\u043D\u0438, \u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u043A \u0434\u0440\u0435\u0432\u043D\u0438\u043C \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u043C \u0441\u043F\u043E\u0440\u0430\u043C \u043E \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435. \u041A\u0430\u043A \u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u0430\u044F \u0434\u0438\u0441\u0446\u0438\u043F\u043B\u0438\u043D\u0430 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0437\u0430\u0440\u043E\u0434\u0438\u043B\u0430\u0441\u044C \u0432 1879 \u0433\u043E\u0434\u0443, \u043A\u043E\u0433\u0434\u0430 \u0412\u0438\u043B\u044C\u0433\u0435\u043B\u044C\u043C \u0412\u0443\u043D\u0434\u0442 \u043E\u0441\u043D\u043E\u0432\u0430\u043B \u043F\u0435\u0440\u0432\u0443\u044E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u044E \u0432 \u041B\u0435\u0439\u043F\u0446\u0438\u0433\u0441\u043A\u043E\u043C \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u0432 \u0413\u0435\u0440\u043C\u0430\u043D\u0438\u0438, \u0447\u0442\u043E \u043E\u0437\u043D\u0430\u043C\u0435\u043D\u043E\u0432\u0430\u043B\u043E \u043F\u0435\u0440\u0435\u0445\u043E\u0434 \u043E\u0442 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0445 \u0441\u043F\u0435\u043A\u0443\u043B\u044F\u0446\u0438\u0439 \u043A \u044D\u043C\u043F\u0438\u0440\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F\u043C. \u0423\u0438\u043B\u044C\u044F\u043C \u0414\u0436\u0435\u0439\u043C\u0441 \u0432\u0441\u043A\u043E\u0440\u0435 \u043E\u0441\u043D\u043E\u0432\u0430\u043B \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u0438\u0441\u0442\u0441\u043A\u0443\u044E \u0448\u043A\u043E\u043B\u0443 \u0432 \u0410\u043C\u0435\u0440\u0438\u043A\u0435 \u0441\u043E \u0441\u0432\u043E\u0438\u043C \u0443\u0447\u0435\u0431\u043D\u0438\u043A\u043E\u043C 1890 \u0433\u043E\u0434\u0430, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0417\u0438\u0433\u043C\u0443\u043D\u0434 \u0424\u0440\u0435\u0439\u0434 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043B \u043F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0437 \u0432 \u0412\u0435\u043D\u0435, \u0434\u0435\u043B\u0430\u044F \u0430\u043A\u0446\u0435\u043D\u0442 \u043D\u0430 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C. \u0421\u0435\u0433\u043E\u0434\u043D\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0448\u0435\u0441\u0442\u044C \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432: \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E, \u043F\u0441\u0438\u0445\u043E\u0434\u0438\u043D\u0430\u043C\u0438\u0447\u0435\u0441\u043A\u0443\u044E, \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0443\u044E, \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u0443\u044E, \u0433\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0438 \u0441\u043E\u0446\u0438\u043E\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u0443\u044E. \u0414\u0438\u0441\u0446\u0438\u043F\u043B\u0438\u043D\u0430 \u043F\u0440\u0435\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0447\u0435\u0442\u044B\u0440\u0435 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0446\u0435\u043B\u0438 \u2014 \u043E\u043F\u0438\u0441\u0430\u0442\u044C, \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C, \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0430\u0442\u044C \u0438 \u043F\u043E\u0432\u043B\u0438\u044F\u0442\u044C \u043D\u0430 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u2014 \u0438 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 50 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u043E\u0431\u043B\u0430\u0441\u0442\u0435\u0439, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0435\u0435 \u043E\u0434\u043D\u043E\u0439 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0448\u0438\u0440\u043E\u043A\u0438\u0445 \u0438 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0445 \u043D\u0430\u0443\u043A.",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0587 \u0574\u057F\u0561\u057E\u0578\u0580 \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u0576\u0565\u0580\u056B \u0563\u056B\u057F\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0567\u055D \u0584\u0576\u0576\u0565\u056C\u0578\u057E, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u0574\u057F\u0561\u056E\u0578\u0582\u0574, \u0566\u0563\u0578\u0582\u0574, \u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0587 \u0583\u0578\u056D\u0561\u0566\u0564\u0578\u0582\u0574 \u0574\u0565\u0566 \u0577\u0580\u057B\u0561\u057A\u0561\u057F\u0578\u0572 \u0561\u0577\u056D\u0561\u0580\u0570\u056B \u0570\u0565\u057F: \u0532\u0561\u057C\u0568 \u056E\u0561\u0563\u0578\u0582\u0574 \u0567 \u0570\u0578\u0582\u0576\u0561\u0580\u0565\u0576 psyche (\u0570\u0578\u0563\u056B \u056F\u0561\u0574 \u0574\u056B\u057F\u0584) \u0587 logos (\u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576) \u0562\u0561\u057C\u0565\u0580\u056B\u0581\u055D \u0561\u0580\u057F\u0561\u0581\u0578\u056C\u0565\u056C\u0578\u057E \u0561\u0580\u0574\u0561\u057F\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0570\u0561\u057D\u0576\u0578\u0582\u0574 \u0565\u0576 \u0574\u056B\u0576\u0579\u0587 \u0574\u0561\u0580\u0564\u056F\u0561\u0575\u056B\u0576 \u0562\u0576\u0578\u0582\u0575\u0569\u056B \u0574\u0561\u057D\u056B\u0576 \u0570\u0576\u0561\u0563\u0578\u0582\u0575\u0576 \u0583\u056B\u056C\u056B\u057D\u0578\u0583\u0561\u0575\u0561\u056F\u0561\u0576 \u0562\u0561\u0576\u0561\u057E\u0565\u0573\u0565\u0580\u0568: \u0548\u0580\u057A\u0565\u057D \u057A\u0561\u0577\u057F\u0578\u0576\u0561\u056F\u0561\u0576 \u0564\u056B\u057D\u0581\u056B\u057A\u056C\u056B\u0576, \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u057D\u056F\u056B\u0566\u0562 \u0567 \u0561\u057C\u0565\u056C 1879 \u0569\u057E\u0561\u056F\u0561\u0576\u056B\u0576, \u0565\u0580\u0562 \u054E\u056B\u056C\u0570\u0565\u056C\u0574 \u054E\u0578\u0582\u0576\u0564\u057F\u0568 \u0570\u056B\u0574\u0576\u0565\u0581 \u0561\u057C\u0561\u057B\u056B\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u056C\u0561\u0562\u0578\u0580\u0561\u057F\u0578\u0580\u056B\u0561\u0576 \u0533\u0565\u0580\u0574\u0561\u0576\u056B\u0561\u0575\u056B \u053C\u0561\u0575\u057A\u0581\u056B\u0563\u056B \u0570\u0561\u0574\u0561\u056C\u057D\u0561\u0580\u0561\u0576\u0578\u0582\u0574\u055D \u0576\u0577\u0561\u0576\u0561\u057E\u0578\u0580\u0565\u056C\u0578\u057E \u0561\u0576\u0581\u0578\u0582\u0574\u0568 \u0583\u056B\u056C\u056B\u057D\u0578\u0583\u0561\u0575\u0561\u056F\u0561\u0576 \u0565\u0576\u0569\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B\u0581 \u0564\u0565\u057A\u056B \u0567\u0574\u057A\u056B\u0580\u056B\u056F \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576: \u0548\u0582\u056B\u056C\u0575\u0561\u0574 \u054B\u0565\u0575\u0574\u057D\u0568 \u0577\u0578\u0582\u057F\u0578\u057E \u0570\u056B\u0574\u0576\u0565\u0581 \u0586\u0578\u0582\u0576\u056F\u0581\u056B\u0578\u0576\u0561\u056C\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u0564\u057A\u0580\u0578\u0581\u0568 \u0531\u0574\u0565\u0580\u056B\u056F\u0561\u0575\u0578\u0582\u0574 \u056B\u0580 1890 \u0569. \u0564\u0561\u057D\u0561\u0563\u0580\u0584\u0578\u057E, \u0574\u056B\u0576\u0579\u0564\u0565\u057C \u0536\u056B\u0563\u0574\u0578\u0582\u0576\u0564 \u0556\u0580\u0578\u0575\u0564\u0568 \u054E\u056B\u0565\u0576\u0576\u0561\u0575\u0578\u0582\u0574 \u0574\u0577\u0561\u056F\u0565\u0581 \u0570\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568\u055D \u0577\u0565\u0577\u057F\u0568 \u0564\u0576\u0565\u056C\u0578\u057E \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576\u056B \u057E\u0580\u0561: \u0531\u0575\u057D\u0585\u0580 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u057E\u0565\u0581 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0561\u056F\u0561\u0576 \u0570\u0565\u057C\u0561\u0576\u056F\u0561\u0580\u0576\u0565\u0580\u055D \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576, \u057A\u057D\u056B\u056D\u0578\u0564\u056B\u0576\u0561\u0574\u056B\u056F, \u057E\u0561\u0580\u0584\u0561\u0575\u056B\u0576, \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576, \u0570\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u0587 \u057D\u0578\u0581\u056B\u0578\u0574\u0577\u0561\u056F\u0578\u0582\u0569\u0561\u0575\u056B\u0576: \u0533\u056B\u057F\u0561\u056F\u0561\u0580\u0563\u0568 \u0570\u0565\u057F\u0561\u057A\u0576\u0564\u0578\u0582\u0574 \u0567 \u0579\u0578\u0580\u057D \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0576\u057A\u0561\u057F\u0561\u056F\u055D \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0565\u056C, \u0562\u0561\u0581\u0561\u057F\u0580\u0565\u056C, \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0565\u056C \u0587 \u0561\u0566\u0564\u0565\u056C \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u057E\u0580\u0561, \u0587 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0561\u057E\u0565\u056C\u056B \u0584\u0561\u0576 50 \u0574\u0561\u057D\u0576\u0561\u0563\u056B\u057F\u0561\u0581\u057E\u0561\u056E \u0565\u0576\u0569\u0561\u0578\u056C\u0578\u0580\u057F\u0576\u0565\u0580\u055D \u0564\u0561\u0580\u0571\u0576\u0565\u056C\u0578\u057E \u0561\u0575\u0576 \u0561\u0574\u0565\u0576\u0561\u056C\u0561\u0575\u0576 \u0587 \u0562\u0561\u0566\u0574\u0561\u056F\u0578\u0572\u0574\u0561\u0576\u056B \u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B\u0581 \u0574\u0565\u056F\u0568:",az:"Psixologiya davran\u0131\u015F v\u0259 zehni prosesl\u0259rin elmi \xF6yr\u0259nilm\u0259sidir - nec\u0259 d\xFC\u015F\xFCnd\xFCy\xFCm\xFCz\xFC, hiss etdiyimizi, h\u0259r\u0259k\u0259t etdiyimizi v\u0259 \u0259traf\u0131m\u0131zdak\u0131 d\xFCnya il\u0259 nec\u0259 qar\u015F\u0131l\u0131ql\u0131 \u0259laq\u0259d\u0259 oldu\u011Fumuzu ara\u015Fd\u0131r\u0131r. Bu s\xF6z yunan dilind\u0259ki psyche (ruh v\u0259 ya a\u011F\u0131l) v\u0259 logos (\xF6yr\u0259nm\u0259) s\xF6zl\u0259rind\u0259n g\xF6t\xFCr\xFClm\xFC\u015Fd\xFCr ki, bu da insan t\u0259bi\u0259ti haqq\u0131nda q\u0259dim f\u0259ls\u0259fi m\xFCzakir\u0259l\u0259r\u0259 gedib \xE7\u0131xan k\xF6kl\u0259ri \u0259ks etdirir. Formal bir intizam olaraq psixologiya 1879-cu ild\u0259 Wilhelm Wundt t\u0259r\u0259find\u0259n Almaniyan\u0131n Leypsiq Universitetind\u0259 ilk psixologiya laboratoriyas\u0131n\u0131n qurulmas\u0131 il\u0259 ba\u015Flam\u0131\u015F v\u0259 f\u0259ls\u0259fi f\u0259rziyy\u0259d\u0259n empirik t\u0259dqiqata ke\xE7idi qeyd etmi\u015Fdir. Uilyam Ceyms tezlikl\u0259 1890-c\u0131 ild\u0259 yazd\u0131\u011F\u0131 d\u0259rslikl\u0259 Amerikada funksionalist m\u0259kt\u0259bini qurdu, Ziqmund Freyd is\u0259 Vyanada \u015Fuursuz a\u011Fla diqq\u0259t yetir\u0259r\u0259k psixoanalizi inki\u015Faf etdirdi. Bu g\xFCn psixologiya alt\u0131 \u0259sas n\u0259z\u0259ri perspektivi \u0259hat\u0259 edir: bioloji, psixodinamik, davran\u0131\u015F, idrak, humanistik v\u0259 sosiom\u0259d\u0259ni. \u0130ntizam d\xF6rd \u0259sas m\u0259qs\u0259d g\xFCd\xFCr - davran\u0131\u015F\u0131 t\u0259svir etm\u0259k, izah etm\u0259k, proqnozla\u015Fd\u0131rmaq v\u0259 t\u0259sir etm\u0259k - v\u0259 50-d\u0259n \xE7ox ixtisasla\u015Fm\u0131\u015F alt sah\u0259ni \u0259hat\u0259 edir v\u0259 onu \u0259n geni\u015F v\u0259 \u0259n \xE7ox y\xF6nl\xFC elml\u0259rd\u0259n birin\u0259 \xE7evirir."},keyPoints:{en:['Psychology literally means "study of the soul" from the Greek words psyche (soul/mind) and logos (study/discourse). While ancient Greek philosophers like Aristotle debated the nature of the mind, psychology only emerged as a separate scientific discipline in the late 19th century.','Wilhelm Wundt established the first psychology laboratory in Leipzig, Germany in 1879, earning him the title "father of psychology." He used introspection \u2014 training subjects to systematically report their conscious experiences \u2014 as his primary research method.',`William James, the father of American psychology, developed functionalism, which asked how mental processes help organisms adapt to their environment. His 1890 textbook "The Principles of Psychology" became the field's most influential early work and introduced concepts still studied today.`,"Sigmund Freud developed psychoanalysis, arguing that unconscious desires, childhood experiences, and defense mechanisms shape personality and behavior. While many of his specific theories have been challenged, his emphasis on the unconscious mind transformed the field of psychology.","The six major perspectives in modern psychology: Biological (brain, genes, hormones, evolution), Psychodynamic (unconscious conflicts and early experiences), Behavioral (observable actions shaped by conditioning and reinforcement), Cognitive (mental processes like thinking, memory, and problem-solving), Humanistic (personal growth, free will, self-actualization), and Sociocultural (cultural, social, and environmental influences on behavior).","Psychology's four primary goals guide all research and practice: Describe (what is happening \u2014 identifying and classifying behavior), Explain (why it happens \u2014 understanding causes), Predict (when it will happen again \u2014 forecasting patterns), and Influence (how to change behavior \u2014 applying knowledge to improve lives).","The nature versus nurture debate has been central since psychology's beginnings. Today, most psychologists embrace an interactionist perspective, recognizing that behavior results from the complex interplay of genetic predispositions and environmental experiences, with each constantly influencing the other.","Modern psychology is remarkably diverse, with over 50 recognized subfields including clinical, developmental, social, cognitive, forensic, health, industrial-organizational, sport, educational, and neuropsychology \u2014 each applying the scientific method to different aspects of human experience and behavior."],ka:['\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10E1\u10D8\u10E2\u10E7\u10D5\u10D0\u10E1\u10D8\u10E2\u10E7\u10D5\u10D8\u10D7 \u10DC\u10D8\u10E8\u10DC\u10D0\u10D5\u10E1 "\u10E1\u10E3\u10DA\u10D8\u10E1 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0\u10E1" \u10D1\u10D4\u10E0\u10EB\u10DC\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E2\u10E7\u10D5\u10D4\u10D1\u10D8\u10D3\u10D0\u10DC psyche \u10D3\u10D0 logos. \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10E0\u10DD\u10D2\u10DD\u10E0\u10EA \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D2\u10D0\u10E9\u10DC\u10D3\u10D0 \u10DB\u10D4-19 \u10E1\u10D0\u10E3\u10D9\u10E3\u10DC\u10D8\u10E1 \u10D1\u10DD\u10DA\u10DD\u10E1.',"\u10D5\u10D8\u10DA\u10F0\u10D4\u10DA\u10DB \u10D5\u10E3\u10DC\u10D3\u10E2\u10DB\u10D0 \u10D3\u10D0\u10D0\u10D0\u10E0\u10E1\u10D0 \u10DE\u10D8\u10E0\u10D5\u10D4\u10DA\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10DA\u10D0\u10D1\u10DD\u10E0\u10D0\u10E2\u10DD\u10E0\u10D8\u10D0 1879 \u10EC\u10D4\u10DA\u10E1.","\u10E3\u10D8\u10DA\u10D8\u10D0\u10DB \u10EF\u10D4\u10D8\u10DB\u10E1\u10DB\u10D0 \u10D2\u10D0\u10DC\u10D0\u10D5\u10D8\u10D7\u10D0\u10E0\u10D0 \u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10DD\u10DC\u10D0\u10DA\u10D8\u10D6\u10DB\u10D8.","\u10D6\u10D8\u10D2\u10DB\u10E3\u10DC\u10D3 \u10E4\u10E0\u10DD\u10D8\u10D3\u10DB\u10D0 \u10E8\u10D4\u10E5\u10DB\u10DC\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10D6\u10D8, \u10E1\u10D0\u10D3\u10D0\u10EA \u10EE\u10D0\u10D6\u10D2\u10D0\u10E1\u10DB\u10E3\u10DA\u10D8\u10D0 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D1\u10D0\u10D5\u10E8\u10D5\u10DD\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10E0\u10DD\u10DA\u10D8.","\u10D4\u10E5\u10D5\u10E1\u10D8 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10DE\u10D4\u10E0\u10E1\u10DE\u10D4\u10E5\u10E2\u10D8\u10D5\u10D0 \u10D7\u10D0\u10DC\u10D0\u10DB\u10D4\u10D3\u10E0\u10DD\u10D5\u10D4 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10E8\u10D8: \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8, \u10E4\u10E1\u10D8\u10E5\u10DD\u10D3\u10D8\u10DC\u10D0\u10DB\u10D8\u10D9\u10E3\u10E0\u10D8, \u10D1\u10D8\u10F0\u10D4\u10D5\u10D8\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8, \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8, \u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10E1\u10DD\u10EA\u10D8\u10DD\u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10E3\u10DA\u10D8.","\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10DD\u10D7\u10EE\u10D8 \u10DB\u10D8\u10D6\u10D0\u10DC\u10D8\u10D0: \u10D0\u10E6\u10EC\u10D4\u10E0\u10D0, \u10D0\u10EE\u10E1\u10DC\u10D0, \u10EC\u10D8\u10DC\u10D0\u10E1\u10EC\u10D0\u10E0\u10DB\u10D4\u10E2\u10E7\u10D5\u10D4\u10DA\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D8\u10E1 \u10DB\u10DD\u10EE\u10D3\u10D4\u10DC\u10D0.","\u10D1\u10E3\u10DC\u10D4\u10D1\u10D0 \u10D0\u10E6\u10D6\u10E0\u10D3\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 \u10D3\u10D4\u10D1\u10D0\u10E2\u10D4\u10D1\u10E8\u10D8 \u10D3\u10E6\u10D4\u10E1 \u10EC\u10D0\u10DB\u10E7\u10D5\u10D0\u10DC\u10D8\u10D0 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D0\u10E5\u10EA\u10D8\u10DD\u10DC\u10D8\u10E1\u10E2\u10E3\u10DA\u10D8 \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D0.","\u10D7\u10D0\u10DC\u10D0\u10DB\u10D4\u10D3\u10E0\u10DD\u10D5\u10D4 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 50-\u10D6\u10D4 \u10DB\u10D4\u10E2 \u10E1\u10DE\u10D4\u10EA\u10D8\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA \u10E1\u10E4\u10D4\u10E0\u10DD\u10E1."],ru:["\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \xAB\u0443\u0447\u0435\u043D\u0438\u0435 \u043E \u0434\u0443\u0448\u0435\xBB. \u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0430 \u043A\u0430\u043A \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u0430\u044F \u043D\u0430\u0443\u0447\u043D\u0430\u044F \u0434\u0438\u0441\u0446\u0438\u043F\u043B\u0438\u043D\u0430 \u0432 \u043A\u043E\u043D\u0446\u0435 19 \u0432\u0435\u043A\u0430.","\u0412\u0438\u043B\u044C\u0433\u0435\u043B\u044C\u043C \u0412\u0443\u043D\u0434\u0442 \u043E\u0441\u043D\u043E\u0432\u0430\u043B \u043F\u0435\u0440\u0432\u0443\u044E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u044E \u0432 1879 \u0433\u043E\u0434\u0443.","\u0423\u0438\u043B\u044C\u044F\u043C \u0414\u0436\u0435\u0439\u043C\u0441 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043B \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u0438\u0437\u043C.","\u0417\u0438\u0433\u043C\u0443\u043D\u0434 \u0424\u0440\u0435\u0439\u0434 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043B \u043F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0437, \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044F, \u0447\u0442\u043E \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0442 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C.","\u0428\u0435\u0441\u0442\u044C \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u043F\u0435\u0440\u0441\u043F\u0435\u043A\u0442\u0438\u0432: \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F, \u043F\u0441\u0438\u0445\u043E\u0434\u0438\u043D\u0430\u043C\u0438\u0447\u0435\u0441\u043A\u0430\u044F, \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0430\u044F, \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u0430\u044F, \u0433\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0438 \u0441\u043E\u0446\u0438\u043E\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u0430\u044F.","\u0427\u0435\u0442\u044B\u0440\u0435 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0446\u0435\u043B\u0438 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438: \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435, \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435, \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u0438 \u0432\u043B\u0438\u044F\u043D\u0438\u0435 \u043D\u0430 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435.","\u0414\u0438\u0441\u043A\u0443\u0441\u0441\u0438\u044F \u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u0438 \u0432\u043E\u0441\u043F\u0438\u0442\u0430\u043D\u0438\u0438 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u0439.","\u0421\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 50 \u043F\u0440\u0438\u0437\u043D\u0430\u043D\u043D\u044B\u0445 \u043F\u043E\u0434\u043E\u0431\u043B\u0430\u0441\u0442\u0435\u0439."],hy:["\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0561\u057C\u0561\u0581\u056B\u0578\u0580\u0565\u0576 \u0576\u0577\u0561\u0576\u0561\u056F\u0578\u0582\u0574 \u0567 \xAB\u0570\u0578\u0563\u0578\u0582 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\xBB\u0589 \u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056B \u0570\u0561\u0575\u057F \u0565\u056F\u0561\u057E \u0578\u0580\u057A\u0565\u057D \u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 19-\u0580\u0564 \u0564\u0561\u0580\u056B \u057E\u0565\u0580\u057B\u056B\u0576:","\u054E\u056B\u056C\u0570\u0565\u056C\u0574 \u054E\u0578\u0582\u0576\u0564\u057F\u0568 \u0570\u056B\u0574\u0576\u0565\u0581 \u0561\u057C\u0561\u057B\u056B\u0576 \u056C\u0561\u0562\u0578\u0580\u0561\u057F\u0578\u0580\u056B\u0561\u0576 1879 \u0569\u057E\u0561\u056F\u0561\u0576\u056B\u0576:","\u0548\u0582\u056B\u056C\u0575\u0561\u0574 \u054B\u0565\u0575\u0574\u057D\u0568 \u0566\u0561\u0580\u0563\u0561\u0581\u0580\u0565\u0581 \u0586\u0578\u0582\u0576\u056F\u0581\u056B\u0578\u0576\u0561\u056C\u056B\u0566\u0574\u0568:","\u0536\u056B\u0563\u0574\u0578\u0582\u0576\u0564 \u0556\u0580\u0578\u0575\u0564\u0568 \u0574\u0577\u0561\u056F\u0565\u0581 \u0570\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:","\u053A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u056F\u056B\u0581 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0565\u0581 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0564\u056B\u057F\u0561\u0576\u056F\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568\u055D \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576, \u057A\u057D\u056B\u056D\u0578\u0564\u056B\u0576\u0561\u0574\u056B\u056F, \u057E\u0561\u0580\u0584\u0561\u0575\u056B\u0576, \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576, \u0570\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u0587 \u057D\u0578\u0581\u056B\u0578\u0574\u0577\u0561\u056F\u0578\u0582\u0569\u0561\u0575\u056B\u0576:","\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0579\u0578\u0580\u057D \u0576\u057A\u0561\u057F\u0561\u056F\u0576\u0565\u0580\u0568\u055D \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0565\u056C, \u0562\u0561\u0581\u0561\u057F\u0580\u0565\u056C, \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0565\u056C \u0587 \u0561\u0566\u0564\u0565\u056C:","\u0532\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0564\u0561\u057D\u057F\u056B\u0561\u0580\u0561\u056F\u0578\u0582\u0569\u0575\u0561\u0576 \u0562\u0561\u0576\u0561\u057E\u0565\u0573\u0578\u0582\u0574 \u0561\u0575\u057D\u0585\u0580 \u0568\u0576\u0564\u0578\u0582\u0576\u057E\u0561\u056E \u0567 \u0583\u0578\u056D\u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0568:","\u053A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u056F\u056B\u0581 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0577\u0561\u057F \u0562\u0561\u0566\u0574\u0561\u0566\u0561\u0576 \u0567\u055D \u0561\u057E\u0565\u056C\u056B \u0584\u0561\u0576 50 \u0565\u0576\u0569\u0561\u0578\u056C\u0578\u0580\u057F\u0576\u0565\u0580\u0578\u057E:"],az:['Psixologiya h\u0259rfi m\u0259nada "ruhun \xF6yr\u0259nilm\u0259si" dem\u0259kdir. Psixologiya yaln\u0131z 19-cu \u0259srin sonlar\u0131nda ayr\u0131 bir elm sah\u0259si olaraq ortaya \xE7\u0131xd\u0131.',"Wilhelm Wundt 1879-cu ild\u0259 ilk psixologiya laboratoriyas\u0131n\u0131 qurdu.","William James funksionalizmi inki\u015Faf etdirdi.","Ziqmund Freyd psixoanalizi inki\u015Faf etdir\u0259r\u0259k s\xFCursuz ist\u0259kl\u0259rin \u015F\u0259xsiyy\u0259ti formala\u015Fd\u0131rd\u0131\u011F\u0131n\u0131 m\xFCdafi\u0259 etdi.","M\xFCasir psixologiyada alt\u0131 \u0259sas perspektiv: Bioloji, Psixodinamik, Bihevioral, Koqnitiv, Humanistik v\u0259 Sosiom\u0259d\u0259ni.","Psixologiyan\u0131n d\xF6rd \u0259sas m\u0259qs\u0259di: T\u0259svir etm\u0259k, \u0130zah etm\u0259k, Proqnozla\u015Fd\u0131rmaq v\u0259 T\u0259sir etm\u0259k.","T\u0259bi\u0259t v\u0259 t\u0259rbiy\u0259 m\xFCbahis\u0259si m\u0259rk\u0259zi yer tutur.","M\xFCasir psixologiya 50-d\u0259n \xE7ox alt sah\u0259ni \u0259hat\u0259 edir."]},funFact:{en:"Wundts first lab experiment measured the time it took people to press a button after hearing a sound \u2014 about 0.1 seconds.",ka:"\u10D5\u10E3\u10DC\u10D3\u10E2\u10D8\u10E1 \u10DE\u10D8\u10E0\u10D5\u10D4\u10DA\u10D8 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D8 \u10D6\u10DD\u10DB\u10D0\u10D5\u10D3\u10D0 \u10D3\u10E0\u10DD\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10E1\u10ED\u10D8\u10E0\u10D3\u10D4\u10D1\u10DD\u10D3\u10D0\u10D7 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10E1 \u10E6\u10D8\u10DA\u10D0\u10D9\u10D6\u10D4 \u10D3\u10D0\u10E1\u10D0\u10ED\u10D4\u10E0\u10D0\u10D3 \u10EE\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D2\u10DD\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2 \u2014 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 0.1 \u10EC\u10D0\u10DB\u10D8.",ru:"\u041F\u0435\u0440\u0432\u044B\u0439 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442 \u0412\u0443\u043D\u0434\u0442\u0430 \u0438\u0437\u043C\u0435\u0440\u044F\u043B \u0432\u0440\u0435\u043C\u044F, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0443, \u0447\u0442\u043E\u0431\u044B \u043D\u0430\u0436\u0430\u0442\u044C \u043A\u043D\u043E\u043F\u043A\u0443 \u043F\u043E\u0441\u043B\u0435 \u0437\u0432\u0443\u043A\u0430 \u2014 \u043E\u043A\u043E\u043B\u043E 0,1 \u0441\u0435\u043A\u0443\u043D\u0434\u044B.",hy:"\u054E\u0578\u0582\u0576\u0564\u057F\u056B \u0561\u057C\u0561\u057B\u056B\u0576 \u056C\u0561\u0562\u0578\u0580\u0561\u057F\u0578\u0580 \u0583\u0578\u0580\u0571\u0568 \u0579\u0561\u0583\u0578\u0582\u0574 \u0567\u0580 \u0561\u0575\u0576 \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u0568, \u0578\u0580\u0568 \u057A\u0561\u0570\u10D0\u10DC\u057B\u057E\u0578\u0582\u0574 \u0567\u0580 \u10DB\u0561\u0580\u0564\u056F\u0561\u0576\u0581 \u0571\u0561\u0575\u0576\u0568 \u056C\u057D\u0565\u056C\u0578\u0582\u0581 \u0570\u0565\u057F\u10DD \u056F\u0578\u0573\u0561\u056F\u0568 \u057D\u0565\u0572\u0574\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580\u055D \u0574\u0578\u057F 0,1 \u057E\u0561\u0575\u0580\u056F\u0575\u0561\u0576:",az:"Vundtun ilk laboratoriya t\u0119cr\xFCb\u0119si bir s\u0119s e\u015Fitdikd\u0119n sonra d\xFCym\u0119ni basmaq \xFC\xE7\xFCn insanlar\u0131n s\u0119rf etdiyi vaxt\u0131 \xF6l\xE7\xFCrdi \u2014 t\u0119xmin\u0119n 0.1 saniy\u0119."},realWorld:{en:"Marketing teams use principles from cognitive and behavioral psychology to design ads that trigger emotional responses.",ka:"\u10DB\u10D0\u10E0\u10D9\u10D4\u10E2\u10D8\u10DC\u10D2\u10E3\u10DA\u10D8 \u10D2\u10E3\u10DC\u10D3\u10D4\u10D1\u10D8 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10D1\u10D8\u10F0\u10D4\u10D5\u10D8\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D4\u10D1\u10E1 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10E0\u10D4\u10D9\u10DA\u10D0\u10DB\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10E5\u10DB\u10DC\u10D4\u10DA\u10D0\u10D3.",ru:"\u041C\u0430\u0440\u043A\u0435\u0442\u043E\u043B\u043E\u0433\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E\u0439 \u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438 \u0434\u043B\u044F \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0440\u0435\u043A\u043B\u0430\u043C\u044B, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0435\u0439 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u043E\u0442\u043A\u043B\u0438\u043A.",hy:"\u0544\u0561\u0580\u0584\u0565\u0569\u056B\u0576\u0563\u0561\u0575\u056B\u0576 \u0569\u056B\u0574\u0565\u0580\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u056F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0587 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u0561\u0575\u056B\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568\u055D \u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0576\u0565\u0580 \u0561\u057C\u0561\u057B\u0561\u0581\u0576\u0578\u0572 \u10D2\u0578\u057E\u0561\u0566\u0564\u0576\u0565\u0580 \u057D\u057F\u0565\u0572\u056E\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580:",az:"Marketinq komandalar\u0131 emosional reaksiyalara s\u0119b\u0119b olan reklamlar haz\u0131rlamaq \xFC\xE7\xFCn koqnitiv v\u0119 bihevioral psixologiya prinsipl\u0119rind\u0119n istifad\u0119 edirl\u0119r."}},2:{title:{en:"Research Methods in Psychology",ka:"\u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10D4\u10D7\u10DD\u10D3\u10D4\u10D1\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10E8\u10D8",ru:"\u041C\u0435\u0442\u043E\u0434\u044B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0432 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438",hy:"\u0540\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0565\u0569\u0578\u0564\u0576\u0565\u0580\u0568 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0565\u057B",az:"Psixologiyada T\u0119dqiqat Metodlar\u0131"},description:{en:"How psychologists conduct research: experiments, observations, surveys, and ethics.",ka:"\u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E2\u10D0\u10E0\u10D4\u10D1\u10D4\u10DC \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D4\u10D1\u10D8 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E1: \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8, \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D0, \u10D2\u10D0\u10DB\u10DD\u10D9\u10D8\u10D7\u10EE\u10D5\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D4\u10D7\u10D8\u10D9\u10D0.",ru:"\u041A\u0430\u043A \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438 \u043F\u0440\u043E\u0432\u043E\u0434\u044F\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F: \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u044B, \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u044F, \u043E\u043F\u0440\u043E\u0441\u044B \u0438 \u044D\u0442\u0438\u043A\u0430.",hy:"\u053B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0576\u0565\u0580\u0568 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0561\u0576\u0581\u056F\u0561\u0581\u0576\u0578\u0582\u0574\u055D \u0583\u0578\u0580\u0571\u0565\u0580, \u0564\u056B\u057F\u0561\u0580\u056F\u0578\u0582\u0574\u0576\u0565\u0580, \u0570\u0561\u0580\u0581\u0578\u0582\u0574\u0576\u0565\u0580 \u0587 \u0567\u0569\u056B\u056F\u0561:",az:"Psixoloqlar\u0131n t\u0119dqiqat aparma \xFCsullar\u0131: eksperimentl\u0119r, m\xFCsahid\u0119l\u0119r, sor\u011Fular v\u0119 etika."},keyTopics:{en:["Scientific Method","Experimental Design","Correlation vs. Causation","Ethics in Research"],ka:["\u10E1\u10D0\u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10DD \u10DB\u10D4\u10D7\u10DD\u10D3\u10D8","\u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D3\u10D8\u10D6\u10D0\u10D8\u10DC\u10D8","\u10D9\u10DD\u10E0\u10D4\u10DA\u10D0\u10EA\u10D8\u10D0 vs \u10DB\u10D8\u10D6\u10D4\u10D6\u10DD\u10D1\u10E0\u10D8\u10DD\u10D1\u10D0","\u10D4\u10D7\u10D8\u10D9\u10D0 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E8\u10D8"],ru:["\u041D\u0430\u0443\u0447\u043D\u044B\u0439 \u043C\u0435\u0442\u043E\u0434","\u042D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0439 \u0434\u0438\u0437\u0430\u0439\u043D","\u041A\u043E\u0440\u0440\u0435\u043B\u044F\u0446\u0438\u044F \u0438 \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E-\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0432\u044F\u0437\u044C","\u042D\u0442\u0438\u043A\u0430 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439"],hy:["\u0533\u056B\u057F\u0561\u056F\u0561\u0576 \u0574\u0565\u0569\u0578\u0564","\u0553\u0578\u0580\u0571\u0561\u0580\u0561\u0580\u0561\u056F\u0561\u0576 \u0564\u056B\u0566\u0561\u0575\u0576","\u053F\u0578\u0580\u0565\u056C\u0561\u0581\u056B\u0561\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u057A\u0561\u057F\u0573\u0561\u057C\u0561\u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0561\u0575\u056B\u0576 \u056F\u0561\u057A\u056B","\u0537\u0569\u056B\u056F\u0561\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0565\u057B"],az:["Elmi Metod","Eksperimental Dizayn","Korrelyasiya v\u0119 S\u0119b\u0119b-N\u0119tic\u0119","T\u011Dqiqatda Etika"]},summary:{en:"This chapter explores the essential tools and methods psychologists use to study behavior scientifically. The scientific method \u2014 a systematic cycle of observation, hypothesis formation, experimentation, and data analysis \u2014 forms the backbone of all psychological research. Key research designs include experiments (which establish cause-and-effect by manipulating independent variables and measuring dependent variables), correlational studies (which reveal relationships but cannot prove causation), surveys, naturalistic observation, and case studies. Rigorous methodology requires control groups, random assignment, and double-blind procedures to eliminate bias. Equally important are the ethical guidelines governing research with human participants \u2014 including informed consent, the right to withdraw, debriefing after participation, and strict confidentiality \u2014 which were strengthened after controversial studies like Milgram's obedience experiments highlighted the need for stronger participant protections.",ka:"\u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D0\u10E3\u10EA\u10D8\u10DA\u10D4\u10D1\u10D4\u10DA \u10D8\u10DC\u10E1\u10E2\u10E0\u10E3\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10DB\u10D4\u10D7\u10DD\u10D3\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10E1\u10D0\u10EA \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D4\u10D1\u10D8 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10E3\u10DA\u10D0\u10D3 \u10E8\u10D4\u10E1\u10D0\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10D3. \u10E1\u10D0\u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10DD \u10DB\u10D4\u10D7\u10DD\u10D3\u10D8 \u10E5\u10DB\u10DC\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10EE\u10D4\u10E0\u10EE\u10D4\u10DB\u10D0\u10DA\u10E1. \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10D3\u10D8\u10D6\u10D0\u10D8\u10DC\u10D4\u10D1\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10E1, \u10D9\u10DD\u10E0\u10D4\u10DA\u10D0\u10EA\u10D8\u10E3\u10E0 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10E1, \u10D2\u10D0\u10DB\u10DD\u10D9\u10D8\u10D7\u10EE\u10D5\u10D4\u10D1\u10E1, \u10D1\u10E3\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5 \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10E8\u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D8\u10E1 \u10E8\u10D4\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10E1. \u10DB\u10D9\u10D0\u10EA\u10E0\u10D8 \u10DB\u10D4\u10D7\u10DD\u10D3\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10DB\u10DD\u10D8\u10D7\u10EE\u10DD\u10D5\u10E1 \u10E1\u10D0\u10D9\u10DD\u10DC\u10E2\u10E0\u10DD\u10DA\u10DD \u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10E1, \u10E8\u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D8\u10D7 \u10D2\u10D0\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10DD\u10E0\u10DB\u10D0\u10D2\u10D0\u10D3 \u10D1\u10E0\u10DB\u10D0 \u10DE\u10E0\u10DD\u10EA\u10D4\u10D3\u10E3\u10E0\u10D4\u10D1\u10E1.",ru:"\u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0438 \u043C\u0435\u0442\u043E\u0434\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u0434\u043B\u044F \u043D\u0430\u0443\u0447\u043D\u043E\u0433\u043E \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u044F \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F. \u041D\u0430\u0443\u0447\u043D\u044B\u0439 \u043C\u0435\u0442\u043E\u0434 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u043E\u0441\u043D\u043E\u0432\u0443 \u0432\u0441\u0435\u0445 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439. \u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043F\u043B\u0430\u043D\u044B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439 \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0442 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u044B, \u043A\u043E\u0440\u0440\u0435\u043B\u044F\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u043E\u043F\u0440\u043E\u0441\u044B, \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0435 \u0438 \u0442\u0435\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F. \u0421\u0442\u0440\u043E\u0433\u0430\u044F \u043C\u0435\u0442\u043E\u0434\u043E\u043B\u043E\u0433\u0438\u044F \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C\u043D\u044B\u0445 \u0433\u0440\u0443\u043F\u043F, \u0441\u043B\u0443\u0447\u0430\u0439\u043D\u043E\u0433\u043E \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0438 \u0434\u0432\u043E\u0439\u043D\u044B\u0445 \u0441\u043B\u0435\u043F\u044B\u0445 \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440.",hy:"\u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0567\u0561\u056F\u0561\u0576 \u0563\u0578\u0580\u056E\u056B\u0584\u0576\u0565\u0580\u0576 \u0578\u0582 \u0574\u0565\u0569\u0578\u0564\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0576\u0565\u0580\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u057E\u0561\u0580\u0584\u0568 \u0563\u056B\u057F\u0561\u056F\u0561\u0576\u0578\u0580\u0565\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580: \u0533\u056B\u057F\u0561\u056F\u0561\u0576 \u0574\u0565\u0569\u0578\u0564\u0568 \u056F\u0561\u0566\u0574\u0578\u0582\u0574 \u0567 \u0562\u0578\u056C\u0578\u0580 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0578\u0572\u0576\u0561\u0577\u0561\u0580\u0568: \u0540\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0561\u056F\u0561\u0576 \u0576\u0561\u056D\u0561\u0563\u056E\u0565\u0580\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0565\u0576 \u0583\u0578\u0580\u0571\u0561\u0580\u056F\u0578\u0582\u0574\u0576\u0565\u0580, \u056F\u0578\u0580\u0565\u056C\u0561\u0581\u056B\u0578\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580, \u0570\u0561\u0580\u0581\u0578\u0582\u0574\u0576\u0565\u0580, \u0562\u0576\u0561\u056F\u0561\u0576 \u0564\u056B\u057F\u0561\u0580\u056F\u0578\u0582\u0574 \u0587 \u0564\u0565\u057A\u0584\u0565\u0580\u056B \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576:",az:"Bu f\u0259sil psixoloqlar\u0131n davran\u0131\u015F\u0131 elmi c\u0259h\u0259td\u0259n \xF6yr\u0259nm\u0259k \xFC\xE7\xFCn istifad\u0259 etdikl\u0259ri \u0259sas al\u0259tl\u0259ri v\u0259 metodlar\u0131 ara\u015Fd\u0131r\u0131r. Elmi metod b\xFCt\xFCn psixoloji t\u0259dqiqatlar\u0131n onur\u011Fa s\xFCtununu t\u0259\u015Fkil edir. \u018Fsas t\u0259dqiqat dizaynlar\u0131na t\u0259cr\xFCb\u0259l\u0259r, korrelyasiya t\u0259dqiqatlar\u0131, sor\u011Fular, naturalist m\xFC\u015Fahid\u0259 v\u0259 hal t\u0259dqiqatlar\u0131 daxildir."},keyPoints:{en:["The scientific method is psychology's foundation: a systematic process of Observation (noticing a phenomenon), Hypothesis (forming a testable prediction), Experiment (testing under controlled conditions), Data Analysis (using statistics to interpret results), and Theory (building broader explanations). This cycle is repeated and refined over time.","In experiments, the independent variable is what the researcher manipulates, and the dependent variable is what is measured. The experimental group receives the treatment while the control group does not, allowing researchers to isolate cause and effect through direct comparison.","Correlation measures the relationship between two variables (ranging from -1.0 to +1.0), but correlation does NOT equal causation. A strong correlation between ice cream sales and drowning does not mean ice cream causes drowning \u2014 a third variable (hot weather) explains both.","Sampling and assignment are critical: random sampling (every person has an equal chance of being selected) ensures the sample represents the population, while random assignment (placing participants in groups by chance) controls for confounding variables in experiments.","Research methods beyond experiments: naturalistic observation (watching behavior in natural settings), surveys (questionnaires or interviews of large samples), case studies (in-depth investigation of one individual or group), and longitudinal studies (following the same participants over months or years to track change).","Double-blind procedures (neither participants nor researchers know who is in which group) eliminate both placebo effects and experimenter bias. Single-blind designs hide group assignment only from participants. These controls are essential for objective results.","Ethical guidelines protect research participants: informed consent (knowing what to expect), right to withdraw at any time, debriefing (explaining the true purpose afterward), confidentiality, and minimal risk. These principles were strengthened after controversial studies like Milgram's obedience experiments and Zimbardo's prison study."],ka:["\u10E1\u10D0\u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10DD \u10DB\u10D4\u10D7\u10DD\u10D3\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10E1\u10D0\u10E4\u10E3\u10EB\u10D5\u10D4\u10DA\u10D8\u10D0.","\u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10E8\u10D8, \u10D3\u10D0\u10DB\u10DD\u10E3\u10D9\u10D8\u10D3\u10D4\u10D1\u10D4\u10DA\u10D8 \u10EA\u10D5\u10DA\u10D0\u10D3\u10D8 \u10D0\u10E0\u10D8\u10E1 \u10D8\u10E1, \u10E0\u10D0\u10E1\u10D0\u10EA \u10DB\u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E0\u10D8 \u10EA\u10D5\u10DA\u10D8\u10E1.","\u10D9\u10DD\u10E0\u10D4\u10DA\u10D0\u10EA\u10D8\u10D0 \u10D6\u10DD\u10DB\u10D0\u10D5\u10E1 \u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10E1 \u10DD\u10E0 \u10EA\u10D5\u10DA\u10D0\u10D3\u10E1 \u10E8\u10DD\u10E0\u10D8\u10E1, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10D9\u10DD\u10E0\u10D4\u10DA\u10D0\u10EA\u10D8\u10D0 \u10D0\u10E0 \u10DC\u10D8\u10E8\u10DC\u10D0\u10D5\u10E1 \u10DB\u10D8\u10D6\u10D4\u10D6\u10DD\u10D1\u10E0\u10D8\u10DD\u10D1\u10D0\u10E1.","\u10E8\u10D4\u10E0\u10E9\u10D4\u10D5\u10D0 \u10D3\u10D0 \u10D2\u10D0\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D1\u10D0 \u10D9\u10E0\u10D8\u10E2\u10D8\u10D9\u10E3\u10DA\u10D8\u10D0 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10E8\u10D8.","\u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10D4\u10D7\u10DD\u10D3\u10D4\u10D1\u10D8 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10E6\u10DB\u10D0: \u10D1\u10E3\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5\u10D8 \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D0, \u10D2\u10D0\u10DB\u10DD\u10D9\u10D8\u10D7\u10EE\u10D5\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D0.\u10E8.","\u10DD\u10E0\u10DB\u10D0\u10D2\u10D0\u10D3 \u10D1\u10E0\u10DB\u10D0 \u10DE\u10E0\u10DD\u10EA\u10D4\u10D3\u10E3\u10E0\u10D4\u10D1\u10D8 \u10D0\u10E5\u10E0\u10DD\u10D1\u10E1 \u10DE\u10DA\u10D0\u10EA\u10D4\u10D1\u10DD\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E1.","\u10D4\u10D7\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D2\u10D0\u10D8\u10D3\u10DA\u10D0\u10D8\u10DC\u10D4\u10D1\u10D8 \u10D8\u10EA\u10D0\u10D5\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10DD\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D4\u10D1\u10E1."],ru:["\u041D\u0430\u0443\u0447\u043D\u044B\u0439 \u043C\u0435\u0442\u043E\u0434 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043E\u0439 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438.","\u0412 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0430\u0445 \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u0430\u044F \u043F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u2014 \u044D\u0442\u043E \u0442\u043E, \u0447\u0435\u043C \u043C\u0430\u043D\u0438\u043F\u0443\u043B\u0438\u0440\u0443\u0435\u0442 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C.","\u041A\u043E\u0440\u0440\u0435\u043B\u044F\u0446\u0438\u044F \u0438\u0437\u043C\u0435\u0440\u044F\u0435\u0442 \u0441\u0432\u044F\u0437\u044C \u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F \u043F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u043C\u0438, \u043D\u043E \u043D\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E-\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0441\u0432\u044F\u0437\u044C.","\u0412\u044B\u0431\u043E\u0440\u043A\u0430 \u0438 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0438\u043C\u0435\u044E\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0435\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.","\u041C\u0435\u0442\u043E\u0434\u044B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043E\u043C\u0438\u043C\u043E \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u043E\u0432: \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0435, \u043E\u043F\u0440\u043E\u0441\u044B \u0438 \u0434\u0440.","\u0414\u0432\u043E\u0439\u043D\u044B\u0435 \u0441\u043B\u0435\u043F\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440\u044B \u0443\u0441\u0442\u0440\u0430\u043D\u044F\u044E\u0442 \u044D\u0444\u0444\u0435\u043A\u0442 \u043F\u043B\u0430\u0446\u0435\u0431\u043E.","\u042D\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B \u0437\u0430\u0449\u0438\u0449\u0430\u044E\u0442 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u043E\u0432 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439."],hy:["\u0533\u056B\u057F\u0561\u056F\u0561\u0576 \u0574\u0565\u0569\u0578\u0564\u0568 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u056B\u0574\u0584\u0576 \u0567:","\u0553\u0578\u0580\u0571\u0565\u0580\u0578\u0582\u0574 \u0561\u0576\u056F\u0561\u056D \u0583\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576\u0568 \u0561\u0575\u0576 \u0567, \u056B\u0576\u0579 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0572\u0568 \u0574\u0561\u0576\u056B\u057A\u0578\u0582\u056C\u0575\u0561\u0581\u056B\u0561\u0575\u056B \u0567 \u0565\u0576\u0569\u0561\u0580\u056F\u0578\u0582\u0574:","\u053F\u0578\u0580\u0565\u056C\u0561\u0581\u056B\u0561\u0576 \u0579\u0561\u0583\u0578\u0582\u0574 \u0567 \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0562\u0561\u0575\u0581 \u0561\u0575\u0576 \u0579\u056B \u0576\u0577\u0561\u0576\u0561\u056F\u0578\u0582\u0574 \u057A\u0561\u057F\u0573\u0561\u057C\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576:","\u0546\u0574\u0578\u0582\u0577\u0561\u057C\u0578\u0582\u0574\u0568 \u0587 \u0576\u0577\u0561\u0576\u0561\u056F\u0578\u0582\u0574\u0568 \u056F\u0561\u0580\u0587\u0578\u0580 \u0565\u0576 \u0583\u0578\u0580\u0571\u0565\u0580\u0578\u0582\u0574:","\u0540\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0565\u0569\u0578\u0564\u0576\u0565\u0580\u0568 \u0583\u0578\u0580\u0571\u0565\u0580\u056B\u0581 \u0561\u0575\u0576 \u056F\u0578\u0572\u0574\u055D \u0562\u0576\u0561\u056F\u0561\u0576 \u0564\u056B\u057F\u0561\u0580\u056F\u0578\u0582\u0574, \u0570\u0561\u0580\u0581\u0578\u0582\u0574\u0576\u0565\u0580:","\u053F\u0580\u056F\u0576\u0561\u056F\u056B \u056F\u0578\u0582\u0575\u0580 \u0568\u0576\u0569\u0561\u0581\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u0568 \u057E\u0565\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u0565\u0576 \u057A\u056C\u0561\u0581\u0565\u0562\u0578\u0575\u056B \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:","\u0537\u0569\u056B\u056F\u0561\u056F\u0561\u0576 \u0578\u0582\u0572\u0565\u0581\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u0568 \u057A\u0561\u0577\u057F\u057A\u0561\u0576\u0578\u0582\u0574 \u0565\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0561\u057D\u0576\u0561\u056F\u056B\u0581\u0576\u0565\u0580\u056B\u0576:"],az:["Elmi metod psixologiyan\u0131n t\u0259m\u0259lidir.","T\u0259cr\xFCb\u0259l\u0259rd\u0259 m\xFCst\u0259qil d\u0259yi\u015F\u0259n t\u0259dqiqat\xE7\u0131n\u0131n manipulyasiya etdiyi \u015Feydir.","Korrelyasiya iki d\u0259yi\u015F\u0259n aras\u0131ndak\u0131 \u0259laq\u0259ni \xF6l\xE7\xFCr, lakin korrelyasiya s\u0259b\u0259biyy\u0259t dem\u0259k deyil.","Se\xE7m\u0259 v\u0259 t\u0259yinat t\u0259cr\xFCb\u0259l\u0259rd\u0259 kritikdir.","T\u0259cr\xFCb\u0259l\u0259rd\u0259n k\u0259nar t\u0259dqiqat \xFCsullar\u0131: naturalist m\xFC\u015Fahid\u0259, sor\u011Fular v\u0259 s.","\u0130kiqat kor prosedurlar plasebo effektini aradan qald\u0131r\u0131r.","Etik qaydalar t\u0259dqiqat i\u015Ftirak\xE7\u0131lar\u0131n\u0131 qoruyur."]},funFact:{en:"The placebo effect can reduce pain by up to 30% even if the pill contains only sugar.",ka:"\u10DE\u10DA\u10D0\u10EA\u10D4\u10D1\u10DD\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E1 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0 \u10E2\u10D9\u10D8\u10D5\u10D8\u10DA\u10D8\u10E1 30%-\u10DB\u10D3\u10D4 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0, \u10DB\u10D0\u10E8\u10D8\u10DC\u10D0\u10EA \u10D9\u10D8, \u10D7\u10E3 \u10D0\u10D1\u10D8 \u10DB\u10EE\u10DD\u10DA\u10DD\u10D3 \u10E8\u10D0\u10E5\u10D0\u10E0\u10E1 \u10E8\u10D4\u10D8\u10EA\u10D0\u10D5\u10E1.",ru:"\u042D\u0444\u0444\u0435\u043A\u0442 \u043F\u043B\u0430\u0446\u0435\u0431\u043E \u043C\u043E\u0436\u0435\u0442 \u0443\u043C\u0435\u043D\u044C\u0448\u0438\u0442\u044C \u0431\u043E\u043B\u044C \u043D\u0430 30%, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 \u0442\u0430\u0431\u043B\u0435\u0442\u043A\u0430 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0437 \u0441\u0430\u0445\u0430\u0440\u0430.",hy:"\u054A\u056C\u0561\u0581\u0565\u0562\u0578\u0575\u056B \u0567\u0586\u0565\u056F\u057F\u0568 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0565\u056C \u0581\u0561\u057E\u0568 \u0574\u056B\u0576\u0579\u0587 30%-\u0578\u057E, \u0576\u0578\u0582\u0575\u0576\u056B\u057D\u056F \u0565\u0569\u0565 \u0570\u0561\u0562\u0568 \u057A\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0578\u0582\u0574 \u0567 \u0574\u056B\u0561\u0575\u0576 \u0577\u0561\u0584\u0561\u0580:",az:"Plasebo effekti, h\u0119tta h\u0119b yaln\u0131z \u015F\u0119k\u0119rd\u0119n ibar\u0119t olsa bel\u0119, a\u011Fr\u0131lar\u0131 30%-\u0119 q\u0119d\u0119r azalda bil\u0119r."},realWorld:{en:"Double-blind trials protect patients from ineffective treatments by ensuring neither the doctor nor the patient knows who got the real medicine.",ka:"\u10DD\u10E0\u10DB\u10D0\u10D2\u10D8 \u10D1\u10E0\u10DB\u10D0 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10D8 \u10D8\u10EA\u10D0\u10D5\u10E1 \u10DE\u10D0\u10EA\u10D8\u10D4\u10DC\u10E2\u10D4\u10D1\u10E1 \u10D0\u10E0\u10D0\u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1\u10D2\u10D0\u10DC.",ru:"\u0414\u0432\u043E\u0439\u043D\u044B\u0435 \u0441\u043B\u0435\u043F\u044B\u0435 \u0438\u0441\u043F\u044B\u0442\u0430\u043D\u0438\u044F \u0437\u0430\u0449\u0438\u0449\u0430\u044E\u0442 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u043E\u0432 \u043E\u0442 \u043D\u0435\u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u043B\u0435\u0447\u0435\u043D\u0438\u044F.",hy:"\u053F\u0580\u056F\u0576\u0561\u056F\u056B \u056F\u0578\u0582\u0575\u0580 \u0583\u0578\u0580\u0571\u0561\u0580\u056F\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u057A\u0561\u0577\u057F\u057A\u0561\u0576\u0578\u0582\u0574 \u0565\u0576 \u057A\u0561\u0581\u056B\u0565\u0576\u057F\u0576\u0565\u0580\u056B\u0576 \u0578\u0579 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0562\u0578\u0582\u056A\u0578\u0582\u0574\u056B\u0581:",az:"Qo\u015Fa kor s\u0131naqlar n\u0119 h\u0119kimin, n\u0119 d\u0119 x\u0119st\u0119nin kimin \u0119sl d\u0119rman\u0131 ald\u0131\u011F\u0131n\u0131 bilm\u0119m\u0119sini t\u0119min ed\u0119r\u0119k x\u0119st\u0119l\u0119ri qeyri-effektiv m\xFCalic\u0119l\u0119rd\u0119n qoruyur."}},3:{title:{en:"Biological Bases of Behavior",ka:"\u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10E1\u10D0\u10E4\u10E3\u10EB\u10D5\u10DA\u10D4\u10D1\u10D8",ru:"\u0411\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043E\u0441\u043D\u043E\u0432\u044B \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F",hy:"\u054E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u056B\u0574\u0584\u0565\u0580\u0568",az:"Davran\u0131\u015F\u0131n Bioloji \u018Fsaslar\u0131"},description:{en:"The brain, nervous system, neurons, and how biology shapes our behavior.",ka:"\u10E2\u10D5\u10D8\u10DC\u10D8, \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0, \u10DC\u10D4\u10D8\u10E0\u10DD\u10DC\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10E1 \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10E9\u10D5\u10D4\u10DC\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1.",ru:"\u041C\u043E\u0437\u0433, \u043D\u0435\u0440\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430, \u043D\u0435\u0439\u0440\u043E\u043D\u044B \u0438 \u0442\u043E, \u043A\u0430\u043A \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u044F \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442 \u043D\u0430\u0448\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435.",hy:"\u0548\u0582\u0572\u0565\u0572\u0568, \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568, \u0576\u0565\u0575\u0580\u0578\u0576\u0576\u0565\u0580\u0568 \u0587 \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0574\u0565\u0580 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568:",az:"Beyin, sinir sistemi, neyronlar v\u0259 biologiya davran\u0131\u015F\u0131m\u0131z\u0131 nec\u0259 formala\u015Fd\u0131r\u0131r."},keyTopics:{en:["Neurons & Synapses","Brain Structure","Nervous System","Neurotransmitters","Genetics & Behavior"],ka:["\u10DC\u10D4\u10D8\u10E0\u10DD\u10DC\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10E1\u10D8\u10DC\u10D0\u10E4\u10E1\u10D4\u10D1\u10D8","\u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10E1\u10E2\u10E0\u10E3\u10E5\u10E2\u10E3\u10E0\u10D0","\u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0","\u10DC\u10D4\u10D8\u10E0\u10DD\u10E2\u10E0\u10D0\u10DC\u10E1\u10DB\u10D8\u10E2\u10D4\u10E0\u10D4\u10D1\u10D8","\u10D2\u10D4\u10DC\u10D4\u10E2\u10D8\u10D9\u10D0 \u10D3\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D0"],ru:["\u041D\u0435\u0439\u0440\u043E\u043D\u044B \u0438 \u0441\u0438\u043D\u0430\u043F\u0441\u044B","\u0421\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u043C\u043E\u0437\u0433\u0430","\u041D\u0435\u0440\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430","\u041D\u0435\u0439\u0440\u043E\u043C\u0435\u0434\u0438\u0430\u0442\u043E\u0440\u044B","\u0413\u0435\u043D\u0435\u0442\u0438\u043A\u0430 \u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435"],hy:["\u0546\u0565\u0575\u0580\u0578\u0576\u0576\u0565\u0580 \u0587 \u057D\u056B\u0576\u0561\u057A\u057D\u0576\u0565\u0580","\u0548\u0582\u0572\u0565\u0572\u056B \u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0568","\u0546\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563","\u0546\u0565\u0575\u0580\u0578\u0570\u0561\u0572\u0578\u0580\u0564\u056B\u0579\u0576\u0565\u0580","\u0533\u0565\u0576\u0565\u057F\u056B\u056F\u0561 \u0587 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E"],az:["Neyronlar v\u0259 Sinapslar","Beyin strukturu","Sinir sistemi","N\xF6rotransmitterl\u0259r","Genetika v\u0259 Davran\u0131\u015F"]},summary:{en:"Every thought, emotion, and action has a biological basis. This chapter explores the biological foundations of behavior, beginning with neurons \u2014 the fundamental building blocks of the nervous system \u2014 and how they communicate through electrochemical signals across synapses. It covers the structure of the central and peripheral nervous systems, examining the major brain regions and their specialized functions: the hindbrain (basic survival), midbrain (sensory relay), and forebrain (higher-order thinking). Key neurotransmitters such as dopamine, serotonin, GABA, and acetylcholine are explored alongside their roles in mood, movement, memory, and mental health. The chapter also examines the cerebral cortex and its four lobes (frontal, parietal, temporal, occipital), the limbic system's role in emotion and memory, the endocrine system's hormonal influences on behavior, and the remarkable phenomenon of neuroplasticity \u2014 the brain's ability to reorganize itself by forming new neural connections throughout life.",ka:"\u10E7\u10D5\u10D4\u10DA\u10D0 \u10D0\u10D6\u10E0\u10E1, \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0\u10E1 \u10D3\u10D0 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D0\u10E1 \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10E1\u10D0\u10E4\u10E3\u10EB\u10D5\u10D4\u10DA\u10D8 \u10D0\u10E5\u10D5\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0 \u10E1\u10D0\u10E4\u10E3\u10EB\u10D5\u10DA\u10D4\u10D1\u10E1, \u10D3\u10D0\u10EC\u10E7\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DC\u10D4\u10D8\u10E0\u10DD\u10DC\u10D4\u10D1\u10D8\u10D3\u10D0\u10DC \u10D3\u10D0 \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D4\u10DC \u10D8\u10E1\u10D8\u10DC\u10D8 \u10E1\u10D8\u10DC\u10D0\u10E4\u10E1\u10D4\u10D1\u10D8\u10E1 \u0DC4\u0DBB\u10E8\u10D4\u10DB\u10DD \u10D4\u10DA\u10D4\u10E5\u10E2\u10E0\u10DD\u10E5\u10D8\u10DB\u10D8\u10E3\u10E0\u10D8 \u10E1\u10D8\u10D2\u10DC\u10D0\u10DA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7. \u10D8\u10E1 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10DE\u10D4\u10E0\u10D8\u10E4\u10D4\u10E0\u10D8\u10E3\u10DA\u10D8 \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D4\u10D1\u10D8\u10E1 \u10E1\u10E2\u10E0\u10E3\u10E5\u10E2\u10E3\u10E0\u10D0\u10E1. \u10D2\u10D0\u10DC\u10EE\u10D8\u10DA\u10E3\u10DA\u10D8\u10D0 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10DC\u10D4\u10D8\u10E0\u10DD\u10E2\u10E0\u10D0\u10DC\u10E1\u10DB\u10D8\u10E2\u10D4\u10E0\u10D4\u10D1\u10D8, \u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10E5\u10D4\u10E0\u10E5\u10D8 \u10D3\u10D0 \u10DA\u10D8\u10DB\u10D1\u10E3\u10E0\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0.",ru:"\u041A\u0430\u0436\u0434\u0430\u044F \u043C\u044B\u0441\u043B\u044C, \u044D\u043C\u043E\u0446\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0438\u043C\u0435\u044E\u0442 \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043E\u0441\u043D\u043E\u0432\u0443. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0442\u0441\u044F \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043E\u0441\u043D\u043E\u0432\u044B \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043D\u0435\u0439\u0440\u043E\u043D\u043E\u0432 \u0438 \u0438\u0445 \u043E\u0431\u0449\u0435\u043D\u0438\u044F \u0447\u0435\u0440\u0435\u0437 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u0445\u0438\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u0438\u0433\u043D\u0430\u043B\u044B \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043D\u0430\u043F\u0441\u044B. \u041E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0443 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u0438 \u043F\u0435\u0440\u0438\u0444\u0435\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043D\u0435\u0440\u0432\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C. \u0420\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043D\u0435\u0439\u0440\u043E\u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0442\u0442\u0435\u0440\u044B, \u043A\u043E\u0440\u0430 \u0433\u043E\u043B\u043E\u0432\u043D\u043E\u0433\u043E \u043C\u043E\u0437\u0433\u0430 \u0438 \u043B\u0438\u043C\u0431\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430.",hy:"\u0545\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580 \u0574\u056B\u057F\u0584, \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584 \u0587 \u0563\u0578\u0580\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u056B \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u056B\u0574\u0584: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u057E\u0561\u0580\u0584\u056B \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u056B\u0574\u0584\u0565\u0580\u0568\u055D \u0576\u0565\u0575\u0580\u0578\u0576\u0576\u0565\u0580\u056B\u0581 \u057D\u056F\u057D\u0561\u056E, \u0587 \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0576\u0580\u0561\u0576\u0584 \u0570\u0561\u0572\u0578\u0580\u0564\u0561\u056F\u0581\u057E\u0578\u0582\u0574 \u0567\u056C\u0565\u056F\u057F\u0580\u0561\u0584\u056B\u0574\u056B\u0561\u056F\u0561\u0576 \u0561\u0566\u0564\u0561\u0576\u0577\u0561\u0576\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u0531\u0575\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u056F\u0561\u0576 \u0587 \u056E\u0561\u0575\u0580\u0561\u0574\u0561\u057D\u0561\u0575\u056B\u0576 \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u056B \u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0568:",az:"H\u0259r d\xFC\u015F\xFCnc\u0259, duy\u011Fu v\u0259 h\u0259r\u0259k\u0259tin bioloji \u0259sas\u0131 var. Bu f\u0259sil neyronlardan ba\u015Flayaraq davran\u0131\u015F\u0131n bioloji \u0259saslar\u0131n\u0131 v\u0259 onlar\u0131n sinapslar vasit\u0259sil\u0259 elektrokimy\u0259vi siqnallar vasit\u0259sil\u0259 nec\u0259 \u0259laq\u0259 qurdu\u011Funu ara\u015Fd\u0131r\u0131r. O, m\u0259rk\u0259zi v\u0259 periferik sinir sisteml\u0259rinin qurulu\u015Funu \u0259hat\u0259 edir."},keyPoints:{en:["Neurons are the basic building blocks of the nervous system, consisting of dendrites (receive signals), a cell body (processes information), an axon (transmits electrical impulses), and terminal buttons (release neurotransmitters). They communicate via electrochemical signals: action potentials travel down the axon, then chemical neurotransmitters cross the synaptic gap to the next neuron.","Key neurotransmitters and their functions: Dopamine (reward, motivation, movement), Serotonin (mood regulation, sleep, appetite), GABA (inhibition, calming neural activity), Glutamate (excitation, learning), Acetylcholine (memory, muscle contraction), Norepinephrine (alertness, fight-or-flight), and Endorphins (natural pain relief). Imbalances are linked to disorders like depression, Parkinson's, and schizophrenia.","The nervous system divides into the Central Nervous System (CNS \u2014 brain and spinal cord) and the Peripheral Nervous System (PNS \u2014 all other nerves). The PNS further splits into the somatic system (voluntary movement) and the autonomic system, which includes the sympathetic branch (fight-or-flight arousal) and parasympathetic branch (rest-and-digest calming).","The brain has three major regions: the Hindbrain (medulla \u2014 heartbeat and breathing; pons \u2014 sleep and arousal; cerebellum \u2014 coordination and balance), the Midbrain (relay station for sensory information), and the Forebrain (thalamus \u2014 sensory relay; hypothalamus \u2014 hunger, thirst, temperature; cerebral cortex \u2014 higher thinking and language).","The cerebral cortex has four specialized lobes: Frontal (executive functions, decision-making, personality, Broca's area for speech production), Parietal (touch, pressure, temperature, spatial awareness), Temporal (hearing, language comprehension via Wernicke's area, face recognition), and Occipital (visual processing).","The limbic system is crucial for emotion and memory: the amygdala processes fear and emotional memories, the hippocampus is essential for forming new long-term memories, and the hypothalamus regulates hunger, thirst, body temperature, and links the nervous system to the endocrine (hormonal) system.","Neuroplasticity is the brain's remarkable ability to reorganize itself by forming new neural connections throughout life, enabling recovery after injury and continuous learning. Roger Sperry's split-brain experiments demonstrated that the left hemisphere specializes in language and logic while the right hemisphere handles spatial tasks, creativity, and holistic processing."],ka:["\u10DC\u10D4\u10D8\u10E0\u10DD\u10DC\u10D4\u10D1\u10D8 \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D8\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10E1\u10D0\u10DB\u10E8\u10D4\u10DC\u10D4\u10D1\u10DA\u10DD \u10D1\u10DA\u10DD\u10D9\u10D4\u10D1\u10D8\u10D0.","\u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10DC\u10D4\u10D8\u10E0\u10DD\u10E2\u10E0\u10D0\u10DC\u10E1\u10DB\u10D8\u10E2\u10D4\u10E0\u10D4\u10D1\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D3\u10DD\u10E4\u10D0\u10DB\u10D8\u10DC\u10E1, \u10E1\u10D4\u10E0\u10DD\u10E2\u10DD\u10DC\u10D8\u10DC\u10E1 \u10D3\u10D0 \u10E1\u10EE\u10D5.","\u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0 \u10D8\u10E7\u10DD\u10E4\u10D0 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D0\u10DA\u10E3\u10E0 \u10D3\u10D0 \u10DE\u10D4\u10E0\u10D8\u10E4\u10D4\u10E0\u10D8\u10E3\u10DA \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D4\u10D1\u10D0\u10D3.","\u10E2\u10D5\u10D8\u10DC\u10E1 \u10D0\u10E5\u10D5\u10E1 \u10E1\u10D0\u10DB\u10D8 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10E0\u10D4\u10D2\u10D8\u10DD\u10DC\u10D8: \u10E3\u10D9\u10D0\u10DC\u10D0, \u10E8\u10E3\u10D0 \u10D3\u10D0 \u10EC\u10D8\u10DC\u10D0 \u10E2\u10D5\u10D8\u10DC\u10D8.","\u10D7\u10D0\u10D5\u10D8\u10E1 \u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10E5\u10D4\u10E0\u10E5\u10E1 \u10D0\u10E5\u10D5\u10E1 \u10DD\u10D7\u10EE\u10D8 \u10E1\u10DE\u10D4\u10EA\u10D8\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8 \u10EC\u10D8\u10DA\u10D8.","\u10DA\u10D8\u10DB\u10D1\u10E3\u10E0\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0 \u10D2\u10D0\u10D3\u10D0\u10DB\u10EC\u10E7\u10D5\u10D4\u10E2\u10D8\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1.","\u10DC\u10D4\u10D8\u10E0\u10DD\u10DE\u10DA\u10D0\u10E1\u10E2\u10D8\u10E3\u10E0\u10DD\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10D0\u10E6\u10E1\u10D0\u10DC\u10D8\u10E8\u10DC\u10D0\u10D5\u10D8 \u10E3\u10DC\u10D0\u10E0\u10D8 \u10E0\u10D4\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D0\u10EA\u10D8\u10D8\u10E1\u10D9\u10D4\u10DC."],ru:["\u041D\u0435\u0439\u0440\u043E\u043D\u044B \u2014 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0441\u0442\u0440\u043E\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0431\u043B\u043E\u043A\u0438 \u043D\u0435\u0440\u0432\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B.","\u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043D\u0435\u0439\u0440\u043E\u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0442\u0442\u0435\u0440\u044B \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0442 \u0434\u043E\u0444\u0430\u043C\u0438\u043D, \u0441\u0435\u0440\u043E\u0442\u043E\u043D\u0438\u043D \u0438 \u0434\u0440.","\u041D\u0435\u0440\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u0443\u044E \u0438 \u043F\u0435\u0440\u0438\u0444\u0435\u0440\u0438\u0447\u0435\u0441\u043A\u0443\u044E.","\u0412 \u043C\u043E\u0437\u0433\u0435 \u0432\u044B\u0434\u0435\u043B\u044F\u044E\u0442 \u0442\u0440\u0438 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u043E\u0442\u0434\u0435\u043B\u0430: \u0440\u043E\u043C\u0431\u044D\u043D\u0446\u0435\u0444\u0430\u043B\u043E\u043D, \u043C\u0435\u0437\u044D\u043D\u0446\u0435\u0444\u0430\u043B\u043E\u043D \u0438 \u043F\u0440\u043E\u0437\u044D\u043D\u0446\u0435\u0444\u0430\u043B\u043E\u043D.","\u041A\u043E\u0440\u0430 \u0433\u043E\u043B\u043E\u0432\u043D\u043E\u0433\u043E \u043C\u043E\u0437\u0433\u0430 \u0438\u043C\u0435\u0435\u0442 \u0447\u0435\u0442\u044B\u0440\u0435 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0434\u043E\u043B\u0438.","\u041B\u0438\u043C\u0431\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0438\u043C\u0435\u0435\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0435\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0434\u043B\u044F \u044D\u043C\u043E\u0446\u0438\u0439 \u0438 \u043F\u0430\u043C\u044F\u0442\u0438.","\u041D\u0435\u0439\u0440\u043E\u043F\u043B\u0430\u0441\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u2014 \u044D\u0442\u043E \u0437\u0430\u043C\u0435\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043C\u043E\u0437\u0433\u0430 \u0440\u0435\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C\u0441\u044F."],hy:["\u0546\u0565\u0575\u0580\u0578\u0576\u0576\u0565\u0580\u0568 \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u056B \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0561\u0575\u056B\u0576 \u0574\u056B\u0561\u057E\u0578\u0580\u0576\u0565\u0580\u0576 \u0565\u0576:","\u0540\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0576\u0565\u0575\u0580\u0578\u0570\u0561\u0572\u0578\u0580\u0564\u056B\u0579\u0576\u0565\u0580\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0565\u0576 \u0564\u0578\u0586\u0561\u0574\u056B\u0576, \u057D\u0565\u0580\u0578\u057F\u0578\u0576\u056B\u0576 \u0587 \u0561\u0575\u056C\u0576:","\u0546\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568 \u0562\u0561\u056A\u0561\u0576\u057E\u0578\u0582\u0574 \u0567 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u056F\u0561\u0576 \u0587 \u056E\u0561\u0575\u0580\u0561\u0574\u0561\u057D\u0561\u0575\u056B\u0576 \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u056B:","\u0548\u0582\u0572\u0565\u0572\u0576 \u0578\u0582\u0576\u056B \u0565\u0580\u0565\u0584 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0577\u0580\u057B\u0561\u0576\u055D \u0570\u0565\u057F\u056B\u0576 \u0578\u0582\u0572\u0565\u0572, \u0574\u056B\u057B\u056B\u0576 \u0578\u0582\u0572\u0565\u0572 \u0587 \u0561\u057C\u057B\u0587\u056B \u0578\u0582\u0572\u0565\u0572:","\u0548\u0582\u0572\u0565\u0572\u056B \u056F\u0565\u0572\u0587\u0576 \u0578\u0582\u0576\u056B \u0579\u0578\u0580\u057D \u0574\u0561\u057D\u0576\u0561\u0563\u056B\u057F\u0561\u0581\u057E\u0561\u056E \u0562\u056C\u0569\u0565\u0580:","\u053C\u056B\u0574\u0562\u056B\u0561\u056F\u0561\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568 \u057E\u0573\u057C\u0578\u0580\u0578\u0577 \u0567 \u0570\u0578\u0582\u0575\u0566\u0565\u0580\u056B \u0587 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u0580:","\u0546\u0565\u0575\u0580\u0578\u057A\u056C\u0561\u057D\u057F\u056B\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0578\u0582\u0572\u0565\u0572\u056B \u056B\u0576\u0584\u0576\u0561\u057E\u0565\u0580\u0561\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u057E\u0565\u056C\u0578\u0582 \u0578\u0582\u0577\u0561\u0563\u0580\u0561\u057E \u0578\u0582\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0567:"],az:["Neyronlar sinir sisteminin \u0259sas tikinti bloklar\u0131d\u0131r.","\u018Fsas n\xF6rotransmitterl\u0259r\u0259 dopamin, serotonin v\u0259 s. daxildir.","Sinir sistemi M\u0259rk\u0259zi v\u0259 Periferik sinir sistemin\u0259 b\xF6l\xFCn\xFCr.","Beynin \xFC\xE7 \u0259sas b\xF6lg\u0259si var: Arxa beyin, Orta beyin v\u0259 \xD6n beyin.","Serebral korteksin d\xF6rd ixtisasla\u015Fm\u0131\u015F lobu var.","Limbik sistem emosiya v\u0259 yadda\u015F \xFC\xE7\xFCn \xE7ox vacibdir.","N\xF6roplastiklik beynin \xF6z\xFCn\xFC yenid\u0259n t\u0259\u015Fkil etm\u0259k \xFC\xE7\xFCn diqq\u0259t\u0259layiq qabiliyy\u0259tidir."]},funFact:{en:"",ka:"\u10DB\u10D8\u10E3\u10EE\u10D4\u10D3\u10D0\u10D5\u10D0\u10D3 \u10D8\u10DB\u10D8\u10E1\u10D0, \u10E0\u10DD\u10DB \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10E1 \u10E2\u10D5\u10D8\u10DC\u10D8 \u10E1\u10EE\u10D4\u10E3\u10DA\u10D8\u10E1 \u10EC\u10DD\u10DC\u10D8\u10E1 \u10DB\u10EE\u10DD\u10DA\u10DD\u10D3 2%-\u10E1 \u10E8\u10D4\u10D0\u10D3\u10D2\u10D4\u10DC\u10E1, \u10D8\u10E1 \u10DB\u10DD\u10D8\u10EE\u10DB\u10D0\u10E0\u10E1 \u10E1\u10EE\u10D4\u10E3\u10DA\u10D8\u10E1 \u10D4\u10DC\u10D4\u10E0\u10D2\u10D8\u10D8\u10E1 20%-\u10E1.",ru:"\u0425\u043E\u0442\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0438\u0439 \u043C\u043E\u0437\u0433 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0432\u0441\u0435\u0433\u043E 2% \u0432\u0435\u0441\u0430 \u0442\u0435\u043B\u0430, \u043E\u043D \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u044F\u0435\u0442 20% \u0432\u0441\u0435\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C\u0430.",hy:"\u0539\u0565\u0587 \u0574\u0561\u0580\u0564\u0578\u0582 \u0578\u0582\u0572\u0565\u0572\u0568 \u056F\u0561\u0566\u0574\u0578\u0582\u0574 \u0567 \u0574\u0561\u0580\u0574\u0576\u056B \u0584\u0561\u0577\u056B \u0568\u0576\u0564\u0561\u0574\u0565\u0576\u0568 2%-\u0568, \u0561\u0575\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0567 \u0574\u0561\u0580\u0574\u0576\u056B \u0567\u0576\u0565\u0580\u0563\u056B\u0561\u0575\u056B 20%-\u0568:",az:"\u0130nsan beyni b\u0259d\u0259n \xE7\u0259kisinin yaln\u0131z 2%-ni t\u0259\u015Fkil ets\u0259 d\u0259, b\u0259d\u0259nin enerjisinin 20%-ni istifad\u0259 edir."},realWorld:{en:"Understanding neurotransmitters revolutionized psychiatry. SSRIs (like Prozac) treat depression by increasing serotonin levels in the brain. Parkinson's disease treatments target dopamine pathways.",ka:"\u10DC\u10D4\u10D8\u10E0\u10DD\u10DE\u10DA\u10D0\u10E1\u10E2\u10D8\u10E3\u10E0\u10DD\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DC\u10EA\u10D4\u10E4\u10EA\u10D8\u10D0 \u10D2\u10D0\u10D3\u10D0\u10DB\u10EC\u10E7\u10D5\u10D4\u10E2 \u10E0\u10DD\u10DA\u10E1 \u10D7\u10D0\u10DB\u10D0\u10E8\u10DD\u10D1\u10E1 \u10D8\u10DC\u10E1\u10E3\u10DA\u10E2\u10D8\u10E1 \u10DB\u10E5\u10DD\u10DC\u10D4 \u10DE\u10D0\u10EA\u10D8\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8\u10E1 \u10E0\u10D4\u10D0\u10D1\u10D8\u10DA\u10D8\u10E2\u10D0\u10EA\u10D8\u10D8\u10E1 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10E8\u10D8.",ru:"\u041A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F \u043D\u0435\u0439\u0440\u043E\u043F\u043B\u0430\u0441\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u0438\u0433\u0440\u0430\u0435\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0443\u044E \u0440\u043E\u043B\u044C \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0440\u0435\u0430\u0431\u0438\u043B\u0438\u0442\u0430\u0446\u0438\u0438 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u043E\u0432 \u043F\u043E\u0441\u043B\u0435 \u0438\u043D\u0441\u0443\u043B\u044C\u0442\u0430.",hy:"\u0546\u0565\u0575\u0580\u0578\u057A\u056C\u0561\u057D\u057F\u056B\u056F\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0575\u0565\u0581\u0561\u056F\u0561\u0580\u0563\u0568 \u057E\u0573\u057C\u0578\u0580\u0578\u0577 \u0564\u0565\u0580 \u0567 \u056D\u0561\u0572\u0578\u0582\u0574 \u056B\u0576\u057D\u10E3\u10DA\u057F \u057D\u057F\u0561\u0581\u0561\u056E \u0570\u056B\u057E\u0561\u0576\u0564\u0576\u0565\u0580\u056B \u057E\u0565\u0580\u0561\u056F\u0561\u0576\u10D2\u10DC\u0574\u0561\u0576 \u10D2\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u0578\u0582\u0574:",az:"Neyroplastiklik anlay\u0131\u015F\u0131 insult ke\xE7irmi\u015F pasiyentl\u0259rin b\u0259rpa prosesind\u0259 m\xFCh\xFCm rol oynay\u0131r."}},4:{title:{en:"Sensation and Perception",ka:"\u10E8\u10D4\u10D2\u10E0\u10EB\u10DC\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D0\u10E6\u10E5\u10DB\u10D0",ru:"\u041E\u0449\u0443\u0449\u0435\u043D\u0438\u0435 \u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435",hy:"\u054D\u0565\u0576\u057D\u0561\u0581\u056B\u0561 \u0587 \u0568\u0576\u056F\u0561\u056C\u0578\u0582\u0574",az:"Duy\u011Fu v\u0259 Qavray\u0131\u015F"},description:{en:"How our senses detect stimuli and our brain interprets them.",ka:"\u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10DB\u10DD\u10D8\u10EA\u10DC\u10DD\u10D1\u10E1 \u10E9\u10D5\u10D4\u10DC\u10D8 \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10E1 \u10D3\u10D0 \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E2\u10D5\u10D8\u10DC\u10D8 \u10D2\u10D0\u10DC\u10DB\u10D0\u10E0\u10E2\u10D0\u10D5\u10E1 \u10DB\u10D0\u10D7.",ru:"\u041A\u0430\u043A \u043D\u0430\u0448\u0438 \u043E\u0440\u0433\u0430\u043D\u044B \u0447\u0443\u0432\u0441\u0442\u0432 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u044E\u0442 \u0441\u0442\u0438\u043C\u0443\u043B\u044B, \u0430 \u043C\u043E\u0437\u0433 \u0438\u0445 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442.",hy:"\u053B\u0576\u0579\u057A\u0565\u057D \u0567 \u0574\u0565\u0580 \u0566\u0563\u0561\u0575\u0561\u0580\u0561\u0576\u0576\u0565\u0580\u0568 \u0570\u0561\u0575\u057F\u0576\u0561\u0562\u0565\u0580\u0578\u0582\u0574 \u0563\u0580\u0563\u057C\u056B\u0579\u0576\u0565\u0580\u0568 \u0587 \u0574\u0565\u0580 \u0578\u0582\u0572\u0565\u0572\u0568 \u0574\u0565\u056F\u0576\u0561\u0562\u0561\u0576\u0578\u0582\u0574 \u0564\u0580\u0561\u0576\u0584:",az:"D\xFCnyan\u0131 nec\u0259 hiss etdiyimiz v\u0259 duy\u011Fusal m\u0259lumatlar\u0131 nec\u0259 \u015F\u0259rh etdiyimiz."},keyTopics:{en:["Vision","Hearing","Other Senses","Perceptual Organization","Illusions"],ka:["\u10EE\u10D4\u10D3\u10D5\u10D0","\u10E1\u10DB\u10D4\u10DC\u10D0","\u10E1\u10EE\u10D5\u10D0 \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8","\u10D0\u10E6\u10E5\u10DB\u10D8\u10E1 \u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0","\u10D8\u10DA\u10E3\u10D6\u10D8\u10D4\u10D1\u10D8"],ru:["\u0417\u0440\u0435\u043D\u0438\u0435","\u0421\u043B\u0443\u0445","\u0414\u0440\u0443\u0433\u0438\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430","\u041F\u0435\u0440\u0446\u0435\u043F\u0442\u0438\u0432\u043D\u0430\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044F","\u0418\u043B\u043B\u044E\u0437\u0438\u0438"],hy:["\u054F\u0565\u057D\u056B\u056C\u0584","\u053C\u057D\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0531\u0575\u056C \u0566\u0563\u0561\u0575\u0561\u0580\u0561\u0576\u0576\u0565\u0580","\u0538\u0576\u056F\u0561\u056C\u0574\u0561\u0576 \u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u054A\u0561\u057F\u0580\u0561\u0576\u0584\u0576\u0565\u0580"],az:["Sensor Sisteml\u0259r","E\u015Fikl\u0259m\u0259l\u0259r","Qavray\u0131\u015F\u0131n T\u0259\u015Fkili","\u0130ll\xFCziyalar"]},summary:{en:"Sensation is the process by which our sensory receptors detect physical energy from the environment, while perception is how the brain organizes and interprets that sensory information into meaningful experience. This chapter examines how our visual, auditory, gustatory, olfactory, and somatosensory systems transform raw stimuli into neural signals through transduction. It covers foundational concepts like absolute and difference thresholds, signal detection theory, and sensory adaptation. The chapter explores the visual system in detail \u2014 from the cornea and retina to the visual cortex \u2014 as well as auditory processing from the ear canal to the auditory cortex. Gestalt principles of perceptual organization (proximity, similarity, closure, continuity) explain how the brain groups sensory elements into coherent wholes, while depth perception, perceptual constancies, and optical illusions reveal the constructive nature of perception and the sometimes surprising ways our brain interprets reality.",ka:"\u10E8\u10D4\u10D2\u10E0\u10EB\u10DC\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D8, \u10E0\u10DD\u10DB\u10DA\u10D8\u10E1 \u10D3\u10E0\u10DD\u10E1\u10D0\u10EA \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA\u10D8 \u10E0\u10D4\u10EA\u10D4\u10DE\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8 \u10D0\u10DB\u10DD\u10D8\u10EA\u10DC\u10DD\u10D1\u10D4\u10DC \u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0 \u10D4\u10DC\u10D4\u10E0\u10D2\u10D8\u10D0\u10E1 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10D3\u10D0\u10DC, \u10EE\u10DD\u10DA\u10DD \u10D0\u10E6\u10E5\u10DB\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10D8\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10EC\u10E7\u10DD\u10D1\u10E1 \u10D3\u10D0 \u10D2\u10D0\u10DC\u10DB\u10D0\u10E0\u10E2\u10D0\u10D5\u10E1 \u10E2\u10D5\u10D8\u10DC\u10D8 \u10D0\u10DB \u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D0\u10D3. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D2\u10D0\u10E0\u10D3\u10D0\u10E5\u10DB\u10DC\u10D8\u10D0\u10DC \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D4\u10D1\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D4\u10D1\u10E1 \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA \u10E1\u10D8\u10D2\u10DC\u10D0\u10DA\u10D4\u10D1\u10D0\u10D3.",ru:"\u041E\u0449\u0443\u0449\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441, \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043D\u0430\u0448\u0438 \u0441\u0435\u043D\u0441\u043E\u0440\u043D\u044B\u0435 \u0440\u0435\u0446\u0435\u043F\u0442\u043E\u0440\u044B \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u044E\u0442 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044B, \u0442\u043E\u0433\u0434\u0430 \u043A\u0430\u043A \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u2014 \u044D\u0442\u043E \u0442\u043E, \u043A\u0430\u043A \u043C\u043E\u0437\u0433 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0443\u0435\u0442 \u0438 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442 \u044D\u0442\u0443 \u0441\u0435\u043D\u0441\u043E\u0440\u043D\u0443\u044E \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E \u0432 \u043E\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u043D\u044B\u0439 \u043E\u043F\u044B\u0442. \u042D\u0442\u0430 \u0433\u043B\u0430\u0432\u0430 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442, \u043A\u0430\u043A \u043D\u0430\u0448\u0438 \u0441\u0435\u043D\u0441\u043E\u0440\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u044E\u0442 \u0441\u0442\u0438\u043C\u0443\u043B\u044B \u0432 \u043D\u0435\u0439\u0440\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0433\u043D\u0430\u043B\u044B.",hy:"\u0536\u0563\u0561\u0575\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0561\u0575\u0576 \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u0576 \u0567, \u0578\u0580\u0578\u057E \u0574\u0565\u0580 \u0566\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u0568\u0576\u056F\u0561\u056C\u056B\u0579\u0576\u0565\u0580\u0568 \u0570\u0561\u0575\u057F\u0576\u0561\u0562\u0565\u0580\u0578\u0582\u0574 \u0565\u0576 \u0586\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576 \u0567\u0576\u0565\u0580\u0563\u056B\u0561\u0576 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u056B\u0581, \u0574\u056B\u0576\u0579\u0564\u0565\u057C \u0568\u0576\u056F\u0561\u056C\u0578\u0582\u0574\u0576 \u0561\u0575\u0576 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u0578\u0582\u0572\u0565\u0572\u0568 \u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u0578\u0582\u0574 \u0587 \u0574\u0565\u056F\u0576\u0561\u0562\u0561\u0576\u0578\u0582\u0574 \u0561\u0575\u0564 \u0566\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0574\u0565\u0580 \u0566\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u0568 \u0563\u0580\u0563\u056B\u057C\u0576\u0565\u0580\u0568 \u057E\u0565\u0580\u0561\u056E\u0578\u0582\u0574 \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0561\u0566\u0564\u0561\u0576\u0577\u0561\u0576\u0576\u0565\u0580\u056B:",az:"Duy\u011Fu sensor reseptorlar\u0131m\u0131z\u0131n \u0259traf m\xFChitd\u0259n fiziki enerjini a\u015Fkar etm\u0259si prosesidir, qavray\u0131\u015F is\u0259 beynin bu m\u0259lumat\u0131n\u0131 nec\u0259 t\u0259\u015Fkil etm\u0259si v\u0259 m\u0259nal\u0131 t\u0259cr\xFCb\u0259 kimi \u015F\u0259rh etm\u0259sidir. Bu f\u0259sil duy\u011Fu sisteml\u0259rimizin xam stimullar\u0131 nec\u0259 neyron siqnallar\u0131na \xE7evirdiyini ara\u015Fd\u0131r\u0131r."},keyPoints:{en:["Sensation = detecting physical energy (light, sound, pressure); Perception = organizing and interpreting that sensory information into something meaningful.","Absolute threshold: the minimum stimulation needed to detect a stimulus 50% of the time. Difference threshold (JND): the smallest detectable difference between two stimuli.","Vision: Light enters through the cornea \u2192 pupil \u2192 lens \u2192 retina. Rods detect dim light; cones detect color. Information travels via the optic nerve to the visual cortex.","Gestalt principles of perception: proximity, similarity, closure, continuity, and figure-ground. The brain fills in gaps to create coherent images.","Color vision: Trichromatic theory (3 types of cones for red, green, blue) explains color mixing; Opponent-process theory (red-green, blue-yellow, black-white pairs) explains afterimages.","Hearing: Sound waves \u2192 eardrum \u2192 ossicles \u2192 cochlea \u2192 hair cells \u2192 auditory nerve. Pitch is encoded by place theory (high frequencies) and frequency theory (low frequencies).","Sensory adaptation: when constant stimulation leads to reduced sensitivity (e.g., you stop noticing a smell after a while)."],ka:["\u10E8\u10D4\u10D2\u10E0\u10EB\u10DC\u10D4\u10D1\u10D0 \u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D4\u10DC\u10D4\u10E0\u10D2\u10D8\u10D8\u10E1 \u10D0\u10DB\u10DD\u10EA\u10DC\u10DD\u10D1\u10D0\u10D0; \u10D0\u10E6\u10E5\u10DB\u10D0 \u10DB\u10D8\u10E1\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10DE\u10E0\u10D4\u10E2\u10D0\u10EA\u10D8\u10D0\u10D0.","\u10D0\u10D1\u10E1\u10DD\u10DA\u10E3\u10E2\u10E3\u10E0\u10D8 \u10D6\u10E6\u10E3\u10E0\u10D1\u10DA\u10D8 \u10D3\u10D0 \u10E1\u10EE\u10D5\u10D0\u10DD\u10D1\u10D8\u10E1 \u10D6\u10E6\u10E3\u10E0\u10D1\u10DA\u10D8 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10EA\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10D0.","\u10DB\u10EE\u10D4\u10D3\u10D5\u10D4\u10DA\u10DD\u10D1\u10D0: \u10E8\u10E3\u10E5\u10D8 \u10E8\u10D4\u10DB\u10DD\u10D3\u10D8\u10E1 \u10E0\u10E5\u10DD\u10D5\u10D0\u10DC\u10D0\u10E8\u10D8 \u10D3\u10D0 \u10D0\u10E6\u10EC\u10D4\u10D5\u10E1 \u10D1\u10D0\u10D3\u10E3\u10E0\u10D0\u10E8\u10D8.","\u10D2\u10D4\u10E8\u10E2\u10D0\u10DA\u10E2\u10D8\u10E1 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D4\u10D1\u10D8: \u10E1\u10D8\u10D0\u10EE\u10DA\u10DD\u10D5\u10D4, \u10DB\u10E1\u10D2\u10D0\u10D5\u10E1\u10D4\u10D1\u10D0, \u10D3\u10D0\u10EE\u10E3\u10E0\u10E3\u10DA\u10DD\u10D1\u10D0 \u10D3\u10D0 \u10E3\u10EC\u10E7\u10D5\u10D4\u10E2\u10DD\u10D1\u10D0.","\u10E4\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10EE\u10D4\u10D3\u10D5\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1 \u10EE\u10E1\u10DC\u10D8\u10E1 \u10E2\u10E0\u10D8\u10E5\u10E0\u10DD\u10DB\u10D0\u10E2\u10E3\u10DA\u10D8 \u10D3\u10D0 \u10DD\u10DE\u10DD\u10DC\u10D4\u10DC\u10E2\u10E3\u10E0\u10D8 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8.","\u10E1\u10DB\u10D4\u10DC\u10D0: \u10D1\u10D2\u10D4\u10E0\u10D8\u10D7\u10D8 \u10E2\u10D0\u10DA\u10E6\u10D4\u10D1\u10D8 \u10D2\u10D0\u10D3\u10D0\u10D4\u10EA\u10D4\u10DB\u10D0 \u10E1\u10D0\u10E1\u10DB\u10D4\u10DC\u10D8 \u10DC\u10D4\u10E0\u10D5\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7.","\u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA\u10D8 \u10D0\u10D3\u10D0\u10DE\u10E2\u10D0\u10EA\u10D8\u10D0 \u10E3\u10D6\u10E0\u10E3\u10DC\u10D5\u10D4\u10DA\u10E7\u10DD\u10E4\u10E1 \u10DB\u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1 \u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D0\u10EA\u10D8\u10D8\u10E1\u10D0\u10E1."],ru:["\u041E\u0449\u0443\u0449\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0435\u043D\u0438\u0435 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438; \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u2014 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u044F.","\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u044B\u0439 \u043F\u043E\u0440\u043E\u0433 \u0438 \u043F\u043E\u0440\u043E\u0433 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u2014 \u043A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438.","\u0417\u0440\u0435\u043D\u0438\u0435: \u0441\u0432\u0435\u0442 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 \u0440\u043E\u0433\u043E\u0432\u0438\u0446\u0443 \u043A \u0441\u0435\u0442\u0447\u0430\u0442\u043A\u0435.","\u0413\u0435\u0448\u0442\u0430\u043B\u044C\u0442-\u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B: \u0431\u043B\u0438\u0437\u043E\u0441\u0442\u044C, \u0441\u0445\u043E\u0434\u0441\u0442\u0432\u043E, \u0437\u0430\u043C\u043A\u043D\u0443\u0442\u043E\u0441\u0442\u044C \u0438 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0441\u0442\u044C.","\u0426\u0432\u0435\u0442\u043E\u0432\u043E\u0435 \u0437\u0440\u0435\u043D\u0438\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F \u0442\u0440\u0438\u0445\u0440\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0442\u0435\u043E\u0440\u0438\u0435\u0439 \u0438 \u0442\u0435\u043E\u0440\u0438\u0435\u0439 \u043E\u043F\u043F\u043E\u043D\u0435\u043D\u0442\u043D\u044B\u0445 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432.","\u0421\u043B\u0443\u0445: \u0437\u0432\u0443\u043A\u043E\u0432\u044B\u0435 \u0432\u043E\u043B\u043D\u044B \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 \u043A \u0441\u043B\u0443\u0445\u043E\u0432\u043E\u043C\u0443 \u043D\u0435\u0440\u0432\u0443.","\u0421\u0435\u043D\u0441\u043E\u0440\u043D\u0430\u044F \u0430\u0434\u0430\u043F\u0442\u0430\u0446\u0438\u044F \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u043A \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u044E \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0439 \u0441\u0442\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438."],hy:["\u0536\u0563\u0561\u0575\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0586\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576 \u0567\u0576\u0565\u0580\u0563\u056B\u0561\u0575\u056B \u0570\u0561\u0575\u057F\u0576\u0561\u0562\u0565\u0580\u0578\u0582\u0574\u0576 \u0567, \u056B\u057D\u056F \u0568\u0576\u056F\u0561\u056C\u0578\u0582\u0574\u0568 \u0564\u0580\u0561 \u0574\u0565\u056F\u0576\u0561\u0562\u0561\u0576\u0578\u0582\u0574\u0568:","\u0532\u0561\u0581\u0561\u0580\u0571\u0561\u056F \u0577\u0565\u0574\u0568 \u0587 \u057F\u0561\u0580\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u0577\u0565\u0574\u0568 \u0561\u057C\u0561\u0576\u0581\u0584\u0561\u0575\u056B\u0576 \u0570\u0561\u057D\u056F\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0565\u0576:","\u054F\u0565\u057D\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u056C\u0578\u0582\u0575\u057D\u0568 \u0561\u0576\u0581\u0576\u0578\u0582\u0574 \u0567 \u0565\u0572\u057B\u0565\u0580\u0561\u0569\u0561\u0572\u0561\u0576\u0569\u0578\u057E \u0564\u0565\u057A\u056B \u0581\u0561\u0576\u0581\u0561\u0569\u0561\u0572\u0561\u0576\u0569:","\u0533\u0565\u0577\u057F\u0561\u056C\u057F \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0576\u0565\u0580. \u0574\u0578\u057F\u056B\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0576\u0574\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0583\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576:","\u0533\u0578\u0582\u0576\u0561\u0575\u056B\u0576 \u057F\u0565\u057D\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0561\u0581\u0561\u057F\u0580\u057E\u0578\u0582\u0574 \u0567 \u0563\u0578\u0582\u0576\u0561\u0575\u056B\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0578\u057E:","\u053C\u057D\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0571\u0561\u0575\u0576\u0561\u0575\u056B\u0576 \u0561\u056C\u056B\u0584\u0576\u0565\u0580\u0568 \u0563\u0576\u0578\u0582\u0574 \u0565\u0576 \u0564\u0565\u057A\u056B \u056C\u057D\u0578\u0572\u0561\u056F\u0561\u0576 \u0576\u0575\u0561\u0580\u0564:","\u0536\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u0561\u0564\u0561\u057A\u057F\u0561\u0581\u056B\u0561\u0576 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u0566\u0563\u0561\u0575\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0570\u0561\u057D\u057F\u0561\u057F\u0578\u0582\u0576 \u0563\u0580\u0563\u057C\u0574\u0561\u0576 \u056A\u0561\u0574\u0561\u0576\u0561\u056F:"],az:["Duy\u011Fu fiziki enerjini a\u015Fkar edir; qavray\u0131\u015F is\u0259 onu \u015F\u0259rh edir.","M\xFCtl\u0259q h\u0259dd v\u0259 f\u0259rq h\u0259ddi \u0259sas anlay\u0131\u015Flard\u0131r.","G\xF6rm\u0259: \u0130\u015F\u0131q buynuz qi\u015Fadan ke\xE7ib torlu qi\u015Faya \xE7at\u0131r.","Ge\u015Ftalt prinsipl\u0259ri: yax\u0131nl\u0131q, ox\u015Farl\u0131q, qapal\u0131l\u0131q v\u0259 davaml\u0131l\u0131q.","R\u0259ngli g\xF6rm\u0259 trikromatik v\u0259 r\u0259qib proses n\u0259z\u0259riyy\u0259l\u0259ri il\u0259 izah olunur.","E\u015Fitm\u0259: S\u0259s dal\u011Falar\u0131 e\u015Fitm\u0259 sinirin\u0259 gedir.","Sensor adaptasiya daimi stimulla\u015Fd\u0131rma zaman\u0131 h\u0259ssasl\u0131\u011F\u0131n azalmas\u0131d\u0131r."]},funFact:{en:"Your eyes can distinguish about 10 million different colors, yet dogs see the world mainly in blues and yellows. The mantis shrimp, however, has 16 types of color receptors compared to our 3!",ka:"\u10E7\u10DC\u10DD\u10E1\u10D5\u10D8\u10E1 \u10E8\u10D4\u10D2\u10E0\u10EB\u10DC\u10D4\u10D1\u10D0 \u10DE\u10D8\u10E0\u10D3\u10D0\u10DE\u10D8\u10E0 \u10D0\u10E0\u10D8\u10E1 \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D0\u10DB\u10D8\u10D2\u10D3\u10D0\u10DA\u10D0\u10E1\u10D7\u10D0\u10DC \u10D3\u10D0 \u10F0\u10D8\u10DE\u10DD\u10D9\u10D0\u10DB\u10DE\u10D7\u10D0\u10DC - \u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D4\u10D1\u10D7\u10D0\u10DC.",ru:"\u041E\u0431\u043E\u043D\u044F\u043D\u0438\u0435 \u043D\u0430\u043F\u0440\u044F\u043C\u0443\u044E \u0441\u0432\u044F\u0437\u0430\u043D\u043E \u0441 \u043C\u0438\u043D\u0434\u0430\u043B\u0435\u0432\u0438\u0434\u043D\u044B\u043C \u0442\u0435\u043B\u043E\u043C \u0438 \u0433\u0438\u043F\u043F\u043E\u043A\u0430\u043C\u043F\u043E\u043C \u2014 \u0446\u0435\u043D\u0442\u0440\u0430\u043C\u0438 \u043F\u0430\u043C\u044F\u0442\u0438 \u0438 \u044D\u043C\u043E\u0446\u0438\u0439 \u043C\u043E\u0437\u0433\u0430.",hy:"\u0540\u0578\u057F\u0561\u057C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0578\u0582\u0572\u0572\u0561\u056F\u056B\u0578\u0580\u0565\u0576 \u056F\u0561\u057A\u057E\u0561\u056E \u0567 \u0561\u0574\u056B\u0563\u0564\u0561\u056C\u0561\u0575\u056B \u0587 \u0570\u056B\u057A\u0578\u056F\u0561\u0574\u057A\u056B \u0570\u0565\u057F\u055D \u0578\u0582\u0572\u0565\u0572\u056B \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0570\u0578\u0582\u0575\u0566\u0565\u0580\u056B \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0576\u0565\u0580\u056B \u0570\u0565\u057F:",az:"Qoxu hissi beynin yadda\u015F v\u0259 emosiya m\u0259rk\u0259zl\u0259ri olan amiqdala v\u0259 hipokampusla birba\u015Fa ba\u011Fl\u0131d\u0131r."},realWorld:{en:"Optical illusions are not just fun tricks \u2014 they reveal how the brain constructs reality. UX designers use Gestalt principles daily: grouping related buttons, using whitespace, and creating visual hierarchies on websites.",ka:'\u10E1\u10D0\u10D2\u10D6\u10D0\u10DD \u10DB\u10DD\u10EB\u10E0\u10D0\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D4\u10E1\u10D4\u10D1\u10E8\u10D8 \u10EC\u10D8\u10D7\u10D4\u10DA\u10D8 \u10E8\u10E3\u10E5\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D0 "\u10D2\u10D0\u10E9\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1" \u10DC\u10D8\u10E8\u10DC\u10D0\u10D3 \u10D4\u10E4\u10E3\u10EB\u10DC\u10D4\u10D1\u10D0 \u10D0\u10E6\u10E5\u10DB\u10D8\u10E1 \u10E9\u10D5\u10D4\u10D5\u10D4\u10D1\u10E1.',ru:"\u0418\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435 \u043A\u0440\u0430\u0441\u043D\u043E\u0433\u043E \u0441\u0432\u0435\u0442\u0430 \u0432 \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u0445 \u0434\u043E\u0440\u043E\u0436\u043D\u043E\u0433\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u043A\u0430\u043A \u0441\u0438\u0433\u043D\u0430\u043B\u0430 \xAB\u0421\u0442\u043E\u043F\xBB \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043E \u043D\u0430 \u043F\u0440\u0438\u0432\u044B\u0447\u043A\u0430\u0445 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F.",hy:"\u0543\u0561\u0576\u0561\u057A\u0561\u0580\u0570\u0561\u0575\u056B\u0576 \u0565\u0580\u0569\u0587\u0565\u056F\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0561\u0576\u0578\u0576\u0576\u0565\u0580\u0578\u0582\u0574 \u056F\u0561\u0580\u0574\u056B\u0580 \u056C\u0578\u0582\u0575\u057D\u056B \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574\u0568 \u0578\u0580\u057A\u0565\u057D \xAB\u053F\u0561\u0576\u0563\xBB \u0561\u0566\u0564\u0561\u0576\u0577\u0561\u0576 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0567 \u0568\u0576\u056F\u0561\u056C\u0574\u0561\u0576 \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0575\u0569\u0576\u0565\u0580\u056B \u057E\u0580\u0561:",az:'Yol h\u0259r\u0259k\u0259ti qaydalar\u0131nda q\u0131rm\u0131z\u0131 i\u015F\u0131\u011F\u0131n "Dayan" siqnal\u0131 kimi istifad\u0259si qavray\u0131\u015F v\u0259rdi\u015Fl\u0259rin\u0259 \u0259saslan\u0131r.'}},5:{title:{en:"States of Consciousness",ka:"\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0",ru:"\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F",hy:"\u0533\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580",az:"\u015E\xFCur V\u0259ziyy\u0259tl\u0259ri"},description:{en:"Sleep, dreams, hypnosis, and altered states of consciousness.",ka:"\u10EB\u10D8\u10DA\u10D8, \u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8, \u10F0\u10D8\u10DE\u10DC\u10DD\u10D6\u10D8 \u10D3\u10D0 \u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10EA\u10D5\u10DA\u10D8\u10DA\u10D8 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0.",ru:"\u0421\u043E\u043D, \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F, \u0433\u0438\u043F\u043D\u043E\u0437 \u0438 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u043D\u044B\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F.",hy:"\u0554\u0578\u0582\u0576, \u0565\u0580\u0561\u0566\u0576\u0565\u0580, \u0570\u056B\u057A\u0576\u0578\u057D \u0587 \u0563\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u0583\u0578\u0583\u0578\u056D\u057E\u0561\u056E \u057E\u056B\u0573\u0561\u056F:",az:"Yuxu, yuxug\xF6rm\u0259, hipnoz v\u0259 meditasiya kimi m\xFCxt\u0259lif \u015F\xFCur hallar\u0131."},keyTopics:{en:["Sleep Stages","Dreams","Hypnosis","Meditation","Psychoactive Substances"],ka:["\u10EB\u10D8\u10DA\u10D8\u10E1 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10D8","\u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8","\u10F0\u10D8\u10DE\u10DC\u10DD\u10D6\u10D8","\u10DB\u10D4\u10D3\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0","\u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D8 \u10DC\u10D8\u10D5\u10D7\u10D8\u10D4\u10E0\u10D4\u10D1\u10D4\u10D1\u10D8"],ru:["\u0421\u0442\u0430\u0434\u0438\u0438 \u0441\u043D\u0430","\u041C\u0435\u0447\u0442\u044B","\u0413\u0438\u043F\u043D\u043E\u0437","\u041C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F","\u041F\u0441\u0438\u0445\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430"],hy:["\u0554\u0576\u056B \u0583\u0578\u0582\u056C\u0565\u0580","\u0535\u0580\u0561\u0566\u0576\u0565\u0580","\u0540\u056B\u057A\u0576\u0578\u0566","\u0544\u0565\u0564\u056B\u057F\u0561\u0581\u056B\u0561","\u0540\u0578\u0563\u0565\u0561\u056F\u057F\u056B\u057E \u0576\u0575\u0578\u0582\u0569\u0565\u0580"],az:["Yuxu Tsikll\u0259ri","Yuxug\xF6rm\u0259 N\u0259\u10D6\u10D4\u10E0\u10D8yy\u0259l\u0259ri","Hipnoz v\u0259 Meditasiya","Psixoaktiv Madd\u0259l\u0259r"]},summary:{en:"Consciousness is our awareness of ourselves and our environment, existing on a continuum from full alertness to deep sleep, with many states in between including daydreaming, meditation, and hypnosis. This chapter explores the biological rhythms that govern our daily cycles \u2014 particularly the circadian rhythm, regulated by the suprachiasmatic nucleus and the hormone melatonin. It examines the architecture of sleep in detail: the progression through NREM stages 1-3 (from light sleep with alpha waves to deep slow-wave sleep with delta waves) and REM sleep (characterized by vivid dreaming and muscle paralysis). Major dream theories are compared, including Freud's wish fulfillment, the activation-synthesis model, and information-processing theory. The chapter also covers sleep disorders (insomnia, narcolepsy, sleep apnea), the serious cognitive and health consequences of sleep deprivation, the nature and limits of hypnosis, and how psychoactive substances \u2014 stimulants, depressants, opioids, and hallucinogens \u2014 alter consciousness by affecting neurotransmitter systems.",ka:"\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E9\u10D5\u10D4\u10DC\u10D8 \u10D3\u10D0 \u10E9\u10D5\u10D4\u10DC\u10D8 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E0\u10E1\u10D4\u10D1\u10DD\u10D1\u10E1 \u10E3\u10EC\u10E7\u10D5\u10D4\u10E2 \u10E1\u10DE\u10D4\u10E5\u10E2\u10E0\u10D6\u10D4 \u10E1\u10E0\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E4\u10EE\u10D8\u10D6\u10DA\u10D8\u10D3\u10D0\u10DC \u10E6\u10E0\u10DB\u10D0 \u10EB\u10D8\u10DA\u10D0\u10DB\u10D3\u10D4, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10D8 \u10E8\u10E3\u10D0\u10DA\u10D4\u10D3\u10E3\u10E0\u10D8 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D8\u10D7, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10DD\u10EA\u10DC\u10D4\u10D1\u10D0, \u10DB\u10D4\u10D3\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0 \u10D3\u10D0 \u10F0\u10D8\u10DE\u10DC\u10DD\u10D6\u10D8. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0 \u10E0\u10D8\u10E2\u10DB\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10DB\u10D0\u10E0\u10D7\u10D0\u10D5\u10D4\u10DC \u10E9\u10D5\u10D4\u10DC\u10E1 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0 \u10EA\u10D8\u10D9\u10DA\u10D4\u10D1\u10E1 \u2014 \u10D2\u10D0\u10DC\u10E1\u10D0\u10D9\u10E3\u10D7\u10E0\u10D4\u10D1\u10D8\u10D7 \u10EA\u10D8\u10E0\u10D9\u10D0\u10D3\u10E3\u10DA \u10E0\u10D8\u10E2\u10DB\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10E1\u10D0\u10EA \u10D0\u10E0\u10D4\u10D2\u10E3\u10DA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10E1\u10E3\u10DE\u10E0\u10D0\u10E5\u10D8\u10D0\u10D6\u10DB\u10D0\u10E2\u10E3\u10E0\u10D8 \u10D1\u10D8\u10E0\u10D7\u10D5\u10D8 \u10D3\u10D0 \u10F0\u10DD\u10E0\u10DB\u10DD\u10DC\u10D8 \u10DB\u10D4\u10DA\u10D0\u10E2\u10DD\u10DC\u10D8\u10DC\u10D8. \u10D8\u10E1 \u10D3\u10D4\u10E2\u10D0\u10DA\u10E3\u10E0\u10D0\u10D3 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10EB\u10D8\u10DA\u10D8\u10E1 \u10D0\u10E0\u10E5\u10D8\u10E2\u10D4\u10E5\u10E2\u10E3\u10E0\u10D0\u10E1: NREM 1-3 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10D8\u10E1 \u10DE\u10E0\u10DD\u10D2\u10E0\u10D4\u10E1\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1 (\u10DB\u10E1\u10E3\u10D1\u10E3\u10E5\u10D8 \u10EB\u10D8\u10DA\u10D8\u10D3\u10D0\u10DC \u10D0\u10DA\u10E4\u10D0 \u10E2\u10D0\u10DA\u10E6\u10D4\u10D1\u10D8\u10D7 \u10E6\u10E0\u10DB\u10D0 \u10DC\u10D4\u10DA-\u10E2\u10D0\u10DA\u10E6\u10DD\u10D5\u10D0\u10DC \u10EB\u10D8\u10DA\u10D0\u10DB\u10D3\u10D4 \u10D3\u10D4\u10DA\u10E2\u10D0 \u10E2\u10D0\u10DA\u10E6\u10D4\u10D1\u10D8\u10D7) \u10D3\u10D0 REM \u10EB\u10D8\u10DA\u10E1 (\u10EE\u10D0\u10E1\u10D8\u10D0\u10D7\u10D3\u10D4\u10D1\u10D0 \u10DC\u10D0\u10D7\u10D4\u10DA\u10D8 \u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8\u10D7 \u10D3\u10D0 \u10D9\u10E3\u10DC\u10D7\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10DB\u10D1\u10DA\u10D8\u10D7). \u10E8\u10D4\u10D3\u10D0\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10E1 \u10E1\u10E3\u10E0\u10D5\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D0, \u10D0\u10E5\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0-\u10E1\u10D8\u10DC\u10D7\u10D4\u10D6\u10D8\u10E1 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8 \u10D3\u10D0 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10EB\u10D8\u10DA\u10D8\u10E1 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10E1 (\u10D8\u10DC\u10E1\u10DD\u10DB\u10DC\u10D8\u10D0, \u10DC\u10D0\u10E0\u10D9\u10DD\u10DA\u10D4\u10E4\u10E1\u10D8\u10D0, \u10EB\u10D8\u10DA\u10D8\u10E1 \u10D0\u10DE\u10DC\u10DD\u10D4), \u10EB\u10D8\u10DA\u10D8\u10E1 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10DD\u10D1\u10D8\u10E1 \u10E1\u10D4\u10E0\u10D8\u10DD\u10D6\u10E3\u10DA \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0 \u10D3\u10D0 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10E1, \u10F0\u10D8\u10DE\u10DC\u10DD\u10D6\u10D8\u10E1 \u10D1\u10E3\u10DC\u10D4\u10D1\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10E1\u10D0\u10D6\u10E6\u10D5\u10E0\u10D4\u10D1\u10E1, \u10D3\u10D0 \u10D8\u10DB\u10D0\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10EA\u10D5\u10DA\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D8 \u10DC\u10D8\u10D5\u10D7\u10D8\u10D4\u10E0\u10D4\u10D1\u10D4\u10D1\u10D8 \u2014 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D0\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8, \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D0\u10DC\u10E2\u10D4\u10D1\u10D8, \u10DD\u10DE\u10D8\u10DD\u10D8\u10D3\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10F0\u10D0\u10DA\u10E3\u10EA\u10D8\u10DC\u10DD\u10D2\u10D4\u10DC\u10D4\u10D1\u10D8 \u2014 \u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1 \u10DC\u10D4\u10D8\u10E0\u10DD\u10E2\u10E0\u10D0\u10DC\u10E1\u10DB\u10D8\u10E2\u10D4\u10E0\u10E3\u10DA \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D4\u10D1\u10D6\u10D4 \u10D6\u10D4\u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D8\u10D7.",ru:"\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u043D\u0430\u0448\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u0435\u0431\u044F \u0438 \u043D\u0430\u0448\u0435\u0433\u043E \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0435 \u0432 \u043A\u043E\u043D\u0442\u0438\u043D\u0443\u0443\u043C\u0435 \u043E\u0442 \u043F\u043E\u043B\u043D\u043E\u0439 \u0431\u043E\u0434\u0440\u043E\u0441\u0442\u0438 \u0434\u043E \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430, \u0441\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043C\u0435\u0447\u0442\u044B, \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044E \u0438 \u0433\u0438\u043F\u043D\u043E\u0437. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0442\u0441\u044F \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0438\u0442\u043C\u044B, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0435 \u043D\u0430\u0448\u0438\u043C\u0438 \u0441\u0443\u0442\u043E\u0447\u043D\u044B\u043C\u0438 \u0446\u0438\u043A\u043B\u0430\u043C\u0438, \u2014 \u0432 \u0447\u0430\u0441\u0442\u043D\u043E\u0441\u0442\u0438, \u0446\u0438\u0440\u043A\u0430\u0434\u043D\u044B\u0439 \u0440\u0438\u0442\u043C, \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u0439 \u0441\u0443\u043F\u0440\u0430\u0445\u0438\u0430\u0437\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u044F\u0434\u0440\u043E\u043C \u0438 \u0433\u043E\u0440\u043C\u043E\u043D\u043E\u043C \u043C\u0435\u043B\u0430\u0442\u043E\u043D\u0438\u043D\u043E\u043C. \u041F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0441\u043D\u0430: \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0441\u0442\u0430\u0434\u0438\u0438 NREM 1-3 (\u043E\u0442 \u043B\u0435\u0433\u043A\u043E\u0433\u043E \u0441\u043D\u0430 \u0441 \u0430\u043B\u044C\u0444\u0430-\u0432\u043E\u043B\u043D\u0430\u043C\u0438 \u0434\u043E \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0432\u043E\u043B\u043D\u043E\u0432\u043E\u0433\u043E \u0441\u043D\u0430 \u0441 \u0434\u0435\u043B\u044C\u0442\u0430-\u0432\u043E\u043B\u043D\u0430\u043C\u0438) \u0438 REM-\u0441\u043E\u043D (\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u044F\u0440\u043A\u0438\u043C\u0438 \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u043C\u044B\u0448\u0435\u0447\u043D\u044B\u043C \u043F\u0430\u0440\u0430\u043B\u0438\u0447\u043E\u043C). \u0421\u0440\u0430\u0432\u043D\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0442\u0435\u043E\u0440\u0438\u0438 \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u0439, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u0439 \u0424\u0440\u0435\u0439\u0434\u0430, \u043C\u043E\u0434\u0435\u043B\u044C \u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u0438-\u0441\u0438\u043D\u0442\u0435\u0437\u0430 \u0438 \u0442\u0435\u043E\u0440\u0438\u044E \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438. \u0413\u043B\u0430\u0432\u0430 \u0442\u0430\u043A\u0436\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u0441\u043D\u0430 (\u0431\u0435\u0441\u0441\u043E\u043D\u043D\u0438\u0446\u0430, \u043D\u0430\u0440\u043A\u043E\u043B\u0435\u043F\u0441\u0438\u044F, \u0430\u043F\u043D\u043E\u044D \u0432\u043E \u0441\u043D\u0435), \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u0435 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0438 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u043B\u0438\u0448\u0435\u043D\u0438\u044F \u0441\u043D\u0430, \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0438 \u0433\u0440\u0430\u043D\u0438\u0446\u044B \u0433\u0438\u043F\u043D\u043E\u0437\u0430, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0442\u043E, \u043A\u0430\u043A \u043F\u0441\u0438\u0445\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430 \u2014 \u0441\u0442\u0438\u043C\u0443\u043B\u044F\u0442\u043E\u0440\u044B, \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0430\u043D\u0442\u044B, \u043E\u043F\u0438\u043E\u0438\u0434\u044B \u0438 \u0433\u0430\u043B\u043B\u044E\u0446\u0438\u043D\u043E\u0433\u0435\u043D\u044B \u2014 \u0438\u0437\u043C\u0435\u043D\u044F\u044E\u0442 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044F \u043D\u0430 \u043D\u0435\u0439\u0440\u043E\u043C\u0435\u0434\u0438\u0430\u0442\u043E\u0440\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B.",hy:"\u0533\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0574\u0565\u0580 \u0587 \u0574\u0565\u0580 \u0577\u0580\u057B\u0561\u057A\u0561\u057F\u056B \u0574\u0561\u057D\u056B\u0576 \u057F\u0565\u0572\u0565\u056F\u0561\u0581\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0567, \u0578\u0580\u0568 \u0563\u0578\u0575\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u056B \u056C\u056B\u0561\u0580\u056A\u0565\u0584 \u0561\u0580\u0569\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u056D\u0578\u0580\u0568 \u0584\u0578\u0582\u0576 \u0568\u0576\u056F\u0561\u056E \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561\u055D \u0562\u0561\u0566\u0574\u0561\u0569\u056B\u057E \u0574\u056B\u057B\u0561\u0576\u056F\u0575\u0561\u056C \u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u0578\u057E, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0565\u0580\u0561\u0566\u056F\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0574\u0565\u0564\u056B\u057F\u0561\u0581\u056B\u0561\u0576 \u0587 \u0570\u056B\u057A\u0576\u0578\u057D\u0568: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u057C\u056B\u0569\u0574\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0578\u0582\u0574 \u0565\u0576 \u0574\u0565\u0580 \u0561\u057C\u0585\u0580\u0575\u0561 \u0581\u056B\u056F\u056C\u0565\u0580\u0568, \u0570\u0561\u057F\u056F\u0561\u057A\u0565\u057D \u0581\u056B\u0580\u056F\u0561\u0564\u0561\u0575\u056B\u0576 \u057C\u056B\u0569\u0574\u0568, \u0578\u0580\u0568 \u056F\u0561\u0580\u0563\u0561\u057E\u0578\u0580\u057E\u0578\u0582\u0574 \u0567 \u057D\u0578\u0582\u057A\u0580\u0561\u056D\u056B\u0561\u0566\u0574\u0561\u057F\u056B\u056F \u0574\u056B\u057B\u0578\u0582\u056F\u0578\u057E \u0587 \u0574\u0565\u056C\u0561\u057F\u0578\u0576\u056B\u0576 \u0570\u0578\u0580\u0574\u0578\u0576\u0578\u057E: \u0531\u0575\u0576 \u0574\u0561\u0576\u0580\u0561\u0574\u0561\u057D\u0576 \u0584\u0576\u0576\u0561\u0580\u056F\u0578\u0582\u0574 \u0567 \u0584\u0576\u056B \u0573\u0561\u0580\u057F\u0561\u0580\u0561\u057A\u0565\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568. NREM 1-3 \u0583\u0578\u0582\u056C\u0565\u0580\u056B \u0561\u057C\u0561\u057B\u0568\u0576\u0569\u0561\u0581\u0568 (\u0561\u056C\u0586\u0561 \u0561\u056C\u056B\u0584\u0576\u0565\u0580\u0578\u057E \u0569\u0565\u0569\u0587 \u0584\u0576\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u0564\u0565\u056C\u057F\u0561 \u0561\u056C\u056B\u0584\u0576\u0565\u0580\u0578\u057E \u056D\u0578\u0580\u0568 \u0564\u0561\u0576\u0564\u0561\u0572 \u0561\u056C\u056B\u0584\u0561\u0575\u056B\u0576 \u0584\u0578\u0582\u0576) \u0587 REM \u0584\u0578\u0582\u0576\u0568 (\u0562\u0576\u0578\u0582\u0569\u0561\u0563\u0580\u057E\u0578\u0582\u0574 \u0567 \u057E\u0561\u057C \u0565\u0580\u0561\u0566\u0576\u0565\u0580\u0578\u057E \u0587 \u0574\u056F\u0561\u0576\u0561\u0575\u056B\u0576 \u056F\u0561\u0569\u057E\u0561\u056E\u0578\u057E): \u0540\u0561\u0574\u0565\u0574\u0561\u057F\u057E\u0578\u0582\u0574 \u0565\u0576 \u0565\u0580\u0561\u0566\u0576\u0565\u0580\u056B \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0556\u0580\u0565\u0575\u0564\u056B \u0581\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u056B\u0580\u0561\u056F\u0561\u0576\u0561\u0581\u0578\u0582\u0574\u0568, \u0561\u056F\u057F\u056B\u057E\u0561\u0581\u0574\u0561\u0576-\u057D\u056B\u0576\u0569\u0565\u0566\u056B \u0574\u0578\u0564\u0565\u056C\u0568 \u0587 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0577\u0561\u056F\u0574\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0533\u056C\u0578\u0582\u056D\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0576\u0561\u0587 \u0584\u0576\u056B \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0568 (\u0561\u0576\u0584\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0576\u0561\u0580\u056F\u0578\u056C\u0565\u057A\u057D\u056B\u0561, \u0584\u0576\u056B \u0561\u057A\u0576\u0578\u0567), \u0584\u0576\u056B \u057A\u0561\u056F\u0561\u057D\u056B \u056C\u0578\u0582\u0580\u057B \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0587 \u0561\u057C\u0578\u0572\u057B\u0561\u056F\u0561\u0576 \u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0576\u0565\u0580\u0568, \u0570\u056B\u057A\u0576\u0578\u057D\u056B \u0567\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0578\u0582 \u057D\u0561\u0570\u0574\u0561\u0576\u0576\u0565\u0580\u0568, \u0587 \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0570\u0578\u0563\u0565\u0561\u056F\u057F\u056B\u057E \u0576\u0575\u0578\u0582\u0569\u0565\u0580\u0568\u055D \u056D\u0569\u0561\u0576\u056B\u0579\u0576\u0565\u0580\u0568, \u0564\u0565\u057A\u0580\u0565\u057D\u0561\u0576\u057F\u0576\u0565\u0580\u0568, \u0585\u0583\u056B\u0578\u056B\u0564\u0576\u0565\u0580\u0568 \u0587 \u0570\u0561\u056C\u0575\u0578\u0582\u0581\u056B\u0576\u0578\u0563\u0565\u0576\u0576\u0565\u0580\u0568, \u0583\u0578\u056D\u0578\u0582\u0574 \u0563\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568\u055D \u0561\u0566\u0564\u0565\u056C\u0578\u057E \u0576\u0565\u0575\u0580\u0578\u0570\u0561\u0572\u0578\u0580\u0564\u056B\u0579 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u056B \u057E\u0580\u0561:",az:"\u015E\xFCur, tam oyaql\u0131qdan d\u0259rin yuxuya q\u0259d\u0259r davam ed\u0259n bir spektrd\u0259 m\xF6vcud olan, qarabasma, meditasiya v\u0259 hipnoz da daxil olmaqla bir \xE7ox aral\u0131q hallar\u0131 olan \xF6z\xFCm\xFCz v\u0259 \u0259traf m\xFChitimiz haqq\u0131nda m\u0259lumatl\u0131l\u0131\u011F\u0131m\u0131zd\u0131r. Bu f\u0259sil g\xFCnd\u0259lik tsikll\u0259rimizi idar\u0259 ed\u0259n bioloji ritml\u0259ri \u2014 x\xFCsusil\u0259 supraxiazmatik n\xFCv\u0259 v\u0259 melatonin hormonu t\u0259r\u0259find\u0259n t\u0259nziml\u0259n\u0259n sirkad ritmi ara\u015Fd\u0131r\u0131r. Yuxunun arxitekturas\u0131 \u0259trafl\u0131 \u015F\u0259kild\u0259 inc\u0259l\u0259nir: NREM 1-3 m\u0259rh\u0259l\u0259l\u0259ri (alfa dal\u011Falar\u0131 olan y\xFCng\xFCl yuxudan delta dal\u011Falar\u0131 olan d\u0259rin yava\u015F dal\u011Fal\u0131 yuxuya q\u0259d\u0259r) v\u0259 REM yuxusu (canl\u0131 yuxular v\u0259 \u0259z\u0259l\u0259 iflici il\u0259 xarakteriz\u0259 olunur). Freydin arzu realla\u015Fd\u0131rmas\u0131, aktivasiya-sintez modeli v\u0259 m\u0259lumat emal\u0131 n\u0259z\u0259riyy\u0259si d\u0259 daxil olmaqla, \u0259sas yuxu n\u0259z\u0259riyy\u0259l\u0259ri m\xFCqayis\u0259 edilir. F\u0259sil h\u0259m\xE7inin yuxu poz\u011Funluqlar\u0131n\u0131 (insomniya, narkolepsiya, yuxu apnoesi), yuxusuzlu\u011Fun ciddi koqnitiv v\u0259 sa\u011Flaml\u0131q n\u0259tic\u0259l\u0259rini, hipnozun t\u0259bi\u0259tini v\u0259 h\xFCdudlar\u0131n\u0131 v\u0259 psixoaktiv madd\u0259l\u0259rin \u2014 stimulyatorlar, depressantlar, opioidl\u0259r v\u0259 hall\xFCsinogenl\u0259rin neyrotransmitter sisteml\u0259rin\u0259 t\u0259sir ed\u0259r\u0259k \u015F\xFCuru nec\u0259 d\u0259yi\u015Fdirdiyini \u0259hat\u0259 edir."},keyPoints:{en:["Consciousness exists on a continuum: from fully alert to deeply asleep, with many states in between (daydreaming, meditation, hypnosis).","Sleep has two main types: NREM (stages 1\u20133, progressively deeper) and REM (rapid eye movement, where vivid dreaming occurs). A full cycle lasts about 90 minutes.","Stage 3 (slow-wave/deep sleep) is critical for physical restoration and growth hormone release. REM sleep is vital for memory consolidation and emotional processing.","Dream theories: Freud's wish fulfillment (dreams express unconscious desires), Activation-synthesis (dreams are the brain's interpretation of random neural firing), Information processing (dreams help sort daily memories).","Sleep deprivation impairs attention, memory, immune function, and emotional regulation. Chronic sleep loss is linked to obesity, depression, and heart disease.","Hypnosis is a state of heightened suggestibility and focused attention \u2014 it does NOT give the hypnotist control over you. It can help with pain management and some habits.","Psychoactive substances work by mimicking, blocking, or altering neurotransmitter activity: stimulants (caffeine, cocaine), depressants (alcohol, barbiturates), opioids (morphine), hallucinogens (LSD, psilocybin)."],ka:["\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10E1\u10D4\u10D1\u10DD\u10D1\u10E1 \u10E3\u10EC\u10E7\u10D5\u10D4\u10E2 \u10E1\u10DE\u10D4\u10E5\u10E2\u10E0\u10D6\u10D4: \u10E1\u10E0\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E4\u10EE\u10D8\u10D6\u10DA\u10D8\u10D3\u10D0\u10DC \u10E6\u10E0\u10DB\u10D0 \u10EB\u10D8\u10DA\u10D0\u10DB\u10D3\u10D4, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10D8 \u10E8\u10E3\u10D0\u10DA\u10D4\u10D3\u10E3\u10E0\u10D8 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D8\u10D7 (\u10DD\u10EA\u10DC\u10D4\u10D1\u10D0, \u10DB\u10D4\u10D3\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0, \u10F0\u10D8\u10DE\u10DC\u10DD\u10D6\u10D8).","\u10EB\u10D8\u10DA\u10E1 \u10D0\u10E5\u10D5\u10E1 \u10DD\u10E0\u10D8 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10E2\u10D8\u10DE\u10D8: NREM (1\u20133 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10D8, \u10DE\u10E0\u10DD\u10D2\u10E0\u10D4\u10E1\u10E3\u10DA\u10D0\u10D3 \u10E3\u10E4\u10E0\u10DD \u10E6\u10E0\u10DB\u10D0) \u10D3\u10D0 REM (\u10D7\u10D5\u10D0\u10DA\u10D8\u10E1 \u10E1\u10EC\u10E0\u10D0\u10E4\u10DB\u10D0\u10DB\u10DD\u10EB\u10E0\u10D0\u10D5\u10D4\u10D1\u10D4\u10DA\u10D8, \u10E1\u10D0\u10D3\u10D0\u10EA \u10EE\u10D3\u10D4\u10D1\u10D0 \u10DC\u10D0\u10D7\u10D4\u10DA\u10D8 \u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8\u10E1 \u10EE\u10D8\u10DA\u10D5\u10D0). \u10E1\u10E0\u10E3\u10DA\u10D8 \u10EA\u10D8\u10D9\u10DA\u10D8 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D3\u10D4\u10D1\u10D0 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 90 \u10EC\u10E3\u10D7\u10D8.","\u10DB\u10D4-3 \u10D4\u10E2\u10D0\u10DE\u10D8 (\u10DC\u10D4\u10DA-\u10E2\u10D0\u10DA\u10E6\u10DD\u10D5\u10D0\u10DC\u10D8/\u10E6\u10E0\u10DB\u10D0 \u10EB\u10D8\u10DA\u10D8) \u10D2\u10D0\u10D3\u10D0\u10DB\u10EC\u10E7\u10D5\u10D4\u10E2\u10D8\u10D0 \u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10E6\u10D3\u10D2\u10D4\u10DC\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D6\u10E0\u10D3\u10D8\u10E1 \u10F0\u10DD\u10E0\u10DB\u10DD\u10DC\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10E7\u10DD\u10E4\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1. REM \u10EB\u10D8\u10DA\u10D8 \u10E1\u10D0\u10E1\u10D8\u10EA\u10DD\u10EA\u10EE\u10DA\u10DD\u10D3 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC\u10D8\u10D0 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DC\u10E1\u10DD\u10DA\u10D8\u10D3\u10D0\u10EA\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1.","\u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8: \u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10E1 \u10E1\u10E3\u10E0\u10D5\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D0 (\u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8 \u10D2\u10D0\u10DB\u10DD\u10EE\u10D0\u10E2\u10D0\u10D5\u10E1 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0 \u10E1\u10E3\u10E0\u10D5\u10D8\u10DA\u10D4\u10D1\u10E1), \u10D0\u10E5\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0-\u10E1\u10D8\u10DC\u10D7\u10D4\u10D6\u10D8 (\u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8 \u10D0\u10E0\u10D8\u10E1 \u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10DB\u10D8\u10D4\u10E0 \u10E8\u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D8\u10D7\u10D8 \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10D0\u10E5\u10E2\u10D8\u10D5\u10DD\u10D1\u10D8\u10E1 \u10D8\u10DC\u10E2\u10D4\u10E0\u10DE\u10E0\u10D4\u10E2\u10D0\u10EA\u10D8\u10D0), \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D0 (\u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8 \u10D2\u10D5\u10D4\u10EE\u10DB\u10D0\u10E0\u10D4\u10D1\u10D0 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0\u10D8 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10EE\u10D0\u10E0\u10D8\u10E1\u10EE\u10D4\u10D1\u10D0\u10E8\u10D8).","\u10EB\u10D8\u10DA\u10D8\u10E1 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10DD\u10D1\u10D0 \u10D0\u10D6\u10D8\u10D0\u10DC\u10D4\u10D1\u10E1 \u10E7\u10E3\u10E0\u10D0\u10D3\u10E6\u10D4\u10D1\u10D0\u10E1, \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1, \u10D8\u10DB\u10E3\u10DC\u10E3\u10E0 \u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10D0\u10E1 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0 \u10E0\u10D4\u10D2\u10E3\u10DA\u10D0\u10EA\u10D8\u10D0\u10E1. \u10EB\u10D8\u10DA\u10D8\u10E1 \u10E5\u10E0\u10DD\u10DC\u10D8\u10D9\u10E3\u10DA\u10D8 \u10E3\u10D9\u10DB\u10D0\u10E0\u10D8\u10E1\u10DD\u10D1\u10D0 \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10E1\u10D8\u10DB\u10E1\u10E3\u10E5\u10DC\u10D4\u10E1\u10D7\u10D0\u10DC, \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D0\u10E1\u10D7\u10D0\u10DC \u10D3\u10D0 \u10D2\u10E3\u10DA\u10D8\u10E1 \u10D3\u10D0\u10D0\u10D5\u10D0\u10D3\u10D4\u10D1\u10D4\u10D1\u10D7\u10D0\u10DC.","\u10F0\u10D8\u10DE\u10DC\u10DD\u10D6\u10D8 \u10D0\u10E0\u10D8\u10E1 \u10D2\u10D0\u10D6\u10E0\u10D3\u10D8\u10DA\u10D8 \u10E8\u10D7\u10D0\u10D2\u10DD\u10DC\u10D4\u10D1\u10D0\u10D3\u10DD\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10E7\u10E3\u10E0\u10D0\u10D3\u10E6\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0 \u2014 \u10D8\u10E1 \u10D0\u10E0 \u10D0\u10DC\u10D8\u10ED\u10D4\u10D1\u10E1 \u10F0\u10D8\u10DE\u10DC\u10DD\u10E2\u10D8\u10D6\u10D8\u10DD\u10E0\u10E1 \u10D7\u10E5\u10D5\u10D4\u10DC\u10D6\u10D4 \u10D9\u10DD\u10DC\u10E2\u10E0\u10DD\u10DA\u10E1. \u10DB\u10D0\u10E1 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0 \u10D3\u10D0\u10D4\u10EE\u10DB\u10D0\u10E0\u10DD\u10E1 \u10E2\u10D9\u10D8\u10D5\u10D8\u10DA\u10D8\u10E1 \u10DB\u10D0\u10E0\u10D7\u10D5\u10D0\u10E8\u10D8 \u10D3\u10D0 \u10D6\u10DD\u10D2\u10D8\u10D4\u10E0\u10D7 \u10E9\u10D5\u10D4\u10D5\u10D0\u10E1\u10D7\u10D0\u10DC \u10D2\u10D0\u10DB\u10D9\u10DA\u10D0\u10D5\u10D4\u10D1\u10D0\u10E8\u10D8.","\u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D8 \u10DC\u10D8\u10D5\u10D7\u10D8\u10D4\u10E0\u10D4\u10D1\u10D4\u10D1\u10D8 \u10DB\u10E3\u10E8\u10D0\u10DD\u10D1\u10D4\u10DC \u10DC\u10D4\u10D8\u10E0\u10DD\u10E2\u10E0\u10D0\u10DC\u10E1\u10DB\u10D8\u10E2\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E5\u10E2\u10D8\u10D5\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D1\u10D0\u10EB\u10D5\u10D8\u10D7, \u10D1\u10DA\u10DD\u10D9\u10D8\u10E0\u10D4\u10D1\u10D8\u10D7 \u10D0\u10DC \u10E8\u10D4\u10EA\u10D5\u10DA\u10D8\u10D7: \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D0\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8 (\u10D9\u10DD\u10E4\u10D4\u10D8\u10DC\u10D8, \u10D9\u10DD\u10D9\u10D0\u10D8\u10DC\u10D8), \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D0\u10DC\u10E2\u10D4\u10D1\u10D8 (\u10D0\u10DA\u10D9\u10DD\u10F0\u10DD\u10DA\u10D8, \u10D1\u10D0\u10E0\u10D1\u10D8\u10E2\u10E3\u10E0\u10D0\u10E2\u10D4\u10D1\u10D8), \u10DD\u10DE\u10D8\u10DD\u10D8\u10D3\u10D4\u10D1\u10D8 (\u10DB\u10DD\u10E0\u10E4\u10D8\u10DC\u10D8), \u10F0\u10D0\u10DA\u10E3\u10EA\u10D8\u10DC\u10DD\u10D2\u10D4\u10DC\u10D4\u10D1\u10D8 (LSD, \u10E4\u10E1\u10D8\u10DA\u10DD\u10EA\u10D8\u10D1\u10D8\u10DC\u10D8)."],ru:["\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043A\u043E\u043D\u0442\u0438\u043D\u0443\u0443\u043C\u0435: \u043E\u0442 \u043F\u043E\u043B\u043D\u043E\u0439 \u0431\u043E\u0434\u0440\u043E\u0441\u0442\u0438 \u0434\u043E \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430, \u0441\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 (\u043C\u0435\u0447\u0442\u044B, \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F, \u0433\u0438\u043F\u043D\u043E\u0437).","\u0421\u043E\u043D \u0438\u043C\u0435\u0435\u0442 \u0434\u0432\u0430 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u0442\u0438\u043F\u0430: NREM (\u0441\u0442\u0430\u0434\u0438\u0438 1\u20133, \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0443\u0433\u043B\u0443\u0431\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F) \u0438 REM (\u0431\u044B\u0441\u0442\u0440\u043E\u0435 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0433\u043B\u0430\u0437, \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u044F\u0440\u043A\u0438\u043C\u0438 \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438). \u041F\u043E\u043B\u043D\u044B\u0439 \u0446\u0438\u043A\u043B \u0434\u043B\u0438\u0442\u0441\u044F \u043E\u043A\u043E\u043B\u043E 90 \u043C\u0438\u043D\u0443\u0442.","\u0421\u0442\u0430\u0434\u0438\u044F 3 (\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0432\u043E\u043B\u043D\u043E\u0432\u043E\u0439/\u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D) \u0438\u043C\u0435\u0435\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0435\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0434\u043B\u044F \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u0438 \u0432\u044B\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0433\u043E\u0440\u043C\u043E\u043D\u0430 \u0440\u043E\u0441\u0442\u0430. REM-\u0441\u043E\u043D \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E \u0432\u0430\u0436\u0435\u043D \u0434\u043B\u044F \u043A\u043E\u043D\u0441\u043E\u043B\u0438\u0434\u0430\u0446\u0438\u0438 \u043F\u0430\u043C\u044F\u0442\u0438 \u0438 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0439 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438.","\u0422\u0435\u043E\u0440\u0438\u0438 \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u0439: \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u0439 \u043F\u043E \u0424\u0440\u0435\u0439\u0434\u0443 (\u0441\u043D\u044B \u0432\u044B\u0440\u0430\u0436\u0430\u044E\u0442 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F), \u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044F-\u0441\u0438\u043D\u0442\u0435\u0437 (\u0441\u043D\u044B \u2014 \u044D\u0442\u043E \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u044F \u043C\u043E\u0437\u0433\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0439\u043D\u043E\u0439 \u043D\u0435\u0439\u0440\u043E\u043D\u043D\u043E\u0439 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438), \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 (\u0441\u043D\u044B \u043F\u043E\u043C\u043E\u0433\u0430\u044E\u0442 \u0441\u043E\u0440\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F).","\u041D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u043A \u0441\u043D\u0430 \u0443\u0445\u0443\u0434\u0448\u0430\u0435\u0442 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435, \u043F\u0430\u043C\u044F\u0442\u044C, \u0438\u043C\u043C\u0443\u043D\u043D\u0443\u044E \u0444\u0443\u043D\u043A\u0446\u0438\u044E \u0438 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0443\u044E \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044E. \u0425\u0440\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043D\u0435\u0445\u0432\u0430\u0442\u043A\u0430 \u0441\u043D\u0430 \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 \u043E\u0436\u0438\u0440\u0435\u043D\u0438\u0435\u043C, \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0435\u0439 \u0438 \u0431\u043E\u043B\u0435\u0437\u043D\u044F\u043C\u0438 \u0441\u0435\u0440\u0434\u0446\u0430.","\u0413\u0438\u043F\u043D\u043E\u0437 \u2014 \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043F\u043E\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0439 \u0432\u043D\u0443\u0448\u0430\u0435\u043C\u043E\u0441\u0442\u0438 \u0438 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F, \u043E\u043D \u041D\u0415 \u0434\u0430\u0435\u0442 \u0433\u0438\u043F\u043D\u043E\u0442\u0438\u0437\u0435\u0440\u0443 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u043D\u0430\u0434 \u0432\u0430\u043C\u0438. \u041E\u043D \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043C\u043E\u0447\u044C \u0432 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u0431\u043E\u043B\u044C\u044E \u0438 \u0438\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u043E\u0442 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u0440\u0438\u0432\u044B\u0447\u0435\u043A.","\u041F\u0441\u0438\u0445\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u043F\u0443\u0442\u0435\u043C \u0438\u043C\u0438\u0442\u0430\u0446\u0438\u0438, \u0431\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0438\u043B\u0438 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 \u043D\u0435\u0439\u0440\u043E\u043C\u0435\u0434\u0438\u0430\u0442\u043E\u0440\u043E\u0432: \u0441\u0442\u0438\u043C\u0443\u043B\u044F\u0442\u043E\u0440\u044B (\u043A\u043E\u0444\u0435\u0438\u043D, \u043A\u043E\u043A\u0430\u0438\u043D), \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0430\u043D\u0442\u044B (\u0430\u043B\u043A\u043E\u0433\u043E\u043B\u044C, \u0431\u0430\u0440\u0431\u0438\u0442\u0443\u0440\u0430\u0442\u044B), \u043E\u043F\u0438\u043E\u0438\u0434\u044B (\u043C\u043E\u0440\u0444\u0438\u043D), \u0433\u0430\u043B\u043B\u044E\u0446\u0438\u043D\u043E\u0433\u0435\u043D\u044B (\u041B\u0421\u0414, \u043F\u0441\u0438\u043B\u043E\u0446\u0438\u0431\u0438\u043D)."],hy:["\u0533\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0563\u0578\u0575\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u056B \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561. \u056C\u056B\u0561\u0580\u056A\u0565\u0584 \u0561\u0580\u0569\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u056D\u0578\u0580\u0568 \u0584\u0578\u0582\u0576\u055D \u0562\u0561\u0566\u0574\u0561\u0569\u056B\u057E \u0574\u056B\u057B\u0561\u0576\u056F\u0575\u0561\u056C \u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u0578\u057E (\u0565\u0580\u0561\u0566\u056F\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0574\u0565\u0564\u056B\u057F\u0561\u0581\u056B\u0561\u0576, \u0570\u056B\u057A\u0576\u0578\u057D):","\u0554\u0578\u0582\u0576\u0576 \u0578\u0582\u0576\u056B \u0565\u0580\u056F\u0578\u0582 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0561\u056F\u055D NREM (1\u20133 \u0583\u0578\u0582\u056C\u0565\u0580, \u0561\u057D\u057F\u056B\u0573\u0561\u0576\u0561\u0562\u0561\u0580 \u0561\u057E\u0565\u056C\u056B \u056D\u0578\u0580\u0568) \u0587 REM (\u0561\u0579\u0584\u0565\u0580\u056B \u0561\u0580\u0561\u0563 \u0577\u0561\u0580\u056A\u0578\u0582\u0574, \u0578\u0580\u057F\u0565\u0572 \u0570\u0561\u0576\u0564\u0565\u057D \u0565\u0576 \u0563\u0561\u056C\u056B\u057D \u057E\u0561\u057C \u0565\u0580\u0561\u0566\u0576\u0565\u0580): \u053C\u0580\u056B\u057E \u0581\u056B\u056F\u056C\u0568 \u057F\u0587\u0578\u0582\u0574 \u0567 \u0574\u0578\u057F 90 \u0580\u0578\u057A\u0565:","3-\u0580\u0564 \u0583\u0578\u0582\u056C\u0568 (\u0564\u0561\u0576\u0564\u0561\u0572 \u0561\u056C\u056B\u0584\u0561\u0575\u056B\u0576/\u056D\u0578\u0580\u0568 \u0584\u0578\u0582\u0576) \u057E\u0573\u057C\u0578\u0580\u0578\u0577 \u0567 \u0586\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576 \u057E\u0565\u0580\u0561\u056F\u0561\u0576\u0563\u0576\u0574\u0561\u0576 \u0587 \u0561\u0573\u056B \u0570\u0578\u0580\u0574\u0578\u0576\u056B \u0561\u0580\u057F\u0561\u0566\u0561\u057F\u0574\u0561\u0576 \u0570\u0561\u0574\u0561\u0580: REM \u0584\u0578\u0582\u0576\u0568 \u056F\u0565\u0576\u057D\u0561\u056F\u0561\u0576 \u0576\u0577\u0561\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u056B \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0574\u0561\u0576 \u0587 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0561\u0575\u056B\u0576 \u0574\u0577\u0561\u056F\u0574\u0561\u0576 \u0570\u0561\u0574\u0561\u0580:","\u0535\u0580\u0561\u0566\u0576\u0565\u0580\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u0556\u0580\u0565\u0575\u0564\u056B \u0581\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u056B\u0580\u0561\u056F\u0561\u0576\u0561\u0581\u0578\u0582\u0574 (\u0565\u0580\u0561\u0566\u0576\u0565\u0580\u0576 \u0561\u0580\u057F\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574 \u0565\u0576 \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576 \u0581\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580), \u0531\u056F\u057F\u056B\u057E\u0561\u0581\u0578\u0582\u0574-\u057D\u056B\u0576\u0569\u0565\u0566 (\u0565\u0580\u0561\u0566\u0576\u0565\u0580\u0576 \u0578\u0582\u0572\u0565\u0572\u056B \u056F\u0578\u0572\u0574\u056B\u0581 \u057A\u0561\u057F\u0561\u0570\u0561\u056F\u0561\u0576 \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0561\u056F\u057F\u056B\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0565\u056F\u0576\u0561\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0565\u0576), \u054F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0577\u0561\u056F\u0578\u0582\u0574 (\u0565\u0580\u0561\u0566\u0576\u0565\u0580\u0576 \u0585\u0563\u0576\u0578\u0582\u0574 \u0565\u0576 \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u0565\u056C \u0561\u0574\u0565\u0576\u0585\u0580\u0575\u0561 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568):","\u0554\u0576\u056B \u057F\u0587\u0561\u056F\u0561\u0576 \u057A\u0561\u056F\u0561\u057D\u0568 \u057E\u0561\u057F\u0569\u0561\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u0578\u0582\u0577\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u056B\u0574\u0578\u0582\u0576\u0561\u0575\u056B\u0576 \u0586\u0578\u0582\u0576\u056F\u0581\u056B\u0561\u0576 \u0587 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0561\u0575\u056B\u0576 \u056F\u0561\u0580\u0563\u0561\u057E\u0578\u0580\u0578\u0582\u0574\u0568: \u0554\u0576\u056B \u0584\u0580\u0578\u0576\u056B\u056F \u056F\u0578\u0580\u0578\u0582\u057D\u057F\u0568 \u056F\u0561\u057A\u057E\u0561\u056E \u0567 \u0573\u0561\u0580\u057A\u0561\u056F\u0561\u056C\u0574\u0561\u0576, \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0587 \u057D\u0580\u057F\u0561\u0575\u056B\u0576 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0570\u0565\u057F:","\u0540\u056B\u057A\u0576\u0578\u057D\u0568 \u0562\u0561\u0580\u0571\u0580 \u0576\u0565\u0580\u0577\u0576\u0579\u057E\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u0581\u057E\u0561\u056E \u0578\u0582\u0577\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u056B\u0573\u0561\u056F \u0567, \u0561\u0575\u0576 \u0549\u053B \u057F\u0561\u056C\u056B\u057D \u0570\u056B\u057A\u0576\u0578\u057D\u0578\u0572\u056B\u0576 \u057E\u0565\u0580\u0561\u0570\u057D\u056F\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0571\u0565\u0580 \u057E\u0580\u0561: \u0531\u0575\u0576 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0585\u0563\u0576\u0565\u056C \u0581\u0561\u057E\u056B \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0574\u0561\u0576 \u0587 \u0578\u0580\u0578\u0577 \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0564\u0565\u057A\u0584\u0578\u0582\u0574:","\u0540\u0578\u0563\u0565\u0561\u056F\u057F\u056B\u057E \u0576\u0575\u0578\u0582\u0569\u0565\u0580\u0576 \u0561\u0577\u056D\u0561\u057F\u0578\u0582\u0574 \u0565\u0576 \u0576\u0574\u0561\u0576\u0561\u056F\u0565\u056C\u0578\u057E, \u0561\u0580\u0563\u0565\u056C\u0561\u0583\u0561\u056F\u0565\u056C\u0578\u057E \u056F\u0561\u0574 \u0583\u0578\u056D\u0565\u056C\u0578\u057E \u0576\u0565\u0575\u0580\u0578\u0570\u0561\u0572\u0578\u0580\u0564\u056B\u0579\u0576\u0565\u0580\u056B \u0561\u056F\u057F\u056B\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568. \u056D\u0569\u0561\u0576\u056B\u0579\u0576\u0565\u0580 (\u056F\u0578\u0586\u0565\u056B\u0576, \u056F\u0578\u056F\u0561\u056B\u0576), \u0564\u0565\u057A\u0580\u0565\u057D\u0561\u0576\u057F\u0576\u0565\u0580 (\u0561\u056C\u056F\u0578\u0570\u0578\u056C, \u0562\u0561\u0580\u0562\u056B\u057F\u0578\u0582\u0580\u0561\u057F\u0576\u0565\u0580), \u0585\u0583\u056B\u0578\u056B\u0564\u0576\u0565\u0580 (\u0574\u0578\u0580\u0586\u056B\u0576), \u0570\u0561\u056C\u0575\u0578\u0582\u0581\u056B\u0576\u0578\u0563\u0565\u0576\u0576\u0565\u0580 (LSD, \u057A\u057D\u056B\u056C\u0578\u0581\u056B\u0562\u056B\u0576):"],az:["\u015E\xFCur bir spektrd\u0259 m\xF6vcuddur: tam oyaq olmaqdan d\u0259rin yuxuya q\u0259d\u0259r, aralar\u0131nda bir \xE7ox v\u0259ziyy\u0259tl\u0259rl\u0259 (qarabasma, meditasiya, hipnoz).","Yuxunun iki \u0259sas n\xF6v\xFC var: NREM (m\u0259rh\u0259l\u0259 1-3, getdikc\u0259 d\u0259rinl\u0259\u015F\u0259n) v\u0259 REM (s\xFCr\u0259tli g\xF6z h\u0259r\u0259k\u0259ti, burada canl\u0131 yuxular ba\u015F verir). Tam bir tsikl t\u0259xmin\u0259n 90 d\u0259qiq\u0259 davam edir.","M\u0259rh\u0259l\u0259 3 (yava\u015F dal\u011Fal\u0131/d\u0259rin yuxu) fiziki b\u0259rpa v\u0259 b\xF6y\xFCm\u0259 hormonunun ifraz\u0131 \xFC\xE7\xFCn \xE7ox vacibdir. REM yuxusu yadda\u015F\u0131n m\xF6hk\u0259ml\u0259ndirilm\u0259si v\u0259 emosional emal \xFC\xE7\xFCn h\u0259yati \u0259h\u0259miyy\u0259t da\u015F\u0131y\u0131r.","Yuxu n\u0259z\u0259riyy\u0259l\u0259ri: Freydin arzu realla\u015Fd\u0131rmas\u0131 (yuxular \u015F\xFCuralt\u0131 ist\u0259kl\u0259ri ifad\u0259 edir), Aktivasiya-sintez (yuxular beynin t\u0259sad\xFCfi neyron f\u0259aliyy\u0259tini \u015F\u0259rh etm\u0259sidir), M\u0259lumat emal\u0131 (yuxular g\xFCnd\u0259lik xatir\u0259l\u0259ri \xE7e\u015Fidl\u0259m\u0259y\u0259 k\xF6m\u0259k edir).","Yuxusuzluq diqq\u0259ti, yadda\u015F\u0131, immun funksiyas\u0131n\u0131 v\u0259 emosional t\u0259nziml\u0259m\u0259ni z\u0259ifl\u0259dir. Xroniki yuxu itkisi obezite, depressiya v\u0259 \xFCr\u0259k x\u0259st\u0259likl\u0259ri il\u0259 \u0259laq\u0259l\u0259ndirilir.","Hipnoz artan t\u0259lqin v\u0259 c\u0259ml\u0259nmi\u015F diqq\u0259t v\u0259ziyy\u0259tidir \u2014 bu, hipnoz\xE7uya sizin \xFCz\u0259rinizd\u0259 n\u0259zar\u0259t VERM\u0130R. A\u011Fr\u0131n\u0131n idar\u0259 olunmas\u0131na v\u0259 b\u0259zi v\u0259rdi\u015Fl\u0259r\u0259 k\xF6m\u0259k ed\u0259 bil\u0259r.","Psixoaktiv madd\u0259l\u0259r neyrotransmitter f\u0259aliyy\u0259tini t\u0259qlid ed\u0259r\u0259k, bloklayaraq v\u0259 ya d\u0259yi\u015Fdir\u0259r\u0259k i\u015Fl\u0259yir: stimulyatorlar (kofein, kokain), depressantlar (alkoqol, barbituratlar), opioidl\u0259r (morfin), hall\xFCsinogenl\u0259r (LSD, psilosibin)."]},funFact:{en:"During REM sleep, your brain paralyzes your voluntary muscles (atonia) so you don't physically act out your dreams. When this system fails, people develop REM Sleep Behavior Disorder and may punch, kick, or jump out of bed while dreaming.",ka:'\u10EB\u10D8\u10DA\u10D8\u10E1 \u10D3\u10E0\u10DD\u10E1 \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E2\u10D5\u10D8\u10DC\u10D8 \u10D2\u10D0\u10D3\u10D0\u10D3\u10D8\u10E1 "\u10E1\u10D0\u10DC\u10D8\u10E2\u10D0\u10E0\u10E3\u10DA" \u10E0\u10D4\u10DF\u10D8\u10DB\u10E8\u10D8, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10EC\u10DB\u10D4\u10DC\u10D3\u10E1 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10E1 \u10D3\u10D0 \u10D0\u10EB\u10DA\u10D8\u10D4\u10E0\u10D4\u10D1\u10E1 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1.',ru:"\u0412\u043E \u0432\u0440\u0435\u043C\u044F \u0441\u043D\u0430 \u043D\u0430\u0448 \u043C\u043E\u0437\u0433 \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0438\u0442 \u0432 \xAB\u0441\u0430\u043D\u0438\u0442\u0430\u0440\u043D\u044B\u0439\xBB \u0440\u0435\u0436\u0438\u043C, \u043E\u0447\u0438\u0449\u0430\u044F \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u0443\u044E \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E \u0438 \u0443\u043A\u0440\u0435\u043F\u043B\u044F\u044F \u043F\u0430\u043C\u044F\u0442\u044C.",hy:"\u0554\u0576\u056B \u056A\u0561\u0574\u0561\u0576\u0561\u056F \u0574\u0565\u0580 \u0578\u0582\u0572\u0565\u0572\u0576 \u0561\u0576\u0581\u0576\u0578\u0582\u0574 \u0567 \xAB\u057D\u0561\u0576\u056B\u057F\u0561\u0580\u0561\u056F\u0561\u0576\xBB \u057C\u0565\u056A\u056B\u0574\u056B, \u0578\u0580\u0568 \u0574\u0561\u0584\u0580\u0578\u0582\u0574 \u0567 \u0561\u0574\u0565\u0576\u0585\u0580\u0575\u0561 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:",az:'Yuxu zaman\u0131 beynimiz g\xFCnd\u0259lik m\u0259lumatlar\u0131 t\u0259mizl\u0259y\u0259n v\u0259 yadda\u015F\u0131 m\xF6hk\u0259ml\u0259ndir\u0259n "sanitariya" rejimin\u0259 ke\xE7ir.'},realWorld:{en:"Understanding sleep stages has transformed shift work policies. Many hospitals and airlines now mandate minimum rest periods because research proved that sleep-deprived professionals make as many errors as intoxicated ones.",ka:"\u10DB\u10D4\u10DA\u10D0\u10E2\u10DD\u10DC\u10D8\u10DC\u10D8\u10E1 \u10D3\u10D0\u10DC\u10D0\u10DB\u10D0\u10E2\u10D4\u10D1\u10D8 \u10D2\u10D0\u10DB\u10DD\u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D0 \u10EA\u10D8\u10E0\u10D9\u10D0\u10D3\u10E3\u10DA\u10D8 \u10E0\u10D8\u10E2\u10DB\u10D8\u10E1 \u10D3\u10D0\u10E1\u10D0\u10E0\u10D4\u10D2\u10E3\u10DA\u10D8\u10E0\u10D4\u10D1\u10DA\u10D0\u10D3 \u10E0\u10D4\u10D0\u10E5\u10E2\u10D8\u10E3\u10DA\u10D8 \u10D7\u10D5\u10D8\u10D7\u10DB\u10E4\u10E0\u10D8\u10DC\u10D0\u10D5\u10D8\u10E1 \u10D3\u10D0\u10D2\u10D5\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8\u10E1 (jet lag) \u10D3\u10E0\u10DD\u10E1.",ru:"\u0414\u043E\u0431\u0430\u0432\u043A\u0438 \u043C\u0435\u043B\u0430\u0442\u043E\u043D\u0438\u043D\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442\u0441\u044F \u0434\u043B\u044F \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0446\u0438\u0440\u043A\u0430\u0434\u043D\u043E\u0433\u043E \u0440\u0438\u0442\u043C\u0430 \u043F\u0440\u0438 \u10E1\u10DB\u10D4\u10DC\u10D0 \u0447\u0430\u0441\u043E\u0432\u044B\u0445 \u043F\u043E\u044F\u0441\u043E\u0432 (\u0434\u0436\u0435\u0442\u043B\u0430\u0433).",hy:"\u0544\u0565\u056C\u0561\u057F\u0578\u0576\u056B\u0576\u056B \u0570\u0561\u057E\u0565\u056C\u0578\u0582\u0574\u0576\u0565\u0580\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u057E\u0578\u0582\u0574 \u0565\u0576 \u0581\u056B\u0580\u056F\u0561\u0564\u0561\u0575\u056B\u0576 \u057C\u056B\u0569\u0574\u0568 \u056F\u0561\u0580\u0563\u0561\u057E\u0578\u0580\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580\u055D \u056A\u0561\u0574\u0561\u0575\u056B\u0576 \u0563\u0578\u057F\u056B\u0576\u0565\u0580\u056B \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0561\u0576 (jet lag) \u056A\u0561\u0574\u0561\u0576\u0561\u056F:",az:"Melatonin \u0259lav\u0259l\u0259ri reaktiv t\u0259yyar\u0259 gecikm\u0259si (jet lag) zaman\u0131 sirkad ritmi t\u0259nziml\u0259m\u0259k \xFC\xE7\xFCn istifad\u0259 olunur."}},6:{title:{en:"Learning",ka:"\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0",ru:"\u041E\u0431\u0443\u0447\u0435\u043D\u0438\u0435",hy:"\u0548\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574",az:"\xD6yr\u0259nm\u0259"},description:{en:"Classical conditioning, operant conditioning, and observational learning.",ka:"\u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0, \u10DD\u10DE\u10D4\u10E0\u10D0\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D8\u10D7\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0.",ru:"\u041A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435, \u043E\u043F\u0435\u0440\u0430\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435 \u0438 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0435.",hy:"\u0534\u0561\u057D\u0561\u056F\u0561\u0576 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574, \u0585\u057A\u0565\u0580\u0561\u0576\u057F \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0587 \u0564\u056B\u057F\u0578\u0572\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574:",az:"Klassik kondisioner, operant kondisioner v\u0259 m\xFC\u015Fahid\u0259 \xF6yr\u0259nm\u0259."},keyTopics:{en:["Classical Conditioning","Operant Conditioning","Reinforcement & Punishment","Observational Learning"],ka:["\u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0","\u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0","\u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D3\u10D0\u10E1\u10EF\u10D0","\u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D8\u10D7\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0"],ru:["\u041A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043A\u043E\u043D\u0434\u0438\u0446\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435","\u041E\u043F\u0435\u0440\u0430\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435","\u041F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435 \u0438 \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435","\u041D\u0430\u0431\u043B\u044E\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435"],hy:["\u0534\u0561\u057D\u0561\u056F\u0561\u0576 \u056F\u0578\u0576\u0564\u056B\u0581\u056B\u0578\u0576\u0565\u0580","\u0533\u0578\u0580\u056E\u0578\u0572 \u0585\u0564\u0561\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0531\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574 \u0587 \u057A\u0561\u057F\u056B\u056A","\u0534\u056B\u057F\u0578\u0580\u0564\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574"],az:["Classic conditioning","Operant conditioning","Observational learning"]},summary:{en:"Learning is a relatively permanent change in behavior or knowledge that results from experience. This chapter covers three major learning paradigms that explain how organisms acquire new behaviors. Classical conditioning, discovered by Ivan Pavlov through his famous experiments with dogs, explains how we learn to associate two stimuli \u2014 producing automatic responses like fear, cravings, or emotional reactions. Operant conditioning, developed by B.F. Skinner, shows how behavior is shaped by its consequences: reinforcement (positive and negative) increases behavior, while punishment decreases it. The chapter details reinforcement schedules (fixed-ratio, variable-ratio, fixed-interval, variable-interval) and their different effects on behavior persistence. Albert Bandura's social learning theory demonstrates that learning also occurs through observation and modeling, as shown in his famous Bobo doll experiment. The chapter also covers cognitive learning concepts including latent learning, insight learning, and cognitive maps, revealing that learning involves far more than simple stimulus-response associations.",ka:"\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D0\u10D3 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D0\u10DC \u10EA\u10DD\u10D3\u10DC\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D0\u10E0\u10D4\u10D1\u10D8\u10D7 \u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10D8 \u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D0. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10E4\u10D0\u10E0\u10D0\u10D5\u10E1 \u10E1\u10D0\u10DB \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10E1\u10D0\u10E1\u10EC\u10D0\u10D5\u10DA\u10DD \u10DE\u10D0\u10E0\u10D0\u10D3\u10D8\u10D2\u10DB\u10D0\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10EE\u10E1\u10DC\u10D8\u10D0\u10DC, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D8\u10EB\u10D4\u10DC\u10D4\u10DC \u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10DB\u10D4\u10D1\u10D8 \u10D0\u10EE\u10D0\u10DA \u10E5\u10EA\u10D4\u10D5\u10D4\u10D1\u10E1. \u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E6\u10DB\u10DD\u10D0\u10E9\u10D8\u10DC\u10D0 \u10D8\u10D5\u10D0\u10DC \u10DE\u10D0\u10D5\u10DA\u10DD\u10D5\u10DB\u10D0 \u10EB\u10D0\u10E6\u10DA\u10D4\u10D1\u10D6\u10D4 \u10D7\u10D0\u10D5\u10D8\u10E1\u10D8 \u10EA\u10DC\u10DD\u10D1\u10D8\u10DA\u10D8 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7, \u10EE\u10E1\u10DC\u10D8\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10E1\u10EC\u10D0\u10D5\u10DA\u10DD\u10D1\u10D7 \u10DD\u10E0\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D8\u10E1 \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1 \u2014 \u10E0\u10D0\u10EA \u10D8\u10EC\u10D5\u10D4\u10D5\u10E1 \u10D0\u10D5\u10E2\u10DD\u10DB\u10D0\u10E2\u10E3\u10E0 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D4\u10D1\u10E1, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10E8\u10D8\u10E8\u10D8, \u10DA\u10E2\u10DD\u10DA\u10D5\u10D0 \u10D0\u10DC \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D4\u10D1\u10D8. \u10DD\u10DE\u10D4\u10E0\u10D0\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0, \u10E8\u10D4\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D1.\u10E4. \u10E1\u10D9\u10D8\u10DC\u10D4\u10E0\u10D8\u10E1 \u10DB\u10D8\u10D4\u10E0, \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10E7\u10D0\u10DA\u10D8\u10D1\u10D3\u10D4\u10D1\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D0 \u10DB\u10D8\u10E1\u10D8 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10D8\u10D7: \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0 (\u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10DC\u10D4\u10D2\u10D0\u10E2\u10D8\u10E3\u10E0\u10D8) \u10D6\u10E0\u10D3\u10D8\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1, \u10EE\u10DD\u10DA\u10DD \u10D3\u10D0\u10E1\u10EF\u10D0 \u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10DB\u10D0\u10E1. \u10D7\u10D0\u10D5\u10D8 \u10D3\u10D4\u10E2\u10D0\u10DA\u10E3\u10E0\u10D0\u10D3 \u10D0\u10E6\u10EC\u10D4\u10E0\u10E1 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D8\u10E1 \u10D2\u10E0\u10D0\u10E4\u10D8\u10D9\u10D4\u10D1\u10E1 (\u10E4\u10D8\u10E5\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D7\u10D0\u10DC\u10D0\u10E4\u10D0\u10E0\u10D3\u10DD\u10D1\u10D0, \u10EA\u10D5\u10DA\u10D0\u10D3\u10D8 \u10D7\u10D0\u10DC\u10D0\u10E4\u10D0\u10E0\u10D3\u10DD\u10D1\u10D0, \u10E4\u10D8\u10E5\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D0\u10DA\u10D8, \u10EA\u10D5\u10DA\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D0\u10DA\u10D8) \u10D3\u10D0 \u10DB\u10D0\u10D7 \u10E1\u10EE\u10D5\u10D0\u10D3\u10D0\u10E1\u10EE\u10D5\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10D3\u10D2\u10E0\u10D0\u10D3\u10DD\u10D1\u10D0\u10D6\u10D4. \u10D0\u10DA\u10D1\u10D4\u10E0\u10E2 \u10D1\u10D0\u10DC\u10D3\u10E3\u10E0\u10D0\u10E1 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10EE\u10D3\u10D4\u10D1\u10D0 \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D6\u10D8\u10D7, \u10E0\u10DD\u10D2\u10DD\u10E0\u10EA \u10D4\u10E1 \u10DC\u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10D8\u10D0 \u10DB\u10D8\u10E1 \u10EA\u10DC\u10DD\u10D1\u10D8\u10DA \u10D1\u10DD\u10D1\u10DD\u10E1 \u10D7\u10DD\u10EF\u10D8\u10DC\u10D8\u10E1 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10E8\u10D8. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D8\u10E1 \u10D9\u10DD\u10DC\u10EA\u10D4\u10E4\u10EA\u10D8\u10D4\u10D1\u10E1, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10DA\u10D0\u10E2\u10D4\u10DC\u10E2\u10E3\u10E0 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10E1, \u10D8\u10DC\u10E1\u10D0\u10D8\u10E2\u10E3\u10E0 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10E1 \u10D3\u10D0 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0 \u10E0\u10E3\u10E5\u10D4\u10D1\u10E1, \u10E0\u10D0\u10EA \u10D0\u10D5\u10DA\u10D4\u10DC\u10E1 \u10D8\u10DB\u10D0\u10E1, \u10E0\u10DD\u10DB \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10E8\u10D4\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D1\u10D4\u10D5\u10E0\u10D0\u10D3 \u10DB\u10D4\u10E2\u10E1, \u10D5\u10D8\u10D3\u10E0\u10D4 \u10E3\u10D1\u10E0\u10D0\u10DA\u10DD \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA-\u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D8\u10E1 \u10D0\u10E1\u10DD\u10EA\u10D8\u10D0\u10EA\u10D8\u10D4\u10D1\u10D8\u10D0.",ru:"\u041E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0438\u043B\u0438 \u0437\u043D\u0430\u043D\u0438\u0439, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u043E\u043F\u044B\u0442\u0430. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0442\u0440\u0438 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043F\u0430\u0440\u0430\u0434\u0438\u0433\u043C\u044B \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F, \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u044E\u0449\u0438\u0435, \u043A\u0430\u043A \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C\u044B \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442 \u043D\u043E\u0432\u044B\u0435 \u0444\u043E\u0440\u043C\u044B \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F. \u041A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435, \u043E\u0442\u043A\u0440\u044B\u0442\u043E\u0435 \u0418\u0432\u0430\u043D\u043E\u043C \u041F\u0430\u0432\u043B\u043E\u0432\u044B\u043C \u0432 \u0445\u043E\u0434\u0435 \u0435\u0433\u043E \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u0445 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u043E\u0432 \u0441 \u0441\u043E\u0431\u0430\u043A\u0430\u043C\u0438, \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442, \u043A\u0430\u043A \u043C\u044B \u0443\u0447\u0438\u043C\u0441\u044F \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u0442\u044C \u0434\u0432\u0430 \u0441\u0442\u0438\u043C\u0443\u043B\u0430, \u0432\u044B\u0437\u044B\u0432\u0430\u044F \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0435\u0430\u043A\u0446\u0438\u0438, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0441\u0442\u0440\u0430\u0445, \u0442\u044F\u0433\u0430 \u0438\u043B\u0438 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u043E\u0442\u0432\u0435\u0442\u044B. \u041E\u043F\u0435\u0440\u0430\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u043E\u0435 \u0411.\u0424. \u0421\u043A\u0438\u043D\u043D\u0435\u0440\u043E\u043C, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u043A\u0430\u043A \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0435\u0433\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F\u043C\u0438: \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435 (\u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u043E\u0435) \u0443\u0441\u0438\u043B\u0438\u0432\u0430\u0435\u0442 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u0435\u0433\u043E \u043E\u0441\u043B\u0430\u0431\u043B\u044F\u0435\u0442. \u0412 \u0433\u043B\u0430\u0432\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u044B \u0440\u0435\u0436\u0438\u043C\u044B \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u044F (\u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0441\u043E\u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u043F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u0444\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B, \u043F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B) \u0438 \u0438\u0445 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u043E\u0435 \u0432\u043B\u0438\u044F\u043D\u0438\u0435 \u043D\u0430 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F. \u0422\u0435\u043E\u0440\u0438\u044F \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F \u0410\u043B\u044C\u0431\u0435\u0440\u0442\u0430 \u0411\u0430\u043D\u0434\u0443\u0440\u044B \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442, \u0447\u0442\u043E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0442\u0430\u043A\u0436\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u044F \u0438 \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u043A\u0430\u043A \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u0435\u0433\u043E \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u043E\u043C \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0435 \u0441 \u043A\u0443\u043A\u043B\u043E\u0439 \u0411\u043E\u0431\u043E. \u0413\u043B\u0430\u0432\u0430 \u0442\u0430\u043A\u0436\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435, \u0438\u043D\u0441\u0430\u0439\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0438 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u043A\u0430\u0440\u0442\u044B, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044F, \u0447\u0442\u043E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0432 \u0441\u0435\u0431\u044F \u0433\u043E\u0440\u0430\u0437\u0434\u043E \u0431\u043E\u043B\u044C\u0448\u0435, \u0447\u0435\u043C \u043F\u0440\u043E\u0441\u0442\u044B\u0435 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u0438 \xAB\u0441\u0442\u0438\u043C\u0443\u043B-\u0440\u0435\u0430\u043A\u0446\u0438\u044F\xBB.",hy:"\u0548\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u056F\u0561\u0574 \u0563\u056B\u057F\u0565\u056C\u056B\u0584\u056B \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0561\u0562\u0561\u0580 \u0574\u0577\u057F\u0561\u056F\u0561\u0576 \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0567, \u0578\u0580\u0576 \u0561\u057C\u0561\u057B\u0561\u0576\u0578\u0582\u0574 \u0567 \u0583\u0578\u0580\u0571\u056B \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0578\u0582\u0574: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u0565\u0580\u0565\u0584 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057A\u0561\u0580\u0561\u0564\u056B\u0563\u0574\u0576\u0565\u0580, \u0578\u0580\u0578\u0576\u0584 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0565\u0576, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0585\u0580\u0563\u0561\u0576\u056B\u0566\u0574\u0576\u0565\u0580\u0568 \u0571\u0565\u057C\u0584 \u0562\u0565\u0580\u0578\u0582\u0574 \u0576\u0578\u0580 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E: \u0534\u0561\u057D\u0561\u056F\u0561\u0576 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574\u0568, \u0578\u0580\u0568 \u0570\u0561\u0575\u057F\u0576\u0561\u0562\u0565\u0580\u0565\u056C \u0567 \u053B\u057E\u0561\u0576 \u054A\u0561\u057E\u056C\u0578\u057E\u0568 \u0577\u0576\u0565\u0580\u056B \u0570\u0565\u057F \u056B\u0580 \u0570\u0561\u0575\u057F\u0576\u056B \u0583\u0578\u0580\u0571\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E, \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0574 \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u0565\u056C \u0565\u0580\u056F\u0578\u0582 \u056D\u0569\u0561\u0576\u055D \u0561\u057C\u0561\u057B\u0561\u0581\u0576\u0565\u056C\u0578\u057E \u0561\u057E\u057F\u0578\u0574\u0561\u057F \u057C\u0565\u0561\u056F\u0581\u056B\u0561\u0576\u0565\u0580, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u057E\u0561\u056D\u0568, \u0581\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0574 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0561\u0575\u056B\u0576 \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0576\u0565\u0580\u0568: \u0555\u057A\u0565\u0580\u0561\u0576\u057F \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574\u0568, \u0578\u0580\u0568 \u0574\u0577\u0561\u056F\u057E\u0565\u056C \u0567 \u0532.\u0556. \u054D\u056F\u056B\u0576\u0565\u0580\u056B \u056F\u0578\u0572\u0574\u056B\u0581, \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568 \u0571\u0587\u0561\u057E\u0578\u0580\u057E\u0578\u0582\u0574 \u056B\u0580 \u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0576\u0565\u0580\u0578\u057E. \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574\u0568 (\u0564\u0580\u0561\u056F\u0561\u0576 \u0587 \u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576) \u0574\u0565\u056E\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568, \u0574\u056B\u0576\u0579\u0564\u0565\u057C \u057A\u0561\u057F\u056B\u056A\u0568 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u0561\u0575\u0576: \u0533\u056C\u0578\u0582\u056D\u0568 \u0574\u0561\u0576\u0580\u0561\u0574\u0561\u057D\u0576\u0578\u0582\u0574 \u0567 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0574\u0561\u0576 \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u0581\u0578\u0582\u0575\u0581\u0565\u0580\u0568 (\u0586\u056B\u0584\u057D\u057E\u0561\u056E \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0583\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576 \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0586\u056B\u0584\u057D\u057E\u0561\u056E \u0568\u0576\u0564\u0574\u056B\u057B\u0578\u0582\u0574, \u0583\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576 \u0568\u0576\u0564\u0574\u056B\u057B\u0578\u0582\u0574) \u0587 \u0564\u0580\u0561\u0576\u0581 \u057F\u0561\u0580\u0562\u0565\u0580 \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u056F\u0561\u0575\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561: \u0531\u056C\u0562\u0565\u0580\u057F \u0532\u0561\u0576\u0564\u0578\u0582\u0580\u0561\u0575\u056B \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568 \u057F\u0565\u0572\u056B \u0567 \u0578\u0582\u0576\u0565\u0576\u0578\u0582\u0574 \u0576\u0561\u0587 \u0564\u056B\u057F\u0561\u0580\u056F\u0574\u0561\u0576 \u0587 \u0574\u0578\u0564\u0565\u056C\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u0574\u056B\u057B\u0578\u0581\u0578\u057E, \u056B\u0576\u0579\u057A\u0565\u057D \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0580\u057E\u0561\u056E \u0532\u0578\u0562\u0578 \u057F\u056B\u056F\u0576\u056B\u056F\u056B \u056B\u0580 \u0570\u0561\u0575\u057F\u0576\u056B \u0583\u0578\u0580\u0571\u056B \u0574\u0565\u057B: \u0533\u056C\u0578\u0582\u056D\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0576\u0561\u0587 \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u0570\u0561\u057D\u056F\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568\u055D \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0569\u0561\u0584\u0576\u057E\u0561\u056E \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568, \u056B\u0576\u057D\u0561\u0575\u0569\u0561\u0575\u056B\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568 \u0587 \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0584\u0561\u0580\u057F\u0565\u0566\u0576\u0565\u0580\u0568, \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0565\u056C\u0578\u057E, \u0578\u0580 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568 \u0577\u0561\u057F \u0561\u057E\u0565\u056C\u056B\u0576 \u0567, \u0584\u0561\u0576 \u057A\u0561\u0580\u0566\u0561\u057A\u0565\u057D \u056D\u0569\u0561\u0576-\u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584 \u0561\u057D\u0578\u0581\u056B\u0561\u0581\u056B\u0561\u0576\u0565\u0580\u0568:",az:"\xD6yr\u0259nm\u0259 t\u0259cr\xFCb\u0259 n\u0259tic\u0259sind\u0259 davran\u0131\u015Fda v\u0259 ya bilikd\u0259 nisb\u0259t\u0259n daimi d\u0259yi\u015Fiklikdir. Bu f\u0259sil orqanizml\u0259rin yeni davran\u0131\u015Flar\u0131 nec\u0259 m\u0259nims\u0259diyini izah ed\u0259n \xFC\xE7 \u0259sas \xF6yr\u0259nm\u0259 paradiqmas\u0131n\u0131 \u0259hat\u0259 edir. \u0130van Pavlov t\u0259r\u0259find\u0259n itl\u0259rl\u0259 apard\u0131\u011F\u0131 m\u0259\u015Fhur t\u0259cr\xFCb\u0259l\u0259rl\u0259 k\u0259\u015Ff edil\u0259n klassik kondisioner, qorxu, h\u0259v\u0259s v\u0259 ya emosional reaksiyalar kimi avtomatik cavablar yaradaraq iki stimulu nec\u0259 \u0259laq\u0259l\u0259ndirm\u0259yi \xF6yr\u0259ndiyimizi izah edir. B.F. Skinner t\u0259r\u0259find\u0259n inki\u015Faf etdiril\u0259n operant kondisioner davran\u0131\u015F\u0131n n\u0259tic\u0259l\u0259ri il\u0259 nec\u0259 formala\u015Fd\u0131\u011F\u0131n\u0131 g\xF6st\u0259rir: g\xFCcl\u0259ndirm\u0259 (m\xFCsb\u0259t v\u0259 m\u0259nfi) davran\u0131\u015F\u0131 art\u0131r\u0131r, c\u0259zaland\u0131rma is\u0259 onu azald\u0131r. F\u0259sil g\xFCcl\u0259ndirm\u0259 c\u0259dv\u0259ll\u0259rini (sabit nisb\u0259t, d\u0259yi\u015F\u0259n nisb\u0259t, sabit interval, d\u0259yi\u015F\u0259n interval) v\u0259 onlar\u0131n davran\u0131\u015F\u0131n davaml\u0131l\u0131\u011F\u0131na f\u0259rqli t\u0259sirl\u0259rini t\u0259f\u0259rr\xFCatland\u0131r\u0131r. Albert Banduran\u0131n sosial \xF6yr\u0259nm\u0259 n\u0259z\u0259riyy\u0259si, onun m\u0259\u015Fhur Bobo g\u0259linciyi t\u0259cr\xFCb\u0259sind\u0259 g\xF6st\u0259rildiyi kimi, \xF6yr\u0259nm\u0259nin h\u0259m d\u0259 m\xFC\u015Fahid\u0259 v\u0259 modell\u0259\u015Fdirm\u0259 yolu il\u0259 ba\u015F verdiyini n\xFCmayi\u015F etdirir. F\u0259sil eyni zamanda gizli \xF6yr\u0259nm\u0259, d\u0259rk ed\u0259r\u0259k \xF6yr\u0259nm\u0259 v\u0259 koqnitiv x\u0259rit\u0259l\u0259r d\u0259 daxil olmaqla koqnitiv \xF6yr\u0259nm\u0259 konsepsiyalar\u0131n\u0131 \u0259hat\u0259 edir v\u0259 \xF6yr\u0259nm\u0259nin sad\u0259 stimul-cavab assosiasiyalar\u0131ndan daha \xE7oxunu ehtiva etdiyini ortaya qoyur."},keyPoints:{en:["Classical conditioning (Pavlov): learning through association of stimuli. A neutral stimulus (e.g., a bell) is repeatedly paired with an unconditioned stimulus (e.g., food) that naturally triggers an unconditioned response (salivation). Eventually, the neutral stimulus alone becomes a conditioned stimulus triggering the conditioned response. Key processes include acquisition, extinction, spontaneous recovery, generalization, and discrimination.",'Operant conditioning (Skinner): learning through consequences. Behavior followed by reinforcement increases in frequency; behavior followed by punishment decreases. Skinner demonstrated these principles using his operant chamber ("Skinner Box"), where animals learned to press levers or peck keys for food rewards.',"Positive vs. negative reinforcement: Positive reinforcement adds something desirable (a treat for good behavior); negative reinforcement removes something unpleasant (aspirin removes a headache). Both increase the likelihood of the behavior being repeated. Importantly, negative reinforcement is NOT the same as punishment.","Reinforcement schedules determine learning speed and resistance to extinction: Fixed-ratio (reward after set number of responses), Variable-ratio (reward after unpredictable number \u2014 produces highest, steadiest rates and is hardest to extinguish), Fixed-interval (reward after set time period), and Variable-interval (reward after unpredictable time periods).","Punishment decreases behavior: Positive punishment adds something unpleasant (a speeding ticket), while negative punishment removes something desirable (taking away phone privileges). Research shows punishment is most effective when immediate, consistent, and paired with reinforcement of alternative desirable behaviors.","Observational learning (Bandura): we learn by watching and imitating models. Bandura's famous Bobo doll experiment showed children who watched an adult act aggressively toward an inflatable doll were significantly more likely to imitate that aggression. This process involves attention, retention, motor reproduction, and motivation (vicarious reinforcement).","Cognitive learning extends beyond simple conditioning: Tolman demonstrated latent learning (learning that occurs but is not shown until motivation arises) through rat maze experiments. Kohler documented insight learning in chimpanzees \u2014 sudden problem-solving without trial and error. These findings show that internal mental processes play a crucial role in learning."],ka:["\u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0 (\u10DE\u10D0\u10D5\u10DA\u10DD\u10D5\u10D8): \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E1\u10DD\u10EA\u10D8\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D2\u10D6\u10D8\u10D7. \u10DC\u10D4\u10D8\u10E2\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D8 (\u10DB\u10D0\u10D2., \u10D6\u10D0\u10E0\u10D8) \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10EF\u10D4\u10E0\u10D0\u10D3\u10D0\u10D3 \u10E3\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D0\u10DE\u10D8\u10E0\u10DD\u10D1\u10D8\u10D7 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10E1 (\u10DB\u10D0\u10D2., \u10E1\u10D0\u10D9\u10D5\u10D4\u10D1\u10E1), \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D1\u10E3\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5\u10D0\u10D3 \u10D8\u10EC\u10D5\u10D4\u10D5\u10E1 \u10D0\u10E0\u10D0\u10DE\u10D8\u10E0\u10DD\u10D1\u10D8\u10D7 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0\u10E1 (\u10DC\u10D4\u10E0\u10EC\u10E7\u10D5\u10D3\u10D4\u10DC\u10D0\u10E1). \u10E1\u10D0\u10D1\u10DD\u10DA\u10DD\u10DD\u10D3, \u10DB\u10EE\u10DD\u10DA\u10DD\u10D3 \u10DC\u10D4\u10D8\u10E2\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D8 \u10EE\u10D3\u10D4\u10D1\u10D0 \u10DE\u10D8\u10E0\u10DD\u10D1\u10D8\u10D7\u10D8 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D8, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D8\u10EC\u10D5\u10D4\u10D5\u10E1 \u10DE\u10D8\u10E0\u10DD\u10D1\u10D8\u10D7 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0\u10E1. \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D4\u10D1\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E8\u10D4\u10EB\u10D4\u10DC\u10D0\u10E1, \u10E9\u10D0\u10E5\u10E0\u10DD\u10D1\u10D0\u10E1, \u10E1\u10DE\u10DD\u10DC\u10E2\u10D0\u10DC\u10E3\u10E0 \u10D0\u10E6\u10D3\u10D2\u10D4\u10DC\u10D0\u10E1, \u10D2\u10D0\u10DC\u10D6\u10DD\u10D2\u10D0\u10D3\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D3\u10D8\u10E1\u10D9\u10E0\u10D8\u10DB\u10D8\u10DC\u10D0\u10EA\u10D8\u10D0\u10E1.",'\u10DD\u10DE\u10D4\u10E0\u10D0\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0 (\u10E1\u10D9\u10D8\u10DC\u10D4\u10E0\u10D8): \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7. \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D8\u10D7 \u10DB\u10D8\u10E7\u10DD\u10DA\u10D8\u10DA\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10E1\u10D8\u10EE\u10E8\u10D8\u10E0\u10D4 \u10D8\u10D6\u10E0\u10D3\u10D4\u10D1\u10D0; \u10D3\u10D0\u10E1\u10EF\u10D8\u10D7 \u10DB\u10D8\u10E7\u10DD\u10DA\u10D8\u10DA\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1\u10D0 \u2014 \u10DB\u10EA\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0. \u10E1\u10D9\u10D8\u10DC\u10D4\u10E0\u10DB\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0 \u10D4\u10E1 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D4\u10D1\u10D8 \u10D7\u10D0\u10D5\u10D8\u10E1\u10D8 \u10DD\u10DE\u10D4\u10E0\u10D0\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D9\u10D0\u10DB\u10D4\u10E0\u10D8\u10E1 ("\u10E1\u10D9\u10D8\u10DC\u10D4\u10E0\u10D8\u10E1 \u10E7\u10E3\u10D7\u10D8") \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10D7, \u10E1\u10D0\u10D3\u10D0\u10EA \u10EA\u10EE\u10DD\u10D5\u10D4\u10DA\u10D4\u10D1\u10DB\u10D0 \u10D8\u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10E1 \u10D1\u10D4\u10E0\u10D9\u10D4\u10E2\u10D4\u10D1\u10D6\u10D4 \u10D3\u10D0\u10ED\u10D4\u10E0\u10D0 \u10D0\u10DC \u10E6\u10D8\u10DA\u10D0\u10D9\u10D4\u10D1\u10D6\u10D4 \u10D3\u10D0\u10E0\u10E2\u10E7\u10DB\u10D0 \u10E1\u10D0\u10D9\u10D5\u10D4\u10D1\u10D8\u10E1 \u10EF\u10D8\u10DA\u10D3\u10DD\u10E1\u10D7\u10D5\u10D8\u10E1.',"\u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10DC\u10D4\u10D2\u10D0\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0: \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0 \u10D0\u10DB\u10D0\u10E2\u10D4\u10D1\u10E1 \u10E0\u10D0\u10E6\u10D0\u10EA \u10E1\u10D0\u10E1\u10E3\u10E0\u10D5\u10D4\u10DA\u10E1 (\u10EF\u10D8\u10DA\u10D3\u10DD \u10D9\u10D0\u10E0\u10D2\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1); \u10DC\u10D4\u10D2\u10D0\u10E2\u10D8\u10E3\u10E0\u10D8 \u10E8\u10D4\u10E1\u10E3\u10E1\u10E2\u10D4\u10D1\u10D0 \u10D0\u10E8\u10DD\u10E0\u10D4\u10D1\u10E1 \u10E0\u10D0\u10E6\u10D0\u10EA \u10E3\u10E1\u10D8\u10D0\u10DB\u10DD\u10D5\u10DC\u10DD\u10E1 (\u10D0\u10E1\u10DE\u10D8\u10E0\u10D8\u10DC\u10D8 \u10D0\u10E5\u10E0\u10DD\u10D1\u10E1 \u10D7\u10D0\u10D5\u10D8\u10E1 \u10E2\u10D9\u10D8\u10D5\u10D8\u10DA\u10E1). \u10DD\u10E0\u10D8\u10D5\u10D4 \u10D6\u10E0\u10D3\u10D8\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D2\u10D0\u10DB\u10D4\u10DD\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D0\u10DA\u10D1\u10D0\u10D7\u10DD\u10D1\u10D0\u10E1. \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC\u10D8\u10D0 \u10D0\u10E6\u10D8\u10DC\u10D8\u10E8\u10DC\u10DD\u10E1, \u10E0\u10DD\u10DB \u10DC\u10D4\u10D2\u10D0\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0 \u10D0\u10E0 \u10D0\u10E0\u10D8\u10E1 \u10D8\u10D2\u10D8\u10D5\u10D4, \u10E0\u10D0\u10EA \u10D3\u10D0\u10E1\u10EF\u10D0.","\u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D8\u10E1 \u10D2\u10E0\u10D0\u10E4\u10D8\u10D9\u10D4\u10D1\u10D8 \u10D2\u10D0\u10DC\u10E1\u10D0\u10D6\u10E6\u10D5\u10E0\u10D0\u10D5\u10D4\u10DC \u10E1\u10EC\u10D0\u10D5\u10DA\u10D8\u10E1 \u10E1\u10D8\u10E9\u10E5\u10D0\u10E0\u10D4\u10E1 \u10D3\u10D0 \u10E9\u10D0\u10E5\u10E0\u10DD\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD\u10D1\u10D0\u10E1: \u10E4\u10D8\u10E5\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D7\u10D0\u10DC\u10D0\u10E4\u10D0\u10E0\u10D3\u10DD\u10D1\u10D0 (\u10EF\u10D8\u10DA\u10D3\u10DD \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10D3\u10D2\u10D4\u10DC\u10D8\u10DA\u10D8 \u10E0\u10D0\u10DD\u10D3\u10D4\u10DC\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2), \u10EA\u10D5\u10DA\u10D0\u10D3\u10D8 \u10D7\u10D0\u10DC\u10D0\u10E4\u10D0\u10E0\u10D3\u10DD\u10D1\u10D0 (\u10EF\u10D8\u10DA\u10D3\u10DD \u10D0\u10E0\u10D0\u10DE\u10E0\u10DD\u10D2\u10DC\u10DD\u10D6\u10D8\u10E0\u10D4\u10D1\u10D0\u10D3\u10D8 \u10E0\u10D0\u10DD\u10D3\u10D4\u10DC\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2 \u2014 \u10D8\u10EB\u10DA\u10D4\u10D5\u10D0 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10DB\u10D0\u10E6\u10D0\u10DA, \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0 \u10DB\u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10DA\u10D4\u10D1\u10E1 \u10D3\u10D0 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10E0\u10D7\u10E3\u10DA\u10D0\u10D3 \u10E5\u10E0\u10D4\u10D1\u10D0), \u10E4\u10D8\u10E5\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D0\u10DA\u10D8 (\u10EF\u10D8\u10DA\u10D3\u10DD \u10D3\u10D0\u10D3\u10D2\u10D4\u10DC\u10D8\u10DA\u10D8 \u10DE\u10D4\u10E0\u10D8\u10DD\u10D3\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2) \u10D3\u10D0 \u10EA\u10D5\u10DA\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D0\u10DA\u10D8 (\u10EF\u10D8\u10DA\u10D3\u10DD \u10D0\u10E0\u10D0\u10DE\u10E0\u10DD\u10D2\u10DC\u10DD\u10D6\u10D8\u10E0\u10D4\u10D1\u10D0\u10D3\u10D8 \u10D3\u10E0\u10DD\u10D8\u10E1 \u10DE\u10D4\u10E0\u10D8\u10DD\u10D3\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2).","\u10D3\u10D0\u10E1\u10EF\u10D0 \u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1: \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E1\u10EF\u10D0 \u10D0\u10DB\u10D0\u10E2\u10D4\u10D1\u10E1 \u10E0\u10D0\u10E6\u10D0\u10EA \u10E3\u10E1\u10D8\u10D0\u10DB\u10DD\u10D5\u10DC\u10DD\u10E1 (\u10EF\u10D0\u10E0\u10D8\u10DB\u10D0 \u10E1\u10D8\u10E9\u10E5\u10D0\u10E0\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10D0\u10E0\u10D1\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1), \u10EE\u10DD\u10DA\u10DD \u10DC\u10D4\u10D2\u10D0\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E1\u10EF\u10D0 \u10D0\u10E8\u10DD\u10E0\u10D4\u10D1\u10E1 \u10E0\u10D0\u10E6\u10D0\u10EA \u10E1\u10D0\u10E1\u10E3\u10E0\u10D5\u10D4\u10DA\u10E1 (\u10E2\u10D4\u10DA\u10D4\u10E4\u10DD\u10DC\u10D8\u10E1 \u10DE\u10E0\u10D8\u10D5\u10D8\u10DA\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8\u10E1 \u10E9\u10D0\u10DB\u10DD\u10E0\u10D7\u10DB\u10D4\u10D5\u10D0). \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D3\u10D0\u10E1\u10EF\u10D0 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8\u10D0, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10D8\u10E1 \u10DB\u10E7\u10D8\u10E1\u10D8\u10D4\u10E0\u10D8\u10D0, \u10D7\u10D0\u10DC\u10DB\u10D8\u10DB\u10D3\u10D4\u10D5\u10E0\u10E3\u10DA\u10D8\u10D0 \u10D3\u10D0 \u10E8\u10D4\u10E0\u10EC\u10E7\u10DB\u10E3\u10DA\u10D8\u10D0 \u10D0\u10DA\u10E2\u10D4\u10E0\u10DC\u10D0\u10E2\u10D8\u10E3\u10DA\u10D8 \u10E1\u10D0\u10E1\u10E3\u10E0\u10D5\u10D4\u10DA\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0\u10E1\u10D7\u10D0\u10DC.","\u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D8\u10D7\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0 (\u10D1\u10D0\u10DC\u10D3\u10E3\u10E0\u10D0): \u10E9\u10D5\u10D4\u10DC \u10D5\u10E1\u10EC\u10D0\u10D5\u10DA\u10DD\u10D1\u10D7 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D4\u10D1\u10D6\u10D4 \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D8\u10D7 \u10D3\u10D0 \u10DB\u10D0\u10D7\u10D8 \u10D8\u10DB\u10D8\u10E2\u10D0\u10EA\u10D8\u10D8\u10D7. \u10D1\u10D0\u10DC\u10D3\u10E3\u10E0\u10D0\u10E1 \u10EA\u10DC\u10DD\u10D1\u10D8\u10DA\u10DB\u10D0 \u10D1\u10DD\u10D1\u10DD\u10E1 \u10D7\u10DD\u10EF\u10D8\u10DC\u10D8\u10E1 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10DB\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10D1\u10D0\u10D5\u10E8\u10D5\u10D4\u10D1\u10D8, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10E3\u10E7\u10E3\u10E0\u10D4\u10D1\u10D3\u10DC\u10D4\u10DC \u10DB\u10DD\u10D6\u10E0\u10D3\u10D8\u10DA\u10D8\u10E1 \u10D0\u10D2\u10E0\u10D4\u10E1\u10D8\u10E3\u10DA \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10D2\u10D0\u10E1\u10D0\u10D1\u10D4\u10E0\u10D8 \u10D7\u10DD\u10EF\u10D8\u10DC\u10D8\u10E1 \u10DB\u10D8\u10DB\u10D0\u10E0\u10D7, \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10DC\u10D0\u10D3 \u10E3\u10E4\u10E0\u10DD \u10DB\u10D4\u10E2\u10D0\u10D3 \u10D1\u10D0\u10EB\u10D0\u10D5\u10D3\u10DC\u10D4\u10DC \u10D0\u10DB \u10D0\u10D2\u10E0\u10D4\u10E1\u10D8\u10D0\u10E1. \u10D4\u10E1 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E7\u10E3\u10E0\u10D0\u10D3\u10E6\u10D4\u10D1\u10D0\u10E1, \u10D3\u10D0\u10DB\u10D0\u10EE\u10E1\u10DD\u10D5\u10E0\u10D4\u10D1\u10D0\u10E1, \u10DB\u10DD\u10E2\u10DD\u10E0\u10E3\u10DA \u10E0\u10D4\u10DE\u10E0\u10DD\u10D3\u10E3\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1 (\u10D8\u10E0\u10D8\u10D1\u10D8 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D0).","\u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0 \u10E1\u10EA\u10D3\u10D4\u10D1\u10D0 \u10E3\u10D1\u10E0\u10D0\u10DA\u10DD \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1: \u10E2\u10DD\u10DA\u10DB\u10D0\u10DC\u10DB\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0 \u10DA\u10D0\u10E2\u10D4\u10DC\u10E2\u10E3\u10E0\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0 (\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10EE\u10D3\u10D4\u10D1\u10D0, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10D0\u10E0 \u10D5\u10DA\u10D8\u10DC\u10D3\u10D4\u10D1\u10D0 \u10DB\u10D0\u10DC\u10D0\u10DB, \u10E1\u10D0\u10DC\u10D0\u10DB \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0 \u10D0\u10E0 \u10D2\u10D0\u10E9\u10DC\u10D3\u10D4\u10D1\u10D0) \u10D5\u10D8\u10E0\u10D7\u10EE\u10D4\u10D1\u10D8\u10E1 \u10DA\u10D0\u10D1\u10D8\u10E0\u10D8\u10DC\u10D7\u10E8\u10D8 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7. \u10D9\u10DD\u10DA\u10D4\u10E0\u10DB\u10D0 \u10D0\u10E6\u10EC\u10D4\u10E0\u10D0 \u10E8\u10D8\u10DB\u10DE\u10D0\u10DC\u10D6\u10D4\u10D4\u10D1\u10E8\u10D8 \u10D8\u10DC\u10E1\u10D0\u10D8\u10E2\u10E3\u10E0\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10D1\u10D0 \u2014 \u10DB\u10DD\u10E3\u10DA\u10DD\u10D3\u10DC\u10D4\u10DA\u10D8 \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10E0\u10D0 \u10EA\u10D3\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E8\u10D4\u10EA\u10D3\u10DD\u10DB\u10D8\u10E1 \u10D2\u10D0\u10E0\u10D4\u10E8\u10D4. \u10D4\u10E1 \u10D3\u10D0\u10E1\u10D9\u10D5\u10DC\u10D4\u10D1\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10E8\u10D8\u10DC\u10D0\u10D2\u10D0\u10DC\u10D8 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D4\u10D1\u10D8 \u10D2\u10D0\u10D3\u10D0\u10DB\u10EC\u10E7\u10D5\u10D4\u10E2 \u10E0\u10DD\u10DA\u10E1 \u10D7\u10D0\u10DB\u10D0\u10E8\u10DD\u10D1\u10D4\u10DC \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10E8\u10D8."],ru:["\u041A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435 (\u041F\u0430\u0432\u043B\u043E\u0432): \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u0443\u0442\u0435\u043C \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u0438 \u0441\u0442\u0438\u043C\u0443\u043B\u043E\u0432. \u041D\u0435\u0439\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u0441\u0442\u0438\u043C\u0443\u043B (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043A\u043E\u043B\u043E\u043A\u043E\u043B\u044C\u0447\u0438\u043A) \u043C\u043D\u043E\u0433\u043E\u043A\u0440\u0430\u0442\u043D\u043E \u0441\u043E\u0447\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0441 \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u044B\u043C \u0441\u0442\u0438\u043C\u0443\u043B\u043E\u043C (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0435\u0434\u043E\u0439), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u0443\u044E \u0440\u0435\u0430\u043A\u0446\u0438\u044E (\u0441\u043B\u044E\u043D\u043E\u043E\u0442\u0434\u0435\u043B\u0435\u043D\u0438\u0435). \u0412 \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u043C \u0438\u0442\u043E\u0433\u0435 \u043E\u0434\u0438\u043D \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u0435\u0439\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u0441\u0442\u0438\u043C\u0443\u043B \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0443\u0441\u043B\u043E\u0432\u043D\u044B\u043C \u0441\u0442\u0438\u043C\u0443\u043B\u043E\u043C, \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u044E\u0449\u0438\u043C \u0443\u0441\u043B\u043E\u0432\u043D\u0443\u044E \u0440\u0435\u0430\u043A\u0446\u0438\u044E. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0442 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435, \u0443\u0433\u0430\u0441\u0430\u043D\u0438\u0435, \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435, \u0433\u0435\u043D\u0435\u0440\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E \u0438 \u0434\u0438\u0441\u043A\u0440\u0438\u043C\u0438\u043D\u0430\u0446\u0438\u044E.","\u041E\u043F\u0435\u0440\u0430\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435 (\u0421\u043A\u0438\u043D\u043D\u0435\u0440): \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F. \u041F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0437\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435, \u0443\u0447\u0430\u0449\u0430\u0435\u0442\u0441\u044F; \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0437\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435, \u0443\u043C\u0435\u043D\u044C\u0448\u0430\u0435\u0442\u0441\u044F. \u0421\u043A\u0438\u043D\u043D\u0435\u0440 \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043B \u044D\u0442\u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0441\u0432\u043E\u044E \u043E\u043F\u0435\u0440\u0430\u043D\u0442\u043D\u0443\u044E \u043A\u0430\u043C\u0435\u0440\u0443 (\xAB\u042F\u0449\u0438\u043A \u0421\u043A\u0438\u043D\u043D\u0435\u0440\u0430\xBB), \u0433\u0434\u0435 \u0436\u0438\u0432\u043E\u0442\u043D\u044B\u0435 \u0443\u0447\u0438\u043B\u0438\u0441\u044C \u043D\u0430\u0436\u0438\u043C\u0430\u0442\u044C \u043D\u0430 \u0440\u044B\u0447\u0430\u0433\u0438 \u0438\u043B\u0438 \u043A\u043B\u0435\u0432\u0430\u0442\u044C \u043A\u043D\u043E\u043F\u043A\u0438 \u0434\u043B\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u043F\u0438\u0449\u0435\u0432\u043E\u0433\u043E \u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u044F.","\u041F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435: \u041F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435 \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442 \u0447\u0442\u043E-\u0442\u043E \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 (\u0443\u0433\u043E\u0449\u0435\u043D\u0438\u0435 \u0437\u0430 \u0445\u043E\u0440\u043E\u0448\u0435\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435); \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435 \u0443\u0431\u0438\u0440\u0430\u0435\u0442 \u0447\u0442\u043E-\u0442\u043E \u043D\u0435\u043F\u0440\u0438\u044F\u0442\u043D\u043E\u0435 (\u0430\u0441\u043F\u0438\u0440\u0438\u043D \u0441\u043D\u0438\u043C\u0430\u0435\u0442 \u0433\u043E\u043B\u043E\u0432\u043D\u0443\u044E \u0431\u043E\u043B\u044C). \u041E\u0431\u0430 \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u0430 \u043F\u043E\u0432\u044B\u0448\u0430\u044E\u0442 \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u044F \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F. \u0412\u0430\u0436\u043D\u043E \u043E\u0442\u043C\u0435\u0442\u0438\u0442\u044C, \u0447\u0442\u043E \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u041D\u0415 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435, \u0447\u0442\u043E \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435.","\u0420\u0435\u0436\u0438\u043C\u044B \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u044F \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044E\u0442 \u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F \u0438 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C \u043A \u0443\u0433\u0430\u0441\u0430\u043D\u0438\u044E: \u0424\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0441\u043E\u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 (\u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430 \u0440\u0435\u0430\u043A\u0446\u0438\u0439), \u041F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 (\u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u0441\u043B\u0435 \u043D\u0435\u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430 \u2014 \u0434\u0430\u0435\u0442 \u0441\u0430\u043C\u044B\u0435 \u0432\u044B\u0441\u043E\u043A\u0438\u0435 \u0438 \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u0435 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0438 \u0438 \u0442\u0440\u0443\u0434\u043D\u0435\u0435 \u0432\u0441\u0435\u0433\u043E \u043F\u043E\u0434\u0434\u0430\u0435\u0442\u0441\u044F \u0443\u0433\u0430\u0441\u0430\u043D\u0438\u044E), \u0424\u0438\u043A\u0441\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B (\u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u0435\u0440\u0438\u043E\u0434\u0430 \u0432\u0440\u0435\u043C\u0435\u043D\u0438) \u0438 \u041F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B (\u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043D\u0435\u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u0443\u0435\u043C\u044B\u0435 \u043F\u0435\u0440\u0438\u043E\u0434\u044B \u0432\u0440\u0435\u043C\u0435\u043D\u0438).","\u041D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u043E\u0441\u043B\u0430\u0431\u043B\u044F\u0435\u0442 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435: \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442 \u0447\u0442\u043E-\u0442\u043E \u043D\u0435\u043F\u0440\u0438\u044F\u0442\u043D\u043E\u0435 (\u0448\u0442\u0440\u0430\u0444 \u0437\u0430 \u043F\u0440\u0435\u0432\u044B\u0448\u0435\u043D\u0438\u0435 \u0441\u043A\u043E\u0440\u043E\u0441\u0442\u0438), \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u043E\u0435 \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u043B\u0438\u0448\u0430\u0435\u0442 \u0447\u0435\u0433\u043E-\u0442\u043E \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0433\u043E (\u043B\u0438\u0448\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0432\u0438\u043B\u0435\u0433\u0438\u0439 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u043E\u043C). \u0418\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442, \u0447\u0442\u043E \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u043E \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0435, \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0438 \u0441\u043E\u0447\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0441 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435\u043C \u0430\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F.","\u041E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0435 (\u0411\u0430\u043D\u0434\u0443\u0440\u0430): \u043C\u044B \u0443\u0447\u0438\u043C\u0441\u044F, \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u044F \u0437\u0430 \u043C\u043E\u0434\u0435\u043B\u044F\u043C\u0438 \u0438 \u0438\u043C\u0438\u0442\u0438\u0440\u0443\u044F \u0438\u0445. \u0417\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u0439 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442 \u0411\u0430\u043D\u0434\u0443\u0440\u044B \u0441 \u043A\u0443\u043A\u043B\u043E\u0439 \u0411\u043E\u0431\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043B, \u0447\u0442\u043E \u0434\u0435\u0442\u0438, \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u0432\u0448\u0438\u0435 \u0437\u0430 \u0442\u0435\u043C, \u043A\u0430\u043A \u0432\u0437\u0440\u043E\u0441\u043B\u044B\u0439 \u0432\u0435\u0434\u0435\u0442 \u0441\u0435\u0431\u044F \u0430\u0433\u0440\u0435\u0441\u0441\u0438\u0432\u043D\u043E \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u043D\u0430\u0434\u0443\u0432\u043D\u043E\u0439 \u043A\u0443\u043A\u043B\u0435, \u0441\u043E \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0441\u0442\u044C\u044E \u0438\u043C\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043B\u0438 \u044D\u0442\u0443 \u0430\u0433\u0440\u0435\u0441\u0441\u0438\u044E. \u042D\u0442\u043E\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0432 \u0441\u0435\u0431\u044F \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435, \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435, \u0434\u0432\u0438\u0433\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0432\u043E\u0441\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0438 \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044E (\u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E\u0435 \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435).","\u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0432\u044B\u0445\u043E\u0434\u0438\u0442 \u0437\u0430 \u0440\u0430\u043C\u043A\u0438 \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u044F: \u0422\u043E\u043B\u043C\u0435\u043D \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043B \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 (\u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442, \u043D\u043E \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u0438) \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u043E\u0432 \u043D\u0430 \u043A\u0440\u044B\u0441\u0430\u0445 \u0432 \u043B\u0430\u0431\u0438\u0440\u0438\u043D\u0442\u0435. \u041A\u0435\u043B\u0435\u0440 \u0437\u0430\u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043B \u0438\u043D\u0441\u0430\u0439\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u0443 \u0448\u0438\u043C\u043F\u0430\u043D\u0437\u0435 \u2014 \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B \u0431\u0435\u0437 \u043C\u0435\u0442\u043E\u0434\u0430 \u043F\u0440\u043E\u0431 \u0438 \u043E\u0448\u0438\u0431\u043E\u043A. \u042D\u0442\u0438 \u0432\u044B\u0432\u043E\u0434\u044B \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442, \u0447\u0442\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0438\u0433\u0440\u0430\u044E\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0443\u044E \u0440\u043E\u043B\u044C \u0432 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0438."],hy:["\u0534\u0561\u057D\u0561\u056F\u0561\u0576 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574 (\u054A\u0561\u057E\u056C\u0578\u057E). \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574 \u056D\u0569\u0561\u0576\u0576\u0565\u0580\u056B \u0561\u057D\u0578\u0581\u056B\u0561\u0581\u056B\u0561\u0575\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u0549\u0565\u0566\u0578\u0584 \u056D\u0569\u0561\u0576\u0568 (\u0585\u0580\u056B\u0576\u0561\u056F\u055D \u0566\u0561\u0576\u0563\u0561\u056F) \u0562\u0561\u0566\u0574\u056B\u0581\u057D \u0566\u0578\u0582\u0563\u0561\u056F\u0581\u057E\u0578\u0582\u0574 \u0567 \u0578\u0579 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u056F\u0561\u0576 \u056D\u0569\u0561\u0576\u056B (\u0585\u0580\u056B\u0576\u0561\u056F\u055D \u057D\u0576\u0576\u0564\u056B) \u0570\u0565\u057F, \u0578\u0580\u0568 \u0562\u0576\u0561\u056F\u0561\u0576\u0561\u0562\u0561\u0580 \u0561\u057C\u0561\u057B\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u0578\u0579 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u056F\u0561\u0576 \u057C\u0565\u0561\u056F\u0581\u056B\u0561 (\u0569\u0584\u0561\u0580\u057F\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576): \u053B \u057E\u0565\u0580\u057B\u0578, \u0574\u056B\u0561\u0575\u0576 \u0579\u0565\u0566\u0578\u0584 \u056D\u0569\u0561\u0576\u0568 \u0564\u0561\u057C\u0576\u0578\u0582\u0574 \u0567 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u057E\u0561\u056E \u056D\u0569\u0561\u0576, \u0578\u0580\u0576 \u0561\u057C\u0561\u057B\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u057E\u0561\u056E \u057C\u0565\u0561\u056F\u0581\u056B\u0561: \u0540\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u0576\u0565\u0580\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0565\u0576 \u0571\u0565\u057C\u0584\u0562\u0565\u0580\u0578\u0582\u0574, \u0574\u0561\u0580\u0578\u0582\u0574, \u056B\u0576\u0584\u0576\u0561\u0562\u0578\u0582\u056D \u057E\u0565\u0580\u0561\u056F\u0561\u0576\u0563\u0576\u0578\u0582\u0574, \u0568\u0576\u0564\u0570\u0561\u0576\u0580\u0561\u0581\u0578\u0582\u0574 \u0587 \u056D\u057F\u0580\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576:","\u0555\u057A\u0565\u0580\u0561\u0576\u057F \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574 (\u054D\u056F\u056B\u0576\u0565\u0580). \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574 \u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u054E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568, \u0578\u0580\u056B\u0576 \u0570\u0561\u057B\u0578\u0580\u0564\u0578\u0582\u0574 \u0567 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574\u0568, \u0574\u0565\u056E\u0561\u0576\u0578\u0582\u0574 \u0567 \u0570\u0561\u0573\u0561\u056D\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0574\u0562. \u057A\u0561\u057F\u056A\u056B\u0576 \u0570\u0561\u057B\u0578\u0580\u0564\u0578\u0572 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568 \u0576\u057E\u0561\u0566\u0578\u0582\u0574 \u0567: \u054D\u056F\u056B\u0576\u0565\u0580\u0576 \u0561\u057A\u0561\u0581\u0578\u0582\u0581\u0565\u0581 \u0561\u0575\u057D \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568\u055D \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0565\u056C\u0578\u057E \u056B\u0580 \u0585\u057A\u0565\u0580\u0561\u0576\u057F \u056D\u0581\u056B\u056F\u0568 (\xAB\u054D\u056F\u056B\u0576\u0565\u0580\u056B \u057F\u0578\u0582\u0583\xBB), \u0578\u0580\u057F\u0565\u0572 \u056F\u0565\u0576\u0564\u0561\u0576\u056B\u0576\u0565\u0580\u0568 \u057D\u0578\u057E\u0578\u0580\u0565\u0581\u056B\u0576 \u057D\u0565\u0572\u0574\u0565\u056C \u056C\u056E\u0561\u056F\u0576\u0565\u0580\u0568 \u056F\u0561\u0574 \u056F\u057F\u0581\u0561\u0570\u0561\u0580\u0565\u056C \u056F\u0578\u0573\u0561\u056F\u0576\u0565\u0580\u0568 \u057D\u0576\u0576\u0564\u056B \u057A\u0561\u0580\u0563\u0587\u0576\u0565\u0580\u056B \u0570\u0561\u0574\u0561\u0580:","\u0534\u0580\u0561\u056F\u0561\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0574\u0561\u0576. \u0534\u0580\u0561\u056F\u0561\u0576 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574\u0576 \u0561\u057E\u0565\u056C\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u0581\u0561\u0576\u056F\u0561\u056C\u056B \u056B\u0576\u0579-\u0578\u0580 \u0562\u0561\u0576 (\u0570\u0575\u0578\u0582\u0580\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u056C\u0561\u057E \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0570\u0561\u0574\u0561\u0580); \u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574\u0568 \u0570\u0565\u057C\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u056B\u0576\u0579-\u0578\u0580 \u057F\u0570\u0561\u0573 \u0562\u0561\u0576 (\u0561\u057D\u057A\u056B\u0580\u056B\u0576\u0568 \u057E\u0565\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u0563\u056C\u056D\u0561\u0581\u0561\u057E\u0568): \u0535\u0580\u056F\u0578\u0582\u057D\u0576 \u0567\u056C \u0574\u0565\u056E\u0561\u0581\u0576\u0578\u0582\u0574 \u0565\u0576 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u056F\u0580\u056F\u0576\u057E\u0565\u056C\u0578\u0582 \u0570\u0561\u057E\u0561\u0576\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u053F\u0561\u0580\u0587\u0578\u0580 \u0567, \u0578\u0580 \u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0578\u0582\u0574\u0568 \u0546\u0548\u0552\u0545\u0546\u0538 \u0549\u0537, \u056B\u0576\u0579 \u057A\u0561\u057F\u056B\u056A\u0568:","\u0531\u0574\u0580\u0561\u057A\u0576\u0564\u0574\u0561\u0576 \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u0581\u0578\u0582\u0575\u0581\u0565\u0580\u0568 \u0578\u0580\u0578\u0577\u0578\u0582\u0574 \u0565\u0576 \u057D\u0578\u057E\u0578\u0580\u0565\u056C\u0578\u0582 \u0561\u0580\u0561\u0563\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0574\u0561\u0580\u0574\u0561\u0576 \u0576\u056F\u0561\u057F\u0574\u0561\u0574\u0562 \u0564\u056B\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568. \u0556\u056B\u0584\u057D\u057E\u0561\u056E \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057A\u0561\u0580\u0563\u0587\u0561\u057E\u0573\u0561\u0580 \u057D\u0561\u0570\u0574\u0561\u0576\u057E\u0561\u056E \u0569\u057E\u0578\u057E \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0576\u0565\u0580\u056B\u0581 \u0570\u0565\u057F\u0578), \u0553\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576 \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057A\u0561\u0580\u0563\u0587\u0561\u057F\u0580\u0578\u0582\u0574 \u0561\u0576\u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0565\u056C\u056B \u0584\u0561\u0576\u0561\u056F\u056B\u0581 \u0570\u0565\u057F\u0578 \u2014 \u0561\u057A\u0561\u0570\u0578\u057E\u0578\u0582\u0574 \u0567 \u0561\u0574\u0565\u0576\u0561\u0562\u0561\u0580\u0571\u0580, \u056F\u0561\u0575\u0578\u0582\u0576 \u057F\u0565\u0574\u057A\u0565\u0580\u0568 \u0587 \u0561\u0574\u0565\u0576\u0561\u0564\u056A\u057E\u0561\u0580\u0576 \u0567 \u0574\u0561\u0580\u0565\u056C), \u0556\u056B\u0584\u057D\u057E\u0561\u056E \u0568\u0576\u0564\u0574\u056B\u057B\u0578\u0582\u0574 (\u057A\u0561\u0580\u0563\u0587 \u057D\u0561\u0570\u0574\u0561\u0576\u057E\u0561\u056E \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u0570\u0561\u057F\u057E\u0561\u056E\u056B\u0581 \u0570\u0565\u057F\u0578) \u0587 \u0553\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576 \u0574\u056B\u057B\u0561\u056F\u0561\u0575\u0584 (\u057A\u0561\u0580\u0563\u0587 \u0561\u0576\u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0565\u056C\u056B \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u0561\u0577\u0580\u057B\u0561\u0576\u0576\u0565\u0580\u056B\u0581 \u0570\u0565\u057F\u0578):","\u054A\u0561\u057F\u056B\u056A\u0568 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568. \u0534\u0580\u0561\u056F\u0561\u0576 \u057A\u0561\u057F\u056B\u056A\u0576 \u0561\u057E\u0565\u056C\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u056B\u0576\u0579-\u0578\u0580 \u057F\u0570\u0561\u0573\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0561\u0580\u0561\u0563\u0578\u0582\u0569\u0575\u0561\u0576 \u0563\u0565\u0580\u0561\u0566\u0561\u0576\u0581\u0574\u0561\u0576 \u057F\u0578\u0582\u0563\u0561\u0576\u0584), \u056B\u057D\u056F \u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576 \u057A\u0561\u057F\u056B\u056A\u0568 \u0570\u0565\u057C\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u0581\u0561\u0576\u056F\u0561\u056C\u056B \u056B\u0576\u0579-\u0578\u0580 \u0562\u0561\u0576 (\u0570\u0565\u057C\u0561\u056D\u0578\u057D\u056B \u0561\u0580\u057F\u0578\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u057E\u0565\u0580\u0581\u0576\u0565\u056C\u0568): \u0540\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0565\u0576 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u057A\u0561\u057F\u056B\u056A\u0576 \u0561\u057C\u0561\u057E\u0565\u056C \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0567, \u0565\u0580\u0562 \u0561\u0576\u0570\u0561\u057A\u0561\u0572 \u0567, \u0570\u0565\u057F\u0587\u0578\u0572\u0561\u056F\u0561\u0576 \u0587 \u0566\u0578\u0582\u0563\u0578\u0580\u0564\u057E\u0578\u0582\u0574 \u0567 \u0561\u0575\u056C\u0568\u0576\u057F\u0580\u0561\u0576\u0584\u0561\u0575\u056B\u0576 \u0581\u0561\u0576\u056F\u0561\u056C\u056B \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u0565\u0580\u056B \u0578\u0582\u056A\u0565\u0572\u0561\u0581\u0574\u0561\u0576 \u0570\u0565\u057F:","\u0534\u056B\u057F\u0578\u0572\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574 (\u0532\u0561\u0576\u0564\u0578\u0582\u0580\u0561). \u0574\u0565\u0576\u0584 \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0574 \u0565\u0576\u0584\u055D \u0564\u056B\u057F\u0565\u056C\u0578\u057E \u0587 \u0568\u0576\u0564\u0585\u0580\u056B\u0576\u0561\u056F\u0565\u056C\u0578\u057E \u0574\u0578\u0564\u0565\u056C\u0576\u0565\u0580\u0568: \u0532\u0561\u0576\u0564\u0578\u0582\u0580\u0561\u0575\u056B \u0532\u0578\u0562\u0578 \u057F\u056B\u056F\u0576\u056B\u056F\u056B \u0570\u0561\u0575\u057F\u0576\u056B \u0583\u0578\u0580\u0571\u0568 \u0581\u0578\u0582\u0575\u0581 \u057F\u057E\u0565\u0581, \u0578\u0580 \u0565\u0580\u0565\u056D\u0561\u0576\u0565\u0580\u0568, \u0578\u057E\u0584\u0565\u0580 \u0564\u056B\u057F\u0578\u0582\u0574 \u0567\u056B\u0576 \u0579\u0561\u0583\u0561\u0570\u0561\u057D\u056B \u0561\u0563\u0580\u0565\u057D\u056B\u057E \u057A\u0561\u0570\u057E\u0561\u056E\u0584\u0568 \u0583\u0579\u0578\u057E\u056B \u057F\u056B\u056F\u0576\u056B\u056F\u056B \u0570\u0561\u0576\u0564\u0565\u057A, \u0566\u0563\u0561\u056C\u056B\u0578\u0580\u0565\u0576 \u0561\u057E\u0565\u056C\u056B \u0570\u0561\u057E\u0561\u0576\u0561\u056F\u0561\u0576 \u0567, \u0578\u0580 \u0576\u0574\u0561\u0576\u0561\u056F\u0565\u0576 \u0561\u0575\u0564 \u0561\u0563\u0580\u0565\u057D\u056B\u0561\u0575\u056B\u0576: \u0531\u0575\u057D \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0578\u0582\u0577\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u057A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574, \u0577\u0561\u0580\u056A\u056B\u0579\u056B \u057E\u0565\u0580\u0561\u0580\u057F\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561 (\u0583\u0578\u056D\u0561\u0580\u056B\u0576\u0578\u0572 \u0578\u0582\u056A\u0565\u0572\u0561\u0581\u0578\u0582\u0574):","\u0543\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568 \u057F\u0561\u0580\u0561\u056E\u057E\u0578\u0582\u0574 \u0567 \u057A\u0561\u0580\u0566 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0565\u056C\u0578\u0582\u0581 \u0564\u0578\u0582\u0580\u057D. \u054F\u0578\u056C\u0574\u0561\u0576\u0568 \u0581\u0578\u0582\u0575\u0581 \u057F\u057E\u0565\u0581 \u0569\u0561\u0584\u0576\u057E\u0561\u056E \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574 (\u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574, \u0578\u0580\u0568 \u057F\u0565\u0572\u056B \u0567 \u0578\u0582\u0576\u0565\u0576\u0578\u0582\u0574, \u0562\u0561\u0575\u0581 \u0579\u056B \u0581\u0578\u0582\u0581\u0561\u0564\u0580\u057E\u0578\u0582\u0574 \u0574\u056B\u0576\u0579\u0587 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0575\u056B \u0561\u057C\u0561\u057B\u0561\u0581\u0578\u0582\u0574\u0568) \u0561\u057C\u0576\u0565\u057F\u0576\u0565\u0580\u056B \u056C\u0561\u0562\u056B\u0580\u056B\u0576\u0569\u0578\u057D\u0561\u0575\u056B\u0576 \u0583\u0578\u0580\u0571\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u053F\u0578\u056C\u0565\u0580\u0568 \u0583\u0561\u057D\u057F\u0565\u056C \u0567 \u0577\u056B\u0574\u057A\u0561\u0576\u0566\u0565\u0576\u0565\u0580\u056B \u0574\u0565\u057B \u056D\u0578\u0580\u0561\u0569\u0561\u0583\u0561\u0576\u0581 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568\u055D \u0570\u0561\u0576\u056F\u0561\u0580\u056E\u0561\u056F\u056B \u056D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u056C\u0578\u0582\u056E\u0578\u0582\u0574 \u0561\u057C\u0561\u0576\u0581 \u0583\u0578\u0580\u0571\u056B \u0587 \u057D\u056D\u0561\u056C\u056B: \u0531\u0575\u057D \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0565\u0576 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0576\u0565\u0580\u0584\u056B\u0576 \u0574\u057F\u0561\u057E\u0578\u0580 \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u0576\u0565\u0580\u0568 \u056F\u0561\u0580\u0587\u0578\u0580 \u0564\u0565\u0580 \u0565\u0576 \u056D\u0561\u0572\u0578\u0582\u0574 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u0563\u0578\u0580\u056E\u0578\u0582\u0574:"],az:["Klassik kondisioner (Pavlov): stimullar\u0131n assosiasiyas\u0131 vasit\u0259sil\u0259 \xF6yr\u0259nm\u0259. Neytral stimul (m\u0259s\u0259l\u0259n, z\u0259ng) t\u0259bii olaraq \u015F\u0259rtsiz reaksiyaya (t\xFCp\xFCrc\u0259k ifraz\u0131) s\u0259b\u0259b olan \u015F\u0259rtsiz stimulla (m\u0259s\u0259l\u0259n, yem\u0259k) t\u0259krar\u0259n \u0259laq\u0259l\u0259ndirilir. N\u0259hay\u0259t, t\u0259kc\u0259 neytral stimul \u015F\u0259rti reaksiyaya s\u0259b\u0259b olan \u015F\u0259rti stimula \xE7evrilir. \u018Fsas prosesl\u0259r\u0259 qazanma, s\xF6nm\u0259, kort\u0259bii b\u0259rpa, \xFCmumil\u0259\u015Fdirm\u0259 v\u0259 ayr\u0131-se\xE7kilik daxildir.",'Operant kondisyoner (Skinner): n\u0259tic\u0259l\u0259r vasit\u0259sil\u0259 \xF6yr\u0259nm\u0259. M\xF6hk\u0259ml\u0259ndirm\u0259nin ard\u0131nca g\u0259l\u0259n davran\u0131\u015F\u0131n tezliyi art\u0131r; c\u0259zan\u0131n ard\u0131nca g\u0259l\u0259n davran\u0131\u015F azal\u0131r. Skinner, heyvanlar\u0131n yem\u0259k m\xFCkafatlar\u0131 \xFC\xE7\xFCn qolu basma\u011F\u0131 v\u0259 ya d\xFCym\u0259l\u0259r\u0259 vurma\u011F\u0131 \xF6yr\u0259ndikl\u0259ri operant kameras\u0131ndan ("Skinner Qutusu") istifad\u0259 ed\u0259r\u0259k bu prinsipl\u0259ri n\xFCmayi\u015F etdirdi.',"M\xFCsb\u0259t v\u0259 m\u0259nfi g\xFCcl\u0259ndirm\u0259: M\xFCsb\u0259t g\xFCcl\u0259ndirm\u0259 arzu olunan bir \u015Fey (yax\u015F\u0131 davran\u0131\u015F \xFC\xE7\xFCn m\xFCkafat) \u0259lav\u0259 edir; m\u0259nfi g\xFCcl\u0259ndirm\u0259 xo\u015Fag\u0259lm\u0259z bir \u015Feyi aradan qald\u0131r\u0131r (aspirin ba\u015F a\u011Fr\u0131s\u0131n\u0131 yox edir). H\u0259r ikisi davran\u0131\u015F\u0131n t\u0259krarlanma ehtimal\u0131n\u0131 art\u0131r\u0131r. \u018Fh\u0259miyy\u0259tli odur ki, m\u0259nfi g\xFCcl\u0259ndirm\u0259 c\u0259za il\u0259 EYN\u0130 DEY\u0130L.","G\xFCcl\u0259ndirm\u0259 c\u0259dv\u0259ll\u0259ri \xF6yr\u0259nm\u0259 s\xFCr\u0259tini v\u0259 s\xF6nm\u0259y\u0259 qar\u015F\u0131 m\xFCqavim\u0259ti m\xFC\u0259yy\u0259n edir: Sabit nisb\u0259t (m\xFC\u0259yy\u0259n edilmi\u015F sayda reaksiyadan sonra m\xFCkafat), D\u0259yi\u015F\u0259n nisb\u0259t (g\xF6zl\u0259nilm\u0259z r\u0259q\u0259md\u0259n sonra m\xFCkafat - \u0259n y\xFCks\u0259k, \u0259n sabit g\xF6st\u0259ricil\u0259ri verir v\u0259 s\xF6nm\u0259si \u0259n \xE7\u0259tindir), Sabit interval (m\xFC\u0259yy\u0259n edilmi\u015F m\xFCdd\u0259td\u0259n sonra m\xFCkafat) v\u0259 D\u0259yi\u015F\u0259n interval (g\xF6zl\u0259nilm\u0259z vaxt d\xF6vrl\u0259rind\u0259n sonra m\xFCkafat).","C\u0259za davran\u0131\u015F\u0131 azald\u0131r: M\xFCsb\u0259t c\u0259za xo\u015Fag\u0259lm\u0259z bir \u015Fey \u0259lav\u0259 edir (s\xFCr\u0259t c\u0259rim\u0259si), m\u0259nfi c\u0259za is\u0259 arzu olunan\u0131 (telefon imtiyazlar\u0131n\u0131 \u0259lind\u0259n alaraq) aradan qald\u0131r\u0131r. T\u0259dqiqatlar g\xF6st\u0259rir ki, c\u0259za an\u0131nda, ard\u0131c\u0131l olduqda v\u0259 alternativ arzu olunan davran\u0131\u015Flar\u0131n g\xFCcl\u0259ndirilm\u0259si il\u0259 qo\u015Fala\u015Fd\u0131qda daha t\u0259sirli olur.","M\xFC\u015Fahid\u0259 yolu il\u0259 \xF6yr\u0259nm\u0259 (Bandura): biz modell\u0259ri izl\u0259y\u0259r\u0259k v\u0259 t\u0259qlid ed\u0259r\u0259k \xF6yr\u0259nirik. Banduran\u0131n m\u0259\u015Fhur Bobo g\u0259linciyi t\u0259cr\xFCb\u0259si g\xF6st\u0259rdi ki, b\xF6y\xFCkl\u0259rin \u015Fi\u015Fm\u0259 g\u0259lincik\u0259 qar\u015F\u0131 aqressiv davran\u0131\u015F\u0131n\u0131 izl\u0259y\u0259n u\u015Faqlarda bu t\u0259cav\xFCz\xFC t\u0259qlid etm\u0259 ehtimal\u0131 \u0259h\u0259miyy\u0259tli d\u0259r\u0259c\u0259d\u0259 daha y\xFCks\u0259k idi. Bu proses diqq\u0259t, yadda saxlama, motorik t\u0259krar istehsal v\u0259 motivasiyan\u0131 (vicarious reinforcement - dolay\u0131 yolla g\xFCcl\u0259ndirm\u0259) n\u0259z\u0259rd\u0259 tutur.","Koqnitiv \xF6yr\u0259nm\u0259 sad\u0259 \u015F\u0259rhl\u0259ndirm\u0259d\u0259n k\u0259nara \xE7\u0131x\u0131r: Tolman si\xE7ovullar \xFCz\u0259rind\u0259 labirint t\u0259cr\xFCb\u0259l\u0259ri vasit\u0259sil\u0259 gizli \xF6yr\u0259nm\u0259ni (ba\u015F ver\u0259n, lakin motivasiya yaranana q\u0259d\u0259r \xF6z\xFCn\xFC g\xF6st\u0259rm\u0259y\u0259n \xF6yr\u0259nm\u0259) n\xFCmayi\u015F etdirdi. Kohler \u015Fimpanzel\u0259rin intuisiyaya (anlay\u0131\u015Fa) \u0259saslanan \xF6yr\u0259nm\u0259l\u0259rini s\u0259n\u0259dl\u0259\u015Fdirdi - s\u0131naq v\u0259 s\u0259hv olmadan ani problem h\u0259lli. Bu tap\u0131nt\u0131lar daxili zehni prosesl\u0259rin \xF6yr\u0259nm\u0259d\u0259 h\u0259lledici rol oynad\u0131\u011F\u0131n\u0131 g\xF6st\u0259rir."]},funFact:{en:"Slot machines use a variable-ratio reinforcement schedule \u2014 the same principle Skinner discovered makes behavior hardest to extinguish. This is why gambling can be so addictive: you never know when the next reward will come.",ka:"\u10E1\u10D0\u10D7\u10D0\u10DB\u10D0\u10E8\u10DD \u10D0\u10DE\u10D0\u10E0\u10D0\u10E2\u10D4\u10D1\u10D8 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u10EA\u10D5\u10DA\u10D0\u10D3\u10D8 \u10D7\u10D0\u10DC\u10D0\u10E4\u10D0\u10E0\u10D3\u10DD\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D8\u10E1 \u10D2\u10E0\u10D0\u10E4\u10D8\u10D9\u10E1 - \u10D8\u10D2\u10D8\u10D5\u10D4 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D8, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10E1\u10D9\u10D8\u10DC\u10D4\u10E0\u10DB\u10D0 \u10D0\u10E6\u10DB\u10DD\u10D0\u10E9\u10D8\u10DC\u10D0.",ru:"\u0418\u0433\u0440\u043E\u0432\u044B\u0435 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u044B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u0433\u0440\u0430\u0444\u0438\u043A \u043F\u043E\u0434\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u044F \u0441 \u043F\u0435\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u043C \u0441\u043E\u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435\u043C \u2014 \u0442\u043E\u0442 \u0436\u0435 \u043F\u0440\u0438\u043D\u0446\u0438\u043F, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0442\u043A\u0440\u044B\u043B \u0421\u043A\u0438\u043D\u043D\u0435\u0440.",hy:"\u053D\u0561\u0572\u0561\u0575\u056B\u0576 \u0561\u057E\u10E2\u10DD\u10DB\u0561\u057F\u0576\u0565\u0580\u0568 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u0583\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576 \u0570\u10D0\u10E0\u10D0\u10D1\u10D4\u10E0\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u0561\u0574\u0580\u0561\u057A\u0576\u0564\u0574\u0561\u0576 \u056A\u10D0\u10DB\u0561\u0576\u0561\u056F\u10D0\u10EA\u0578\u0582\u0575\u0581. \u0576\u0578\u0582\u0575\u0576 \u057D\u10D9\u0566\u10D1\u10E3\u10DC\u10E5\u0568, \u0578\u0580\u0568 \u0570\u0561\u056A\u057F\u0576\u0561\u0562\u0565\u0580\u10D4\u10DA \u0567 \u054D\u056F\u10D8\u10DC\u0565\u0580\u0568:",az:"Slot ma\u015F\u0131nlar\u0131 d\u0259\u10D2\u10D8\u10E8\u0259n nis\u10D1\u0259tli g\xFCcl\u0259ndirm\u0259 c\u0259dv\u0259lind\u0259n istifad\u0259 edir - Skinnerin k\u0259\u10E8f etdiyi eyni prinsip."},realWorld:{en:'Dog trainers use operant conditioning (clicker training = positive reinforcement). Advertisers pair products with pleasant images (classical conditioning). Social media "likes" use variable-ratio reinforcement to keep you scrolling.',ka:"\u10EB\u10D0\u10E6\u10DA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10EC\u10D5\u10E0\u10D7\u10DC\u10D4\u10DA\u10D4\u10D1\u10D8 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u10DD\u10DE\u10D4\u10E0\u10D0\u10DC\u10E2\u10E3\u10DA \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1. \u10E0\u10D4\u10D9\u10DA\u10D0\u10DB\u10D4\u10D1\u10D8 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1.",ru:"\u0414\u0440\u0435\u0441\u0441\u0438\u0440\u043E\u0432\u0449\u0438\u043A\u0438 \u0441\u043E\u0431\u0430\u043A \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u043E\u043F\u0435\u0440\u0430\u043D\u0442\u043D\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435. \u0420\u0435\u043A\u043B\u0430\u043C\u043E\u0434\u0430\u0442\u0435\u043B\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u043A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435.",hy:"\u0547\u0576\u0565\u0580\u056B \u057E\u0561\u0580\u056A\u0565\u0581\u0576\u0578\u0572\u0576\u0565\u0580\u0568 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u0585\u057A\u0565\u0580\u0561\u0576\u057F \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574: \u0533\u0578\u057E\u0561\u0566\u0564\u0561\u057F\u0578\u0582\u0576\u0565\u0580\u0568 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u0564\u0561\u057D\u0561\u056F\u0561\u0576 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574:",az:"\u0130t t\u0259lim\xE7il\u0259ri operant kondisioner istifad\u0259 edirl\u0259r. Reklam\xE7\u0131lar klassik kondisionerd\u0259n istifad\u0259 edirl\u0259r."}},7:{title:{en:"Memory",ka:"\u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0",ru:"\u041F\u0430\u043C\u044F\u0442\u044C",hy:"\u0540\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576",az:"Yadda\u015F"},description:{en:"How we encode, store, and retrieve information.",ka:"\u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10D0\u10E8\u10D8\u10E4\u10E0\u10D0\u10D5\u10D7, \u10D5\u10D8\u10DC\u10D0\u10EE\u10D0\u10D5\u10D7 \u10D3\u10D0 \u10D5\u10D8\u10E6\u10D4\u10D1\u10D7 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10E1.",ru:"\u041A\u0430\u043A \u043C\u044B \u043A\u043E\u0434\u0438\u0440\u0443\u0435\u043C, \u0445\u0440\u0430\u043D\u0438\u043C \u0438 \u0438\u0437\u0432\u043B\u0435\u043A\u0430\u0435\u043C \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E.",hy:"\u053B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0578\u0582\u0574, \u057A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574 \u0587 \u0561\u057C\u0562\u0565\u0580\u0578\u0582\u0574 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:",az:"M\u0259lumat\u0131 nec\u0259 kodla\u015Fd\u0131r\u0131r\u0131q, saxlay\u0131r\u0131q v\u0259 \u0259ld\u0259 edirik."},keyTopics:{en:["Encoding","Storage","Retrieval","Forgetting","Memory Improvement"],ka:["\u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D0","\u10E8\u10D4\u10DC\u10D0\u10EE\u10D5\u10D0","\u10DB\u10DD\u10EB\u10D8\u10D4\u10D1\u10D0","\u10D3\u10D0\u10D5\u10D8\u10EC\u10E7\u10D4\u10D1\u10D0","\u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D4\u10D1\u10D0"],ru:["\u041A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435","\u0425\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435","\u041F\u043E\u0438\u0441\u043A","\u0417\u0430\u0431\u044B\u0432\u0447\u0438\u0432\u043E\u0441\u0442\u044C","\u0423\u043B\u0443\u0447\u0448\u0435\u043D\u0438\u0435 \u043F\u0430\u043C\u044F\u0442\u0438"],hy:["\u053F\u0578\u0564\u0561\u057E\u0578\u0580\u0578\u0582\u0574","\u054A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574","\u0531\u057C\u0562\u0565\u0580\u0578\u0582\u0574","\u0544\u0578\u057C\u0561\u0576\u0561\u056C\u0578\u057E","\u0540\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u0578\u0582\u0574"],az:["\xDC\xE7 m\u0259rh\u0259l\u0259li model","Kodla\u015Fd\u0131rma, Saxlama, B\u0259rpa"]},summary:{en:"Memory is the persistence of learning over time through the encoding, storage, and retrieval of information. This chapter examines the multi-store model proposed by Atkinson and Shiffrin, which describes three memory systems: sensory memory (a brief buffer holding raw sensory input for milliseconds to seconds), short-term or working memory (an active processing system with a capacity of about 7 plus-or-minus 2 items), and long-term memory (a virtually unlimited permanent store). It distinguishes between explicit memory \u2014 conscious recall of facts (semantic) and personal experiences (episodic) \u2014 and implicit memory, including procedural skills and conditioned responses. The chapter explores encoding strategies that improve retention (chunking, mnemonics, the spacing effect, deep processing), the mechanisms of forgetting (encoding failure, storage decay, proactive and retroactive interference), and the reconstructive nature of memory, including Loftus's groundbreaking research on the misinformation effect and false memories, which has profound implications for eyewitness testimony and the legal system.",ka:"\u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10D3\u10E0\u10DD\u10D7\u10D0 \u10D2\u10D0\u10DC\u10DB\u10D0\u10D5\u10DA\u10DD\u10D1\u10D0\u10E8\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D8\u10E1 \u10E8\u10D4\u10DC\u10D0\u10E0\u10E9\u10E3\u10DC\u10D4\u10D1\u10D0 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1, \u10E8\u10D4\u10DC\u10D0\u10EE\u10D5\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D0\u10E6\u10D3\u10D2\u10D4\u10DC\u10D8\u10E1 \u10D2\u10D6\u10D8\u10D7. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10D0\u10E2\u10D9\u10D8\u10DC\u10E1\u10DD\u10DC\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E8\u10D8\u10E4\u10E0\u10D8\u10DC\u10D8\u10E1 \u10DB\u10D8\u10D4\u10E0 \u10E8\u10D4\u10DB\u10DD\u10D7\u10D0\u10D5\u10D0\u10D6\u10D4\u10D1\u10E3\u10DA \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10E1\u10D0\u10EA\u10D0\u10D5\u10D8\u10D0\u10DC \u10DB\u10DD\u10D3\u10D4\u10DA\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E6\u10EC\u10D4\u10E0\u10E1 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D0\u10DB \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10E1: \u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10DB\u10DD\u10D9\u10DA\u10D4 \u10D1\u10E3\u10E4\u10D4\u10E0\u10D8, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D8\u10DC\u10D0\u10EE\u10D0\u10D5\u10E1 \u10DC\u10D4\u10D3\u10DA \u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10E1 \u10DB\u10D8\u10DA\u10D8\u10EC\u10D0\u10DB\u10D4\u10D1\u10D8\u10D3\u10D0\u10DC \u10EC\u10D0\u10DB\u10D4\u10D1\u10D0\u10DB\u10D3\u10D4), \u10DB\u10DD\u10D9\u10DA\u10D4\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8 \u10D0\u10DC \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 7 \u10DE\u10DA\u10E3\u10E1-\u10DB\u10D8\u10DC\u10E3\u10E1 2 \u10D4\u10E0\u10D7\u10D4\u10E3\u10DA\u10D8\u10E1 \u10E2\u10D4\u10D5\u10D0\u10D3\u10DD\u10D1\u10D8\u10D7) \u10D3\u10D0 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10E4\u10D0\u10E5\u10E2\u10DD\u10D1\u10E0\u10D8\u10D5\u10D0\u10D3 \u10E8\u10D4\u10E3\u10D6\u10E6\u10E3\u10D3\u10D0\u10D5\u10D8 \u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10D8 \u10E1\u10D0\u10EA\u10D0\u10D5\u10D8). \u10D8\u10E1 \u10D2\u10D0\u10DC\u10D0\u10E1\u10EE\u10D5\u10D0\u10D5\u10D4\u10D1\u10E1 \u10D4\u10E5\u10E1\u10DE\u10DA\u10D8\u10EA\u10D8\u10E2\u10E3\u10E0 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1 \u2014 \u10E4\u10D0\u10E5\u10E2\u10D4\u10D1\u10D8\u10E1 (\u10E1\u10D4\u10DB\u10D0\u10DC\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8) \u10D3\u10D0 \u10DE\u10D8\u10E0\u10D0\u10D3\u10D8 \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 (\u10D4\u10DE\u10D8\u10D6\u10DD\u10D3\u10E3\u10E0\u10D8) \u10E8\u10D4\u10D2\u10DC\u10D4\u10D1\u10E3\u10DA \u10D2\u10D0\u10EE\u10E1\u10D4\u10DC\u10D4\u10D1\u10D0\u10E1 \u2014 \u10D3\u10D0 \u10D8\u10DB\u10DE\u10DA\u10D8\u10EA\u10D8\u10E2\u10E3\u10E0 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10DE\u10E0\u10DD\u10EA\u10D4\u10D3\u10E3\u10E0\u10E3\u10DA \u10E3\u10DC\u10D0\u10E0\u10D4\u10D1\u10E1 \u10D3\u10D0 \u10DE\u10D8\u10E0\u10DD\u10D1\u10D8\u10D7 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D4\u10D1\u10E1. \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10D0\u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D4\u10D1\u10D4\u10DC \u10E8\u10D4\u10DC\u10D0\u10E0\u10E9\u10E3\u10DC\u10D4\u10D1\u10D0\u10E1 (\u10D3\u10D0\u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10D0, \u10DB\u10DC\u10D4\u10DB\u10DD\u10DC\u10D8\u10D9\u10D0, \u10D2\u10D0\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8, \u10E6\u10E0\u10DB\u10D0 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D0), \u10D3\u10D0\u10D5\u10D8\u10EC\u10E7\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E5\u10D0\u10DC\u10D8\u10D6\u10DB\u10D4\u10D1\u10E1 (\u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E3\u10D9\u10DB\u10D0\u10E0\u10D8\u10E1\u10DD\u10D1\u10D0, \u10E8\u10D4\u10DC\u10D0\u10EE\u10D5\u10D8\u10E1 \u10D2\u10D0\u10E3\u10D0\u10E0\u10D4\u10E1\u10D4\u10D1\u10D0, \u10DE\u10E0\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10DA\u10D8 \u10D3\u10D0 \u10E0\u10D4\u10E2\u10E0\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10DA\u10D8 \u10E9\u10D0\u10E0\u10D4\u10D5\u10D0) \u10D3\u10D0 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E0\u10D4\u10D9\u10DD\u10DC\u10E1\u10E2\u10E0\u10E3\u10E5\u10EA\u10D8\u10E3\u10DA \u10D1\u10E3\u10DC\u10D4\u10D1\u10D0\u10E1, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10DA\u10DD\u10E4\u10E2\u10E3\u10E1\u10D8\u10E1 \u10D8\u10DC\u10DD\u10D5\u10D0\u10EA\u10D8\u10E3\u10E0 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E1 \u10D3\u10D4\u10D6\u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10EA\u10E0\u10E3 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1, \u10E0\u10D0\u10E1\u10D0\u10EA \u10E6\u10E0\u10DB\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0 \u10D0\u10E5\u10D5\u10E1 \u10D7\u10D5\u10D8\u10D7\u10DB\u10EE\u10D8\u10DA\u10D5\u10D4\u10DA\u10D7\u10D0 \u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10D8\u10E3\u10E0\u10D8\u10D3\u10D8\u10E3\u10DA \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10D6\u10D4.",ru:"\u041F\u0430\u043C\u044F\u0442\u044C \u2014 \u044D\u0442\u043E \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F \u0441 \u0442\u0435\u0447\u0435\u043D\u0438\u0435\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043C\u043D\u043E\u0433\u043E\u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u043D\u0430\u044F \u043C\u043E\u0434\u0435\u043B\u044C, \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043D\u0430\u044F \u0410\u0442\u043A\u0438\u043D\u0441\u043E\u043D\u043E\u043C \u0438 \u0428\u0438\u0444\u0444\u0440\u0438\u043D\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0442\u0440\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043F\u0430\u043C\u044F\u0442\u0438: \u0441\u0435\u043D\u0441\u043E\u0440\u043D\u0443\u044E \u043F\u0430\u043C\u044F\u0442\u044C (\u043A\u0440\u0430\u0442\u043A\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0431\u0443\u0444\u0435\u0440, \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u0439 \u043D\u0435\u043E\u0431\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u044B\u0435 \u0441\u0435\u043D\u0441\u043E\u0440\u043D\u044B\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u043E\u0442 \u043C\u0438\u043B\u043B\u0438\u0441\u0435\u043A\u0443\u043D\u0434 \u0434\u043E \u0441\u0435\u043A\u0443\u043D\u0434), \u043A\u0440\u0430\u0442\u043A\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0443\u044E \u0438\u043B\u0438 \u0440\u0430\u0431\u043E\u0447\u0443\u044E \u043F\u0430\u043C\u044F\u0442\u044C (\u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0441 \u0435\u043C\u043A\u043E\u0441\u0442\u044C\u044E \u043E\u043A\u043E\u043B\u043E 7 \u043F\u043B\u044E\u0441-\u043C\u0438\u043D\u0443\u0441 2 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432) \u0438 \u0434\u043E\u043B\u0433\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0443\u044E \u043F\u0430\u043C\u044F\u0442\u044C (\u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u0435 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u0445\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435). \u041F\u0440\u043E\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u044D\u043A\u0441\u043F\u043B\u0438\u0446\u0438\u0442\u043D\u043E\u0439 \u043F\u0430\u043C\u044F\u0442\u044C\u044E \u2014 \u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435\u043C \u0444\u0430\u043A\u0442\u043E\u0432 (\u0441\u0435\u043C\u0430\u043D\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439) \u0438 \u043B\u0438\u0447\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 (\u044D\u043F\u0438\u0437\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u043E\u0439) \u2014 \u0438 \u0438\u043C\u043F\u043B\u0438\u0446\u0438\u0442\u043D\u043E\u0439 \u043F\u0430\u043C\u044F\u0442\u044C\u044E, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0435\u0439 \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440\u043D\u044B\u0435 \u043D\u0430\u0432\u044B\u043A\u0438 \u0438 \u0443\u0441\u043B\u043E\u0432\u043D\u044B\u0435 \u0440\u0435\u0430\u043A\u0446\u0438\u0438. \u0412 \u0433\u043B\u0430\u0432\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0442\u0441\u044F \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0443\u043B\u0443\u0447\u0448\u0430\u044E\u0449\u0438\u0435 \u0437\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 (\u0447\u0430\u043D\u043A\u0438\u043D\u0433, \u043C\u043D\u0435\u043C\u043E\u043D\u0438\u043A\u0430, \u044D\u0444\u0444\u0435\u043A\u0442 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0433\u043B\u0443\u0431\u043E\u043A\u0430\u044F \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430), \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C\u044B \u0437\u0430\u0431\u044B\u0432\u0430\u043D\u0438\u044F (\u0441\u0431\u043E\u0439 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0440\u0430\u0441\u043F\u0430\u0434 \u0441\u043B\u0435\u0434\u0430 \u043F\u0430\u043C\u044F\u0442\u0438, \u043F\u0440\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u0438 \u0440\u0435\u0442\u0440\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u044F), \u0430 \u0442\u0430\u043A\u0436\u0435 \u0440\u0435\u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u043F\u0430\u043C\u044F\u0442\u0438, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043D\u043E\u0432\u0430\u0442\u043E\u0440\u0441\u043A\u0438\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u041B\u043E\u0444\u0442\u0443\u0441 \u043E\u0431 \u044D\u0444\u0444\u0435\u043A\u0442\u0435 \u0434\u0435\u0437\u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u0438 \u043B\u043E\u0436\u043D\u044B\u0445 \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F\u0445, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u043C\u0435\u044E\u0442 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u0434\u043B\u044F \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0438\u0439 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u0439 \u0438 \u043F\u0440\u0430\u0432\u043E\u0432\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B.",hy:"\u0540\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u057A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574\u0576 \u0567 \u056A\u0561\u0574\u0561\u0576\u0561\u056F\u056B \u0568\u0576\u0569\u0561\u0581\u0584\u0578\u0582\u0574\u055D \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576, \u057A\u0561\u0570\u057A\u0561\u0576\u0574\u0561\u0576 \u0587 \u0561\u057C\u0562\u0565\u0580\u0574\u0561\u0576 \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0531\u057F\u056F\u056B\u0576\u057D\u0578\u0576\u056B \u0587 \u0547\u056B\u0586\u0580\u056B\u0576\u056B \u0561\u057C\u0561\u057B\u0561\u0580\u056F\u0561\u056E \u0562\u0561\u0566\u0574\u0561\u056D\u0561\u0576\u0578\u0582\u0569 \u0574\u0578\u0564\u0565\u056C\u0568, \u0578\u0580\u0568 \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0565\u0580\u0565\u0584 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0565\u0580. \u0566\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u056F\u0561\u0580\u0573 \u0562\u0578\u0582\u0586\u0565\u0580, \u0578\u0580\u0568 \u057A\u0561\u0570\u0578\u0582\u0574 \u0567 \u0579\u0574\u0577\u0561\u056F\u057E\u0561\u056E \u0566\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u0574\u0578\u0582\u057F\u0584\u0561\u0563\u0580\u0578\u0582\u0574\u0568 \u0574\u056B\u056C\u056B\u057E\u0561\u0575\u0580\u056F\u0575\u0561\u0576\u0576\u0565\u0580\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u057E\u0561\u0575\u0580\u056F\u0575\u0561\u0576\u0576\u0565\u0580), \u056F\u0561\u0580\u0573\u0561\u056A\u0561\u0574\u056F\u0565\u057F \u056F\u0561\u0574 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u0561\u0575\u056B\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0574\u0578\u057F 7 \u057A\u056C\u0575\u0578\u0582\u057D-\u0574\u056B\u0576\u0578\u0582\u057D 2 \u057F\u0561\u0580\u0580\u0565\u0580\u056B \u0570\u0566\u0578\u0580\u0578\u0582\u0569\u0575\u0561\u0574\u0562 \u0561\u056F\u057F\u056B\u057E \u0574\u0577\u0561\u056F\u0574\u0561\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563) \u0587 \u0565\u0580\u056F\u0561\u0580\u0561\u056A\u0561\u0574\u056F\u0565\u057F \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0563\u0580\u0565\u0569\u0565 \u0561\u0576\u057D\u0561\u0570\u0574\u0561\u0576\u0561\u0583\u0561\u056F \u0574\u0577\u057F\u0561\u056F\u0561\u0576 \u056D\u0561\u0576\u0578\u0582\u0569): \u0531\u0575\u0576 \u057F\u0561\u0580\u0562\u0565\u0580\u0561\u056F\u0578\u0582\u0574 \u0567 \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568\u055D \u0583\u0561\u057D\u057F\u0565\u0580\u056B (\u056B\u0574\u0561\u057D\u057F\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576) \u0587 \u0561\u0576\u0571\u0576\u0561\u056F\u0561\u0576 \u0583\u0578\u0580\u0571\u056B (\u0564\u0580\u057E\u0561\u0563\u0561\u0575\u056B\u0576) \u0563\u056B\u057F\u0561\u056F\u0581\u057E\u0561\u056E \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0587 \u0561\u0576\u0578\u0582\u0572\u0572\u0561\u056F\u056B \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0568\u0576\u0569\u0561\u0581\u0561\u056F\u0561\u0580\u0563\u0561\u0575\u056B\u0576 \u0570\u0574\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0587 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u057E\u0561\u056E \u057C\u0565\u0561\u056F\u0581\u056B\u0561\u0576\u0565\u0580\u0568: \u0533\u056C\u0578\u0582\u056D\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u0578\u0582\u0574 \u0565\u0576 \u057A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574\u0568 (\u056D\u0574\u0562\u0561\u057E\u0578\u0580\u0578\u0582\u0574, \u0574\u0576\u0565\u0574\u0578\u0576\u056B\u056F\u0561, \u057F\u0561\u0580\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0567\u0586\u0565\u056F\u057F, \u056D\u0578\u0580\u0568 \u0574\u0577\u0561\u056F\u0578\u0582\u0574), \u0574\u0578\u057C\u0561\u0576\u0561\u056C\u0578\u0582 \u0574\u0565\u056D\u0561\u0576\u056B\u0566\u0574\u0576\u0565\u0580\u0568 (\u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u0571\u0561\u056D\u0578\u0572\u0578\u0582\u0574, \u057A\u0561\u0570\u057A\u0561\u0576\u0574\u0561\u0576 \u0584\u0561\u0575\u0584\u0561\u0575\u0578\u0582\u0574, \u0561\u056F\u057F\u056B\u057E \u0587 \u0570\u0565\u057F\u0561\u0564\u0561\u0580\u0571 \u0574\u056B\u057B\u0561\u0574\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576) \u0587 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0565\u0580\u0561\u056F\u0561\u057C\u0578\u0582\u0581\u0578\u0572\u0561\u056F\u0561\u0576 \u0562\u0576\u0578\u0582\u0575\u0569\u0568, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u053C\u0578\u0586\u057F\u0578\u0582\u057D\u056B \u0562\u0565\u056F\u0578\u0582\u0574\u0576\u0561\u0575\u056B\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0561\u057A\u0561\u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0567\u0586\u0565\u056F\u057F\u056B \u0587 \u056F\u0565\u0572\u056E \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0575\u0561\u056C, \u0578\u0580\u0576 \u0578\u0582\u0576\u056B \u056D\u0578\u0580\u0568 \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0561\u056F\u0561\u0576\u0561\u057F\u0565\u057D\u0576\u0565\u0580\u056B \u057E\u056F\u0561\u0575\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u056B\u0580\u0561\u057E\u0561\u056F\u0561\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u056B \u057E\u0580\u0561:",az:"Yadda\u015F m\u0259lumat\u0131 kodla\u015Fd\u0131rma, saxlama v\u0259 b\u0259rpa etm\u0259 vasit\u0259sil\u0259 \xF6yr\u0259nm\u0259nin zamanla qorunub saxlanmas\u0131d\u0131r. Bu f\u0259sil Atkinson v\u0259 \u015Eiffrin t\u0259r\u0259find\u0259n ir\u0259li s\xFCr\xFCl\u0259n \xE7oxma\u011Fazal\u0131 modeli ara\u015Fd\u0131r\u0131r v\u0259 \xFC\xE7 yadda\u015F sistemini t\u0259svir edir: sensor yadda\u015F (xammal sensor daxiletm\u0259ni millisaniy\u0259l\u0259rd\u0259n saniy\u0259l\u0259r\u0259 q\u0259d\u0259r saxlayan q\u0131sa bufer), q\u0131sam\xFCdd\u0259tli v\u0259 ya i\u015F\xE7i yadda\u015F (t\u0259xmin\u0259n 7 plus-minus 2 element tutumlu aktiv emal sistemi) v\u0259 uzunm\xFCdd\u0259tli yadda\u015F (faktiki olaraq m\u0259hdudiyy\u0259tsiz daimi ma\u011Faza). O, a\u015Fkar (a\xE7\u0131q) yadda\u015F \u2014 faktlar\u0131n (semantik) v\u0259 \u015F\u0259xsi t\u0259cr\xFCb\u0259l\u0259rin (epizodik) \u015F\xFCurlu \u015F\u0259kild\u0259 xat\u0131rlanmas\u0131 \u2014  v\u0259 prosedur bacar\u0131qlar\u0131 v\u0259 \u015F\u0259rti reaksiyalar\u0131 \xF6z\xFCnd\u0259 birl\u0259\u015Fdir\u0259n gizli (\xF6rt\xFCl\xFC) yadda\u015F aras\u0131nda f\u0259rq qoyur. F\u0259sil yadda saxlama\u011F\u0131 yax\u015F\u0131la\u015Fd\u0131ran kodla\u015Fd\u0131rma strategiyalar\u0131n\u0131 (qrupla\u015Fd\u0131rma, mnemonika, aral\u0131q effekti, d\u0259rin emal), unutma mexanizml\u0259rini (kodla\u015Fd\u0131rma x\u0259tas\u0131, saxlaman\u0131n pozulmas\u0131, proaktiv v\u0259 retroaktiv m\xFCdaxil\u0259) v\u0259 yadda\u015F\u0131n rekonstruktiv xarakterini, o c\xFCml\u0259d\u0259n Loftusun \u015Fahidl\u0259rin ifad\u0259l\u0259ri v\u0259 h\xFCquq sistemi \xFC\xE7\xFCn d\u0259rin n\u0259tic\u0259l\u0259ri olan dezinformasiya effekti v\u0259 yalan xatir\u0259l\u0259r \xFCzr\u0259 \u0259sasl\u0131 t\u0259dqiqat\u0131n\u0131 ara\u015Fd\u0131r\u0131r."},keyPoints:{en:["The Atkinson-Shiffrin three-stage model describes memory flowing through three systems: Sensory memory (holds raw input for fractions of a second \u2014 iconic for visual, echoic for auditory), Short-term/Working memory (holds about 7 plus-or-minus 2 items for 20-30 seconds; Baddeley's model includes the phonological loop, visuospatial sketchpad, and central executive), and Long-term memory (virtually unlimited capacity and duration).",'Explicit (declarative) memory involves conscious recall with two subtypes: Semantic memory (general knowledge and facts \u2014 "Paris is the capital of France") and Episodic memory (personal experiences and events \u2014 "my first day of school"). Both are processed through the hippocampus.',"Implicit (non-declarative) memory operates without conscious awareness: Procedural memory (skills and habits like riding a bike \u2014 processed in the cerebellum and basal ganglia), classical conditioning effects, and Priming (exposure to one stimulus influences the response to a later stimulus).","Effective encoding strategies dramatically improve retention: Chunking (grouping information into meaningful units), Mnemonics (memory aids like acronyms or the method of loci), the Spacing effect (distributed practice is far superior to cramming), Elaborative rehearsal (connecting new information to existing knowledge), and Depth of processing (deeper semantic processing creates stronger memories).","Retrieval depends on cues: Context-dependent memory (recall improves when the environment matches the encoding setting), State-dependent memory (recall improves when internal state matches), and the Encoding specificity principle (memory is best when retrieval cues match encoding conditions). The tip-of-the-tongue phenomenon illustrates partial retrieval failure.","Forgetting occurs through several mechanisms: Encoding failure (information never entered long-term memory), Storage decay (Ebbinghaus's forgetting curve shows most forgetting happens within the first hour), Proactive interference (old memories disrupt new learning), and Retroactive interference (new learning disrupts recall of old memories).","Memory is reconstructive, not reproductive \u2014 we actively rebuild memories each time, making them susceptible to distortion. Elizabeth Loftus's misinformation effect research showed that misleading post-event information can alter memories of events. This has profound implications for eyewitness testimony reliability and has led to reforms in police lineup procedures."],ka:["\u10D0\u10E2\u10D9\u10D8\u10DC\u10E1\u10DD\u10DC-\u10E8\u10D8\u10E4\u10E0\u10D8\u10DC\u10D8\u10E1 \u10E1\u10D0\u10DB\u10E1\u10D0\u10E4\u10D4\u10EE\u10E3\u10E0\u10D8\u10D0\u10DC\u10D8 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8 \u10D0\u10E6\u10EC\u10D4\u10E0\u10E1 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D8\u10DC\u10D4\u10D1\u10D0\u10E1 \u10E1\u10D0\u10DB \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10E8\u10D8: \u10E1\u10D4\u10DC\u10E1\u10DD\u10E0\u10E3\u10DA\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10D8\u10DC\u10D0\u10EE\u10D0\u10D5\u10E1 \u10E1\u10D0\u10EC\u10E7\u10D8\u10E1 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10E1 \u10EC\u10D0\u10DB\u10D8\u10E1 \u10E4\u10E0\u10D0\u10E5\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10D0\u10D5\u10DA\u10DD\u10D1\u10D0\u10E8\u10D8 \u2014 \u10EE\u10D0\u10E2\u10DD\u10D5\u10D0\u10DC\u10D8 \u10D5\u10D8\u10D6\u10E3\u10D0\u10DA\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1, \u10D4\u10E5\u10DD\u10E3\u10E0\u10D8 \u10D0\u10E3\u10D3\u10D8\u10DD\u10E1\u10D7\u10D5\u10D8\u10E1), \u10DB\u10DD\u10D9\u10DA\u10D4\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8/\u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10D8\u10DC\u10D0\u10EE\u10D0\u10D5\u10E1 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 7 \u10DE\u10DA\u10E3\u10E1-\u10DB\u10D8\u10DC\u10E3\u10E1 2 \u10D4\u10E0\u10D7\u10D4\u10E3\u10DA\u10E1 20-30 \u10EC\u10D0\u10DB\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10D0\u10D5\u10DA\u10DD\u10D1\u10D0\u10E8\u10D8; \u10D1\u10D4\u10D3\u10DA\u10D8\u10E1 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E4\u10DD\u10DC\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0 \u10DB\u10D0\u10E0\u10E7\u10E3\u10DF\u10E1, \u10D5\u10D8\u10D6\u10E3\u10D0\u10DA\u10E3\u10E0-\u10E1\u10D8\u10D5\u10E0\u10EA\u10D8\u10D7 \u10D4\u10E1\u10D9\u10D8\u10D6\u10E1 \u10D3\u10D0 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D0\u10DA\u10E3\u10E0 \u10E8\u10D4\u10DB\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D4\u10DA\u10E1), \u10D3\u10D0 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10E3\u10DA\u10D0\u10D3 \u10E8\u10D4\u10E3\u10D6\u10E6\u10E3\u10D3\u10D0\u10D5\u10D8 \u10E2\u10D4\u10D5\u10D0\u10D3\u10DD\u10D1\u10D0 \u10D3\u10D0 \u10EE\u10D0\u10DC\u10D2\u10E0\u10EB\u10DA\u10D8\u10D5\u10DD\u10D1\u10D0).",'\u10D4\u10E5\u10E1\u10DE\u10DA\u10D8\u10EA\u10D8\u10E2\u10E3\u10E0\u10D8 (\u10D3\u10D4\u10D9\u10DA\u10D0\u10E0\u10D0\u10E2\u10D8\u10E3\u10DA\u10D8) \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E8\u10D4\u10D2\u10DC\u10D4\u10D1\u10E3\u10DA \u10D2\u10D0\u10EE\u10E1\u10D4\u10DC\u10D4\u10D1\u10D0\u10E1 \u10DD\u10E0\u10D8 \u10E5\u10D5\u10D4\u10E2\u10D8\u10DE\u10D8\u10D7: \u10E1\u10D4\u10DB\u10D0\u10DC\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10D6\u10DD\u10D2\u10D0\u10D3\u10D8 \u10EA\u10DD\u10D3\u10DC\u10D0 \u10D3\u10D0 \u10E4\u10D0\u10E5\u10E2\u10D4\u10D1\u10D8 - "\u10DE\u10D0\u10E0\u10D8\u10D6\u10D8 \u10E1\u10D0\u10E4\u10E0\u10D0\u10DC\u10D2\u10D4\u10D7\u10D8\u10E1 \u10D3\u10D4\u10D3\u10D0\u10E5\u10D0\u10DA\u10D0\u10E5\u10D8\u10D0") \u10D3\u10D0 \u10D4\u10DE\u10D8\u10D6\u10DD\u10D3\u10E3\u10E0\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10DE\u10D8\u10E0\u10D0\u10D3\u10D8 \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10DB\u10DD\u10D5\u10DA\u10D4\u10DC\u10D4\u10D1\u10D8 - "\u10E9\u10D4\u10DB\u10D8 \u10DE\u10D8\u10E0\u10D5\u10D4\u10DA\u10D8 \u10D3\u10E6\u10D4 \u10E1\u10D9\u10DD\u10DA\u10D0\u10E8\u10D8"). \u10DD\u10E0\u10D8\u10D5\u10D4 \u10DB\u10E3\u10E8\u10D0\u10D5\u10D3\u10D4\u10D1\u10D0 \u10F0\u10D8\u10DE\u10DD\u10D9\u10D0\u10DB\u10DE\u10E3\u10E1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7.',"\u10D8\u10DB\u10DE\u10DA\u10D8\u10EA\u10D8\u10E2\u10E3\u10E0\u10D8 (\u10D0\u10E0\u10D0\u10D3\u10D4\u10D9\u10DA\u10D0\u10E0\u10D0\u10E2\u10D8\u10E3\u10DA\u10D8) \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10DD\u10DC\u10D8\u10E0\u10D4\u10D1\u10E1 \u10E8\u10D4\u10D2\u10DC\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D2\u10D0\u10E0\u10D4\u10E8\u10D4: \u10DE\u10E0\u10DD\u10EA\u10D4\u10D3\u10E3\u10E0\u10E3\u10DA\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10E3\u10DC\u10D0\u10E0\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10E9\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10D5\u10D4\u10DA\u10DD\u10E1\u10D8\u10DE\u10D4\u10D3\u10D8\u10E1 \u10E2\u10D0\u10E0\u10D4\u10D1\u10D0 - \u10DB\u10E3\u10E8\u10D0\u10D5\u10D3\u10D4\u10D1\u10D0 \u10DC\u10D0\u10D7\u10EE\u10D4\u10DB\u10E1\u10D0 \u10D3\u10D0 \u10D1\u10D0\u10D6\u10D0\u10DA\u10E3\u10E0 \u10D2\u10D0\u10DC\u10D2\u10DA\u10D8\u10D4\u10D1\u10E8\u10D8), \u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D9\u10DD\u10DC\u10D3\u10D8\u10EA\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10DE\u10E0\u10D0\u10D8\u10DB\u10D8\u10DC\u10D2\u10D8 (\u10D4\u10E0\u10D7 \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D6\u10D4 \u10D4\u10E5\u10E1\u10DE\u10DD\u10D6\u10D8\u10EA\u10D8\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1 \u10D0\u10EE\u10D3\u10D4\u10DC\u10E1 \u10DE\u10D0\u10E1\u10E3\u10EE\u10D6\u10D4 \u10E8\u10D4\u10DB\u10D3\u10D2\u10DD\u10DB \u10E1\u10E2\u10D8\u10DB\u10E3\u10DA\u10D6\u10D4).","\u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8 \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8 \u10DB\u10D9\u10D5\u10D4\u10D7\u10E0\u10D0\u10D3 \u10D0\u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D4\u10D1\u10E1 \u10D3\u10D0\u10DB\u10D0\u10EE\u10E1\u10DD\u10D5\u10E0\u10D4\u10D1\u10D0\u10E1: \u10D3\u10D0\u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10D0 (\u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D3\u10D0\u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10D0 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC \u10D4\u10E0\u10D7\u10D4\u10E3\u10DA\u10D4\u10D1\u10D0\u10D3), \u10DB\u10DC\u10D4\u10DB\u10DD\u10DC\u10D8\u10D9\u10D0 (\u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10DB\u10EE\u10DB\u10D0\u10E0\u10D4 \u10E1\u10D0\u10E8\u10E3\u10D0\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10D0\u10D9\u10E0\u10DD\u10DC\u10D8\u10DB\u10D4\u10D1\u10D8 \u10D0\u10DC \u10DA\u10DD\u10D9\u10E3\u10E1\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10D7\u10DD\u10D3\u10D8), \u10D2\u10D0\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8 (\u10D2\u10D0\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10D0 \u10D1\u10D4\u10D5\u10E0\u10D0\u10D3 \u10D0\u10E6\u10D4\u10DB\u10D0\u10E2\u10D4\u10D1\u10D0 \u10D3\u10D0\u10D6\u10D4\u10DE\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1), \u10D4\u10DA\u10D0\u10D1\u10DD\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 \u10D2\u10D0\u10DB\u10D4\u10DD\u10E0\u10D4\u10D1\u10D0 (\u10D0\u10EE\u10D0\u10DA\u10D8 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10E1\u10D4\u10D1\u10E3\u10DA \u10EA\u10DD\u10D3\u10DC\u10D0\u10E1\u10D7\u10D0\u10DC) \u10D3\u10D0 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D8\u10E6\u10E0\u10DB\u10D4 (\u10E3\u10E4\u10E0\u10DD \u10E6\u10E0\u10DB\u10D0 \u10E1\u10D4\u10DB\u10D0\u10DC\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D0 \u10E5\u10DB\u10DC\u10D8\u10E1 \u10E3\u10E4\u10E0\u10DD \u10EB\u10DA\u10D8\u10D4\u10E0 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10E1).",'\u10D0\u10DB\u10DD\u10E6\u10D4\u10D1\u10D0 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10DB\u10D8\u10DC\u10D8\u10E8\u10DC\u10D4\u10D1\u10D4\u10D1\u10D6\u10D4: \u10D9\u10DD\u10DC\u10E2\u10D4\u10E5\u10E1\u10E2\u10D6\u10D4 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10D2\u10D0\u10EE\u10E1\u10D4\u10DC\u10D4\u10D1\u10D0 \u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D3\u10D4\u10D1\u10D0, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD \u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D0 \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DE\u10D0\u10E0\u10D0\u10DB\u10D4\u10E2\u10E0\u10E1), \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0\u10D6\u10D4 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10D2\u10D0\u10EE\u10E1\u10D4\u10DC\u10D4\u10D1\u10D0 \u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D3\u10D4\u10D1\u10D0, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10E8\u10D8\u10DC\u10D0\u10D2\u10D0\u10DC\u10D8 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0 \u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D0) \u10D3\u10D0 \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10DE\u10D4\u10EA\u10D8\u10E4\u10D8\u10D9\u10E3\u10E0\u10DD\u10D1\u10D8\u10E1 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D8 (\u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10E1\u10D0\u10E3\u10D9\u10D4\u10D7\u10D4\u10E1\u10DD\u10D0, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10D0\u10DB\u10DD\u10E6\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10DC\u10D8\u10E8\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D0 \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DE\u10D8\u10E0\u10DD\u10D1\u10D4\u10D1\u10E1). "\u10D4\u10DC\u10D8\u10E1 \u10EC\u10D5\u10D4\u10E0\u10D6\u10D4" \u10E4\u10D4\u10DC\u10DD\u10DB\u10D4\u10DC\u10D8 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D0\u10D3\u10D2\u10D4\u10DC\u10E1 \u10D0\u10DB\u10DD\u10E6\u10D4\u10D1\u10D8\u10E1 \u10DC\u10D0\u10EC\u10D8\u10DA\u10DD\u10D1\u10E0\u10D8\u10D5 \u10E3\u10D9\u10DB\u10D0\u10E0\u10D8\u10E1\u10DD\u10D1\u10D0\u10E1.',"\u10D3\u10D0\u10D5\u10D8\u10EC\u10E7\u10D4\u10D1\u10D0 \u10EE\u10D3\u10D4\u10D1\u10D0 \u10E0\u10D0\u10DB\u10D3\u10D4\u10DC\u10D8\u10DB\u10D4 \u10DB\u10D4\u10E5\u10D0\u10DC\u10D8\u10D6\u10DB\u10D8\u10D7: \u10D9\u10DD\u10D3\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E3\u10D9\u10DB\u10D0\u10E0\u10D8\u10E1\u10DD\u10D1\u10D0 (\u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0 \u10D0\u10E0\u10D0\u10E1\u10DD\u10D3\u10D4\u10E1 \u10E8\u10D4\u10E1\u10E3\u10DA\u10D0 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC \u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E8\u10D8), \u10E8\u10D4\u10DC\u10D0\u10EE\u10D5\u10D8\u10E1 \u10D3\u10D4\u10D2\u10E0\u10D0\u10D3\u10D0\u10EA\u10D8\u10D0 (\u10D4\u10D1\u10D8\u10DC\u10D2\u10F0\u10D0\u10E3\u10E1\u10D8\u10E1 \u10D3\u10D0\u10D5\u10D8\u10EC\u10E7\u10D4\u10D1\u10D8\u10E1 \u10DB\u10E0\u10E3\u10D3\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D3\u10D0\u10D5\u10D8\u10EC\u10E7\u10D4\u10D1\u10D8\u10E1 \u10E3\u10DB\u10D4\u10E2\u10D4\u10E1\u10D8 \u10DC\u10D0\u10EC\u10D8\u10DA\u10D8 \u10EE\u10D3\u10D4\u10D1\u10D0 \u10DE\u10D8\u10E0\u10D5\u10D4\u10DA \u10E1\u10D0\u10D0\u10D7\u10E8\u10D8), \u10DE\u10E0\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10DA\u10D8 \u10E9\u10D0\u10E0\u10D4\u10D5\u10D0 (\u10EB\u10D5\u10D4\u10DA\u10D8 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8 \u10EE\u10D4\u10DA\u10E1 \u10E3\u10E8\u10DA\u10D8\u10E1 \u10D0\u10EE\u10D0\u10DA \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10E1) \u10D3\u10D0 \u10E0\u10D4\u10E2\u10E0\u10DD\u10D0\u10E5\u10E2\u10D8\u10E3\u10DA\u10D8 \u10E9\u10D0\u10E0\u10D4\u10D5\u10D0 (\u10D0\u10EE\u10D0\u10DA\u10D8 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10EE\u10D4\u10DA\u10E1 \u10E3\u10E8\u10DA\u10D8\u10E1 \u10EB\u10D5\u10D4\u10DA\u10D8 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10EE\u10E1\u10D4\u10DC\u10D4\u10D1\u10D0\u10E1).","\u10DB\u10D4\u10EE\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E0\u10D4\u10D9\u10DD\u10DC\u10E1\u10E2\u10E0\u10E3\u10E5\u10EA\u10D8\u10E3\u10DA\u10D8, \u10D0\u10E0\u10D0 \u10E0\u10D4\u10DE\u10E0\u10DD\u10D3\u10E3\u10E5\u10EA\u10D8\u10E3\u10DA\u10D8 - \u10E9\u10D5\u10D4\u10DC \u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D0\u10D3 \u10D5\u10D0\u10E8\u10D4\u10DC\u10D4\u10D1\u10D7 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10E1 \u10E7\u10DD\u10D5\u10D4\u10DA \u10EF\u10D4\u10E0\u10D6\u10D4, \u10E0\u10D0\u10EA \u10DB\u10D0\u10D7 \u10D3\u10D0\u10DB\u10D0\u10EE\u10D8\u10DC\u10EF\u10D4\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10DB\u10D8\u10D3\u10E0\u10D4\u10D9\u10D8\u10DA\u10E1 \u10EE\u10D3\u10D8\u10E1. \u10D4\u10DA\u10D8\u10D6\u10D0\u10D1\u10D4\u10E2 \u10DA\u10DD\u10E4\u10E2\u10E3\u10E1\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10DB \u10D3\u10D4\u10D6\u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10DB\u10DD\u10D5\u10DA\u10D4\u10DC\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D2\u10DD\u10DB\u10DB\u10D0 \u10DB\u10EA\u10D3\u10D0\u10E0\u10DB\u10D0 \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10DB \u10E8\u10D4\u10D8\u10EB\u10DA\u10D4\u10D1\u10D0 \u10E8\u10D4\u10EA\u10D5\u10D0\u10DA\u10DD\u10E1 \u10DB\u10DD\u10D5\u10DA\u10D4\u10DC\u10D4\u10D1\u10D8\u10E1 \u10DB\u10DD\u10D2\u10DD\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8. \u10D0\u10DB\u10D0\u10E1 \u10D0\u10E5\u10D5\u10E1 \u10E6\u10E0\u10DB\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0 \u10D7\u10D5\u10D8\u10D7\u10DB\u10EE\u10D8\u10DA\u10D5\u10D4\u10DA\u10D7\u10D0 \u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D0\u10DC\u10D3\u10DD\u10DD\u10D1\u10D0\u10D6\u10D4 \u10D3\u10D0 \u10D2\u10D0\u10DB\u10DD\u10D8\u10EC\u10D5\u10D8\u10D0 \u10E0\u10D4\u10E4\u10DD\u10E0\u10DB\u10D4\u10D1\u10D8 \u10DE\u10DD\u10DA\u10D8\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D0\u10DB\u10DD\u10EA\u10DC\u10DD\u10D1\u10D8\u10E1 \u10DE\u10E0\u10DD\u10EA\u10D4\u10D3\u10E3\u10E0\u10D4\u10D1\u10E8\u10D8."],ru:["\u0422\u0440\u0435\u0445\u0441\u0442\u0443\u043F\u0435\u043D\u0447\u0430\u0442\u0430\u044F \u043C\u043E\u0434\u0435\u043B\u044C \u0410\u0442\u043A\u0438\u043D\u0441\u043E\u043D\u0430-\u0428\u0438\u0444\u0444\u0440\u0438\u043D\u0430 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u043F\u0430\u043C\u044F\u0442\u044C, \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u0447\u0435\u0440\u0435\u0437 \u0442\u0440\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u044B: \u0441\u0435\u043D\u0441\u043E\u0440\u043D\u0430\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043D\u0435\u043E\u0431\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u0443\u044E \u0438\u043D\u0444\u0443 \u0434\u043E\u043B\u0438 \u0441\u0435\u043A\u0443\u043D\u0434\u044B \u2014 \u0438\u043A\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0434\u043B\u044F \u0437\u0440\u0435\u043D\u0438\u044F, \u044D\u0445\u043E\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0434\u043B\u044F \u0441\u043B\u0443\u0445\u0430), \u043A\u0440\u0430\u0442\u043A\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F/\u0440\u0430\u0431\u043E\u0447\u0430\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043E\u043A\u043E\u043B\u043E 7 \u043F\u043B\u044E\u0441-\u043C\u0438\u043D\u0443\u0441 2 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 20-30 \u0441\u0435\u043A\u0443\u043D\u0434; \u043C\u043E\u0434\u0435\u043B\u044C \u0411\u044D\u0434\u0434\u0435\u043B\u0438 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0444\u043E\u043D\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043F\u0435\u0442\u043B\u044E, \u0432\u0438\u0437\u0443\u0430\u043B\u044C\u043D\u043E-\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0431\u043B\u043E\u043A\u043D\u043E\u0442 \u0438 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u044D\u043B\u0435\u043C\u0435\u043D\u0442) \u0438 \u0434\u043E\u043B\u0433\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u0435\u043C\u043A\u043E\u0441\u0442\u044C \u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C).","\u042D\u043A\u0441\u043F\u043B\u0438\u0446\u0438\u0442\u043D\u0430\u044F (\u0434\u0435\u043A\u043B\u0430\u0440\u0430\u0442\u0438\u0432\u043D\u0430\u044F) \u043F\u0430\u043C\u044F\u0442\u044C \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u043F\u0440\u0438\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u0434\u0432\u0443\u0445 \u043F\u043E\u0434\u0442\u0438\u043F\u043E\u0432: \u0441\u0435\u043C\u0430\u043D\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u043E\u0431\u0449\u0438\u0435 \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0444\u0430\u043A\u0442\u044B \u2014 \xAB\u041F\u0430\u0440\u0438\u0436 \u2014 \u0441\u0442\u043E\u043B\u0438\u0446\u0430 \u0424\u0440\u0430\u043D\u0446\u0438\u0438\xBB) \u0438 \u044D\u043F\u0438\u0437\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u043B\u0438\u0447\u043D\u044B\u0435 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F \u0438 \u0441\u043E\u0431\u044B\u0442\u0438\u044F \u2014 \xAB\u043C\u043E\u0439 \u043F\u0435\u0440\u0432\u044B\u0439 \u0434\u0435\u043D\u044C \u0432 \u0448\u043A\u043E\u043B\u0435\xBB). \u041E\u0431\u0435 \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0433\u0438\u043F\u043F\u043E\u043A\u0430\u043C\u043F\u043E\u043C.","\u0418\u043C\u043F\u043B\u0438\u0446\u0438\u0442\u043D\u0430\u044F (\u043D\u0435\u0434\u0435\u043A\u043B\u0430\u0440\u0430\u0442\u0438\u0432\u043D\u0430\u044F) \u043F\u0430\u043C\u044F\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0431\u0435\u0437 \u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F: \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440\u043D\u0430\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u043D\u0430\u0432\u044B\u043A\u0438 \u0438 \u043F\u0440\u0438\u0432\u044B\u0447\u043A\u0438, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0435\u0437\u0434\u0430 \u043D\u0430 \u0432\u0435\u043B\u043E\u0441\u0438\u043F\u0435\u0434\u0435 \u2014 \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0432 \u043C\u043E\u0437\u0436\u0435\u0447\u043A\u0435 \u0438 \u0431\u0430\u0437\u0430\u043B\u044C\u043D\u044B\u0445 \u0433\u0430\u043D\u0433\u043B\u0438\u044F\u0445), \u044D\u0444\u0444\u0435\u043A\u0442\u044B \u043A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u044F \u0438 \u043F\u0440\u0430\u0439\u043C\u0438\u043D\u0433 (\u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043E\u0434\u043D\u043E\u0433\u043E \u0441\u0442\u0438\u043C\u0443\u043B\u0430 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u0440\u0435\u0430\u043A\u0446\u0438\u044E \u043D\u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0441\u0442\u0438\u043C\u0443\u043B).","\u042D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0443\u043B\u0443\u0447\u0448\u0430\u044E\u0442 \u0437\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435: \u0447\u0430\u043D\u043A\u0438\u043D\u0433 (\u0433\u0440\u0443\u043F\u043F\u0438\u0440\u043E\u0432\u043A\u0430 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u0432 \u0441\u043C\u044B\u0441\u043B\u043E\u0432\u044B\u0435 \u0435\u0434\u0438\u043D\u0438\u0446\u044B), \u043C\u043D\u0435\u043C\u043E\u043D\u0438\u043A\u0430 (\u0432\u0441\u043F\u043E\u043C\u043E\u0433\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043F\u0430\u043C\u044F\u0442\u0438, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0430\u0431\u0431\u0440\u0435\u0432\u0438\u0430\u0442\u0443\u0440\u044B \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434 \u043B\u043E\u043A\u0443\u0441\u043E\u0432), \u044D\u0444\u0444\u0435\u043A\u0442 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 (\u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430 \u043D\u0430\u043C\u043D\u043E\u0433\u043E \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u0437\u0443\u0431\u0440\u0435\u0436\u043A\u0443), \u044D\u043B\u0430\u0431\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435 (\u0441\u0432\u044F\u0437\u044B\u0432\u0430\u043D\u0438\u0435 \u043D\u043E\u0432\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u0441 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C\u0438 \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438) \u0438 \u0433\u043B\u0443\u0431\u0438\u043D\u0430 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 (\u0431\u043E\u043B\u0435\u0435 \u0433\u043B\u0443\u0431\u043E\u043A\u0430\u044F \u0441\u0435\u043C\u0430\u043D\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u0441\u043E\u0437\u0434\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 \u043F\u0440\u043E\u0447\u043D\u044B\u0435 \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F).","\u0418\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u0441\u0438\u0433\u043D\u0430\u043B\u043E\u0432: \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u0430\u044F \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430 \u043F\u0430\u043C\u044F\u0442\u044C (\u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u0443\u043B\u0443\u0447\u0448\u0430\u0435\u0442\u0441\u044F, \u043A\u043E\u0433\u0434\u0430 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0435 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0441 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u043C\u0438 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F), \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u0430\u044F \u043E\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043F\u0430\u043C\u044F\u0442\u044C (\u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u0443\u043B\u0443\u0447\u0448\u0430\u0435\u0442\u0441\u044F, \u043A\u043E\u0433\u0434\u0430 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435) \u0438 \u043F\u0440\u0438\u043D\u0446\u0438\u043F \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F (\u043F\u0430\u043C\u044F\u0442\u044C \u043B\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442, \u043A\u043E\u0433\u0434\u0430 \u0441\u0438\u0433\u043D\u0430\u043B\u044B \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u044E\u0442 \u0441 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u043C\u0438 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F). \u0424\u0435\u043D\u043E\u043C\u0435\u043D \xAB\u043D\u0430 \u043A\u043E\u043D\u0447\u0438\u043A\u0435 \u044F\u0437\u044B\u043A\u0430\xBB \u0438\u043B\u043B\u044E\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u044B\u0439 \u0441\u0431\u043E\u0439 \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F.","\u0417\u0430\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437-\u0437\u0430 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C\u043E\u0432: \u0441\u0431\u043E\u0439 \u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F (\u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F \u0442\u0430\u043A \u0438 \u043D\u0435 \u043F\u043E\u043F\u0430\u043B\u0430 \u0432 \u0434\u043E\u043B\u0433\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0443\u044E \u043F\u0430\u043C\u044F\u0442\u044C), \u0440\u0430\u0441\u043F\u0430\u0434 \u0441\u043B\u0435\u0434\u0430 \u043F\u0430\u043C\u044F\u0442\u0438 (\u043A\u0440\u0438\u0432\u0430\u044F \u0437\u0430\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u042D\u0431\u0431\u0438\u043D\u0433\u0430\u0443\u0437\u0430 \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u0431\u043E\u043B\u044C\u0448\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u0437\u0430\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432 \u043F\u0435\u0440\u0432\u044B\u0439 \u0447\u0430\u0441), \u043F\u0440\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u044F (\u0441\u0442\u0430\u0440\u044B\u0435 \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F \u043C\u0435\u0448\u0430\u044E\u0442 \u043D\u043E\u0432\u043E\u043C\u0443 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044E) \u0438 \u0440\u0435\u0442\u0440\u043E\u0430\u043A\u0442\u0438\u0432\u043D\u0430\u044F \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u044F (\u043D\u043E\u0432\u043E\u0435 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u0435 \u043C\u0435\u0448\u0430\u0435\u0442 \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044E \u0441\u0442\u0430\u0440\u043E\u0433\u043E).","\u041F\u0430\u043C\u044F\u0442\u044C \u0440\u0435\u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0442\u0438\u0432\u043D\u0430, \u0430 \u043D\u0435 \u0440\u0435\u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0438\u0432\u043D\u0430 \u2014 \u043C\u044B \u0430\u043A\u0442\u0438\u0432\u043D\u043E \u043F\u0435\u0440\u0435\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u043C \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F \u043A\u0430\u0436\u0434\u044B\u0439 \u0440\u0430\u0437, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0438\u0445 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u0438\u044F\u043C. \u0418\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u042D\u043B\u0438\u0437\u0430\u0431\u0435\u0442 \u041B\u043E\u0444\u0442\u0443\u0441 \u043E\u0431 \u044D\u0444\u0444\u0435\u043A\u0442\u0435 \u0434\u0435\u0437\u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043F\u043E\u043A\u0430\u0437\u0430\u043B\u043E, \u0447\u0442\u043E \u0432\u0432\u043E\u0434\u044F\u0449\u0430\u044F \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u0430\u044F \u043F\u043E\u0441\u043B\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u043C\u043E\u0436\u0435\u0442 \u0438\u0437\u043C\u0435\u043D\u0438\u0442\u044C \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F \u043E \u043D\u0435\u043C. \u042D\u0442\u043E \u0438\u043C\u0435\u0435\u0442 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u0434\u043B\u044F \u043D\u0430\u0434\u0435\u0436\u043D\u043E\u0441\u0442\u0438 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0438\u0439 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u0439 \u0438 \u043F\u0440\u0438\u0432\u0435\u043B\u043E \u043A \u0440\u0435\u0444\u043E\u0440\u043C\u0430\u043C \u0432 \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440\u0430\u0445 \u043E\u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0432 \u043F\u043E\u043B\u0438\u0446\u0438\u0438."],hy:["\u0531\u057F\u056F\u056B\u0576\u057D\u0578\u0576-\u0547\u056B\u0586\u0580\u056B\u0576\u056B \u0565\u057C\u0561\u057D\u057F\u056B\u0573\u0561\u0576 \u0574\u0578\u0564\u0565\u056C\u0568 \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0578\u057D\u0584\u0568 \u0565\u0580\u0565\u0584 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u0578\u057E. \u0536\u0563\u0561\u0575\u0561\u056F\u0561\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057A\u0561\u0570\u0578\u0582\u0574 \u0567 \u0579\u0574\u0577\u0561\u056F\u057E\u0561\u056E \u057F\u057E\u0575\u0561\u056C\u0576\u0565\u0580 \u057E\u0561\u0575\u0580\u056F\u0575\u0561\u0576\u056B \u056F\u0578\u057F\u0578\u0580\u0561\u056F\u0578\u057E \u2014 \u057A\u0561\u057F\u056F\u0565\u0580\u0561\u0575\u056B\u0576\u0568 \u057F\u0565\u057D\u0578\u0572\u0561\u056F\u0561\u0576\u056B \u0570\u0561\u0574\u0561\u0580, \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0578\u0572\u0568 \u0571\u0561\u0575\u0576\u056B \u0570\u0561\u0574\u0561\u0580), \u053F\u0561\u0580\u0573\u0561\u056A\u0561\u0574\u056F\u0565\u057F/\u0531\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u0561\u0575\u056B\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057A\u0561\u0570\u0578\u0582\u0574 \u0567 \u0574\u0578\u057F 7 \u057A\u056C\u0575\u0578\u0582\u057D-\u0574\u056B\u0576\u0578\u0582\u057D 2 \u057F\u0561\u0580\u0580 20-30 \u057E\u0561\u0575\u0580\u056F\u0575\u0561\u0576. \u0532\u0561\u0564\u0564\u0565\u056C\u056B\u056B \u0574\u0578\u0564\u0565\u056C\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0570\u0576\u0579\u0575\u0578\u0582\u0576\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0585\u0572\u0561\u056F\u0568, \u057F\u0565\u057D\u0561\u057F\u0561\u0580\u0561\u056E\u0561\u056F\u0561\u0576 \u0578\u0582\u0580\u057E\u0561\u0563\u056B\u056E\u0568 \u0587 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u056F\u0561\u0576 \u0572\u0565\u056F\u0561\u057E\u0561\u0580 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568) \u0587 \u0535\u0580\u056F\u0561\u0580\u0561\u056A\u0561\u0574\u056F\u0565\u057F \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0563\u0580\u0565\u0569\u0565 \u0561\u0576\u057D\u0561\u0570\u0574\u0561\u0576\u0561\u0583\u0561\u056F \u0570\u0566\u0578\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u057F\u0587\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576):","\u0532\u0561\u0581\u0561\u0570\u0561\u0575\u057F (\u0570\u057C\u0579\u0561\u056F\u0561\u0563\u0580\u0561\u0575\u056B\u0576) \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0563\u056B\u057F\u0561\u056F\u0581\u057E\u0561\u056E \u0570\u056B\u0577\u0565\u0581\u0578\u0582\u0574 \u0565\u0580\u056F\u0578\u0582 \u0565\u0576\u0569\u0561\u057F\u0565\u057D\u0561\u056F\u0576\u0565\u0580\u0578\u057E. \u053B\u0574\u0561\u057D\u057F\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0563\u056B\u057F\u0565\u056C\u056B\u0584\u0576\u0565\u0580 \u0587 \u0583\u0561\u057D\u057F\u0565\u0580 \u2014 \xAB\u0553\u0561\u0580\u056B\u0566\u0568 \u0556\u0580\u0561\u0576\u057D\u056B\u0561\u0575\u056B \u0574\u0561\u0575\u0580\u0561\u0584\u0561\u0572\u0561\u0584\u0576 \u0567\xBB) \u0587 \u0537\u057A\u056B\u0566\u0578\u0564\u056B\u056F \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0561\u0576\u0571\u0576\u0561\u056F\u0561\u0576 \u0583\u0578\u0580\u0571\u0561\u057C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0587 \u056B\u0580\u0561\u0564\u0561\u0580\u0571\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u2014 \xAB\u056B\u0574 \u0561\u057C\u0561\u057B\u056B\u0576 \u0585\u0580\u0568 \u0564\u057A\u0580\u0578\u0581\u0578\u0582\u0574\xBB): \u0535\u0580\u056F\u0578\u0582\u057D\u0576 \u0567\u056C \u0574\u0577\u0561\u056F\u057E\u0578\u0582\u0574 \u0565\u0576 \u0570\u056B\u057A\u0578\u056F\u0561\u0574\u057A\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E:","\u0539\u0561\u0584\u0576\u057E\u0561\u056E (\u0578\u0579 \u0564\u0565\u056F\u056C\u0561\u0580\u0561\u057F\u056B\u057E) \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0567 \u0561\u057C\u0561\u0576\u0581 \u0563\u056B\u057F\u0561\u056F\u0581\u057E\u0561\u056E \u056B\u0580\u0561\u0566\u0565\u056F\u0574\u0561\u0576. \u0538\u0576\u0569\u0561\u0581\u0561\u056F\u0561\u0580\u0563\u0561\u0575\u056B\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u0574\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0587 \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u0570\u0565\u056E\u0561\u0576\u056B\u057E \u057E\u0561\u0580\u0565\u056C\u0568 \u2014 \u0574\u0577\u0561\u056F\u057E\u0578\u0582\u0574 \u0567 \u0578\u0582\u0572\u0565\u0572\u056B\u056F\u056B \u0587 \u0562\u0561\u0566\u0561\u056C\u0561\u0575\u056B\u0576 \u0563\u0561\u0576\u0563\u056C\u056B\u0561\u0576\u0565\u0580\u056B \u0574\u0565\u057B), \u0564\u0561\u057D\u0561\u056F\u0561\u0576 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0576\u0565\u0580\u0568 \u0587 \u054A\u0580\u0561\u0575\u0574\u056B\u0576\u0563 (\u0574\u0565\u056F \u056D\u0569\u0561\u0576\u056B \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0561\u0566\u0564\u0578\u0582\u0574 \u0567 \u0561\u057E\u0565\u056C\u056B \u0578\u0582\u0577 \u056D\u0569\u0561\u0576\u056B \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u056B \u057E\u0580\u0561):","\u0531\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u056F\u057F\u0580\u0578\u0582\u056F \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u0578\u0582\u0574 \u0565\u0576 \u057A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574\u0568. \u053D\u0574\u0562\u0561\u057E\u0578\u0580\u0578\u0582\u0574 (\u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0574\u0562\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u056B\u0574\u0561\u057D\u057F\u0561\u056C\u056B\u0581 \u0574\u056B\u0561\u057E\u0578\u0580\u0576\u0565\u0580\u056B \u0574\u0565\u057B), \u0544\u0576\u0565\u0574\u0578\u0576\u056B\u056F\u0561 (\u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056D\u0569\u0561\u0576\u0578\u0572 \u0574\u056B\u057B\u0578\u0581\u0576\u0565\u0580, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u0570\u0561\u057A\u0561\u057E\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u056F\u0561\u0574 \u056C\u0578\u056F\u0578\u0582\u057D\u0576\u0565\u0580\u056B \u0574\u0565\u0569\u0578\u0564\u0568), \u054F\u0561\u0580\u0561\u056E\u0574\u0561\u0576 \u0567\u0586\u0565\u056F\u057F (\u0562\u0561\u0577\u056D\u057E\u0561\u056E \u057A\u0580\u0561\u056F\u057F\u056B\u056F\u0561\u0576 \u0577\u0561\u057F \u0561\u057E\u0565\u056C\u056B \u0562\u0561\u0580\u0571\u0580 \u0567, \u0584\u0561\u0576 \u057D\u0565\u0580\u057F\u0565\u056C\u0568), \u0544\u0577\u0561\u056F\u057E\u0561\u056E \u056F\u0580\u056F\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0576\u0578\u0580 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u057A\u0565\u056C\u0578\u057E \u0561\u057C\u056F\u0561 \u0563\u056B\u057F\u0565\u056C\u056B\u0584\u0576\u0565\u0580\u056B \u0570\u0565\u057F), \u0587 \u0544\u0577\u0561\u056F\u0574\u0561\u0576 \u056D\u0578\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u056D\u0578\u0580\u0568 \u056B\u0574\u0561\u057D\u057F\u0561\u0575\u056B\u0576 \u0574\u0577\u0561\u056F\u0578\u0582\u0574\u0568 \u057D\u057F\u0565\u0572\u056E\u0578\u0582\u0574 \u0567 \u0561\u057E\u0565\u056C\u056B \u0578\u0582\u056A\u0565\u0572 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580):","\u0531\u057C\u0562\u0565\u0580\u0578\u0582\u0574\u0568 \u056F\u0561\u056D\u057E\u0561\u056E \u0567 \u0570\u0578\u0582\u0577\u0578\u0582\u0574\u0576\u0565\u0580\u056B\u0581. \u053F\u0578\u0576\u057F\u0565\u0584\u057D\u057F\u056B\u0581 \u056F\u0561\u056D\u057E\u0561\u056E \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u056B\u0577\u0565\u056C\u0568 \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u057E\u0578\u0582\u0574 \u0567, \u0565\u0580\u0562 \u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0568 \u0570\u0561\u0574\u0568\u0576\u056F\u0576\u0578\u0582\u0574 \u0567 \u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u056B \u0570\u0565\u057F), \u054E\u056B\u0573\u0561\u056F\u056B\u0581 \u056F\u0561\u056D\u057E\u0561\u056E \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u056B\u0577\u0565\u056C\u0568 \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u057E\u0578\u0582\u0574 \u0567, \u0565\u0580\u0562 \u0576\u0565\u0580\u0584\u056B\u0576 \u057E\u056B\u0573\u0561\u056F\u0568 \u0570\u0561\u0574\u0568\u0576\u056F\u0576\u0578\u0582\u0574 \u0567), \u0587 \u053F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u0575\u0578\u0582\u0580\u0561\u0570\u0561\u057F\u056F\u0578\u0582\u0569\u0575\u0561\u0576 \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0568 (\u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056C\u0561\u057E\u0561\u0563\u0578\u0582\u0575\u0576\u0576 \u0567, \u0565\u0580\u0562 \u0578\u0580\u0578\u0576\u0574\u0561\u0576 \u0576\u0577\u0561\u0576\u0576\u0565\u0580\u0568 \u0570\u0561\u0574\u0568\u0576\u056F\u0576\u0578\u0582\u0574 \u0565\u0576 \u056F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u057A\u0561\u0575\u0574\u0561\u0576\u0576\u0565\u0580\u056B \u0570\u0565\u057F): \u053C\u0565\u0566\u057E\u056B \u056E\u0561\u0575\u0580\u056B \u0565\u0580\u0587\u0578\u0582\u0575\u0569\u0568 \u056C\u0578\u0582\u057D\u0561\u0562\u0561\u0576\u0578\u0582\u0574 \u0567 \u0578\u0580\u0578\u0576\u0574\u0561\u0576 \u0574\u0561\u057D\u0576\u0561\u056F\u056B \u0571\u0561\u056D\u0578\u0572\u0578\u0582\u0574\u0568:","\u0544\u0578\u057C\u0561\u0576\u0561\u056C\u0568 \u057F\u0565\u0572\u056B \u0567 \u0578\u0582\u0576\u0565\u0576\u0578\u0582\u0574 \u0574\u056B \u0584\u0561\u0576\u056B \u0574\u0565\u056D\u0561\u0576\u056B\u0566\u0574\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E. \u053F\u0578\u0564\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u0571\u0561\u056D\u0578\u0572\u0578\u0582\u0574 (\u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0565\u0580\u0562\u0565\u0584 \u0579\u056B \u0574\u057F\u0565\u056C \u0565\u0580\u056F\u0561\u0580\u0561\u056A\u0561\u0574\u056F\u0565\u057F \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u054A\u0561\u0570\u057A\u0561\u0576\u0574\u0561\u0576 \u0584\u0561\u0575\u0584\u0561\u0575\u0578\u0582\u0574 (\u0537\u0562\u056B\u0576\u0563\u0570\u0561\u0578\u0582\u057D\u056B \u0574\u0578\u057C\u0561\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0578\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0574\u0578\u057C\u0561\u0576\u0561\u056C\u0578\u0582 \u0574\u0565\u056E \u0574\u0561\u057D\u0568 \u057F\u0565\u0572\u056B \u0567 \u0578\u0582\u0576\u0565\u0576\u0578\u0582\u0574 \u0561\u057C\u0561\u057B\u056B\u0576 \u056A\u0561\u0574\u057E\u0561 \u0568\u0576\u0569\u0561\u0581\u0584\u0578\u0582\u0574), \u054A\u0580\u0578\u0561\u056F\u057F\u056B\u057E \u0574\u056B\u057B\u0561\u0574\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u056B\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574 \u0565\u0576 \u0576\u0578\u0580 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576\u0568) \u0587 \u0540\u0565\u057F\u0561\u0564\u0561\u0580\u0571 \u0574\u056B\u057B\u0561\u0574\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0576\u0578\u0580 \u0578\u0582\u057D\u0578\u0582\u0581\u0578\u0582\u0574\u0568 \u056D\u0561\u0569\u0561\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0576 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u057E\u0565\u0580\u0570\u056B\u0577\u0565\u056C\u0568):","\u0540\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u057E\u0565\u0580\u0561\u057D\u057F\u0565\u0572\u056E\u0578\u0572\u0561\u0563\u0580\u0561\u056F\u0561\u0576 \u0567, \u0578\u0579 \u0569\u0565 \u057E\u0565\u0580\u0561\u0580\u057F\u0561\u0564\u0580\u0578\u0572\u0561\u056F\u0561\u0576. \u0574\u0565\u0576\u0584 \u0561\u056F\u057F\u056B\u057E\u0578\u0580\u0565\u0576 \u057E\u0565\u0580\u0561\u056F\u0561\u057C\u0578\u0582\u0581\u0578\u0582\u0574 \u0565\u0576\u0584 \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0561\u0574\u0565\u0576 \u0561\u0576\u0563\u0561\u0574\u055D \u0564\u0580\u0561\u0576\u0584 \u0565\u0576\u0569\u0561\u056F\u0561 \u0564\u0561\u0580\u0571\u0576\u0565\u056C\u0578\u057E \u056D\u0565\u0572\u0561\u0569\u0575\u0578\u0582\u0580\u0574\u0561\u0576: \u0537\u056C\u056B\u0566\u0561\u0562\u0565\u0569 \u053C\u0578\u0586\u057F\u0578\u0582\u057D\u056B \u0561\u057A\u0561\u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0567\u0586\u0565\u056F\u057F\u056B \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u057E\u0565\u056C, \u0578\u0580 \u0574\u056B\u057B\u0578\u0581\u0561\u057C\u0578\u0582\u0574\u0576\u0565\u0580\u056B\u0581 \u0570\u0565\u057F\u0578 \u0561\u057A\u0561\u056F\u0578\u0572\u0574\u0576\u0578\u0580\u0578\u0577\u056B\u0579 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0583\u0578\u056D\u0565\u056C \u056B\u0580\u0561\u0564\u0561\u0580\u0571\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568: \u054D\u0561 \u056D\u0578\u0580\u0568 \u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0576\u0565\u0580 \u0578\u0582\u0576\u056B \u0561\u056F\u0561\u0576\u0561\u057F\u0565\u057D\u0576\u0565\u0580\u056B \u0581\u0578\u0582\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0570\u0578\u0582\u057D\u0561\u056C\u056B\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u0580 \u0587 \u0570\u0561\u0576\u0563\u0565\u0581\u0580\u0565\u056C \u0567 \u0578\u057D\u057F\u056B\u056F\u0561\u0576\u0561\u056F\u0561\u0576 \u0573\u0561\u0576\u0561\u0579\u0574\u0561\u0576 \u0568\u0576\u0569\u0561\u0581\u0561\u056F\u0561\u0580\u0563\u0565\u0580\u056B \u0562\u0561\u0580\u0565\u0583\u0578\u056D\u0578\u0582\u0574\u0576\u0565\u0580\u056B:"],az:["Atkinson-Shiffrin \xFC\xE7 m\u0259rh\u0259l\u0259li modeli \xFC\xE7 sistemd\u0259n ke\xE7\u0259n yadda\u015F\u0131 t\u0259svir edir: Sensor yadda\u015F\u0131 (xammal m\u0259lumatlar\u0131n\u0131 saniy\u0259nin hiss\u0259l\u0259ri \xFC\xE7\xFCn saxlay\u0131r - vizual \xFC\xE7\xFCn ikonik, s\u0259sli \xFC\xE7\xFCn \u0259k-s\u0259dal\u0131), Q\u0131sam\xFCdd\u0259tli/\u0130\u015F\xE7i yadda\u015F (20-30 saniy\u0259 \u0259rzind\u0259 t\u0259xmin\u0259n 7 plus-minus 2 elementi saxlay\u0131r; Baddeley modelin\u0259 fonoloji d\xF6ng\u0259, f\u0259za-vizual eskiz plan\u0131 v\u0259 m\u0259rk\u0259zi icraedici daxildir) v\u0259 Uzunm\xFCdd\u0259tli yadda\u015F (faktiki olaraq m\u0259hdudiyy\u0259tsiz tutum v\u0259 m\xFCdd\u0259t).",'A\u015Fkar (deklarativ) yadda\u015F iki alt tipl\u0259 \u015F\xFCurlu xat\u0131rlaman\u0131 \u0259hat\u0259 edir: Semantik yadda\u015F (m\u0259s\u0259l\u0259n, "Paris Fransan\u0131n paytaxt\u0131d\u0131r" kimi \xFCmumi bilik v\u0259 faktlar) v\u0259 Epizodik yadda\u015F (\u015F\u0259xsi t\u0259cr\xFCb\u0259l\u0259r v\u0259 hadis\u0259l\u0259r \u2014 "m\u0259kt\u0259bd\u0259 ilk g\xFCn\xFCm"). H\u0259r ikisi hipokampus vasit\u0259sil\u0259 i\u015Fl\u0259nir.',"Gizli (qeyri-deklarativ) yadda\u015F \u015F\xFCurlu m\u0259lumatl\u0131q olmadan f\u0259aliyy\u0259t g\xF6st\u0259rir: Prosedur yadda\u015F\u0131 (velosiped s\xFCrm\u0259k kimi bacar\u0131qlar v\u0259 v\u0259rdi\u015Fl\u0259r - beyincik v\u0259 bazal qanqliyada i\u015Fl\u0259nir), klassik kondisioner effektl\u0259ri v\u0259 Prayminq (bir stimula m\u0259ruz qalma sonrak\u0131 stimulun reaksiyas\u0131na t\u0259sir g\xF6st\u0259rir).","Effektiv kodla\u015Fd\u0131rma strategiyalar\u0131 yadda saxlama\u011F\u0131 k\u0259skin \u015F\u0259kild\u0259 yax\u015F\u0131la\u015Fd\u0131r\u0131r: Qrupla\u015Fd\u0131rma (m\u0259lumat\u0131 m\u0259nal\u0131 vahidl\u0259r\u0259 qrupla\u015Fd\u0131rmaq), Mnemonika (akroniml\u0259r v\u0259 ya lokus metodu kimi yadda\u015F yard\u0131mlar\u0131), Aral\u0131q effekti (paylanm\u0131\u015F t\u0259cr\xFCb\u0259 \u0259zb\u0259rl\u0259m\u0259kd\u0259n daha \xFCst\xFCnd\xFCr), T\u0259kmill\u0259\u015Fdirici t\u0259krar (yeni m\u0259lumatlar\u0131 m\xF6vcud bilikl\u0259rl\u0259 \u0259laq\u0259l\u0259ndirm\u0259k) v\u0259 Emal d\u0259rinliyi (daha d\u0259rin semantik emal daha g\xFCcl\xFC xatir\u0259l\u0259r yarad\u0131r).","B\u0259rpa etm\u0259k i\u015Far\u0259l\u0259rd\u0259n as\u0131l\u0131d\u0131r: Kontekstd\u0259n as\u0131l\u0131 yadda\u015F (\u0259traf m\xFChit kodla\u015Fd\u0131rma parametrin\u0259 uy\u011Fun g\u0259ldikd\u0259 xat\u0131rlama yax\u015F\u0131la\u015F\u0131r), V\u0259ziyy\u0259tl\u0259 ba\u011Fl\u0131 yadda\u015F (daxili v\u0259ziyy\u0259t uy\u011Funla\u015Fd\u0131qda xat\u0131rlama yax\u015F\u0131la\u015F\u0131r) v\u0259 Kodla\u015Fd\u0131rma x\xFCsusiyy\u0259ti prinsipi (geri qaytarma i\u015Far\u0259l\u0259ri kodla\u015Fd\u0131rma \u015F\u0259rtl\u0259rin\u0259 uy\u011Fun g\u0259ldikd\u0259 yadda\u015F \u0259n yax\u015F\u0131 formada olur). Dilin ucu (tip-of-the-tongue) fenomeni qism\u0259n axtar\u0131\u015F u\u011Fursuzlu\u011Funu n\xFCmayi\u015F etdirir.","Unutma bir ne\xE7\u0259 mexanizm vasit\u0259sil\u0259 ba\u015F verir: Kodla\u015Fd\u0131rma x\u0259tas\u0131 (m\u0259lumat he\xE7 vaxt uzunm\xFCdd\u0259tli yadda\u015Fa daxil olmad\u0131), Saxlaman\u0131n pozulmas\u0131 (Ebbinghaus-un unutma \u0259yrisi g\xF6st\u0259rir ki, \u0259ks\u0259r unutmamaq ilk saat \u0259rzind\u0259 ba\u015F verir), Proaktiv m\xFCdaxil\u0259 (k\xF6hn\u0259 xatir\u0259l\u0259r yeni \xF6yr\u0259nm\u0259ni pozur) v\u0259 Retroaktiv m\xFCdaxil\u0259 (yeni \xF6yr\u0259nm\u0259 k\xF6hn\u0259 xatir\u0259l\u0259rin xat\u0131rlanmas\u0131n\u0131 pozur).","Yadda\u015F rekonstruktivdir, reproduktiv deyil - biz h\u0259r d\u0259f\u0259 xatir\u0259l\u0259ri aktiv \u015F\u0259kild\u0259 yenid\u0259n qururuq v\u0259 onlar\u0131 t\u0259hrif\u0259 qar\u015F\u0131 h\u0259ssas edirik. Elizabeth Loftus-un dezinformasiya effekti il\u0259 ba\u011Fl\u0131 ara\u015Fd\u0131rmas\u0131 g\xF6st\u0259rdi ki, hadis\u0259d\u0259n sonrak\u0131 yanl\u0131\u015F m\u0259lumatlar hadis\u0259l\u0259rin xatir\u0259l\u0259rini d\u0259yi\u015Fdir\u0259 bil\u0259r. Bunun \u015Fahidl\u0259rin ifad\u0259l\u0259rinin etibarl\u0131l\u0131\u011F\u0131na d\u0259rind\u0259n t\u0259sirl\u0259ri oldu v\u0259 polisin tan\u0131nmas\u0131 prosedurlar\u0131nda islahatlara s\u0259b\u0259b oldu."]},funFact:{en:'The "Google effect" (digital amnesia) is a real phenomenon: people are less likely to remember information they know they can easily look up online. Your brain outsources memory storage to your phone!',ka:"\u201EGoogle-\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u201C \u10E0\u10D4\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E4\u10D4\u10DC\u10DD\u10DB\u10D4\u10DC\u10D8\u10D0: \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D0\u10D3 \u10D8\u10DB\u10D0\u10EE\u10E1\u10DD\u10D5\u10E0\u10D4\u10D1\u10D4\u10DC \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D8\u10E1 \u10DB\u10DD\u10EB\u10D8\u10D4\u10D1\u10D0\u10EA \u10DB\u10D0\u10E0\u10E2\u10D8\u10D5\u10D0\u10D3 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0\u10D7 \u10D8\u10DC\u10E2\u10D4\u10E0\u10DC\u10D4\u10E2\u10E8\u10D8.",ru:"\xAB\u042D\u0444\u0444\u0435\u043A\u0442 Google\xBB \u2014 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0439 \u0444\u0435\u043D\u043E\u043C\u0435\u043D: \u043B\u044E\u0434\u0438 \u0440\u0435\u0436\u0435 \u0437\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u044E\u0442 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u043C\u043E\u0436\u043D\u043E \u043B\u0435\u0433\u043A\u043E \u043D\u0430\u0439\u0442\u0438 \u0432 \u0418\u043D\u0442\u0435\u0440\u043D\u0435\u0442\u0435.",hy:"\xABGoogle-\u056B \u0567\u0586\u0565\u056F\u057F\u0568\xBB \u056B\u0580\u0561\u056F\u0561\u0576 \u0565\u0580\u0587\u0578\u0582\u0575\u0569 \u0567. \u0574\u0561\u0580\u0564\u056B\u056F \u0561\u057E\u0565\u056C\u056B \u0584\u056B\u0579 \u0570\u0561\u056F\u057E\u0561\u056E \u0565\u0576 \u0570\u056B\u0577\u0565\u056C \u0561\u0575\u0576 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0578\u0580\u0568 \u0563\u056B\u057F\u0565\u0576, \u0578\u0580 \u056F\u0561\u0580\u0578\u0572 \u0565\u0576 \u0570\u0565\u0577\u057F\u0578\u0582\u0569\u0575\u0561\u0574\u0562 \u0563\u057F\u0576\u0565\u056C \u0561\u057C\u0581\u0561\u0576\u0581:",az:'"Google effekti" real fenomendir: insanlar internetd\u0259 asanl\u0131qla tapa bil\u0259c\u0259kl\u0259ri m\u0259lumatlar\u0131 daha az yadda saxlay\u0131rlar.'},realWorld:{en:"Spaced repetition (reviewing at increasing intervals) is the single most effective study technique. Apps like Anki use it. Cramming the night before works for short-term recall but fades within days.",ka:"\u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DB\u10D4\u10DD\u10E0\u10D4\u10D1\u10D0 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8 \u10E1\u10D0\u10E1\u10EC\u10D0\u10D5\u10DA\u10DD \u10E2\u10D4\u10E5\u10DC\u10D8\u10D9\u10D0\u10D0.",ru:"\u0418\u043D\u0442\u0435\u0440\u0432\u0430\u043B\u044C\u043D\u044B\u0435 \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u044F \u2014 \u0441\u0430\u043C\u044B\u0439 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0439 \u043C\u0435\u0442\u043E\u0434 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F.",hy:"\u053B\u0576\u057F\u0565\u0580\u057E\u0561\u056C\u0561\u0575\u056B\u0576 \u056F\u0580\u10D9\u10DC\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u0561\u0574\u0565\u0576\u0561\u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0574\u0565\u0569\u0578\u0564\u0576 \u0567:",az:"Aral\u0131ql\u0131 t\u0259krar \u0259n effektiv \xF6yr\u0259nm\u0259 \xFCsuludur."}},8:{title:{en:"Cognition and Intelligence",ka:"\u10E8\u10D4\u10DB\u10D4\u10EA\u10DC\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8",ru:"\u041F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0438 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442",hy:"\u0543\u0561\u0576\u0561\u0579\u0578\u0582\u0574 \u0587 \u0562\u0561\u0576\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576",az:"\u0130drak v\u0259 \u0130ntellekt"},description:{en:"Thinking, problem-solving, language, and measuring intelligence.",ka:"\u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0, \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10E0\u10D0, \u10D4\u10DC\u10D0 \u10D3\u10D0 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8\u10E1 \u10D2\u10D0\u10D6\u10DD\u10DB\u10D5\u10D0.",ru:"\u041C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C, \u044F\u0437\u044B\u043A \u0438 \u0438\u0437\u043C\u0435\u0440\u0435\u043D\u0438\u0435 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430.",hy:"\u0544\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u056D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u056C\u0578\u0582\u056E\u0578\u0582\u0574, \u056C\u0565\u0566\u0578\u0582 \u0587 \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u056B \u0579\u0561\u0583\u0578\u0582\u0574:",az:"D\xFC\u015F\xFCnm\u0259, problem h\u0259ll etm\u0259, dil v\u0259 z\u0259kan\u0131n \xF6l\xE7\xFClm\u0259si."},keyTopics:{en:["Problem Solving","Decision Making","Language","Intelligence Testing","Creativity"],ka:["\u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10E0\u10D0","\u10D2\u10D0\u10D3\u10D0\u10EC\u10E7\u10D5\u10D4\u10E2\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10E6\u10D4\u10D1\u10D0","\u10D4\u10DC\u10D0","\u10D3\u10D0\u10D6\u10D5\u10D4\u10E0\u10D5\u10D8\u10E1 \u10E2\u10D4\u10E1\u10E2\u10D8\u10E0\u10D4\u10D1\u10D0","\u10D9\u10E0\u10D4\u10D0\u10E2\u10D8\u10E3\u10DA\u10DD\u10D1\u10D0"],ru:["\u0420\u0435\u0448\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C","\u041F\u0440\u0438\u043D\u044F\u0442\u0438\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0439","\u042F\u0437\u044B\u043A","\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430","\u041A\u0440\u0435\u0430\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C"],hy:["\u053D\u0576\u0564\u0580\u056B \u056C\u0578\u0582\u056E\u0578\u0582\u0574","\u0548\u0580\u0578\u0577\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u056F\u0561\u0575\u0561\u0581\u0578\u0582\u0574","\u053C\u0565\u0566\u0578\u0582","\u0540\u0565\u057F\u0561\u056D\u0578\u0582\u0566\u0578\u0582\u0569\u0575\u0561\u0576 \u0569\u0565\u057D\u057F\u0561\u057E\u0578\u0580\u0578\u0582\u0574","\u054D\u057F\u0565\u0572\u056E\u0561\u0563\u0578\u0580\u056E\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576"],az:["Problemin h\u0259lli","Q\u0259rar verm\u0259","Dil","K\u0259\u015Ffiyyat Testi","Yarad\u0131c\u0131l\u0131q"]},summary:{en:"Cognition encompasses all mental activities involved in acquiring, processing, and using knowledge \u2014 including perceiving, thinking, reasoning, problem-solving, decision-making, and communicating through language. This chapter examines how we form concepts and categories to organize our world, exploring problem-solving strategies such as algorithms (systematic but slow), heuristics (fast mental shortcuts prone to error), and insight (sudden moments of clarity). It covers the major cognitive biases that systematically distort our thinking \u2014 confirmation bias, the availability heuristic, anchoring, and the framing effect \u2014 extensively studied by Daniel Kahneman and Amos Tversky. The chapter also explores language development from babbling to complex grammar, Chomsky's theory of an innate Language Acquisition Device, and the Sapir-Whorf hypothesis about how language may shape thought. Intelligence is examined through competing theories \u2014 Spearman's general intelligence (g), Gardner's multiple intelligences, and Sternberg's triarchic model \u2014 alongside the history, methodology, and controversies surrounding IQ testing, including heritability, cultural bias, and the Flynn effect.",ka:"\u10E8\u10D4\u10DB\u10D4\u10EA\u10DC\u10D4\u10D1\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0 \u10D2\u10DD\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5 \u10D0\u10E5\u10E2\u10D8\u10D5\u10DD\u10D1\u10D0\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10EA\u10DD\u10D3\u10DC\u10D8\u10E1 \u10DB\u10DD\u10DE\u10DD\u10D5\u10D4\u10D1\u10D0\u10E1\u10D7\u10D0\u10DC, \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D0\u10E1\u10D7\u10D0\u10DC \u10D3\u10D0 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D0\u10E1\u10D7\u10D0\u10DC \u2014 \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10D0\u10E6\u10E5\u10DB\u10D0\u10E1, \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1, \u10DB\u10E1\u10EF\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1, \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10E0\u10D0\u10E1, \u10D2\u10D0\u10D3\u10D0\u10EC\u10E7\u10D5\u10D4\u10E2\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10E6\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D4\u10DC\u10D8\u10E1 \u10E1\u10D0\u10E8\u10E3\u10D0\u10DA\u10D4\u10D1\u10D8\u10D7 \u10D9\u10DD\u10DB\u10E3\u10DC\u10D8\u10D9\u10D0\u10EA\u10D8\u10D0\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10E5\u10DB\u10DC\u10D8\u10D7 \u10EA\u10DC\u10D4\u10D1\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10D9\u10D0\u10E2\u10D4\u10D2\u10DD\u10E0\u10D8\u10D4\u10D1\u10E1 \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E1\u10D0\u10DB\u10E7\u10D0\u10E0\u10DD\u10E1 \u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1, \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10D8\u10DB\u10DD\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10E0\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10E1, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10D0\u10DA\u10D2\u10DD\u10E0\u10D8\u10D7\u10DB\u10D4\u10D1\u10D8 (\u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10E2\u10E3\u10E0\u10D8, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10DC\u10D4\u10DA\u10D8), \u10F0\u10D4\u10D5\u10E0\u10D8\u10E1\u10E2\u10D8\u10D9\u10D0 (\u10E1\u10EC\u10E0\u10D0\u10E4\u10D8 \u10D2\u10DD\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5\u10D8 \u10DB\u10D0\u10DA\u10E1\u10D0\u10EE\u10DB\u10DD\u10D1\u10D4\u10D1\u10D8, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10E8\u10D4\u10EA\u10D3\u10DD\u10DB\u10D4\u10D1\u10D8\u10E1\u10D9\u10D4\u10DC \u10D0\u10E0\u10D8\u10E1 \u10DB\u10D8\u10D3\u10E0\u10D4\u10D9\u10D8\u10DA\u10D8) \u10D3\u10D0 \u10D8\u10DC\u10E1\u10D0\u10D8\u10E2\u10D8 (\u10E1\u10D8\u10EA\u10EE\u10D0\u10D3\u10D8\u10E1 \u10DB\u10DD\u10E3\u10DA\u10DD\u10D3\u10DC\u10D4\u10DA\u10D8 \u10DB\u10DD\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8). \u10D8\u10E1 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10E2\u10E3\u10E0\u10D0\u10D3 \u10D0\u10DB\u10D0\u10EE\u10D8\u10DC\u10EF\u10D4\u10D1\u10D4\u10DC \u10E9\u10D5\u10D4\u10DC\u10E1 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1 \u2014 \u10D3\u10D0\u10D3\u10D0\u10E1\u10E2\u10E3\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D0\u10E1, \u10EE\u10D4\u10DA\u10DB\u10D8\u10E1\u10D0\u10EC\u10D5\u10D3\u10DD\u10DB\u10DD\u10D1\u10D8\u10E1 \u10F0\u10D4\u10D5\u10E0\u10D8\u10E1\u10E2\u10D8\u10D9\u10D0\u10E1, \u10D0\u10DC\u10D9\u10DD\u10E0\u10D8\u10DC\u10D2\u10E1 \u10D3\u10D0 \u10E4\u10E0\u10D4\u10D8\u10DB\u10D8\u10DC\u10D2\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E1 \u2014 \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10E4\u10D0\u10E0\u10D7\u10DD\u10D3 \u10E8\u10D4\u10D8\u10E1\u10EC\u10D0\u10D5\u10DA\u10D4\u10E1 \u10D3\u10D0\u10DC\u10D8\u10D4\u10DA \u10D9\u10D0\u10DC\u10D4\u10DB\u10D0\u10DC\u10DB\u10D0 \u10D3\u10D0 \u10D0\u10DB\u10DD\u10E1 \u10E2\u10D5\u10D4\u10E0\u10E1\u10D9\u10D8\u10DB. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D4\u10DC\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10E1 \u10E2\u10D8\u10E2\u10D8\u10DC\u10D8\u10D3\u10D0\u10DC (babbling) \u10E0\u10D7\u10E3\u10DA \u10D2\u10E0\u10D0\u10DB\u10D0\u10E2\u10D8\u10D9\u10D0\u10DB\u10D3\u10D4, \u10E9\u10DD\u10DB\u10E1\u10D9\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0\u10E1 \u10D4\u10DC\u10D8\u10E1 \u10D0\u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D0\u10DC\u10D3\u10D0\u10E7\u10DD\u10DA\u10D8\u10DA\u10D8 \u10DB\u10D4\u10E5\u10D0\u10DC\u10D8\u10D6\u10DB\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1 \u10D3\u10D0 \u10E1\u10D0\u10DE\u10D8\u10E0-\u10E3\u10DD\u10E0\u10E4\u10D8\u10E1 \u10F0\u10D8\u10DE\u10DD\u10D7\u10D4\u10D6\u10D0\u10E1 \u10D8\u10DB\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10E1 \u10D4\u10DC\u10D0 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1. \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D4\u10D1\u10D0 \u10D9\u10DD\u10DC\u10D9\u10E3\u10E0\u10D4\u10DC\u10E2\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7 \u2014 \u10E1\u10DE\u10D8\u10E0\u10DB\u10D4\u10DC\u10D8\u10E1 \u10D6\u10DD\u10D2\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 (g), \u10D2\u10D0\u10E0\u10D3\u10DC\u10D4\u10E0\u10D8\u10E1 \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10DB\u10EE\u10E0\u10D8\u10D5\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 \u10D3\u10D0 \u10E1\u10E2\u10D4\u10E0\u10DC\u10D1\u10D4\u10E0\u10D2\u10D8\u10E1 \u10E2\u10E0\u10D8\u10D0\u10E0\u10E5\u10D8\u10E3\u10DA\u10D8 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8 \u2014 IQ \u10E2\u10D4\u10E1\u10E2\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D8\u10E1\u10E2\u10DD\u10E0\u10D8\u10D0\u10E1\u10D7\u10D0\u10DC, \u10DB\u10D4\u10D7\u10DD\u10D3\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10E1\u10D7\u10D0\u10DC \u10D3\u10D0 \u10D3\u10D0\u10DE\u10D8\u10E0\u10D8\u10E1\u10DE\u10D8\u10E0\u10D4\u10D1\u10D4\u10D1\u10D7\u10D0\u10DC \u10D4\u10E0\u10D7\u10D0\u10D3, \u10DB\u10D4\u10DB\u10D9\u10D5\u10D8\u10D3\u10E0\u10D4\u10DD\u10D1\u10D8\u10D7\u10DD\u10D1\u10D8\u10E1, \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10E3\u10DA\u10D8 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0 \u10E4\u10DA\u10D8\u10DC\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u10E1 \u10E9\u10D0\u10D7\u10D5\u10DA\u10D8\u10D7.",ru:"\u041F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0432\u0441\u044E \u0443\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0443\u044E \u0441 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435\u043C, \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u043E\u0439 \u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u0437\u043D\u0430\u043D\u0438\u0439, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435, \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0435, \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C, \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0438 \u0432\u0435\u0440\u0431\u0430\u043B\u044C\u043D\u043E\u0435 \u043E\u0431\u0449\u0435\u043D\u0438\u0435. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043A\u0430\u043A \u043C\u044B \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u043C \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438 \u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u0434\u043B\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u043D\u0430\u0448\u0435\u0433\u043E \u043C\u0438\u0440\u0430, \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0442\u0441\u044F \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0430\u043B\u0433\u043E\u0440\u0438\u0442\u043C\u044B (\u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435, \u043D\u043E \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u044B\u0435), \u044D\u0432\u0440\u0438\u0441\u0442\u0438\u043A\u0438 (\u0431\u044B\u0441\u0442\u0440\u044B\u0435 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u044F\u0440\u043B\u044B\u043A\u0438, \u0441\u043A\u043B\u043E\u043D\u043D\u044B\u0435 \u043A \u043E\u0448\u0438\u0431\u043A\u0430\u043C) \u0438 \u0438\u043D\u0441\u0430\u0439\u0442 (\u0432\u043D\u0435\u0437\u0430\u043F\u043D\u044B\u0435 \u043C\u043E\u043C\u0435\u043D\u0442\u044B \u043F\u0440\u043E\u0437\u0440\u0435\u043D\u0438\u044F). \u0412 \u043D\u0435\u0439 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0438\u0441\u043A\u0430\u0436\u0430\u044E\u0442 \u043D\u0430\u0448\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \u2014 \u043F\u0440\u0435\u0434\u0432\u0437\u044F\u0442\u043E\u0441\u0442\u044C \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F, \u044D\u0432\u0440\u0438\u0441\u0442\u0438\u043A\u0430 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0441\u0442\u0438, \u044D\u0444\u0444\u0435\u043A\u0442 \u043F\u0440\u0438\u0432\u044F\u0437\u043A\u0438 \u0438 \u044D\u0444\u0444\u0435\u043A\u0442 \u0444\u0440\u0435\u0439\u043C\u0438\u043D\u0433\u0430, \u2014 \u0448\u0438\u0440\u043E\u043A\u043E \u0438\u0437\u0443\u0447\u0435\u043D\u043D\u044B\u0435 \u0414\u044D\u043D\u0438\u0435\u043B\u043E\u043C \u041A\u0430\u043D\u0435\u043C\u0430\u043D\u043E\u043C \u0438 \u0410\u043C\u043E\u0441\u043E\u043C \u0422\u0432\u0435\u0440\u0441\u043A\u0438. \u0413\u043B\u0430\u0432\u0430 \u0442\u0430\u043A\u0436\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u044F\u0437\u044B\u043A\u0430 \u043E\u0442 \u043B\u0435\u043F\u0435\u0442\u0430 \u0434\u043E \u0441\u043B\u043E\u0436\u043D\u043E\u0439 \u0433\u0440\u0430\u043C\u043C\u0430\u0442\u0438\u043A\u0438, \u0442\u0435\u043E\u0440\u0438\u044E \u0425\u043E\u043C\u0441\u043A\u043E\u0433\u043E \u043E \u0432\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u043C \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435 \u0443\u0441\u0432\u043E\u0435\u043D\u0438\u044F \u044F\u0437\u044B\u043A\u0430 \u0438 \u0433\u0438\u043F\u043E\u0442\u0435\u0437\u0443 \u0421\u0435\u043F\u0438\u0440\u0430-\u0423\u043E\u0440\u0444\u0430 \u043E \u0442\u043E\u043C, \u043A\u0430\u043A \u044F\u0437\u044B\u043A \u043C\u043E\u0436\u0435\u0442 \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435. \u0418\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u0438\u0437\u043C\u0443 \u043A\u043E\u043D\u043A\u0443\u0440\u0438\u0440\u0443\u044E\u0449\u0438\u0445 \u0442\u0435\u043E\u0440\u0438\u0439 \u2014 \u043E\u0431\u0449\u0435\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 \u0421\u043F\u0438\u0440\u043C\u0435\u043D\u0430 (g), \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 \u0413\u0430\u0440\u0434\u043D\u0435\u0440\u0430 \u0438 \u0442\u0440\u0438\u0430\u0440\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043C\u043E\u0434\u0435\u043B\u0438 \u0421\u0442\u0435\u0440\u043D\u0431\u0435\u0440\u0433\u0430 \u2014 \u043D\u0430\u0440\u044F\u0434\u0443 \u0441 \u0438\u0441\u0442\u043E\u0440\u0438\u0435\u0439, \u043C\u0435\u0442\u043E\u0434\u043E\u043B\u043E\u0433\u0438\u0435\u0439 \u0438 \u0441\u043F\u043E\u0440\u0430\u043C\u0438 \u0432\u043E\u043A\u0440\u0443\u0433 IQ-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043D\u0430\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C, \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u0443\u044E \u043F\u0440\u0435\u0434\u0432\u0437\u044F\u0442\u043E\u0441\u0442\u044C \u0438 \u044D\u0444\u0444\u0435\u043A\u0442 \u0424\u043B\u0438\u043D\u043D\u0430.",hy:"\u0543\u0561\u0576\u0561\u0579\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0563\u056B\u057F\u0565\u056C\u056B\u0584\u0576\u0565\u0580\u056B \u0571\u0565\u057C\u0584\u0562\u0565\u0580\u0574\u0561\u0576, \u0574\u0577\u0561\u056F\u0574\u0561\u0576 \u0587 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0574\u0561\u0576 \u0570\u0565\u057F \u056F\u0561\u057A\u057E\u0561\u056E \u0562\u0578\u056C\u0578\u0580 \u0574\u057F\u0561\u057E\u0578\u0580 \u0563\u0578\u0580\u056E\u0578\u0582\u0576\u0565\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568\u055D \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0568\u0576\u056F\u0561\u056C\u0578\u0582\u0574\u0568, \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u057F\u0580\u0561\u0574\u0561\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u056D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u056C\u0578\u0582\u056E\u0578\u0582\u0574\u0568, \u0578\u0580\u0578\u0577\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u056F\u0561\u0575\u0561\u0581\u0578\u0582\u0574\u0568 \u0587 \u056C\u0565\u0566\u057E\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E \u0570\u0561\u0572\u0578\u0580\u0564\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0584\u0576\u0576\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0563\u0561\u0572\u0561\u0583\u0561\u0580\u0576\u0565\u0580 \u0587 \u056F\u0561\u057F\u0565\u0563\u0578\u0580\u056B\u0561\u0576\u0565\u0580\u055D \u0574\u0565\u0580 \u0561\u0577\u056D\u0561\u0580\u0570\u0568 \u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580\u055D \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0565\u056C\u0578\u057E \u056D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u056C\u0578\u0582\u056E\u0574\u0561\u0576 \u0561\u0575\u0576\u057A\u056B\u057D\u056B \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u0561\u056C\u0563\u0578\u0580\u056B\u0569\u0574\u0576\u0565\u0580\u0568 (\u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u057E\u0561\u056E, \u0562\u0561\u0575\u0581 \u0564\u0561\u0576\u0564\u0561\u0572), \u0567\u057E\u0580\u056B\u057D\u057F\u056B\u056F\u0561\u0576 (\u0561\u0580\u0561\u0563 \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0561\u0580\u0573\u0578\u0582\u0572\u056B\u0576\u0565\u0580, \u0578\u0580\u0578\u0576\u0584 \u0570\u0561\u056F\u057E\u0561\u056E \u0565\u0576 \u057D\u056D\u0561\u056C\u0576\u0565\u0580\u056B) \u0587 \u056B\u0576\u057D\u0561\u0575\u0569\u0568 (\u057A\u0561\u0580\u0566\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0576\u056F\u0561\u0580\u056E\u0561\u056F\u056B \u057A\u0561\u0570\u0565\u0580): \u0531\u0575\u0576 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u057A\u0561\u0580\u0562\u0565\u0580\u0561\u0562\u0561\u0580 \u056D\u0565\u0572\u0561\u0569\u0575\u0578\u0582\u0580\u0578\u0582\u0574 \u0565\u0576 \u0574\u0565\u0580 \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568\u055D \u0570\u0561\u057D\u057F\u0561\u057F\u0574\u0561\u0576 \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0561\u057C\u056F\u0561\u0575\u0578\u0582\u0569\u0575\u0561\u0576 \u0567\u057E\u0580\u056B\u057D\u057F\u056B\u056F\u0561\u0576, \u056D\u0561\u0580\u057D\u056D\u0578\u0582\u0574\u0568 \u0587 \u0577\u0580\u057B\u0561\u0576\u0561\u056F\u0574\u0561\u0576 \u0567\u0586\u0565\u056F\u057F\u0568, \u0578\u0580\u0578\u0576\u0584 \u056C\u0561\u0575\u0576\u0578\u0580\u0565\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u057E\u0565\u056C \u0565\u0576 \u0534\u0561\u0576\u056B\u0565\u056C \u053F\u0561\u0576\u0565\u0574\u0561\u0576\u056B \u0587 \u0531\u0574\u0578\u057D \u054F\u057E\u0565\u0580\u057D\u056F\u0578\u0582 \u056F\u0578\u0572\u0574\u056B\u0581: \u0533\u056C\u0578\u0582\u056D\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0576\u0561\u0587 \u056C\u0565\u0566\u057E\u056B \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574\u0568 \u0569\u0578\u0569\u0578\u057E\u0561\u0576\u0584\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u0562\u0561\u0580\u0564 \u0584\u0565\u0580\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0549\u0578\u0574\u057D\u056F\u0578\u0582 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056C\u0565\u0566\u057E\u056B \u0571\u0565\u057C\u0584\u0562\u0565\u0580\u0574\u0561\u0576 \u0562\u0576\u0561\u056E\u056B\u0576 \u057D\u0561\u0580\u0584\u056B \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0575\u0561\u056C, \u0587 \u054D\u0561\u057A\u056B\u0580-\u0548\u0582\u0578\u0580\u0586\u056B \u057E\u0561\u0580\u056F\u0561\u056E\u0576 \u0561\u0575\u0576 \u0574\u0561\u057D\u056B\u0576, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u056F\u0561\u0580\u0578\u0572 \u0567 \u056C\u0565\u0566\u0578\u0582\u0576 \u0571\u0587\u0561\u057E\u0578\u0580\u0565\u056C \u0574\u056B\u057F\u0584\u0568: \u053B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0568 \u0564\u056B\u057F\u0561\u0580\u056F\u057E\u0578\u0582\u0574 \u0567 \u0574\u0580\u0581\u0561\u056F\u0581\u0578\u0572 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E\u055D \u054D\u0583\u056B\u0580\u0574\u0561\u0576\u056B \u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0568 (g), \u0533\u0561\u0580\u0564\u0576\u0565\u0580\u056B \u0562\u0561\u0566\u0574\u0561\u056F\u056B \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0576\u0565\u0580\u0568 \u0587 \u054D\u057F\u0565\u0580\u0576\u0562\u0565\u0580\u0563\u056B \u0565\u057C\u0561\u0579\u0561\u0583 \u0574\u0578\u0564\u0565\u056C\u0568\u055D IQ \u0569\u0565\u057D\u057F\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u057A\u0561\u057F\u0574\u0578\u0582\u0569\u0575\u0561\u0576, \u0574\u0565\u0569\u0578\u0564\u0561\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0570\u0561\u056F\u0561\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0570\u0565\u057F \u0574\u0565\u056F\u057F\u0565\u0572, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u056A\u0561\u057C\u0561\u0576\u0563\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0574\u0577\u0561\u056F\u0578\u0582\u0569\u0561\u0575\u056B\u0576 \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0556\u056C\u056B\u0576\u0576\u056B \u0567\u0586\u0565\u056F\u057F\u0568:",az:"\u0130drak m\u0259lumat\u0131n \u0259ld\u0259 edilm\u0259si, i\u015Fl\u0259nm\u0259si v\u0259 istifad\u0259si il\u0259 ba\u011Fl\u0131 b\xFCt\xFCn zehni f\u0259aliyy\u0259tl\u0259ri \u2014 o c\xFCml\u0259d\u0259n qavray\u0131\u015F, d\xFC\u015F\xFCnm\u0259, m\xFChakim\u0259 y\xFCr\xFCtm\u0259, problem h\u0259ll etm\u0259, q\u0259rar verm\u0259 v\u0259 dil vasit\u0259sil\u0259 \xFCnsiyy\u0259t qurma\u011F\u0131 \u0259hat\u0259 edir. Bu f\u0259sil d\xFCnyam\u0131z\u0131 t\u0259\u015Fkil etm\u0259k \xFC\xE7\xFCn anlay\u0131\u015Flar v\u0259 kateqoriyalar yaratma\u011F\u0131m\u0131z\u0131 t\u0259dqiq edir, alqoritml\u0259r (sistematik, lakin yava\u015F), hevristikalar (s\xFCr\u0259tli, lakin x\u0259talara meylli zehni q\u0131sa yollar) v\u0259 b\u0259sir\u0259t/insayt (q\u0259fil ayd\u0131nl\u0131q anlar\u0131) kimi problem h\u0259ll etm\u0259 strategiyalar\u0131n\u0131 ara\u015Fd\u0131r\u0131r. O, Daniel Kahneman v\u0259 Amos Tversky t\u0259r\u0259find\u0259n geni\u015F \u015F\u0259kild\u0259 t\u0259dqiq edilmi\u015F d\xFC\u015F\xFCnc\u0259mizi sistematik olaraq t\u0259hrif ed\u0259n \u0259sas koqnitiv q\u0259r\u0259zl\u0259ri \u2014 t\u0259sdiql\u0259m\u0259 q\u0259r\u0259zi, \u0259l\xE7atanl\u0131q hevristikas\u0131, l\xF6vb\u0259rl\u0259m\u0259 v\u0259 \xE7\u0259r\xE7iv\u0259l\u0259m\u0259 effekti \u2014 \u0259hat\u0259 edir. F\u0259sil h\u0259m\xE7inin babblingd\u0259n (\xE7a\u011Falar\u0131n \xE7\u0131xard\u0131\u011F\u0131 s\u0259sl\u0259r) m\xFCr\u0259kk\u0259b qrammatikaya q\u0259d\u0259r dilin inki\u015Faf\u0131n\u0131, Chomskynin fitri Dil \u018Fld\u0259etm\u0259 Mexanizmi (LAD) n\u0259z\u0259riyy\u0259sini v\u0259 dilin d\xFC\u015F\xFCnc\u0259ni nec\u0259 formala\u015Fd\u0131ra bil\u0259c\u0259yin\u0259 dair Sapir-Whorf hipotezini ara\u015Fd\u0131r\u0131r. \u0130ntellekt r\u0259qib n\u0259z\u0259riyy\u0259l\u0259r \u2014 Spearmanin \xFCmumi intellekti (g), Gardnerin \xE7ox\u015Fax\u0259li intellekti v\u0259 Sternbergin triarxik modeli vasit\u0259sil\u0259 n\u0259z\u0259rd\u0259n ke\xE7irilir, h\u0259m\xE7inin irsiyy\u0259t, m\u0259d\u0259ni q\u0259r\u0259z v\u0259 Flynn effekti d\u0259 daxil olmaqla IQ testl\u0259rinin tarixi, metodologiyas\u0131 v\u0259 m\xFCbahis\u0259l\u0259ri d\u0259 \u0259hat\u0259 olunur."},keyPoints:{en:["Cognition includes all mental activities: perceiving, thinking, remembering, and communicating.",'Problem-solving strategies: algorithms (step-by-step, guaranteed), heuristics (mental shortcuts, fast but error-prone), and insight (sudden "aha!" moments).',"Cognitive biases: Confirmation bias (seeking info that confirms beliefs), Availability heuristic (judging frequency by ease of recall), Anchoring (over-relying on first information), Framing effect (decisions change based on how options are presented).","Language development: Babbling (6 mo) \u2192 One-word (12 mo) \u2192 Two-word (24 mo) \u2192 Full sentences (3\u20134 yrs). Chomsky argued humans have an innate Language Acquisition Device (LAD).","The Sapir-Whorf hypothesis suggests that language shapes thought. The strong version (language determines thought) is mostly rejected; the weak version (language influences thought) has support.","Intelligence theories: Spearman's g (general intelligence), Gardner's multiple intelligences (8 types), Sternberg's triarchic theory (analytical, creative, practical).","IQ tests (Stanford-Binet, WAIS) have mean = 100, SD = 15. IQ is 50\u201380% heritable, but environment matters enormously \u2014 the Flynn effect shows IQ scores have risen ~3 points per decade worldwide."],ka:["\u10E8\u10D4\u10DB\u10D4\u10EA\u10DC\u10D4\u10D1\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0 \u10D2\u10DD\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5 \u10D0\u10E5\u10E2\u10D8\u10D5\u10DD\u10D1\u10D0\u10E1: \u10E0\u10D0\u10D8\u10DB\u10D4\u10E1 \u10D0\u10E6\u10E5\u10DB\u10D0\u10E1, \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1, \u10D3\u10D0\u10DB\u10D0\u10EE\u10E1\u10DD\u10D5\u10E0\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D9\u10DD\u10DB\u10E3\u10DC\u10D8\u10D9\u10D0\u10EA\u10D8\u10D0\u10E1.",'\u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10ED\u10E0\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8: \u10D0\u10DA\u10D2\u10DD\u10E0\u10D8\u10D7\u10DB\u10D4\u10D1\u10D8 (\u10DC\u10D0\u10D1\u10D8\u10EF-\u10DC\u10D0\u10D1\u10D8\u10EF, \u10D2\u10D0\u10E0\u10D0\u10DC\u10E2\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8), \u10F0\u10D4\u10D5\u10E0\u10D8\u10E1\u10E2\u10D8\u10D9\u10D0 (\u10D2\u10DD\u10DC\u10D4\u10D1\u10E0\u10D8\u10D5\u10D8 \u10DB\u10D0\u10DA\u10E1\u10D0\u10EE\u10DB\u10DD\u10D1\u10D4\u10D1\u10D8, \u10E1\u10EC\u10E0\u10D0\u10E4\u10D8, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10E8\u10D4\u10EA\u10D3\u10DD\u10DB\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10DB\u10D8\u10D3\u10E0\u10D4\u10D9\u10D8\u10DA\u10D8) \u10D3\u10D0 \u10D8\u10DC\u10E1\u10D0\u10D8\u10E2\u10D8 (\u10DB\u10DD\u10E3\u10DA\u10DD\u10D3\u10DC\u10D4\u10DA\u10D8 "\u10D0\u10F0\u10D0!" \u10DB\u10DD\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8).',"\u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D0: \u10D3\u10D0\u10D3\u10D0\u10E1\u10E2\u10E3\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D0 (\u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D8\u10E1 \u10EB\u10D8\u10D4\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10D3\u10D0\u10E1\u10E2\u10E3\u10E0\u10D4\u10D1\u10E1 \u10E0\u10EC\u10DB\u10D4\u10DC\u10D0\u10E1), \u10EE\u10D4\u10DA\u10DB\u10D8\u10E1\u10D0\u10EC\u10D5\u10D3\u10DD\u10DB\u10DD\u10D1\u10D8\u10E1 \u10F0\u10D4\u10D5\u10E0\u10D8\u10E1\u10E2\u10D8\u10D9\u10D0 (\u10E1\u10D8\u10EE\u10E8\u10D8\u10E0\u10D8\u10E1 \u10D2\u10D0\u10DC\u10E1\u10EF\u10D0 \u10D3\u10D0\u10DB\u10D0\u10EE\u10E1\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D8\u10DB\u10D0\u10E0\u10E2\u10D8\u10D5\u10D8\u10D7), \u10D0\u10DC\u10D9\u10DD\u10E0\u10D8\u10DC\u10D2\u10D8 (\u10D6\u10D4\u10D3\u10DB\u10D4\u10E2\u10D8 \u10D3\u10D0\u10E7\u10E0\u10D3\u10DC\u10DD\u10D1\u10D0 \u10DE\u10D8\u10E0\u10D5\u10D4\u10DA \u10D8\u10DC\u10E4\u10DD\u10E0\u10DB\u10D0\u10EA\u10D8\u10D0\u10D6\u10D4), \u10E4\u10E0\u10D4\u10D8\u10DB\u10D8\u10DC\u10D2\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8 (\u10D2\u10D0\u10D3\u10D0\u10EC\u10E7\u10D5\u10D4\u10E2\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D8\u10EA\u10D5\u10DA\u10D4\u10D1\u10D0 \u10D8\u10DB\u10D8\u10E1 \u10DB\u10D8\u10EE\u10D4\u10D3\u10D5\u10D8\u10D7, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E0\u10D8\u10E1 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D3\u10D2\u10D4\u10DC\u10D8\u10DA\u10D8 \u10D5\u10D0\u10E0\u10D8\u10D0\u10DC\u10E2\u10D4\u10D1\u10D8).","\u10D4\u10DC\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0: \u10E2\u10D8\u10E2\u10D8\u10DC\u10D8 (6 \u10D7\u10D5\u10D4) \u2192 \u10D4\u10E0\u10D7\u10D8 \u10E1\u10D8\u10E2\u10E7\u10D5\u10D0 (12 \u10D7\u10D5\u10D4) \u2192 \u10DD\u10E0\u10D8 \u10E1\u10D8\u10E2\u10E7\u10D5\u10D0 (24 \u10D7\u10D5\u10D4) \u2192 \u10E1\u10E0\u10E3\u10DA\u10D8 \u10EC\u10D8\u10DC\u10D0\u10D3\u10D0\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8 (3\u20134 \u10EC\u10D4\u10DA\u10D8). \u10E9\u10DD\u10DB\u10E1\u10D9\u10D8 \u10D0\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10D3\u10D0, \u10E0\u10DD\u10DB \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10E1 \u10D0\u10E5\u10D5\u10D7 \u10D4\u10DC\u10D8\u10E1 \u10D0\u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D0\u10DC\u10D3\u10D0\u10E7\u10DD\u10DA\u10D8\u10DA\u10D8 \u10DB\u10D4\u10E5\u10D0\u10DC\u10D8\u10D6\u10DB\u10D8 (LAD).","\u10E1\u10D0\u10DE\u10D8\u10E0-\u10E3\u10DD\u10E0\u10E4\u10D8\u10E1 \u10F0\u10D8\u10DE\u10DD\u10D7\u10D4\u10D6\u10D0 \u10D5\u10D0\u10E0\u10D0\u10E3\u10D3\u10DD\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D4\u10DC\u10D0 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10E1 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1. \u10EB\u10DA\u10D8\u10D4\u10E0\u10D8 \u10D5\u10D4\u10E0\u10E1\u10D8\u10D0 (\u10D4\u10DC\u10D0 \u10D2\u10D0\u10DC\u10E1\u10D0\u10D6\u10E6\u10D5\u10E0\u10D0\u10D5\u10E1 \u10D0\u10D6\u10E0\u10E1) \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D0\u10D3 \u10E3\u10D0\u10E0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D8\u10D0; \u10EE\u10DD\u10DA\u10DD \u10E1\u10E3\u10E1\u10E2 \u10D5\u10D4\u10E0\u10E1\u10D8\u10D0\u10E1 (\u10D4\u10DC\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1 \u10D0\u10EE\u10D3\u10D4\u10DC\u10E1 \u10D0\u10D6\u10E0\u10D6\u10D4) \u10D0\u10E5\u10D5\u10E1 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10ED\u10D4\u10E0\u10D0.","\u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8: \u10E1\u10DE\u10D8\u10E0\u10DB\u10D4\u10DC\u10D8\u10E1 g (\u10D6\u10DD\u10D2\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8), \u10D2\u10D0\u10E0\u10D3\u10DC\u10D4\u10E0\u10D8\u10E1 \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA\u10DB\u10EE\u10E0\u10D8\u10D5\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 (8 \u10E2\u10D8\u10DE\u10D8), \u10E1\u10E2\u10D4\u10E0\u10DC\u10D1\u10D4\u10E0\u10D2\u10D8\u10E1 \u10E2\u10E0\u10D8\u10D0\u10E0\u10E5\u10D8\u10E3\u10DA\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 (\u10D0\u10DC\u10D0\u10DA\u10D8\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8, \u10D9\u10E0\u10D4\u10D0\u10E2\u10D8\u10E3\u10DA\u10D8, \u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10E3\u10DA\u10D8).","IQ \u10E2\u10D4\u10E1\u10E2\u10D4\u10D1\u10E1 (\u10E1\u10E2\u10D4\u10DC\u10E4\u10DD\u10E0\u10D3-\u10D1\u10D8\u10DC\u10D4, WAIS) \u10D0\u10E5\u10D5\u10D7 \u10E1\u10D0\u10E8\u10E3\u10D0\u10DA\u10DD = 100, \u10E1\u10E2\u10D0\u10DC\u10D3\u10D0\u10E0\u10E2\u10E3\u10DA\u10D8 \u10D2\u10D0\u10D3\u10D0\u10EE\u10E0\u10D0 = 15. IQ 50\u201380%-\u10D8\u10D7 \u10DB\u10D4\u10DB\u10D9\u10D5\u10D8\u10D3\u10E0\u10D4\u10DD\u10D1\u10D8\u10D7\u10D8\u10D0, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10E3\u10D3\u10D8\u10D3\u10D4\u10E1\u10D8 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D1\u10D0 \u10D0\u10E5\u10D5\u10E1 \u2014 \u10E4\u10DA\u10D8\u10DC\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB IQ-\u10E1 \u10DB\u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10DA\u10D4\u10D1\u10D8 \u10DB\u10D7\u10D4\u10DA \u10DB\u10E1\u10DD\u10E4\u10DA\u10D8\u10DD\u10E8\u10D8 \u10D0\u10D7\u10EC\u10DA\u10D4\u10E3\u10DA\u10E8\u10D8 ~3 \u10E5\u10E3\u10DA\u10D8\u10D7 \u10D2\u10D0\u10D8\u10D6\u10D0\u10E0\u10D3\u10D0."],ru:["\u041F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0432 \u0441\u0435\u0431\u044F \u0432\u0441\u044E \u0443\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C: \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435, \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u0437\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u0438 \u043E\u0431\u0449\u0435\u043D\u0438\u0435.","\u0421\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u0437\u0430\u0434\u0430\u0447: \u0430\u043B\u0433\u043E\u0440\u0438\u0442\u043C\u044B (\u043F\u043E\u0448\u0430\u0433\u043E\u0432\u044B\u0435, \u0433\u0430\u0440\u0430\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435), \u044D\u0432\u0440\u0438\u0441\u0442\u0438\u043A\u0438 (\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u044F\u0440\u043B\u044B\u043A\u0438, \u0431\u044B\u0441\u0442\u0440\u044B\u0435, \u043D\u043E \u0441\u043A\u043B\u043E\u043D\u043D\u044B\u0435 \u043A \u043E\u0448\u0438\u0431\u043A\u0430\u043C) \u0438 \u0438\u043D\u0441\u0430\u0439\u0442 (\u0432\u043D\u0435\u0437\u0430\u043F\u043D\u044B\u0435 \u043C\u043E\u043C\u0435\u043D\u0442\u044B \xAB\u0430\u0433\u0430!\xBB).","\u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u0438\u044F: \u041F\u0440\u0435\u0434\u0432\u0437\u044F\u0442\u043E\u0441\u0442\u044C \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F (\u043F\u043E\u0438\u0441\u043A \u0438\u043D\u0444\u044B, \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0449\u0435\u0439 \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u0438\u044F), \u042D\u0432\u0440\u0438\u0441\u0442\u0438\u043A\u0430 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0441\u0442\u0438 (\u043E\u0446\u0435\u043D\u043A\u0430 \u0447\u0430\u0441\u0442\u043E\u0442\u044B \u043F\u043E \u043B\u0435\u0433\u043A\u043E\u0441\u0442\u0438 \u0432\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F), \u042D\u0444\u0444\u0435\u043A\u0442 \u043F\u0440\u0438\u0432\u044F\u0437\u043A\u0438 (\u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u0435 \u0434\u043E\u0432\u0435\u0440\u0438\u0435 \u043F\u0435\u0440\u0432\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438), \u042D\u0444\u0444\u0435\u043A\u0442 \u0444\u0440\u0435\u0439\u043C\u0438\u043D\u0433\u0430 (\u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043C\u0435\u043D\u044F\u044E\u0442\u0441\u044F \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u044B \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u044B).","\u0420\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u044F\u0437\u044B\u043A\u0430: \u041B\u0435\u043F\u0435\u0442 (6 \u043C\u0435\u0441) \u2192 \u041E\u0434\u043D\u043E \u0441\u043B\u043E\u0432\u043E (12 \u043C\u0435\u0441) \u2192 \u0414\u0432\u0430 \u0441\u043B\u043E\u0432\u0430 (24 \u043C\u0435\u0441) \u2192 \u041F\u043E\u043B\u043D\u044B\u0435 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u044F (3\u20134 \u0433\u043E\u0434\u0430). \u0425\u043E\u043C\u0441\u043A\u0438\u0439 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u043B, \u0447\u0442\u043E \u0443 \u043B\u044E\u0434\u0435\u0439 \u0435\u0441\u0442\u044C \u0432\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0435 \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E \u0443\u0441\u0432\u043E\u0435\u043D\u0438\u044F \u044F\u0437\u044B\u043A\u0430 (LAD).","\u0413\u0438\u043F\u043E\u0442\u0435\u0437\u0430 \u0421\u0435\u043F\u0438\u0440\u0430-\u0423\u043E\u0440\u0444\u0430 \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442, \u0447\u0442\u043E \u044F\u0437\u044B\u043A \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435. \u0421\u0438\u043B\u044C\u043D\u0430\u044F \u0432\u0435\u0440\u0441\u0438\u044F (\u044F\u0437\u044B\u043A \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435) \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C \u043E\u0442\u0432\u0435\u0440\u0433\u0430\u0435\u0442\u0441\u044F; \u0441\u043B\u0430\u0431\u0430\u044F \u0432\u0435\u0440\u0441\u0438\u044F (\u044F\u0437\u044B\u043A \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435) \u0438\u043C\u0435\u0435\u0442 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0443.","\u0422\u0435\u043E\u0440\u0438\u0438 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430: g-\u0444\u0430\u043A\u0442\u043E\u0440 \u0421\u043F\u0438\u0440\u043C\u0435\u043D\u0430 (\u043E\u0431\u0449\u0438\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442), \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 \u0413\u0430\u0440\u0434\u043D\u0435\u0440\u0430 (8 \u0442\u0438\u043F\u043E\u0432), \u0442\u0440\u0438\u0430\u0440\u0445\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u043E\u0440\u0438\u044F \u0421\u0442\u0435\u0440\u043D\u0431\u0435\u0440\u0433\u0430 (\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439, \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439, \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439).","IQ-\u0442\u0435\u0441\u0442\u044B (\u0421\u0442\u044D\u043D\u0444\u043E\u0440\u0434-\u0411\u0438\u043D\u0435, WAIS) \u0438\u043C\u0435\u044E\u0442 \u0441\u0440\u0435\u0434\u043D\u0435\u0435 = 100, SD = 15. IQ \u043D\u0430\u0441\u043B\u0435\u0434\u0443\u0435\u0442\u0441\u044F \u043D\u0430 50\u201380%, \u043D\u043E \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0430\u044F \u0441\u0440\u0435\u0434\u0430 \u0438\u043C\u0435\u0435\u0442 \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u2014 \u044D\u0444\u0444\u0435\u043A\u0442 \u0424\u043B\u0438\u043D\u043D\u0430 \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0438 IQ \u0440\u0430\u0441\u0442\u0443\u0442 \u043F\u0440\u0438\u043C\u0435\u0440\u043D\u043E \u043D\u0430 3 \u0431\u0430\u043B\u043B\u0430 \u0437\u0430 \u0434\u0435\u0441\u044F\u0442\u0438\u043B\u0435\u0442\u0438\u0435 \u043F\u043E \u0432\u0441\u0435\u043C\u0443 \u043C\u0438\u0440\u0443."],hy:["\u0543\u0561\u0576\u0561\u0579\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0574\u057F\u0561\u057E\u0578\u0580 \u0562\u0578\u056C\u0578\u0580 \u0563\u0578\u0580\u056E\u0578\u0582\u0576\u0565\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568. \u0568\u0576\u056F\u0561\u056C\u0578\u0582\u0574, \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0570\u056B\u0577\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0570\u0561\u0572\u0578\u0580\u0564\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576:","\u053D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u056C\u0578\u0582\u056E\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u0561\u056C\u0563\u0578\u0580\u056B\u0569\u0574\u0576\u0565\u0580 (\u0584\u0561\u0575\u056C \u0561\u057C \u0584\u0561\u0575\u056C, \u0565\u0580\u0561\u0577\u056D\u0561\u057E\u0578\u0580\u057E\u0561\u056E), \u0567\u057E\u0580\u056B\u057D\u057F\u056B\u056F\u0561 (\u0574\u057F\u0561\u057E\u0578\u0580 \u056F\u0561\u0580\u0573\u0578\u0582\u0572\u056B\u0576\u0565\u0580, \u0561\u0580\u0561\u0563, \u0562\u0561\u0575\u0581 \u057D\u056D\u0561\u056C\u0576\u0565\u0580\u056B \u0570\u0561\u056F\u057E\u0561\u056E) \u0587 \u056B\u0576\u057D\u0561\u0575\u0569 (\u0570\u0561\u0576\u056F\u0561\u0580\u056E\u0561\u056F\u056B \xAB\u0561\u0570\u0561\xBB \u057A\u0561\u0570\u0565\u0580):","\u053F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u0540\u0561\u057D\u057F\u0561\u057F\u0574\u0561\u0576 \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057F\u0565\u0572\u0565\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0583\u0576\u057F\u0580\u0565\u056C, \u0578\u0580\u0568 \u0570\u0561\u057D\u057F\u0561\u057F\u0578\u0582\u0574 \u0567 \u0570\u0561\u0574\u0578\u0566\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568), \u0540\u0561\u057D\u0561\u0576\u0565\u056C\u056B\u0578\u0582\u0569\u0575\u0561\u0576 \u0567\u057E\u0580\u056B\u057D\u057F\u056B\u056F\u0561 (\u0570\u0561\u0573\u0561\u056D\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0564\u0561\u057F\u0565\u056C\u0578\u057E \u0570\u056B\u0577\u0565\u056C\u0578\u0582 \u0570\u0565\u0577\u057F\u0578\u0582\u0569\u0575\u0561\u0574\u0562), \u053D\u0561\u0580\u057D\u056D\u0578\u0582\u0574 (\u0561\u057C\u0561\u057B\u056B\u0576 \u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561 \u0579\u0561\u0583\u0561\u0566\u0561\u0576\u0581 \u0574\u0565\u056E \u056F\u0561\u056D\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0547\u0580\u057B\u0561\u0576\u0561\u056F\u0574\u0561\u0576 \u0567\u0586\u0565\u056F\u057F (\u0578\u0580\u0578\u0577\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0583\u0578\u056D\u057E\u0578\u0582\u0574 \u0565\u0576 \u0565\u056C\u0576\u0565\u056C\u0578\u057E \u0576\u0580\u0561\u0576\u056B\u0581, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0576\u0565\u0580\u056F\u0561\u0575\u0561\u0581\u057E\u0561\u056E \u057F\u0561\u0580\u0562\u0565\u0580\u0561\u056F\u0576\u0565\u0580\u0568):","\u053C\u0565\u0566\u057E\u056B \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574. \u0539\u0578\u0569\u0578\u057E\u0561\u0576\u0584 (6 \u0561\u0574\u057D.) \u2192 \u0544\u0565\u056F \u0562\u0561\u057C (12 \u0561\u0574\u057D.) \u2192 \u0535\u0580\u056F\u0578\u0582 \u0562\u0561\u057C (24 \u0561\u0574\u057D.) \u2192 \u0531\u0574\u0562\u0578\u0572\u057B\u0561\u056F\u0561\u0576 \u0576\u0561\u056D\u0561\u0564\u0561\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 (3\u20134 \u057F\u0561\u0580\u0565\u056F\u0561\u0576): \u0549\u0578\u0574\u057D\u056F\u056B\u0576 \u057A\u0576\u0564\u0578\u0582\u0574 \u0567\u0580, \u0578\u0580 \u0574\u0561\u0580\u0564\u056B\u056F \u0578\u0582\u0576\u0565\u0576 \u053C\u0565\u0566\u057E\u056B \u0545\u0578\u0582\u0580\u0561\u0581\u0574\u0561\u0576 \u0532\u0576\u0561\u056E\u056B\u0576 \u054D\u0561\u0580\u0584 (LAD):","\u054D\u0561\u057A\u056B\u0580-\u0548\u0582\u0578\u0580\u0586\u056B \u057E\u0561\u0580\u056F\u0561\u056E\u0568 \u0570\u0578\u0582\u0577\u0578\u0582\u0574 \u0567, \u0578\u0580 \u056C\u0565\u0566\u0578\u0582\u0576 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0567 \u0574\u056B\u057F\u0584\u0568: \u0548\u0582\u056A\u0565\u0572 \u057E\u0561\u0580\u056F\u0561\u056E\u0568 (\u056C\u0565\u0566\u0578\u0582\u0576 \u0578\u0580\u0578\u0577\u0578\u0582\u0574 \u0567 \u0574\u056B\u057F\u0584\u0568) \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576\u0578\u0582\u0574 \u0574\u0565\u0580\u056A\u057E\u0578\u0582\u0574 \u0567. \u0569\u0578\u0582\u0575\u056C \u057F\u0561\u0580\u0562\u0565\u0580\u0561\u056F\u0568 (\u056C\u0565\u0566\u0578\u0582\u0576 \u0561\u0566\u0564\u0578\u0582\u0574 \u0567 \u0574\u057F\u0584\u056B \u057E\u0580\u0561) \u0561\u057B\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u056B:","\u053B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u054D\u0583\u056B\u0580\u0574\u0561\u0576\u056B g (\u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F), \u0533\u0561\u0580\u0564\u0576\u0565\u0580\u056B \u0562\u0561\u0566\u0574\u0561\u056F\u056B \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F (8 \u057F\u0565\u057D\u0561\u056F), \u054D\u057F\u0565\u0580\u0576\u0562\u0565\u0580\u0563\u056B \u0565\u057C\u0561\u0579\u0561\u0583 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0561\u056F\u0561\u0576, \u057D\u057F\u0565\u0572\u056E\u0561\u0563\u0578\u0580\u056E\u0561\u056F\u0561\u0576, \u0563\u0578\u0580\u056E\u0576\u0561\u056F\u0561\u0576):","IQ \u0569\u0565\u057D\u057F\u0565\u0580\u0568 (\u054D\u057F\u0565\u0576\u0586\u0578\u0580\u0564-\u0532\u056B\u0576\u0565, WAIS) \u0578\u0582\u0576\u0565\u0576 \u0574\u056B\u057B\u056B\u0576\u0568 = 100, SD = 15: IQ-\u0576 50\u201380%-\u0578\u057E \u056A\u0561\u057C\u0561\u0576\u0563\u0561\u056F\u0561\u0576 \u0567, \u0562\u0561\u0575\u0581 \u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0568 \u0570\u057D\u056F\u0561\u0575\u0561\u056F\u0561\u0576 \u0576\u0577\u0561\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u056B. \u0556\u056C\u056B\u0576\u0576\u056B \u0567\u0586\u0565\u056F\u057F\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0561\u0574\u0562\u0578\u0572\u057B \u0561\u0577\u056D\u0561\u0580\u0570\u0578\u0582\u0574 IQ-\u056B \u0581\u0578\u0582\u0581\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u0568 \u0575\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580 \u057F\u0561\u057D\u0576\u0561\u0574\u0575\u0561\u056F\u0578\u0582\u0574 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0565\u056C \u0565\u0576 \u0574\u0578\u057F 3 \u0574\u056B\u0561\u057E\u0578\u0580\u0578\u057E:"],az:["\u0130drak b\xFCt\xFCn zehni f\u0259aliyy\u0259tl\u0259ri \u0259hat\u0259 edir: qavray\u0131\u015F, d\xFC\u015F\xFCnm\u0259, yadda saxlama v\u0259 \xFCnsiyy\u0259t.",'Problem h\u0259lli strategiyalar\u0131: alqoritml\u0259r (add\u0131m-add\u0131m, z\u0259man\u0259tli), hevristikalar (zehni q\u0131sa yollar, s\xFCr\u0259tli lakin s\u0259hv\u0259 meylli) v\u0259 b\u0259sir\u0259t/insayt (q\u0259fil "aha!" anlar\u0131).',"Koqnitiv q\u0259r\u0259zl\u0259r: T\u0259sdiql\u0259m\u0259 q\u0259r\u0259zi (inanclar\u0131 t\u0259sdiql\u0259y\u0259n m\u0259lumat axtarma), \u018Fl\xE7atanl\u0131q hevristikas\u0131 (xat\u0131rlama asanl\u0131\u011F\u0131na g\xF6r\u0259 tezliyin m\xFChakim\u0259 olunmas\u0131), L\xF6vb\u0259rl\u0259m\u0259 (ilk m\u0259lumata h\u0259ddind\u0259n art\u0131q g\xFCv\u0259nm\u0259k), \xC7\u0259r\xE7iv\u0259l\u0259m\u0259 effekti (q\u0259rarlar se\xE7iml\u0259rin nec\u0259 t\u0259qdim olundu\u011Funa \u0259sas\u0259n d\u0259yi\u015Fir).","Dilin inki\u015Faf\u0131: Babbling/q\u0131\u011F\u0131ldama (6 ay) \u2192 T\u0259k s\xF6z (12 ay) \u2192 \u0130ki s\xF6z (24 ay) \u2192 Tam c\xFCml\u0259l\u0259r (3\u20134 ya\u015F). Chomsky insanlar\u0131n fitri Dil \u018Fld\u0259etm\u0259 Mexanizmin\u0259 (LAD) sahib oldu\u011Funu iddia etdi.","Sapir-Whorf hipotezi dilin d\xFC\u015F\xFCnc\u0259ni formala\u015Fd\u0131rd\u0131\u011F\u0131n\u0131 ir\u0259li s\xFCr\xFCr. G\xFCcl\xFC versiya (dil d\xFC\u015F\xFCnc\u0259ni m\xFC\u0259yy\u0259n edir) \u0259sas\u0259n r\u0259dd edilir; z\u0259if versiya (dil d\xFC\u015F\xFCnc\u0259y\u0259 t\u0259sir edir) is\u0259 d\u0259st\u0259kl\u0259nir.","\u0130ntellekt n\u0259z\u0259riyy\u0259l\u0259ri: Spearman\u0131n g-faktoru (\xFCmumi intellekt), Gardnerin \xE7ox\u015Fax\u0259li intellektl\u0259ri (8 n\xF6v), Sternbergin triarxik n\u0259z\u0259riyy\u0259si (analitik, yarad\u0131c\u0131, praktik).","IQ testl\u0259ri (Stanford-Binet, WAIS) orta g\xF6st\u0259ricisi = 100, SD = 15. IQ 50-80% irsidir, lakin \u0259traf m\xFChit b\xF6y\xFCk \u0259h\u0259miyy\u0259t da\u015F\u0131y\u0131r \u2014 Flynn effekti g\xF6st\u0259rir ki, d\xFCnya miqyas\u0131nda IQ ballar\u0131 h\u0259r onillikd\u0259 t\u0259xmin\u0259n 3 bal artm\u0131\u015Fd\u0131r."]},funFact:{en:'The "Dunning-Kruger effect" shows that people with the least competence in a skill tend to overestimate their ability the most, while experts tend to underestimate theirs. The less you know, the more confident you feel!',ka:"\u201E\u10D3\u10D0\u10DC\u10D8\u10DC\u10D2-\u10D9\u10E0\u10E3\u10D2\u10D4\u10E0\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u201C \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D0\u10D3 \u10D9\u10DD\u10DB\u10DE\u10D4\u10E2\u10D4\u10DC\u10E2\u10E3\u10E0\u10D8 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10EE\u10E8\u10D8\u10E0\u10D0\u10D3 \u10D0\u10ED\u10D0\u10E0\u10D1\u10D4\u10D1\u10D4\u10DC \u10E1\u10D0\u10D9\u10E3\u10D7\u10D0\u10E0 \u10E8\u10D4\u10E1\u10D0\u10EB\u10DA\u10D4\u10D1\u10DA\u10DD\u10D1\u10D4\u10D1\u10E1.",ru:"\xAB\u042D\u0444\u0444\u0435\u043A\u0442 \u0414\u0430\u043D\u043D\u0438\u043D\u0433\u0430-\u041A\u0440\u044E\u0433\u0435\u0440\u0430\xBB \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u043C\u0435\u043D\u0435\u0435 \u043A\u043E\u043C\u043F\u0435\u0442\u0435\u043D\u0442\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 \u0447\u0430\u0441\u0442\u043E \u043F\u0435\u0440\u0435\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438.",hy:"\xAB\u0534\u0561\u0576\u056B\u0576\u0563-\u053F\u0580\u0575\u0578\u0582\u0563\u0565\u0580\u056B \u0567\u0586\u0565\u056F\u057F\u0568\xBB \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u057E\u0565\u056C, \u0578\u0580 \u0578\u0579 \u056F\u0578\u0574\u057A\u0565\u057F\u0565\u0576\u057F \u0574\u0561\u0580\u0564\u056B\u056F \u0570\u0561\u0573\u0561\u056D \u0563\u0565\u0580\u0561\u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574 \u0565\u0576 \u056B\u0580\u0565\u0576\u0581 \u056F\u0561\u0580\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568:",az:'"Dunning-Kruger effekti" g\xF6st\u0259r\xEDr ki, daha az s\u0259ri\u015Ft\u0259li insanlar tez-tez \xF6z qabiliyy\u0259tl\u0259rini h\u0259dsiz d\u0259r\u0259zec\u0259d\u0259 y\xFCks\u0259k qiym\u0259tl\u0259ndirirl\u0259r.'},realWorld:{en:"Cognitive biases affect everyone: doctors, judges, investors. Daniel Kahneman won a Nobel Prize showing how systematic biases in thinking lead to predictable errors in decision-making.",ka:"\u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1 \u10D0\u10EE\u10D3\u10D4\u10DC\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4: \u10D4\u10E5\u10D8\u10DB\u10D4\u10D1\u10D6\u10D4, \u10DB\u10DD\u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10D4\u10D4\u10D1\u10D6\u10D4, \u10D8\u10DC\u10D5\u10D4\u10E1\u10E2\u10DD\u10E0\u10D4\u10D1\u10D6\u10D4.",ru:"\u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u0438\u044F \u0432\u043B\u0438\u044F\u044E\u0442 \u043D\u0430 \u0432\u0441\u0435\u0445: \u0432\u0440\u0430\u0447\u0435\u0439, \u0441\u0443\u0434\u0435\u0439, \u0438\u043D\u0432\u0435\u0441\u0442\u043E\u0440\u043E\u0432.",hy:"\u053F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0561\u0566\u0564\u0578\u0582\u0574 \u0565\u0576 \u0562\u0578\u056C\u0578\u0580\u056B \u057E\u0580\u0561\u055D \u0562\u056A\u056B\u0577\u056F\u0576\u0565\u0580\u056B, \u0564\u0561\u057F\u0561\u057E\u0578\u0580\u0576\u0565\u0580\u056B, \u0576\u0565\u0580\u0564\u0580\u0578\u0572\u0576\u0565\u0580\u056B:",az:"Koqnitiv q\u0259r\u0259zl\u0259r h\u0259r k\u0259s\u0259 t\u0259sir edir: h\u0259kiml\u0259r\u0259, hakiml\u0259r\u0259, investorlara."}},9:{title:{en:"Human Development",ka:"\u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0",ru:"\u0427\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435",hy:"\u0544\u0561\u0580\u0564\u056F\u0561\u0575\u056B\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574",az:"\u0130nsan \u0130nki\u015Faf\u0131"},description:{en:"Physical, cognitive, and social development across the lifespan.",ka:"\u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0\u10D8, \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0 \u10DB\u10D7\u10D4\u10DA\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D0\u10DC\u10EB\u10D8\u10DA\u10D6\u10D4.",ru:"\u0424\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435, \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u0438 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0439 \u0436\u0438\u0437\u043D\u0438.",hy:"\u0556\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576, \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0587 \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574 \u0578\u0572\u057B \u056F\u0575\u0561\u0576\u0584\u056B \u0568\u0576\u0569\u0561\u0581\u0584\u0578\u0582\u0574:",az:"H\u0259yat boyu fiziki, koqnitiv v\u0259 sosial inki\u015Faf."},keyTopics:{en:["Piaget's Stages","Attachment","Erikson's Stages","Moral Development","Aging"],ka:["\u10DE\u10D8\u10D0\u10DF\u10D4\u10E1 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10D8","\u10D3\u10D0\u10DC\u10D0\u10E0\u10D7\u10D8","\u10D4\u10E0\u10D8\u10E5\u10E1\u10DD\u10DC\u10D8\u10E1 \u10E1\u10EA\u10D4\u10DC\u10D4\u10D1\u10D8","\u10DB\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0","\u10D3\u10D0\u10D1\u10D4\u10E0\u10D4\u10D1\u10D0"],ru:["\u042D\u0442\u0430\u043F\u044B \u041F\u0438\u0430\u0436\u0435","\u0412\u043B\u043E\u0436\u0435\u043D\u0438\u0435","\u042D\u0442\u0430\u043F\u044B \u042D\u0440\u0438\u043A\u0441\u043E\u043D\u0430","\u041C\u043E\u0440\u0430\u043B\u044C\u043D\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435","\u0421\u0442\u0430\u0440\u0435\u043D\u0438\u0435"],hy:["\u054A\u056B\u0561\u056A\u0565\u056B \u0583\u0578\u0582\u056C\u0565\u0580\u0568","\u0540\u0561\u057E\u0565\u056C\u057E\u0561\u056E","\u0537\u0580\u056B\u056F\u057D\u0578\u0576\u056B \u0583\u0578\u0582\u056C\u0565\u0580\u0568","\u0532\u0561\u0580\u0578\u0575\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574","\u053E\u0565\u0580\u0561\u0581\u0578\u0582\u0574"],az:["Piagetin m\u0259rh\u0259l\u0259l\u0259ri","Qo\u015Fma","Eriksonun m\u0259rh\u0259l\u0259l\u0259ri","M\u0259n\u0259vi \u0130nki\u015Faf","Ya\u015Flanma"]},summary:{en:"Human development is a lifelong process of physical, cognitive, and psychosocial change that begins at conception and continues through old age. This chapter examines the major theories and research findings that explain how we grow and change across the lifespan. Piaget's theory of cognitive development describes four stages \u2014 sensorimotor, preoperational, concrete operational, and formal operational \u2014 each characterized by qualitatively different ways of thinking. Bowlby and Ainsworth's attachment theory reveals how early bonds between infants and caregivers profoundly shape social and emotional development, with secure attachment predicting healthier relationships throughout life. Erikson's eight psychosocial stages span the entire lifespan, from trust versus mistrust in infancy to integrity versus despair in late adulthood, each presenting a central crisis that must be resolved. The chapter also covers Kohlberg's stages of moral development, the physical and emotional turbulence of adolescence (including ongoing prefrontal cortex development until approximately age 25), and the complexities of aging \u2014 noting that while fluid intelligence declines with age, crystallized intelligence and wisdom often continue to grow.",ka:"\u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0\u10D8, \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D7\u10D4\u10DA\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D0\u10DC\u10EB\u10D8\u10DA\u10D6\u10D4 \u10DB\u10D8\u10DB\u10D3\u10D8\u10DC\u10D0\u10E0\u10D4 \u10DE\u10E0\u10DD\u10EA\u10D4\u10E1\u10D8, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D8\u10EC\u10E7\u10D4\u10D1\u10D0 \u10E9\u10D0\u10E1\u10D0\u10EE\u10D5\u10D8\u10D3\u10D0\u10DC \u10D3\u10D0 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D3\u10D4\u10D1\u10D0 \u10E1\u10D8\u10D1\u10D4\u10E0\u10D4\u10DB\u10D3\u10D4. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10EE\u10E1\u10DC\u10D8\u10D0\u10DC, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10D8\u10D6\u10E0\u10D3\u10D4\u10D1\u10D8\u10D7 \u10D3\u10D0 \u10D5\u10D8\u10EA\u10D5\u10DA\u10D4\u10D1\u10D8\u10D7 \u10DB\u10D7\u10D4\u10DA\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10D0\u10D5\u10DA\u10DD\u10D1\u10D0\u10E8\u10D8. \u10DE\u10D8\u10D0\u10DF\u10D4\u10E1 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 \u10D0\u10E6\u10EC\u10D4\u10E0\u10E1 \u10DD\u10D7\u10EE \u10D4\u10E2\u10D0\u10DE\u10E1 - \u10E1\u10D4\u10DC\u10E1\u10DD\u10DB\u10DD\u10E2\u10DD\u10E0\u10E3\u10DA\u10E1, \u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10D0\u10DB\u10D3\u10D4\u10DA\u10E1, \u10D9\u10DD\u10DC\u10D9\u10E0\u10D4\u10E2\u10E3\u10DA-\u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10E1\u10D0 \u10D3\u10D0 \u10E4\u10DD\u10E0\u10DB\u10D0\u10DA\u10E3\u10E0-\u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10E1 - \u10D7\u10D8\u10D7\u10DD\u10D4\u10E3\u10DA\u10D8 \u10EE\u10D0\u10E1\u10D8\u10D0\u10D7\u10D3\u10D4\u10D1\u10D0 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D5\u10D8\u10E1\u10DD\u10D1\u10E0\u10D8\u10D5\u10D0\u10D3 \u10D2\u10D0\u10DC\u10E1\u10EE\u10D5\u10D0\u10D5\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D2\u10D6\u10D4\u10D1\u10D8\u10D7. \u10D1\u10DD\u10E3\u10DA\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D4\u10D8\u10DC\u10E1\u10D5\u10DD\u10E0\u10E2\u10D8\u10E1 \u10DB\u10D8\u10EF\u10D0\u10ED\u10D5\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 \u10D0\u10D5\u10DA\u10D4\u10DC\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10E1 \u10E9\u10D5\u10D8\u10DA\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10DB\u10DD\u10DB\u10D5\u10DA\u10D4\u10DA\u10D4\u10D1\u10E1 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10D0\u10D3\u10E0\u10D4\u10E3\u10DA\u10D8 \u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10D8 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10E1, \u10E1\u10D0\u10D3\u10D0\u10EA \u10E3\u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10DD \u10DB\u10D8\u10EF\u10D0\u10ED\u10D5\u10E3\u10DA\u10DD\u10D1\u10D0 \u10DB\u10D7\u10D4\u10DA\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10D0\u10D5\u10DA\u10DD\u10D1\u10D0\u10E8\u10D8 \u10EF\u10D0\u10DC\u10E1\u10D0\u10E6\u10D8 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1 \u10DE\u10E0\u10DD\u10D2\u10DC\u10DD\u10D6\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D0\u10E4\u10E3\u10EB\u10D5\u10D4\u10DA\u10D8\u10D0. \u10D4\u10E0\u10D8\u10E5\u10E1\u10DD\u10DC\u10D8\u10E1 \u10E0\u10D5\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D4\u10E2\u10D0\u10DE\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10DB\u10D7\u10D4\u10DA \u10E1\u10D8\u10EA\u10DD\u10EA\u10EE\u10DA\u10D4\u10E1, \u10E9\u10D5\u10D8\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D0\u10E1\u10D0\u10D9\u10E8\u10D8 \u10DC\u10D3\u10DD\u10D1\u10D0-\u10E3\u10DC\u10D3\u10DD\u10D1\u10DA\u10DD\u10D1\u10D8\u10D3\u10D0\u10DC \u10D3\u10D0\u10EC\u10E7\u10D4\u10D1\u10E3\u10DA\u10D8, \u10D2\u10D5\u10D8\u10D0\u10DC \u10D6\u10E0\u10D3\u10D0\u10E1\u10E0\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DE\u10D4\u10E0\u10D8\u10DD\u10D3\u10E8\u10D8 \u10DB\u10D7\u10DA\u10D8\u10D0\u10DC\u10DD\u10D1\u10D0-\u10E1\u10D0\u10E1\u10DD\u10EC\u10D0\u10E0\u10D9\u10D5\u10D4\u10D7\u10D8\u10DA\u10D4\u10D1\u10D0\u10DB\u10D3\u10D4, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D7\u10D0\u10D2\u10D0\u10DC \u10D7\u10D8\u10D7\u10DD\u10D4\u10E3\u10DA\u10D8 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D0\u10D3\u10D2\u10D4\u10DC\u10E1 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D0\u10DA\u10E3\u10E0 \u10D9\u10E0\u10D8\u10D6\u10D8\u10E1\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10E3\u10DC\u10D3\u10D0 \u10DB\u10DD\u10D2\u10D5\u10D0\u10E0\u10D3\u10D4\u10E1. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D9\u10DD\u10DA\u10D1\u10D4\u10E0\u10D2\u10D8\u10E1 \u10DB\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10E1, \u10DB\u10DD\u10D6\u10D0\u10E0\u10D3\u10DD\u10D1\u10D8\u10E1 \u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0 \u10E2\u10E3\u10E0\u10D1\u10E3\u10DA\u10D4\u10DC\u10E2\u10DD\u10D1\u10D0\u10E1 (\u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10DE\u10E0\u10D4\u10E4\u10E0\u10DD\u10DC\u10E2\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E5\u10D4\u10E0\u10E5\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 25 \u10EC\u10DA\u10D0\u10DB\u10D3\u10D4) \u10D3\u10D0 \u10D3\u10D0\u10D1\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D8\u10E0\u10D7\u10E3\u10DA\u10D4\u10D4\u10D1\u10E1 - \u10D0\u10E6\u10DC\u10D8\u10E8\u10DC\u10D0\u10D5\u10E1, \u10E0\u10DD\u10DB \u10DB\u10D8\u10E3\u10EE\u10D4\u10D3\u10D0\u10D5\u10D0\u10D3 \u10D8\u10DB\u10D8\u10E1\u10D0, \u10E0\u10DD\u10DB \u10D7\u10EE\u10D4\u10D5\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 \u10D0\u10E1\u10D0\u10D9\u10D7\u10D0\u10DC \u10D4\u10E0\u10D7\u10D0\u10D3 \u10DB\u10EA\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0, \u10D9\u10E0\u10D8\u10E1\u10E2\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 \u10D3\u10D0 \u10E1\u10D8\u10D1\u10E0\u10EB\u10DC\u10D4 \u10EE\u10E8\u10D8\u10E0\u10D0\u10D3 \u10D0\u10D2\u10E0\u10EB\u10D4\u10DA\u10D4\u10D1\u10E1 \u10D6\u10E0\u10D3\u10D0\u10E1.",ru:"\u0427\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u2014 \u044D\u0442\u043E \u043F\u043E\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0439 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u0445, \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0445 \u0438 \u043F\u0441\u0438\u0445\u043E\u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 \u0437\u0430\u0447\u0430\u0442\u0438\u044F \u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F \u0434\u043E \u0441\u0430\u043C\u043E\u0439 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0442\u0435\u043E\u0440\u0438\u0438 \u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439, \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u044E\u0449\u0438\u0435, \u043A\u0430\u043A \u043C\u044B \u0440\u0430\u0441\u0442\u0451\u043C \u0438 \u043C\u0435\u043D\u044F\u0435\u043C\u0441\u044F \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u0436\u0438\u0437\u043D\u0438. \u0422\u0435\u043E\u0440\u0438\u044F \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u041F\u0438\u0430\u0436\u0435 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0447\u0435\u0442\u044B\u0440\u0435 \u0441\u0442\u0430\u0434\u0438\u0438 \u2014 \u0441\u0435\u043D\u0441\u043E\u043C\u043E\u0442\u043E\u0440\u043D\u0443\u044E, \u0434\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0443\u044E, \u0441\u0442\u0430\u0434\u0438\u044E \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0445 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 \u0438 \u0441\u0442\u0430\u0434\u0438\u044E \u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u044B\u0445 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 \u2014 \u043A\u0430\u0436\u0434\u0430\u044F \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0440\u0430\u0437\u043D\u044B\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F. \u0422\u0435\u043E\u0440\u0438\u044F \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0411\u043E\u0443\u043B\u0431\u0438 \u0438 \u042D\u0439\u043D\u0441\u0432\u043E\u0440\u0442 \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u043A\u0430\u043A \u0440\u0430\u043D\u043D\u0438\u0435 \u0441\u0432\u044F\u0437\u0438 \u043C\u0435\u0436\u0434\u0443 \u043C\u043B\u0430\u0434\u0435\u043D\u0446\u0430\u043C\u0438 \u0438 \u0442\u0435\u043C\u0438, \u043A\u0442\u043E \u043E \u043D\u0438\u0445 \u0437\u0430\u0431\u043E\u0442\u0438\u0442\u0441\u044F, \u0433\u043B\u0443\u0431\u043E\u043A\u043E \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0442 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0435 \u0438 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435, \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u043D\u0430\u0434\u0435\u0436\u043D\u0430\u044F \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 \u0437\u0434\u043E\u0440\u043E\u0432\u044B\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0439 \u0436\u0438\u0437\u043D\u0438. \u0412\u043E\u0441\u0435\u043C\u044C \u043F\u0441\u0438\u0445\u043E\u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u0442\u0430\u0434\u0438\u0439 \u042D\u0440\u0438\u043A\u0441\u043E\u043D\u0430 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0442 \u0432\u0441\u044E \u0436\u0438\u0437\u043D\u044C, \u043E\u0442 \u0434\u043E\u0432\u0435\u0440\u0438\u044F \u043F\u0440\u043E\u0442\u0438\u0432 \u043D\u0435\u0434\u043E\u0432\u0435\u0440\u0438\u044F \u0432 \u043C\u043B\u0430\u0434\u0435\u043D\u0447\u0435\u0441\u0442\u0432\u0435 \u0434\u043E \u0446\u0435\u043B\u043E\u0441\u0442\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u043E\u0442\u0438\u0432 \u043E\u0442\u0447\u0430\u044F\u043D\u0438\u044F \u0432 \u043F\u043E\u0437\u0434\u043D\u0435\u0439 \u0432\u0437\u0440\u043E\u0441\u043B\u043E\u0441\u0442\u0438, \u043A\u0430\u0436\u0434\u0430\u044F \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u043A\u0440\u0438\u0437\u0438\u0441, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0440\u0430\u0437\u0440\u0435\u0448\u0438\u0442\u044C. \u0412 \u0433\u043B\u0430\u0432\u0435 \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0441\u0442\u0430\u0434\u0438\u0438 \u043C\u043E\u0440\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u041A\u043E\u043B\u044C\u0431\u0435\u0440\u0433\u0430, \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0438 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0430\u044F \u0442\u0443\u0440\u0431\u0443\u043B\u0435\u043D\u0442\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0434\u0440\u043E\u0441\u0442\u043A\u043E\u0432\u043E\u0433\u043E \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u0430 (\u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u043F\u0440\u0435\u0444\u0440\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u043A\u043E\u0440\u044B \u043F\u0440\u0438\u043C\u0435\u0440\u043D\u043E \u0434\u043E 25 \u043B\u0435\u0442) \u0438 \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0441\u0442\u0430\u0440\u0435\u043D\u0438\u044F \u2014 \u043E\u0442\u043C\u0435\u0447\u0430\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u0445\u043E\u0442\u044F \u0442\u0435\u043A\u0443\u0447\u0438\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 \u0441 \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u043E\u043C \u0441\u043D\u0438\u0436\u0430\u0435\u0442\u0441\u044F, \u043A\u0440\u0438\u0441\u0442\u0430\u043B\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 \u0438 \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C \u0447\u0430\u0441\u0442\u043E \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 \u0440\u0430\u0441\u0442\u0438.",hy:"\u0544\u0561\u0580\u0564\u056F\u0561\u0575\u056B\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574\u0568 \u0586\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576, \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0587 \u0570\u0578\u0563\u0565\u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0581\u0574\u0561\u0570 \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581 \u0567, \u0578\u0580\u0576 \u057D\u056F\u057D\u057E\u0578\u0582\u0574 \u0567 \u0562\u0565\u0572\u0574\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574\u056B\u0581 \u0587 \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u057E\u0578\u0582\u0574 \u0574\u056B\u0576\u0579\u0587 \u056D\u0578\u0580 \u056E\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0587 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0565\u0576, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u0561\u0573\u0578\u0582\u0574 \u0587 \u0583\u0578\u056D\u057E\u0578\u0582\u0574 \u056F\u0575\u0561\u0576\u0584\u056B \u0568\u0576\u0569\u0561\u0581\u0584\u0578\u0582\u0574: \u054A\u056B\u0561\u056A\u0565\u056B \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0578\u0582\u0574 \u0567 \u0579\u0578\u0580\u057D \u0583\u0578\u0582\u056C\u0565\u0580\u055D \u057D\u0565\u0576\u057D\u0578\u0574\u0578\u057F\u0578\u0580\u0561\u0575\u056B\u0576, \u0576\u0561\u056D\u0561\u0563\u0578\u0580\u056E\u0561\u057C\u0576\u0561\u056F\u0561\u0576, \u056F\u0578\u0576\u056F\u0580\u0565\u057F \u0563\u0578\u0580\u056E\u0561\u057C\u0576\u0561\u056F\u0561\u0576 \u0587 \u0586\u0578\u0580\u0574\u0561\u056C \u0563\u0578\u0580\u056E\u0561\u057C\u0576\u0561\u056F\u0561\u0576. \u0575\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580\u0568 \u0562\u0576\u0578\u0582\u0569\u0561\u0563\u0580\u057E\u0578\u0582\u0574 \u0567 \u0574\u057F\u0561\u056E\u0565\u056C\u0561\u056F\u0565\u0580\u057A\u056B \u0578\u0580\u0561\u056F\u0561\u057A\u0565\u057D \u057F\u0561\u0580\u0562\u0565\u0580 \u0565\u0572\u0561\u0576\u0561\u056F\u0576\u0565\u0580\u0578\u057E: \u0532\u0578\u0578\u0582\u056C\u0562\u056B\u056B \u0587 \u0537\u0575\u0576\u057D\u057E\u0578\u0580\u0569\u056B \u056F\u0561\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0576\u0578\u0580\u0561\u056E\u056B\u0576\u0576\u0565\u0580\u056B \u0587 \u056D\u0576\u0561\u0574\u0561\u056F\u0561\u056C\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0587 \u057E\u0561\u0572 \u056F\u0561\u057A\u0565\u0580\u0568 \u056D\u0578\u0580\u0561\u057A\u0565\u057D \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0587 \u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574\u0568, \u0578\u0580\u057F\u0565\u0572 \u0561\u057A\u0561\u0570\u0578\u057E \u056F\u0561\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0578\u0582\u0574 \u0567 \u0561\u057E\u0565\u056C\u056B \u0561\u057C\u0578\u0572\u057B \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0578\u0572\u057B \u056F\u0575\u0561\u0576\u0584\u056B \u0568\u0576\u0569\u0561\u0581\u0584\u0578\u0582\u0574: \u0537\u0580\u056B\u056F\u057D\u0578\u0576\u056B \u0578\u0582\u0569 \u0570\u0578\u0563\u0565\u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0583\u0578\u0582\u056C\u0565\u0580\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0565\u0576 \u0578\u0572\u057B \u056F\u0575\u0561\u0576\u0584\u0568\u055D \u057D\u056F\u057D\u0561\u056E \u0576\u0578\u0580\u0561\u056E\u0576\u0561\u0575\u056B\u0576 \u057F\u0561\u0580\u056B\u0584\u0578\u0582\u0574 \u057E\u057D\u057F\u0561\u0570\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0561\u0576\u057E\u057D\u057F\u0561\u0570\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u056B\u0576\u0579\u0587 \u0578\u0582\u0577 \u0570\u0561\u057D\u0578\u0582\u0576 \u057F\u0561\u0580\u056B\u0584\u0578\u0582\u0574 \u0561\u0574\u0562\u0578\u0572\u057B\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0570\u0578\u0582\u057D\u0561\u0570\u0561\u057F\u0578\u0582\u0569\u0575\u0561\u0576, \u0578\u0580\u0578\u0576\u0581\u056B\u0581 \u0575\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580\u0568 \u0576\u0565\u0580\u056F\u0561\u0575\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u056F\u0561\u0576 \u0573\u0563\u0576\u0561\u056A\u0561\u0574, \u0578\u0580\u0568 \u057A\u0565\u057F\u0584 \u0567 \u056C\u0578\u0582\u056E\u057E\u056B: \u0533\u056C\u0578\u0582\u056D\u0568 \u0576\u0561\u0587 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0554\u0578\u056C\u0562\u0565\u0580\u0563\u056B \u0562\u0561\u0580\u0578\u0575\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576 \u0583\u0578\u0582\u056C\u0565\u0580\u0568, \u0564\u0565\u057C\u0561\u0570\u0561\u057D\u0578\u0582\u0569\u0575\u0561\u0576 \u0586\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576 \u0587 \u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u057F\u0578\u0582\u0580\u0562\u0578\u0582\u056C\u0565\u0576\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 (\u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0576\u0561\u056D\u0561\u0573\u0561\u056F\u0561\u057F\u0561\u0575\u056B\u0576 \u056F\u0565\u0572\u0587\u056B \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574\u0568 \u0574\u056B\u0576\u0579\u0587 \u0574\u0578\u057F\u0561\u057E\u0578\u0580\u0561\u057A\u0565\u057D 25 \u057F\u0561\u0580\u0565\u056F\u0561\u0576) \u0587 \u056E\u0565\u0580\u0561\u0581\u0574\u0561\u0576 \u0562\u0561\u0580\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568. \u0576\u0577\u0565\u056C\u0578\u057E, \u0578\u0580 \u0569\u0565\u0587 \u0570\u0565\u0572\u0578\u0582\u056F \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0568 \u057F\u0561\u0580\u056B\u0584\u056B \u0570\u0565\u057F \u0576\u057E\u0561\u0566\u0578\u0582\u0574 \u0567, \u0562\u0575\u0578\u0582\u0580\u0565\u0572\u0561\u0581\u057E\u0561\u056E \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0568 \u0587 \u056B\u0574\u0561\u057D\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0570\u0561\u0573\u0561\u056D \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0578\u0582\u0574 \u0565\u0576 \u0561\u0573\u0565\u056C:",az:"\u0130nsan inki\u015Faf\u0131 mayalanmadan ba\u015Flayan v\u0259 qocal\u0131\u011Fa q\u0259d\u0259r davam ed\u0259n fiziki, koqnitiv v\u0259 psixososial d\u0259yi\u015Fiklikl\u0259rin \xF6m\xFCr boyu davam ed\u0259n prosesidir. Bu f\u0259sil \xF6m\xFCr boyu nec\u0259 b\xF6y\xFCd\xFCy\xFCm\xFCz\xFC v\u0259 d\u0259yi\u015Fdiyimizi izah ed\u0259n \u0259sas n\u0259z\u0259riyy\u0259l\u0259ri v\u0259 t\u0259dqiqat n\u0259tic\u0259l\u0259rini ara\u015Fd\u0131r\u0131r. Piagetin koqnitiv inki\u015Faf n\u0259z\u0259riyy\u0259si d\xF6rd m\u0259rh\u0259l\u0259ni t\u0259svir edir - sensomotor, \u0259m\u0259liyyat\xF6n\xFC, konkret \u0259m\u0259liyyatlar v\u0259 formal \u0259m\u0259liyyatlar - h\u0259r biri f\u0259rqli d\xFC\u015F\xFCnc\u0259 t\u0259rzi il\u0259 xarakteriz\u0259 olunur. Bowlby v\u0259 Ainsworth-un qo\u015Fulma n\u0259z\u0259riyy\u0259si, k\xF6rp\u0259l\u0259r v\u0259 bax\u0131c\u0131lar aras\u0131ndak\u0131 erk\u0259n ba\u011Flar\u0131n sosial v\u0259 emosional inki\u015Faf\u0131 nec\u0259 d\u0259rind\u0259n formala\u015Fd\u0131rd\u0131\u011F\u0131n\u0131 a\u015Fkar edir, g\xFCv\u0259nli qo\u015Fulma b\xFCt\xFCn h\u0259yat boyu daha sa\u011Flam m\xFCnasib\u0259tl\u0259ri proqnozla\u015Fd\u0131r\u0131r. Eriksonun s\u0259kkiz psixososial m\u0259rh\u0259l\u0259si b\xFCt\xFCn \xF6mr\xFC \u0259hat\u0259 edir, k\xF6rp\u0259lik d\xF6vr\xFCnd\u0259 inam v\u0259 g\xFCv\u0259nsizlikd\u0259n ba\u015Flayaraq g\u0259nc ya\u015Fl\u0131l\u0131qda b\xFCt\xF6vl\xFCk v\u0259 \xFCmidsizliy\u0259 q\u0259d\u0259r, h\u0259r biri h\u0259lledilm\u0259li olan m\u0259rk\u0259zi b\xF6hran\u0131 t\u0259qdim edir. F\u0259sil eyni zamanda Kohlberg-in m\u0259n\u0259vi inki\u015Faf m\u0259rh\u0259l\u0259l\u0259rini, yeniyetm\u0259liyin fiziki v\u0259 emosional dal\u011Falanmalar\u0131n\u0131 (t\u0259xmin\u0259n 25 ya\u015Fa q\u0259d\u0259r prefrontal korteksin davam ed\u0259n inki\u015Faf\u0131 daxil olmaqla) v\u0259 ya\u015Flanman\u0131n m\xFCr\u0259kk\u0259blikl\u0259rini d\u0259 \u0259hat\u0259 edir, qeyd ed\u0259r\u0259k ki, ax\u0131c\u0131 intellekt ya\u015Fla birlikd\u0259 azalsa da, kristalla\u015Fm\u0131\u015F intellekt v\u0259 hikm\u0259t \xE7ox vaxt inki\u015Faf etm\u0259y\u0259 davam edir."},keyPoints:{en:["Nature vs. nurture is a false dichotomy: genes and environment interact continuously. Epigenetics shows that experiences can turn genes on or off.","Piaget's 4 cognitive stages: Sensorimotor (0\u20132, object permanence), Preoperational (2\u20137, symbolic thinking but egocentric), Concrete operational (7\u201311, logical thinking), Formal operational (12+, abstract reasoning).","Attachment theory (Bowlby/Ainsworth): Secure attachment (caregiver responsive) leads to healthy social development. Insecure types: avoidant, anxious-ambivalent, disorganized. Measured by the Strange Situation test.","Erikson's 8 psychosocial stages span the entire lifespan: Trust vs. Mistrust (infancy), Autonomy vs. Shame (toddler), Initiative vs. Guilt (preschool), Industry vs. Inferiority (school age), Identity vs. Role Confusion (adolescence), Intimacy vs. Isolation (young adult), Generativity vs. Stagnation (middle adult), Integrity vs. Despair (late adult).","Kohlberg's moral development: Preconventional (self-interest), Conventional (social norms), Postconventional (universal ethical principles). Most adults operate at the conventional level.",`Adolescence brings identity exploration (Erikson's "identity crisis"), prefrontal cortex development (not complete until ~25), and heightened emotional volatility due to hormonal changes.`,"Aging: Fluid intelligence (processing speed) declines with age, but crystallized intelligence (accumulated knowledge) remains stable or even increases. Neuroplasticity continues throughout life."],ka:["\u10D1\u10E3\u10DC\u10D4\u10D1\u10D0 \u10D0\u10E6\u10D6\u10E0\u10D3\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 \u10D0\u10E0\u10D8\u10E1 \u10DB\u10EA\u10D3\u10D0\u10E0\u10D8 \u10D3\u10D8\u10E5\u10DD\u10E2\u10DD\u10DB\u10D8\u10D0: \u10D2\u10D4\u10DC\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD \u10D2\u10D0\u10DC\u10E3\u10EC\u10E7\u10D5\u10D4\u10E2\u10DA\u10D8\u10D5 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D4\u10DC. \u10D4\u10DE\u10D8\u10D2\u10D4\u10DC\u10D4\u10E2\u10D8\u10D9\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0 \u10D2\u10D4\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E9\u10D0\u10E0\u10D7\u10D5\u10D0 \u10D0\u10DC \u10D2\u10D0\u10DB\u10DD\u10E0\u10D7\u10D5\u10D0.","\u10DE\u10D8\u10D0\u10DF\u10D4\u10E1 4 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D4\u10E2\u10D0\u10DE\u10D8: \u10E1\u10D4\u10DC\u10E1\u10DD\u10DB\u10DD\u10E2\u10DD\u10E0\u10E3\u10DA\u10D8 (0\u20132, \u10DD\u10D1\u10D8\u10D4\u10E5\u10E2\u10D8\u10E1 \u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10DD\u10D1\u10D0), \u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10D0\u10DB\u10D3\u10D4\u10DA\u10D8 (2\u20137, \u10E1\u10D8\u10DB\u10D1\u10DD\u10DA\u10E3\u10E0\u10D8 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10D4\u10D2\u10DD\u10EA\u10D4\u10DC\u10E2\u10E0\u10E3\u10DA\u10D8), \u10D9\u10DD\u10DC\u10D9\u10E0\u10D4\u10E2\u10E3\u10DA-\u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 (7\u201311, \u10DA\u10DD\u10D2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0), \u10E4\u10DD\u10E0\u10DB\u10D0\u10DA\u10E3\u10E0-\u10DD\u10DE\u10D4\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 (12+, \u10D0\u10D1\u10E1\u10E2\u10E0\u10D0\u10E5\u10E2\u10E3\u10DA\u10D8 \u10DB\u10E1\u10EF\u10D4\u10DA\u10DD\u10D1\u10D0).","\u10DB\u10D8\u10EF\u10D0\u10ED\u10D5\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 (\u10D1\u10DD\u10E3\u10DA\u10D1\u10D8/\u10D4\u10D8\u10DC\u10E1\u10D5\u10DD\u10E0\u10E2\u10D8): \u10E3\u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10DD \u10DB\u10D8\u10EF\u10D0\u10ED\u10D5\u10E3\u10DA\u10DD\u10D1\u10D0 (\u10DB\u10DD\u10DB\u10D5\u10DA\u10D4\u10DA\u10D8\u10E1 \u10DB\u10EE\u10E0\u10D8\u10D3\u10D0\u10DC \u10DE\u10D0\u10E1\u10E3\u10EE\u10D8\u10E1\u10DB\u10D2\u10D4\u10D1\u10DA\u10DD\u10D1\u10D0) \u10D8\u10EC\u10D5\u10D4\u10D5\u10E1 \u10EF\u10D0\u10DC\u10E1\u10D0\u10E6 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10E1. \u10D0\u10E0\u10D0\u10E1\u10D0\u10D8\u10DB\u10D4\u10D3\u10DD \u10E2\u10D8\u10DE\u10D4\u10D1\u10D8: \u10D0\u10DB\u10E0\u10D8\u10D3\u10D4\u10D1\u10D4\u10DA\u10D8, \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10D7-\u10D0\u10DB\u10D1\u10D8\u10D5\u10D0\u10DA\u10D4\u10DC\u10E2\u10E3\u10E0\u10D8, \u10D3\u10D4\u10D6\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8. \u10D8\u10D6\u10DD\u10DB\u10D4\u10D1\u10D0 '\u10E3\u10EA\u10DC\u10DD\u10D1\u10D8 \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10D8\u10E1' \u10E2\u10D4\u10E1\u10E2\u10D8\u10D7.","\u10D4\u10E0\u10D8\u10E5\u10E1\u10DD\u10DC\u10D8\u10E1 8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10E2\u10D0\u10D3\u10D8\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10DB\u10D7\u10D4\u10DA \u10E1\u10D8\u10EA\u10DD\u10EA\u10EE\u10DA\u10D4\u10E1: \u10DC\u10D3\u10DD\u10D1\u10D0 \u10E3\u10DC\u10D3\u10DD\u10D1\u10DA\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10E9\u10D5\u10D8\u10DA\u10DD\u10D1\u10D0), \u10D0\u10D5\u10E2\u10DD\u10DC\u10DD\u10DB\u10D8\u10D0 \u10E1\u10D8\u10E0\u10EA\u10EE\u10D5\u10D8\u10DA\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10D0\u10D3\u10E0\u10D4\u10E3\u10DA\u10D8 \u10D1\u10D0\u10D5\u10E8\u10D5\u10DD\u10D1\u10D0), \u10D8\u10DC\u10D8\u10EA\u10D8\u10D0\u10E2\u10D8\u10D5\u10D0 \u10D3\u10D0\u10DC\u10D0\u10E8\u10D0\u10E3\u10DA\u10D8\u10E1 \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10E1\u10D9\u10DD\u10DA\u10D0\u10DB\u10D3\u10D4\u10DA\u10D8 \u10D0\u10E1\u10D0\u10D9\u10D8), \u10E8\u10E0\u10DD\u10DB\u10D8\u10E1\u10DB\u10DD\u10E7\u10D5\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0 \u10D0\u10E0\u10D0\u10E1\u10E0\u10E3\u10DA\u10E4\u10D0\u10E1\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10E1\u10D0\u10E1\u10D9\u10DD\u10DA\u10DD \u10D0\u10E1\u10D0\u10D9\u10D8), \u10D8\u10D3\u10D4\u10DC\u10E2\u10DD\u10D1\u10D0 \u10E0\u10DD\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10E3\u10E0\u10D9\u10D5\u10D4\u10D5\u10DA\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10DB\u10DD\u10D6\u10D0\u10E0\u10D3\u10DD\u10D1\u10D0), \u10D8\u10DC\u10E2\u10D8\u10DB\u10E3\u10E0\u10DD\u10D1\u10D0 \u10D8\u10D6\u10DD\u10DA\u10D0\u10EA\u10D8\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10D0\u10EE\u10D0\u10DA\u10D2\u10D0\u10D6\u10E0\u10D3\u10DD\u10D1\u10D0), \u10D2\u10D4\u10DC\u10D4\u10E0\u10D0\u10EA\u10D8\u10E3\u10DA\u10DD\u10D1\u10D0 \u10E1\u10E2\u10D0\u10D2\u10DC\u10D0\u10EA\u10D8\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10E8\u10E3\u10D0 \u10EE\u10DC\u10D8\u10E1 \u10D0\u10E1\u10D0\u10D9\u10D8), \u10DB\u10D7\u10DA\u10D8\u10D0\u10DC\u10DD\u10D1\u10D0 \u10E1\u10D0\u10E1\u10DD\u10EC\u10D0\u10E0\u10D9\u10D5\u10D4\u10D7\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 (\u10D2\u10D5\u10D8\u10D0\u10DC\u10D8 \u10D6\u10E0\u10D3\u10D0\u10E1\u10E0\u10E3\u10DA\u10DD\u10D1\u10D0).","\u10D9\u10DD\u10DA\u10D1\u10D4\u10E0\u10D2\u10D8\u10E1 \u10DB\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0: \u10DE\u10E0\u10D4\u10D9\u10DD\u10DC\u10D5\u10D4\u10DC\u10EA\u10D8\u10E3\u10E0\u10D8 (\u10DE\u10D8\u10E0\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D4\u10E1\u10D8), \u10D9\u10DD\u10DC\u10D5\u10D4\u10DC\u10EA\u10D8\u10E3\u10E0\u10D8 (\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10DC\u10DD\u10E0\u10DB\u10D4\u10D1\u10D8), \u10DE\u10DD\u10E1\u10E2\u10D9\u10DD\u10DC\u10D5\u10D4\u10DC\u10EA\u10D8\u10E3\u10E0\u10D8 (\u10E3\u10DC\u10D8\u10D5\u10D4\u10E0\u10E1\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D4\u10D7\u10D8\u10D9\u10E3\u10E0\u10D8 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D4\u10D1\u10D8). \u10D6\u10E0\u10D3\u10D0\u10E1\u10E0\u10E3\u10DA\u10D7\u10D0 \u10E3\u10DB\u10D4\u10E2\u10D4\u10E1\u10DD\u10D1\u10D0 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10E1 \u10D9\u10DD\u10DC\u10D5\u10D4\u10DC\u10EA\u10D8\u10E3\u10E0 \u10D3\u10DD\u10DC\u10D4\u10D6\u10D4.","\u10DB\u10DD\u10D6\u10D0\u10E0\u10D3\u10DD\u10D1\u10D0\u10E1 \u10DB\u10DD\u10D0\u10E5\u10D5\u10E1 \u10D8\u10D3\u10D4\u10DC\u10E2\u10DD\u10D1\u10D8\u10E1 \u10EB\u10D8\u10D4\u10D1\u10D0 (\u10D4\u10E0\u10D8\u10E5\u10E1\u10DD\u10DC\u10D8\u10E1 '\u10D8\u10D3\u10D4\u10DC\u10E2\u10DD\u10D1\u10D8\u10E1 \u10D9\u10E0\u10D8\u10D6\u10D8\u10E1\u10D8'), \u10DE\u10E0\u10D4\u10E4\u10E0\u10DD\u10DC\u10E2\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E5\u10D4\u10E0\u10E5\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0 (\u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E0 \u10E1\u10E0\u10E3\u10DA\u10D3\u10D4\u10D1\u10D0 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 25 \u10EC\u10DA\u10D0\u10DB\u10D3\u10D4) \u10D3\u10D0 \u10D2\u10D0\u10D6\u10E0\u10D3\u10D8\u10DA\u10D8 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D0\u10E0\u10D0\u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10DD\u10D1\u10D0 \u10F0\u10DD\u10E0\u10DB\u10DD\u10DC\u10D0\u10DA\u10E3\u10E0\u10D8 \u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD.","\u10D3\u10D0\u10D1\u10D4\u10E0\u10D4\u10D1\u10D0: \u10D7\u10EE\u10D4\u10D5\u10D0\u10D3\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 (\u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D8\u10E9\u10E5\u10D0\u10E0\u10D4) \u10DB\u10EA\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0 \u10D0\u10E1\u10D0\u10D9\u10D7\u10D0\u10DC \u10D4\u10E0\u10D7\u10D0\u10D3, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10D9\u10E0\u10D8\u10E1\u10E2\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 (\u10D3\u10D0\u10D2\u10E0\u10DD\u10D5\u10D8\u10DA\u10D8 \u10EA\u10DD\u10D3\u10DC\u10D0) \u10E0\u10E9\u10D4\u10D1\u10D0 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10D8 \u10D0\u10DC \u10D8\u10D6\u10E0\u10D3\u10D4\u10D1\u10D0 \u10D9\u10D8\u10D3\u10D4\u10EA. \u10DC\u10D4\u10D8\u10E0\u10DD\u10DE\u10DA\u10D0\u10E1\u10E2\u10D8\u10E3\u10E0\u10DD\u10D1\u10D0 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D3\u10D4\u10D1\u10D0 \u10DB\u10D7\u10D4\u10DA\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10DB\u10D0\u10D5\u10DA\u10DD\u10D1\u10D0\u10E8\u10D8."],ru:["\u041F\u0440\u0438\u0440\u043E\u0434\u0430 \u043F\u0440\u043E\u0442\u0438\u0432 \u0432\u043E\u0441\u043F\u0438\u0442\u0430\u043D\u0438\u044F \u2014 \u043B\u043E\u0436\u043D\u0430\u044F \u0434\u0438\u0445\u043E\u0442\u043E\u043C\u0438\u044F: \u0433\u0435\u043D\u044B \u0438 \u0441\u0440\u0435\u0434\u0430 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442. \u042D\u043F\u0438\u0433\u0435\u043D\u0435\u0442\u0438\u043A\u0430 \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u043E\u043F\u044B\u0442 \u043C\u043E\u0436\u0435\u0442 \u0432\u043A\u043B\u044E\u0447\u0430\u0442\u044C \u0438\u043B\u0438 \u0432\u044B\u043A\u043B\u044E\u0447\u0430\u0442\u044C \u0433\u0435\u043D\u044B.","4 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0441\u0442\u0430\u0434\u0438\u0438 \u041F\u0438\u0430\u0436\u0435: \u0441\u0435\u043D\u0441\u043E\u043C\u043E\u0442\u043E\u0440\u043D\u0430\u044F (0\u20132, \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u0441\u0442\u0432\u043E \u043E\u0431\u044A\u0435\u043A\u0442\u0430), \u0434\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0430\u044F (2\u20137, \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0447\u0435\u0441\u043A\u043E\u0435, \u043D\u043E \u044D\u0433\u043E\u0446\u0435\u043D\u0442\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435), \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0445 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 (7\u201311, \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435), \u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u044B\u0445 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 (12+, \u0430\u0431\u0441\u0442\u0440\u0430\u043A\u0442\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0435).","\u0422\u0435\u043E\u0440\u0438\u044F \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 (\u0411\u043E\u0443\u043B\u0431\u0438/\u042D\u0439\u043D\u0441\u0432\u043E\u0440\u0442): \u041D\u0430\u0434\u0435\u0436\u043D\u0430\u044F \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C (\u043E\u0442\u0437\u044B\u0432\u0447\u0438\u0432\u044B\u0439 \u043E\u043F\u0435\u043A\u0443\u043D) \u0432\u0435\u0434\u0435\u0442 \u043A \u0437\u0434\u043E\u0440\u043E\u0432\u043E\u043C\u0443 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u043C\u0443 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044E. \u041D\u0435\u043D\u0430\u0434\u0435\u0436\u043D\u044B\u0435 \u0442\u0438\u043F\u044B: \u0438\u0437\u0431\u0435\u0433\u0430\u044E\u0449\u0438\u0439, \u0442\u0440\u0435\u0432\u043E\u0436\u043D\u043E-\u0430\u043C\u0431\u0438\u0432\u0430\u043B\u0435\u043D\u0442\u043D\u044B\u0439, \u0434\u0435\u0437\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u044B\u0439. \u0418\u0437\u043C\u0435\u0440\u044F\u0435\u0442\u0441\u044F \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0442\u0435\u0441\u0442\u0430 '\u041D\u0435\u0437\u043D\u0430\u043A\u043E\u043C\u0430\u044F \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044F'.","8 \u043F\u0441\u0438\u0445\u043E\u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u0442\u0430\u0434\u0438\u0439 \u042D\u0440\u0438\u043A\u0441\u043E\u043D\u0430 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0442 \u0432\u0441\u044E \u0436\u0438\u0437\u043D\u044C: \u0414\u043E\u0432\u0435\u0440\u0438\u0435 \u043F\u0440\u043E\u0442\u0438\u0432 \u043D\u0435\u0434\u043E\u0432\u0435\u0440\u0438\u044F (\u043C\u043B\u0430\u0434\u0435\u043D\u0447\u0435\u0441\u0442\u0432\u043E), \u0410\u0432\u0442\u043E\u043D\u043E\u043C\u0438\u044F \u043F\u0440\u043E\u0442\u0438\u0432 \u0441\u0442\u044B\u0434\u0430 (\u0440\u0430\u043D\u043D\u0435\u0435 \u0434\u0435\u0442\u0441\u0442\u0432\u043E), \u0418\u043D\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u0430 \u043F\u0440\u043E\u0442\u0438\u0432 \u0432\u0438\u043D\u044B (\u0434\u043E\u0448\u043A\u043E\u043B\u044C\u043D\u044B\u0439 \u0432\u043E\u0437\u0440\u0430\u0441\u0442), \u0422\u0440\u0443\u0434\u043E\u043B\u044E\u0431\u0438\u0435 \u043F\u0440\u043E\u0442\u0438\u0432 \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0438 (\u0448\u043A\u043E\u043B\u044C\u043D\u044B\u0439 \u0432\u043E\u0437\u0440\u0430\u0441\u0442), \u0418\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0442\u0438\u0432 \u043F\u0443\u0442\u0430\u043D\u0438\u0446\u044B \u0440\u043E\u043B\u0435\u0439 (\u043F\u043E\u0434\u0440\u043E\u0441\u0442\u043A\u043E\u0432\u044B\u0439 \u0432\u043E\u0437\u0440\u0430\u0441\u0442), \u0411\u043B\u0438\u0437\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0442\u0438\u0432 \u0438\u0437\u043E\u043B\u044F\u0446\u0438\u0438 (\u043C\u043E\u043B\u043E\u0434\u043E\u0441\u0442\u044C), \u0413\u0435\u043D\u0435\u0440\u0430\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0442\u0438\u0432 \u0441\u0442\u0430\u0433\u043D\u0430\u0446\u0438\u0438 (\u0437\u0440\u0435\u043B\u044B\u0439 \u0432\u043E\u0437\u0440\u0430\u0441\u0442), \u0426\u0435\u043B\u043E\u0441\u0442\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0442\u0438\u0432 \u043E\u0442\u0447\u0430\u044F\u043D\u0438\u044F (\u043F\u043E\u0436\u0438\u043B\u043E\u0439 \u0432\u043E\u0437\u0440\u0430\u0441\u0442).","\u041C\u043E\u0440\u0430\u043B\u044C\u043D\u043E\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u041A\u043E\u043B\u044C\u0431\u0435\u0440\u0433\u0430: \u043F\u0440\u0435\u0434\u043A\u043E\u043D\u0432\u0435\u043D\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0435 (\u043B\u0438\u0447\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0435\u0441), \u043A\u043E\u043D\u0432\u0435\u043D\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0435 (\u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0435 \u043D\u043E\u0440\u043C\u044B), \u043F\u043E\u0441\u0442\u043A\u043E\u043D\u0432\u0435\u043D\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0435 (\u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0435 \u044D\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B). \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0432\u0437\u0440\u043E\u0441\u043B\u044B\u0445 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u043D\u0430 \u043A\u043E\u043D\u0432\u0435\u043D\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u043C \u0443\u0440\u043E\u0432\u043D\u0435.","\u041F\u043E\u0434\u0440\u043E\u0441\u0442\u043A\u043E\u0432\u044B\u0439 \u0432\u043E\u0437\u0440\u0430\u0441\u0442 \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u043F\u043E\u0438\u0441\u043A \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 ('\u043A\u0440\u0438\u0437\u0438\u0441 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438' \u042D\u0440\u0438\u043A\u0441\u043E\u043D\u0430), \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u043F\u0440\u0435\u0444\u0440\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u043A\u043E\u0440\u044B (\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0435 \u0437\u0430\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u0434\u043E ~25 \u043B\u0435\u0442) \u0438 \u043F\u043E\u0432\u044B\u0448\u0435\u043D\u043D\u0443\u044E \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0443\u044E \u043D\u0435\u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438\u0437-\u0437\u0430 \u0433\u043E\u0440\u043C\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439.","\u0421\u0442\u0430\u0440\u0435\u043D\u0438\u0435: \u0442\u0435\u043A\u0443\u0447\u0438\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 (\u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438) \u0441\u043D\u0438\u0436\u0430\u0435\u0442\u0441\u044F \u0441 \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u043E\u043C, \u043D\u043E \u043A\u0440\u0438\u0441\u0442\u0430\u043B\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 (\u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u044B\u0435 \u0437\u043D\u0430\u043D\u0438\u044F) \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u043C \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u0430\u0435\u0442. \u041D\u0435\u0439\u0440\u043E\u043F\u043B\u0430\u0441\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u0432\u0441\u0435\u0439 \u0436\u0438\u0437\u043D\u0438."],hy:["\u0532\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0564\u0561\u057D\u057F\u056B\u0561\u0580\u0561\u056F\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0565\u0572\u056E \u0565\u0580\u056F\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0567. \u0563\u0565\u0576\u0565\u0580\u0568 \u0587 \u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0568 \u0574\u0577\u057F\u0561\u057A\u0565\u057D \u0583\u0578\u056D\u0561\u0566\u0564\u0578\u0582\u0574 \u0565\u0576: \u0537\u057A\u056B\u0563\u0565\u0576\u0565\u057F\u056B\u056F\u0561\u0576 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0583\u0578\u0580\u0571\u0561\u057C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u056F\u0561\u0580\u0578\u0572 \u0565\u0576 \u0574\u056B\u0561\u0581\u0576\u0565\u056C \u056F\u0561\u0574 \u0561\u0576\u057B\u0561\u057F\u0565\u056C \u0563\u0565\u0576\u0565\u0580\u0568:","\u054A\u056B\u0561\u056A\u0565\u056B 4 \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0561\u056F\u0561\u0576 \u0583\u0578\u0582\u056C\u0565\u0580\u0568\u055D \u054D\u0565\u0576\u057D\u0578\u0574\u0578\u057F\u0578\u0580\u0561\u0575\u056B\u0576 (0\u20132, \u0561\u057C\u0561\u0580\u056F\u0561\u0575\u056B \u0574\u0577\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0546\u0561\u056D\u0561\u0563\u0578\u0580\u056E\u0561\u057C\u0576\u0561\u056F\u0561\u0576 (2\u20137, \u057D\u056B\u0574\u057E\u0578\u056C\u056B\u056F \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0562\u0561\u0575\u0581 \u0567\u0563\u0578\u0581\u0565\u0576\u057F\u0580\u056B\u056F), \u053F\u0578\u0576\u056F\u0580\u0565\u057F \u0563\u0578\u0580\u056E\u0561\u057C\u0576\u0561\u056F\u0561\u0576 (7\u201311, \u057F\u0580\u0561\u0574\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0556\u0578\u0580\u0574\u0561\u056C \u0563\u0578\u0580\u056E\u0561\u057C\u0576\u0561\u056F\u0561\u0576 (12+, \u0561\u0562\u057D\u057F\u0580\u0561\u056F\u057F \u0564\u0561\u057F\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576):","\u053F\u0561\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0532\u0578\u0578\u0582\u056C\u0562\u056B/\u0537\u0575\u0576\u057D\u057E\u0578\u0580\u0569). \u0531\u057A\u0561\u0570\u0578\u057E \u056F\u0561\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 (\u056D\u0576\u0561\u0574\u0561\u056F\u0561\u056C\u056B \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0578\u0572\u0578\u0582\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576) \u0570\u0561\u0576\u0563\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u0561\u057C\u0578\u0572\u057B \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576: \u0531\u0576\u0561\u057A\u0561\u0570\u0578\u057E \u057F\u0565\u057D\u0561\u056F\u0576\u0565\u0580\u055D \u056D\u0578\u0582\u057D\u0561\u0583\u0578\u0572\u0561\u056F\u0561\u0576, \u057F\u0561\u0563\u0576\u0561\u057A\u0561\u0575\u056B\u0576-\u0561\u0574\u0562\u056B\u057E\u0561\u056C\u0565\u0576\u057F, \u0561\u0576\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A. \u0579\u0561\u0583\u057E\u0578\u0582\u0574 \u0567 '\u0531\u0576\u056E\u0561\u0576\u0578\u0569 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u056B' \u0569\u0565\u057D\u057F\u0578\u057E:","\u0537\u0580\u056B\u056F\u057D\u0578\u0576\u056B 8 \u0570\u0578\u0563\u0565\u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0583\u0578\u0582\u056C\u0565\u0580\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0565\u0576 \u0578\u0572\u057B \u056F\u0575\u0561\u0576\u0584\u0568\u055D \u054E\u057D\u057F\u0561\u0570\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0561\u0576\u057E\u057D\u057F\u0561\u0570\u0578\u0582\u0569\u0575\u0561\u0576 (\u0574\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u053B\u0576\u0584\u0576\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0561\u0574\u0578\u0569\u056B (\u057E\u0561\u0572 \u0574\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0546\u0561\u056D\u0561\u0571\u0565\u057C\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0574\u0565\u0572\u0584\u056B \u0566\u0563\u0561\u0581\u0578\u0582\u0574\u056B (\u0576\u0561\u056D\u0561\u0564\u057A\u0580\u0578\u0581\u0561\u056F\u0561\u0576), \u0531\u0577\u056D\u0561\u057F\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0569\u0565\u0580\u0561\u0580\u056A\u0565\u0584\u0578\u0582\u0569\u0575\u0561\u0576 (\u0564\u057A\u0580\u0578\u0581\u0561\u056F\u0561\u0576 \u057F\u0561\u0580\u056B\u0584), \u053B\u0576\u0584\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0564\u0565\u0580\u0565\u0580\u056B \u0577\u0583\u0578\u0569\u0578\u0582\u0569\u0575\u0561\u0576 (\u0564\u0565\u057C\u0561\u0570\u0561\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0544\u057F\u0565\u0580\u0574\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0574\u0565\u056F\u0578\u0582\u057D\u0561\u0581\u0574\u0561\u0576 (\u0565\u0580\u056B\u057F\u0561\u057D\u0561\u0580\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0533\u0565\u0576\u0565\u0580\u0561\u057F\u056B\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u056C\u0573\u0561\u0581\u0574\u0561\u0576 (\u0574\u056B\u057B\u056B\u0576 \u057F\u0561\u0580\u056B\u0584), \u0531\u0574\u0562\u0578\u0572\u057B\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0568\u0576\u0564\u0564\u0565\u0574 \u0570\u0578\u0582\u057D\u0561\u0570\u0561\u057F\u0578\u0582\u0569\u0575\u0561\u0576 (\u0578\u0582\u0577 \u057F\u0561\u0580\u056B\u0584):","\u0554\u0578\u056C\u0562\u0565\u0580\u0563\u056B \u0562\u0561\u0580\u0578\u0575\u0561\u056F\u0561\u0576 \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574. \u0546\u0561\u056D\u0561\u056F\u0578\u0576\u057E\u0565\u0576\u0581\u056B\u0578\u0576\u0561\u056C (\u0561\u0576\u0571\u0576\u0561\u056F\u0561\u0576 \u0577\u0561\u0570), \u053F\u0578\u0576\u057E\u0565\u0576\u0581\u056B\u0578\u0576\u0561\u056C (\u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0576\u0578\u0580\u0574\u0565\u0580), \u0540\u0565\u057F\u056F\u0578\u0576\u057E\u0565\u0576\u0581\u056B\u0578\u0576\u0561\u056C (\u0570\u0561\u0574\u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0567\u0569\u056B\u056F\u0561\u056F\u0561\u0576 \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0576\u0565\u0580): \u0544\u0565\u056E\u0561\u0570\u0561\u057D\u0561\u056F\u0576\u0565\u0580\u056B \u0574\u0565\u056E \u0574\u0561\u057D\u0568 \u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0567 \u056F\u0578\u0576\u057E\u0565\u0576\u0581\u056B\u0578\u0576\u0561\u056C \u0574\u0561\u056F\u0561\u0580\u0564\u0561\u056F\u0578\u0582\u0574:","\u0534\u0565\u057C\u0561\u0570\u0561\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0565\u0580\u0578\u0582\u0574 \u0567 \u056B\u0576\u0584\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0578\u0580\u0578\u0576\u0578\u0582\u0574 (\u0537\u0580\u056B\u056F\u057D\u0578\u0576\u056B \xAB\u056B\u0576\u0584\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0573\u0563\u0576\u0561\u056A\u0561\u0574\xBB), \u0576\u0561\u056D\u0561\u0573\u0561\u056F\u0561\u057F\u0561\u0575\u056B\u0576 \u056F\u0565\u0572\u0587\u056B \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0582\u0574 (\u0578\u0580\u0568 \u056D\u0578\u0580\u0561\u057A\u0565\u057D \u0579\u056B \u0561\u057E\u0561\u0580\u057F\u057E\u0578\u0582\u0574 \u0574\u056B\u0576\u0579\u0587 ~25 \u057F\u0561\u0580\u0565\u056F\u0561\u0576) \u0587 \u0568\u0576\u0564\u0563\u056E\u057E\u0561\u056E \u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u0561\u0576\u056F\u0561\u0575\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0570\u0578\u0580\u0574\u0578\u0576\u0561\u056C \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u057A\u0561\u057F\u0573\u0561\u057C\u0578\u057E:","\u053E\u0565\u0580\u0561\u0581\u0578\u0582\u0574. \u0540\u0565\u0572\u0578\u0582\u056F \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0568 (\u057F\u0565\u0572\u0565\u056F\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0577\u0561\u056F\u0574\u0561\u0576 \u0561\u0580\u0561\u0563\u0578\u0582\u0569\u0575\u0578\u0582\u0576) \u057F\u0561\u0580\u056B\u0584\u056B \u0570\u0565\u057F \u0576\u057E\u0561\u0566\u0578\u0582\u0574 \u0567, \u0562\u0561\u0575\u0581 \u0562\u0575\u0578\u0582\u0580\u0565\u0572\u0561\u0581\u057E\u0561\u056E \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u0568 (\u056F\u0578\u0582\u057F\u0561\u056F\u057E\u0561\u056E \u0563\u056B\u057F\u0565\u056C\u056B\u0584\u0576\u0565\u0580) \u0574\u0576\u0578\u0582\u0574 \u0567 \u056F\u0561\u0575\u0578\u0582\u0576 \u056F\u0561\u0574 \u0576\u0578\u0582\u0575\u0576\u056B\u057D\u056F \u0561\u057E\u0565\u056C\u0561\u0576\u0578\u0582\u0574 \u0567: \u0546\u0565\u0575\u0580\u0578\u057A\u056C\u0561\u057D\u057F\u056B\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u057E\u0578\u0582\u0574 \u0567 \u0578\u0572\u057B \u056F\u0575\u0561\u0576\u0584\u056B \u0568\u0576\u0569\u0561\u0581\u0584\u0578\u0582\u0574:"],az:["T\u0259bi\u0259t t\u0259rbiy\u0259y\u0259 qar\u015F\u0131 yaln\u0131\u015F bir dixotomiyad\u0131r: genl\u0259r v\u0259 \u0259traf m\xFChit davaml\u0131 olaraq qar\u015F\u0131l\u0131ql\u0131 \u0259laq\u0259d\u0259dir. Epigenetika g\xF6st\u0259rir ki, t\u0259cr\xFCb\u0259l\u0259r genl\u0259ri a\xE7a v\u0259 ya ba\u011Flaya bil\u0259r.","Piaget-nin 4 koqnitiv m\u0259rh\u0259l\u0259si: Sensomotor (0\u20132, obyektin qal\u0131c\u0131l\u0131\u011F\u0131), \u018Fm\u0259liyyat\xF6n\xFC (2\u20137, simvolik d\xFC\u015F\xFCnc\u0259 lakin eqosentrik), Konkret \u0259m\u0259liyyatlar (7\u201311, m\u0259ntiqi d\xFC\u015F\xFCnc\u0259), Formal \u0259m\u0259liyyatlar (12+, m\xFCc\u0259rr\u0259d m\xFClahiz\u0259).","Qo\u015Fulma n\u0259z\u0259riyy\u0259si (Bowlby/Ainsworth): G\xFCv\u0259nli qo\u015Fulma (bax\u0131c\u0131n\u0131n h\u0259ssasl\u0131\u011F\u0131) sa\u011Flam sosial inki\u015Fafa s\u0259b\u0259b olur. G\xFCv\u0259nsiz n\xF6vl\u0259r: \xE7\u0259kin\u0259n, narahat-ikivalent, qeyri-m\xFCt\u0259\u015F\u0259kkil. 'Yad V\u0259ziyy\u0259t' testi il\u0259 \xF6l\xE7\xFCl\xFCr.","Eriksonun 8 psixososial m\u0259rh\u0259l\u0259si b\xFCt\xFCn h\u0259yat\u0131 \u0259hat\u0259 edir: G\xFCv\u0259n v\u0259 G\xFCv\u0259nsizlik (k\xF6rp\u0259lik), Muxtariyy\u0259t v\u0259 Utanc (erk\u0259n u\u015Faql\u0131q), T\u0259\u015F\u0259bb\xFCs v\u0259 G\xFCnah (m\u0259kt\u0259b\u0259q\u0259d\u0259r), \xC7al\u0131\u015Fqanl\u0131q v\u0259 A\u015Fa\u011F\u0131l\u0131q (m\u0259kt\u0259b ya\u015F\u0131), Kimlik v\u0259 Rol qar\u0131\u015F\u0131ql\u0131\u011F\u0131 (yeniyetm\u0259lik), Yax\u0131nl\u0131q v\u0259 T\u0259crid (g\u0259nclik), Generativlik v\u0259 Dur\u011Funluq (orta ya\u015F), B\xFCt\xF6vl\xFCk v\u0259 \xDCmidsizlik (gec ya\u015Fl\u0131l\u0131q).","Kohlberg-in m\u0259n\u0259vi inki\u015Faf\u0131: Prekonvensional (\u015F\u0259xsi maraq), Konvensional (sosial normalar), Postkonvensional (universal etik prinsipl\u0259r). \u018Fks\u0259r b\xF6y\xFCkl\u0259r konvensional s\u0259viyy\u0259d\u0259 f\u0259aliyy\u0259t g\xF6st\u0259rirl\u0259r.","Yeniyetm\u0259lik d\xF6vr\xFC f\u0259rdiyy\u0259t axtar\u0131\u015F\u0131n\u0131 (Eriksonun 'kimlik b\xF6hran\u0131'), prefrontal korteksin inki\u015Faf\u0131n\u0131 (~25 ya\u015Fa q\u0259d\u0259r tamamlanmayan) v\u0259 hormonal d\u0259yi\u015Fiklikl\u0259r\u0259 g\xF6r\u0259 y\xFCks\u0259k emosional d\u0259yi\u015Fk\u0259nliyi g\u0259tirir.","Ya\u015Flanma: Ax\u0131c\u0131 (fluid) intellekt (i\u015Fl\u0259m\u0259 s\xFCr\u0259ti) ya\u015Fla azal\u0131r, ancaq kristalla\u015Fm\u0131\u015F intellekt (toplanm\u0131\u015F bilik) sabit qal\u0131r v\u0259 ya daha da art\u0131r. Neyroplastiklik b\xFCt\xFCn h\u0259yat boyu davam edir."]},funFact:{en:'Babies can distinguish all speech sounds from all languages until about 10 months of age. After that, their brains "prune" unused neural pathways and specialize in their native language sounds \u2014 which is why learning a second language gets harder with age.',ka:"\u10E9\u10D5\u10D8\u10DA\u10D4\u10D1\u10D8 10 \u10D7\u10D5\u10D4\u10DB\u10D3\u10D4 \u10D0\u10E1\u10EE\u10D5\u10D0\u10D5\u10D4\u10D1\u10D4\u10DC \u10E7\u10D5\u10D4\u10DA\u10D0 \u10D4\u10DC\u10D8\u10E1 \u10D1\u10D2\u10D4\u10E0\u10D0\u10E1. \u10D0\u10DB\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2 \u10EE\u10D3\u10D4\u10D1\u10D0 \u10DC\u10D4\u10D8\u10E0\u10DD\u10DC\u10E3\u10DA\u10D8 \u10D2\u10D6\u10D4\u10D1\u10D8\u10E1 \u201E\u10D2\u10D0\u10E1\u10EE\u10D5\u10DA\u10D0\u201C.",ru:"\u041C\u043B\u0430\u0434\u0435\u043D\u0446\u044B \u043C\u043E\u0433\u0443\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u0442\u044C \u0437\u0432\u0443\u043A\u0438 \u0432\u0441\u0435\u0445 \u044F\u0437\u044B\u043A\u043E\u0432 \u0434\u043E 10 \u043C\u0435\u0441\u044F\u0446\u0435\u0432. \u041F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E \u043C\u043E\u0437\u0433 \xAB\u043E\u0442\u0441\u0435\u043A\u0430\u0435\u0442\xBB \u043D\u0435\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u044B\u0435 \u043D\u0435\u0439\u0440\u043E\u043D\u043D\u044B\u0435 \u0441\u0432\u044F\u0437\u0438.",hy:"\u0544\u056B\u0576\u0579\u0587 10 \u0561\u0574\u057D\u0561\u056F\u0561\u0576 \u0565\u0580\u0565\u056D\u0561\u0576\u0565\u0580\u0568 \u056F\u0561\u0580\u0578\u0572 \u0565\u0576 \u057F\u0561\u0580\u0562\u0565\u0580\u0565\u056C \u0562\u0578\u056C\u0578\u0580 \u056C\u0565\u0566\u0578\u0582\u0576\u0565\u0580\u056B \u0570\u0576\u0579\u0575\u10E3\u10DC\u0576\u0565\u0580\u0568: \u0534\u0580\u0561\u0576\u056B\u0581 \u0570\u0565\u057F\u0578 \u0578\u0582\u0572\u0565\u0572\u0568 \xAB\u0567\u057F\u0578\u0582\u0574\xBB \u0567 \u0579\u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u057E\u0561\u056E \u0576\u0565\u0575\u0580\u0578\u0576\u0561\u0575\u056B\u0576 \u0578\u0582\u0572\u056B\u0576\u0565\u0580\u0568:",az:"K\xF6rp\u0259l\u0259r t\u0259xmin\u0259n 10 ayl\u0131q olana q\u0259d\u0259r b\xFCt\xFCn dill\u0259rd\u0259ki s\u0259sl\u0259ri f\u0259rql\u0259ndir\u0259 bilirl\u0259r. Bundan sonra beyin istifad\u0259 olunmayan yollar\u0131 'buday\u0131r'."},realWorld:{en:"Ainsworth' attachment research directly influenced childcare policies worldwide. Secure attachment in infancy predicts better relationships, higher self-esteem, and more resilience in adulthood.",ka:"\u10D4\u10D8\u10DC\u10E1\u10D5\u10DD\u10E0\u10E2\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10DB \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0 \u10DB\u10DD\u10D0\u10EE\u10D3\u10D8\u10DC\u10D0 \u10D1\u10D0\u10D5\u10E8\u10D5\u10D7\u10D0 \u10DB\u10DD\u10D5\u10DA\u10D8\u10E1 \u10DE\u10DD\u10DA\u10D8\u10E2\u10D8\u10D9\u10D0\u10D6\u10D4. \u10E3\u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10DD \u10DB\u10D8\u10EF\u10D0\u10ED\u10D5\u10E3\u10DA\u10DD\u10D1\u10D0 \u10D2\u10D0\u10DC\u10D0\u10DE\u10D8\u10E0\u10DD\u10D1\u10D4\u10D1\u10E1 \u10E3\u10D9\u10D4\u10D7\u10D4\u10E1 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D4\u10D1\u10E1.",ru:"\u0418\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u042D\u0439\u043D\u0441\u0432\u043E\u0440\u0442 \u043F\u043E\u0432\u043B\u0438\u044F\u043B\u043E \u043D\u0430 \u043F\u043E\u043B\u0438\u0442\u0438\u043A\u0443 \u0443\u0445\u043E\u0434\u0430 \u0437\u0430 \u0434\u0435\u0442\u044C\u043C\u0438. \u041D\u0430\u0434\u0435\u0436\u043D\u0430\u044F \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043B\u0443\u0447\u0448\u0438\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F.",hy:"\u0537\u0575\u0576\u057D\u057E\u0578\u0580\u0569\u056B \u056F\u0561\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0561\u0566\u0564\u0565\u056C \u0567 \u0565\u0580\u0565\u056D\u0561\u0576\u0565\u0580\u056B \u056D\u0576\u0561\u0574\u0584\u056B \u0584\u0561\u0572\u0561\u0584\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561: \u0531\u057A\u0561\u0570\u0578\u057E \u056F\u0561\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0578\u0582\u0574 \u0567 \u0561\u057E\u0565\u056C\u056B \u056C\u0561\u057E \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580:",az:"Ainsworth-un qo\u015Fulma ara\u015Fd\u0131rmas\u0131 d\xFCnya miqyas\u0131nda u\u015Faqlara qulluq siyas\u0259tin\u0259 birba\u015Fa t\u0259sir g\xF6st\u0259rmi\u015Fdir."}},10:{title:{en:"Motivation and Emotion",ka:"\u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0",ru:"\u041C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u0438 \u044D\u043C\u043E\u0446\u0438\u0438",hy:"\u0544\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561 \u0587 \u0536\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584",az:"Motivasiya v\u0259 Emosiya"},description:{en:"What drives human behavior and the science of emotions.",ka:"\u10E0\u10D0 \u10D0\u10DB\u10DD\u10EB\u10E0\u10D0\u10D5\u10D4\u10D1\u10E1 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1.",ru:"\u0427\u0442\u043E \u0434\u0432\u0438\u0436\u0435\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0438\u043C \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C \u0438 \u043D\u0430\u0443\u043A\u0430 \u043E\u0431 \u044D\u043C\u043E\u0446\u0438\u044F\u0445.",hy:"\u053B\u0576\u0579\u0576 \u0567 \u0574\u0572\u0578\u0582\u0574 \u0574\u0561\u0580\u0564\u0578\u0582 \u057E\u0561\u0580\u0584\u0568 \u0587 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:",az:"\u0130nsan davran\u0131\u015F\u0131n\u0131 v\u0259 duy\u011Fular elmini idar\u0259 ed\u0259n n\u0259dir."},keyTopics:{en:["Maslow's Hierarchy","Hunger & Eating","Achievement Motivation","Basic Emotions","Emotional Intelligence"],ka:["\u10DB\u10D0\u10E1\u10DA\u10DD\u10E3\u10E1 \u10D8\u10D4\u10E0\u10D0\u10E0\u10E5\u10D8\u10D0","\u10E8\u10D8\u10DB\u10E8\u10D8\u10DA\u10D8 \u10D3\u10D0 \u10ED\u10D0\u10DB\u10D0","\u10DB\u10D8\u10E6\u10EC\u10D4\u10D5\u10D8\u10E1 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0","\u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D8","\u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8"],ru:["\u0418\u0435\u0440\u0430\u0440\u0445\u0438\u044F \u041C\u0430\u0441\u043B\u043E\u0443","\u0413\u043E\u043B\u043E\u0434 \u0438 \u0435\u0434\u0430","\u041C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F","\u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u044D\u043C\u043E\u0446\u0438\u0438","\u042D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442"],hy:["\u0544\u0561\u057D\u056C\u0578\u0578\u0582\u056B \u0570\u056B\u0565\u0580\u0561\u0580\u056D\u056B\u0561","\u054D\u0578\u057E \u0587 \u0578\u0582\u057F\u0565\u056C","\u0541\u0565\u057C\u0584\u0562\u0565\u0580\u0574\u0561\u0576 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561","\u0540\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0570\u0578\u0582\u0575\u0566\u0565\u0580","\u0536\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0561\u0575\u056B\u0576 \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F"],az:["Maslow iyerarxiyas\u0131","Acl\u0131q v\u0259 Yem\u0259k","Nailiyy\u0259t Motivasiyas\u0131","\u018Fsas Emosiyalar","Emosional \u0130ntellekt"]},summary:{en:"Motivation is the set of forces that energize, direct, and sustain behavior, while emotion is the complex psychological state involving subjective experience, physiological arousal, and behavioral expression. This chapter examines the major theories that explain why we do what we do \u2014 from basic drive-reduction theory (behavior motivated by restoring homeostasis) to Maslow's hierarchy of needs (physiological, safety, belonging, esteem, and self-actualization). It explores the critical distinction between intrinsic motivation (doing something for its inherent satisfaction) and extrinsic motivation (driven by external rewards or punishments), including research on the overjustification effect. The chapter compares three influential theories of emotion: James-Lange (body reacts first, then we feel), Cannon-Bard (body and emotion occur simultaneously), and Schachter-Singer's two-factor theory (arousal plus cognitive labeling produces emotion). It also covers Paul Ekman's discovery of six universal facial expressions, the role of the amygdala and autonomic nervous system in emotional processing, and Daniel Goleman's influential concept of emotional intelligence \u2014 the ability to perceive, understand, manage, and effectively use emotions.",ka:"\u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10D8\u10DB \u10EB\u10D0\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E0\u10D7\u10DD\u10D1\u10DA\u10D8\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D4\u10DC\u10D4\u10E0\u10D2\u10D8\u10D8\u10D7 \u10D0\u10D5\u10E1\u10D4\u10D1\u10E1, \u10DB\u10D0\u10E0\u10D7\u10D0\u10D5\u10E1 \u10D3\u10D0 \u10D8\u10DC\u10D0\u10E0\u10E9\u10E3\u10DC\u10D4\u10D1\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1, \u10EE\u10DD\u10DA\u10DD \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E0\u10D7\u10E3\u10DA\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E1\u10E3\u10D1\u10D8\u10D4\u10E5\u10E2\u10E3\u10E0 \u10D2\u10D0\u10DB\u10DD\u10EA\u10D3\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1, \u10E4\u10D8\u10D6\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0 \u10D0\u10D2\u10D6\u10DC\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D8\u10D7 \u10D2\u10D0\u10DB\u10DD\u10EE\u10D0\u10E2\u10E3\u10DA\u10D4\u10D1\u10D0\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10EE\u10E1\u10DC\u10D8\u10D0\u10DC \u10D7\u10E3 \u10E0\u10D0\u10E2\u10DD\u10DB \u10D5\u10D0\u10D9\u10D4\u10D7\u10D4\u10D1\u10D7 \u10D8\u10DB\u10D0\u10E1, \u10E0\u10D0\u10E1\u10D0\u10EA \u10D5\u10D0\u10D9\u10D4\u10D7\u10D4\u10D1\u10D7 - \u10D3\u10D0\u10EC\u10E7\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DA\u10E2\u10DD\u10DA\u10D5\u10D8\u10E1 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D8\u10D3\u10D0\u10DC (\u10F0\u10DD\u10DB\u10D4\u10DD\u10E1\u10E2\u10D0\u10D6\u10D8\u10E1 \u10D0\u10E6\u10D3\u10D2\u10D4\u10DC\u10D8\u10D7 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D0), \u10DB\u10D0\u10E1\u10DA\u10DD\u10E3\u10E1 \u10E1\u10D0\u10ED\u10D8\u10E0\u10DD\u10D4\u10D1\u10D0\u10D7\u10D0 \u10D8\u10D4\u10E0\u10D0\u10E0\u10E5\u10D8\u10D0\u10DB\u10D3\u10D4 (\u10E4\u10D8\u10D6\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8, \u10E3\u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10DD\u10D4\u10D1\u10D8\u10E1, \u10DB\u10D8\u10D9\u10E3\u10D7\u10D5\u10DC\u10D4\u10D1\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1, \u10DE\u10D0\u10E2\u10D8\u10D5\u10D8\u10E1\u10EA\u10D4\u10DB\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D7\u10D5\u10D8\u10D7\u10D0\u10E5\u10E2\u10E3\u10D0\u10DA\u10D8\u10D6\u10D0\u10EA\u10D8\u10D8\u10E1 \u10E1\u10D0\u10ED\u10D8\u10E0\u10DD\u10D4\u10D1\u10D4\u10D1\u10D8). \u10D8\u10D2\u10D8 \u10E8\u10D4\u10D8\u10E1\u10EC\u10D0\u10D5\u10DA\u10D8\u10E1 \u10D9\u10E0\u10D8\u10E2\u10D8\u10D9\u10E3\u10DA \u10D2\u10D0\u10DC\u10E1\u10EE\u10D5\u10D0\u10D5\u10D4\u10D1\u10D0\u10E1 \u10E8\u10D8\u10DC\u10D0\u10D2\u10D0\u10DC \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1 (\u10E0\u10D0\u10E6\u10D0\u10EA\u10D8\u10E1 \u10D9\u10D4\u10D7\u10D4\u10D1\u10D0 \u10DB\u10D8\u10E1\u10D8 \u10D7\u10D0\u10DC\u10D3\u10D0\u10E7\u10DD\u10DA\u10D8\u10DA\u10D8 \u10D9\u10DB\u10D0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1) \u10D3\u10D0 \u10D2\u10D0\u10E0\u10D4\u10D2\u10D0\u10DC \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1 (\u10EC\u10D0\u10EE\u10D0\u10DA\u10D8\u10E1\u10D4\u10D1\u10D0 \u10D2\u10D0\u10E0\u10D4 \u10EF\u10D8\u10DA\u10D3\u10DD\u10D4\u10D1\u10D8\u10D7 \u10D0\u10DC \u10D3\u10D0\u10E1\u10EF\u10D8\u10D7) \u10E8\u10DD\u10E0\u10D8\u10E1, \u10ED\u10D0\u10E0\u10D1\u10D8 \u10D2\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10E9\u10D0\u10D7\u10D5\u10DA\u10D8\u10D7. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10D3\u10D0\u10E0\u10D4\u10D1\u10E1 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D8\u10E1 \u10E1\u10D0\u10DB \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D8\u10D0\u10DC \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0\u10E1: \u10EF\u10D4\u10D8\u10DB\u10E1-\u10DA\u10D0\u10DC\u10D2\u10D4\u10E1 (\u10E1\u10EE\u10D4\u10E3\u10DA\u10D8 \u10EF\u10D4\u10E0 \u10E0\u10D4\u10D0\u10D2\u10D8\u10E0\u10D4\u10D1\u10E1, \u10DB\u10D4\u10E0\u10D4 \u10D5\u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D7), \u10D9\u10D0\u10DC\u10DD\u10DC-\u10D1\u10D0\u10E0\u10D3\u10D8\u10E1 (\u10E1\u10EE\u10D4\u10E3\u10DA\u10D8 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0 \u10D4\u10E0\u10D7\u10D3\u10E0\u10DD\u10E3\u10DA\u10D0\u10D3 \u10E9\u10DC\u10D3\u10D4\u10D1\u10D0) \u10D3\u10D0 \u10E8\u10D0\u10EE\u10E2\u10D4\u10E0-\u10D6\u10D8\u10DC\u10D2\u10D4\u10E0\u10D8\u10E1 \u10DD\u10E0\u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D8\u10D0\u10DC \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0\u10E1 (\u10D0\u10D2\u10D6\u10DC\u10D4\u10D1\u10D0 \u10DE\u10DA\u10E3\u10E1 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D8\u10D0\u10E0\u10DA\u10D8\u10E7\u10D8 \u10EC\u10D0\u10E0\u10DB\u10DD\u10E5\u10DB\u10DC\u10D8\u10E1 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0\u10E1). \u10D8\u10D2\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10DE\u10DD\u10DA \u10D4\u10D9\u10DB\u10D0\u10DC\u10D8\u10E1 \u10DB\u10D8\u10D4\u10E0 \u10E1\u10D0\u10EE\u10D8\u10E1 \u10D4\u10E5\u10D5\u10E1\u10D8 \u10E3\u10DC\u10D8\u10D5\u10D4\u10E0\u10E1\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DB\u10DD\u10DB\u10D4\u10E2\u10E7\u10D5\u10D4\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E6\u10DB\u10DD\u10E9\u10D4\u10DC\u10D0\u10E1, \u10D0\u10DB\u10D8\u10D2\u10D3\u10D0\u10DA\u10D0\u10E1 \u10D3\u10D0 \u10D5\u10D4\u10D2\u10D4\u10E2\u10D0\u10E2\u10D8\u10E3\u10E0\u10D8 \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D8\u10E1 \u10E0\u10DD\u10DA\u10E1 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0 \u10D3\u10D0\u10DB\u10E3\u10E8\u10D0\u10D5\u10D4\u10D1\u10D0\u10E8\u10D8 \u10D3\u10D0 \u10D3\u10D0\u10DC\u10D8\u10D4\u10DA \u10D2\u10DD\u10E3\u10DA\u10DB\u10D0\u10DC\u10D8\u10E1 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D8\u10D0\u10DC \u10D9\u10DD\u10DC\u10EA\u10D4\u10E4\u10EA\u10D8\u10D0\u10E1 \u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1 - \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E6\u10E5\u10DB\u10D8\u10E1, \u10D2\u10D0\u10D2\u10D4\u10D1\u10D8\u10E1, \u10DB\u10D0\u10E0\u10D7\u10D5\u10D8\u10E1 \u10D3\u10D0 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D0\u10D3 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E3\u10DC\u10D0\u10E0\u10E1.",ru:"\u041C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u2014 \u044D\u0442\u043E \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0441\u0438\u043B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0437\u0430\u0440\u044F\u0436\u0430\u044E\u0442 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439, \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0442 \u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0442 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u044D\u043C\u043E\u0446\u0438\u044F \u2014 \u044D\u0442\u043E \u0441\u043B\u043E\u0436\u043D\u043E\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0435\u0435 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0439 \u043E\u043F\u044B\u0442, \u0444\u0438\u0437\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u043E\u0435 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0442\u0435\u043E\u0440\u0438\u0438, \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u044E\u0449\u0438\u0435, \u043F\u043E\u0447\u0435\u043C\u0443 \u043C\u044B \u0434\u0435\u043B\u0430\u0435\u043C \u0442\u043E, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u043C \u2014 \u043E\u0442 \u0431\u0430\u0437\u043E\u0432\u043E\u0439 \u0442\u0435\u043E\u0440\u0438\u0438 \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u044F \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F (\u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u043C\u043E\u0442\u0438\u0432\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0433\u043E\u043C\u0435\u043E\u0441\u0442\u0430\u0437\u0430) \u0434\u043E \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u0438 \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0435\u0439 \u041C\u0430\u0441\u043B\u043E\u0443 (\u0444\u0438\u0437\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435, \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u043D\u043E\u0441\u0442\u044C, \u0443\u0432\u0430\u0436\u0435\u043D\u0438\u0435 \u0438 \u0441\u0430\u043C\u043E\u0430\u043A\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F). \u0418\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442\u0441\u044F \u043A\u0440\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u0435\u0439 (\u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u0442\u043E \u0440\u0430\u0434\u0438 \u043F\u0440\u0438\u0441\u0443\u0449\u0435\u0433\u043E \u044D\u0442\u043E\u043C\u0443 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F) \u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u0439 \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u0435\u0439 (\u0434\u0432\u0438\u0436\u0438\u043C\u043E\u0439 \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 \u043D\u0430\u0433\u0440\u0430\u0434\u0430\u043C\u0438 \u0438\u043B\u0438 \u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u044F\u043C\u0438), \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u044D\u0444\u0444\u0435\u043A\u0442\u0430 \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u0433\u043E \u043E\u043F\u0440\u0430\u0432\u0434\u0430\u043D\u0438\u044F. \u0412 \u0433\u043B\u0430\u0432\u0435 \u0441\u0440\u0430\u0432\u043D\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0442\u0440\u0438 \u0432\u043B\u0438\u044F\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0442\u0435\u043E\u0440\u0438\u0438 \u044D\u043C\u043E\u0446\u0438\u0439: \u0414\u0436\u0435\u0439\u043C\u0441\u0430-\u041B\u0430\u043D\u0433\u0435 (\u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442 \u0442\u0435\u043B\u043E, \u0437\u0430\u0442\u0435\u043C \u043C\u044B \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u043C), \u041A\u044D\u043D\u043D\u043E\u043D\u0430-\u0411\u0430\u0440\u0434\u0430 (\u0442\u0435\u043B\u043E \u0438 \u044D\u043C\u043E\u0446\u0438\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E) \u0438 \u0434\u0432\u0443\u0445\u0444\u0430\u043A\u0442\u043E\u0440\u043D\u0430\u044F \u0442\u0435\u043E\u0440\u0438\u044F \u0428\u0430\u0445\u0442\u0435\u0440\u0430-\u0417\u0438\u043D\u0433\u0435\u0440\u0430 (\u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043B\u044E\u0441 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0439 \u044F\u0440\u043B\u044B\u043A \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0442 \u044D\u043C\u043E\u0446\u0438\u044E). \u0422\u0430\u043A\u0436\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u041F\u043E\u043B\u043E\u043C \u042D\u043A\u043C\u0430\u043D\u043E\u043C \u0448\u0435\u0441\u0442\u0438 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0445 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0439 \u043B\u0438\u0446\u0430, \u0440\u043E\u043B\u044C \u043C\u0438\u043D\u0434\u0430\u043B\u0435\u0432\u0438\u0434\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0430 \u0438 \u0432\u0435\u0433\u0435\u0442\u0430\u0442\u0438\u0432\u043D\u043E\u0439 \u043D\u0435\u0440\u0432\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0432 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0439 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0435, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0432\u043B\u0438\u044F\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 \u0414\u044D\u043D\u0438\u0435\u043B\u0430 \u0413\u043E\u0443\u043B\u043C\u0430\u043D\u0430 \u2014 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C, \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0438 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u044D\u043C\u043E\u0446\u0438\u0438.",hy:"\u0544\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576 \u0561\u0575\u0576 \u0578\u0582\u056A\u0565\u0580\u056B \u0561\u0574\u0562\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0567, \u0578\u0580\u0578\u0576\u0584 \u0567\u0576\u0565\u0580\u0563\u056B\u0561 \u0565\u0576 \u0570\u0561\u0572\u0578\u0580\u0564\u0578\u0582\u0574, \u0578\u0582\u0572\u0572\u0578\u0580\u0564\u0578\u0582\u0574 \u0587 \u057A\u0561\u0570\u057A\u0561\u0576\u0578\u0582\u0574 \u057E\u0561\u0580\u0584\u0568, \u0574\u056B\u0576\u0579\u0564\u0565\u057C \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0568 \u0562\u0561\u0580\u0564 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u057E\u056B\u0573\u0561\u056F \u0567, \u0578\u0580\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u057D\u0578\u0582\u0562\u0575\u0565\u056F\u057F\u056B\u057E \u0583\u0578\u0580\u0571, \u0586\u056B\u0566\u056B\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u0563\u0580\u0563\u057C\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u057E\u0561\u0580\u0584\u0561\u0575\u056B\u0576 \u0561\u0580\u057F\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0565\u0576, \u0569\u0565 \u056B\u0576\u0579\u0578\u0582 \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u0561\u0576\u0578\u0582\u0574 \u0561\u0575\u0576, \u056B\u0576\u0579 \u0561\u0576\u0578\u0582\u0574 \u0565\u0576\u0584\u055D \u057D\u056F\u057D\u0561\u056E \u0574\u0572\u0574\u0561\u0576 \u0576\u057E\u0561\u0566\u0565\u0581\u0574\u0561\u0576 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u056B\u0581 (\u0570\u0578\u0574\u0565\u0578\u057D\u057F\u0561\u0566\u056B \u057E\u0565\u0580\u0561\u056F\u0561\u0576\u0563\u0576\u0574\u0561\u0574\u0562 \u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u057E\u0561\u056E \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E) \u0574\u056B\u0576\u0579\u0587 \u0544\u0561\u057D\u056C\u0578\u0578\u0582\u056B \u056F\u0561\u0580\u056B\u0584\u0576\u0565\u0580\u056B \u0570\u056B\u0565\u0580\u0561\u0580\u056D\u056B\u0561\u0576 (\u0586\u056B\u0566\u056B\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576, \u0561\u0576\u057E\u057F\u0561\u0576\u0563\u0578\u0582\u0569\u0575\u0561\u0576, \u057A\u0561\u057F\u056F\u0561\u0576\u0565\u056C\u0578\u0582\u0569\u0575\u0561\u0576, \u0570\u0561\u0580\u0563\u0561\u0576\u0584\u056B \u0587 \u056B\u0576\u0584\u0576\u0561\u056B\u0580\u0561\u0581\u0574\u0561\u0576): \u0531\u0575\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0567\u0561\u056F\u0561\u0576 \u057F\u0561\u0580\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u0565\u0580\u0584\u056B\u0576 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0575\u056B (\u0578\u0580\u0587\u0567 \u0562\u0561\u0576 \u0561\u0576\u0565\u056C \u056B\u0580 \u0562\u0576\u0578\u0580\u0578\u0577 \u0562\u0561\u057E\u0561\u0580\u0561\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u0580) \u0587 \u0561\u0580\u057F\u0561\u0584\u056B\u0576 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0575\u056B \u0574\u056B\u057B\u0587 (\u057A\u0561\u0575\u0574\u0561\u0576\u0561\u057E\u0578\u0580\u057E\u0561\u056E \u0561\u0580\u057F\u0561\u0584\u056B\u0576 \u057A\u0561\u0580\u0563\u0587\u0576\u0565\u0580\u0578\u057E \u056F\u0561\u0574 \u057A\u0561\u057F\u056B\u056A\u0576\u0565\u0580\u0578\u057E), \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0563\u0565\u0580\u0561\u0580\u0564\u0561\u0580\u0561\u0581\u0574\u0561\u0576 \u0567\u0586\u0565\u056F\u057F\u056B \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0533\u056C\u0578\u0582\u056D\u0568 \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0578\u0582\u0574 \u0567 \u0570\u0578\u0582\u0575\u0566\u0565\u0580\u056B \u0565\u0580\u0565\u0584 \u0561\u0566\u0564\u0565\u0581\u056B\u056F \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568. \u054B\u0565\u0575\u0574\u057D-\u053C\u0561\u0576\u0563\u0565 (\u0574\u0561\u0580\u0574\u056B\u0576\u0568 \u0576\u0561\u056D \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0578\u0582\u0574 \u0567, \u0570\u0565\u057F\u0578 \u0574\u0565\u0576\u0584 \u0566\u0563\u0578\u0582\u0574 \u0565\u0576\u0584), \u0554\u0565\u0576\u0578\u0576-\u0532\u0561\u0580\u0564 (\u0574\u0561\u0580\u0574\u056B\u0576\u0568 \u0587 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0568 \u0574\u056B\u0561\u056A\u0561\u0574\u0561\u0576\u0561\u056F \u0565\u0576 \u0561\u057C\u0561\u057B\u0561\u0576\u0578\u0582\u0574) \u0587 \u0547\u0561\u056D\u057F\u0565\u0580-\u0536\u056B\u0576\u0563\u0565\u0580\u056B \u0565\u0580\u056F\u0563\u0578\u0580\u056E\u0578\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0563\u0580\u0563\u057C\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u056F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0574\u0565\u056F\u0576\u0561\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0561\u057C\u0561\u057B\u0561\u0581\u0576\u0578\u0582\u0574 \u0565\u0576 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584): \u0531\u0575\u0576 \u0576\u0561\u0587 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0553\u0578\u056C \u0537\u056F\u0574\u0561\u0576\u056B \u056F\u0578\u0572\u0574\u056B\u0581 \u057E\u0565\u0581 \u0578\u0582\u0576\u056B\u057E\u0565\u0580\u057D\u0561\u056C \u0564\u056B\u0574\u0561\u056D\u0561\u0572\u0565\u0580\u056B \u0570\u0561\u0575\u057F\u0576\u0561\u0562\u0565\u0580\u0578\u0582\u0574\u0568, \u0576\u0577\u0561\u0563\u0565\u0572\u0571\u056B \u0587 \u056B\u0576\u0584\u0576\u0561\u057E\u0561\u0580 \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u056B \u0564\u0565\u0580\u0568 \u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u0574\u0577\u0561\u056F\u0574\u0561\u0576 \u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0587 \u0534\u0561\u0576\u056B\u0565\u056C \u0533\u0578\u0578\u0582\u056C\u0574\u0561\u0576\u056B \u0561\u0566\u0564\u0565\u0581\u056B\u056F \u0564\u056B\u0580\u0584\u0578\u0580\u0578\u0577\u0578\u0582\u0574\u0568 \u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u056B \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0575\u0561\u056C\u055D \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0576 \u0568\u0576\u056F\u0561\u056C\u0565\u056C\u0578\u0582, \u0570\u0561\u057D\u056F\u0561\u0576\u0561\u056C\u0578\u0582, \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0565\u056C\u0578\u0582 \u0587 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0565\u056C\u0578\u0582 \u0578\u0582\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576:",az:"Motivasiya, davran\u0131\u015F\u0131 g\xFCcl\u0259ndir\u0259n, y\xF6nl\u0259ndir\u0259n v\u0259 davam etdir\u0259n q\xFCvv\u0259l\u0259r m\u0259cmusudur, emosiya is\u0259 subyektiv t\u0259cr\xFCb\u0259ni, fizioloji oyan\u0131\u015F\u0131 v\u0259 davran\u0131\u015F ifad\u0259sini \xF6z\xFCnd\u0259 birl\u0259\u015Fdir\u0259n m\xFCr\u0259kk\u0259b psixoloji v\u0259ziyy\u0259tdir. Bu f\u0259sil n\u0259 etdiyimizi niy\u0259 etdiyimizi izah ed\u0259n \u0259sas n\u0259z\u0259riyy\u0259l\u0259ri - t\u0259m\u0259l s\xFCr\xFCc\xFC-azaltma n\u0259z\u0259riyy\u0259sind\u0259n (homeostaz\u0131 b\u0259rpa etm\u0259kl\u0259 idar\u0259 olunan davran\u0131\u015F) Maslow-un ehtiyaclar iyerarxiyas\u0131na (fizioloji, t\u0259hl\xFCk\u0259sizlik, m\u0259nsubiyy\u0259t, h\xF6rm\u0259t v\u0259 \xF6z\xFCn\xFCrealla\u015Fd\u0131rma) q\u0259d\u0259r ara\u015Fd\u0131r\u0131r. H\u0259ddind\u0259n art\u0131q b\u0259ra\u0259t effekti il\u0259 ba\u011Fl\u0131 t\u0259dqiqatlar da daxil olmaqla, daxili motivasiya (bir \u015Feyi \xF6z\xFCnd\u0259 olan m\u0259mnunluq \xFC\xE7\xFCn etm\u0259k) v\u0259 xarici motivasiya (xarici m\xFCkafatlar v\u0259 ya c\u0259zalarla idar\u0259 olunan) aras\u0131ndak\u0131 kritik f\u0259rqi ara\u015Fd\u0131r\u0131r. F\u0259sil \xFC\xE7 t\u0259sirli f\u0259rqli emosiya n\u0259z\u0259riyy\u0259sini m\xFCqayis\u0259 edir: James-Lange (b\u0259d\u0259n \u0259vv\u0259lc\u0259 reaksiya verir, sonra hiss edirik), Cannon-Bard (b\u0259d\u0259n v\u0259 emosiya eyni vaxtda ba\u015F verir) v\u0259 Schachter-Singer-in ikifaktorlu n\u0259z\u0259riyy\u0259si (oyan\u0131ql\u0131q v\u0259 koqnitiv etiket birlikd\u0259 emosiya yarad\u0131r). Eyni zamanda Paul Ekman t\u0259r\u0259find\u0259n alt\u0131 universal \xFCz ifad\u0259sinin k\u0259\u015Ffi, emosional emal prosesind\u0259 amiqdala v\u0259 avtonom sinir sisteminin rolu, h\u0259m\xE7inin Daniel Goleman-\u0131n hissl\u0259ri qavramaq, anlamaq, idar\u0259 etm\u0259k v\u0259 t\u0259sirli \u015F\u0259kild\u0259 istifad\u0259 etm\u0259k bacar\u0131\u011F\u0131 olan emosional intellektin t\u0259sirli konsepsiyas\u0131 da \u0259hat\u0259 olunur."},keyPoints:{en:["Motivation has three components: activation (initiating), persistence (continuing effort), and intensity (how hard you try).","Drive-reduction theory: physiological needs create drives (hunger, thirst) that motivate behavior to restore homeostasis. But it can't explain curiosity or thrill-seeking.","Maslow's hierarchy of needs (bottom to top): Physiological \u2192 Safety \u2192 Love/Belonging \u2192 Esteem \u2192 Self-actualization. Lower needs must be met before higher ones become motivating.","Intrinsic motivation (doing something for its own sake) is more sustainable than extrinsic motivation (rewards/punishments). The overjustification effect: rewarding an already enjoyed activity can decrease intrinsic motivation.","Theories of emotion: James-Lange (body reacts first, then we feel emotion), Cannon-Bard (body reaction and emotion occur simultaneously), Schachter-Singer / Two-factor (physiological arousal + cognitive label = emotion).","Paul Ekman identified 6 universal facial expressions: happiness, sadness, anger, fear, surprise, and disgust. These are recognized across all cultures.","Emotional intelligence (Goleman): the ability to perceive, understand, manage, and use emotions effectively. High EQ predicts better relationships, leadership, and mental health."],ka:["\u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1 \u10D0\u10E5\u10D5\u10E1 \u10E1\u10D0\u10DB\u10D8 \u10D9\u10DD\u10DB\u10DE\u10DD\u10DC\u10D4\u10DC\u10E2\u10D8: \u10D0\u10E5\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0 (\u10D3\u10D0\u10EC\u10E7\u10D4\u10D1\u10D0), \u10E8\u10D4\u10E3\u10DE\u10DD\u10D5\u10E0\u10DD\u10D1\u10D0 (\u10D2\u10D0\u10DC\u10D2\u10E0\u10EB\u10DD\u10D1\u10D8\u10D7\u10D8 \u10EB\u10D0\u10DA\u10D8\u10E1\u10EE\u10DB\u10D4\u10D5\u10D0) \u10D3\u10D0 \u10D8\u10DC\u10E2\u10D4\u10DC\u10E1\u10D8\u10D5\u10DD\u10D1\u10D0 (\u10E0\u10D0\u10DB\u10D3\u10D4\u10DC\u10D0\u10D3 \u10DB\u10DD\u10DC\u10D3\u10DD\u10DB\u10D4\u10D1\u10E3\u10DA\u10D8 \u10EE\u10D0\u10E0\u10D7).","\u10DA\u10E2\u10DD\u10DA\u10D5\u10D8\u10E1 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0: \u10E4\u10D8\u10D6\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10E1\u10D0\u10ED\u10D8\u10E0\u10DD\u10D4\u10D1\u10D4\u10D1\u10D8 \u10E5\u10DB\u10DC\u10D8\u10D0\u10DC \u10DA\u10E2\u10DD\u10DA\u10D5\u10D0\u10E1 (\u10E8\u10D8\u10DB\u10E8\u10D8\u10DA\u10D8, \u10EC\u10E7\u10E3\u10E0\u10D5\u10D8\u10DA\u10D8), \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1 \u10D0\u10EB\u10DA\u10D4\u10D5\u10D4\u10DC \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10F0\u10DD\u10DB\u10D4\u10DD\u10E1\u10E2\u10D0\u10D6\u10D8\u10E1 \u10D0\u10E6\u10E1\u10D0\u10D3\u10D2\u10D4\u10DC\u10D0\u10D3. \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10DB\u10D0\u10E1 \u10D0\u10E0 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0 \u10D0\u10EE\u10E1\u10DC\u10D0\u10E1 \u10EA\u10DC\u10DD\u10D1\u10D8\u10E1\u10DB\u10DD\u10E7\u10D5\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0 \u10D0\u10DC \u10DB\u10EB\u10D0\u10E4\u10E0\u10D8 \u10E8\u10D4\u10D2\u10E0\u10EB\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10EB\u10D8\u10D4\u10D1\u10D0.","\u10DB\u10D0\u10E1\u10DA\u10DD\u10E3\u10E1 \u10E1\u10D0\u10ED\u10D8\u10E0\u10DD\u10D4\u10D1\u10D0\u10D7\u10D0 \u10D8\u10D4\u10E0\u10D0\u10E0\u10E5\u10D8\u10D0 (\u10E5\u10D5\u10D4\u10DB\u10DD\u10D3\u10D0\u10DC \u10D6\u10D4\u10DB\u10DD\u10D7): \u10E4\u10D8\u10D6\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u2192 \u10E3\u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10DD\u10D4\u10D1\u10D0 \u2192 \u10E1\u10D8\u10E7\u10D5\u10D0\u10E0\u10E3\u10DA\u10D8/\u10DB\u10D8\u10D9\u10E3\u10D7\u10D5\u10DC\u10D4\u10D1\u10E3\u10DA\u10DD\u10D1\u10D0 \u2192 \u10DE\u10D0\u10E2\u10D8\u10D5\u10D8\u10E1\u10EA\u10D4\u10DB\u10D0 \u2192 \u10D7\u10D5\u10D8\u10D7\u10D0\u10E5\u10E2\u10E3\u10D0\u10DA\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0. \u10E5\u10D5\u10D4\u10D3\u10D0 \u10D3\u10DD\u10DC\u10D8\u10E1 \u10E1\u10D0\u10ED\u10D8\u10E0\u10DD\u10D4\u10D1\u10D4\u10D1\u10D8 \u10E3\u10DC\u10D3\u10D0 \u10D3\u10D0\u10D9\u10DB\u10D0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D3\u10D4\u10E1 \u10DB\u10D0\u10DC\u10D0\u10DB, \u10E1\u10D0\u10DC\u10D0\u10DB \u10E3\u10E4\u10E0\u10DD \u10DB\u10D0\u10E6\u10D0\u10DA\u10D8 \u10D3\u10DD\u10DC\u10D8\u10E1 \u10E1\u10D0\u10ED\u10D8\u10E0\u10DD\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D2\u10D0\u10EE\u10D3\u10D4\u10D1\u10D0 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10E2\u10DD\u10E0\u10D8.","\u10E8\u10D8\u10DC\u10D0\u10D2\u10D0\u10DC\u10D8 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0 (\u10E0\u10D0\u10E6\u10D0\u10EA\u10D8\u10E1 \u10D9\u10D4\u10D7\u10D4\u10D1\u10D0 \u10E1\u10D0\u10D9\u10E3\u10D7\u10D0\u10E0\u10D8 \u10D7\u10D0\u10D5\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1) \u10E3\u10E4\u10E0\u10DD \u10DB\u10D3\u10D2\u10E0\u10D0\u10D3\u10D8\u10D0, \u10D5\u10D8\u10D3\u10E0\u10D4 \u10D2\u10D0\u10E0\u10D4\u10D2\u10D0\u10DC\u10D8 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0 (\u10EF\u10D8\u10DA\u10D3\u10DD\u10D4\u10D1\u10D8/\u10D3\u10D0\u10E1\u10EF\u10D0). \u10ED\u10D0\u10E0\u10D1\u10D8 \u10D2\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8: \u10E3\u10D9\u10D5\u10D4 \u10E1\u10D0\u10E1\u10D8\u10D0\u10DB\u10DD\u10D5\u10DC\u10DD \u10E1\u10D0\u10E5\u10DB\u10D8\u10D0\u10DC\u10DD\u10D1\u10D8\u10E1 \u10D3\u10D0\u10EF\u10D8\u10DA\u10D3\u10DD\u10D4\u10D1\u10D0\u10DB \u10E8\u10D4\u10D8\u10EB\u10DA\u10D4\u10D1\u10D0 \u10E8\u10D4\u10D0\u10DB\u10EA\u10D8\u10E0\u10DD\u10E1 \u10E8\u10D8\u10DC\u10D0\u10D2\u10D0\u10DC\u10D8 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0.","\u10D4\u10DB\u10DD\u10EA\u10D8\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8: \u10EF\u10D4\u10D8\u10DB\u10E1-\u10DA\u10D0\u10DC\u10D2\u10D4 (\u10E1\u10EE\u10D4\u10E3\u10DA\u10D8 \u10EF\u10D4\u10E0 \u10E0\u10D4\u10D0\u10D2\u10D8\u10E0\u10D4\u10D1\u10E1, \u10DB\u10D4\u10E0\u10D4 \u10D5\u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D7 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0\u10E1), \u10D9\u10D0\u10DC\u10DD\u10DC-\u10D1\u10D0\u10E0\u10D3\u10D8 (\u10E1\u10EE\u10D4\u10E3\u10DA\u10D8\u10E1 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0 \u10D4\u10E0\u10D7\u10D3\u10E0\u10DD\u10E3\u10DA\u10D0\u10D3 \u10EE\u10D3\u10D4\u10D1\u10D0), \u10E8\u10D0\u10EE\u10E2\u10D4\u10E0-\u10D6\u10D8\u10DC\u10D2\u10D4\u10E0\u10D8 / \u10DD\u10E0\u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D8\u10D0\u10DC\u10D8 (\u10E4\u10D8\u10D6\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D0\u10D2\u10D6\u10DC\u10D4\u10D1\u10D0 + \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D8\u10D0\u10E0\u10DA\u10D8\u10E7\u10D8 = \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0).","\u10DE\u10DD\u10DA \u10D4\u10D9\u10DB\u10D0\u10DC\u10DB\u10D0 \u10D2\u10D0\u10DB\u10DD\u10E7\u10DD 6 \u10E3\u10DC\u10D8\u10D5\u10D4\u10E0\u10E1\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10D0\u10EE\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10DB\u10D4\u10E2\u10E7\u10D5\u10D4\u10DA\u10D4\u10D1\u10D0: \u10D1\u10D4\u10D3\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0, \u10E1\u10D4\u10D5\u10D3\u10D0, \u10D1\u10E0\u10D0\u10D6\u10D8, \u10E8\u10D8\u10E8\u10D8, \u10D2\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10D6\u10D8\u10D6\u10E6\u10D8. \u10D4\u10E1\u10D4\u10DC\u10D8 \u10D0\u10E6\u10D8\u10D0\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10E7\u10D5\u10D4\u10DA\u10D0 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D0\u10E8\u10D8.","\u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 (\u10D2\u10DD\u10E3\u10DA\u10DB\u10D0\u10DC\u10D8): \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D0\u10D3 \u10D0\u10E6\u10E5\u10DB\u10D8\u10E1, \u10D2\u10D0\u10D2\u10D4\u10D1\u10D8\u10E1, \u10DB\u10D0\u10E0\u10D7\u10D5\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E3\u10DC\u10D0\u10E0\u10D8. \u10DB\u10D0\u10E6\u10D0\u10DA\u10D8 EQ \u10EC\u10D8\u10DC\u10D0\u10E1\u10EC\u10D0\u10E0\u10DB\u10D4\u10E2\u10E7\u10D5\u10D4\u10DA\u10D4\u10D1\u10E1 \u10E3\u10D9\u10D4\u10D7\u10D4\u10E1 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D4\u10D1\u10E1, \u10DA\u10D8\u10D3\u10D4\u10E0\u10DD\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1."],ru:["\u041C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u0438\u043C\u0435\u0435\u0442 \u0442\u0440\u0438 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u0430: \u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044F (\u0438\u043D\u0438\u0446\u0438\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435), \u043D\u0430\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C (\u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0435\u043D\u0438\u0435 \u0443\u0441\u0438\u043B\u0438\u0439) \u0438 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u044C (\u0441\u0442\u0435\u043F\u0435\u043D\u044C \u0443\u0441\u0438\u043B\u0438\u0439).","\u0422\u0435\u043E\u0440\u0438\u044F \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u044F \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F: \u0444\u0438\u0437\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0437\u0434\u0430\u044E\u0442 \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F (\u0433\u043E\u043B\u043E\u0434, \u0436\u0430\u0436\u0434\u0430), \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u043E\u0442\u0438\u0432\u0438\u0440\u0443\u044E\u0442 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0434\u043B\u044F \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u0433\u043E\u043C\u0435\u043E\u0441\u0442\u0430\u0437\u0430. \u041D\u043E \u044D\u0442\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u043B\u044E\u0431\u043E\u043F\u044B\u0442\u0441\u0442\u0432\u043E \u0438\u043B\u0438 \u043F\u043E\u0438\u0441\u043A \u043E\u0441\u0442\u0440\u044B\u0445 \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u0439.","\u0418\u0435\u0440\u0430\u0440\u0445\u0438\u044F \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0435\u0439 \u041C\u0430\u0441\u043B\u043E\u0443 (\u0441\u043D\u0438\u0437\u0443 \u0432\u0432\u0435\u0440\u0445): \u0424\u0438\u0437\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u2192 \u0411\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C \u2192 \u041B\u044E\u0431\u043E\u0432\u044C/\u041F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u043D\u043E\u0441\u0442\u044C \u2192 \u0423\u0432\u0430\u0436\u0435\u043D\u0438\u0435 \u2192 \u0421\u0430\u043C\u043E\u0430\u043A\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F. \u041D\u0438\u0437\u0448\u0438\u0435 \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0438 \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u044B \u0434\u043E \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u0432\u044B\u0441\u0448\u0438\u0435 \u0441\u0442\u0430\u043D\u0443\u0442 \u043C\u043E\u0442\u0438\u0432\u0438\u0440\u0443\u044E\u0449\u0438\u043C\u0438.","\u0412\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044F (\u0434\u0435\u043B\u0430\u0442\u044C \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u0440\u0430\u0434\u0438 \u0441\u0430\u043C\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430) \u0431\u043E\u043B\u0435\u0435 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u0430, \u0447\u0435\u043C \u0432\u043D\u0435\u0448\u043D\u044F\u044F \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044F (\u043D\u0430\u0433\u0440\u0430\u0434\u044B/\u043D\u0430\u043A\u0430\u0437\u0430\u043D\u0438\u044F). \u042D\u0444\u0444\u0435\u043A\u0442 \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E\u0433\u043E \u043E\u043F\u0440\u0430\u0432\u0434\u0430\u043D\u0438\u044F: \u0432\u043E\u0437\u043D\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0437\u0430 \u0443\u0436\u0435 \u043F\u0440\u0438\u044F\u0442\u043D\u043E\u0435 \u0437\u0430\u043D\u044F\u0442\u0438\u0435 \u043C\u043E\u0436\u0435\u0442 \u0441\u043D\u0438\u0437\u0438\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044E.","\u0422\u0435\u043E\u0440\u0438\u0438 \u044D\u043C\u043E\u0446\u0438\u0439: \u0414\u0436\u0435\u0439\u043C\u0441-\u041B\u0430\u043D\u0433\u0435 (\u0442\u0435\u043B\u043E \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442 \u043F\u0435\u0440\u0432\u044B\u043C, \u0437\u0430\u0442\u0435\u043C \u043C\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u043C \u044D\u043C\u043E\u0446\u0438\u044E), \u041A\u044D\u043D\u043D\u043E\u043D-\u0411\u0430\u0440\u0434 (\u0440\u0435\u0430\u043A\u0446\u0438\u044F \u0442\u0435\u043B\u0430 \u0438 \u044D\u043C\u043E\u0446\u0438\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E), \u0428\u0430\u0445\u0442\u0435\u0440-\u0417\u0438\u043D\u0433\u0435\u0440 / \u0414\u0432\u0443\u0445\u0444\u0430\u043A\u0442\u043E\u0440\u043D\u0430\u044F (\u0444\u0438\u0437\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 + \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0439 \u044F\u0440\u043B\u044B\u043A = \u044D\u043C\u043E\u0446\u0438\u044F).","\u041F\u043E\u043B \u042D\u043A\u043C\u0430\u043D \u0432\u044B\u0434\u0435\u043B\u0438\u043B 6 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u044B\u0445 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0439 \u043B\u0438\u0446\u0430: \u0441\u0447\u0430\u0441\u0442\u044C\u0435, \u0433\u0440\u0443\u0441\u0442\u044C, \u0433\u043D\u0435\u0432, \u0441\u0442\u0440\u0430\u0445, \u0443\u0434\u0438\u0432\u043B\u0435\u043D\u0438\u0435 \u0438 \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435. \u041E\u043D\u0438 \u0440\u0430\u0441\u043F\u043E\u0437\u043D\u0430\u044E\u0442\u0441\u044F \u0432\u043E \u0432\u0441\u0435\u0445 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0430\u0445.","\u042D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 (\u0413\u043E\u0443\u043B\u043C\u0430\u043D): \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C, \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u044D\u043C\u043E\u0446\u0438\u0438 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E. \u0412\u044B\u0441\u043E\u043A\u0438\u0439 EQ \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043B\u0443\u0447\u0448\u0438\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F, \u043B\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u043E \u0438 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u0435."],hy:["\u0544\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576 \u0578\u0582\u0576\u056B \u0565\u0580\u0565\u0584 \u0562\u0561\u0572\u0561\u0564\u0580\u056B\u0579\u055D \u0561\u056F\u057F\u056B\u057E\u0561\u0581\u0578\u0582\u0574 (\u0576\u0561\u056D\u0561\u0571\u0565\u057C\u0576\u0578\u0582\u0574), \u0570\u0561\u0574\u0561\u057C\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u0561\u056F\u0561\u0576 \u057B\u0561\u0576\u0584) \u0587 \u056B\u0576\u057F\u0565\u0576\u057D\u056B\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0578\u0580\u0584\u0561\u0576 \u0565\u0584 \u0583\u0578\u0580\u0571\u0578\u0582\u0574):","\u0544\u0572\u0574\u0561\u0576 \u0576\u057E\u0561\u0566\u0565\u0581\u0574\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0586\u056B\u0566\u056B\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u056F\u0561\u0580\u056B\u0584\u0576\u0565\u0580\u0568 \u057D\u057F\u0565\u0572\u056E\u0578\u0582\u0574 \u0565\u0576 \u0574\u0572\u0578\u0582\u0574\u0576\u0565\u0580 (\u057D\u0578\u057E, \u056E\u0561\u0580\u0561\u057E), \u0578\u0580\u0578\u0576\u0584 \u0564\u0580\u0564\u0578\u0582\u0574 \u0565\u0576 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568 \u057E\u0565\u0580\u0561\u056F\u0561\u0576\u0563\u0576\u0565\u056C\u0578\u0582 \u0570\u0578\u0574\u0565\u0578\u057D\u057F\u0561\u0566\u0568: \u0532\u0561\u0575\u0581 \u0564\u0561 \u0579\u056B \u056F\u0561\u0580\u0578\u0572 \u0562\u0561\u0581\u0561\u057F\u0580\u0565\u056C \u0570\u0565\u057F\u0561\u0584\u0580\u0584\u0580\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0574 \u057D\u0578\u0582\u0580 \u0566\u0563\u0561\u0581\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0578\u0580\u0578\u0576\u0578\u0582\u0574\u0568:","\u0544\u0561\u057D\u056C\u0578\u0578\u0582\u056B \u056F\u0561\u0580\u056B\u0584\u0576\u0565\u0580\u056B \u0570\u056B\u0565\u0580\u0561\u0580\u056D\u056B\u0561\u0576 (\u0576\u0565\u0580\u0584\u0587\u056B\u0581 \u057E\u0565\u0580\u0587). \u0556\u056B\u0566\u056B\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u2192 \u0531\u0576\u057E\u057F\u0561\u0576\u0563\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u2192 \u054D\u0565\u0580/\u054A\u0561\u057F\u056F\u0561\u0576\u0565\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u2192 \u0540\u0561\u0580\u0563\u0561\u0576\u0584 \u2192 \u053B\u0576\u0584\u0576\u0561\u056B\u0580\u0561\u0581\u0578\u0582\u0574: \u0531\u057E\u0565\u056C\u056B \u0581\u0561\u056E\u0580 \u056F\u0561\u0580\u056B\u0584\u0576\u0565\u0580\u0568 \u057A\u0565\u057F\u0584 \u0567 \u0562\u0561\u057E\u0561\u0580\u0561\u0580\u057E\u0565\u0576 \u0576\u0561\u056D\u0584\u0561\u0576 \u0561\u057E\u0565\u056C\u056B \u0562\u0561\u0580\u0571\u0580 \u056F\u0561\u0580\u056B\u0584\u0576\u0565\u0580\u0568 \u0578\u0580\u057A\u0565\u057D \u0577\u0561\u0580\u056A\u056B\u0579 \u0578\u0582\u056A \u0564\u0561\u057C\u0576\u0561\u0576:","\u0546\u0565\u0580\u0584\u056B\u0576 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576 (\u056B\u0576\u0579-\u0578\u0580 \u0562\u0561\u0576 \u0561\u0576\u0565\u056C \u0570\u0561\u0576\u0578\u0582\u0576 \u0562\u0578\u0582\u0576 \u0563\u0578\u0580\u056E\u0568\u0576\u0569\u0561\u0581\u056B) \u0561\u057E\u0565\u056C\u056B \u056F\u0561\u0575\u0578\u0582\u0576 \u0567, \u0584\u0561\u0576 \u0561\u0580\u057F\u0561\u0584\u056B\u0576 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576 (\u057A\u0561\u0580\u0563\u0587\u0576\u0565\u0580/\u057A\u0561\u057F\u056B\u056A\u0576\u0565\u0580): \u0533\u0565\u0580\u0561\u0580\u0564\u0561\u0580\u0561\u0581\u0574\u0561\u0576 \u0567\u0586\u0565\u056F\u057F. \u0561\u0580\u0564\u0565\u0576 \u056B\u057D\u056F \u0570\u0561\u0573\u0565\u056C\u056B \u0563\u0578\u0580\u056E\u0578\u0582\u0576\u0565\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u0580 \u057E\u0561\u0580\u0571\u0561\u057F\u0580\u0565\u056C\u0568 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0565\u056C \u0576\u0565\u0580\u0584\u056B\u0576 \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576:","\u0540\u0578\u0582\u0575\u0566\u0565\u0580\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u054B\u0565\u0575\u0574\u057D-\u053C\u0561\u0576\u0563\u0565 (\u0574\u0561\u0580\u0574\u056B\u0576\u0568 \u0576\u0561\u056D \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0578\u0582\u0574 \u0567, \u0570\u0565\u057F\u0578 \u0574\u0565\u0576\u0584 \u0570\u0578\u0582\u0575\u0566 \u0565\u0576\u0584 \u0566\u0563\u0578\u0582\u0574), \u0554\u0565\u0576\u0578\u0576-\u0532\u0561\u0580\u0564 (\u0574\u0561\u0580\u0574\u0576\u056B \u057C\u0565\u0561\u056F\u0581\u056B\u0561\u0576 \u0587 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0568 \u057F\u0565\u0572\u056B \u0565\u0576 \u0578\u0582\u0576\u0565\u0576\u0578\u0582\u0574 \u0574\u056B\u0561\u056A\u0561\u0574\u0561\u0576\u0561\u056F), \u0547\u0561\u056D\u057F\u0565\u0580-\u0536\u056B\u0576\u0563\u0565\u0580 / \u0535\u0580\u056F\u0563\u0578\u0580\u056E\u0578\u0576 (\u0586\u056B\u0566\u056B\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u0563\u0580\u0563\u057C\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576 + \u056F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0574\u0565\u056F\u0576\u0561\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 = \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584):","\u0553\u0578\u056C \u0537\u056F\u0574\u0561\u0576\u0568 \u0561\u057C\u0561\u0576\u0571\u0576\u0561\u0581\u0580\u0565\u0581 6 \u0570\u0561\u0574\u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0564\u0565\u0574\u0584\u056B \u0561\u0580\u057F\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u055D \u0564\u0580\u0561\u056F\u0561\u0576 (\u0565\u0580\u057B\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u057F\u056D\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0566\u0561\u0575\u0580\u0578\u0582\u0575\u0569, \u057E\u0561\u056D, \u0561\u0576\u0561\u056F\u0576\u056F\u0561\u056C \u0587 \u0566\u0566\u057E\u0561\u0576\u0584: \u0534\u0580\u0561\u0576\u0584 \u0573\u0561\u0576\u0561\u0579\u057E\u0578\u0582\u0574 \u0565\u0576 \u0562\u0578\u056C\u0578\u0580 \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u0576\u0565\u0580\u0578\u0582\u0574:","\u0540\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F (\u0533\u0578\u0578\u0582\u056C\u0574\u0561\u0576). \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0576 \u0568\u0576\u056F\u0561\u056C\u0565\u056C\u0578\u0582, \u0570\u0561\u057D\u056F\u0561\u0576\u0561\u056C\u0578\u0582, \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0565\u056C\u0578\u0582 \u0587 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0565\u056C\u0578\u0582 \u056F\u0561\u0580\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576: \u0532\u0561\u0580\u0571\u0580 EQ-\u0576 \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0578\u0582\u0574 \u0567 \u0561\u057E\u0565\u056C\u056B \u056C\u0561\u057E \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580, \u0561\u057C\u0561\u057B\u0576\u0578\u0580\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0578\u0582\u0576:"],az:["Motivasiyan\u0131n \xFC\xE7 komponenti var: aktivl\u0259\u015Fm\u0259 (ba\u015Flan\u011F\u0131c), davaml\u0131l\u0131q (davam ed\u0259n c\u0259hd) v\u0259 intensivlik (n\u0259 q\u0259d\u0259r s\u0259y g\xF6st\u0259rdiyiniz).","S\xFCr\xFCc\xFC azaltma n\u0259z\u0259riyy\u0259si: fizioloji ehtiyaclar (acl\u0131q, susuzluq) homeostaz\u0131 b\u0259rpa etm\u0259k \xFC\xE7\xFCn davran\u0131\u015F\u0131 stimulla\u015Fd\u0131r\u0131r. Ancaq bu, mara\u011F\u0131 v\u0259 ya h\u0259y\u0259can axtar\u0131\u015F\u0131n\u0131 izah ed\u0259 bilmir.","Maslow-un ehtiyaclar iyerarxiyas\u0131 (a\u015Fa\u011F\u0131dan yuxar\u0131ya): Fizioloji \u2192 T\u0259hl\xFCk\u0259sizlik \u2192 Sevgi/M\u0259nsubiyy\u0259t \u2192 H\xF6rm\u0259t \u2192 \xD6z\xFCn\xFCrealla\u015Fd\u0131rma. Daha y\xFCks\u0259k ehtiyaclar\u0131n motivasiya ola bilm\u0259si \xFC\xE7\xFCn \u0259vv\u0259lc\u0259 a\u015Fa\u011F\u0131 s\u0259viyy\u0259li ehtiyaclar \xF6d\u0259nilm\u0259lidir.","Daxili motivasiya (bir \u015Feyi yaln\u0131z onun \xF6z\xFC \xFC\xE7\xFCn etm\u0259k) xarici motivasiyadan (m\xFCkafatlar/c\u0259zalar) daha davaml\u0131d\u0131r. H\u0259ddind\u0259n art\u0131q b\u0259ra\u0259t effekti: onsuz da z\xF6vq al\u0131nan bir f\u0259aliyy\u0259ti m\xFCkafatland\u0131rmaq daxili motivasiyan\u0131 azalda bil\u0259r.","Emosiya n\u0259z\u0259riyy\u0259l\u0259ri: James-Lange (b\u0259d\u0259n \u0259vv\u0259lc\u0259 reaksiya verir, sonra emosiya hiss edirik), Cannon-Bard (b\u0259d\u0259n reaksiyas\u0131 v\u0259 emosiya eyni vaxtda ba\u015F verir), Schachter-Singer / \u0130ki-faktorlu (fizioloji oyan\u0131\u015F + koqnitiv etiket = emosiya).","Paul Ekman 6 universal \xFCz ifad\u0259sini m\xFC\u0259yy\u0259n etmi\u015Fdir: xo\u015Fb\u0259xtlik, k\u0259d\u0259r, q\u0259z\u0259b, qorxu, t\u0259\u0259cc\xFCb v\u0259 ikrah. Bunlar b\xFCt\xFCn m\u0259d\u0259niyy\u0259tl\u0259rd\u0259 q\u0259bul edilir.","Emosional intellekt (Goleman): emosiyalar\u0131 d\u0259rk etm\u0259k, anlamaq, idar\u0259 etm\u0259k v\u0259 t\u0259sirli \u015F\u0259kild\u0259 istifad\u0259 etm\u0259k bacar\u0131\u011F\u0131. Y\xFCks\u0259k EQ daha yax\u015F\u0131 m\xFCnasib\u0259tl\u0259ri, liderliyi v\u0259 psixi sa\u011Flaml\u0131\u011F\u0131 proqnozla\u015Fd\u0131r\u0131r."]},funFact:{en:'The "misattribution of arousal" study showed that men who crossed a scary suspension bridge rated a female interviewer as more attractive than men who crossed a safe bridge \u2014 they mistook their fear-based arousal for romantic attraction!',ka:"\u201E\u10D0\u10D2\u10D6\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E0\u10D0\u10E1\u10EC\u10DD\u10E0\u10D8 \u10D0\u10E2\u10E0\u10D8\u10D1\u10E3\u10EA\u10D8\u10D8\u10E1\u201C \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10DB \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10EE\u10E8\u10D8\u10E0\u10D0\u10D3 \u10E3\u10E0\u10D4\u10D5\u10D4\u10DC \u10E8\u10D8\u10E8\u10E1 \u10D3\u10D0 \u10E0\u10DD\u10DB\u10D0\u10DC\u10E2\u10D8\u10D9\u10E3\u10DA \u10DB\u10D8\u10D6\u10D8\u10D3\u10E3\u10DA\u10DD\u10D1\u10D0\u10E1.",ru:"\u0418\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \xAB\u043E\u0448\u0438\u0431\u043E\u0447\u043D\u043E\u0439 \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438 \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F\xBB \u043F\u043E\u043A\u0430\u0437\u0430\u043B\u043E, \u0447\u0442\u043E \u043B\u044E\u0434\u0438 \u0447\u0430\u0441\u0442\u043E \u043F\u0443\u0442\u0430\u044E\u0442 \u0441\u0442\u0440\u0430\u0445 \u0441 \u0440\u043E\u043C\u0430\u043D\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435\u043C.",hy:"\xAB\u0533\u0580\u0563\u057C\u0574\u0561\u0576 \u057D\u056D\u0561\u056C \u057E\u0565\u0580\u0561\u0563\u0580\u0574\u0561\u0576\xBB \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u057E\u0565\u056C, \u0578\u0580 \u0574\u0561\u0580\u0564\u056B\u056F \u0570\u0561\u0573\u0561\u056D \u0577\u0583\u0578\u0569\u0578\u0582\u0574 \u0565\u0576 \u057E\u0561\u056D\u0568 \u057C\u0578\u0574\u0561\u0576\u057F\u056B\u056F \u0570\u0580\u0561\u057A\u0578\u0582\u0580\u0561\u0576\u0584\u056B \u0570\u0565\u057F:",az:'"Oyan\u0131\u015F\u0131n s\u0259hv aid edilm\u0259si" ara\u015Fd\u0131rmas\u0131 g\xF6st\u0259rdi ki, qorxulu k\xF6rp\xFCd\u0259n ke\xE7\u0259n ki\u015Fil\u0259r qorxular\u0131n\u0131 romantik cazib\u0259 il\u0259 qar\u0131\u015Fd\u0131r\u0131blar.'},realWorld:{en:`Companies like Google use Maslow's hierarchy to design workplaces: free food (physiological), job security (safety), team activities (belonging), recognition programs (esteem), and "20% time" for passion projects (self-actualization).`,ka:"\u10D8\u10E1\u10D4\u10D7\u10D8 \u10D9\u10DD\u10DB\u10DE\u10D0\u10DC\u10D8\u10D4\u10D1\u10D8, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 Google, \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u10DB\u10D0\u10E1\u10DA\u10DD\u10E3\u10E1 \u10D8\u10D4\u10E0\u10D0\u10E0\u10E5\u10D8\u10D0\u10E1 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10D0\u10D3\u10D2\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10E1\u10D0\u10DE\u10E0\u10DD\u10D4\u10E5\u10E2\u10D4\u10D1\u10DA\u10D0\u10D3.",ru:"\u0422\u0430\u043A\u0438\u0435 \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0438, \u043A\u0430\u043A Google, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u044E \u041C\u0430\u0441\u043B\u043E\u0443 \u0434\u043B\u044F \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0440\u0430\u0431\u043E\u0447\u0438\u0445 \u043C\u0435\u0441\u0442.",hy:"Google-\u056B \u0576\u0574\u0561\u0576 \u0568\u0576\u056F\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u0544\u0561\u057D\u056C\u0578\u0578\u0582\u056B \u0570\u056B\u0565\u0580\u0561\u0580\u056D\u056B\u0561\u0576 \u0561\u0577\u056D\u0561\u057F\u0561\u057F\u0565\u0572\u0565\u0580\u056B \u0576\u0561\u056D\u0561\u0563\u056E\u0574\u0561\u0576 \u0570\u0561\u0574\u0561\u0580:",az:"Google kimi \u015Firk\u0259tl\u0259r i\u015F yerl\u0259rini dizayn etm\u0259k \xFC\xE7\xFCn Maslow iyerarxiyas\u0131ndan istifad\u0259 edirl\u0259r."}},11:{title:{en:"Personality",ka:"\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0",ru:"\u041B\u0438\u0447\u043D\u043E\u0441\u0442\u044C",hy:"\u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576",az:"\u015E\u0259xsiyy\u0259t"},description:{en:"Theories of personality: from Freud to the Big Five.",ka:"\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8: \u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10D3\u10D0\u10DC \u10D3\u10D8\u10D3 \u10EE\u10E3\u10D7\u10D0\u10DB\u10D3\u10D4.",ru:"\u0422\u0435\u043E\u0440\u0438\u0438 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438: \u043E\u0442 \u0424\u0440\u0435\u0439\u0434\u0430 \u0434\u043E \xAB\u0411\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u043A\u0438\xBB.",hy:"\u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u0556\u0580\u0565\u0575\u0564\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u0544\u0565\u056E \u0570\u0576\u0563\u0575\u0561\u056F.",az:"\u015E\u0259xsiyy\u0259t n\u0259z\u0259riyy\u0259l\u0259ri: Freydd\u0259n B\xF6y\xFCk Be\u015Fliy\u0259 q\u0259d\u0259r."},keyTopics:{en:["Psychoanalytic Theory","Humanistic Theory","Trait Theory","Big Five","Personality Assessment"],ka:["\u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0","\u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0","\u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0","\u10D3\u10D8\u10D3\u10D8 \u10EE\u10E3\u10D7\u10D4\u10E3\u10DA\u10D8","\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D0"],ru:["\u041F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u043E\u0440\u0438\u044F","\u0413\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u043E\u0440\u0438\u044F","\u0422\u0435\u043E\u0440\u0438\u044F \u0447\u0435\u0440\u0442","\u0411\u043E\u043B\u044C\u0448\u0430\u044F \u043F\u044F\u0442\u0435\u0440\u043A\u0430","\u041E\u0446\u0435\u043D\u043A\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438"],hy:["\u0540\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0540\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0540\u0561\u057F\u056F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0544\u0565\u056E \u0570\u0576\u0563\u0575\u0561\u056F","\u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574"],az:["Psixoanalitik n\u0259z\u0259riyy\u0259","Humanist n\u0259z\u0259riyy\u0259","X\xFCsusiyy\u0259tl\u0259r n\u0259z\u0259riyy\u0259si","B\xF6y\xFCk be\u015Flik","\u015E\u0259xsiyy\u0259tin qiym\u0259tl\u0259ndirilm\u0259si"]},summary:{en:"Personality refers to the unique and relatively stable pattern of thoughts, feelings, and behaviors that characterizes each individual. This chapter surveys the major theoretical perspectives that attempt to explain why people differ from one another. Freud's psychoanalytic theory proposes that personality arises from unconscious conflicts between the id (primal desires), ego (rational mediator), and superego (moral conscience), with defense mechanisms like repression and projection protecting the ego from anxiety. Neo-Freudians such as Jung, Adler, and Horney modified Freud's ideas \u2014 Jung introducing the collective unconscious and archetypes, Adler emphasizing the inferiority complex. Humanistic psychologists like Rogers and Maslow shifted focus to personal growth, emphasizing unconditional positive regard and self-actualization. Trait theories describe personality along measurable dimensions, culminating in the Big Five model (OCEAN): Openness, Conscientiousness, Extraversion, Agreeableness, and Neuroticism \u2014 traits that are partially heritable, relatively stable after age 30, and predict important life outcomes including job performance and relationship satisfaction. The chapter also examines personality assessment tools, comparing self-report inventories like the MMPI with projective tests like the Rorschach inkblots.",ka:"\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0 \u10D2\u10E3\u10DA\u10D8\u10E1\u10EE\u10DB\u10DD\u10D1\u10E1 \u10D0\u10D6\u10E0\u10D4\u10D1\u10D8\u10E1, \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E3\u10DC\u10D8\u10D9\u10D0\u10DA\u10E3\u10E0 \u10D3\u10D0 \u10E8\u10D4\u10D3\u10D0\u10E0\u10D4\u10D1\u10D8\u10D7 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0 \u10DC\u10D8\u10DB\u10E3\u10E8\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10EE\u10D0\u10E1\u10D8\u10D0\u10D7\u10D4\u10D1\u10E1 \u10D7\u10D8\u10D7\u10DD\u10D4\u10E3\u10DA \u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10DB\u10D8\u10DB\u10DD\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D7\u10D4\u10DD\u10E0\u10D8\u10E3\u10DA \u10DE\u10D4\u10E0\u10E1\u10DE\u10D4\u10E5\u10E2\u10D8\u10D5\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10EA\u10D3\u10D8\u10DA\u10DD\u10D1\u10D4\u10DC \u10D0\u10EE\u10E1\u10DC\u10D0\u10DC, \u10D7\u10E3 \u10E0\u10D0\u10E2\u10DD\u10DB \u10D2\u10D0\u10DC\u10E1\u10EE\u10D5\u10D0\u10D5\u10D3\u10D4\u10D1\u10D8\u10D0\u10DC \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10D4\u10E0\u10D7\u10DB\u10D0\u10DC\u10D4\u10D7\u10D8\u10E1\u10D2\u10D0\u10DC. \u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 \u10D5\u10D0\u10E0\u10D0\u10E3\u10D3\u10DD\u10D1\u10E1, \u10E0\u10DD\u10DB \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D8\u10E5\u10DB\u10DC\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D8 \u10D9\u10DD\u10DC\u10E4\u10DA\u10D8\u10E5\u10E2\u10D4\u10D1\u10D8\u10D3\u10D0\u10DC \u10D8\u10D3\u10E1 (\u10DE\u10D8\u10E0\u10D5\u10D4\u10DA\u10E7\u10DD\u10E4\u10D8\u10DA\u10D8 \u10E1\u10E3\u10E0\u10D5\u10D8\u10DA\u10D4\u10D1\u10D8), \u10D4\u10D2\u10DD\u10E1\u10D0 (\u10E0\u10D0\u10EA\u10D8\u10DD\u10DC\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E8\u10E3\u10D0\u10DB\u10D0\u10D5\u10D0\u10DA\u10D8) \u10D3\u10D0 \u10E1\u10E3\u10DE\u10D4\u10E0\u10D4\u10D2\u10DD\u10E1 (\u10DB\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10D8\u10DC\u10D3\u10D8\u10E1\u10D8) \u10E8\u10DD\u10E0\u10D8\u10E1, \u10E1\u10D0\u10D3\u10D0\u10EA \u10D7\u10D0\u10D5\u10D3\u10D0\u10EA\u10D5\u10D8\u10E1 \u10DB\u10D4\u10E5\u10D0\u10DC\u10D8\u10D6\u10DB\u10D4\u10D1\u10D8, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10E0\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D0 \u10D3\u10D0 \u10DE\u10E0\u10DD\u10D4\u10E5\u10EA\u10D8\u10D0, \u10D8\u10EA\u10D0\u10D5\u10E1 \u10D4\u10D2\u10DD\u10E1 \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10E1\u10D2\u10D0\u10DC. \u10DC\u10D4\u10DD\u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10D0\u10DC\u10D4\u10DA\u10D4\u10D1\u10DB\u10D0, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D4\u10D1\u10D8\u10EA \u10D0\u10E0\u10D8\u10D0\u10DC \u10D8\u10E3\u10DC\u10D2\u10D8, \u10D0\u10D3\u10DA\u10D4\u10E0\u10D8 \u10D3\u10D0 \u10F0\u10DD\u10E0\u10DC\u10D8, \u10E8\u10D4\u10EA\u10D5\u10D0\u10DA\u10D4\u10E1 \u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10E1 \u10D8\u10D3\u10D4\u10D4\u10D1\u10D8 - \u10D8\u10E3\u10DC\u10D2\u10DB\u10D0 \u10E8\u10D4\u10DB\u10DD\u10D8\u10E2\u10D0\u10DC\u10D0 \u10D9\u10DD\u10DA\u10D4\u10E5\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D0\u10E0\u10E5\u10D4\u10E2\u10D8\u10DE\u10D4\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DC\u10EA\u10D4\u10E4\u10EA\u10D8\u10D0, \u10D0\u10D3\u10DA\u10D4\u10E0\u10DB\u10D0 \u10EE\u10D0\u10D6\u10D8 \u10D2\u10D0\u10E3\u10E1\u10D5\u10D0 \u10D0\u10E0\u10D0\u10E1\u10E0\u10E3\u10DA\u10E4\u10D0\u10E1\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DB\u10DE\u10DA\u10D4\u10E5\u10E1\u10E1. \u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10DB\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D4\u10D1\u10DB\u10D0, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D4\u10D1\u10D8\u10EA \u10D8\u10E7\u10D5\u10DC\u10D4\u10DC \u10E0\u10DD\u10EF\u10D4\u10E0\u10E1\u10D8 \u10D3\u10D0 \u10DB\u10D0\u10E1\u10DA\u10DD\u10E3, \u10E7\u10E3\u10E0\u10D0\u10D3\u10E6\u10D4\u10D1\u10D0 \u10D2\u10D0\u10D3\u10D0\u10D8\u10E2\u10D0\u10DC\u10D4\u10E1 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10E3\u10DA \u10D6\u10E0\u10D3\u10D0\u10D6\u10D4, \u10EE\u10D0\u10D6\u10E1 \u10E3\u10E1\u10D5\u10D0\u10DB\u10D3\u10DC\u10D4\u10DC \u10E0\u10D0 \u10E3\u10DE\u10D8\u10E0\u10DD\u10D1\u10DD \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D7\u10D5\u10D8\u10D7\u10D0\u10E5\u10E2\u10E3\u10D0\u10DA\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0\u10E1. \u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D0\u10D7\u10D0 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8 \u10D0\u10E6\u10EC\u10D4\u10E0\u10D4\u10DC \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1 \u10D2\u10D0\u10D6\u10DD\u10DB\u10D5\u10D0\u10D3\u10D8 \u10D2\u10D0\u10DC\u10D6\u10DD\u10DB\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10E1\u10EC\u10D5\u10E0\u10D8\u10D5, \u10E0\u10D0\u10EA \u10D9\u10E3\u10DA\u10DB\u10D8\u10DC\u10D0\u10EA\u10D8\u10D0\u10E1 \u10D0\u10E6\u10EC\u10D4\u10D5\u10E1 \u10D3\u10D8\u10D3\u10D8 \u10EE\u10E3\u10D7\u10D4\u10E3\u10DA\u10D8\u10E1 \u121E\u10D3\u10D4\u10DA\u10E8\u10D8 (OCEAN): \u10E6\u10D8\u10D0\u10DD\u10D1\u10D0, \u10D9\u10D4\u10D7\u10D8\u10DA\u10E1\u10D8\u10DC\u10D3\u10D8\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0, \u10D4\u10E5\u10E1\u10E2\u10E0\u10D0\u10D5\u10D4\u10E0\u10E1\u10D8\u10D0, \u10D7\u10D0\u10DC\u10EE\u10DB\u10DD\u10D1\u10D0 \u10D3\u10D0 \u10DC\u10D4\u10D5\u10E0\u10DD\u10E2\u10D8\u10D6\u10DB\u10D8 - \u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D4\u10D1\u10D8, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10DC\u10D0\u10EC\u10D8\u10DA\u10DD\u10D1\u10E0\u10D8\u10D5 \u10DB\u10D4\u10DB\u10D9\u10D5\u10D8\u10D3\u10E0\u10D4\u10DD\u10D1\u10D8\u10D7\u10D8\u10D0, \u10E8\u10D4\u10D3\u10D0\u10E0\u10D4\u10D1\u10D8\u10D7 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10D8\u10D0 30 \u10EC\u10DA\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2 \u10D3\u10D0 \u10DE\u10E0\u10DD\u10D2\u10DC\u10DD\u10D6\u10D8\u10E0\u10D4\u10D1\u10D4\u10DC \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10E1, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD\u10E1 \u10E8\u10D4\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D8\u10D7 \u10D9\u10DB\u10D0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D8\u10DC\u10E1\u10E2\u10E0\u10E3\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10E1, \u10D0\u10D3\u10D0\u10E0\u10D4\u10D1\u10E1 \u10D7\u10D5\u10D8\u10D7\u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D8\u10DC\u10D5\u10D4\u10DC\u10E2\u10D0\u10E0\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0\u10E1 (\u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 MMPI) \u10DE\u10E0\u10DD\u10D4\u10E5\u10EA\u10D8\u10E3\u10DA \u10E2\u10D4\u10E1\u10E2\u10D4\u10D1\u10E1 (\u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10E0\u10DD\u10E0\u10E8\u10D0\u10EE\u10D8\u10E1 \u10DA\u10D0\u10E5\u10D4\u10D1\u10D8).",ru:"\u041B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u2014 \u044D\u0442\u043E \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0439 \u0438 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u043C\u044B\u0441\u043B\u0435\u0439, \u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043D\u044B\u0439 \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u044B, \u043F\u044B\u0442\u0430\u044E\u0449\u0438\u0435\u0441\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u043B\u044E\u0434\u0438 \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430. \u041F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u043E\u0440\u0438\u044F \u0424\u0440\u0435\u0439\u0434\u0430 \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442, \u0447\u0442\u043E \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438\u0437 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u043E\u0432 \u043C\u0435\u0436\u0434\u0443 \u0418\u0434 (\u043F\u0435\u0440\u0432\u043E\u0431\u044B\u0442\u043D\u044B\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F), \u042D\u0433\u043E (\u0440\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u043F\u043E\u0441\u0440\u0435\u0434\u043D\u0438\u043A) \u0438 \u0421\u0443\u043F\u0435\u0440-\u042D\u0433\u043E (\u043C\u043E\u0440\u0430\u043B\u044C\u043D\u0430\u044F \u0441\u043E\u0432\u0435\u0441\u0442\u044C), \u0430 \u0437\u0430\u0449\u0438\u0442\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C\u044B, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0432\u044B\u0442\u0435\u0441\u043D\u0435\u043D\u0438\u0435 \u0438 \u043F\u0440\u043E\u0435\u043A\u0446\u0438\u044F, \u0437\u0430\u0449\u0438\u0449\u0430\u044E\u0442 \u042D\u0433\u043E \u043E\u0442 \u0442\u0440\u0435\u0432\u043E\u0433\u0438. \u041D\u0435\u043E\u0444\u0440\u0435\u0439\u0434\u0438\u0441\u0442\u044B, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u042E\u043D\u0433, \u0410\u0434\u043B\u0435\u0440 \u0438 \u0425\u043E\u0440\u043D\u0438, \u043C\u043E\u0434\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043B\u0438 \u0438\u0434\u0435\u0438 \u0424\u0440\u0435\u0439\u0434\u0430: \u042E\u043D\u0433 \u0432\u0432\u0435\u043B \u043F\u043E\u043D\u044F\u0442\u0438\u0435 \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0438 \u0430\u0440\u0445\u0435\u0442\u0438\u043F\u043E\u0432, \u0410\u0434\u043B\u0435\u0440 \u0441\u0434\u0435\u043B\u0430\u043B \u0430\u043A\u0446\u0435\u043D\u0442 \u043D\u0430 \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0441\u0435 \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u0413\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A \u0420\u043E\u0434\u0436\u0435\u0440\u0441 \u0438 \u041C\u0430\u0441\u043B\u043E\u0443, \u0441\u043C\u0435\u0441\u0442\u0438\u043B\u0438 \u0444\u043E\u043A\u0443\u0441 \u043D\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u043D\u044B\u0439 \u0440\u043E\u0441\u0442, \u043F\u043E\u0434\u0447\u0435\u0440\u043A\u0438\u0432\u0430\u044F \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E\u0435 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u0438 \u0441\u0430\u043C\u043E\u0430\u043A\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E. \u0422\u0435\u043E\u0440\u0438\u0438 \u0447\u0435\u0440\u0442 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0432 \u0438\u0437\u043C\u0435\u0440\u0438\u043C\u044B\u0445 \u0438\u0437\u043C\u0435\u0440\u0435\u043D\u0438\u044F\u0445, \u043A\u0443\u043B\u044C\u043C\u0438\u043D\u0430\u0446\u0438\u0435\u0439 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043C\u043E\u0434\u0435\u043B\u044C \u0411\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u043A\u0438 (OCEAN): \u041E\u0442\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u044C (Openness), \u0414\u043E\u0431\u0440\u043E\u0441\u043E\u0432\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u044C (Conscientiousness), \u042D\u043A\u0441\u0442\u0440\u0430\u0432\u0435\u0440\u0441\u0438\u044F (Extraversion), \u0414\u043E\u0431\u0440\u043E\u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C (Agreeableness) \u0438 \u041D\u0435\u0439\u0440\u043E\u0442\u0438\u0437\u043C (Neuroticism) \u2014 \u0447\u0435\u0440\u0442\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E \u043F\u0435\u0440\u0435\u0434\u0430\u044E\u0442\u0441\u044F \u043F\u043E \u043D\u0430\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0443, \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B \u043F\u043E\u0441\u043B\u0435 30 \u043B\u0435\u0442 \u0438 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u0432\u0430\u0436\u043D\u044B\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0442\u0440\u0443\u0434\u0430 \u0438 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F\u043C\u0438. \u0412 \u0433\u043B\u0430\u0432\u0435 \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u043E\u0446\u0435\u043D\u043A\u0438 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438, \u0441\u0440\u0430\u0432\u043D\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u043F\u0440\u043E\u0441\u043D\u0438\u043A\u0438 \u0441\u0430\u043C\u043E\u043E\u0442\u0447\u0435\u0442\u0430, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A MMPI, \u0441 \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u043C\u0438 \u0442\u0435\u0441\u0442\u0430\u043C\u0438, \u0442\u0430\u043A\u0438\u043C\u0438 \u043A\u0430\u043A \u043F\u044F\u0442\u043D\u0430 \u0420\u043E\u0440\u0448\u0430\u0445\u0430.",hy:"\u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0574 \u0567 \u0574\u057F\u0584\u0565\u0580\u056B, \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0587 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0565\u0566\u0561\u056F\u056B \u0587 \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0561\u0562\u0561\u0580 \u056F\u0561\u0575\u0578\u0582\u0576 \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0561\u0576\u0568, \u0578\u0580\u0568 \u0562\u0576\u0578\u0582\u0569\u0561\u0563\u0580\u0578\u0582\u0574 \u0567 \u0575\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580 \u0561\u0576\u0570\u0561\u057F\u056B: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0561\u056F\u0561\u0576 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0583\u0578\u0580\u0571\u0578\u0582\u0574 \u0565\u0576 \u0562\u0561\u0581\u0561\u057F\u0580\u0565\u056C, \u0569\u0565 \u056B\u0576\u0579\u0578\u0582 \u0565\u0576 \u0574\u0561\u0580\u0564\u056B\u056F \u057F\u0561\u0580\u0562\u0565\u0580\u057E\u0578\u0582\u0574 \u0574\u056B\u0574\u0575\u0561\u0576\u0581\u056B\u0581: \u0556\u0580\u0565\u0575\u0564\u056B \u0570\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0565\u0576\u0569\u0561\u0564\u0580\u0578\u0582\u0574 \u0567, \u0578\u0580 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0561\u057C\u0561\u057B\u0561\u0576\u0578\u0582\u0574 \u0567 Id-\u056B (\u0576\u0561\u056D\u0576\u0561\u0564\u0561\u0580\u0575\u0561\u0576 \u0581\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580), Ego-\u056B (\u057C\u0561\u0581\u056B\u0578\u0576\u0561\u056C \u0574\u056B\u057B\u0576\u0578\u0580\u0564) \u0587 Superego-\u056B (\u0562\u0561\u0580\u0578\u0575\u0561\u056F\u0561\u0576 \u056D\u056B\u0572\u0573) \u0574\u056B\u057B\u0587 \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u056B\u0581 \u0570\u0561\u056F\u0561\u0574\u0561\u0580\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B\u0581, \u0578\u0580\u057F\u0565\u0572 \u057A\u0561\u0577\u057F\u057A\u0561\u0576\u0561\u056F\u0561\u0576 \u0574\u0565\u056D\u0561\u0576\u056B\u0566\u0574\u0576\u0565\u0580\u0568, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u0573\u0576\u0577\u0578\u0582\u0574\u0568 \u0587 \u057A\u0580\u0578\u0575\u0565\u056F\u0581\u056B\u0561\u0576, \u057A\u0561\u0577\u057F\u057A\u0561\u0576\u0578\u0582\u0574 \u0565\u0576 \u0567\u0563\u0578\u0576 \u0561\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u056B\u0581: \u0546\u0565\u0578\u0586\u0580\u0565\u0575\u0564\u056B\u057D\u057F\u0576\u0565\u0580\u0568, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u0545\u0578\u0582\u0576\u0563\u0568, \u0531\u0564\u056C\u0565\u0580\u0568 \u0587 \u0540\u0578\u0580\u0576\u056B\u0576, \u0583\u0578\u0583\u0578\u056D\u0565\u0581\u056B\u0576 \u0556\u0580\u0565\u0575\u0564\u056B \u0563\u0561\u0572\u0561\u0583\u0561\u0580\u0576\u0565\u0580\u0568. \u0545\u0578\u0582\u0576\u0563\u0568 \u0576\u0565\u0580\u0574\u0578\u0582\u056E\u0565\u0581 \u056F\u0578\u056C\u0565\u056F\u057F\u056B\u057E \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576\u056B \u0587 \u0561\u0580\u056D\u0565\u057F\u056B\u057A\u0565\u0580 \u0570\u0561\u057D\u056F\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0531\u0564\u056C\u0565\u0580\u0576 \u0568\u0576\u0564\u0563\u056E\u0565\u0581 \u0569\u0565\u0580\u0561\u0580\u056A\u0565\u0584\u0578\u0582\u0569\u0575\u0561\u0576 \u0562\u0561\u0580\u0564\u0578\u0582\u0575\u0569\u0568: \u0540\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0576\u0565\u0580\u0568, \u056B\u0576\u0579\u057A\u056B\u057D\u056B\u0584 \u0565\u0576 \u054C\u0578\u057B\u0565\u0580\u057D\u0568 \u0587 \u0544\u0561\u057D\u056C\u0578\u0578\u0582\u0576, \u0578\u0582\u0577\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u057F\u0565\u0572\u0561\u0583\u0578\u056D\u0565\u0581\u056B\u0576 \u0561\u0576\u0571\u0576\u0561\u056F\u0561\u0576 \u0561\u0573\u056B \u057E\u0580\u0561\u055D \u0577\u0565\u0577\u057F\u0565\u056C\u0578\u057E \u0561\u0576\u057E\u0565\u0580\u0561\u057A\u0561\u0570 \u0564\u0580\u0561\u056F\u0561\u0576 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584\u0568 \u0587 \u056B\u0576\u0584\u0576\u0561\u056B\u0580\u0561\u0581\u0578\u0582\u0574\u0568: \u0540\u0561\u057F\u056F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0578\u0582\u0574 \u0565\u0576 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0579\u0561\u0583\u0565\u056C\u056B \u0570\u0561\u0580\u0569\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0578\u057E, \u0578\u0580\u0578\u0576\u0584 \u0563\u0561\u0563\u0561\u0569\u0576\u0561\u056F\u0565\u057F\u056B\u0576 \u0565\u0576 \u0570\u0561\u057D\u0576\u0578\u0582\u0574 \u0544\u0565\u056E \u0570\u0576\u0563\u0575\u0561\u056F\u056B (OCEAN) \u0574\u0578\u0564\u0565\u056C\u0578\u0582\u0574\u055D \u0532\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0532\u0561\u0580\u0565\u056D\u0572\u0573\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0537\u0584\u057D\u057F\u0580\u0561\u057E\u0565\u0580\u057D\u056B\u0561, \u0540\u0561\u0574\u0561\u0571\u0561\u0575\u0576\u0565\u056C\u056B\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0546\u0587\u0580\u0578\u057F\u056B\u056F\u056B\u0566\u0574 \u2014 \u0563\u056E\u0565\u0580, \u0578\u0580\u0578\u0576\u0584 \u0574\u0561\u057D\u0561\u0574\u0562 \u056A\u0561\u057C\u0561\u0576\u0563\u0561\u056F\u0561\u0576 \u0565\u0576, \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0561\u0562\u0561\u0580 \u056F\u0561\u0575\u0578\u0582\u0576 30 \u057F\u0561\u0580\u0565\u056F\u0561\u0576\u056B\u0581 \u0570\u0565\u057F\u0578 \u0587 \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0578\u0582\u0574 \u0565\u0576 \u056F\u0575\u0561\u0576\u0584\u056B \u056F\u0561\u0580\u0587\u0578\u0580 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0576\u0565\u0580, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u056F\u0561\u057F\u0561\u0580\u0578\u0572\u0561\u056F\u0561\u0576\u0568 \u0587 \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0562\u0561\u057E\u0561\u0580\u0561\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0533\u056C\u0578\u0582\u056D\u0568 \u0576\u0561\u0587 \u0584\u0576\u0576\u0561\u0580\u056F\u0578\u0582\u0574 \u0567 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0563\u0576\u0561\u0570\u0561\u057F\u0574\u0561\u0576 \u0563\u0578\u0580\u056E\u056B\u0584\u0576\u0565\u0580\u055D \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0565\u056C\u0578\u057E \u056B\u0576\u0584\u0576\u0561\u0566\u0565\u056F\u0578\u0582\u0581\u0574\u0561\u0576 \u0570\u0561\u0580\u0581\u0561\u0577\u0561\u0580\u0565\u0580\u0568 \u056D\u0565\u056C\u0584\u0561\u0563\u0580\u057E\u0561\u056E\u0584\u0578\u057E (\u0585\u0580\u056B\u0576\u0561\u056F\u055D MMPI) \u057A\u0580\u0578\u0575\u0565\u056F\u057F\u056B\u057E \u0569\u0565\u057D\u057F\u0565\u0580\u056B \u0570\u0565\u057F (\u0585\u0580\u056B\u0576\u0561\u056F\u055D \u054C\u0578\u0580\u0577\u0561\u056D\u056B \u0562\u056E\u0565\u0580):",az:"\u015E\u0259xsiyy\u0259t h\u0259r bir f\u0259rdi xarakteriz\u0259 ed\u0259n d\xFC\u015F\xFCnc\u0259, hiss v\u0259 davran\u0131\u015Flar\u0131n unikal v\u0259 nisb\u0259t\u0259n sabit n\xFCmun\u0259sin\u0259 aiddir. Bu f\u0259sil insanlar\u0131n bir-birind\u0259n niy\u0259 f\u0259rql\u0259ndiyini izah etm\u0259y\u0259 \xE7al\u0131\u015Fan \u0259sas n\u0259z\u0259ri bax\u0131\u015Flar\u0131 n\u0259z\u0259rd\u0259n ke\xE7irir. Freydin psixoanalitik n\u0259z\u0259riyy\u0259si, \u015F\u0259xsiyy\u0259tin id (ilkin ist\u0259kl\u0259r), eqo (rasional vasit\u0259\xE7i) v\u0259 supereqo (m\u0259n\u0259vi vicdan) aras\u0131ndak\u0131 \u015F\xFCursuz qar\u015F\u0131durmalardan yarand\u0131\u011F\u0131n\u0131 iddia edir, basd\u0131r\u0131lma v\u0259 proyeksiya kimi m\xFCdafi\u0259 mexanizml\u0259ri eqonu narahatl\u0131qdan qoruyur. Yunq, Adler v\u0259 Horney kimi Neo-Freyd\xE7il\u0259r Freydin ideyalar\u0131n\u0131 d\u0259yi\u015Fdirdil\u0259r \u2014 Yunq kollektiv \u015F\xFCuralt\u0131 v\u0259 arxetipl\u0259ri t\u0259qdim etdi, Adler a\u015Fa\u011F\u0131l\u0131q kompleksini vur\u011Fulad\u0131. Rogers v\u0259 Maslow kimi humanist psixoloqlar is\u0259 diqq\u0259ti qeyd-\u015F\u0259rtsiz m\xFCsb\u0259t m\xFCnasib\u0259ti v\u0259 \xF6z\xFCn\xFCrealla\u015Fd\u0131rman\u0131 vur\u011Fulayaraq \u015F\u0259xsi inki\u015Fafa y\xF6n\u0259ltdil\u0259r. X\xFCsusiyy\u0259t n\u0259z\u0259riyy\u0259l\u0259ri \u015F\u0259xsiyy\u0259ti \xF6l\xE7\xFCl\u0259 bil\u0259n \xF6l\xE7\xFCl\u0259rl\u0259 t\u0259svir edir v\u0259 B\xF6y\xFCk Be\u015Flik modeli (OCEAN) il\u0259 zirv\u0259y\u0259 \xE7at\u0131r: A\xE7\u0131ql\u0131q, Vicdanl\u0131l\u0131q, Ekstraversiya, Uy\u011Funluq v\u0259 Nevrotizm \u2014 qism\u0259n irsi olan, 30 ya\u015F\u0131ndan sonra nisb\u0259t\u0259n sabit olan v\u0259 i\u015F performans\u0131 v\u0259 m\xFCnasib\u0259t m\u0259mnunlu\u011Fu daxil olmaqla h\u0259yat\u0131n vacib n\u0259tic\u0259l\u0259rini proqnozla\u015Fd\u0131ran \u0259lam\u0259tl\u0259r. F\u0259sil h\u0259m\xE7inin x\u0259st\u0259xana \u015F\u0259xsiyy\u0259tinin qiym\u0259tl\u0259ndirilm\u0259si al\u0259tl\u0259rini ara\u015Fd\u0131r\u0131r, MMPI kimi \xF6z\xFCn\xFC hesabat inventarlar\u0131n\u0131 Rorschach l\u0259k\u0259l\u0259ri kimi proyektiv testl\u0259rl\u0259 m\xFCqayis\u0259 edir."},keyPoints:{en:["Freud's psychoanalytic theory: Personality is shaped by unconscious conflicts between the Id (primal desires), Ego (rational mediator), and Superego (moral conscience). Defense mechanisms (repression, projection, denial) protect the ego.","Freud's psychosexual stages: Oral, Anal, Phallic (Oedipus complex), Latency, Genital. Fixation at any stage can affect adult personality.","Neo-Freudians (Adler, Jung, Horney) kept the unconscious but de-emphasized sexuality. Jung introduced collective unconscious and archetypes. Adler focused on inferiority complex.","Humanistic approaches: Rogers emphasized unconditional positive regard and self-concept. Maslow focused on self-actualization \u2014 becoming the best version of yourself.","Trait theories describe personality using stable dimensions. The Big Five (OCEAN): Openness (curiosity), Conscientiousness (organization), Extraversion (sociability), Agreeableness (cooperativeness), Neuroticism (emotional instability).","The Big Five are partially heritable (~40\u201360%), relatively stable after age 30, and predict job performance, relationship satisfaction, and health outcomes.","Personality assessment: Self-report inventories (MMPI, NEO-PI-R) have good reliability but are subject to social desirability bias. Projective tests (Rorschach, TAT) have weaker validity."],ka:["\u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0: \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0 \u10E7\u10D0\u10DA\u10D8\u10D1\u10D3\u10D4\u10D1\u10D0 \u10D8\u10D3\u10E1 (\u10DE\u10D8\u10E0\u10D5\u10D4\u10DA\u10E7\u10DD\u10E4\u10D8\u10DA\u10D8 \u10E1\u10E3\u10E0\u10D5\u10D8\u10DA\u10D4\u10D1\u10D8), \u10D4\u10D2\u10DD\u10E1\u10D0 (\u10E0\u10D0\u10EA\u10D8\u10DD\u10DC\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E8\u10E3\u10D0\u10DB\u10D0\u10D5\u10D0\u10DA\u10D8) \u10D3\u10D0 \u10E1\u10E3\u10DE\u10D4\u10E0\u10D4\u10D2\u10DD\u10E1 (\u10DB\u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10D8\u10DC\u10D3\u10D8\u10E1\u10D8) \u10E8\u10DD\u10E0\u10D8\u10E1 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D8 \u10D9\u10DD\u10DC\u10E4\u10DA\u10D8\u10E5\u10E2\u10D4\u10D1\u10D8\u10D7. \u10D7\u10D0\u10D5\u10D3\u10D0\u10EA\u10D5\u10D8\u10E1 \u10DB\u10D4\u10E5\u10D0\u10DC\u10D8\u10D6\u10DB\u10D4\u10D1\u10D8 (\u10E0\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D0, \u10DE\u10E0\u10DD\u10D4\u10E5\u10EA\u10D8\u10D0, \u10E3\u10D0\u10E0\u10E7\u10DD\u10E4\u10D0) \u10D8\u10EA\u10D0\u10D5\u10E1 \u10D4\u10D2\u10DD\u10E1.","\u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10E1\u10D4\u10E5\u10E1\u10E3\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10D8: \u10DD\u10E0\u10D0\u10DA\u10E3\u10E0\u10D8, \u10D0\u10DC\u10D0\u10DA\u10E3\u10E0\u10D8, \u10E4\u10D0\u10DA\u10E3\u10E0\u10D8 (\u10DD\u10D8\u10D3\u10D8\u10DE\u10DD\u10E1\u10D8\u10E1 \u10D9\u10DD\u10DB\u10DE\u10DA\u10D4\u10E5\u10E1\u10D8), \u10DA\u10D0\u10E2\u10D4\u10DC\u10E2\u10E3\u10E0\u10D8, \u10D2\u10D4\u10DC\u10D8\u10E2\u10D0\u10DA\u10E3\u10E0\u10D8. \u10DC\u10D4\u10D1\u10D8\u10E1\u10DB\u10D8\u10D4\u10E0 \u10D4\u10E2\u10D0\u10DE\u10D6\u10D4 \u10E4\u10D8\u10E5\u10E1\u10D0\u10EA\u10D8\u10D0\u10DB \u10E8\u10D4\u10D8\u10EB\u10DA\u10D4\u10D1\u10D0 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0 \u10DB\u10DD\u10D0\u10EE\u10D3\u10D8\u10DC\u10DD\u10E1 \u10D6\u10E0\u10D3\u10D0\u10E1\u10E0\u10E3\u10DA\u10D7\u10D0 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10D6\u10D4.","\u10DC\u10D4\u10DD\u10E4\u10E0\u10DD\u10D8\u10D3\u10D8\u10D0\u10DC\u10D4\u10DA\u10D4\u10D1\u10DB\u10D0 (\u10D0\u10D3\u10DA\u10D4\u10E0\u10D8, \u10D8\u10E3\u10DC\u10D2\u10D8, \u10F0\u10DD\u10E0\u10DC\u10D8) \u10E8\u10D4\u10D8\u10DC\u10D0\u10E0\u10E9\u10E3\u10DC\u10D4\u10E1 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D8, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10E8\u10D4\u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10E1 \u10E1\u10D4\u10E5\u10E1\u10E3\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D1\u10D0. \u10D8\u10E3\u10DC\u10D2\u10DB\u10D0 \u10E8\u10D4\u10DB\u10DD\u10D8\u10E2\u10D0\u10DC\u10D0 \u10D9\u10DD\u10DA\u10D4\u10E5\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0\u10D8 \u10D3\u10D0 \u10D0\u10E0\u10E5\u10D4\u10E2\u10D8\u10DE\u10D4\u10D1\u10D8. \u10D0\u10D3\u10DA\u10D4\u10E0\u10DB\u10D0 \u10E7\u10E3\u10E0\u10D0\u10D3\u10E6\u10D4\u10D1\u10D0 \u10D2\u10D0\u10D0\u10DB\u10D0\u10EE\u10D5\u10D8\u10DA\u10D0 \u10D0\u10E0\u10D0\u10E1\u10E0\u10E3\u10DA\u10E4\u10D0\u10E1\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DB\u10DE\u10DA\u10D4\u10E5\u10E1\u10D6\u10D4.","\u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D4\u10D1\u10D8: \u10E0\u10DD\u10EF\u10D4\u10E0\u10E1\u10D8 \u10EE\u10D0\u10D6\u10E1 \u10E3\u10E1\u10D5\u10D0\u10DB\u10D3\u10D0 \u10E3\u10DE\u10D8\u10E0\u10DD\u10D1\u10DD \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D7\u10D5\u10D8\u10D7\u10D9\u10DD\u10DC\u10EA\u10D4\u10E4\u10EA\u10D8\u10D0\u10E1. \u10DB\u10D0\u10E1\u10DA\u10DD\u10E3 \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10E7\u10DD \u10D7\u10D5\u10D8\u10D7\u10D0\u10E5\u10E2\u10E3\u10D0\u10DA\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0\u10D6\u10D4 - \u10D2\u10D0\u10EE\u10D3\u10D4\u10D7 \u10D7\u10E5\u10D5\u10D4\u10DC\u10D8 \u10E1\u10D0\u10E3\u10D9\u10D4\u10D7\u10D4\u10E1\u10DD \u10D5\u10D4\u10E0\u10E1\u10D8\u10D0.","\u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D0\u10D7\u10D0 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D4\u10D1\u10D8 \u10D0\u10E6\u10EC\u10D4\u10E0\u10D4\u10DC \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10D8 \u10D2\u10D0\u10DC\u10D6\u10DD\u10DB\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10D7. \u10D3\u10D8\u10D3\u10D8 \u10EE\u10E3\u10D7\u10D4\u10E3\u10DA\u10D8 (OCEAN): \u10E6\u10D8\u10D0\u10DD\u10D1\u10D0 (\u10EA\u10DC\u10DD\u10D1\u10D8\u10E1\u10DB\u10DD\u10E7\u10D5\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0), \u10D9\u10D4\u10D7\u10D8\u10DA\u10E1\u10D8\u10DC\u10D3\u10D8\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 (\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10DD\u10D1\u10D0), \u10D4\u10E5\u10E1\u10E2\u10E0\u10D0\u10D5\u10D4\u10E0\u10E1\u10D8\u10D0 (\u10D9\u10DD\u10DB\u10E3\u10DC\u10D8\u10D9\u10D0\u10D1\u10D4\u10DA\u10E3\u10E0\u10DD\u10D1\u10D0), \u10D7\u10D0\u10DC\u10EE\u10DB\u10DD\u10D1\u10D0 (\u10D7\u10D0\u10DC\u10D0\u10DB\u10E8\u10E0\u10DD\u10DB\u10DA\u10DD\u10D1\u10D0), \u10DC\u10D4\u10D5\u10E0\u10DD\u10E2\u10D8\u10D6\u10DB\u10D8 (\u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D0\u10E0\u10D0\u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10DD\u10D1\u10D0).","\u10D3\u10D8\u10D3\u10D8 \u10EE\u10E3\u10D7\u10D4\u10E3\u10DA\u10D8 \u10DC\u10D0\u10EC\u10D8\u10DA\u10DD\u10D1\u10E0\u10D8\u10D5 \u10DB\u10D4\u10DB\u10D9\u10D5\u10D8\u10D3\u10E0\u10D4\u10DD\u10D1\u10D8\u10D7\u10D8\u10D0 (~40-60%), \u10E8\u10D4\u10D3\u10D0\u10E0\u10D4\u10D1\u10D8\u10D7 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10D8\u10D0 30 \u10EC\u10DA\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2 \u10D3\u10D0 \u10DE\u10E0\u10DD\u10D2\u10DC\u10DD\u10D6\u10D8\u10E0\u10D4\u10D1\u10E1 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD\u10E1 \u10E8\u10D4\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D0\u10E1, \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D8\u10D7 \u10D9\u10DB\u10D0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10E1.","\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D0: \u10D7\u10D5\u10D8\u10D7\u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D8\u10E1 \u10D8\u10DC\u10D5\u10D4\u10DC\u10E2\u10D0\u10E0\u10E1 (MMPI, NEO-PI-R) \u10D0\u10E5\u10D5\u10E1 \u10D9\u10D0\u10E0\u10D2\u10D8 \u10E1\u10D0\u10D8\u10DB\u10D4\u10D3\u10DD\u10DD\u10D1\u10D0, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB \u10D4\u10E5\u10D5\u10D4\u10DB\u10D3\u10D4\u10D1\u10D0\u10E0\u10D4\u10D1\u10D0 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10D0\u10E1\u10E3\u10E0\u10D5\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D9\u10D4\u10E0\u10EB\u10DD\u10D4\u10D1\u10D0\u10E1. \u10DE\u10E0\u10DD\u10D4\u10E5\u10EA\u10D8\u10E3\u10DA \u10E2\u10D4\u10E1\u10E2\u10D4\u10D1\u10E1 (\u10E0\u10DD\u10E0\u10E8\u10D0\u10EE\u10D8, TAT) \u10D0\u10E5\u10D5\u10D7 \u10E3\u10E4\u10E0\u10DD \u10E1\u10E3\u10E1\u10E2\u10D8 \u10D5\u10D0\u10DA\u10D8\u10D3\u10DD\u10D1\u10D0."],ru:["\u041F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u043E\u0440\u0438\u044F \u0424\u0440\u0435\u0439\u0434\u0430: \u041B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u043E\u0432 \u043C\u0435\u0436\u0434\u0443 \u0418\u0434 (\u043F\u0435\u0440\u0432\u043E\u0431\u044B\u0442\u043D\u044B\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F), \u042D\u0433\u043E (\u0440\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u043F\u043E\u0441\u0440\u0435\u0434\u043D\u0438\u043A) \u0438 \u0421\u0443\u043F\u0435\u0440-\u042D\u0433\u043E (\u043C\u043E\u0440\u0430\u043B\u044C\u043D\u0430\u044F \u0441\u043E\u0432\u0435\u0441\u0442\u044C). \u0417\u0430\u0449\u0438\u0442\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C\u044B (\u0432\u044B\u0442\u0435\u0441\u043D\u0435\u043D\u0438\u0435, \u043F\u0440\u043E\u0435\u043A\u0446\u0438\u044F, \u043E\u0442\u0440\u0438\u0446\u0430\u043D\u0438\u0435) \u0437\u0430\u0449\u0438\u0449\u0430\u044E\u0442 \u042D\u0433\u043E.","\u041F\u0441\u0438\u0445\u043E\u0441\u0435\u043A\u0441\u0443\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0442\u0430\u0434\u0438\u0438 \u0424\u0440\u0435\u0439\u0434\u0430: \u043E\u0440\u0430\u043B\u044C\u043D\u0430\u044F, \u0430\u043D\u0430\u043B\u044C\u043D\u0430\u044F, \u0444\u0430\u043B\u043B\u0438\u0447\u0435\u0441\u043A\u0430\u044F (\u044D\u0434\u0438\u043F\u043E\u0432 \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0441), \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u0430\u044F, \u0433\u0435\u043D\u0438\u0442\u0430\u043B\u044C\u043D\u0430\u044F. \u0424\u0438\u043A\u0441\u0430\u0446\u0438\u044F \u043D\u0430 \u043B\u044E\u0431\u043E\u0439 \u0441\u0442\u0430\u0434\u0438\u0438 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u0432\u043B\u0438\u044F\u0442\u044C \u043D\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0432\u0437\u0440\u043E\u0441\u043B\u043E\u0433\u043E.","\u041D\u0435\u043E\u0444\u0440\u0435\u0439\u0434\u0438\u0441\u0442\u044B (\u0410\u0434\u043B\u0435\u0440, \u042E\u043D\u0433, \u0425\u043E\u0440\u043D\u0438) \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u043B\u0438 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435, \u043D\u043E \u0443\u043C\u0435\u043D\u044C\u0448\u0438\u043B\u0438 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0441\u0435\u043A\u0441\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u042E\u043D\u0433 \u0432\u0432\u0435\u043B \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0435 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0438 \u0430\u0440\u0445\u0435\u0442\u0438\u043F\u044B. \u0410\u0434\u043B\u0435\u0440 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u043B\u0441\u044F \u043D\u0430 \u043A\u043E\u043C\u043F\u043B\u0435\u043A\u0441\u0435 \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0438.","\u0413\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u044B: \u0420\u043E\u0434\u0436\u0435\u0440\u0441 \u043F\u043E\u0434\u0447\u0435\u0440\u043A\u0438\u0432\u0430\u043B \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E\u0435 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u0438 \u042F-\u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044E. \u041C\u0430\u0441\u043B\u043E\u0443 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u043B\u0441\u044F \u043D\u0430 \u0441\u0430\u043C\u043E\u0430\u043A\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u2014 \u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0438 \u043B\u0443\u0447\u0448\u0435\u0439 \u0432\u0435\u0440\u0441\u0438\u0435\u0439 \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u0435\u0431\u044F.","\u0422\u0435\u043E\u0440\u0438\u0438 \u0447\u0435\u0440\u0442 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u0435 \u0438\u0437\u043C\u0435\u0440\u0435\u043D\u0438\u044F. \u0411\u043E\u043B\u044C\u0448\u0430\u044F \u043F\u044F\u0442\u0435\u0440\u043A\u0430 (OCEAN): \u041E\u0442\u043A\u0440\u044B\u0442\u043E\u0441\u0442\u044C (\u043B\u044E\u0431\u043E\u043F\u044B\u0442\u0441\u0442\u0432\u043E), \u0414\u043E\u0431\u0440\u043E\u0441\u043E\u0432\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u044C (\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0441\u0442\u044C), \u042D\u043A\u0441\u0442\u0440\u0430\u0432\u0435\u0440\u0441\u0438\u044F (\u043E\u0431\u0449\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C), \u0414\u043E\u0431\u0440\u043E\u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C (\u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u043E), \u041D\u0435\u0439\u0440\u043E\u0442\u0438\u0437\u043C (\u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u0430\u044F \u043D\u0435\u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u043E\u0441\u0442\u044C).","\u0427\u0435\u0440\u0442\u044B \u0411\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u043A\u0438 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E \u043D\u0430\u0441\u043B\u0435\u0434\u0443\u044E\u0442\u0441\u044F (~40\u201360%), \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B \u043F\u043E\u0441\u043B\u0435 30 \u043B\u0435\u0442 \u0438 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0442\u0440\u0443\u0434\u0430, \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0438 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F.","\u041E\u0446\u0435\u043D\u043A\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438: \u041E\u043F\u0440\u043E\u0441\u043D\u0438\u043A\u0438 \u0441\u0430\u043C\u043E\u043E\u0442\u0447\u0435\u0442\u0430 (MMPI, NEO-PI-R) \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0442 \u0445\u043E\u0440\u043E\u0448\u0435\u0439 \u043D\u0430\u0434\u0435\u0436\u043D\u043E\u0441\u0442\u044C\u044E, \u043D\u043E \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u044B \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u0438\u044E \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u041F\u0440\u043E\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0435 \u0442\u0435\u0441\u0442\u044B (\u0420\u043E\u0440\u0448\u0430\u0445, \u0422\u0410\u0422) \u0438\u043C\u0435\u044E\u0442 \u0431\u043E\u043B\u0435\u0435 \u0441\u043B\u0430\u0431\u0443\u044E \u0432\u0430\u043B\u0438\u0434\u043D\u043E\u0441\u0442\u044C."],hy:["\u0556\u0580\u0565\u0575\u0564\u056B \u0570\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0571\u0587\u0561\u057E\u0578\u0580\u057E\u0578\u0582\u0574 \u0567 Id-\u056B (\u0576\u0561\u056D\u0576\u0561\u0564\u0561\u0580\u0575\u0561\u0576 \u0581\u0561\u0576\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580), Ego-\u056B (\u057C\u0561\u0581\u056B\u0578\u0576\u0561\u056C \u0574\u056B\u057B\u0576\u0578\u0580\u0564) \u0587 Superego-\u056B (\u0562\u0561\u0580\u0578\u0575\u0561\u056F\u0561\u0576 \u056D\u056B\u0572\u0573) \u0574\u056B\u057B\u0587 \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u056B\u0581 \u0570\u0561\u056F\u0561\u0574\u0561\u0580\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0578\u0582\u0574: \u054A\u0561\u0577\u057F\u057A\u0561\u0576\u0561\u056F\u0561\u0576 \u0574\u0565\u056D\u0561\u0576\u056B\u0566\u0574\u0576\u0565\u0580\u0568 (\u0573\u0576\u0577\u0578\u0582\u0574, \u057A\u0580\u0578\u0575\u0565\u056F\u0581\u056B\u0561, \u056A\u056D\u057F\u0578\u0582\u0574) \u057A\u0561\u0577\u057F\u057A\u0561\u0576\u0578\u0582\u0574 \u0565\u0576 \u0567\u0563\u0578\u0576:","\u0556\u0580\u0565\u0575\u0564\u056B \u057A\u057D\u056B\u056D\u0578\u057D\u0565\u0584\u057D\u0578\u0582\u0561\u056C \u0583\u0578\u0582\u056C\u0565\u0580\u0568\u055D \u0555\u0580\u0561\u056C, \u0531\u0576\u0561\u056C, \u0556\u0561\u056C\u056C\u056B\u056F (\u0537\u0564\u056B\u057A\u0575\u0561\u0576 \u0562\u0561\u0580\u0564\u0578\u0582\u0575\u0569), \u053C\u0561\u057F\u0565\u0576\u057F, \u0533\u0565\u0576\u056B\u057F\u0561\u056C: \u0551\u0561\u0576\u056F\u0561\u0581\u0561\u056E \u0583\u0578\u0582\u056C\u0578\u0582\u0574 \u0586\u056B\u0584\u057D\u0561\u0581\u056B\u0561\u0576 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0561\u0566\u0564\u0565\u056C \u0570\u0561\u057D\u0578\u0582\u0576 \u0561\u0576\u0571\u056B \u057E\u0580\u0561:","\u0546\u0565\u0578\u0586\u0580\u0565\u0575\u0564\u056B\u057D\u057F\u0576\u0565\u0580\u0568 (\u0531\u0564\u056C\u0565\u0580, \u0545\u0578\u0582\u0576\u0563, \u0540\u0578\u0580\u0576\u056B) \u057A\u0561\u0570\u057A\u0561\u0576\u0565\u0581\u056B\u0576 \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576\u0568, \u0562\u0561\u0575\u0581 \u0576\u057E\u0561\u0566\u0565\u0581\u0580\u056B\u0576 \u057D\u0565\u0584\u057D\u0578\u0582\u0561\u056C\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0561\u0580\u0587\u0578\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0545\u0578\u0582\u0576\u0563\u0568 \u0576\u0565\u0580\u0574\u0578\u0582\u056E\u0565\u0581 \u056F\u0578\u056C\u0565\u056F\u057F\u056B\u057E \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576\u056B \u0587 \u0561\u0580\u056D\u0565\u057F\u056B\u057A\u0565\u0580 \u0570\u0561\u057D\u056F\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0531\u0564\u056C\u0565\u0580\u0568 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u0581\u0561\u057E \u0569\u0565\u0580\u0561\u0580\u056A\u0565\u0584\u0578\u0582\u0569\u0575\u0561\u0576 \u0562\u0561\u0580\u0564\u0578\u0582\u0575\u0569\u056B \u057E\u0580\u0561:","\u0540\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0576\u0565\u0580. \u054C\u0578\u057B\u0565\u0580\u057D\u0576 \u0568\u0576\u0564\u0563\u056E\u0565\u056C \u0567 \u0561\u0576\u057E\u0565\u0580\u0561\u057A\u0561\u0570 \u0564\u0580\u0561\u056F\u0561\u0576 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584\u0568 \u0587 \u056B\u0576\u0584\u0576\u0561\u0568\u0576\u056F\u0561\u056C\u0578\u0582\u0574\u0568: \u0544\u0561\u057D\u056C\u0578\u0578\u0582\u0576 \u056F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u0581\u0565\u056C \u0567 \u056B\u0576\u0584\u0576\u0561\u056B\u0580\u0561\u0581\u0574\u0561\u0576 \u057E\u0580\u0561\u055D \u0564\u0561\u057C\u0576\u0561\u056C\u0578\u057E \u0584\u0578 \u056C\u0561\u057E\u0561\u0563\u0578\u0582\u0575\u0576 \u057F\u0561\u0580\u0562\u0565\u0580\u0561\u056F\u0568:","\u0540\u0561\u057F\u056F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0578\u0582\u0574 \u0565\u0576 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0575\u0578\u0582\u0576 \u0579\u0561\u0583\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u0544\u0565\u056E \u0570\u0576\u0563\u0575\u0561\u056F\u0568 (OCEAN)\u055D \u0532\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u0565\u057F\u0561\u0584\u0580\u0584\u0580\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0532\u0561\u0580\u0565\u056D\u0572\u0573\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0537\u0584\u057D\u057F\u0580\u0561\u057E\u0565\u0580\u057D\u056B\u0561 (\u0577\u0583\u057E\u0578\u0572\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0540\u0561\u0574\u0561\u0571\u0561\u0575\u0576\u0565\u056C\u056B\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u0561\u0574\u0561\u0563\u0578\u0580\u056E\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u0546\u0587\u0580\u0578\u057F\u056B\u056F\u056B\u0566\u0574 (\u0570\u0578\u0582\u0566\u0561\u056F\u0561\u0576 \u0561\u0576\u056F\u0561\u0575\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576):","\u0544\u0565\u056E \u0570\u0576\u0563\u0575\u0561\u056F\u0568 \u0574\u0561\u057D\u0561\u0574\u0562 \u056A\u0561\u057C\u0561\u0576\u0563\u0561\u056F\u0561\u0576 \u0567 (~40\u201360%), \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0561\u0562\u0561\u0580 \u056F\u0561\u0575\u0578\u0582\u0576 \u0567 30 \u057F\u0561\u0580\u0565\u056F\u0561\u0576\u056B\u0581 \u0570\u0565\u057F\u0578 \u0587 \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0578\u0582\u0574 \u0567 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u056F\u0561\u057F\u0561\u0580\u0578\u0572\u0561\u056F\u0561\u0576\u0568, \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0562\u0561\u057E\u0561\u0580\u0561\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0561\u057C\u0578\u0572\u057B\u0561\u056F\u0561\u0576 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568:","\u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574. \u053B\u0576\u0584\u0576\u0561\u0566\u0565\u056F\u0578\u0582\u0581\u0574\u0561\u0576 \u0570\u0561\u0580\u0581\u0561\u0580\u0561\u0576\u0576\u0565\u0580\u0568 (MMPI, NEO-PI-R) \u0578\u0582\u0576\u0565\u0576 \u056C\u0561\u057E \u0570\u0578\u0582\u057D\u0561\u056C\u056B\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0562\u0561\u0575\u0581 \u0565\u0576\u0569\u0561\u056F\u0561 \u0565\u0576 \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0581\u0561\u0576\u056F\u0561\u056C\u056B\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u0561\u056C\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0565\u0572\u0561\u0569\u0575\u0578\u0582\u0580\u0574\u0561\u0576: \u054A\u0580\u0578\u0575\u0565\u056F\u057F\u056B\u057E \u0569\u0565\u057D\u057F\u0565\u0580\u0568 (\u054C\u0578\u0580\u0577\u0561\u056D, TAT) \u0561\u057E\u0565\u056C\u056B \u0569\u0578\u0582\u0575\u056C \u057E\u0561\u057E\u0565\u0580\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0578\u0582\u0576\u0565\u0576:"],az:["Freydin psixoanalitik n\u0259z\u0259riyy\u0259si: \u015E\u0259xsiyy\u0259t Id (ilkin ist\u0259kl\u0259r), Eqo (rasional vasit\u0259\xE7i) v\u0259 Supereqo (m\u0259n\u0259vi vicdan) aras\u0131ndak\u0131 \u015F\xFCursuz qar\u015F\u0131durmalarla formala\u015F\u0131r. M\xFCdafi\u0259 mexanizml\u0259ri (basd\u0131r\u0131lma, proyeksiya, inkar) eqonu qoruyur.","Freydin psixoseksual m\u0259rh\u0259l\u0259l\u0259ri: Oral, Anal, Fallik (Edip kompleksi), Latent, Genital. H\u0259r hans\u0131 bir m\u0259rh\u0259l\u0259d\u0259 fiksasiya yetkin \u015F\u0259xsiyy\u0259t\u0259 t\u0259sir ed\u0259 bil\u0259r.","Neo-Freyd\xE7il\u0259r (Adler, Yunq, Horney) \u015F\xFCuralt\u0131n\u0131 qoruyub saxlasalar da, seksuall\u0131\u011F\u0131n \u0259h\u0259miyy\u0259tini azaltd\u0131lar. Yunq kollektiv \u015F\xFCuralt\u0131 v\u0259 arxetipl\u0259ri t\u0259qdim etdi. Adler a\u015Fa\u011F\u0131l\u0131q kompleksin\u0259 fokusland\u0131.","Humanist yana\u015Fmalar: Rogers qeyd-\u015F\u0259rtsiz m\xFCsb\u0259t m\xFCnasib\u0259ti v\u0259 m\u0259nlik konsepsiyas\u0131n\u0131 vur\u011Fulad\u0131. Maslow \xF6z\xFCn\xFCrealla\u015Fd\u0131rmaya - \xF6z\xFCn\xFCz\xFCn \u0259n yax\u015F\u0131 versiyan\u0131z olma\u011Fa diqq\u0259t yetirdi.","X\xFCsusiyy\u0259t n\u0259z\u0259riyy\u0259l\u0259ri \u015F\u0259xsiyy\u0259ti sabit \xF6l\xE7\xFCl\u0259rd\u0259n istifad\u0259 ed\u0259r\u0259k t\u0259svir edir. B\xF6y\xFCk Be\u015Flik (OCEAN): A\xE7\u0131ql\u0131q (maraq), Vicdanl\u0131l\u0131q (t\u0259\u015Fkilatlanma), Ekstraversiya (\xFCnsiyy\u0259tcillik), Uy\u011Funluq (\u0259m\u0259kda\u015Fl\u0131q), Nevrotizm (emosional qeyri-sabitlik).","B\xF6y\xFCk Be\u015Flik \u0259lam\u0259tl\u0259ri qism\u0259n irsi ke\xE7ir (~40\u201360%), 30 ya\u015Fdan sonra nisb\u0259t\u0259n sabitdir v\u0259 i\u015Fin icras\u0131n\u0131, m\xFCnasib\u0259tl\u0259rd\u0259n m\u0259mnunlu\u011Fu v\u0259 sa\u011Flaml\u0131q n\u0259tic\u0259l\u0259rini proqnozla\u015Fd\u0131r\u0131r.","\u015E\u0259xsiyy\u0259tin qiym\u0259tl\u0259ndirilm\u0259si: \xD6z\xFCn\xFChesabat inventarlar\u0131 (MMPI, NEO-PI-R) yax\u015F\u0131 etibarl\u0131l\u0131\u011Fa malikdir, lakin sosial arzuolunma q\u0259r\u0259zin\u0259 m\u0259ruz qal\u0131r. Proyektiv testl\u0259r (Rorschach, TAT) daha z\u0259if etibarl\u0131l\u0131\u011Fa malikdir."]},funFact:{en:"The Myers-Briggs Type Indicator (MBTI) is used by 88% of Fortune 500 companies, yet most personality psychologists consider it scientifically unreliable \u2014 about 50% of people get a different result when retested. The Big Five is the gold standard in research.",ka:"Myers-Briggs \u10E2\u10D8\u10DE\u10D8\u10E1 \u10D8\u10DC\u10D3\u10D8\u10D9\u10D0\u10E2\u10DD\u10E0\u10E1 (MBTI) \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 Fortune 500 \u10D9\u10DD\u10DB\u10DE\u10D0\u10DC\u10D8\u10D4\u10D1\u10D8\u10E1 88%, \u10D7\u10E3\u10DB\u10EA\u10D0 \u10DB\u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E0\u10D7\u10D0 \u10E3\u10DB\u10D4\u10E2\u10D4\u10E1\u10DD\u10D1\u10D0 \u10DB\u10D0\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10E3\u10DA\u10D0\u10D3 \u10D0\u10E0\u10D0\u10E1\u10D0\u10D8\u10DB\u10D4\u10D3\u10DD\u10D3 \u10DB\u10D8\u10D8\u10E9\u10DC\u10D4\u10D5\u10E1.",ru:"\u0418\u043D\u0434\u0438\u043A\u0430\u0442\u043E\u0440 \u0442\u0438\u043F\u043E\u0432 \u041C\u0430\u0439\u0435\u0440\u0441-\u0411\u0440\u0438\u0433\u0433\u0441 (MBTI) \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F 88% \u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0439 \u0438\u0437 \u0441\u043F\u0438\u0441\u043A\u0430 Fortune 500, \u043E\u0434\u043D\u0430\u043A\u043E \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u043E\u0432 \u0441\u0447\u0438\u0442\u0430\u044E\u0442 \u0435\u0433\u043E \u043D\u0430\u0443\u0447\u043D\u043E \u043D\u0435\u043D\u0430\u0434\u0435\u0436\u043D\u044B\u043C.",hy:"\u0544\u0561\u0575\u0565\u0580\u057D-\u0532\u0580\u056B\u0563\u057D \u057F\u056B\u057A\u056B \u056B\u0576\u0564\u056B\u056F\u0561\u057F\u0578\u0580\u0568 (MBTI) \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u057E\u0578\u0582\u0574 \u0567 Fortune 500 \u0568\u0576\u056F\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B 88%-\u056B \u056F\u0578\u0572\u0574\u056B\u0581, \u057D\u0561\u056F\u0561\u0575\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0576\u0565\u0580\u056B \u0574\u0565\u056E \u0574\u0561\u057D\u0568 \u0561\u0575\u0576 \u0570\u0561\u0574\u0561\u0580\u0578\u0582\u0574 \u0567 \u0563\u056B\u057F\u0561\u056F\u0561\u0576\u0578\u0580\u0565\u0576 \u0561\u0576\u0570\u0578\u0582\u057D\u0561\u056C\u056B:",az:"Myers-Briggs Tip G\xF6st\u0259ricisi (MBTI) Fortune 500 \u015Firk\u0259tl\u0259rinin 88%-i t\u0259r\u0259find\u0259n istifad\u0259 olunur, lakin \u0259ks\u0259r psixoloqlar bunu elmi c\u0259h\u0259td\u0259n etibars\u0131z hesab edirl\u0259r."},realWorld:{en:"Recruiters use Big Five assessments because Conscientiousness is the strongest personality predictor of job performance across all occupations. Agreeableness predicts teamwork, and Openness predicts creativity.",ka:"\u10E0\u10D4\u10D9\u10E0\u10E3\u10E2\u10D4\u10E0\u10D4\u10D1\u10D8 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u201E\u10D3\u10D8\u10D3\u10D8 \u10EE\u10E3\u10D7\u10D4\u10E3\u10DA\u10D8\u10E1\u201C \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D4\u10D1\u10E1, \u10E0\u10D0\u10D3\u10D2\u10D0\u10DC \u10D9\u10D4\u10D7\u10D8\u10DA\u10E1\u10D8\u10DC\u10D3\u10D8\u10E1\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD\u10E1 \u10E8\u10D4\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D8\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10EB\u10DA\u10D8\u10D4\u10E0\u10D8 \u10DE\u10E0\u10DD\u10D2\u10DC\u10DD\u10D6\u10D8\u10E0\u10D4\u10D1\u10D0\u10D3\u10D8 \u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D8.",ru:"\u0420\u0435\u043A\u0440\u0443\u0442\u0435\u0440\u044B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u043E\u0446\u0435\u043D\u043A\u0438 \xAB\u0411\u043E\u043B\u044C\u0448\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u043A\u0438\xBB, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0434\u043E\u0431\u0440\u043E\u0441\u043E\u0432\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u044C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043B\u044C\u043D\u0435\u0439\u0448\u0438\u043C \u043F\u0440\u0435\u0434\u0438\u043A\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0442\u0440\u0443\u0434\u0430.",hy:"\u054C\u0565\u0584\u0580\u0578\u0582\u0569\u0565\u0580\u0576\u0565\u0580\u0568 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u0544\u0565\u056E \u0570\u0576\u0563\u0575\u0561\u056F\u056B \u0563\u0576\u0561\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0576\u0565\u0580\u0568, \u0584\u0561\u0576\u056B \u0578\u0580 \u0562\u0561\u0580\u0565\u056D\u0572\u0573\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u056F\u0561\u057F\u0561\u0580\u0578\u0572\u0561\u056F\u0561\u0576\u056B \u0561\u0574\u0565\u0576\u0561\u0578\u0582\u056A\u0565\u0572 \u056F\u0561\u0576\u056D\u0561\u057F\u0565\u057D\u0578\u0572\u0576 \u0567:",az:"\u0130\u015F\u0259 g\xF6t\xFCr\u0259nl\u0259r B\xF6y\xFCk Be\u015Flik qiym\u0259tl\u0259ndirm\u0259l\u0259rind\u0259n istifad\u0259 edirl\u0259r, \xE7\xFCnki Vicdanl\u0131l\u0131q i\u015F performans\u0131n\u0131n \u0259n g\xFCcl\xFC proqnozla\u015Fd\u0131r\u0131c\u0131s\u0131d\u0131r."}},12:{title:{en:"Social Psychology",ka:"\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0",ru:"\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F",hy:"\u054D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576",az:"Sosial Psixologiya"},description:{en:"How others influence our thoughts, feelings, and behavior.",ka:"\u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10EE\u10D3\u10D4\u10DC\u10D4\u10DC \u10E1\u10EE\u10D5\u10D4\u10D1\u10D8 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1 \u10E9\u10D5\u10D4\u10DC\u10E1 \u10D0\u10D6\u10E0\u10D4\u10D1\u10D6\u10D4, \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D0\u10D6\u10D4.",ru:"\u041A\u0430\u043A \u0434\u0440\u0443\u0433\u0438\u0435 \u0432\u043B\u0438\u044F\u044E\u0442 \u043D\u0430 \u043D\u0430\u0448\u0438 \u043C\u044B\u0441\u043B\u0438, \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435.",hy:"\u053B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0578\u0582\u0580\u056B\u0577\u0576\u0565\u0580\u0576 \u0561\u0566\u0564\u0578\u0582\u0574 \u0574\u0565\u0580 \u0574\u057F\u0584\u0565\u0580\u056B, \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0587 \u057E\u0561\u0580\u0584\u056B \u057E\u0580\u0561:",az:"Ba\u015Fqalar\u0131n\u0131n d\xFC\u015F\xFCnc\u0259l\u0259rimiz\u0259, hissl\u0259rimiz\u0259 v\u0259 davran\u0131\u015Flar\u0131m\u0131za nec\u0259 t\u0259sir etdiyi."},keyTopics:{en:["Conformity","Obedience","Attitudes","Group Behavior","Prejudice"],ka:["\u10D9\u10DD\u10DC\u10E4\u10DD\u10E0\u10DB\u10E3\u10DA\u10DD\u10D1\u10D0","\u10DB\u10DD\u10E0\u10E9\u10D8\u10DA\u10D4\u10D1\u10D0","\u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8","\u10EF\u10D2\u10E3\u10E4\u10E3\u10E0\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D0","\u10EA\u10E0\u10E3\u10E0\u10EC\u10DB\u10D4\u10DC\u10D0"],ru:["\u0421\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435","\u041F\u043E\u0441\u043B\u0443\u0448\u0430\u043D\u0438\u0435","\u041E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F","\u0413\u0440\u0443\u043F\u043F\u043E\u0432\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435","\u041F\u0440\u0435\u0434\u0440\u0430\u0441\u0441\u0443\u0434\u043A\u0438"],hy:["\u0540\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0540\u0576\u0561\u0566\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u054E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580","\u053D\u0574\u0562\u0561\u0575\u056B\u0576 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E","\u0546\u0561\u056D\u0561\u057A\u0561\u0577\u0561\u0580\u0574\u0578\u0582\u0576\u0584"],az:["Uy\u011Funluq","\u0130ta\u0259t","M\xFCnasib\u0259tl\u0259r","Qrup Davran\u0131\u015F\u0131","Q\u0259r\u0259z"]},summary:{en:"Social psychology is the scientific study of how people's thoughts, feelings, and behaviors are influenced by the actual, imagined, or implied presence of others. This chapter explores the powerful ways social situations shape individual behavior \u2014 often more than personality traits do. Attribution theory examines how we explain others' behavior, revealing the fundamental attribution error: our tendency to overestimate personality factors and underestimate situational influences when judging others. Classic experiments by Asch demonstrated that people conform to group pressure even when the group is clearly wrong, while Milgram's obedience studies showed that 65% of ordinary people would deliver apparently lethal electric shocks when instructed by an authority figure. Festinger's theory of cognitive dissonance explains the discomfort we feel when our actions contradict our beliefs, and how we change our attitudes to resolve this tension. The chapter also covers group phenomena including social facilitation, social loafing, groupthink, and deindividuation; the components of prejudice (stereotypes, attitudes, and discrimination) and strategies for reducing it; and the bystander effect \u2014 Darley and Latane's finding that the more people present during an emergency, the less likely any individual is to help.",ka:"\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10E3\u10DA\u10D8 \u10E8\u10D4\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10D8\u10DB\u10D8\u10E1\u10D0, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D2\u10D0\u10DC\u10D8\u10EA\u10D3\u10D8\u10D0\u10DC \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D0\u10D6\u10E0\u10D4\u10D1\u10D8, \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D4\u10D1\u10D8 \u10E1\u10EE\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E0\u10D4\u10D0\u10DA\u10E3\u10E0\u10D8, \u10EC\u10D0\u10E0\u10DB\u10DD\u10E1\u10D0\u10EE\u10D5\u10D8\u10D7\u10D8 \u10D7\u10E3 \u10DC\u10D0\u10D2\u10E3\u10DA\u10D8\u10E1\u10EE\u10DB\u10D4\u10D5\u10D8 \u10D7\u10D0\u10DC\u10D3\u10D0\u10E1\u10EC\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D8\u10DB \u10DB\u10EB\u10DA\u10D0\u10D5\u10E0 \u10D2\u10D6\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10D7\u10D0\u10EA \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10D4\u10D1\u10D8 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10D4\u10DC \u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10E3\u10D0\u10DA\u10E3\u10E0 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u2014 \u10EE\u10E8\u10D8\u10E0\u10D0\u10D3 \u10E3\u10E4\u10E0\u10DD \u10DB\u10D4\u10E2\u10D0\u10D3\u10EA, \u10D5\u10D8\u10D3\u10E0\u10D4 \u10D0\u10DB\u10D0\u10E1 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10E3\u10DA\u10D8 \u10D7\u10D5\u10D8\u10E1\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D0\u10D9\u10D4\u10D7\u10D4\u10D1\u10D4\u10DC. \u10D0\u10E2\u10E0\u10D8\u10D1\u10E3\u10EA\u10D8\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 \u10E8\u10D4\u10D8\u10E1\u10EC\u10D0\u10D5\u10DA\u10D8\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10EE\u10E1\u10DC\u10D8\u10D7 \u10E1\u10EE\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1, \u10D2\u10D0\u10DB\u10DD\u10D0\u10D5\u10DA\u10D4\u10DC\u10E1 \u10E0\u10D0 \u10E4\u10E3\u10DC\u10D3\u10D0\u10DB\u10D4\u10DC\u10E2\u10E3\u10E0 \u10D0\u10E2\u10E0\u10D8\u10D1\u10E3\u10EA\u10D8\u10E3\u10DA \u10E8\u10D4\u10EA\u10D3\u10DD\u10DB\u10D0\u10E1: \u10E9\u10D5\u10D4\u10DC\u10E1 \u10E2\u10D4\u10DC\u10D3\u10D4\u10DC\u10EA\u10D8\u10D0\u10E1, \u10E1\u10EE\u10D5\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10E1\u10EF\u10D8\u10E1\u10D0\u10E1 \u10D2\u10D0\u10D3\u10D0\u10D5\u10D0\u10ED\u10D0\u10E0\u10D1\u10DD\u10D7 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10E3\u10DA\u10D8 \u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0 \u10E1\u10D0\u10D7\u10D0\u10DC\u10D0\u10D3\u10DD\u10D3 \u10D0\u10E0 \u10D3\u10D0\u10D5\u10D0\u10E4\u10D0\u10E1\u10DD\u10D7 \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D8\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D1\u10D0. \u10D0\u10E8\u10D8\u10E1 \u10D9\u10DA\u10D0\u10E1\u10D8\u10D9\u10E3\u10E0\u10DB\u10D0 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10DB\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10D4\u10DB\u10DD\u10E0\u10E9\u10D8\u10DA\u10D4\u10D1\u10D8\u10D0\u10DC \u10EF\u10D2\u10E3\u10E4\u10D8\u10E1 \u10D6\u10D4\u10EC\u10DD\u10DA\u10D0\u10E1 \u10DB\u10D0\u10E8\u10D8\u10DC\u10D0\u10EA \u10D9\u10D8, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10EF\u10D2\u10E3\u10E4\u10D8 \u10D0\u10E8\u10D9\u10D0\u10E0\u10D0\u10D3 \u10EA\u10D3\u10D4\u10D1\u10D0, \u10EE\u10DD\u10DA\u10DD \u10DB\u10D8\u10DA\u10D2\u10E0\u10D0\u10DB\u10D8\u10E1 \u10DB\u10DD\u10E0\u10E9\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10DB\u10D0 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10E0\u10D8\u10D2\u10D8\u10D7\u10D8 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8\u10E1 65% \u10DB\u10D8\u10D0\u10E7\u10D4\u10DC\u10D4\u10D1\u10D3\u10D0 \u10D0\u10E8\u10D9\u10D0\u10E0\u10D0\u10D3 \u10E1\u10D0\u10E1\u10D8\u10D9\u10D5\u10D3\u10D8\u10DA\u10DD \u10D4\u10DA\u10D4\u10E5\u10E2\u10E0\u10DD\u10E8\u10DD\u10D9\u10E1, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10D0\u10DB\u10D0\u10E1 \u10D0\u10D5\u10E2\u10DD\u10E0\u10D8\u10E2\u10D4\u10E2\u10E3\u10DA\u10D8 \u10E4\u10D8\u10D2\u10E3\u10E0\u10D0 \u10D0\u10D5\u10D0\u10DA\u10D4\u10D1\u10D3\u10D0. \u10E4\u10D4\u10E1\u10E2\u10D8\u10DC\u10D2\u10D4\u10E0\u10D8\u10E1 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D8\u10E1\u10DD\u10DC\u10D0\u10DC\u10E1\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0 \u10EE\u10E1\u10DC\u10D8\u10E1 \u10D3\u10D8\u10E1\u10D9\u10DD\u10DB\u10E4\u10DD\u10E0\u10E2\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10E1\u10D0\u10EA \u10D5\u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D7, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D4\u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10D4\u10D1\u10D0 \u10E9\u10D5\u10D4\u10DC\u10E1 \u10E0\u10EC\u10DB\u10D4\u10DC\u10D0\u10E1 \u10D3\u10D0 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D5\u10EA\u10D5\u10DA\u10D8\u10D7 \u10E9\u10D5\u10D4\u10DC\u10E1 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10E1 \u10D0\u10DB \u10D3\u10D0\u10EB\u10D0\u10D1\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10DD\u10E1\u10D0\u10EE\u10E1\u10DC\u10D4\u10DA\u10D0\u10D3. \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10EF\u10D2\u10E3\u10E4\u10E3\u10E0 \u10E4\u10D4\u10DC\u10DD\u10DB\u10D4\u10DC\u10D4\u10D1\u10E1, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0 \u10E4\u10D0\u10E1\u10D8\u10DA\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0\u10E1, \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0 \u10DA\u10DD\u10E3\u10E4\u10D8\u10DC\u10D2\u10E1, \u10EF\u10D2\u10E3\u10E4\u10E3\u10E0 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10D3\u10D4\u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10E3\u10D0\u10EA\u10D8\u10D0\u10E1; \u10EA\u10E0\u10E3\u10E0\u10EC\u10DB\u10D4\u10DC\u10D8\u10E1 \u10D9\u10DD\u10DB\u10DE\u10DD\u10DC\u10D4\u10DC\u10E2\u10D4\u10D1\u10E1 (\u10E1\u10E2\u10D4\u10E0\u10D4\u10DD\u10E2\u10D8\u10DE\u10D4\u10D1\u10D8, \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D3\u10D8\u10E1\u10D9\u10E0\u10D8\u10DB\u10D8\u10DC\u10D0\u10EA\u10D8\u10D0) \u10D3\u10D0 \u10DB\u10D8\u10E1\u10D8 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10E1; \u10D3\u10D0 \u10D2\u10D0\u10E0\u10D4\u10E8\u10D4 \u10DE\u10D8\u10E0\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E1 \u2014 \u10D3\u10D0\u10E0\u10DA\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DA\u10D0\u10E2\u10D0\u10DC\u10D4\u10E1 \u10D0\u10E6\u10DB\u10DD\u10E9\u10D4\u10DC\u10D0\u10E1, \u10E0\u10DD\u10DB \u10E0\u10D0\u10EA \u10E3\u10E4\u10E0\u10DD \u10DB\u10D4\u10E2\u10D8 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10D0 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D3\u10D2\u10D4\u10DC\u10D8\u10DA\u10D8 \u10E1\u10D0\u10D2\u10D0\u10DC\u10D2\u10D4\u10D1\u10DD \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10D8\u10E1 \u10D3\u10E0\u10DD\u10E1, \u10DB\u10D8\u10D7 \u10E3\u10E4\u10E0\u10DD \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D8\u10D0 \u10D0\u10DA\u10D1\u10D0\u10D7\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10DB\u10D4 \u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10D8 \u10D5\u10D8\u10DC\u10DB\u10D4\u10E1 \u10D3\u10D0\u10D4\u10EE\u10DB\u10D0\u10E0\u10DD\u10E1.",ru:"\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u2014 \u044D\u0442\u043E \u043D\u0430\u0443\u0447\u043D\u043E\u0435 \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043D\u0430 \u043C\u044B\u0441\u043B\u0438, \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u043B\u044E\u0434\u0435\u0439 \u0432\u043B\u0438\u044F\u0435\u0442 \u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435, \u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0430\u0435\u043C\u043E\u0435 \u0438\u043B\u0438 \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u043C\u043E\u0435 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0434\u0440\u0443\u0433\u0438\u0445. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0442\u0441\u044F \u0442\u0435 \u043C\u043E\u0449\u043D\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u044B, \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0442 \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u2014 \u0437\u0430\u0447\u0430\u0441\u0442\u0443\u044E \u0432 \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438, \u0447\u0435\u043C \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u043D\u044B\u0435 \u0447\u0435\u0440\u0442\u044B. \u0422\u0435\u043E\u0440\u0438\u044F \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442, \u043A\u0430\u043A \u043C\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u043C \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0434\u0440\u0443\u0433\u0438\u0445, \u0432\u044B\u044F\u0432\u043B\u044F\u044F \u0444\u0443\u043D\u0434\u0430\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u0443\u044E \u043E\u0448\u0438\u0431\u043A\u0443 \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438: \u043D\u0430\u0448\u0443 \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u044E \u043F\u0435\u0440\u0435\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0442\u044C \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u043D\u044B\u0435 \u0444\u0430\u043A\u0442\u043E\u0440\u044B \u0438 \u043D\u0435\u0434\u043E\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0442\u044C \u0441\u0438\u0442\u0443\u0430\u0442\u0438\u0432\u043D\u044B\u0435 \u0432\u043B\u0438\u044F\u043D\u0438\u044F \u043F\u0440\u0438 \u043E\u0446\u0435\u043D\u043A\u0435 \u0434\u0440\u0443\u0433\u0438\u0445. \u041A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u044B \u0410\u0448\u0430 \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043B\u0438, \u0447\u0442\u043E \u043B\u044E\u0434\u0438 \u043F\u043E\u0434\u0447\u0438\u043D\u044F\u044E\u0442\u0441\u044F \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u043E\u043C\u0443 \u0434\u0430\u0432\u043B\u0435\u043D\u0438\u044E, \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 \u0433\u0440\u0443\u043F\u043F\u0430 \u044F\u0432\u043D\u043E \u043D\u0435\u043F\u0440\u0430\u0432\u0430, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043E\u0441\u043B\u0443\u0448\u0430\u043D\u0438\u044F \u041C\u0438\u043B\u0433\u0440\u0430\u043C\u0430 \u043F\u043E\u043A\u0430\u0437\u0430\u043B\u0438, \u0447\u0442\u043E 65% \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 \u043C\u043E\u0433\u0443\u0442 \u043D\u0430\u043D\u043E\u0441\u0438\u0442\u044C \u044D\u043B\u0435\u043A\u0442\u0440\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0443\u0434\u0430\u0440\u044B, \u043A\u0430\u0436\u0443\u0449\u0438\u0435\u0441\u044F \u0441\u043C\u0435\u0440\u0442\u0435\u043B\u044C\u043D\u044B\u043C\u0438, \u043F\u043E \u0443\u043A\u0430\u0437\u0430\u043D\u0438\u044E \u0430\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442\u043D\u043E\u0433\u043E \u043B\u0438\u0446\u0430. \u0422\u0435\u043E\u0440\u0438\u044F \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0434\u0438\u0441\u0441\u043E\u043D\u0430\u043D\u0441\u0430 \u0424\u0435\u0441\u0442\u0438\u043D\u0433\u0435\u0440\u0430 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0434\u0438\u0441\u043A\u043E\u043C\u0444\u043E\u0440\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043C\u044B \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u043C, \u043A\u043E\u0433\u0434\u0430 \u043D\u0430\u0448\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0430\u0442 \u043D\u0430\u0448\u0438\u043C \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u0438\u044F\u043C, \u0438 \u0442\u043E, \u043A\u0430\u043A \u043C\u044B \u043C\u0435\u043D\u044F\u0435\u043C \u0441\u0432\u043E\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u0447\u0442\u043E\u0431\u044B \u0440\u0430\u0437\u0440\u0435\u0448\u0438\u0442\u044C \u044D\u0442\u043E \u043D\u0430\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435. \u0412 \u0433\u043B\u0430\u0432\u0435 \u0442\u0430\u043A\u0436\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u044B\u0435 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u044B, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0443\u044E \u0444\u0430\u0441\u0438\u043B\u0438\u0442\u0430\u0446\u0438\u044E, \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0443\u044E \u043B\u0435\u043D\u043E\u0441\u0442\u044C, \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \u0438 \u0434\u0435\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E; \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B \u043F\u0440\u0435\u0434\u0440\u0430\u0441\u0441\u0443\u0434\u043A\u043E\u0432 (\u0441\u0442\u0435\u0440\u0435\u043E\u0442\u0438\u043F\u044B, \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u0438 \u0434\u0438\u0441\u043A\u0440\u0438\u043C\u0438\u043D\u0430\u0446\u0438\u044F) \u0438 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u0438\u0445 \u0443\u043C\u0435\u043D\u044C\u0448\u0435\u043D\u0438\u044F; \u0430 \u0442\u0430\u043A\u0436\u0435 \u044D\u0444\u0444\u0435\u043A\u0442 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F \u2014 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435 \u0414\u0430\u0440\u043B\u0438 \u0438 \u041B\u0430\u0442\u0430\u043D\u0435, \u0447\u0442\u043E \u0447\u0435\u043C \u0431\u043E\u043B\u044C\u0448\u0435 \u043B\u044E\u0434\u0435\u0439 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438, \u0442\u0435\u043C \u043C\u0435\u043D\u044C\u0448\u0435 \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0441\u0442\u044C \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043A\u0442\u043E-\u0442\u043E \u043E\u0434\u0438\u043D \u043F\u043E\u043C\u043E\u0436\u0435\u0442.",hy:"\u054D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0563\u056B\u057F\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0567 \u0561\u0575\u0576 \u0574\u0561\u057D\u056B\u0576, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0574\u0561\u0580\u0564\u056F\u0561\u0576\u0581 \u0574\u057F\u0584\u0565\u0580\u0568, \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568 \u0587 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0576 \u0561\u0566\u0564\u057E\u0578\u0582\u0574 \u0578\u0582\u0580\u056B\u0577\u0576\u0565\u0580\u056B \u056B\u0580\u0561\u056F\u0561\u0576, \u0565\u0580\u0587\u0561\u056F\u0561\u0575\u0561\u056F\u0561\u0576 \u056F\u0561\u0574 \u0565\u0576\u0569\u0561\u0564\u0580\u0575\u0561\u056C \u0576\u0565\u0580\u056F\u0561\u0575\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u056B\u0581: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0561\u0575\u0576 \u0570\u0566\u0578\u0580 \u0578\u0582\u0572\u056B\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0581\u0578\u057E \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u0568 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0565\u0576 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568\u055D \u0570\u0561\u0573\u0561\u056D \u0561\u057E\u0565\u056C\u056B \u0577\u0561\u057F, \u0584\u0561\u0576 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0563\u056E\u0565\u0580\u0568: \u0531\u057F\u0580\u056B\u0562\u0578\u0582\u0581\u056B\u0561\u0575\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0578\u0582\u0580\u056B\u0577\u0576\u0565\u0580\u056B \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568\u055D \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0565\u056C\u0578\u057E \u0561\u057F\u0580\u056B\u0562\u0578\u0582\u0581\u056B\u0561\u0575\u056B \u0570\u056B\u0574\u0576\u0561\u0580\u0561\u0580 \u057D\u056D\u0561\u056C\u0568. \u0578\u0582\u0580\u056B\u0577\u0576\u0565\u0580\u056B\u0576 \u0564\u0561\u057F\u0565\u056C\u056B\u057D \u0574\u0565\u0576\u0584 \u0570\u0561\u056F\u057E\u0561\u056E \u0565\u0576\u0584 \u0563\u0565\u0580\u0561\u0563\u0576\u0561\u0570\u0561\u057F\u0565\u056C\u0578\u0582 \u0561\u0576\u0571\u0576\u0561\u0575\u056B\u0576 \u0563\u0578\u0580\u056E\u0578\u0576\u0576\u0565\u0580\u0568 \u0587 \u0569\u0565\u0580\u0561\u0563\u0576\u0561\u0570\u0561\u057F\u0565\u056C\u0578\u0582 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u0561\u0575\u056B\u0576 \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568: \u0531\u0577\u056B \u0564\u0561\u057D\u0561\u056F\u0561\u0576 \u0583\u0578\u0580\u0571\u0565\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u057F\u057E\u0565\u0581\u056B\u0576, \u0578\u0580 \u0574\u0561\u0580\u0564\u056B\u056F \u0565\u0576\u0569\u0561\u0580\u056F\u057E\u0578\u0582\u0574 \u0565\u0576 \u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u0573\u0576\u0577\u0574\u0561\u0576\u0568 \u0576\u0578\u0582\u0575\u0576\u056B\u057D\u056F \u0561\u0575\u0576 \u056A\u0561\u0574\u0561\u0576\u0561\u056F, \u0565\u0580\u0562 \u056D\u0578\u0582\u0574\u0562\u0568 \u0561\u056F\u0576\u0570\u0561\u0575\u057F\u0578\u0580\u0565\u0576 \u057D\u056D\u0561\u056C\u057E\u0578\u0582\u0574 \u0567, \u0574\u056B\u0576\u0579\u0564\u0565\u057C \u0544\u056B\u056C\u0563\u0580\u0561\u0574\u056B \u0570\u0576\u0561\u0566\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0565\u0576 \u057F\u057E\u0565\u056C, \u0578\u0580 \u057D\u0578\u057E\u0578\u0580\u0561\u056F\u0561\u0576 \u0574\u0561\u0580\u0564\u056F\u0561\u0576\u0581 65%-\u0568 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0569\u057E\u0561\u0581\u0575\u0561\u056C \u0574\u0561\u0570\u0561\u0581\u0578\u0582 \u0567\u056C\u0565\u056F\u057F\u0580\u0561\u056F\u0561\u0576 \u0581\u0576\u0581\u0578\u0582\u0574\u0576\u0565\u0580 \u0570\u0561\u057D\u0581\u0576\u0565\u056C \u0570\u0565\u0572\u056B\u0576\u0561\u056F\u0561\u057E\u0578\u0580 \u0561\u0576\u0571\u056B \u0581\u0578\u0582\u0581\u0578\u0582\u0574\u0578\u057E: \u0556\u0565\u057D\u057F\u056B\u0576\u0563\u0565\u0580\u056B \u056F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0564\u056B\u057D\u0578\u0576\u0561\u0576\u057D\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0567 \u0561\u0575\u0576 \u0561\u0576\u0570\u0561\u0580\u0574\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0578\u0580\u0568 \u0574\u0565\u0576\u0584 \u0566\u0563\u0578\u0582\u0574 \u0565\u0576\u0584, \u0565\u0580\u0562 \u0574\u0565\u0580 \u0563\u0578\u0580\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0570\u0561\u056F\u0561\u057D\u0578\u0582\u0574 \u0565\u0576 \u0574\u0565\u0580 \u0570\u0561\u0574\u0578\u0566\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B\u0576, \u0587 \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576\u0584 \u0574\u0565\u0576\u0584 \u0583\u0578\u056D\u0578\u0582\u0574 \u0574\u0565\u0580 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584\u0568 \u0561\u0575\u057D \u056C\u0561\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056C\u0578\u0582\u056E\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580: \u0533\u056C\u0578\u0582\u056D\u0568 \u0576\u0561\u0587 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u0565\u0580\u0587\u0578\u0582\u0575\u0569\u0576\u0565\u0580\u0568, \u0561\u0575\u0564 \u0569\u057E\u0578\u0582\u0574\u055D \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0586\u0561\u057D\u056B\u056C\u056B\u057F\u0561\u0581\u056B\u0561\u0576, \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0561\u0576\u0563\u0578\u0580\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0564\u0565\u056B\u0576\u0564\u056B\u057E\u056B\u0564\u0578\u0582\u0561\u0581\u056B\u0561\u0576. \u0576\u0561\u056D\u0561\u057A\u0561\u0577\u0561\u0580\u0574\u0578\u0582\u0576\u0584\u056B \u0562\u0561\u0572\u056F\u0561\u0581\u0578\u0582\u0581\u056B\u0579\u0576\u0565\u0580\u0568 (\u056F\u0561\u0580\u056E\u0580\u0561\u057F\u056B\u057A\u0565\u0580, \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584 \u0587 \u056D\u057F\u0580\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576) \u0587 \u0564\u0580\u0561 \u0576\u057E\u0561\u0566\u0565\u0581\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568. \u056B\u0576\u0579\u057A\u0565\u057D \u0576\u0561\u0587 \u056F\u0578\u0572\u0574\u0576\u0561\u056F\u056B \u0564\u056B\u057F\u0578\u0580\u0564\u056B \u0567\u0586\u0565\u056F\u057F\u0568\u055D \u0534\u0561\u0580\u056C\u056B\u056B \u0587 \u053C\u0561\u057F\u0561\u0576\u0565\u056B \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574\u0568, \u0578\u0580\u0584\u0561\u0576 \u0577\u0561\u057F \u0574\u0561\u0580\u0564 \u0567 \u0576\u0565\u0580\u056F\u0561 \u0561\u0580\u057F\u0561\u056F\u0561\u0580\u0563 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u056B \u056A\u0561\u0574\u0561\u0576\u0561\u056F, \u0561\u0575\u0576\u0584\u0561\u0576 \u057A\u0561\u056F\u0561\u057D \u0570\u0561\u057E\u0561\u0576\u0561\u056F\u0561\u0576 \u0567, \u0578\u0580 \u0578\u0580\u0587\u0567 \u0561\u0576\u0570\u0561\u057F \u0585\u0563\u0576\u056B:",az:"Sosial psixologiya, insanlar\u0131n d\xFC\u015F\xFCnc\u0259l\u0259rinin, hissl\u0259rinin v\u0259 davran\u0131\u015Flar\u0131n\u0131n ba\u015Fqalar\u0131n\u0131n faktiki, x\u0259yali v\u0259 ya n\u0259z\u0259rd\u0259 tutulan varl\u0131\u011F\u0131ndan nec\u0259 t\u0259sirl\u0259ndiyini \xF6yr\u0259n\u0259n elmi sah\u0259dir. Bu f\u0259sil sosial v\u0259ziyy\u0259tl\u0259rin f\u0259rdi davran\u0131\u015F\u0131 formala\u015Fd\u0131rd\u0131\u011F\u0131 g\xFCcl\xFC yollar\u0131 \u2014 \xE7ox vaxt \u015F\u0259xsiyy\u0259t x\xFCsusiyy\u0259tl\u0259rind\u0259n bel\u0259 daha \xE7ox \u2014 ara\u015Fd\u0131r\u0131r. Attribusiya n\u0259z\u0259riyy\u0259si ba\u015Fqalar\u0131n\u0131n davran\u0131\u015Flar\u0131n\u0131 nec\u0259 izah etdiyimizi ara\u015Fd\u0131raraq fundamental attribusiya x\u0259tas\u0131n\u0131 ortaya qoyur: ba\u015Fqalar\u0131n\u0131 m\xFChakim\u0259 ed\u0259rk\u0259n \u015F\u0259xsiyy\u0259t faktorlar\u0131n\u0131 h\u0259ddind\u0259n art\u0131q d\u0259r\u0259c\u0259d\u0259 \u015Fi\u015Firtm\u0259k v\u0259 situasiya t\u0259sirl\u0259rini laz\u0131m\u0131nca qiym\u0259tl\u0259ndirm\u0259m\u0259k meylimiz. Asch-in klassik t\u0259cr\xFCb\u0259l\u0259ri n\xFCmayi\u015F etdirdi ki, insanlar qrup a\xE7\u0131q-a\u015Fkar s\u0259hv etdikd\u0259 bel\u0259 qrup t\u0259zyiqin\u0259 uy\u011Funla\u015F\u0131rlar, Milgram-\u0131n ita\u0259t ara\u015Fd\u0131rmalar\u0131 is\u0259 g\xF6st\u0259rdi ki, sad\u0259 insanlar\u0131n 65%-i avtoritet bir fiqur t\u0259r\u0259find\u0259n g\xF6st\u0259ri\u015F verildiyi zaman \xF6l\xFCmc\xFCl g\xF6r\xFCn\u0259n elektrik c\u0259r\u0259yan\u0131 t\u0259tbiq ed\u0259rl\u0259r. Festinger-in koqnitiv dissonans n\u0259z\u0259riyy\u0259si, h\u0259r\u0259k\u0259tl\u0259rimiz inanclar\u0131m\u0131zla ziddiyy\u0259t t\u0259\u015Fkil etdikd\u0259 hiss etdiyimiz narahatl\u0131\u011F\u0131 v\u0259 bu g\u0259rginliyi h\u0259ll etm\u0259k \xFC\xE7\xFCn m\xFCnasib\u0259timizi nec\u0259 d\u0259yi\u015Fdirdiyimizi izah edir. F\u0259sil h\u0259m\xE7inin sosial fasilitasiya, sosial t\u0259nb\u0259llik, qrup d\xFC\u015F\xFCnc\u0259si v\u0259 deindividuasiya daxil olmaqla qrup fenomenl\u0259rini; q\u0259r\u0259zin komponentl\u0259rini (stereotipl\u0259r, m\xFCnasib\u0259tl\u0259r v\u0259 ayr\u0131-se\xE7kilik) v\u0259 onu azaltmaq \xFC\xE7\xFCn strategiyalar\u0131; el\u0259c\u0259 d\u0259 \u015Fahid effektini \u2014 Darley v\u0259 Latane t\u0259r\u0259find\u0259n a\u015Fkar edilmi\u015F, f\xF6vq\u0259lad\u0259 hal zaman\u0131 n\u0259 q\u0259d\u0259r \xE7ox insan olursa, h\u0259r hans\u0131 bir f\u0259rdin k\xF6m\u0259k etm\u0259 ehtimal\u0131n\u0131n bir o q\u0259d\u0259r az oldu\u011Funu \u0259hat\u0259 edir."},keyPoints:{en:["Attribution theory: We explain others' behavior using dispositional (personality) or situational (environment) attributions. The fundamental attribution error: we overestimate personality and underestimate situations when judging others.","Conformity (Asch): People agree with an obviously wrong answer to match the group about 37% of the time. Increases with group size (up to ~5) and unanimity.","Obedience (Milgram): 65% of participants delivered what they believed were lethal electric shocks when instructed by an authority figure. Authority, proximity, and legitimacy increased obedience.","Cognitive dissonance (Festinger): When our actions contradict our beliefs, we feel discomfort and change our attitudes to match our behavior. Explains why hazing rituals increase group loyalty.","Group phenomena: Social facilitation (performing better on easy tasks when watched), Social loafing (working less in groups), Groupthink (cohesive groups suppress dissent), Deindividuation (anonymity reduces self-awareness).","Prejudice involves stereotypes (beliefs), prejudice (attitudes), and discrimination (behaviors). Reduced through intergroup contact when groups have equal status and share common goals.","Bystander effect (Darley & Latan\xE9): The more people present, the less likely anyone is to help. Caused by diffusion of responsibility and pluralistic ignorance."],ka:["\u10D0\u10E2\u10E0\u10D8\u10D1\u10E3\u10EA\u10D8\u10D8\u10E1 \u10D7\u10D4\u10DD\u10E0\u10D8\u10D0: \u10E9\u10D5\u10D4\u10DC \u10D5\u10EE\u10E1\u10DC\u10D8\u10D7 \u10E1\u10EE\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10D3\u10D8\u10E1\u10DE\u10DD\u10D6\u10D8\u10EA\u10D8\u10E3\u10E0\u10D8 (\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0) \u10D0\u10DC \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10E3\u10E0\u10D8 (\u10D2\u10D0\u10E0\u10D4\u10DB\u10DD) \u10D0\u10E2\u10E0\u10D8\u10D1\u10E3\u10E2\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10D7. \u10E4\u10E3\u10DC\u10D3\u10D0\u10DB\u10D4\u10DC\u10E2\u10E3\u10E0\u10D8 \u10D0\u10E2\u10E0\u10D8\u10D1\u10E3\u10EA\u10D8\u10D8\u10E1 \u10E8\u10D4\u10EA\u10D3\u10DD\u10DB\u10D0: \u10E1\u10EE\u10D5\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10E1\u10EF\u10D8\u10E1\u10D0\u10E1 \u10E9\u10D5\u10D4\u10DC \u10D6\u10D4\u10D3\u10DB\u10D4\u10E2\u10D0\u10D3 \u10D5\u10D0\u10E4\u10D0\u10E1\u10D4\u10D1\u10D7 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D0\u10D3 \u10D5\u10D0\u10E4\u10D0\u10E1\u10D4\u10D1\u10D7 \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10D4\u10D1\u10E1.","\u10D9\u10DD\u10DC\u10E4\u10DD\u10E0\u10DB\u10E3\u10DA\u10DD\u10D1\u10D0 (\u10D0\u10E8\u10D8): \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10D4\u10D7\u10D0\u10DC\u10EE\u10DB\u10D4\u10D1\u10D8\u10D0\u10DC \u10D0\u10E8\u10D9\u10D0\u10E0\u10D0\u10D3 \u10DB\u10EA\u10D3\u10D0\u10E0 \u10DE\u10D0\u10E1\u10E3\u10EE\u10E1 \u10EF\u10D2\u10E3\u10E4\u10D7\u10D0\u10DC \u10E8\u10D4\u10E1\u10D0\u10D1\u10D0\u10DB\u10D8\u10E1\u10DD\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D7\u10EE\u10D5\u10D4\u10D5\u10D0\u10D7\u10D0 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 37%-\u10E8\u10D8. \u10D8\u10D6\u10E0\u10D3\u10D4\u10D1\u10D0 \u10EF\u10D2\u10E3\u10E4\u10D8\u10E1 \u10D6\u10DD\u10DB\u10D0\u10E1\u10D7\u10D0\u10DC (\u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 5-\u10DB\u10D3\u10D4) \u10D3\u10D0 \u10D4\u10E0\u10D7\u10E1\u10E3\u10DA\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1\u10D7\u10D0\u10DC \u10D4\u10E0\u10D7\u10D0\u10D3.","\u10DB\u10DD\u10E0\u10E9\u10D8\u10DA\u10D4\u10D1\u10D0 (\u10DB\u10D8\u10DA\u10D2\u10E0\u10D0\u10DB\u10D8): \u10DB\u10DD\u10DC\u10D0\u10EC\u10D8\u10DA\u10D4\u10D7\u10D0 65%-\u10DB\u10D0 \u10DB\u10D8\u10D0\u10E7\u10D4\u10DC\u10D0, \u10DB\u10D0\u10D7\u10D8 \u10D0\u10D6\u10E0\u10D8\u10D7, \u10DA\u10D4\u10E2\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D4\u10DA\u10D4\u10E5\u10E2\u10E0\u10DD\u10E8\u10DD\u10D9\u10D8, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10D0\u10DB\u10D0\u10E1 \u10D0\u10D5\u10E2\u10DD\u10E0\u10D8\u10E2\u10D4\u10E2\u10E3\u10DA\u10D8 \u10E4\u10D8\u10D2\u10E3\u10E0\u10D0 \u10D0\u10D5\u10D0\u10DA\u10D4\u10D1\u10D3\u10D0. \u10D0\u10D5\u10E2\u10DD\u10E0\u10D8\u10E2\u10D4\u10E2\u10DB\u10D0, \u10E1\u10D8\u10D0\u10EE\u10DA\u10DD\u10D5\u10D4\u10DB \u10D3\u10D0 \u10DA\u10D4\u10D2\u10D8\u10E2\u10D8\u10DB\u10E3\u10E0\u10DD\u10D1\u10D0\u10DB \u10D2\u10D0\u10D6\u10D0\u10E0\u10D3\u10D0 \u10DB\u10DD\u10E0\u10E9\u10D8\u10DA\u10D4\u10D1\u10D0.","\u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D8\u10E1\u10DD\u10DC\u10D0\u10DC\u10E1\u10D8 (\u10E4\u10D4\u10E1\u10E2\u10D8\u10DC\u10D2\u10D4\u10E0\u10D8): \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10E9\u10D5\u10D4\u10DC\u10D8 \u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8 \u10D4\u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10D4\u10D1\u10D0 \u10E9\u10D5\u10D4\u10DC\u10E1 \u10E0\u10EC\u10DB\u10D4\u10DC\u10D0\u10E1, \u10E9\u10D5\u10D4\u10DC \u10D2\u10D0\u10DC\u10D5\u10D8\u10EA\u10D3\u10D8\u10D7 \u10D3\u10D8\u10E1\u10D9\u10DD\u10DB\u10E4\u10DD\u10E0\u10E2\u10E1 \u10D3\u10D0 \u10D5\u10EA\u10D5\u10DA\u10D8\u10D7 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10E1 \u10D8\u10E1\u10D4, \u10E0\u10DD\u10DB \u10D8\u10E1 \u10E9\u10D5\u10D4\u10DC\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10E8\u10D4\u10D4\u10E1\u10D0\u10D1\u10D0\u10DB\u10D4\u10D1\u10DD\u10D3\u10D4\u10E1. \u10EE\u10E1\u10DC\u10D8\u10E1 \u10D7\u10E3 \u10E0\u10D0\u10E2\u10DD\u10DB \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D8\u10DC\u10D8\u10EA\u10D8\u10D0\u10EA\u10D8\u10D8\u10E1 \u10E0\u10D8\u10E2\u10E3\u10D0\u10DA\u10D4\u10D1\u10D8 \u10EF\u10D2\u10E3\u10E4\u10D8\u10E1 \u10DA\u10DD\u10D8\u10D0\u10DA\u10E3\u10E0\u10DD\u10D1\u10D0\u10E1.","\u10EF\u10D2\u10E3\u10E4\u10E3\u10E0\u10D8 \u10E4\u10D4\u10DC\u10DD\u10DB\u10D4\u10DC\u10D4\u10D1\u10D8: \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E4\u10D0\u10E1\u10D8\u10DA\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0 (\u10DB\u10D0\u10E0\u10E2\u10D8\u10D5\u10D8 \u10D0\u10DB\u10DD\u10EA\u10D0\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E3\u10D9\u10D4\u10D7 \u10E8\u10D4\u10E1\u10E0\u10E3\u10DA\u10D4\u10D1\u10D0 \u10D3\u10D0\u10D9\u10D5\u10D8\u10E0\u10D5\u10D4\u10D1\u10D8\u10E1\u10D0\u10E1), \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10DA\u10DD\u10E3\u10E4\u10D8\u10DC\u10D2\u10D8 (\u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D8 \u10DB\u10E3\u10E8\u10D0\u10DD\u10D1\u10D0 \u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10E8\u10D8), \u10EF\u10D2\u10E3\u10E4\u10E3\u10E0\u10D8 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0 (\u10E8\u10D4\u10D9\u10E0\u10E3\u10DA\u10D8 \u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10D8 \u10D7\u10E0\u10D2\u10E3\u10DC\u10D0\u10D5\u10D4\u10DC \u10D2\u10D0\u10DC\u10E1\u10EE\u10D5\u10D0\u10D5\u10D4\u10D1\u10E3\u10DA \u10D0\u10D6\u10E0\u10E1), \u10D3\u10D4\u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10E3\u10D0\u10EA\u10D8\u10D0 (\u10D0\u10DC\u10DD\u10DC\u10D8\u10DB\u10E3\u10E0\u10DD\u10D1\u10D0 \u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10D7\u10D5\u10D8\u10D7\u10E8\u10D4\u10D2\u10DC\u10D4\u10D1\u10D0\u10E1).","\u10EA\u10E0\u10E3\u10E0\u10EC\u10DB\u10D4\u10DC\u10D0 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E1\u10E2\u10D4\u10E0\u10D4\u10DD\u10E2\u10D8\u10DE\u10D4\u10D1\u10E1 (\u10E0\u10EC\u10DB\u10D4\u10DC\u10D0\u10E1), \u10EC\u10D8\u10DC\u10D0\u10E1\u10EC\u10D0\u10E0\u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D0\u10E1 (\u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10E1) \u10D3\u10D0 \u10D3\u10D8\u10E1\u10D9\u10E0\u10D8\u10DB\u10D8\u10DC\u10D0\u10EA\u10D8\u10D0\u10E1 (\u10E5\u10EA\u10D4\u10D5\u10D0\u10E1). \u10DB\u10EA\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0 \u10EF\u10D2\u10E3\u10E4\u10D7\u10D0\u10E8\u10DD\u10E0\u10D8\u10E1\u10D8 \u10D9\u10DD\u10DC\u10E2\u10D0\u10E5\u10E2\u10D8\u10D7, \u10E0\u10DD\u10D3\u10D4\u10E1\u10D0\u10EA \u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10E1 \u10D0\u10E5\u10D5\u10D7 \u10D7\u10D0\u10DC\u10D0\u10D1\u10D0\u10E0\u10D8 \u10E1\u10E2\u10D0\u10E2\u10E3\u10E1\u10D8 \u10D3\u10D0 \u10D8\u10D6\u10D8\u10D0\u10E0\u10D4\u10D1\u10D4\u10DC \u10E1\u10D0\u10D4\u10E0\u10D7\u10DD \u10DB\u10D8\u10D6\u10DC\u10D4\u10D1\u10E1.","\u10D2\u10D0\u10E0\u10D4\u10E8\u10D4 \u10DE\u10D8\u10E0\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8 (\u10D3\u10D0\u10E0\u10DA\u10D8 \u10D3\u10D0 \u10DA\u10D0\u10E2\u10D0\u10DC\u10D4): \u10E0\u10D0\u10EA \u10E3\u10E4\u10E0\u10DD \u10DB\u10D4\u10E2\u10D8 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10D0, \u10DB\u10D8\u10D7 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D8\u10D0 \u10D0\u10DA\u10D1\u10D0\u10D7\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB \u10D5\u10D8\u10DC\u10DB\u10D4 \u10D3\u10D0\u10D4\u10EE\u10DB\u10D0\u10E0\u10D4\u10D1\u10D0 \u10E1\u10EE\u10D5\u10D0\u10E1. \u10D2\u10D0\u10DB\u10DD\u10EC\u10D5\u10D4\u10E3\u10DA\u10D8\u10D0 \u10DE\u10D0\u10E1\u10E3\u10EE\u10D8\u10E1\u10DB\u10D2\u10D4\u10D1\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D3\u10D8\u10E4\u10E3\u10D6\u10D8\u10D8\u10D7\u10D0 \u10D3\u10D0 \u10DE\u10DA\u10E3\u10E0\u10D0\u10DA\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D8\u10D2\u10DC\u10DD\u10E0\u10D8\u10E0\u10D4\u10D1\u10D8\u10D7."],ru:["\u0422\u0435\u043E\u0440\u0438\u044F \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438: \u041C\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u043C \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0434\u0440\u0443\u0433\u0438\u0445 \u043B\u044E\u0434\u0435\u0439 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0434\u0438\u0441\u043F\u043E\u0437\u0438\u0446\u0438\u043E\u043D\u043D\u044B\u0435 (\u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C) \u0438\u043B\u0438 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 (\u0441\u0440\u0435\u0434\u0430) \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438. \u0424\u0443\u043D\u0434\u0430\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u0430\u044F \u043E\u0448\u0438\u0431\u043A\u0430 \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438: \u043F\u0440\u0438 \u043E\u0446\u0435\u043D\u043A\u0435 \u0434\u0440\u0443\u0433\u0438\u0445 \u043C\u044B \u043F\u0435\u0440\u0435\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u043C \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0438 \u043D\u0435\u0434\u043E\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u043C \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438.","\u041A\u043E\u043D\u0444\u043E\u0440\u043C\u043D\u043E\u0441\u0442\u044C (\u0410\u0448): \u041B\u044E\u0434\u0438 \u0441\u043E\u0433\u043B\u0430\u0448\u0430\u044E\u0442\u0441\u044F \u0441 \u044F\u0432\u043D\u043E \u043D\u0435\u0432\u0435\u0440\u043D\u044B\u043C \u043E\u0442\u0432\u0435\u0442\u043E\u043C, \u0447\u0442\u043E\u0431\u044B \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0433\u0440\u0443\u043F\u043F\u0435, \u043F\u0440\u0438\u043C\u0435\u0440\u043D\u043E \u0432 37% \u0441\u043B\u0443\u0447\u0430\u0435\u0432. \u0423\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0441 \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C \u0433\u0440\u0443\u043F\u043F\u044B (\u0434\u043E ~5) \u0438 \u0435\u0434\u0438\u043D\u043E\u0434\u0443\u0448\u0438\u0435\u043C.","\u041F\u043E\u0441\u043B\u0443\u0448\u0430\u043D\u0438\u0435 (\u041C\u0438\u043B\u0433\u0440\u0430\u043C): 65% \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u043E\u0432 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u043B\u0438, \u043F\u043E \u0438\u0445 \u043C\u043D\u0435\u043D\u0438\u044E, \u0441\u043C\u0435\u0440\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0443\u0434\u0430\u0440\u044B \u0442\u043E\u043A\u043E\u043C \u043F\u043E \u0443\u043A\u0430\u0437\u0430\u043D\u0438\u044E \u0430\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442\u043D\u043E\u0433\u043E \u043B\u0438\u0446\u0430. \u0410\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442, \u0431\u043B\u0438\u0437\u043E\u0441\u0442\u044C \u0438 \u043B\u0435\u0433\u0438\u0442\u0438\u043C\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0432\u044B\u0448\u0430\u043B\u0438 \u043F\u043E\u0441\u043B\u0443\u0448\u0430\u043D\u0438\u0435.","\u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0439 \u0434\u0438\u0441\u0441\u043E\u043D\u0430\u043D\u0441 (\u0424\u0435\u0441\u0442\u0438\u043D\u0433\u0435\u0440): \u041A\u043E\u0433\u0434\u0430 \u043D\u0430\u0448\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0440\u0435\u0447\u0430\u0442 \u043D\u0430\u0448\u0438\u043C \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u0438\u044F\u043C, \u043C\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u043C \u0434\u0438\u0441\u043A\u043E\u043C\u0444\u043E\u0440\u0442 \u0438 \u043C\u0435\u043D\u044F\u0435\u043C \u0441\u0432\u043E\u0438 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u0442\u0430\u043A, \u0447\u0442\u043E\u0431\u044B \u043E\u043D\u0438 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u043B\u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044E. \u041E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442, \u043F\u043E\u0447\u0435\u043C\u0443 \u0440\u0438\u0442\u0443\u0430\u043B\u044B \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0438\u044F \u043F\u043E\u0432\u044B\u0448\u0430\u044E\u0442 \u043B\u043E\u044F\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043A \u0433\u0440\u0443\u043F\u043F\u0435.","\u0413\u0440\u0443\u043F\u043F\u043E\u0432\u044B\u0435 \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u044B: \u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u0444\u0430\u0441\u0438\u043B\u0438\u0442\u0430\u0446\u0438\u044F (\u043B\u0443\u0447\u0448\u0435\u0435 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u043F\u0440\u043E\u0441\u0442\u044B\u0445 \u0437\u0430\u0434\u0430\u0447 \u043F\u0440\u0438 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0438), \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u043B\u0435\u043D\u043E\u0441\u0442\u044C (\u043C\u0435\u043D\u044C\u0448\u0435 \u0443\u0441\u0438\u043B\u0438\u0439 \u043F\u0440\u0438 \u0440\u0430\u0431\u043E\u0442\u0435 \u0432 \u0433\u0440\u0443\u043F\u043F\u0435), \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 (\u0441\u043F\u043B\u043E\u0447\u0435\u043D\u043D\u044B\u0435 \u0433\u0440\u0443\u043F\u043F\u044B \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0442 \u0438\u043D\u0430\u043A\u043E\u043C\u044B\u0441\u043B\u0438\u0435), \u0434\u0435\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F (\u0430\u043D\u043E\u043D\u0438\u043C\u043D\u043E\u0441\u0442\u044C \u0441\u043D\u0438\u0436\u0430\u0435\u0442 \u0441\u0430\u043C\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435).","\u041F\u0440\u0435\u0434\u0440\u0430\u0441\u0441\u0443\u0434\u043A\u0438 \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0442 \u0441\u0442\u0435\u0440\u0435\u043E\u0442\u0438\u043F\u044B (\u0443\u0431\u0435\u0436\u0434\u0435\u043D\u0438\u044F), \u043F\u0440\u0435\u0434\u0443\u0431\u0435\u0436\u0434\u0435\u043D\u0438\u044F (\u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438) \u0438 \u0434\u0438\u0441\u043A\u0440\u0438\u043C\u0438\u043D\u0430\u0446\u0438\u044E (\u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435). \u0421\u043D\u0438\u0436\u0430\u044E\u0442\u0441\u044F \u0437\u0430 \u0441\u0447\u0435\u0442 \u043C\u0435\u0436\u0433\u0440\u0443\u043F\u043F\u043E\u0432\u043E\u0433\u043E \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u0430, \u043A\u043E\u0433\u0434\u0430 \u0433\u0440\u0443\u043F\u043F\u044B \u0438\u043C\u0435\u044E\u0442 \u0440\u0430\u0432\u043D\u044B\u0439 \u0441\u0442\u0430\u0442\u0443\u0441 \u0438 \u043E\u0431\u0449\u0438\u0435 \u0446\u0435\u043B\u0438.","\u042D\u0444\u0444\u0435\u043A\u0442 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F (\u0414\u0430\u0440\u043B\u0438 \u0438 \u041B\u0430\u0442\u0430\u043D\u0435): \u0427\u0435\u043C \u0431\u043E\u043B\u044C\u0448\u0435 \u043B\u044E\u0434\u0435\u0439 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442, \u0442\u0435\u043C \u043C\u0435\u043D\u044C\u0448\u0435 \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0441\u0442\u044C \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043A\u0442\u043E-\u0442\u043E \u043F\u043E\u043C\u043E\u0436\u0435\u0442. \u0412\u044B\u0437\u0432\u0430\u043D\u043E \u0440\u0430\u0437\u043C\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0438 \u043F\u043B\u044E\u0440\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043E\u043C."],hy:["\u0531\u057F\u0580\u056B\u0562\u0578\u0582\u0581\u056B\u0561\u0575\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0544\u0565\u0576\u0584 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0565\u0576\u0584 \u0578\u0582\u0580\u056B\u0577\u0576\u0565\u0580\u056B \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568\u055D \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0565\u056C\u0578\u057E \u0564\u056B\u057D\u057A\u0578\u0566\u056B\u0581\u056B\u0578\u0576\u0561\u056C (\u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576) \u056F\u0561\u0574 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u0561\u0575\u056B\u0576 (\u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580) \u0561\u057F\u0580\u056B\u0562\u0578\u0582\u057F\u0576\u0565\u0580\u0568: \u0531\u057F\u0580\u056B\u0562\u0578\u0582\u0581\u056B\u0561\u0575\u056B \u0570\u056B\u0574\u0576\u0561\u0580\u0561\u0580 \u057D\u056D\u0561\u056C. \u0578\u0582\u0580\u056B\u0577\u0576\u0565\u0580\u056B\u0576 \u0564\u0561\u057F\u0565\u056C\u056B\u057D \u0574\u0565\u0576\u0584 \u0563\u0565\u0580\u0561\u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574 \u0565\u0576\u0584 \u0561\u0576\u0571\u0568 \u0587 \u0569\u0565\u0580\u0561\u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574 \u0565\u0576\u0584 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u0568:","\u0540\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0531\u0577). \u0544\u0561\u0580\u0564\u056B\u056F \u0570\u0561\u0574\u0561\u0571\u0561\u0575\u0576\u0578\u0582\u0574 \u0565\u0576 \u0561\u056F\u0576\u0570\u0561\u0575\u057F \u057D\u056D\u0561\u056C \u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u056B \u0570\u0565\u057F\u055D \u056D\u0574\u0562\u056B\u0576 \u0570\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580 \u0564\u0565\u057A\u0584\u0565\u0580\u056B \u0574\u0578\u057F 37%-\u0578\u0582\u0574: \u0544\u0565\u056E\u0561\u0576\u0578\u0582\u0574 \u0567 \u056D\u0574\u0562\u056B \u0579\u0561\u0583\u056B (\u0574\u056B\u0576\u0579\u0587 ~5) \u0587 \u0574\u056B\u0561\u0571\u0561\u0575\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0565\u057F:","\u0540\u0576\u0561\u0566\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0544\u056B\u056C\u0563\u0580\u0561\u0574). \u0544\u0561\u057D\u0576\u0561\u056F\u056B\u0581\u0576\u0565\u0580\u056B 65%-\u0568 \u0570\u0561\u057D\u0581\u0580\u0565\u056C \u0567 \u056B\u0580\u0565\u0576\u0581 \u056F\u0561\u0580\u056E\u056B\u0584\u0578\u057E \u0574\u0561\u0570\u0561\u0581\u0578\u0582 \u0567\u056C\u0565\u056F\u057F\u0580\u0561\u056F\u0561\u0576 \u0581\u0576\u0581\u0578\u0582\u0574\u0576\u0565\u0580, \u0565\u0580\u0562 \u0570\u0580\u0561\u0570\u0561\u0576\u0563\u057E\u0565\u056C \u0567 \u0570\u0565\u0572\u056B\u0576\u0561\u056F\u0561\u057E\u0578\u0580 \u0561\u0576\u0571\u056B \u056F\u0578\u0572\u0574\u056B\u0581: \u0540\u0565\u0572\u056B\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0574\u0578\u057F\u056B\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u056C\u0565\u0563\u056B\u057F\u056B\u0574\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0580\u0565\u056C \u0565\u0576 \u0570\u0576\u0561\u0566\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:","\u053F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0564\u056B\u057D\u0578\u0576\u0561\u0576\u057D (\u0556\u0565\u057D\u057F\u056B\u0576\u0563\u0565\u0580). \u0535\u0580\u0562 \u0574\u0565\u0580 \u0563\u0578\u0580\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0570\u0561\u056F\u0561\u057D\u0578\u0582\u0574 \u0565\u0576 \u0574\u0565\u0580 \u0570\u0561\u0574\u0578\u0566\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B\u0576, \u0574\u0565\u0576\u0584 \u0561\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0565\u0576\u0584 \u0566\u0563\u0578\u0582\u0574 \u0587 \u0583\u0578\u056D\u0578\u0582\u0574 \u0574\u0565\u0580 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584\u0568 \u0574\u0565\u0580 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B\u0576 \u0570\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580: \u0532\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u0578\u0582 \u0565\u0576 \u0571\u0565\u057C\u0576\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056E\u0565\u057D\u0565\u0580\u0568 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u056C\u0578\u0575\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:","\u053D\u0574\u0562\u0561\u0575\u056B\u0576 \u0565\u0580\u0587\u0578\u0582\u0575\u0569\u0576\u0565\u0580. \u054D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0586\u0561\u057D\u056B\u056C\u056B\u057F\u0561\u0581\u056B\u0561 (\u0570\u0565\u0577\u057F \u0561\u057C\u0561\u057B\u0561\u0564\u0580\u0561\u0576\u0584\u0576\u0565\u0580\u056B \u0561\u057E\u0565\u056C\u056B \u056C\u0561\u057E \u056F\u0561\u057F\u0561\u0580\u0578\u0582\u0574 \u0564\u056B\u057F\u0565\u056C\u056B\u057D), \u054D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0561\u0576\u0563\u0578\u0580\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u056D\u0574\u0562\u0565\u0580\u0578\u0582\u0574 \u0561\u057E\u0565\u056C\u056B \u0584\u056B\u0579 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584), \u053D\u0574\u0562\u0561\u0575\u056B\u0576 \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u0561\u0574\u0561\u056D\u0574\u0562\u057E\u0561\u056E \u056D\u0574\u0562\u0565\u0580\u0568 \u0573\u0576\u0577\u0578\u0582\u0574 \u0565\u0576 \u0561\u0575\u056C\u0561\u056D\u0578\u0570\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568), \u0534\u0565\u056B\u0576\u0564\u056B\u057E\u056B\u0564\u0578\u0582\u0561\u0581\u056B\u0561 (\u0561\u0576\u0561\u0576\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u056B\u0576\u0584\u0576\u0561\u0563\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568):","\u0546\u0561\u056D\u0561\u057A\u0561\u0577\u0561\u0580\u0574\u0578\u0582\u0576\u0584\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u056F\u0561\u0580\u056E\u0580\u0561\u057F\u056B\u057A\u0565\u0580 (\u0570\u0561\u0574\u0578\u0566\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580), \u056F\u0561\u0576\u056D\u0561\u056F\u0561\u056C \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584 (\u0564\u056B\u0580\u0584\u0578\u0580\u0578\u0577\u0578\u0582\u0574) \u0587 \u056D\u057F\u0580\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E): \u0546\u057E\u0561\u0566\u0578\u0582\u0574 \u0567 \u0574\u056B\u057B\u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u0577\u0583\u0574\u0561\u0576 \u0574\u056B\u057B\u0578\u0581\u0578\u057E, \u0565\u0580\u0562 \u056D\u0574\u0562\u0565\u0580\u0576 \u0578\u0582\u0576\u0565\u0576 \u0570\u0561\u057E\u0561\u057D\u0561\u0580 \u056F\u0561\u0580\u0563\u0561\u057E\u056B\u0573\u0561\u056F \u0587 \u056F\u056B\u057D\u0578\u0582\u0574 \u0565\u0576 \u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0576\u057A\u0561\u057F\u0561\u056F\u0576\u0565\u0580:","\u053F\u0578\u0572\u0574\u0576\u0561\u056F\u056B \u0564\u056B\u057F\u0578\u0580\u0564\u056B \u0567\u0586\u0565\u056F\u057F (\u0534\u0561\u0580\u056C\u056B \u0587 \u053C\u0561\u057F\u0561\u0576\u0565). \u0548\u0580\u0584\u0561\u0576 \u0577\u0561\u057F \u0574\u0561\u0580\u0564 \u0567 \u0576\u0565\u0580\u056F\u0561, \u0561\u0575\u0576\u0584\u0561\u0576 \u0584\u056B\u0579 \u0570\u0561\u057E\u0561\u0576\u0561\u056F\u0561\u0576 \u0567, \u0578\u0580 \u0578\u0580\u0587\u0567 \u0574\u0565\u056F\u0568 \u056F\u0585\u0563\u0576\u056B: \u0531\u057C\u0561\u057B\u0561\u0576\u0578\u0582\u0574 \u0567 \u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0561\u057F\u057E\u0578\u0582\u0569\u0575\u0561\u0576 \u0581\u0580\u0574\u0561\u0576 \u0587 \u0562\u0561\u0566\u0574\u0561\u056F\u0561\u0580\u056E\u0561\u056F\u0561\u0576 \u0561\u0576\u057F\u0565\u0572\u0575\u0561\u056F\u0578\u0582\u0569\u0575\u0561\u0576 \u057A\u0561\u057F\u0573\u0561\u057C\u0578\u057E:"],az:["Attribusiya n\u0259z\u0259riyy\u0259si: Ba\u015Fqalar\u0131n\u0131n davran\u0131\u015Flar\u0131n\u0131 \u015F\u0259xsi x\xFCsusiyy\u0259tl\u0259r (\u015F\u0259xsiyy\u0259t) v\u0259 ya situasiya (m\xFChit) faktorlar\u0131ndan istifad\u0259 ed\u0259r\u0259k izah edirik. Fundamental attribusiya x\u0259tas\u0131: ba\u015Fqalar\u0131n\u0131 m\xFChakim\u0259 ed\u0259rk\u0259n \u015F\u0259xsiyy\u0259ti h\u0259ddind\u0259n art\u0131q d\u0259r\u0259c\u0259d\u0259, v\u0259ziyy\u0259tl\u0259ri is\u0259 az qiym\u0259tl\u0259ndiririk.","Uy\u011Funla\u015Fma (Asch): \u0130nsanlar qrupa uy\u011Funla\u015Fmaq \xFC\xE7\xFCn hallar\u0131n t\u0259xmin\u0259n 37%-ind\u0259 a\xE7\u0131q-a\u015Fkar yanl\u0131\u015F cavabla raz\u0131la\u015F\u0131rlar. Qrup \xF6l\xE7\xFCs\xFC (~5-\u0259 q\u0259d\u0259r) v\u0259 yekdillikl\u0259 art\u0131r.","\u0130ta\u0259t (Milgram): \u0130\u015Ftirak\xE7\u0131lar\u0131n 65%-i bir avtoritet fiqur t\u0259r\u0259find\u0259n idar\u0259 olunduqda \xF6l\xFCmc\xFCl oldu\u011Funa inand\u0131qlar\u0131 elektrik \u015Foku verdil\u0259r. N\xFCfuz, yax\u0131nl\u0131q v\u0259 qanunilik ita\u0259tkarl\u0131\u011F\u0131 art\u0131rd\u0131.","Koqnitiv dissonans (Festinger): H\u0259r\u0259k\u0259tl\u0259rimiz inanclar\u0131m\u0131zla ziddiyy\u0259t t\u0259\u015Fkil etdikd\u0259, diskomfort hiss edirik v\u0259 davran\u0131\u015Flar\u0131m\u0131za uy\u011Funla\u015Fmaq \xFC\xE7\xFCn m\xFCnasib\u0259timizi d\u0259yi\u015Firik. Niy\u0259 q\u0259bul rituallar\u0131n\u0131n qrup s\u0259daq\u0259tini art\u0131rd\u0131\u011F\u0131n\u0131 izah edir.","Qrup fenomenl\u0259ri: Sosial asanla\u015Fd\u0131rma (izl\u0259n\u0259rk\u0259n asan tap\u015F\u0131r\u0131qlar\u0131 daha yax\u015F\u0131 yerin\u0259 yetirm\u0259k), Sosial t\u0259nb\u0259llik (qruplarda daha az i\u015Fl\u0259m\u0259k), Qrup d\xFC\u015F\xFCnc\u0259si (vahid qruplar f\u0259rqli fikri basd\u0131r\u0131r), Deindividuasiya (anonimlik \xF6z\xFCn\xFCd\u0259rki azald\u0131r).","Q\u0259r\u0259z stereotipl\u0259r (inanclar), q\u0259r\u0259zl\u0259r (m\xFCnasib\u0259tl\u0259r) v\u0259 ayr\u0131-se\xE7kilikd\u0259n (davran\u0131\u015Flar) ibar\u0259tdir. Qruplar b\u0259rab\u0259r statusa malik olduqda v\u0259 \xFCmumi m\u0259qs\u0259dl\u0259ri payla\u015Fd\u0131qda qruplararas\u0131 t\u0259mas yolu il\u0259 azal\u0131r.","\u015Eahid effekti (Darley v\u0259 Latan\xE9): Daha \xE7ox insan i\u015Ftirak etdikd\u0259, kimins\u0259 k\xF6m\u0259k etm\u0259 ehtimal\u0131 bir o q\u0259d\u0259r azd\u0131r. M\u0259suliyy\u0259tin yay\u0131lmas\u0131 v\u0259 pl\xFCralistik c\u0259hal\u0259td\u0259n yaran\u0131r."]},funFact:{en:`Zimbardo's Stanford Prison Experiment (1971) was meant to last 2 weeks but was stopped after just 6 days because "guards" became sadistic and "prisoners" showed signs of psychological breakdown \u2014 demonstrating the power of situational forces on behavior.`,ka:"\u10D6\u10D8\u10DB\u10D1\u10D0\u10E0\u10D3\u10DD\u10E1 \u10E1\u10E2\u10D4\u10DC\u10E4\u10DD\u10E0\u10D3\u10D8\u10E1 \u10EA\u10D8\u10EE\u10D8\u10E1 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10D8\u10DB\u10D4\u10DC\u10E2\u10D8 2 \u10D9\u10D5\u10D8\u10E0\u10D0 \u10E3\u10DC\u10D3\u10D0 \u10D2\u10D0\u10D2\u10E0\u10EB\u10D4\u10DA\u10D4\u10D1\u10E3\u10DA\u10D8\u10E7\u10DD, \u10DB\u10D0\u10D2\u10E0\u10D0\u10DB 6 \u10D3\u10E6\u10D4\u10E8\u10D8 \u10E8\u10D4\u10EC\u10E7\u10D3\u10D0 \u201E\u10D6\u10D4\u10D3\u10D0\u10DB\u10EE\u10D4\u10D3\u10D5\u10D4\u10DA\u10D4\u10D1\u10D8\u10E1\u201C \u10E1\u10D0\u10D3\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD.",ru:"\u0421\u0442\u044D\u043D\u0444\u043E\u0440\u0434\u0441\u043A\u0438\u0439 \u0442\u044E\u0440\u0435\u043C\u043D\u044B\u0439 \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442 \u0417\u0438\u043C\u0431\u0430\u0440\u0434\u043E (1971) \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u043B \u0434\u043B\u0438\u0442\u044C\u0441\u044F 2 \u043D\u0435\u0434\u0435\u043B\u0438, \u043D\u043E \u0431\u044B\u043B \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D \u0432\u0441\u0435\u0433\u043E \u0447\u0435\u0440\u0435\u0437 6 \u0434\u043D\u0435\u0439 \u0438\u0437-\u0437\u0430 \u0441\u0430\u0434\u0438\u0437\u043C\u0430 \xAB\u043E\u0445\u0440\u0430\u043D\u043D\u0438\u043A\u043E\u0432\xBB.",hy:"\u0536\u056B\u0574\u0562\u0561\u0580\u0564\u0578\u0575\u056B \u054D\u0569\u0565\u0576\u0586\u0578\u0580\u0564\u056B \u0562\u0561\u0576\u057F\u0561\u0575\u056B\u0576 \u0583\u0578\u0580\u0571\u0568 \u057A\u0565\u057F\u0584 \u0567 \u057F\u0587\u0565\u0580 2 \u0577\u0561\u0562\u10D0\u0569, \u0562\u0561\u0575\u0581 \u0564\u0561\u0564\u0561\u0580\u0565\u0581\u057E\u0565\u0581 \u0568\u0576\u0564\u0561\u0574\u0565\u0576\u0568 6 \u0585\u0580 \u0570\u0565\u057F\u0578\u055D \xAB\u057A\u0561\u0570\u0561\u056F\u10D4\u10D1\u10D8\u10E1\xBB \u057D\u0561\u0564\u056B\u057D\u057F\u10E3\u10E0\u10D8 \u057E\u0561\u0580\u0584\u056B \u057A\u0561\u057F\u0573\u0561\u057C\u0578\u057E:",az:'Zimbardo-nun Stanford H\u0259bsxana Eksperimenti 2 h\u0259ft\u0259 davam etm\u0259li idi, lakin "m\xFChafiz\u0259\xE7il\u0259rin" sadistl\u0259\u015Fm\u0259si s\u0259b\u0259bind\u0259n c\u0259mi 6 g\xFCnd\u0259n sonra dayand\u0131r\u0131ld\u0131.'},realWorld:{en:'Understanding conformity and obedience explains everything from workplace culture ("nobody questions the boss") to historical atrocities. Modern organizations use these insights to create psychological safety \u2014 environments where people feel safe to speak up.',ka:"\u10D9\u10DD\u10DC\u10E4\u10DD\u10E0\u10DB\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DB\u10DD\u10E0\u10E9\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10D2\u10D4\u10D1\u10D0 \u10EE\u10E1\u10DC\u10D8\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0\u10E4\u10D4\u10E0\u10E1 - \u10D3\u10D0\u10EC\u10E7\u10D4\u10D1\u10E3\u10DA\u10D8 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D8\u10D3\u10D0\u10DC, \u10D3\u10D0\u10DB\u10D7\u10D0\u10D5\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10E1\u10E2\u10DD\u10E0\u10D8\u10E3\u10DA\u10D8 \u10D3\u10D0\u10DC\u10D0\u10E8\u10D0\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10D7.",ru:"\u041F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043A\u043E\u043D\u0444\u043E\u0440\u043C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043F\u043E\u0441\u043B\u0443\u0448\u0430\u043D\u0438\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0432\u0441\u0435: \u043E\u0442 \u0440\u0430\u0431\u043E\u0447\u0435\u0439 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B \u0434\u043E \u0438\u0441\u0442\u043E\u0440\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0437\u043B\u043E\u0434\u0435\u044F\u043D\u0438\u0439.",hy:"\u0540\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0570\u0576\u0561\u0566\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0561\u0576 \u0568\u0574\u0562\u057C\u0576\u0578\u0582\u0574\u0568 \u0562\u0561\u0581\u0561\u057F\u0580\u0578\u0582\u0574 \u0567 \u0561\u0574\u0565\u0576 \u056B\u0576\u0579\u055D \u057D\u056F\u057D\u0561\u056E \u0561\u0577\u056D\u0561\u057F\u0561\u057E\u0561\u0575\u0580\u056B \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u056B\u0581 \u0574\u056B\u0576\u0579\u0587 \u057A\u0561\u057F\u0574\u0561\u056F\u0561\u0576 \u057E\u0561\u0575\u0580\u0561\u0563\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580:",az:"Uy\u011Funluq v\u0259 ita\u0259ti ba\u015Fa d\xFC\u015Fm\u0259k i\u015F yeri m\u0259d\u0259niyy\u0259tind\u0259n tutmu\u015F tarixi v\u0259h\u015Filikl\u0259r\u0259 q\u0259d\u0259r h\u0259r \u015Feyi izah edir."}},13:{title:{en:"Stress, Health, and Coping",ka:"\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8, \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0 \u10D3\u10D0 \u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D0",ru:"\u0421\u0442\u0440\u0435\u0441\u0441, \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u0435 \u0438 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u043D\u0438\u0435 \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u0435\u0439",hy:"\u054D\u0569\u0580\u0565\u057D, \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0570\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0578\u0582\u0574",az:"Stress, Sa\u011Flaml\u0131q v\u0259 M\xFCbariz\u0259"},description:{en:"How stress affects us and strategies to cope with it.",ka:"\u10E0\u10DD\u10D2\u10DD\u10E0 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10E1 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 \u10E9\u10D5\u10D4\u10DC\u10D6\u10D4 \u10D3\u10D0 \u10DB\u10D0\u10E1\u10D7\u10D0\u10DC \u10D2\u10D0\u10DB\u10D9\u10DA\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8.",ru:"\u041A\u0430\u043A \u0441\u0442\u0440\u0435\u0441\u0441 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u043D\u0430\u0441 \u0438 \u043A\u0430\u043A \u0441 \u043D\u0438\u043C \u0441\u043F\u0440\u0430\u0432\u0438\u0442\u044C\u0441\u044F.",hy:"\u053B\u0576\u0579\u057A\u0565\u057D \u0567 \u057D\u0569\u0580\u0565\u057D\u0568 \u0561\u0566\u0564\u0578\u0582\u0574 \u0574\u0565\u0566 \u057E\u0580\u0561 \u0587 \u0564\u0580\u0561 \u0564\u0565\u0574 \u057A\u0561\u0575\u0584\u0561\u0580\u056B \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580:",az:"Stress biz\u0259 nec\u0259 t\u0259sir edir v\u0259 bununla m\xFCbariz\u0259 strategiyalar\u0131."},keyTopics:{en:["Stress Response","Stressors","Coping Strategies","Health Psychology","Resilience"],ka:["\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0","\u10E1\u10E2\u10E0\u10D4\u10E1\u10DD\u10E0\u10D4\u10D1\u10D8","\u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8","\u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0","\u10D2\u10D0\u10DB\u10EB\u10DA\u10D4\u10DD\u10D1\u10D0"],ru:["\u0421\u0442\u0440\u0435\u0441\u0441\u043E\u0432\u0430\u044F \u0440\u0435\u0430\u043A\u0446\u0438\u044F","\u0421\u0442\u0440\u0435\u0441\u0441\u043E\u0440\u044B","\u0421\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u043D\u0438\u044F \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u0435\u0439","\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F","\u0423\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C"],hy:["\u054D\u0569\u0580\u0565\u057D\u056B \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584","\u054D\u0569\u0580\u0565\u057D\u0576\u0565\u0580","\u0540\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580","\u0531\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0543\u056F\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576"],az:["Stress cavab\u0131","Stressorlar","M\xFCbariz\u0259 Strategiyalar\u0131","Sa\u011Flaml\u0131q Psixologiyas\u0131","D\xF6z\xFCml\xFCl\xFCk"]},summary:{en:"Stress is the body's physiological and psychological response to perceived threats, demands, or challenges in the environment. This chapter examines how stress affects health and well-being, beginning with Selye's General Adaptation Syndrome (GAS), which describes three stages: alarm (activation of the fight-or-flight response with adrenaline and cortisol release), resistance (the body adapts to sustained stress), and exhaustion (resources are depleted, leaving the body vulnerable to illness). It distinguishes between eustress (positive, motivating stress) and distress (harmful, overwhelming stress), and examines how major life events, daily hassles, and catastrophes all contribute to the stress burden. The chapter covers the emerging field of psychoneuroimmunology, revealing how chronic stress suppresses the immune system and increases vulnerability to cardiovascular disease, depression, and accelerated cellular aging. Coping strategies are explored in depth \u2014 problem-focused coping (taking direct action) versus emotion-focused coping (managing emotional reactions) \u2014 alongside protective factors including social support (the single most powerful buffer against stress), regular exercise, mindfulness and meditation, perceived control, and optimistic thinking.",ka:"\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 \u10D0\u10E0\u10D8\u10E1 \u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10DB\u10D8\u10E1 \u10E4\u10D8\u10D6\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E8\u10D8 \u10D0\u10E0\u10E1\u10D4\u10D1\u10E3\u10DA \u10D0\u10E6\u10E5\u10DB\u10E3\u10DA \u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10D4\u10D4\u10D1\u10D6\u10D4, \u10DB\u10DD\u10D7\u10EE\u10DD\u10D5\u10DC\u10D4\u10D1\u10E1\u10D0 \u10D7\u10E3 \u10D2\u10D0\u10DB\u10DD\u10EC\u10D5\u10D4\u10D5\u10D4\u10D1\u10D6\u10D4. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10E1 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10D9\u10D4\u10D7\u10D8\u10DA\u10D3\u10E6\u10D4\u10DD\u10D1\u10D0\u10D6\u10D4, \u10D3\u10D0\u10EC\u10E7\u10D4\u10D1\u10E3\u10DA\u10D8 \u10E1\u10D4\u10DA\u10D8\u10D4\u10E1 \u10D6\u10DD\u10D2\u10D0\u10D3\u10D8 \u10D0\u10D3\u10D0\u10DE\u10E2\u10D0\u10EA\u10D8\u10D8\u10E1 \u10E1\u10D8\u10DC\u10D3\u10E0\u10DD\u10DB\u10D8\u10D7 (GAS), \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E6\u10EC\u10D4\u10E0\u10E1 \u10E1\u10D0\u10DB \u10E1\u10E2\u10D0\u10D3\u10D8\u10D0\u10E1: \u10D2\u10D0\u10DC\u10D2\u10D0\u10E8\u10D8 (\u201E\u10D1\u10E0\u10EB\u10DD\u10DA\u10D0 \u10D0\u10DC \u10D2\u10D0\u10E5\u10EA\u10D4\u10D5\u10D8\u10E1\u201C \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D8\u10E1 \u10D2\u10D0\u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D4\u10D1\u10D0 \u10D0\u10D3\u10E0\u10D4\u10DC\u10D0\u10DA\u10D8\u10DC\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D9\u10DD\u10E0\u10E2\u10D8\u10D6\u10DD\u10DA\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10E7\u10DD\u10E4\u10D8\u10D7), \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD\u10D1\u10D0 (\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10DB\u10D8 \u10D4\u10D2\u10E3\u10D4\u10D1\u10D0 \u10D2\u10D0\u10EE\u10D0\u10DC\u10D2\u10E0\u10EB\u10DA\u10D8\u10D5\u10D4\u10D1\u10E3\u10DA \u10E1\u10E2\u10E0\u10D4\u10E1\u10E1) \u10D3\u10D0 \u10D2\u10D0\u10DB\u10DD\u10E4\u10D8\u10E2\u10D5\u10D0 (\u10E0\u10D4\u10E1\u10E3\u10E0\u10E1\u10D4\u10D1\u10D8 \u10D8\u10EC\u10E3\u10E0\u10D4\u10D1\u10D0, \u10E0\u10D0\u10EA \u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10DB\u10E1 \u10D3\u10D0\u10D0\u10D5\u10D0\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10DB\u10DD\u10EC\u10E7\u10D5\u10DA\u10D0\u10D3\u10E1 \u10EE\u10D3\u10D8\u10E1). \u10D8\u10E1 \u10D2\u10D0\u10DC\u10D0\u10E1\u10EE\u10D5\u10D0\u10D5\u10D4\u10D1\u10E1 \u10D4\u10D5\u10E1\u10E2\u10E0\u10D4\u10E1\u10E1 (\u10D3\u10D0\u10D3\u10D4\u10D1\u10D8\u10D7\u10D8, \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10E3\u10E0\u10D8 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8) \u10D3\u10D0 \u10D3\u10D8\u10E1\u10E2\u10E0\u10D4\u10E1\u10E1 (\u10DB\u10D0\u10D5\u10DC\u10D4, \u10D3\u10D0\u10DB\u10D7\u10E0\u10D2\u10E3\u10DC\u10D5\u10D4\u10DA\u10D8 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8) \u10D3\u10D0 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10E3\u10EC\u10E7\u10DD\u10D1\u10E1 \u10EE\u10D4\u10DA\u10E1 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1\u10D4\u10E3\u10DA\u10D8 \u10DB\u10DD\u10D5\u10DA\u10D4\u10DC\u10D4\u10D1\u10D8, \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0\u10D8 \u10E1\u10D8\u10E0\u10D7\u10E3\u10DA\u10D4\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D9\u10D0\u10E2\u10D0\u10E1\u10E2\u10E0\u10DD\u10E4\u10D4\u10D1\u10D8 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10E2\u10D5\u10D8\u10E0\u10D7\u10D8\u10E1 \u10D6\u10E0\u10D3\u10D0\u10E1. \u10D7\u10D0\u10D5\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DC\u10D4\u10D8\u10E0\u10DD\u10D8\u10DB\u10E3\u10DC\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10D3 \u10E1\u10E4\u10D4\u10E0\u10DD\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D7\u10E0\u10D2\u10E3\u10DC\u10D0\u10D5\u10E1 \u10E5\u10E0\u10DD\u10DC\u10D8\u10D9\u10E3\u10DA\u10D8 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 \u10D8\u10DB\u10E3\u10DC\u10E3\u10E0 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10E1 \u10D3\u10D0 \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D2\u10E3\u10DA-\u10E1\u10D8\u10E1\u10EE\u10DA\u10EB\u10D0\u10E0\u10E6\u10D5\u10D7\u10D0 \u10D3\u10D0\u10D0\u10D5\u10D0\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1, \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E3\u10EF\u10E0\u10D4\u10D3\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10E9\u10E5\u10D0\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D3\u10D0\u10D1\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E0\u10D8\u10E1\u10D9\u10E1. \u10D3\u10D4\u10E2\u10D0\u10DA\u10E3\u10E0\u10D0\u10D3\u10D0\u10D0 \u10D2\u10D0\u10DC\u10EE\u10D8\u10DA\u10E3\u10DA\u10D8 \u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8 \u2014 \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D0\u10D6\u10D4 \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D0 (\u10DE\u10D8\u10E0\u10D3\u10D0\u10DE\u10D8\u10E0\u10D8 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D0) \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D6\u10D4 \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D8\u10E1 (\u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D0\u10E0\u10D7\u10D5\u10D0) \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2 \u2014 \u10D8\u10E1\u10D4\u10D7 \u10D3\u10D0\u10DB\u10EA\u10D0\u10D5 \u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D4\u10D1\u10D7\u10D0\u10DC \u10D4\u10E0\u10D7\u10D0\u10D3, \u10E0\u10DD\u10D2\u10DD\u10E0\u10D8\u10EA\u10D0\u10D0 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10ED\u10D4\u10E0\u10D0 (\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10E1\u10D0\u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10EB\u10DA\u10D8\u10D4\u10E0\u10D8 \u10D1\u10E3\u10E4\u10D4\u10E0\u10D8), \u10E0\u10D4\u10D2\u10E3\u10DA\u10D0\u10E0\u10E3\u10DA\u10D8 \u10D5\u10D0\u10E0\u10EF\u10D8\u10E8\u10D8, \u10DB\u10D0\u10D8\u10DC\u10D3\u10E4\u10E3\u10DA\u10DC\u10D4\u10E1\u10D8 \u10D3\u10D0 \u10DB\u10D4\u10D3\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0, \u10D0\u10E6\u10E5\u10DB\u10E3\u10DA\u10D8 \u10D9\u10DD\u10DC\u10E2\u10E0\u10DD\u10DA\u10D8 \u10D3\u10D0 \u10DD\u10DE\u10E2\u10D8\u10DB\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0.",ru:"\u0421\u0442\u0440\u0435\u0441\u0441 \u2014 \u044D\u0442\u043E \u0444\u0438\u0437\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0438 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0440\u0435\u0430\u043A\u0446\u0438\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C\u0430 \u043D\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0435 \u0443\u0433\u0440\u043E\u0437\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u0438\u043B\u0438 \u0432\u044B\u0437\u043E\u0432\u044B \u0432 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043A\u0430\u043A \u0441\u0442\u0440\u0435\u0441\u0441 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u0435 \u0438 \u0431\u043B\u0430\u0433\u043E\u043F\u043E\u043B\u0443\u0447\u0438\u0435, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043E\u0431\u0449\u0435\u0433\u043E \u0430\u0434\u0430\u043F\u0442\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0438\u043D\u0434\u0440\u043E\u043C\u0430 \u0421\u0435\u043B\u044C\u0435 (GAS), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0442\u0440\u0438 \u0441\u0442\u0430\u0434\u0438\u0438: \u0441\u0442\u0430\u0434\u0438\u044F \u0442\u0440\u0435\u0432\u043E\u0433\u0438 (\u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u0440\u0435\u0430\u043A\u0446\u0438\u0438 \xAB\u0431\u0435\u0439 \u0438\u043B\u0438 \u0431\u0435\u0433\u0438\xBB \u0441 \u0432\u044B\u0431\u0440\u043E\u0441\u043E\u043C \u0430\u0434\u0440\u0435\u043D\u0430\u043B\u0438\u043D\u0430 \u0438 \u043A\u043E\u0440\u0442\u0438\u0437\u043E\u043B\u0430), \u0441\u0442\u0430\u0434\u0438\u044F \u0441\u043E\u043F\u0440\u043E\u0442\u0438\u0432\u043B\u0435\u043D\u0438\u044F (\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C \u0430\u0434\u0430\u043F\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043A \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 \u0441\u0442\u0440\u0435\u0441\u0441\u0443) \u0438 \u0441\u0442\u0430\u0434\u0438\u044F \u0438\u0441\u0442\u043E\u0449\u0435\u043D\u0438\u044F (\u0440\u0435\u0441\u0443\u0440\u0441\u044B \u0438\u0441\u0442\u043E\u0449\u0430\u044E\u0442\u0441\u044F, \u0434\u0435\u043B\u0430\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C \u0443\u044F\u0437\u0432\u0438\u043C\u044B\u043C \u0434\u043B\u044F \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439). \u041F\u0440\u043E\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u044D\u0443\u0441\u0442\u0440\u0435\u0441\u0441\u043E\u043C (\u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C, \u043C\u043E\u0442\u0438\u0432\u0438\u0440\u0443\u044E\u0449\u0438\u043C \u0441\u0442\u0440\u0435\u0441\u0441\u043E\u043C) \u0438 \u0434\u0438\u0441\u0442\u0440\u0435\u0441\u0441\u043E\u043C (\u0432\u0440\u0435\u0434\u043D\u044B\u043C, \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u043C \u0441\u0442\u0440\u0435\u0441\u0441\u043E\u043C), \u0430 \u0442\u0430\u043A\u0436\u0435 \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442\u0441\u044F, \u043A\u0430\u043A \u043A\u0440\u0443\u043F\u043D\u044B\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u0445\u043B\u043E\u043F\u043E\u0442\u044B \u0438 \u043A\u0430\u0442\u0430\u0441\u0442\u0440\u043E\u0444\u044B \u0432\u043D\u043E\u0441\u044F\u0442 \u0432\u043A\u043B\u0430\u0434 \u0432 \u0441\u0442\u0440\u0435\u0441\u0441\u043E\u0432\u0443\u044E \u043D\u0430\u0433\u0440\u0443\u0437\u043A\u0443. \u0413\u043B\u0430\u0432\u0430 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u044E\u0449\u0443\u044E\u0441\u044F \u043E\u0431\u043B\u0430\u0441\u0442\u044C \u043F\u0441\u0438\u0445\u043E\u043D\u0435\u0439\u0440\u043E\u0438\u043C\u043C\u0443\u043D\u043E\u043B\u043E\u0433\u0438\u0438, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044F, \u043A\u0430\u043A \u0445\u0440\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0441\u0442\u0440\u0435\u0441\u0441 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u043C\u043C\u0443\u043D\u043D\u0443\u044E \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u0438 \u043F\u043E\u0432\u044B\u0448\u0430\u0435\u0442 \u0443\u044F\u0437\u0432\u0438\u043C\u043E\u0441\u0442\u044C \u043A \u0441\u0435\u0440\u0434\u0435\u0447\u043D\u043E-\u0441\u043E\u0441\u0443\u0434\u0438\u0441\u0442\u044B\u043C \u0437\u0430\u0431\u043E\u043B\u0435\u0432\u0430\u043D\u0438\u044F\u043C, \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438 \u0438 \u0443\u0441\u043A\u043E\u0440\u0435\u043D\u043D\u043E\u043C\u0443 \u0441\u0442\u0430\u0440\u0435\u043D\u0438\u044E \u043A\u043B\u0435\u0442\u043E\u043A. \u041F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u043D\u0438\u044F \u0441\u0442\u0440\u0435\u0441\u0441\u0430 \u2014 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u043D\u043E-\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043A\u043E\u043F\u0438\u043D\u0433 (\u043F\u0440\u0438\u043D\u044F\u0442\u0438\u0435 \u043F\u0440\u044F\u043C\u044B\u0445 \u043C\u0435\u0440) \u0432 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0432\u0435\u0441 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E-\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u043C\u0443 (\u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u044D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u0440\u0435\u0430\u043A\u0446\u0438\u044F\u043C\u0438) \u2014 \u043D\u0430\u0440\u044F\u0434\u0443 \u0441 \u0437\u0430\u0449\u0438\u0442\u043D\u044B\u043C\u0438 \u0444\u0430\u043A\u0442\u043E\u0440\u0430\u043C\u0438, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u043C\u0438 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0443\u044E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0443 (\u0441\u0430\u043C\u044B\u0439 \u043C\u043E\u0449\u043D\u044B\u0439 \u0431\u0443\u0444\u0435\u0440 \u043F\u0440\u043E\u0442\u0438\u0432 \u0441\u0442\u0440\u0435\u0441\u0441\u0430), \u0440\u0435\u0433\u0443\u043B\u044F\u0440\u043D\u044B\u0435 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0443\u043F\u0440\u0430\u0436\u043D\u0435\u043D\u0438\u044F, \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0438 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044E, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0439 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u0438 \u043E\u043F\u0442\u0438\u043C\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435.",hy:"\u054D\u0569\u0580\u0565\u057D\u0568 \u0585\u0580\u0563\u0561\u0576\u056B\u0566\u0574\u056B \u0586\u056B\u0566\u056B\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u0587 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0576 \u0567 \u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0578\u0582\u0574 \u0568\u0576\u056F\u0561\u056C\u057E\u0578\u0572 \u057D\u057A\u0561\u057C\u0576\u0561\u056C\u056B\u0584\u0576\u0565\u0580\u056B\u0576, \u057A\u0561\u0570\u0561\u0576\u057B\u0576\u0565\u0580\u056B\u0576 \u056F\u0561\u0574 \u0574\u0561\u0580\u057F\u0561\u0570\u0580\u0561\u057E\u0565\u0580\u0576\u0565\u0580\u056B\u0576: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u057D\u0569\u0580\u0565\u057D\u0568 \u0561\u0566\u0564\u0578\u0582\u0574 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0562\u0561\u0580\u0565\u056F\u0565\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561\u055D \u057D\u056F\u057D\u0561\u056E \u054D\u0565\u056C\u0575\u0565\u056B \u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0570\u0561\u0580\u0574\u0561\u0580\u057E\u0578\u0572\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u056D\u057F\u0561\u0576\u056B\u0577\u056B\u0581 (GAS), \u0578\u0580\u0568 \u0576\u056F\u0561\u0580\u0561\u0563\u0580\u0578\u0582\u0574 \u0567 \u0565\u0580\u0565\u0584 \u0583\u0578\u0582\u056C. \u057F\u0561\u0563\u0576\u0561\u057A (\xAB\u056F\u057C\u057E\u0565\u056C \u056F\u0561\u0574 \u0583\u0561\u056D\u0579\u0565\u056C\xBB \u057C\u0565\u0561\u056F\u0581\u056B\u0561\u0575\u056B \u0561\u056F\u057F\u056B\u057E\u0561\u0581\u0578\u0582\u0574\u055D \u0561\u0564\u0580\u0565\u0576\u0561\u056C\u056B\u0576\u056B \u0587 \u056F\u0578\u0580\u057F\u056B\u0566\u0578\u056C\u056B \u0561\u0580\u057F\u0561\u0566\u0561\u057F\u0574\u0561\u0574\u0562), \u0564\u056B\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0585\u0580\u0563\u0561\u0576\u056B\u0566\u0574\u0568 \u0570\u0561\u0580\u0574\u0561\u0580\u057E\u0578\u0582\u0574 \u0567 \u057F\u0587\u0561\u056F\u0561\u0576 \u057D\u0569\u0580\u0565\u057D\u056B\u0576) \u0587 \u0570\u0575\u0578\u0582\u056E\u0578\u0582\u0574 (\u057C\u0565\u057D\u0578\u0582\u0580\u057D\u0576\u0565\u0580\u0568 \u057D\u057A\u0561\u057C\u057E\u0578\u0582\u0574 \u0565\u0576\u055D \u0585\u0580\u0563\u0561\u0576\u056B\u0566\u0574\u0568 \u056D\u0578\u0581\u0565\u056C\u056B \u0564\u0561\u0580\u0571\u0576\u0565\u056C\u0578\u057E \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0576\u056F\u0561\u057F\u0574\u0561\u0574\u0562)\u0589 \u0531\u0575\u0576 \u057F\u0561\u0580\u0562\u0565\u0580\u0561\u056F\u0578\u0582\u0574 \u0567 \u0567\u0578\u0582\u057D\u0569\u0580\u0565\u057D\u0568 (\u0564\u0580\u0561\u056F\u0561\u0576, \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u0576\u0578\u0572 \u057D\u0569\u0580\u0565\u057D) \u0587 \u0564\u056B\u057D\u0569\u0580\u0565\u057D\u0568 (\u057E\u0576\u0561\u057D\u0561\u056F\u0561\u0580, \u0573\u0576\u0577\u0578\u0572 \u057D\u0569\u0580\u0565\u057D) \u0587 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u056F\u0575\u0561\u0576\u0584\u056B \u056D\u0578\u0577\u0578\u0580 \u056B\u0580\u0561\u0564\u0561\u0580\u0571\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0561\u057C\u0585\u0580\u0575\u0561 \u0570\u0578\u0563\u057D\u0565\u0580\u0568 \u0587 \u0561\u0572\u0565\u057F\u0576\u0565\u0580\u0568 \u0576\u057A\u0561\u057D\u057F\u0578\u0582\u0574 \u057D\u0569\u0580\u0565\u057D\u056B \u056E\u0561\u0576\u0580\u0561\u0562\u0565\u057C\u0576\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576\u0568: \u0533\u056C\u0578\u0582\u056D\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0570\u0578\u0563\u0565\u0576\u0565\u0575\u0580\u0578\u056B\u0574\u0578\u0582\u0576\u0578\u056C\u0578\u0563\u056B\u0561\u0575\u056B \u0566\u0561\u0580\u0563\u0561\u0581\u0578\u0572 \u0578\u056C\u0578\u0580\u057F\u0568\u055D \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0565\u056C\u0578\u057E, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u0584\u0580\u0578\u0576\u056B\u056F\u0561\u056F\u0561\u0576 \u057D\u0569\u0580\u0565\u057D\u0568 \u0573\u0576\u0577\u0578\u0582\u0574 \u056B\u0574\u0578\u0582\u0576\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568 \u0587 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u056D\u0578\u0581\u0565\u056C\u056B\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u057D\u056B\u0580\u057F-\u0561\u0576\u0578\u0569\u0561\u0575\u056B\u0576 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B, \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0587 \u0562\u057B\u057B\u0561\u0575\u056B\u0576 \u0561\u0580\u0561\u0563\u0561\u0581\u057E\u0561\u056E \u056E\u0565\u0580\u0561\u0581\u0574\u0561\u0576 \u0576\u056F\u0561\u057F\u0574\u0561\u0574\u0562: \u0544\u0561\u0576\u0580\u0561\u0574\u0561\u057D\u0576\u0578\u0580\u0565\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u057E\u0578\u0582\u0574 \u0565\u0576 \u0570\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568\u055D \u056D\u0576\u0564\u0580\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0570\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0578\u0582\u0574 (\u0578\u0582\u0572\u0572\u0561\u056F\u056B \u0563\u0578\u0580\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0564\u056B\u0574\u0565\u056C\u0568) \u0568\u0576\u0564\u0564\u0565\u0574 \u0570\u0578\u0582\u0575\u0566\u0565\u0580\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0570\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0574\u0561\u0576 (\u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0561\u0575\u056B\u0576 \u0570\u0561\u056F\u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0578\u0582\u0574)\u055D \u0566\u0578\u0582\u0563\u0578\u0580\u0564\u057E\u0561\u056E \u057A\u0561\u0577\u057F\u057A\u0561\u0576\u056B\u0579 \u0563\u0578\u0580\u056E\u0578\u0576\u0576\u0565\u0580\u0578\u057E, \u0578\u0580\u0578\u0576\u0584 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0565\u0576 \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0561\u057B\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 (\u057D\u0569\u0580\u0565\u057D\u056B \u0564\u0565\u0574 \u0561\u0574\u0565\u0576\u0561\u0570\u0566\u0578\u0580 \u0562\u0578\u0582\u0586\u0565\u0580\u0568), \u056F\u0561\u0576\u0578\u0576\u0561\u057E\u0578\u0580 \u057E\u0561\u0580\u056A\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568, \u0563\u056B\u057F\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0574\u0565\u0564\u056B\u057F\u0561\u0581\u056B\u0561\u0576, \u0568\u0576\u056F\u0561\u056C\u057E\u0578\u0572 \u057E\u0565\u0580\u0561\u0570\u057D\u056F\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u056C\u0561\u057E\u0561\u057F\u0565\u057D\u0561\u056F\u0561\u0576 \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:",az:"Stress orqanizmin \u0259traf m\xFChitd\u0259ki t\u0259hdidl\u0259r\u0259, t\u0259l\u0259bl\u0259r\u0259 v\u0259 ya \xE7\u0259tinlikl\u0259r\u0259 verdiyi fizioloji v\u0259 psixoloji reaksiyad\u0131r. Bu f\u0259sil stressin sa\u011Flaml\u0131\u011Fa v\u0259 rifaha nec\u0259 t\u0259sir etdiyini ara\u015Fd\u0131r\u0131r v\u0259 \xFC\xE7 m\u0259rh\u0259l\u0259ni t\u0259svir ed\u0259n Selyenin \xDCmumi Adaptasiya Sindromu (GAS) il\u0259 ba\u015Flay\u0131r: h\u0259y\u0259can (adrenalin v\u0259 kortizol ifraz\u0131 il\u0259 'd\xF6y\xFC\u015F ya da qa\xE7' reaksiyas\u0131n\u0131n aktivl\u0259\u015Fm\u0259si), m\xFCqavim\u0259t (b\u0259d\u0259nin davaml\u0131 stress\u0259 uy\u011Funla\u015Fmas\u0131) v\u0259 t\xFCk\u0259nm\u0259 (resurslar\u0131n t\xFCk\u0259n\u0259r\u0259k orqanizmi x\u0259st\u0259likl\u0259r\u0259 qar\u015F\u0131 h\u0259ssasla\u015Fd\u0131rmas\u0131). F\u0259sil eustress (m\xFCsb\u0259t, motivasiyaedici stress) v\u0259 distress (z\u0259r\u0259rli, \xFCst\xFCn g\u0259l\u0259n stress) aras\u0131nda f\u0259rq qoyur v\u0259 \u0259h\u0259miyy\u0259tli h\u0259yat hadis\u0259l\u0259rinin, g\xFCnd\u0259lik narahatl\u0131qlar\u0131n v\u0259 f\u0259lak\u0259tl\u0259rin stress y\xFCk\xFCn\u0259 nec\u0259 t\u0259sir etdiyini ara\u015Fd\u0131r\u0131r. F\u0259sil h\u0259m\xE7inin xroniki stressin immun sistemini nec\u0259 basd\u0131rd\u0131\u011F\u0131n\u0131 v\u0259 \xFCr\u0259k-damar x\u0259st\u0259likl\u0259rin\u0259, depressiyaya v\u0259 s\xFCr\u0259tl\u0259nmi\u015F h\xFCceyr\u0259 ya\u015Flanmas\u0131na qar\u015F\u0131 h\u0259ssasl\u0131\u011F\u0131 nec\u0259 art\u0131rd\u0131\u011F\u0131n\u0131 a\u015Fkar ed\u0259r\u0259k inki\u015Faf ed\u0259n psixoneyroimmunologiya sah\u0259sini \u0259hat\u0259 edir. \xD6hd\u0259sind\u0259n g\u0259lm\u0259 strategiyalar\u0131 d\u0259rind\u0259n ara\u015Fd\u0131r\u0131l\u0131r \u2014 problemm\u0259rk\u0259zli m\xFCbariz\u0259 (birba\u015Fa t\u0259dbir g\xF6rm\u0259k) emosiyam\u0259rk\u0259zli m\xFCbariz\u0259y\u0259 (emosional reaksiyalar\u0131 idar\u0259 etm\u0259k) qar\u015F\u0131 \u2014 v\u0259 eyni zamanda sosial d\u0259st\u0259k (stress\u0259 qar\u015F\u0131 \u0259n g\xFCcl\xFC bufer), m\xFCnt\u0259z\u0259m m\u0259\u015Fq, f\u0259rqind\u0259lik v\u0259 meditasiya, q\u0259bul edil\u0259n n\u0259zar\u0259t v\u0259 optimist d\xFC\u015F\xFCnc\u0259 kimi qoruyucu amill\u0259r t\u0259qdim edilir."},keyPoints:{en:["Stress is the body's response to any perceived threat or demand. Eustress (positive) helps performance; distress (negative) harms health.","Selye's General Adaptation Syndrome (GAS): Alarm (fight-or-flight activated) \u2192 Resistance (body adapts to ongoing stress) \u2192 Exhaustion (resources depleted, vulnerability to illness).","The fight-or-flight response: the sympathetic nervous system releases adrenaline and cortisol, increasing heart rate, blood pressure, and blood sugar. Useful for short-term threats, harmful when chronic.","Major stressors: catastrophes, significant life changes (Holmes-Rahe scale), and daily hassles. Research shows daily hassles (traffic, deadlines) may affect health more than major events.","Chronic stress suppresses the immune system (psychoneuroimmunology), increases risk of cardiovascular disease, contributes to depression and anxiety, and accelerates cellular aging.","Coping strategies: Problem-focused coping (taking action to solve the problem) works best for controllable situations. Emotion-focused coping (managing feelings) is better for uncontrollable situations.","Protective factors: Social support (the #1 buffer against stress), exercise (reduces cortisol), mindfulness and meditation (reduces amygdala reactivity), perceived control (believing you can influence outcomes), and optimism."],ka:["\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 \u10D0\u10E0\u10D8\u10E1 \u10E1\u10EE\u10D4\u10E3\u10DA\u10D8\u10E1 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0 \u10DC\u10D4\u10D1\u10D8\u10E1\u10DB\u10D8\u10D4\u10E0 \u10D0\u10E6\u10E5\u10DB\u10E3\u10DA \u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10D4\u10D6\u10D4 \u10D0\u10DC \u10DB\u10DD\u10D7\u10EE\u10DD\u10D5\u10DC\u10D0\u10D6\u10D4. \u10D4\u10D5\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 (\u10D3\u10D0\u10D3\u10D4\u10D1\u10D8\u10D7\u10D8) \u10D4\u10EE\u10DB\u10D0\u10E0\u10D4\u10D1\u10D0 \u10DB\u10E3\u10E8\u10D0\u10DD\u10D1\u10D0\u10E1; \u10D3\u10D8\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 (\u10E3\u10D0\u10E0\u10E7\u10DD\u10E4\u10D8\u10D7\u10D8) \u10D6\u10D8\u10D0\u10DC\u10E1 \u10D0\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1.","\u10E1\u10D4\u10DA\u10D8\u10D4\u10E1 \u10D6\u10DD\u10D2\u10D0\u10D3\u10D8 \u10D0\u10D3\u10D0\u10DE\u10E2\u10D0\u10EA\u10D8\u10D8\u10E1 \u10E1\u10D8\u10DC\u10D3\u10E0\u10DD\u10DB\u10D8 (GAS): \u10D2\u10D0\u10DC\u10D2\u10D0\u10E8\u10D8 (\u10D0\u10E5\u10E2\u10D8\u10E3\u10E0\u10D3\u10D4\u10D1\u10D0 \u201E\u10D1\u10E0\u10EB\u10DD\u10DA\u10D0-\u10D0\u10DC-\u10D2\u10D0\u10E5\u10EA\u10D4\u10D5\u10D0\u201C) \u2192 \u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD\u10D1\u10D0 (\u10E1\u10EE\u10D4\u10E3\u10DA\u10D8 \u10D0\u10D3\u10D0\u10DE\u10E2\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0 \u10DB\u10D8\u10DB\u10D3\u10D8\u10DC\u10D0\u10E0\u10D4 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D7\u10D0\u10DC) \u2192 \u10D2\u10D0\u10DB\u10DD\u10E4\u10D8\u10E2\u10D5\u10D0 (\u10E0\u10D4\u10E1\u10E3\u10E0\u10E1\u10D4\u10D1\u10D8 \u10D8\u10EC\u10E3\u10E0\u10D4\u10D1\u10D0, \u10D3\u10D0\u10D0\u10D5\u10D0\u10D3\u10D4\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10DB\u10DD\u10EC\u10E7\u10D5\u10DA\u10D0\u10D3\u10DD\u10D1\u10D0).","\u10D1\u10E0\u10EB\u10DD\u10DA\u10D8\u10E1 \u10D0\u10DC \u10D2\u10D0\u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10E0\u10D4\u10D0\u10E5\u10EA\u10D8\u10D0: \u10E1\u10D8\u10DB\u10DE\u10D0\u10D7\u10D8\u10D9\u10E3\u10E0\u10D8 \u10DC\u10D4\u10E0\u10D5\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0 \u10D2\u10D0\u10DB\u10DD\u10E7\u10DD\u10E4\u10E1 \u10D0\u10D3\u10E0\u10D4\u10DC\u10D0\u10DA\u10D8\u10DC\u10E1 \u10D3\u10D0 \u10D9\u10DD\u10E0\u10E2\u10D8\u10D6\u10DD\u10DA\u10E1, \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D2\u10E3\u10DA\u10D8\u10E1\u10EA\u10D4\u10DB\u10D0\u10E1, \u10D0\u10E0\u10E2\u10D4\u10E0\u10D8\u10E3\u10DA \u10EC\u10DC\u10D4\u10D5\u10D0\u10E1 \u10D3\u10D0 \u10E1\u10D8\u10E1\u10EE\u10DA\u10E8\u10D8 \u10E8\u10D0\u10E5\u10E0\u10D8\u10E1 \u10D3\u10DD\u10DC\u10D4\u10E1. \u10E1\u10D0\u10E1\u10D0\u10E0\u10D2\u10D4\u10D1\u10DA\u10DD\u10D0 \u10DB\u10DD\u10D9\u10DA\u10D4\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8 \u10E1\u10D0\u10E4\u10E0\u10D7\u10EE\u10D4\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1, \u10DB\u10D0\u10D5\u10DC\u10D4\u10D0 \u10E5\u10E0\u10DD\u10DC\u10D8\u10D9\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1\u10D0\u10E1.","\u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10E1\u10E2\u10E0\u10D4\u10E1\u10DD\u10E0\u10D4\u10D1\u10D8: \u10D9\u10D0\u10E2\u10D0\u10E1\u10E2\u10E0\u10DD\u10E4\u10D4\u10D1\u10D8, \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1\u10D4\u10E3\u10DA\u10D8 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC\u10D8 \u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8 (\u10F0\u10DD\u10DA\u10DB\u10E1-\u10E0\u10D0\u10F0\u10D4\u10E1 \u10E1\u10D9\u10D0\u10DA\u10D0) \u10D3\u10D0 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0\u10D8 \u10E1\u10D8\u10E0\u10D7\u10E3\u10DA\u10D4\u10D4\u10D1\u10D8. \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0\u10DB\u10D0 \u10E1\u10D8\u10E0\u10D7\u10E3\u10DA\u10D4\u10D4\u10D1\u10DB\u10D0 (\u10E1\u10D0\u10EA\u10DD\u10D1\u10D4\u10D1\u10D8, \u10D3\u10D4\u10D3\u10DA\u10D0\u10D8\u10DC\u10D4\u10D1\u10D8) \u10E8\u10D4\u10D8\u10EB\u10DA\u10D4\u10D1\u10D0 \u10E3\u10E4\u10E0\u10DD \u10DB\u10D4\u10E2\u10D0\u10D3 \u10D8\u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10DD\u10E1 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0\u10D6\u10D4, \u10D5\u10D8\u10D3\u10E0\u10D4 \u10D3\u10D8\u10D3\u10DB\u10D0 \u10DB\u10DD\u10D5\u10DA\u10D4\u10DC\u10D4\u10D1\u10DB\u10D0.","\u10E5\u10E0\u10DD\u10DC\u10D8\u10D9\u10E3\u10DA\u10D8 \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8 \u10D7\u10E0\u10D2\u10E3\u10DC\u10D0\u10D5\u10E1 \u10D8\u10DB\u10E3\u10DC\u10E3\u10E0 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0\u10E1 (\u10E4\u10E1\u10D8\u10E5\u10DD\u10DC\u10D4\u10D8\u10E0\u10DD\u10D8\u10DB\u10E3\u10DC\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0), \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D2\u10E3\u10DA-\u10E1\u10D8\u10E1\u10EE\u10DA\u10EB\u10D0\u10E0\u10E6\u10D5\u10D7\u10D0 \u10D3\u10D0\u10D0\u10D5\u10D0\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10E0\u10D8\u10E1\u10D9\u10E1, \u10EE\u10D4\u10DA\u10E1 \u10E3\u10EC\u10E7\u10DD\u10D1\u10E1 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10E8\u10E4\u10DD\u10D7\u10D5\u10D0\u10E1, \u10D0\u10E9\u10E5\u10D0\u10E0\u10D4\u10D1\u10E1 \u10E3\u10EF\u10E0\u10D4\u10D3\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10D1\u10D4\u10E0\u10D4\u10D1\u10D0\u10E1.","\u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D8\u10E1 \u10E1\u10E2\u10E0\u10D0\u10E2\u10D4\u10D2\u10D8\u10D4\u10D1\u10D8: \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D0\u10D6\u10D4 \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D0 (\u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DC\u10EE\u10DD\u10E0\u10EA\u10D8\u10D4\u10DA\u10D4\u10D1\u10D0 \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10E1\u10D0\u10ED\u10E0\u10D4\u10DA\u10D0\u10D3) \u10E1\u10D0\u10E3\u10D9\u10D4\u10D7\u10D4\u10E1\u10DD\u10D3 \u10DB\u10E3\u10E8\u10D0\u10DD\u10D1\u10E1 \u10D9\u10DD\u10DC\u10E2\u10E0\u10DD\u10DA\u10D8\u10E0\u10D4\u10D1\u10D0\u10D3 \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10D4\u10D1\u10E8\u10D8. \u10D4\u10DB\u10DD\u10EA\u10D8\u10D0\u10D6\u10D4 \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D3\u10D0\u10EB\u10DA\u10D4\u10D5\u10D0 (\u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D0\u10E0\u10D7\u10D5\u10D0) \u10E3\u10D9\u10D4\u10D7\u10D4\u10E1\u10D8\u10D0 \u10E3\u10D9\u10DD\u10DC\u10E2\u10E0\u10DD\u10DA\u10DD \u10E1\u10D8\u10E2\u10E3\u10D0\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1.","\u10D3\u10D0\u10DB\u10EA\u10D0\u10D5\u10D8 \u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8: \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10ED\u10D4\u10E0\u10D0 (\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10E1\u10D0\u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD #1 \u10D1\u10E3\u10E4\u10D4\u10E0\u10D8), \u10D5\u10D0\u10E0\u10EF\u10D8\u10E8\u10D8 (\u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10D9\u10DD\u10E0\u10E2\u10D8\u10D6\u10DD\u10DA\u10E1), \u10DB\u10D0\u10D8\u10DC\u10D3\u10E4\u10E3\u10DA\u10DC\u10D4\u10E1\u10D8 \u10D3\u10D0 \u10DB\u10D4\u10D3\u10D8\u10E2\u10D0\u10EA\u10D8\u10D0 (\u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10D0\u10DB\u10D8\u10D2\u10D3\u10D0\u10DA\u10D0\u10E1 \u10E0\u10D4\u10D0\u10E5\u10E2\u10D8\u10E3\u10DA\u10DD\u10D1\u10D0\u10E1), \u10D0\u10E6\u10E5\u10DB\u10E3\u10DA\u10D8 \u10D9\u10DD\u10DC\u10E2\u10E0\u10DD\u10DA\u10D8 (\u10E0\u10EC\u10DB\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10E8\u10D4\u10D2\u10D8\u10EB\u10DA\u10D8\u10D0\u10D7 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0 \u10DB\u10DD\u10D0\u10EE\u10D3\u10D8\u10DC\u10DD\u10D7 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10D6\u10D4) \u10D3\u10D0 \u10DD\u10DE\u10E2\u10D8\u10DB\u10D8\u10D6\u10DB\u10D8."],ru:["\u0421\u0442\u0440\u0435\u0441\u0441 \u2014 \u044D\u0442\u043E \u0440\u0435\u0430\u043A\u0446\u0438\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C\u0430 \u043D\u0430 \u043B\u044E\u0431\u0443\u044E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u0443\u044E \u0443\u0433\u0440\u043E\u0437\u0443 \u0438\u043B\u0438 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0435. \u042D\u0443\u0441\u0442\u0440\u0435\u0441\u0441 (\u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439) \u0443\u043B\u0443\u0447\u0448\u0430\u0435\u0442 \u0440\u0430\u0431\u043E\u0442\u043E\u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C; \u0434\u0438\u0441\u0442\u0440\u0435\u0441\u0441 (\u043E\u0442\u0440\u0438\u0446\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439) \u0432\u0440\u0435\u0434\u0438\u0442 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044E.","\u041E\u0431\u0449\u0438\u0439 \u0430\u0434\u0430\u043F\u0442\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0439 \u0441\u0438\u043D\u0434\u0440\u043E\u043C \u0421\u0435\u043B\u044C\u0435 (GAS): \u0422\u0440\u0435\u0432\u043E\u0433\u0430 (\u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u0440\u0435\u0430\u043A\u0446\u0438\u0438 \xAB\u0431\u0435\u0439 \u0438\u043B\u0438 \u0431\u0435\u0433\u0438\xBB) \u2192 \u0421\u043E\u043F\u0440\u043E\u0442\u0438\u0432\u043B\u0435\u043D\u0438\u0435 (\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043C \u0430\u0434\u0430\u043F\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043A \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0441\u0442\u0440\u0435\u0441\u0441\u0443) \u2192 \u0418\u0441\u0442\u043E\u0449\u0435\u043D\u0438\u0435 (\u0440\u0435\u0441\u0443\u0440\u0441\u044B \u0438\u0441\u0442\u043E\u0449\u0430\u044E\u0442\u0441\u044F, \u0443\u044F\u0437\u0432\u0438\u043C\u043E\u0441\u0442\u044C \u043A \u0431\u043E\u043B\u0435\u0437\u043D\u044F\u043C).","\u0420\u0435\u0430\u043A\u0446\u0438\u044F \xAB\u0431\u0435\u0439 \u0438\u043B\u0438 \u0431\u0435\u0433\u0438\xBB: \u0441\u0438\u043C\u043F\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043D\u0435\u0440\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0432\u044B\u0434\u0435\u043B\u044F\u0435\u0442 \u0430\u0434\u0440\u0435\u043D\u0430\u043B\u0438\u043D \u0438 \u043A\u043E\u0440\u0442\u0438\u0437\u043E\u043B, \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u044F \u0447\u0430\u0441\u0442\u043E\u0442\u0443 \u0441\u0435\u0440\u0434\u0435\u0447\u043D\u044B\u0445 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0439, \u043A\u0440\u043E\u0432\u044F\u043D\u043E\u0435 \u0434\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0441\u0430\u0445\u0430\u0440\u0430 \u0432 \u043A\u0440\u043E\u0432\u0438. \u041F\u043E\u043B\u0435\u0437\u043D\u0430 \u043F\u0440\u0438 \u043A\u0440\u0430\u0442\u043A\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0443\u0433\u0440\u043E\u0437\u0430\u0445, \u0432\u0440\u0435\u0434\u043D\u0430, \u0435\u0441\u043B\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0445\u0440\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439.","\u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0441\u0442\u0440\u0435\u0441\u0441\u043E\u0440\u044B: \u043A\u0430\u0442\u0430\u0441\u0442\u0440\u043E\u0444\u044B, \u0437\u043D\u0430\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F (\u0448\u043A\u0430\u043B\u0430 \u0425\u043E\u043B\u043C\u0441\u0430-\u0420\u0430\u0433\u0435) \u0438 \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u043D\u0435\u043F\u0440\u0438\u044F\u0442\u043D\u043E\u0441\u0442\u0438. \u0418\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442, \u0447\u0442\u043E \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u0441\u0442\u0440\u0435\u0441\u0441\u044B (\u043F\u0440\u043E\u0431\u043A\u0438, \u0434\u0435\u0434\u043B\u0430\u0439\u043D\u044B) \u043C\u043E\u0433\u0443\u0442 \u0432\u043B\u0438\u044F\u0442\u044C \u043D\u0430 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u0435 \u0431\u043E\u043B\u044C\u0448\u0435, \u0447\u0435\u043C \u043A\u0440\u0443\u043F\u043D\u044B\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F.","\u0425\u0440\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0441\u0442\u0440\u0435\u0441\u0441 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u043C\u043C\u0443\u043D\u043D\u0443\u044E \u0441\u0438\u0441\u0442\u0435\u043C\u0443 (\u043F\u0441\u0438\u0445\u043E\u043D\u0435\u0439\u0440\u043E\u0438\u043C\u043C\u0443\u043D\u043E\u043B\u043E\u0433\u0438\u044F), \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0435\u0442 \u0440\u0438\u0441\u043A \u0441\u0435\u0440\u0434\u0435\u0447\u043D\u043E-\u0441\u043E\u0441\u0443\u0434\u0438\u0441\u0442\u044B\u0445 \u0437\u0430\u0431\u043E\u043B\u0435\u0432\u0430\u043D\u0438\u0439, \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u0435\u0442 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438 \u0438 \u0442\u0440\u0435\u0432\u043E\u0433\u0435, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0443\u0441\u043A\u043E\u0440\u044F\u0435\u0442 \u0441\u0442\u0430\u0440\u0435\u043D\u0438\u0435 \u043A\u043B\u0435\u0442\u043E\u043A.","\u0421\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u043D\u0438\u044F: \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u043D\u043E-\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043A\u043E\u043F\u0438\u043D\u0433 (\u043F\u0440\u0438\u043D\u044F\u0442\u0438\u0435 \u043C\u0435\u0440 \u0434\u043B\u044F \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B) \u043B\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0432 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u0445 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044F\u0445. \u042D\u043C\u043E\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u043E-\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043A\u043E\u043F\u0438\u043D\u0433 (\u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438) \u043B\u0443\u0447\u0448\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 \u0434\u043B\u044F \u043D\u0435\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u0445 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0439.","\u0417\u0430\u0449\u0438\u0442\u043D\u044B\u0435 \u0444\u0430\u043A\u0442\u043E\u0440\u044B: \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0430 (\u0431\u0443\u0444\u0435\u0440 \u21161 \u043E\u0442 \u0441\u0442\u0440\u0435\u0441\u0441\u0430), \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0443\u043F\u0440\u0430\u0436\u043D\u0435\u043D\u0438\u044F (\u0441\u043D\u0438\u0436\u0430\u044E\u0442 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u043A\u043E\u0440\u0442\u0438\u0437\u043E\u043B\u0430), \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0438 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F (\u0441\u043D\u0438\u0436\u0430\u044E\u0442 \u0440\u0435\u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u043C\u0438\u043D\u0434\u0430\u043B\u0435\u0432\u0438\u0434\u043D\u043E\u0433\u043E \u0442\u0435\u043B\u0430), \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0439 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C (\u0432\u0435\u0440\u0430 \u0432 \u0442\u043E, \u0447\u0442\u043E \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0432\u043B\u0438\u044F\u0442\u044C \u043D\u0430 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B) \u0438 \u043E\u043F\u0442\u0438\u043C\u0438\u0437\u043C."],hy:["\u054D\u0569\u0580\u0565\u057D\u0568 \u0574\u0561\u0580\u0574\u0576\u056B \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584\u0576 \u0567 \u0581\u0561\u0576\u056F\u0561\u0581\u0561\u056E \u0568\u0576\u056F\u0561\u056C\u057E\u0578\u0572 \u057D\u057A\u0561\u057C\u0576\u0561\u056C\u056B\u0584\u056B \u056F\u0561\u0574 \u057A\u0561\u0570\u0561\u0576\u057B\u056B: \u0537\u0578\u0582\u057D\u0569\u0580\u0565\u057D\u0568 (\u0564\u0580\u0561\u056F\u0561\u0576) \u0585\u0563\u0576\u0578\u0582\u0574 \u0567 \u056F\u0561\u057F\u0561\u0580\u0578\u0572\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576\u0568; \u0564\u056B\u057D\u0569\u0580\u0565\u057D\u0568 (\u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576) \u057E\u0576\u0561\u057D\u0578\u0582\u0574 \u0567 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576\u0568:","\u054D\u0565\u056C\u0575\u0565\u056B \u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0570\u0561\u0580\u0574\u0561\u0580\u057E\u0578\u0572\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u056D\u057F\u0561\u0576\u056B\u0577 (GAS). \u0561\u0570\u0561\u0566\u0561\u0576\u0563 (\u0574\u056B\u0561\u0576\u0578\u0582\u0574 \u0567 \xAB\u056F\u057C\u057E\u0565\u056C \u056F\u0561\u0574 \u0583\u0561\u056D\u0579\u0565\u056C\xBB \u057C\u0565\u0561\u056F\u0581\u056B\u0561\u0576) \u2192 \u0564\u056B\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0574\u0561\u0580\u0574\u056B\u0576\u0568 \u0570\u0561\u0580\u0574\u0561\u0580\u057E\u0578\u0582\u0574 \u0567 \u0577\u0561\u0580\u0578\u0582\u0576\u0561\u056F\u057E\u0578\u0572 \u057D\u0569\u0580\u0565\u057D\u056B\u0576) \u2192 \u0570\u0575\u0578\u0582\u056E\u0578\u0582\u0574 (\u057C\u0565\u057D\u0578\u0582\u0580\u057D\u0576\u0565\u0580\u0568 \u057D\u057A\u0561\u057C\u057E\u0561\u056E \u0565\u0576, \u056D\u0578\u0581\u0565\u056C\u056B\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0576\u056F\u0561\u057F\u0574\u0561\u0574\u0562):","\xAB\u053F\u057C\u057E\u0565\u056C \u056F\u0561\u0574 \u0583\u0561\u056D\u0579\u0565\u056C\xBB \u0561\u0580\u0571\u0561\u0563\u0561\u0576\u0584. \u057D\u056B\u0574\u057A\u0561\u0569\u056B\u056F \u0576\u0575\u0561\u0580\u0564\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568 \u0561\u0580\u057F\u0561\u0566\u0561\u057F\u0578\u0582\u0574 \u0567 \u0561\u0564\u0580\u0565\u0576\u0561\u056C\u056B\u0576 \u0587 \u056F\u0578\u0580\u057F\u056B\u0566\u0578\u056C, \u0578\u0580\u0578\u0576\u0584 \u0574\u0565\u056E\u0561\u0581\u0576\u0578\u0582\u0574 \u0565\u0576 \u057D\u0580\u057F\u056B \u0570\u0561\u0573\u0561\u056D\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0561\u0580\u0575\u0561\u0576 \u0573\u0576\u0577\u0578\u0582\u0574\u0568 \u0587 \u0561\u0580\u0575\u0561\u0576 \u0574\u0565\u057B \u0577\u0561\u0584\u0561\u0580\u056B \u0574\u0561\u056F\u0561\u0580\u0564\u0561\u056F\u0568: \u0555\u0563\u057F\u0561\u056F\u0561\u0580 \u0567 \u056F\u0561\u0580\u0573\u0561\u056A\u0561\u0574\u056F\u0565\u057F \u057D\u057A\u0561\u057C\u0576\u0561\u056C\u056B\u0584\u0576\u0565\u0580\u056B \u0564\u0565\u057A\u0584\u0578\u0582\u0574, \u057E\u0576\u0561\u057D\u0561\u056F\u0561\u0580 \u0567, \u0565\u0580\u0562 \u0561\u0575\u0576 \u0564\u0561\u057C\u0576\u0578\u0582\u0574 \u0567 \u0584\u0580\u0578\u0576\u056B\u056F:","\u0540\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057D\u0569\u0580\u0565\u057D\u0561\u0575\u056B\u0576 \u0563\u0578\u0580\u056E\u0578\u0576\u0576\u0565\u0580\u0568\u055D \u0561\u0572\u0565\u057F\u0576\u0565\u0580, \u056F\u0575\u0561\u0576\u0584\u056B \u0566\u0563\u0561\u056C\u056B \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 (\u0540\u0578\u056C\u0574\u057D-\u054C\u0561\u0570\u0565\u056B \u057D\u0561\u0576\u0564\u0572\u0561\u056F) \u0587 \u0561\u0574\u0565\u0576\u0585\u0580\u0575\u0561 \u0564\u056A\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580: \u0540\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0565\u0576 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0561\u057C\u0585\u0580\u0575\u0561 \u0570\u0578\u0563\u057D\u0565\u0580\u0568 (\u056D\u0581\u0561\u0576\u0578\u0582\u0574\u0576\u0565\u0580 \u057E\u0565\u0580\u057B\u0576\u0561\u056A\u0561\u0574\u056F\u0565\u057F\u0576\u0565\u0580) \u056F\u0561\u0580\u0578\u0572 \u0565\u0576 \u0561\u057E\u0565\u056C\u056B \u0577\u0561\u057F \u0561\u0566\u0564\u0565\u056C \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561, \u0584\u0561\u0576 \u056D\u0578\u0577\u0578\u0580 \u056B\u0580\u0561\u0564\u0561\u0580\u0571\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568:","\u0554\u0580\u0578\u0576\u056B\u056F \u057D\u0569\u0580\u0565\u057D\u0568 \u0573\u0576\u0577\u0578\u0582\u0574 \u0567 \u056B\u0574\u0578\u0582\u0576\u0561\u0575\u056B\u0576 \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563\u0568 (\u0570\u0578\u0563\u0565\u0576\u0565\u0575\u0580\u0578\u056B\u0574\u0578\u0582\u0576\u0578\u056C\u0578\u0563\u056B\u0561), \u0574\u0565\u056E\u0561\u0581\u0576\u0578\u0582\u0574 \u0567 \u057D\u056B\u057C\u057F-\u0561\u0576\u0578\u0569\u0561\u0575\u056B\u0576 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u057C\u056B\u057D\u056F\u0568, \u0576\u057A\u0561\u057D\u057F\u0578\u0582\u0574 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B\u0576 \u0587 \u0561\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0561\u0576\u0568 \u0587 \u0561\u0580\u0561\u0563\u0561\u0581\u0576\u0578\u0582\u0574 \u0562\u057B\u057B\u0561\u0575\u056B\u0576 \u056E\u0565\u0580\u0561\u0581\u0578\u0582\u0574\u0568:","\u0540\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0574\u0561\u0576 \u057C\u0561\u0566\u0574\u0561\u057E\u0561\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u056D\u0576\u0564\u0580\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0570\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0578\u0582\u0574\u0568 (\u0584\u0561\u0575\u056C\u0565\u0580 \u0571\u0565\u057C\u0576\u0561\u0580\u056F\u0565\u056C \u056D\u0576\u0564\u056B\u0580\u0568 \u056C\u0578\u0582\u056E\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580) \u056C\u0561\u057E\u0561\u0563\u0578\u0582\u0575\u0576\u057D \u0561\u0577\u056D\u0561\u057F\u0578\u0582\u0574 \u0567 \u057E\u0565\u0580\u0561\u0570\u057D\u056F\u057E\u0578\u0572 \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u0578\u0582\u0574: \u0540\u0578\u0582\u0575\u0566\u0565\u0580\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0570\u0561\u0572\u0569\u0561\u0570\u0561\u0580\u0578\u0582\u0574\u0568 (\u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0568 \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0565\u056C\u0568) \u0561\u057E\u0565\u056C\u056B \u056C\u0561\u057E \u0567 \u0561\u0576\u057E\u0565\u0580\u0561\u0570\u057D\u056F\u0565\u056C\u056B \u056B\u0580\u0561\u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u056B \u0570\u0561\u0574\u0561\u0580:","\u054A\u0561\u0577\u057F\u057A\u0561\u0576\u056B\u0579 \u0563\u0578\u0580\u056E\u0578\u0576\u0576\u0565\u0580. \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0561\u057B\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u057D\u0569\u0580\u0565\u057D\u056B \u0564\u0565\u0574 \u057A\u0561\u0575\u0584\u0561\u0580\u0578\u0572 \u0569\u056B\u057E 1 \u0562\u0578\u0582\u0586\u0565\u0580\u0568), \u057E\u0561\u0580\u056A\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 (\u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u056F\u0578\u0580\u057F\u056B\u0566\u0578\u056C\u0568), \u0578\u0582\u0577\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0574\u0565\u0564\u056B\u057F\u0561\u0581\u056B\u0561 (\u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u0561\u0574\u056B\u0563\u0564\u0561\u056C\u0561\u0575\u056B \u057C\u0565\u0561\u056F\u057F\u056B\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568), \u0568\u0576\u056F\u0561\u056C\u057E\u0578\u0572 \u057E\u0565\u0580\u0561\u0570\u057D\u056F\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0570\u0561\u057E\u0561\u057F\u0561\u056C\u0578\u057E, \u0578\u0580 \u0564\u0578\u0582\u0584 \u056F\u0561\u0580\u0578\u0572 \u0565\u0584 \u0561\u0566\u0564\u0565\u056C \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u057E\u0580\u0561) \u0587 \u056C\u0561\u057E\u0561\u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576:"],az:["Stress b\u0259d\u0259nin h\u0259r hans\u0131 t\u0259s\u0259vv\xFCr edil\u0259n t\u0259hl\xFCk\u0259 v\u0259 ya t\u0259l\u0259b\u0259 verdiyi cavabd\u0131r. Eustress (m\xFCsb\u0259t) performans\u0131 yax\u015F\u0131la\u015Fd\u0131r\u0131r; distress (m\u0259nfi) is\u0259 sa\u011Flaml\u0131\u011Fa z\u0259r\u0259r verir.","Selye-nin \xDCmumi Adaptasiya Sindromu (GAS): Siqnal (d\xF6y\xFC\u015F v\u0259 ya qa\xE7 reaksiyas\u0131 aktivl\u0259\u015Fir) \u2192 M\xFCqavim\u0259t (b\u0259d\u0259n davam ed\u0259n stress\u0259 uy\u011Funla\u015F\u0131r) \u2192 T\xFCk\u0259nm\u0259 (resurslar t\xFCk\u0259nir, x\u0259st\u0259likl\u0259r\u0259 qar\u015F\u0131 h\u0259ssasl\u0131q yaran\u0131r).","D\xF6y\xFC\u015F ya da qa\xE7 cavab\u0131: simpatik sinir sistemi adrenalin v\u0259 kortizol ifraz ed\u0259r\u0259k, \xFCr\u0259k d\xF6y\xFCnt\xFCs\xFCn\xFC, qan t\u0259zyiqini v\u0259 qan \u015F\u0259k\u0259rini art\u0131r\u0131r. Q\u0131sam\xFCdd\u0259tli t\u0259hdidl\u0259r \xFC\xE7\xFCn faydal\u0131d\u0131r, lakin xroniki olanda z\u0259r\u0259rlidir.","\u018Fsas stress faktorlar\u0131: f\u0259lak\u0259tl\u0259r, m\xFCh\xFCm h\u0259yat d\u0259yi\u015Fiklikl\u0259ri (Holms-Rahe miqyas\u0131) v\u0259 g\xFCnd\u0259lik \xE7\u0259tinlikl\u0259r. Ara\u015Fd\u0131rmalar g\xF6st\u0259rir ki, g\xFCnd\u0259lik \xE7\u0259tinlikl\u0259r (t\u0131xac, x\xFCsusi vaxt m\u0259hdudiyy\u0259tl\u0259ri) sa\u011Flaml\u0131\u011Fa m\xFCh\xFCm hadis\u0259l\u0259rd\u0259n daha \xE7ox t\u0259sir ed\u0259 bil\u0259r.","Xroniki stress immun sistemini z\u0259ifl\u0259dir (psixoneyroimmunologiya), \xFCr\u0259k-damar x\u0259st\u0259likl\u0259ri riskini art\u0131r\u0131r, depressiya v\u0259 narahatl\u0131\u011Fa k\xF6m\u0259k edir v\u0259 s\xFCr\u0259tl\u0259nmi\u015F h\xFCceyr\u0259 ya\u015Flanmas\u0131na s\u0259b\u0259b olur.","M\xFCbariz\u0259 strategiyalar\u0131: Problem\u0259 y\xF6n\u0259lmi\u015F m\xFCbariz\u0259 (problemi h\u0259ll etm\u0259k \xFC\xE7\xFCn t\u0259dbirl\u0259r g\xF6rm\u0259k) idar\u0259 oluna bil\u0259n v\u0259ziyy\u0259tl\u0259rd\u0259 \u0259n yax\u015F\u0131 n\u0259tic\u0259 verir. Emosiyaya y\xF6n\u0259lmi\u015F m\xFCbariz\u0259 (hissl\u0259rin idar\u0259 olunmas\u0131) n\u0259zar\u0259t edil\u0259 bilm\u0259y\u0259n v\u0259ziyy\u0259tl\u0259r \xFC\xE7\xFCn daha \u0259lveri\u015Flidir.","Qoruyucu amill\u0259r: Sosial d\u0259st\u0259k (stress\u0259 qar\u015F\u0131 1 n\xF6mr\u0259li bufer), m\u0259\u015Fq (kortizolu azald\u0131r), zehinlilik v\u0259 meditasiya (amiqdala reaksiyas\u0131n\u0131 azald\u0131r), q\u0259bul edil\u0259n n\u0259zar\u0259t (n\u0259tic\u0259l\u0259r\u0259 t\u0259sir ed\u0259 bil\u0259c\u0259yiniz\u0259 inanmaq) v\u0259 optimistlik."]},funFact:{en:'Laughing reduces cortisol by 39% and increases endorphins by 27%. Studies show that even anticipating a funny experience can reduce stress hormones. Hospitals now use "laughter therapy" with positive results.',ka:"\u10E1\u10D8\u10EA\u10D8\u10DA\u10D8 \u10D0\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10E1 \u10D9\u10DD\u10E0\u10E2\u10D8\u10D6\u10DD\u10DA\u10E1 39%-\u10D8\u10D7 \u10D3\u10D0 \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D4\u10DC\u10D3\u10DD\u10E0\u10E4\u10D8\u10DC\u10D4\u10D1\u10E1 27%-\u10D8\u10D7. \u10E1\u10D0\u10D0\u10D5\u10D0\u10D3\u10DB\u10E7\u10DD\u10E4\u10DD\u10D4\u10D1\u10D8 \u10D0\u10EE\u10DA\u10D0 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D4\u10DC \u201E\u10E1\u10D8\u10EA\u10D8\u10DA\u10D8\u10E1 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0\u10E1\u201C \u10D3\u10D0\u10D3\u10D4\u10D1\u10D8\u10D7\u10D8 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D4\u10D1\u10D8\u10D7.",ru:"\u0421\u043C\u0435\u0445 \u0441\u043D\u0438\u0436\u0430\u0435\u0442 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u043A\u043E\u0440\u0442\u0438\u0437\u043E\u043B\u0430 \u043D\u0430 39% \u0438 \u043F\u043E\u0432\u044B\u0448\u0430\u0435\u0442 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u044D\u043D\u0434\u043E\u0440\u0444\u0438\u043D\u043E\u0432 \u043D\u0430 27%. \u0411\u043E\u043B\u044C\u043D\u0438\u0446\u044B \u0442\u0435\u043F\u0435\u0440\u044C \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \xAB\u0441\u043C\u0435\u0445\u043E\u0442\u0435\u0440\u0430\u043F\u0438\u044E\xBB \u0441 \u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438.",hy:"\u053E\u056B\u056E\u0561\u0572\u0568 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0578\u0582\u0574 \u0567 \u056F\u0578\u0580\u057F\u056B\u0566\u0578\u056C\u056B \u0574\u0561\u056F\u0561\u0580\u0564\u0561\u056F\u0568 39%-\u0578\u057E \u0587 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u0567\u0576\u0564\u0578\u0580\u0586\u056B\u0576\u0576\u0565\u0580\u0568 27%-\u0578\u057E: \u0540\u056B\u057E\u0561\u0576\u0564\u0561\u0576\u0578\u0581\u0576\u0565\u0580\u0576 \u0561\u0575\u056A\u0574 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \xAB\u056E\u056B\u056E\u0561\u0572\u056B \u0569\u0565\u0580\u0561\u057A\u056B\u0561\xBB \u0564\u0580\u0561\u056F\u0561\u0576 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u0578\u057E\u0589",az:'G\xFCl\xFC\u015F kortizolu 39% azald\u0131r v\u0259 endorphinl\u0259ri 27% art\u0131r\u0131r. X\u0259st\u0259xanalar art\u0131q m\xFCsb\u0259t n\u0259tic\u0259l\u0259rl\u0259 "g\xFCl\xFC\u015F terapiyas\u0131"ndan istifad\u0259 edirl\u0259r.'},realWorld:{en:"Burnout (emotional exhaustion, depersonalization, reduced accomplishment) affects 67% of workers at some point. Companies that implement stress management programs see 25% reductions in sick days and higher productivity.",ka:"\u10D4\u10DB\u10DD\u10EA\u10D8\u10E3\u10E0\u10D8 \u10D2\u10D0\u10D3\u10D0\u10EC\u10D5\u10D0 \u10DB\u10E3\u10E8\u10D0\u10D9\u10D7\u10D0 67%-\u10D6\u10D4 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10E1. \u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10DB\u10D0\u10E0\u10D7\u10D5\u10D8\u10E1 \u10DE\u10E0\u10DD\u10D2\u10E0\u10D0\u10DB\u10D4\u10D1\u10D8\u10E1 \u10DB\u10E5\u10DD\u10DC\u10D4 \u10D9\u10DD\u10DB\u10DE\u10D0\u10DC\u10D8\u10D4\u10D1\u10E8\u10D8 \u10D0\u10D5\u10D0\u10D3\u10DB\u10E7\u10DD\u10E4\u10DD\u10D1\u10D8\u10E1 \u10D3\u10E6\u10D4\u10D4\u10D1\u10D8 25%-\u10D8\u10D7 \u10DB\u10EA\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0.",ru:"\u0412\u044B\u0433\u043E\u0440\u0430\u043D\u0438\u0435 \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442 67% \u0440\u0430\u0431\u043E\u0442\u043D\u0438\u043A\u043E\u0432. \u041A\u043E\u043C\u043F\u0430\u043D\u0438\u0438, \u0432\u043D\u0435\u0434\u0440\u044F\u044E\u0449\u0438\u0435 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u044B \u043F\u043E \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044E \u0441\u0442\u0440\u0435\u0441\u0441\u043E\u043C, \u043E\u0442\u043C\u0435\u0447\u0430\u044E\u0442 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0431\u043E\u043B\u044C\u043D\u0438\u0447\u043D\u044B\u0445 \u043D\u0430 25%.",hy:"\u0537\u0574\u0578\u0581\u056B\u0578\u0576\u0561\u056C \u0561\u0575\u0580\u0578\u0582\u0574\u0568 \u0561\u0566\u0564\u0578\u0582\u0574 \u0567 \u0561\u0577\u056D\u0561\u057F\u0578\u0572\u0576\u0565\u0580\u056B 67%-\u056B \u057E\u0580\u0561: \u054D\u0569\u0580\u0565\u057D\u056B \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0574\u0561\u0576 \u056E\u0580\u0561\u0563\u0580\u0565\u0580 \u056B\u0580\u0561\u056F\u0561\u0576\u0561\u0581\u0576\u0578\u0572 \u0568\u0576\u056F\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0576\u056F\u0561\u057F\u0578\u0582\u0574 \u0565\u0576 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0561\u0576 \u0561\u0580\u0571\u0561\u056F\u0578\u0582\u0580\u0564\u0576\u0565\u0580\u056B 25% \u056F\u0580\u0573\u0561\u057F\u0578\u0582\u0574:",az:"Emosional yanma i\u015F\xE7il\u0259rin 67%-n\u0259 t\u0259sir edir. Stressin idar\u0259 edilm\u0259si proqramlar\u0131n\u0131 h\u0259yata ke\xE7ir\u0259n \u015Firk\u0259tl\u0259r x\u0259st\u0259lik g\xFCnl\u0259rinin 25% azald\u0131\u011F\u0131n\u0131 g\xF6r\xFCrl\u0259r."}},14:{title:{en:"Psychological Disorders",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8",ru:"\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580",az:"Psixoloji poz\u011Funluqlar"},description:{en:"Understanding mental disorders: symptoms, causes, and classification.",ka:"\u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D2\u10D0\u10D2\u10D4\u10D1\u10D0: \u10E1\u10D8\u10DB\u10DE\u10E2\u10DD\u10DB\u10D4\u10D1\u10D8, \u10DB\u10D8\u10D6\u10D4\u10D6\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D9\u10DA\u10D0\u10E1\u10D8\u10E4\u10D8\u10D9\u10D0\u10EA\u10D8\u10D0.",ru:"\u041F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432: \u0441\u0438\u043C\u043F\u0442\u043E\u043C\u044B, \u043F\u0440\u0438\u0447\u0438\u043D\u044B \u0438 \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F.",hy:"\u0540\u0561\u057D\u056F\u0561\u0576\u0561\u056C\u0578\u057E \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0568. \u0561\u056D\u057F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u0568, \u057A\u0561\u057F\u0573\u0561\u057C\u0576\u0565\u0580\u0568 \u0587 \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u0578\u0582\u0574\u0568:",az:"Psixi poz\u011Funluqlar\u0131 ba\u015Fa d\xFC\u015Fm\u0259k: simptomlar, s\u0259b\u0259bl\u0259r v\u0259 t\u0259snifat."},keyTopics:{en:["DSM Classification","Anxiety Disorders","Mood Disorders","Schizophrenia","Personality Disorders"],ka:["DSM \u10D9\u10DA\u10D0\u10E1\u10D8\u10E4\u10D8\u10D9\u10D0\u10EA\u10D8\u10D0","\u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10D7\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8","\u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8","\u10E8\u10D8\u10D6\u10DD\u10E4\u10E0\u10D4\u10DC\u10D8\u10D0","\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8"],ru:["\u041A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0414\u0421\u041C","\u0422\u0440\u0435\u0432\u043E\u0436\u043D\u044B\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430","\u0420\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F","\u0428\u0438\u0437\u043E\u0444\u0440\u0435\u043D\u0438\u044F","\u0420\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438"],hy:["DSM \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u0578\u0582\u0574","\u0531\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580","\u054F\u0580\u0561\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580","\u0547\u056B\u0566\u0578\u0586\u0580\u0565\u0576\u056B\u0561","\u0531\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580"],az:["DSM t\u0259snifat\u0131","Anksiyete poz\u011Funluqlar\u0131","\u018Fhval poz\u011Funluqlar\u0131","\u015Eizofreniya","\u015E\u0259xsiyy\u0259t poz\u011Funluqlar\u0131"]},summary:{en:"Psychological disorders are patterns of thoughts, feelings, or behaviors that are deviant, distressful, and dysfunctional \u2014 the three D's that help define what is considered abnormal, always within the context of culture and circumstances. This chapter examines how mental disorders are classified using the DSM-5 (Diagnostic and Statistical Manual of Mental Disorders), which categorizes conditions by symptom patterns rather than underlying causes. It covers the most prevalent categories: anxiety disorders (generalized anxiety, panic disorder, phobias, OCD, and PTSD \u2014 the most common category overall), mood disorders (major depressive disorder, the leading cause of disability worldwide, and bipolar disorder with alternating mania and depression), schizophrenia (a severe disorder involving hallucinations, delusions, and disorganized thinking, linked to the dopamine hypothesis), and personality disorders (including antisocial, borderline, and narcissistic types). The chapter emphasizes the diathesis-stress model, which proposes that disorders arise from the interaction of genetic or biological predispositions with environmental triggers. It also addresses the importance of reducing stigma and increasing mental health literacy, noting that approximately one in five adults experiences a mental health condition each year.",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8 \u10D0\u10E0\u10D8\u10E1 \u10D0\u10D6\u10E0\u10D4\u10D1\u10D8\u10E1, \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D0\u10DC \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10D8\u10E1\u10D4\u10D7\u10D8 \u10DC\u10D8\u10DB\u10E3\u10E8\u10D4\u10D1\u10D8, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10D3\u10D4\u10D5\u10D8\u10D0\u10DC\u10E2\u10E3\u10E0\u10D8, \u10E1\u10E2\u10E0\u10D4\u10E1\u10E3\u10DA\u10D8 \u10D3\u10D0 \u10D3\u10D8\u10E1\u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10E3\u10E0\u10D8\u10D0 \u2014 \u10D4\u10E1 \u10D0\u10E0\u10D8\u10E1 \u10E1\u10D0\u10DB\u10D8 \u201E\u10D3\u201C (deviant, distressful, dysfunctional), \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10D4\u10EE\u10DB\u10D0\u10E0\u10D4\u10D1\u10D0 \u10D8\u10DB\u10D8\u10E1 \u10D3\u10D0\u10D3\u10D2\u10D4\u10DC\u10D0\u10E1, \u10D7\u10E3 \u10E0\u10D0 \u10D8\u10D7\u10D5\u10DA\u10D4\u10D1\u10D0 \u10D0\u10E0\u10D0\u10DC\u10DD\u10E0\u10DB\u10D0\u10DA\u10E3\u10E0\u10D0\u10D3 \u10D3\u10D0 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D7\u10D5\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D4\u10D1\u10D0 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DC\u10E2\u10D4\u10E5\u10E1\u10E2\u10E8\u10D8. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D9\u10DA\u10D0\u10E1\u10D8\u10E4\u10D8\u10EA\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8 DSM-5-\u10D8\u10E1 (\u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D0\u10D3\u10D8\u10D0\u10D2\u10DC\u10DD\u10E1\u10E2\u10D8\u10D9\u10DD \u10D3\u10D0 \u10E1\u10E2\u10D0\u10E2\u10D8\u10E1\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10E1\u10D0\u10EE\u10D4\u10DA\u10DB\u10EB\u10E6\u10D5\u10D0\u10DC\u10D4\u10DA\u10DD) \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10D7, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10E1 \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D4\u10D1\u10E1 \u10E1\u10D8\u10DB\u10DE\u10E2\u10DD\u10DB\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10EE\u10D4\u10D3\u10D5\u10D8\u10D7 \u10D3\u10D0 \u10D0\u10E0\u10D0 \u10D2\u10D0\u10DB\u10DD\u10DB\u10EC\u10D5\u10D4\u10D5\u10D8 \u10DB\u10D8\u10D6\u10D4\u10D6\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10EE\u10D4\u10D3\u10D5\u10D8\u10D7. \u10D8\u10D2\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10D2\u10D0\u10D5\u10E0\u10EA\u10D4\u10DA\u10D4\u10D1\u10E3\u10DA \u10D9\u10D0\u10E2\u10D4\u10D2\u10DD\u10E0\u10D8\u10D4\u10D1\u10E1: \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10D7\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8 (\u10D2\u10D4\u10DC\u10D4\u10E0\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8 \u10E8\u10E4\u10DD\u10D7\u10D5\u10D0, \u10DE\u10D0\u10DC\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0, \u10E4\u10DD\u10D1\u10D8\u10D4\u10D1\u10D8, OCD \u10D3\u10D0 PTSD \u2014 \u10E0\u10DD\u10DB\u10D4\u10DA\u10D7\u10D0 \u10D9\u10D0\u10E2\u10D4\u10D2\u10DD\u10E0\u10D8\u10D0\u10EA \u10DB\u10D7\u10DA\u10D8\u10D0\u10DC\u10DD\u10D1\u10D0\u10E8\u10D8 \u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10D2\u10D0\u10D5\u10E0\u10EA\u10D4\u10DA\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0), \u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D4\u10D1\u10D8 (\u10DB\u10D7\u10D0\u10D5\u10D0\u10E0\u10D8 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10E3\u10DA\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10DB\u10E1\u10DD\u10E4\u10DA\u10D8\u10DD\u10E8\u10D8 \u10E8\u10E0\u10DD\u10DB\u10D8\u10E1\u10E3\u10E3\u10DC\u10D0\u10E0\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D0\u10DB\u10E7\u10D5\u10D0\u10DC\u10D8 \u10DB\u10D8\u10D6\u10D4\u10D6\u10D8\u10D0, \u10D3\u10D0 \u10D1\u10D8\u10DE\u10DD\u10DA\u10D0\u10E0\u10E3\u10DA\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 \u10DB\u10D0\u10DC\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1 \u10DB\u10DD\u10DC\u10D0\u10EA\u10D5\u10DA\u10D4\u10DD\u10D1\u10D8\u10D7), \u10E8\u10D8\u10D6\u10DD\u10E4\u10E0\u10D4\u10DC\u10D8\u10D0 (\u10DB\u10EB\u10D8\u10DB\u10D4 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10F0\u10D0\u10DA\u10E3\u10EA\u10D8\u10DC\u10D0\u10EA\u10D8\u10D4\u10D1\u10E1, \u10D1\u10DD\u10D3\u10D5\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10D0\u10E0\u10D0\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0\u10E1, \u10E0\u10D0\u10EA \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10D3\u10DD\u10E4\u10D0\u10DB\u10D8\u10DC\u10D8\u10E1 \u10F0\u10D8\u10DE\u10DD\u10D7\u10D4\u10D6\u10D0\u10E1\u10D7\u10D0\u10DC) \u10D3\u10D0 \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D4\u10D1\u10D8 (\u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10D0\u10DC\u10E2\u10D8\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8, \u10DB\u10DD\u10E1\u10D0\u10D6\u10E6\u10D5\u10E0\u10D4 (Borderline) \u10D3\u10D0 \u10DC\u10D0\u10E0\u10EA\u10D8\u10E1\u10E3\u10DA\u10D8 \u10E2\u10D8\u10DE\u10D4\u10D1\u10D8). \u10D7\u10D0\u10D5\u10D8 \u10EE\u10D0\u10D6\u10E1 \u10E3\u10E1\u10D5\u10D0\u10DB\u10E1 \u10D3\u10D8\u10D0\u10D7\u10D4\u10D6-\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10DB\u10DD\u10D3\u10D4\u10DA\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D8\u10E1 \u10D7\u10D0\u10DC\u10D0\u10EE\u10DB\u10D0\u10D3\u10D0\u10EA \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D4\u10D1\u10D8 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D8\u10E8\u10D5\u10D0 \u10D2\u10D4\u10DC\u10D4\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10DC \u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10EC\u10D8\u10DC\u10D0\u10E1\u10EC\u10D0\u10E0\u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10E1\u10E2\u10E0\u10D4\u10E1\u10DD\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D0\u10D3. \u10D8\u10D2\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10E7\u10E3\u10E0\u10D0\u10D3\u10E6\u10D4\u10D1\u10D0\u10E1 \u10D0\u10DB\u10D0\u10EE\u10D5\u10D8\u10DA\u10D4\u10D1\u10E1 \u10E1\u10E2\u10D8\u10D2\u10DB\u10D8\u10E1 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D8\u10D2\u10DC\u10D8\u10D4\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10D6\u10E0\u10D3\u10D8\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D1\u10D0\u10D6\u10D4 \u10D3\u10D0 \u10D0\u10E6\u10DC\u10D8\u10E8\u10DC\u10D0\u10D5\u10E1, \u10E0\u10DD\u10DB \u10E7\u10DD\u10D5\u10D4\u10DA\u10EC\u10DA\u10D8\u10E3\u10E0\u10D0\u10D3 \u10D3\u10D0\u10D0\u10EE\u10DA\u10DD\u10D4\u10D1\u10D8\u10D7 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D8 \u10DB\u10D4\u10EE\u10E3\u10D7\u10D4 \u10D6\u10E0\u10D3\u10D0\u10E1\u10E0\u10E3\u10DA\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EA\u10D3\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0\u10E1.",ru:"\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u2014 \u044D\u0442\u043E \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B \u043C\u044B\u0441\u043B\u0435\u0439, \u0447\u0443\u0432\u0441\u0442\u0432 \u0438\u043B\u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0442\u043A\u043B\u043E\u043D\u044F\u044E\u0449\u0438\u043C\u0438\u0441\u044F, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0438 \u0434\u0438\u0441\u0442\u0440\u0435\u0441\u0441 \u0438 \u0434\u0438\u0441\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u2014 \u0442\u0440\u0438 \u0444\u0430\u043A\u0442\u043E\u0440\u0430 (\u0434\u0435\u0432\u0438\u0430\u043D\u0442\u043D\u043E\u0441\u0442\u044C, \u0434\u0438\u0441\u0442\u0440\u0435\u0441\u0441 \u0438 \u0434\u0438\u0441\u0444\u0443\u043D\u043A\u0446\u0438\u044F), \u043F\u043E\u043C\u043E\u0433\u0430\u044E\u0449\u0438\u0435 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0438\u0442\u044C, \u0447\u0442\u043E \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0430\u043D\u043E\u043C\u0430\u043B\u044C\u043D\u044B\u043C, \u0432\u0441\u0435\u0433\u0434\u0430 \u0441 \u0443\u0447\u0435\u0442\u043E\u043C \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B \u0438 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043A\u0430\u043A \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u0441 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435\u043C DSM-5 (\u0414\u0438\u0430\u0433\u043D\u043E\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0438 \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u043E \u043F\u043E \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430\u043C), \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043F\u043E \u043D\u0430\u0431\u043E\u0440\u0430\u043C \u0441\u0438\u043C\u043F\u0442\u043E\u043C\u043E\u0432, \u0430 \u043D\u0435 \u043F\u043E \u043F\u0435\u0440\u0432\u043E\u043F\u0440\u0438\u0447\u0438\u043D\u0430\u043C. \u041E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u043D\u044B\u0435 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438: \u0442\u0440\u0435\u0432\u043E\u0436\u043D\u044B\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 (\u0433\u0435\u043D\u0435\u0440\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0442\u0440\u0435\u0432\u043E\u0436\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E, \u043F\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E, \u0444\u043E\u0431\u0438\u0438, \u041E\u041A\u0420 \u0438 \u041F\u0422\u0421\u0420 \u2014 \u0441\u0430\u043C\u0430\u044F \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u043D\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F \u0432 \u0446\u0435\u043B\u043E\u043C), \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F (\u0431\u043E\u043B\u044C\u0448\u043E\u0435 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0432\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E, \u0432\u0435\u0434\u0443\u0449\u0430\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0438\u043D\u0432\u0430\u043B\u0438\u0434\u043D\u043E\u0441\u0442\u0438 \u0432 \u043C\u0438\u0440\u0435, \u0438 \u0431\u0438\u043F\u043E\u043B\u044F\u0440\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E \u0441 \u0447\u0435\u0440\u0435\u0434\u0443\u044E\u0449\u0438\u043C\u0438\u0441\u044F \u043C\u0430\u043D\u0438\u044F\u043C\u0438 \u0438 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F\u043C\u0438), \u0448\u0438\u0437\u043E\u0444\u0440\u0435\u043D\u0438\u044F (\u0442\u044F\u0436\u0435\u043B\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0435\u0435 \u0433\u0430\u043B\u043B\u044E\u0446\u0438\u043D\u0430\u0446\u0438\u0438, \u0431\u0440\u0435\u0434 \u0438 \u0434\u0435\u0437\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0435 \u0441 \u0434\u043E\u0444\u0430\u043C\u0438\u043D\u043E\u0432\u043E\u0439 \u0433\u0438\u043F\u043E\u0442\u0435\u0437\u043E\u0439) \u0438 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 (\u0432\u043A\u043B\u044E\u0447\u0430\u044F \u0430\u043D\u0442\u0438\u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439, \u043F\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u044B\u0439 \u0438 \u043D\u0430\u0440\u0446\u0438\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0442\u0438\u043F\u044B). \u0412 \u0433\u043B\u0430\u0432\u0435 \u043F\u043E\u0434\u0447\u0435\u0440\u043A\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0434\u0438\u0430\u0442\u0435\u0437-\u0441\u0442\u0440\u0435\u0441\u0441\u043E\u0432\u0430\u044F \u043C\u043E\u0434\u0435\u043B\u044C, \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u044E\u0449\u0430\u044F, \u0447\u0442\u043E \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0438\u0437-\u0437\u0430 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0433\u0435\u043D\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0438\u043B\u0438 \u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u0440\u0435\u0434\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441 \u0442\u0440\u0438\u0433\u0433\u0435\u0440\u0430\u043C\u0438 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044B. \u0422\u0430\u043A\u0436\u0435 \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u0430\u0436\u043D\u043E\u0441\u0442\u044C \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u044F \u0441\u0442\u0438\u0433\u043C\u0430\u0442\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u043F\u043E\u0432\u044B\u0448\u0435\u043D\u0438\u044F \u0433\u0440\u0430\u043C\u043E\u0442\u043D\u043E\u0441\u0442\u0438 \u0432 \u0432\u043E\u043F\u0440\u043E\u0441\u0430\u0445 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F, \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u043E\u0442\u043C\u0435\u0447\u0430\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u043F\u0440\u0438\u043C\u0435\u0440\u043D\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u043F\u044F\u0442\u044B\u0439 \u0432\u0437\u0440\u043E\u0441\u043B\u044B\u0439 \u0435\u0436\u0435\u0433\u043E\u0434\u043D\u043E \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0441 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430\u043C\u0438 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F.",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0574\u057F\u0584\u0565\u0580\u056B, \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u056F\u0561\u0574 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0565\u0576, \u0578\u0580\u0578\u0576\u0584 \u0577\u0565\u0572\u057E\u0561\u056E \u0565\u0576, \u057F\u0561\u0563\u0576\u0561\u057A\u0561\u056C\u056B \u0587 \u0564\u056B\u057D\u0586\u0578\u0582\u0576\u056F\u0581\u056B\u0578\u0576\u0561\u056C. \u0561\u0575\u057D \u0565\u0580\u0565\u0584 \xAB\u0534\xBB-\u0565\u0580\u0568 \u0585\u0563\u0576\u0578\u0582\u0574 \u0565\u0576 \u057D\u0561\u0570\u0574\u0561\u0576\u0565\u056C, \u0569\u0565 \u056B\u0576\u0579\u0576 \u0567 \u0570\u0561\u0574\u0561\u0580\u057E\u0578\u0582\u0574 \u0561\u0576\u0576\u0578\u0580\u0574\u0561\u056C\u055D \u0574\u056B\u0577\u057F \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u056B \u0587 \u0570\u0561\u0576\u0563\u0561\u0574\u0561\u0576\u0584\u0576\u0565\u0580\u056B \u0570\u0561\u0574\u0561\u057F\u0565\u0584\u057D\u057F\u0578\u0582\u0574: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0584\u0576\u0576\u0561\u0580\u056F\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u057E\u0578\u0582\u0574\u055D \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0565\u056C\u0578\u057E DSM-5-\u0568 (\u0540\u0578\u0563\u0565\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u0561\u056D\u057F\u0578\u0580\u0578\u0577\u056B\u0579 \u0587 \u057E\u056B\u0573\u0561\u056F\u0561\u0563\u0580\u0561\u056F\u0561\u0576 \u0571\u0565\u057C\u0576\u0561\u0580\u056F), \u0578\u0580\u0568 \u056D\u0574\u0562\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0567 \u057E\u056B\u0573\u0561\u056F\u0576\u0565\u0580\u0568\u055D \u0565\u056C\u0576\u0565\u056C\u0578\u057E \u0561\u056D\u057F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u056B \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B\u0581, \u0561\u0575\u056C \u0578\u0579 \u0569\u0565 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057A\u0561\u057F\u0573\u0561\u057C\u0576\u0565\u0580\u056B\u0581: \u0531\u0575\u0576 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0561\u057C\u0561\u057E\u0565\u056C \u057F\u0561\u0580\u0561\u056E\u057E\u0561\u056E \u056F\u0561\u057F\u0565\u0563\u0578\u0580\u056B\u0561\u0576\u0565\u0580\u0568\u055D \u057F\u0561\u0563\u0576\u0561\u057A\u0561\u0575\u056B\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580 (\u0568\u0576\u0564\u0570\u0561\u0576\u0580\u0561\u0581\u057E\u0561\u056E \u057F\u0561\u0563\u0576\u0561\u057A, \u056D\u0578\u0582\u0573\u0561\u057A\u0561\u0575\u056B\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574, \u0586\u0578\u0562\u056B\u0561\u0576\u0565\u0580, \u0555\u053F\u053D (OCD) \u0587 \u0540\u054F\u054D\u053D (PTSD)\u055D \u0568\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u0561\u057C\u0574\u0561\u0574\u0562 \u0561\u0574\u0565\u0576\u0561\u057F\u0561\u0580\u0561\u056E\u057E\u0561\u056E \u056F\u0561\u057F\u0565\u0563\u0578\u0580\u056B\u0561\u0576), \u057F\u0580\u0561\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580 (\u056D\u0578\u0577\u0578\u0580 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u057E \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u055D \u0561\u0577\u056D\u0561\u0580\u0570\u0578\u0582\u0574 \u0570\u0561\u0577\u0574\u0561\u0576\u0564\u0561\u0574\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057A\u0561\u057F\u0573\u0561\u057C\u0568, \u0587 \u0565\u0580\u056F\u0562\u0587\u0565\u057C \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u055D \u0570\u0561\u057B\u0578\u0580\u0564\u057E\u0578\u0572 \u0574\u0561\u0576\u056B\u0561\u0575\u0578\u057E \u0587 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u0578\u057E), \u0577\u056B\u0566\u0578\u0586\u0580\u0565\u0576\u056B\u0561 (\u056E\u0561\u0576\u0580 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u055D \u0570\u0561\u056C\u0575\u0578\u0582\u0581\u056B\u0576\u0561\u0581\u056B\u0561\u0576\u0565\u0580\u0578\u057E, \u0566\u0561\u057C\u0561\u0576\u0581\u0561\u0576\u0584\u0576\u0565\u0580\u0578\u057E \u0587 \u0561\u0576\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0574\u0562, \u0578\u0580\u0568 \u056F\u0561\u057A\u057E\u0561\u056E \u0567 \u0564\u0578\u0586\u0561\u0574\u056B\u0576\u0561\u0575\u056B\u0576 \u057E\u0561\u0580\u056F\u0561\u056E\u056B \u0570\u0565\u057F) \u0587 \u0561\u0576\u0571\u0576\u0561\u0575\u056B\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580 (\u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0570\u0561\u056F\u0561\u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576, \u057D\u0561\u0570\u0574\u0561\u0576\u0561\u0575\u056B\u0576 \u0587 \u0576\u0561\u0580\u0581\u056B\u057D\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u057F\u0565\u057D\u0561\u056F\u0576\u0565\u0580\u0568): \u0533\u056C\u056D\u0578\u0582\u0574 \u0568\u0576\u0564\u0563\u056E\u057E\u0578\u0582\u0574 \u0567 \u0564\u056B\u0561\u0569\u0565\u0566-\u057D\u0569\u0580\u0565\u057D \u0574\u0578\u0564\u0565\u056C\u0568, \u0578\u0580\u0576 \u0561\u057C\u0561\u057B\u0561\u0580\u056F\u0578\u0582\u0574 \u0567, \u0578\u0580 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0576 \u0561\u057C\u0561\u057B\u0561\u0576\u0578\u0582\u0574 \u0565\u0576 \u0563\u0565\u0576\u0565\u057F\u056B\u056F\u0561\u056F\u0561\u0576 \u056F\u0561\u0574 \u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u0561\u056F\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u056B \u057D\u0569\u0580\u0565\u057D\u0561\u0575\u056B\u0576 \u0563\u0578\u0580\u056E\u0578\u0576\u0576\u0565\u0580\u056B \u0583\u0578\u056D\u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u056B\u0581\u0589 \u0531\u0575\u0576 \u0576\u0561\u0587 \u0561\u0576\u0564\u0580\u0561\u0564\u0561\u057C\u0576\u0578\u0582\u0574 \u0567 \u057D\u057F\u056B\u0563\u0574\u0561\u0575\u056B \u0576\u057E\u0561\u0566\u0565\u0581\u0574\u0561\u0576 \u0587 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0575\u0561\u056C \u0563\u0580\u0561\u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0574\u0561\u0576 \u056F\u0561\u0580\u0587\u0578\u0580\u0578\u0582\u0569\u0575\u0561\u0576\u0568\u055D \u0576\u0577\u0565\u056C\u0578\u057E, \u0578\u0580 \u0561\u0574\u0565\u0576 \u0570\u056B\u0576\u0563\u0565\u0580\u0578\u0580\u0564 \u0579\u0561\u0583\u0561\u0570\u0561\u057D\u0568 \u0561\u0574\u0565\u0576 \u057F\u0561\u0580\u056B \u0562\u0561\u056D\u057E\u0578\u0582\u0574 \u0567 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u0570\u0565\u057F:",az:"Psixoloji poz\u011Funluqlar deviant, k\u0259d\u0259rli v\u0259 disfunksiyal\u0131 olan d\xFC\u015F\xFCnc\u0259l\u0259r, hissl\u0259r v\u0259 ya davran\u0131\u015Flar n\xFCmun\u0259sidir \u2014 bu \xFC\xE7 x\xFCsusiyy\u0259t (deviant, distressful, dysfunctional) h\u0259mi\u015F\u0259 m\u0259d\u0259niyy\u0259t v\u0259 \u015F\u0259rtl\u0259r kontekstind\u0259 n\u0259yin anormal hesab edildiyini m\xFC\u0259yy\u0259n etm\u0259y\u0259 k\xF6m\u0259k edir. Bu f\u0259sil psixi x\u0259st\u0259likl\u0259rin \xF6z \u0259sas s\u0259b\u0259bl\u0259rin\u0259 g\xF6r\u0259 deyil, simptom qruplar\u0131na g\xF6r\u0259 t\u0259snif ed\u0259n DSM-5-d\u0259n (Psixi Poz\u011Funluqlar\u0131n Diaqnostika v\u0259 Statistik T\u0259limat\u0131) istifad\u0259 ed\u0259r\u0259k nec\u0259 t\u0259snif edildiyini ara\u015Fd\u0131r\u0131r. \u018Fn \xE7ox yay\u0131lm\u0131\u015F kateqoriyalar\u0131 \u0259hat\u0259 edir: anksiyete poz\u011Funluqlar\u0131 (\xFCmumi t\u0259\u015Fvi\u015F poz\u011Funlu\u011Fu, panik poz\u011Funlu\u011Fu, fobiyalar, OKB v\u0259 TSSB - b\xFCt\xF6vl\xFCkd\u0259 \u0259n \xE7ox yay\u0131lm\u0131\u015F kateqoriya), \u0259hval poz\u011Funluqlar\u0131 (d\xFCnyada \u015Fik\u0259stliyin \u0259sas s\u0259b\u0259bi olan b\xF6y\xFCk depressiv poz\u011Funluq v\u0259 n\xF6vb\u0259l\u0259\u015F\u0259n maniya v\u0259 depressiya il\u0259 bipolyar poz\u011Funluq), \u015Fizofreniya (dofamin f\u0259rziyy\u0259si il\u0259 \u0259laq\u0259li hal\xFCsinasiyalar, del\xFCziyalar v\u0259 pozulmu\u015F d\xFC\u015F\xFCnm\u0259ni ehtiva ed\u0259n a\u011F\u0131r poz\u011Funluq) v\u0259 \u015F\u0259xsiyy\u0259t poz\u011Funluqlar\u0131 (antisosial, s\u0259rh\u0259d (borderline) v\u0259 narsisistik tipl\u0259r daxil olmaqla). F\u0259sil, x\u0259st\u0259likl\u0259rin genetik v\u0259 ya bioloji meyll\u0259rin \u0259traf m\xFChit tetikleyicileri il\u0259 qar\u015F\u0131l\u0131ql\u0131 t\u0259sirind\u0259n yarand\u0131\u011F\u0131n\u0131 iddia ed\u0259n diathesis-stress modelini vur\u011Fulay\u0131r. H\u0259m\xE7inin dam\u011Falanman\u0131n (stiqma) azalmas\u0131n\u0131n v\u0259 psixi sa\u011Flaml\u0131q savadl\u0131l\u0131\u011F\u0131n\u0131n art\u0131r\u0131lmas\u0131n\u0131n vacibliyini qeyd ed\u0259r\u0259k h\u0259r be\u015F yetkind\u0259n t\u0259xmin\u0259n birinin h\u0259r il psixi sa\u011Flaml\u0131q problemi ya\u015Fad\u0131\u011F\u0131n\u0131 qeyd edir."},keyPoints:{en:[`A psychological disorder is a pattern of thoughts, feelings, or behaviors that is deviant, distressful, and dysfunctional (the "3 D's"). Context and culture matter in defining "abnormal."`,"The DSM-5 (Diagnostic and Statistical Manual) is the standard classification system. It categorizes disorders by symptoms, not causes, and is used for diagnosis and insurance.","Anxiety disorders (most common): Generalized Anxiety Disorder (persistent worry), Panic Disorder (sudden intense fear attacks), Phobias (irrational fear of specific things), OCD (obsessive thoughts + compulsive rituals), PTSD (after trauma).","Mood disorders: Major Depressive Disorder (persistent sadness, loss of interest, lasting 2+ weeks) and Bipolar Disorder (alternating episodes of mania and depression). Depression is the leading cause of disability worldwide.","Schizophrenia: a severe disorder involving positive symptoms (hallucinations, delusions, disorganized speech) and negative symptoms (flat affect, social withdrawal). Dopamine hypothesis: excess dopamine activity in certain brain pathways.","Personality disorders: enduring, inflexible patterns. Antisocial PD (disregard for others' rights, lack of empathy), Borderline PD (unstable relationships and emotions), Narcissistic PD (grandiosity, need for admiration).","The diathesis-stress model: disorders result from a genetic/biological predisposition (diathesis) + environmental triggers (stress). Neither alone is usually sufficient."],ka:["\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 \u10D0\u10E0\u10D8\u10E1 \u10D0\u10D6\u10E0\u10D4\u10D1\u10D8\u10E1, \u10D2\u10E0\u10EB\u10DC\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D0\u10DC \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10DC\u10D8\u10DB\u10E3\u10E8\u10D8, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D3\u10D4\u10D5\u10D8\u10D0\u10DC\u10E2\u10E3\u10E0\u10D8, \u10E1\u10E2\u10E0\u10D4\u10E1\u10E3\u10DA\u10D8 \u10D3\u10D0 \u10D3\u10D8\u10E1\u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10E3\u10E0\u10D8\u10D0 (\u201E\u10E1\u10D0\u10DB\u10D8 \u10D3\u201C). \u10E1\u10D8\u10E2\u10E7\u10D5\u10D0 \u201E\u10D0\u10E0\u10D0\u10DC\u10DD\u10E0\u10DB\u10D0\u10DA\u10E3\u10E0\u10D8\u10E1\u201C \u10D2\u10D0\u10DC\u10E1\u10D0\u10D6\u10E6\u10D5\u10E0\u10D8\u10E1\u10D0\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D1\u10D0 \u10D0\u10E5\u10D5\u10E1 \u10D9\u10DD\u10DC\u10E2\u10D4\u10E5\u10E1\u10E2\u10E1 \u10D3\u10D0 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D0\u10E1.","DSM-5 (\u10E1\u10D0\u10D3\u10D8\u10D0\u10D2\u10DC\u10DD\u10E1\u10E2\u10D8\u10D9\u10DD \u10D3\u10D0 \u10E1\u10E2\u10D0\u10E2\u10D8\u10E1\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10E1\u10D0\u10EE\u10D4\u10DA\u10DB\u10EB\u10E6\u10D5\u10D0\u10DC\u10D4\u10DA\u10DD) \u10D0\u10E0\u10D8\u10E1 \u10D9\u10DA\u10D0\u10E1\u10D8\u10E4\u10D8\u10D9\u10D0\u10EA\u10D8\u10D8\u10E1 \u10E1\u10E2\u10D0\u10DC\u10D3\u10D0\u10E0\u10E2\u10E3\u10DA\u10D8 \u10E1\u10D8\u10E1\u10E2\u10D4\u10DB\u10D0. \u10D8\u10E1 \u10D0\u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10E1 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10E1 \u10E1\u10D8\u10DB\u10DE\u10E2\u10DD\u10DB\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D8\u10EE\u10D4\u10D3\u10D5\u10D8\u10D7, \u10D3\u10D0 \u10D0\u10E0\u10D0 \u10D2\u10D0\u10DB\u10DD\u10DB\u10EC\u10D5\u10D4\u10D5\u10D8 \u10DB\u10D8\u10D6\u10D4\u10D6\u10D4\u10D1\u10D8\u10D7, \u10D3\u10D0 \u10D2\u10D0\u10DB\u10DD\u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D0 \u10D3\u10D8\u10D0\u10D2\u10DC\u10DD\u10E1\u10E2\u10D8\u10D9\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D3\u10D0\u10D6\u10E6\u10D5\u10D4\u10D5\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1.","\u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10D7\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8 (\u10E7\u10D5\u10D4\u10DA\u10D0\u10D6\u10D4 \u10D2\u10D0\u10D5\u10E0\u10EA\u10D4\u10DA\u10D4\u10D1\u10E3\u10DA\u10D8): \u10D2\u10D4\u10DC\u10D4\u10E0\u10D0\u10DA\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8 \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10D7\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10D8 \u10EC\u10E3\u10EE\u10D8\u10DA\u10D8), \u10DE\u10D0\u10DC\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10E8\u10D8\u10E8\u10D8\u10E1 \u10E3\u10D4\u10EA\u10D0\u10E0\u10D8 \u10DB\u10EB\u10D0\u10E4\u10E0\u10D8 \u10E8\u10D4\u10E2\u10D4\u10D5\u10D4\u10D1\u10D8), \u10E4\u10DD\u10D1\u10D8\u10D4\u10D1\u10D8 (\u10D9\u10DD\u10DC\u10D9\u10E0\u10D4\u10E2\u10E3\u10DA\u10D8 \u10E1\u10D0\u10D2\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D8\u10E0\u10D0\u10EA\u10D8\u10DD\u10DC\u10D0\u10DA\u10E3\u10E0\u10D8 \u10E8\u10D8\u10E8\u10D8), OCD (\u10DD\u10D1\u10E1\u10D4\u10E1\u10D8\u10E3\u10E0\u10D8 \u10D0\u10D6\u10E0\u10D4\u10D1\u10D8 + \u10D9\u10DD\u10DB\u10DE\u10E3\u10DA\u10E1\u10D8\u10E3\u10E0\u10D8 \u10E0\u10D8\u10E2\u10E3\u10D0\u10DA\u10D4\u10D1\u10D8), PTSD (\u10E2\u10E0\u10D0\u10D5\u10DB\u10D8\u10E1 \u10E8\u10D4\u10DB\u10D3\u10D4\u10D2).","\u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8: \u10DB\u10D7\u10D0\u10D5\u10D0\u10E0\u10D8 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10E3\u10DA\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10D8 \u10E1\u10D4\u10D5\u10D3\u10D0, \u10D8\u10DC\u10E2\u10D4\u10E0\u10D4\u10E1\u10D8\u10E1 \u10D3\u10D0\u10D9\u10D0\u10E0\u10D2\u10D5\u10D0, \u10D2\u10E0\u10EB\u10D4\u10DA\u10D3\u10D4\u10D1\u10D0 2+ \u10D9\u10D5\u10D8\u10E0\u10D0) \u10D3\u10D0 \u10D1\u10D8\u10DE\u10DD\u10DA\u10D0\u10E0\u10E3\u10DA\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10DB\u10D0\u10DC\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1 \u10DB\u10DD\u10DC\u10D0\u10EA\u10D5\u10DA\u10D4\u10DD\u10D1\u10D8\u10D7\u10D8 \u10D4\u10DE\u10D8\u10D6\u10DD\u10D3\u10D4\u10D1\u10D8). \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D0 \u10E8\u10E0\u10DD\u10DB\u10D8\u10E1\u10E3\u10E3\u10DC\u10D0\u10E0\u10DD\u10D1\u10D8\u10E1 \u10EC\u10D0\u10DB\u10E7\u10D5\u10D0\u10DC\u10D8 \u10DB\u10D8\u10D6\u10D4\u10D6\u10D8\u10D0 \u10DB\u10E1\u10DD\u10E4\u10DA\u10D8\u10DD\u10E8\u10D8.","\u10E8\u10D8\u10D6\u10DD\u10E4\u10E0\u10D4\u10DC\u10D8\u10D0: \u10DB\u10EB\u10D8\u10DB\u10D4 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0 \u10E1\u10D8\u10DB\u10DE\u10E2\u10DD\u10DB\u10D4\u10D1\u10E1 (\u10F0\u10D0\u10DA\u10E3\u10EA\u10D8\u10DC\u10D0\u10EA\u10D8\u10D4\u10D1\u10D8, \u10D1\u10DD\u10D3\u10D5\u10D0, \u10D0\u10E0\u10D0\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DB\u10D4\u10E2\u10E7\u10D5\u10D4\u10DA\u10D4\u10D1\u10D0) \u10D3\u10D0 \u10DC\u10D4\u10D2\u10D0\u10E2\u10D8\u10E3\u10E0 \u10E1\u10D8\u10DB\u10DE\u10E2\u10DD\u10DB\u10D4\u10D1\u10E1 (\u10D1\u10E0\u10E2\u10E7\u10D4\u10DA\u10D8 \u10D0\u10E4\u10D4\u10E5\u10E2\u10D8, \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D8\u10D6\u10DD\u10DA\u10D0\u10EA\u10D8\u10D0). \u10D3\u10DD\u10E4\u10D0\u10DB\u10D8\u10DC\u10D8\u10E1 \u10F0\u10D8\u10DE\u10DD\u10D7\u10D4\u10D6\u10D0: \u10D3\u10DD\u10E4\u10D0\u10DB\u10D8\u10DC\u10D8\u10E1 \u10ED\u10D0\u10E0\u10D1\u10D8 \u10D0\u10E5\u10E2\u10D8\u10D5\u10DD\u10D1\u10D0 \u10E2\u10D5\u10D8\u10DC\u10D8\u10E1 \u10D2\u10D0\u10E0\u10D9\u10D5\u10D4\u10E3\u10DA \u10D2\u10D6\u10D4\u10D1\u10E8\u10D8.","\u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8: \u10DB\u10E3\u10D3\u10DB\u10D8\u10D5\u10D8, \u10DB\u10DD\u10E3\u10E5\u10DC\u10D4\u10DA\u10D8 \u10E4\u10DD\u10E0\u10DB\u10D4\u10D1\u10D8. \u10D0\u10DC\u10E2\u10D8\u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10E1\u10EE\u10D5\u10D0\u10D7\u10D0 \u10E3\u10E4\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10E3\u10D2\u10E3\u10DA\u10D4\u10D1\u10D4\u10DA\u10E7\u10DD\u10E4\u10D0, \u10D4\u10DB\u10DE\u10D0\u10D7\u10D8\u10D8\u10E1 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10DD\u10D1\u10D0), \u10DB\u10DD\u10E1\u10D0\u10D6\u10E6\u10D5\u10E0\u10D4 (Borderline) \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10D0\u10E0\u10D0\u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10E3\u10E0\u10D8 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D4\u10D1\u10D8 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10D8), \u10DC\u10D0\u10E0\u10EA\u10D8\u10E1\u10E3\u10DA\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D0 (\u10D2\u10E0\u10D0\u10DC\u10D3\u10D8\u10DD\u10D6\u10E3\u10DA\u10DD\u10D1\u10D0, \u10D0\u10E6\u10E2\u10D0\u10EA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10DD\u10D7\u10EE\u10DD\u10D5\u10DC\u10D8\u10DA\u10D4\u10D1\u10D0).","\u10D3\u10D8\u10D0\u10D7\u10D4\u10D6-\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8\u10E1 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8: \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D4\u10D1\u10D8 \u10D2\u10D4\u10DC\u10D4\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8/\u10D1\u10D8\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10EC\u10D8\u10DC\u10D0\u10E1\u10EC\u10D0\u10E0\u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1 (\u10D3\u10D8\u10D0\u10D7\u10D4\u10D6\u10D8) \u10D3\u10D0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD \u10E4\u10D0\u10E5\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8\u10E1 (\u10E1\u10E2\u10E0\u10D4\u10E1\u10D8) \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10D3\u10D4\u10D2\u10D8\u10D0. \u10DB\u10EE\u10DD\u10DA\u10DD\u10D3 \u10D4\u10E0\u10D7\u10D8 \u10DB\u10D0\u10D7\u10D2\u10D0\u10DC\u10D8 \u10E9\u10D5\u10D4\u10E3\u10DA\u10D4\u10D1\u10E0\u10D8\u10D5 \u10E1\u10D0\u10D9\u10DB\u10D0\u10E0\u10D8\u10E1\u10D8 \u10D0\u10E0 \u10D0\u10E0\u10D8\u10E1."],ru:["\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E \u2014 \u044D\u0442\u043E \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u043C\u044B\u0441\u043B\u0435\u043D, \u0447\u0443\u0432\u0441\u0442\u0432 \u0438\u043B\u0438 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0435\u0432\u0438\u0430\u043D\u0442\u043D\u044B\u043C, \u0432\u044B\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0434\u0438\u0441\u0442\u0440\u0435\u0441\u0441 \u0438 \u0434\u0438\u0441\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u043C (\xAB\u0442\u0440\u0438 \u0414\xBB). \u041A\u043E\u043D\u0442\u0435\u043A\u0441\u0442 \u0438 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0430 \u0438\u043C\u0435\u044E\u0442 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u043F\u0440\u0438 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0438 \xAB\u043D\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438\xBB.","DSM-5 (\u0414\u0438\u0430\u0433\u043D\u043E\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0438 \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0441\u0442\u0432\u043E) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u043E\u0439 \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438. \u0420\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u0432 \u043D\u0435\u0439 \u043A\u043B\u0430\u0441\u0441\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043F\u043E \u0441\u0438\u043C\u043F\u0442\u043E\u043C\u0430\u043C, \u0430 \u043D\u0435 \u043F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u043C, \u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0434\u043B\u044F \u0434\u0438\u0430\u0433\u043D\u043E\u0441\u0442\u0438\u043A\u0438, \u0442\u0430\u043A \u0438 \u0434\u043B\u044F \u0441\u0442\u0440\u0430\u0445\u043E\u0432\u0430\u043D\u0438\u044F.","\u0422\u0440\u0435\u0432\u043E\u0436\u043D\u044B\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 (\u0441\u0430\u043C\u044B\u0435 \u0447\u0430\u0441\u0442\u044B\u0435): \u0413\u0435\u043D\u0435\u0440\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u0442\u0440\u0435\u0432\u043E\u0436\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E (\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0439\u0441\u0442\u0432\u043E), \u041F\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E (\u0432\u043D\u0435\u0437\u0430\u043F\u043D\u044B\u0435 \u043F\u0440\u0438\u0441\u0442\u0443\u043F\u044B \u0441\u0438\u043B\u044C\u043D\u043E\u0433\u043E \u0441\u0442\u0440\u0430\u0445\u0430), \u0424\u043E\u0431\u0438\u0438 (\u0438\u0440\u0440\u0430\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u0441\u0442\u0440\u0430\u0445 \u043F\u0435\u0440\u0435\u0434 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u043C\u0438 \u0432\u0435\u0449\u0430\u043C\u0438), \u041E\u041A\u0420 (\u043D\u0430\u0432\u044F\u0437\u0447\u0438\u0432\u044B\u0435 \u043C\u044B\u0441\u043B\u0438 + \u043A\u043E\u043C\u043F\u0443\u043B\u044C\u0441\u0438\u0432\u043D\u044B\u0435 \u0440\u0438\u0442\u0443\u0430\u043B\u044B), \u041F\u0422\u0421\u0420 (\u043F\u043E\u0441\u043B\u0435 \u0442\u0440\u0430\u0432\u043C\u044B).","\u0420\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F: \u0411\u043E\u043B\u044C\u0448\u043E\u0435 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0432\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E (\u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u0430\u044F \u0433\u0440\u0443\u0441\u0442\u044C, \u043F\u043E\u0442\u0435\u0440\u044F \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u0430 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E \u0431\u043E\u043B\u0435\u0435 2 \u043D\u0435\u0434\u0435\u043B\u044C) \u0438 \u0411\u0438\u043F\u043E\u043B\u044F\u0440\u043D\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E (\u0447\u0435\u0440\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u044D\u043F\u0438\u0437\u043E\u0434\u043E\u0432 \u043C\u0430\u043D\u0438\u0438 \u0438 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438). \u0414\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0435\u0434\u0443\u0449\u0435\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0438\u043D\u0432\u0430\u043B\u0438\u0434\u043D\u043E\u0441\u0442\u0438 \u0432\u043E \u0432\u0441\u0435\u043C \u043C\u0438\u0440\u0435.","\u0428\u0438\u0437\u043E\u0444\u0440\u0435\u043D\u0438\u044F: \u0442\u044F\u0436\u0435\u043B\u043E\u0435 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0435\u0435 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0441\u0438\u043C\u043F\u0442\u043E\u043C\u044B (\u0433\u0430\u043B\u043B\u044E\u0446\u0438\u043D\u0430\u0446\u0438\u0438, \u0431\u0440\u0435\u0434, \u0434\u0435\u0437\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0440\u0435\u0447\u044C) \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u044B\u0435 \u0441\u0438\u043C\u043F\u0442\u043E\u043C\u044B (\u0443\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u0439 \u0430\u0444\u0444\u0435\u043A\u0442, \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0430\u044F \u0438\u0437\u043E\u043B\u044F\u0446\u0438\u044F). \u0414\u043E\u0444\u0430\u043C\u0438\u043D\u043E\u0432\u0430\u044F \u0433\u0438\u043F\u043E\u0442\u0435\u0437\u0430: \u0438\u0437\u0431\u044B\u0442\u043E\u0447\u043D\u0430\u044F \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u0434\u043E\u0444\u0430\u043C\u0438\u043D\u0430 \u0432 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0445 \u043F\u0443\u0442\u044F\u0445 \u043C\u043E\u0437\u0433\u0430.","\u0420\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438: \u0441\u0442\u043E\u0439\u043A\u0438\u0435, \u043D\u0435\u0433\u0438\u0431\u043A\u0438\u0435 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B. \u0410\u043D\u0442\u0438\u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0435 \u0420\u041B (\u043F\u0440\u0435\u043D\u0435\u0431\u0440\u0435\u0436\u0435\u043D\u0438\u0435 \u043F\u0440\u0430\u0432\u0430\u043C\u0438 \u0434\u0440\u0443\u0433\u0438\u0445, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u044D\u043C\u043F\u0430\u0442\u0438\u0438), \u041F\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u0435 \u0420\u041B (\u043D\u0435\u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u044B\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u0438 \u044D\u043C\u043E\u0446\u0438\u0438), \u041D\u0430\u0440\u0446\u0438\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0420\u041B (\u0433\u0440\u0430\u043D\u0434\u0438\u043E\u0437\u043D\u043E\u0441\u0442\u044C, \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u044C \u0432 \u0432\u043E\u0441\u0445\u0438\u0449\u0435\u043D\u0438\u0438).","\u041C\u043E\u0434\u0435\u043B\u044C \u0434\u0438\u0430\u0442\u0435\u0437\u0430-\u0441\u0442\u0440\u0435\u0441\u0441\u0430: \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0441\u043E\u0447\u0435\u0442\u0430\u043D\u0438\u044F \u0433\u0435\u043D\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439/\u0431\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u0440\u0435\u0434\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u0438 (\u0434\u0438\u0430\u0442\u0435\u0437) \u0438 \u0442\u0440\u0438\u0433\u0433\u0435\u0440\u043E\u0432 \u0438\u0437 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044B (\u0441\u0442\u0440\u0435\u0441\u0441). \u041D\u0438 \u0442\u043E\u0433\u043E, \u043D\u0438 \u0434\u0440\u0443\u0433\u043E\u0433\u043E \u0432 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043E\u0431\u044B\u0447\u043D\u043E \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E."],hy:["\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0568 \u0574\u057F\u0584\u0565\u0580\u056B, \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u056F\u0561\u0574 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0567, \u0578\u0580\u0568 \u0577\u0565\u0572\u057E\u0561\u056E \u0567, \u057F\u0561\u0563\u0576\u0561\u057A\u0561\u056C\u056B \u0587 \u0564\u056B\u057D\u0586\u0578\u0582\u0576\u056F\u0581\u056B\u0578\u0576\u0561\u056C (\u0565\u0580\u0565\u0584 \xAB\u0534\xBB): \u054F\u056B\u057A\u056B\u056F \u0579\u0570\u0561\u0574\u0561\u0580\u057E\u0578\u0572 \xAB\u0561\u0576\u0576\u0578\u0580\u0574\u0561\u056C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568\xBB \u057D\u0561\u0570\u0574\u0561\u0576\u0565\u056C\u056B\u057D \u056F\u0561\u0580\u0587\u0578\u0580 \u0565\u0576 \u0570\u0561\u0574\u0561\u057F\u0565\u0584\u057D\u057F\u0568 \u0587 \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u0568:","DSM-5-\u0568 (\u0531\u056D\u057F\u0578\u0580\u0578\u0577\u056B\u0579 \u0587 \u057E\u056B\u0573\u0561\u056F\u0561\u0563\u0580\u0561\u056F\u0561\u0576 \u0571\u0565\u057C\u0576\u0561\u0580\u056F) \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u0574\u0561\u0576 \u057D\u057F\u0561\u0576\u0564\u0561\u0580\u057F \u0570\u0561\u0574\u0561\u056F\u0561\u0580\u0563 \u0567: \u0531\u0575\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0564\u0561\u057D\u0561\u056F\u0561\u0580\u0563\u0578\u0582\u0574 \u0567 \u0568\u057D\u057F \u0561\u056D\u057F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u056B, \u0561\u0575\u056C \u0578\u0579 \u0569\u0565 \u057A\u0561\u057F\u0573\u0561\u057C\u0576\u0565\u0580\u056B, \u0587 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u057E\u0578\u0582\u0574 \u0567 \u0561\u056D\u057F\u0578\u0580\u0578\u0577\u0574\u0561\u0576 \u0587 \u0561\u057A\u0561\u0570\u0578\u057E\u0561\u0563\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0561\u0574\u0561\u0580:","\u0531\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580 (\u0561\u0574\u0565\u0576\u0561\u057F\u0561\u0580\u0561\u056E\u057E\u0561\u056E). \u0538\u0576\u0564\u0570\u0561\u0576\u0578\u0582\u0580 \u057F\u0561\u0563\u0576\u0561\u057A\u0561\u0575\u056B\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574 (\u0570\u0561\u0574\u0561\u057C \u0561\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576), \u056D\u0578\u0582\u0573\u0561\u057A\u0561\u0575\u056B\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574 (\u0570\u0561\u0576\u056F\u0561\u0580\u056E\u0561\u056F\u056B \u0578\u0582\u056A\u0565\u0572 \u057E\u0561\u056D\u056B \u0576\u0578\u057A\u0561\u0576\u0565\u0580), \u0586\u0578\u0562\u056B\u0561\u0576\u0565\u0580 (\u0578\u0580\u0578\u0577\u0561\u056F\u056B \u0562\u0561\u0576\u0565\u0580\u056B \u0570\u0561\u0576\u0564\u0565\u057A \u056B\u057C\u0561\u0581\u056B\u0578\u0576\u0561\u056C \u057E\u0561\u056D), OCD (\u056F\u057A\u0579\u0578\u0582\u0576 \u0574\u057F\u0584\u0565\u0580 + \u0570\u0561\u0580\u056F\u0561\u0564\u0580\u0561\u056F\u0561\u0576 \u056E\u0565\u057D\u0565\u0580), PTSD (\u057F\u0580\u0561\u057E\u0574\u0561\u0575\u056B\u0581 \u0570\u0565\u057F\u0578):","\u054F\u0580\u0561\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580. \u053D\u0578\u0577\u0578\u0580 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u057E \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574 (\u0574\u0577\u057F\u0561\u056F\u0561\u0576 \u057F\u056D\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0570\u0565\u057F\u0561\u0584\u0580\u0584\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0578\u0580\u0578\u0582\u057D\u057F, \u0578\u0580\u0568 \u057F\u0587\u0578\u0582\u0574 \u0567 2+ \u0577\u0561\u0562\u0561\u0569) \u0587 \u0535\u0580\u056F\u0562\u0587\u0565\u057C \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574 (\u0574\u0561\u0576\u056B\u0561\u0575\u056B \u0587 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0583\u0578\u056D\u0561\u0580\u056B\u0576\u057E\u0578\u0572 \u0564\u0580\u057E\u0561\u0563\u0576\u0565\u0580): \u0534\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0576 \u0561\u0577\u056D\u0561\u0580\u0570\u0578\u0582\u0574 \u0570\u0561\u0577\u0574\u0561\u0576\u0564\u0561\u0574\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u057A\u0561\u057F\u0573\u0561\u057C\u0576 \u0567:","\u0547\u056B\u0566\u0578\u0586\u0580\u0565\u0576\u056B\u0561. \u056E\u0561\u0576\u0580 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574, \u0578\u0580\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0564\u0580\u0561\u056F\u0561\u0576 \u0561\u056D\u057F\u0561\u0576\u056B\u0577\u0576\u0565\u0580 (\u0570\u0561\u056C\u0575\u0578\u0582\u0581\u056B\u0576\u0561\u0581\u056B\u0561\u0576\u0565\u0580, \u0566\u0561\u057C\u0561\u0576\u0581\u0561\u0576\u0584, \u0561\u0576\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A \u056D\u0578\u057D\u0584) \u0587 \u0562\u0561\u0581\u0561\u057D\u0561\u056F\u0561\u0576 \u0561\u056D\u057F\u0561\u0576\u056B\u0577\u0576\u0565\u0580 (\u0570\u0561\u0580\u0569 \u0561\u0586\u0565\u056F\u057F, \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0574\u0565\u056F\u0578\u0582\u057D\u0561\u0581\u0578\u0582\u0574): \u0534\u0578\u0586\u0561\u0574\u056B\u0576\u056B \u0570\u056B\u057A\u0578\u0569\u0565\u0566. \u0578\u0582\u0572\u0565\u0572\u056B \u0578\u0580\u0578\u0577\u0561\u056F\u056B \u0578\u0582\u0572\u056B\u0576\u0565\u0580\u0578\u0582\u0574 \u0564\u0578\u0586\u0561\u0574\u056B\u0576\u056B \u0561\u057E\u0565\u056C\u0581\u0578\u0582\u056F\u0561\u0575\u056B\u0576 \u0561\u056F\u057F\u056B\u057E\u0578\u0582\u0569\u0575\u0578\u0582\u0576:","\u0531\u0576\u0571\u0576\u0561\u0575\u056B\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580. \u056F\u0561\u0575\u0578\u0582\u0576, \u0561\u0576\u0573\u056F\u0578\u0582\u0576 \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580. \u0540\u0561\u056F\u0561\u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0531\u053D (\u0574\u0575\u0578\u0582\u057D\u0576\u0565\u0580\u056B \u056B\u0580\u0561\u057E\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0561\u0576\u057F\u0565\u057D\u0578\u0582\u0574, \u056F\u0561\u0580\u0565\u056F\u0581\u0561\u0576\u0584\u056B \u057A\u0561\u056F\u0561\u057D), \u057D\u0561\u0570\u0574\u0561\u0576\u0561\u0575\u056B\u0576 \u0531\u053D (\u0561\u0576\u056F\u0561\u0575\u0578\u0582\u0576 \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0587 \u0566\u0563\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580), \u0576\u0561\u0580\u0581\u056B\u057D\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u0531\u053D (\u057E\u0565\u0570\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0570\u056B\u0561\u0581\u0574\u0578\u0582\u0576\u0584\u056B \u056F\u0561\u0580\u056B\u0584):","\u0534\u056B\u0561\u0569\u0565\u0566-\u057D\u0569\u0580\u0565\u057D \u0574\u0578\u0564\u0565\u056C. \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0561\u057C\u0561\u057B\u0561\u0576\u0578\u0582\u0574 \u0565\u0576 \u0563\u0565\u0576\u0565\u057F\u056B\u056F\u0561\u056F\u0561\u0576/\u056F\u0565\u0576\u057D\u0561\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u0570\u0561\u056F\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 (\u0564\u056B\u0561\u0569\u0565\u0566) + \u0577\u0580\u057B\u0561\u056F\u0561 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u056B \u0563\u0578\u0580\u056E\u0578\u0576\u0576\u0565\u0580\u056B (\u057D\u0569\u0580\u0565\u057D) \u0570\u0561\u0574\u0561\u056F\u0581\u0574\u0561\u0576 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0584\u0578\u0582\u0574: \u054D\u0578\u057E\u0578\u0580\u0561\u0562\u0561\u0580 \u0564\u0580\u0561\u0576\u0581\u056B\u0581 \u0578\u0579 \u0574\u0565\u056F\u0568 \u0574\u056B\u0561\u0575\u0576\u0561\u056F \u0562\u0561\u057E\u0561\u0580\u0561\u0580 \u0579\u0567:"],az:['Psixoloji poz\u011Funluq deviant, k\u0259d\u0259rli v\u0259 disfunksiyal\u0131 (\xFC\xE7 "D") olan d\xFC\u015F\xFCnc\u0259l\u0259r, hissl\u0259r v\u0259 ya davran\u0131\u015Flar n\xFCmun\u0259sidir. "Anormal"\u0131 m\xFC\u0259yy\u0259nl\u0259\u015Fdir\u0259rk\u0259n kontekst v\u0259 m\u0259d\u0259niyy\u0259t vacibdir.',"DSM-5 (Diaqnostika v\u0259 Statistik T\u0259limat) standart t\u0259snifat sistemidir. \u015Eik\u0259stlikl\u0259ri s\u0259b\u0259bl\u0259rin\u0259 deyil, simptomlar\u0131na g\xF6r\u0259 t\u0259snif edir v\u0259 h\u0259m diaqnostika, h\u0259m d\u0259 s\u0131\u011Forta \xFC\xE7\xFCn istifad\u0259 olunur.","Anksiyete poz\u011Funluqlar\u0131 (\u0259n \xE7ox yay\u0131lm\u0131\u015F): \xDCmumi t\u0259\u015Fvi\u015F poz\u011Funlu\u011Fu (davaml\u0131 narahatl\u0131q), Panik poz\u011Funlu\u011Fu (q\u0259fil s\u0131x qorxu h\xFCcumlar\u0131), Fobiyalar (m\xFC\u0259yy\u0259n \u015Feyl\u0259r \xFC\xE7\xFCn irrasional qorxu), OKB (obsesif d\xFC\u015F\xFCnc\u0259l\u0259r + kompulsiv rituallar), TSSB (travmadan sonra).","\u018Fhval poz\u011Funluqlar\u0131: B\xF6y\xFCk Depressiv Poz\u011Funluq (davaml\u0131 k\u0259d\u0259r, maraq itkisi, 2+ h\u0259ft\u0259 davam ed\u0259n) v\u0259 Bipolyar Poz\u011Funluq (maniya v\u0259 depressiyan\u0131n n\xF6vb\u0259l\u0259\u015F\u0259n epizodlar\u0131). Depressiya d\xFCnya miqyas\u0131nda \u0259lilliyin \u0259sas s\u0259b\u0259bidir.","\u015Eizofreniya: m\xFCsb\u0259t simptomlar\u0131 (hal\xFCsinasiyalar, del\xFCziyalar, nizams\u0131z nitq) v\u0259 m\u0259nfi simptomlar\u0131 (d\xFCz affekt, sosial \xE7\u0259kilm\u0259) \u0259hat\u0259 ed\u0259n a\u011F\u0131r bir poz\u011Funluqdur. Dofamin f\u0259rziyy\u0259si: m\xFC\u0259yy\u0259n beyin yollar\u0131nda h\u0259ddind\u0259n art\u0131q dofamin aktivliyi.","\u015E\u0259xsiyy\u0259t poz\u011Funluqlar\u0131: davaml\u0131, qeyri-\xE7evik n\xFCmun\u0259l\u0259r. Antisosial \u015EP (ba\u015Fkalar\u0131n\u0131n h\xFCquqlar\u0131na m\u0259h\u0259l qoymamaq, empatiya \xE7at\u0131\u015Fmazl\u0131\u011F\u0131), S\u0259rh\u0259d \u015EP (qeyri-sabit m\xFCnasib\u0259tl\u0259r v\u0259 emosiyalar), Narsisistik \u015EP (\u0259z\u0259m\u0259tlilik, heyranl\u0131q ehtiyac\u0131).","Diathesis-stress modeli: poz\u011Funluqlar genetik/bioloji meyil (diathesis) v\u0259 m\xFChitd\u0259n g\u0259l\u0259n t\u0259tik\xE7il\u0259r (stress) birl\u0259\u015Fm\u0259sinin n\u0259tic\u0259sidir. He\xE7 biri t\u0259k ba\u015F\u0131na ad\u0259t\u0259n kifay\u0259t deyil."]},funFact:{en:"About 1 in 5 adults experiences a mental health condition in any given year. Depression and anxiety cost the global economy $1 trillion annually in lost productivity \u2014 yet most disorders are highly treatable with proper intervention.",ka:"\u10E7\u10DD\u10D5\u10D4\u10DA\u10EC\u10DA\u10D8\u10E3\u10E0\u10D0\u10D3 5-\u10D3\u10D0\u10DC 1 \u10D6\u10E0\u10D3\u10D0\u10E1\u10E0\u10E3\u10DA\u10D8 \u10D2\u10D0\u10DC\u10D8\u10EA\u10D3\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1\u10D7\u10D0\u10DC \u10D3\u10D0\u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA \u10DB\u10D3\u10D2\u10DD\u10DB\u10D0\u10E0\u10D4\u10DD\u10D1\u10D0\u10E1. \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D0 \u10D3\u10D0 \u10E8\u10E4\u10DD\u10D7\u10D5\u10D0 \u10DB\u10E1\u10DD\u10E4\u10DA\u10D8\u10DD \u10D4\u10D9\u10DD\u10DC\u10DD\u10DB\u10D8\u10D9\u10D0\u10E1 \u10E7\u10DD\u10D5\u10D4\u10DA\u10EC\u10DA\u10D8\u10E3\u10E0\u10D0\u10D3 1 \u10E2\u10E0\u10D8\u10DA\u10D8\u10DD\u10DC\u10D8 \u10D3\u10DD\u10DA\u10D0\u10E0\u10D8 \u10E3\u10EF\u10D3\u10D4\u10D1\u10D0.",ru:"\u041F\u0440\u0438\u043C\u0435\u0440\u043D\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u043F\u044F\u0442\u044B\u0439 \u0432\u0437\u0440\u043E\u0441\u043B\u044B\u0439 \u0435\u0436\u0435\u0433\u043E\u0434\u043D\u043E \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0441 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430\u043C\u0438 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F. \u0414\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F \u0438 \u0442\u0440\u0435\u0432\u043E\u0433\u0430 \u0435\u0436\u0435\u0433\u043E\u0434\u043D\u043E \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 \u043C\u0438\u0440\u043E\u0432\u043E\u0439 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u0435 1 \u0442\u0440\u0438\u043B\u043B\u0438\u043E\u043D \u0434\u043E\u043B\u043B\u0430\u0440\u043E\u0432 \u0438\u0437-\u0437\u0430 \u043F\u043E\u0442\u0435\u0440\u0438 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438.",hy:"\u0545\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580 5 \u0574\u0565\u056E\u0561\u0570\u0561\u057D\u0561\u056F\u056B\u0581 \u0574\u0578\u057F 1-\u0568 \u0561\u0574\u0565\u0576 \u057F\u0561\u0580\u056B \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u056B\u0573\u0561\u056F \u0567 \u0578\u0582\u0576\u0565\u0576\u0578\u0582\u0574: \u0534\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0576 \u0587 \u0561\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0570\u0561\u0574\u0561\u0577\u056D\u0561\u0580\u0570\u0561\u0575\u056B\u0576 \u057F\u0576\u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0561\u0576\u0568 \u057F\u0561\u0580\u0565\u056F\u0561\u0576 1 \u057F\u0580\u056B\u056C\u056B\u0578\u0576 \u0564\u0578\u056C\u0561\u0580 \u0565\u0576 \u0561\u0580\u056A\u0565\u0576\u0578\u0582\u0574:",az:"H\u0259r 5 yetkind\u0259n t\u0259xmin\u0259n 1-i h\u0259r il psixi sa\u011Flaml\u0131q problemi ya\u015Fay\u0131r. Depressiya v\u0259 narahatl\u0131q qlobal iqtisadiyyata h\u0259r il 1 trilyon dollara ba\u015Fa g\u0259lir."},realWorld:{en:"The shift from institutionalization to community-based mental health care (deinstitutionalization) transformed treatment. Today, early intervention programs for psychosis can reduce symptoms by 50% and dramatically improve long-term outcomes.",ka:"\u10D8\u10DC\u10E1\u10E2\u10D8\u10E2\u10E3\u10EA\u10D8\u10DD\u10DC\u10D0\u10DA\u10D8\u10D6\u10D0\u10EA\u10D8\u10D8\u10D3\u10D0\u10DC \u10E1\u10D0\u10D6\u10DD\u10D2\u10D0\u10D3\u10DD\u10D4\u10D1\u10D0\u10D6\u10D4 \u10D3\u10D0\u10E4\u10E3\u10EB\u10DC\u10D4\u10D1\u10E3\u10DA \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0 \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D0\u10D6\u10D4 \u10D2\u10D0\u10D3\u10D0\u10E1\u10D5\u10DA\u10D0\u10DB \u10E8\u10D4\u10EA\u10D5\u10D0\u10DA\u10D0 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D0. \u10D0\u10D3\u10E0\u10D4\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D4\u10DC\u10EA\u10D8\u10D8\u10E1 \u10DE\u10E0\u10DD\u10D2\u10E0\u10D0\u10DB\u10D4\u10D1\u10E1 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0\u10D7 \u10E1\u10D8\u10DB\u10DE\u10E2\u10DD\u10DB\u10D4\u10D1\u10D8\u10E1 50%-\u10D8\u10D7 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0.",ru:"\u041F\u0435\u0440\u0435\u0445\u043E\u0434 \u043E\u0442 \u0438\u043D\u0441\u0442\u0438\u0442\u0443\u0446\u0438\u043E\u043D\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043A \u043F\u0441\u0438\u0445\u0438\u0430\u0442\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043F\u043E\u043C\u043E\u0449\u0438 \u043F\u043E \u043C\u0435\u0441\u0442\u0443 \u0436\u0438\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430 (\u0434\u0435\u0438\u043D\u0441\u0442\u0438\u0442\u0443\u0446\u0438\u043E\u043D\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F) \u0438\u0437\u043C\u0435\u043D\u0438\u043B \u043C\u0435\u0442\u043E\u0434\u044B \u043B\u0435\u0447\u0435\u043D\u0438\u044F. \u0420\u0430\u043D\u043D\u0435\u0435 \u0432\u043C\u0435\u0448\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E \u043C\u043E\u0436\u0435\u0442 \u0443\u043C\u0435\u043D\u044C\u0448\u0438\u0442\u044C \u0441\u0438\u043C\u043F\u0442\u043E\u043C\u044B \u043D\u0430 50%.",hy:"\u053B\u0576\u057D\u057F\u056B\u057F\u0578\u0582\u0581\u056B\u0578\u0576\u0561\u056C\u0561\u0581\u0578\u0582\u0574\u056B\u0581 \u057F\u0565\u0572\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u0561\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0576\u0561\u0574\u0584\u056B \u0561\u0576\u0581\u0578\u0582\u0574\u0568 (\u0564\u0565\u056B\u0576\u057D\u057F\u056B\u057F\u0578\u0582\u0581\u056B\u0578\u0576\u0561\u056C\u0561\u0581\u0578\u0582\u0574) \u0583\u0578\u056D\u0565\u0581 \u0562\u0578\u0582\u056A\u0578\u0582\u0574\u0568: \u054E\u0561\u0572 \u0574\u056B\u057B\u0561\u0574\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0565\u056C \u0561\u056D\u057F\u0561\u0576\u056B\u0577\u0576\u0565\u0580\u0568 50%-\u0578\u057E:",az:"\u0130nstitusionalla\u015Fmadan icma \u0259sasl\u0131 psixi sa\u011Flaml\u0131q xidm\u0259tin\u0259 ke\xE7id (deinstitusionalla\u015Fma) m\xFCalic\u0259ni d\u0259yi\u015Fdirdi. Erk\u0259n m\xFCdaxil\u0259 proqramlar\u0131 simptomlar\u0131 50% azalda bil\u0259r."}},15:{title:{en:"Therapies",ka:"\u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D4\u10D1\u10D8",ru:"\u0422\u0435\u0440\u0430\u043F\u0438\u044F",hy:"\u0539\u0565\u0580\u0561\u057A\u056B\u0561\u0576\u0565\u0580",az:"Terapiyalar"},description:{en:"Approaches to treating psychological disorders.",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D4\u10D1\u10D8.",ru:"\u041F\u043E\u0434\u0445\u043E\u0434\u044B \u043A \u043B\u0435\u0447\u0435\u043D\u0438\u044E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432.",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u0562\u0578\u0582\u056A\u0574\u0561\u0576 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0576\u0565\u0580.",az:"Psixoloji poz\u011Funluqlar\u0131n m\xFCalic\u0259sin\u0259 yana\u015Fmalar."},keyTopics:{en:["Psychotherapy","CBT","Humanistic Therapy","Biomedical Therapies","Group Therapy"],ka:["\u10E4\u10E1\u10D8\u10E5\u10DD\u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0","CBT","\u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0","\u10D1\u10D8\u10DD\u10E1\u10D0\u10DB\u10D4\u10D3\u10D8\u10EA\u10D8\u10DC\u10DD \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0","\u10EF\u10D2\u10E3\u10E4\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0"],ru:["\u041F\u0441\u0438\u0445\u043E\u0442\u0435\u0440\u0430\u043F\u0438\u044F","\u0417\u0411\u0422","\u0413\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F","\u0411\u0438\u043E\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F","\u0413\u0440\u0443\u043F\u043F\u043E\u0432\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F"],hy:["\u0540\u0578\u0563\u0565\u0569\u0565\u0580\u0561\u057A\u056B\u0561","CBT","\u0540\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u0569\u0565\u0580\u0561\u057A\u056B\u0561","\u053F\u0565\u0576\u057D\u0561\u0562\u056A\u0577\u056F\u0561\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561","\u053D\u0574\u0562\u0561\u0575\u056B\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561"],az:["Psixoterapiya","CBT","Humanist Terapiya","Biotibbi M\xFCalic\u0259l\u0259r","Qrup terapiyas\u0131"]},summary:{en:"Treatment of psychological disorders takes many forms, each grounded in different theoretical perspectives about the causes of mental illness. This chapter compares the major therapeutic approaches and evaluates their effectiveness. Psychoanalytic and psychodynamic therapies explore unconscious conflicts through free association, dream analysis, and the therapeutic relationship, offering long-term, insight-oriented treatment. Cognitive-Behavioral Therapy (CBT) \u2014 the gold standard for anxiety and depression \u2014 identifies and restructures distorted thinking patterns while modifying maladaptive behaviors, typically in 12 to 20 sessions. Humanistic therapy, particularly Rogers's client-centered approach, creates a supportive environment through unconditional positive regard, empathy, and genuineness to facilitate self-exploration. Biomedical therapies include antidepressants (SSRIs that increase serotonin), anti-anxiety medications (benzodiazepines), antipsychotics (dopamine blockers), mood stabilizers (lithium), and ECT for treatment-resistant depression. The chapter also covers group therapy, family therapy, and the importance of evidence-based practice \u2014 matching the treatment approach to the specific diagnosis based on research evidence, clinical expertise, and patient preferences.",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10E0\u10E6\u10D5\u10D4\u10D5\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D0 \u10DB\u10E0\u10D0\u10D5\u10D0\u10DA \u10E4\u10DD\u10E0\u10DB\u10D0\u10E1 \u10D8\u10E6\u10D4\u10D1\u10E1, \u10D7\u10D8\u10D7\u10DD\u10D4\u10E3\u10DA\u10D8 \u10D4\u10E4\u10E3\u10EB\u10DC\u10D4\u10D1\u10D0 \u10E4\u10E1\u10D8\u10E5\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D6\u10D4\u10D6\u10D4\u10D1\u10D8\u10E1 \u10E8\u10D4\u10E1\u10D0\u10EE\u10D4\u10D1  \u10E1\u10EE\u10D5\u10D0\u10D3\u10D0\u10E1\u10EE\u10D5\u10D0 \u10D7\u10D4\u10DD\u10E0\u10D8\u10E3\u10DA \u10DE\u10D4\u10E0\u10E1\u10DE\u10D4\u10E5\u10E2\u10D8\u10D5\u10D0\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D0\u10D3\u10D0\u10E0\u10D4\u10D1\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10E3\u10DA \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D4\u10D1\u10E1 \u10D3\u10D0 \u10D0\u10E4\u10D0\u10E1\u10D4\u10D1\u10E1 \u10DB\u10D0\u10D7 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10DD\u10D1\u10D0\u10E1. \u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10D3\u10D8\u10DC\u10D0\u10DB\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D4\u10D1\u10D8 \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0 \u10D9\u10DD\u10DC\u10E4\u10DA\u10D8\u10E5\u10E2\u10D4\u10D1\u10E1 \u10D7\u10D0\u10D5\u10D8\u10E1\u10E3\u10E4\u10D0\u10DA\u10D8 \u10D0\u10E1\u10DD\u10EA\u10D8\u10D0\u10EA\u10D8\u10D8\u10E1, \u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D0\u10DC\u10D0\u10DA\u10D8\u10D6\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10E3\u10DA\u10D8 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7, \u10E1\u10D7\u10D0\u10D5\u10D0\u10D6\u10DD\u10D1\u10E1 \u10D2\u10E0\u10EB\u10D4\u10DA\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC, \u10D8\u10DC\u10E1\u10D0\u10D8\u10E2\u10D6\u10D4 \u10DD\u10E0\u10D8\u10D4\u10DC\u10E2\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D0\u10E1. \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0-\u10D1\u10D8\u10F0\u10D4\u10D5\u10D8\u10DD\u10E0\u10E3\u10DA\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 (CBT) \u2014 \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1 \u201E\u10DD\u10E5\u10E0\u10DD\u10E1 \u10E1\u10E2\u10D0\u10DC\u10D3\u10D0\u10E0\u10E2\u10D8\u201C \u2014 \u10D0\u10D5\u10DA\u10D4\u10DC\u10E1 \u10D3\u10D0 \u10EA\u10D5\u10DA\u10D8\u10E1 \u10D3\u10D0\u10DB\u10D0\u10EE\u10D8\u10DC\u10EF\u10D4\u10D1\u10E3\u10DA \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E4\u10DD\u10E0\u10DB\u10D4\u10D1\u10E1, \u10D0\u10DB\u10D0\u10E1\u10D7\u10D0\u10DC \u10EA\u10D5\u10DA\u10D8\u10E1 \u10DB\u10D0\u10D5\u10DC\u10D4 \u10E5\u10EA\u10D4\u10D5\u10D4\u10D1\u10E1, \u10E0\u10DD\u10D2\u10DD\u10E0\u10EA \u10EC\u10D4\u10E1\u10D8 12-\u10D3\u10D0\u10DC 20 \u10E1\u10D4\u10E1\u10D8\u10D0\u10DB\u10D3\u10D4 \u10DE\u10D4\u10E0\u10D8\u10DD\u10D3\u10E8\u10D8. \u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0, \u10D2\u10D0\u10DC\u10E1\u10D0\u10D9\u10E3\u10D7\u10E0\u10D4\u10D1\u10D8\u10D7 \u10E0\u10DD\u10EF\u10D4\u10E0\u10E1\u10D8\u10E1 \u10D9\u10DA\u10D8\u10D4\u10DC\u10E2\u10D6\u10D4 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D0, \u10E3\u10D6\u10E0\u10E3\u10DC\u10D5\u10D4\u10DA\u10E7\u10DD\u10E4\u10E1 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10DB\u10ED\u10D4\u10E0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10E3\u10DE\u10D8\u10E0\u10DD\u10D1\u10DD \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D8\u10E1, \u10D4\u10DB\u10DE\u10D0\u10D7\u10D8\u10D8\u10E1 \u10D3\u10D0 \u10D2\u10E3\u10DA\u10EC\u10E0\u10E4\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7, \u10E0\u10D0\u10D7\u10D0 \u10EE\u10D4\u10DA\u10D8 \u10E8\u10D4\u10E3\u10EC\u10E7\u10DD\u10E1 \u10E1\u10D0\u10D9\u10E3\u10D7\u10D0\u10E0\u10D8 \u10D7\u10D0\u10D5\u10D8\u10E1 \u10E8\u10D4\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0\u10E1. \u10D1\u10D8\u10DD\u10E1\u10D0\u10DB\u10D4\u10D3\u10D8\u10EA\u10D8\u10DC\u10DD \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D4\u10D1\u10D8 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D0\u10DC\u10E2\u10D8\u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D0\u10DC\u10E2\u10D4\u10D1\u10E1 (SSRI-\u10D4\u10D1\u10D8, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10D6\u10E0\u10D3\u10D8\u10E1 \u10E1\u10D4\u10E0\u10DD\u10E2\u10DD\u10DC\u10D8\u10DC\u10E1), \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10E1 \u10E1\u10D0\u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD \u10DB\u10D4\u10D3\u10D8\u10D9\u10D0\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10E1 (\u10D1\u10D4\u10DC\u10D6\u10DD\u10D3\u10D8\u10D0\u10D6\u10D4\u10DE\u10D8\u10DC\u10D4\u10D1\u10D8), \u10D0\u10DC\u10E2\u10D8\u10E4\u10E1\u10D8\u10E5\u10DD\u10E2\u10D8\u10D9\u10D4\u10D1\u10E1 (\u10D3\u10DD\u10E4\u10D0\u10DB\u10D8\u10DC\u10D8\u10E1 \u10D1\u10DA\u10DD\u10D9\u10D0\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8), \u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10D8\u10D6\u10D0\u10E2\u10DD\u10E0\u10D4\u10D1\u10E1 (\u10DA\u10D8\u10D7\u10D8\u10E3\u10DB\u10D8) \u10D3\u10D0 ECT-\u10E1 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10E0\u10D4\u10D6\u10D8\u10E1\u10E2\u10D4\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10EF\u10D2\u10E3\u10E4\u10E3\u10E0 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0\u10E1, \u10DD\u10EF\u10D0\u10EE\u10E3\u10E0 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0\u10E1 \u10D3\u10D0 \u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D6\u10D4 \u10D3\u10D0\u10E4\u10E3\u10EB\u10DC\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10D8\u10E1 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1 \u2014 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DB\u10D8\u10D3\u10D2\u10DD\u10DB\u10D8\u10E1 \u10DB\u10DD\u10E0\u10D2\u10D4\u10D1\u10D0\u10E1 \u10D9\u10DD\u10DC\u10D9\u10E0\u10D4\u10E2\u10E3\u10DA \u10D3\u10D8\u10D0\u10D2\u10DC\u10DD\u10D6\u10D6\u10D4 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1, \u10D9\u10DA\u10D8\u10DC\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10E2\u10D8\u10D6\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DE\u10D0\u10EA\u10D8\u10D4\u10DC\u10E2\u10D8\u10E1 \u10DE\u10E0\u10D4\u10E4\u10D4\u10E0\u10D4\u10DC\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D0\u10E4\u10E3\u10EB\u10D5\u10D4\u10DA\u10D6\u10D4.",ru:"\u041B\u0435\u0447\u0435\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0444\u043E\u0440\u043C, \u043A\u0430\u0436\u0434\u0430\u044F \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0430 \u043D\u0430 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0432\u0437\u0433\u043B\u044F\u0434\u0430\u0445 \u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u0445 \u043F\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0437\u0430\u0431\u043E\u043B\u0435\u0432\u0430\u043D\u0438\u0439. \u042D\u0442\u0430 \u0433\u043B\u0430\u0432\u0430 \u0441\u0440\u0430\u0432\u043D\u0438\u0432\u0430\u0435\u0442 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0442\u0435\u0440\u0430\u043F\u0435\u0432\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u044B \u0438 \u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u0442 \u0438\u0445 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C. \u041F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0438 \u043F\u0441\u0438\u0445\u043E\u0434\u0438\u043D\u0430\u043C\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u044B \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0445 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u0439, \u0430\u043D\u0430\u043B\u0438\u0437\u0430 \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u0439 \u0438 \u0442\u0435\u0440\u0430\u043F\u0435\u0432\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0439, \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044F \u0434\u043E\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u043E\u0435 \u043B\u0435\u0447\u0435\u043D\u0438\u0435, \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043D\u0430 \u0438\u043D\u0441\u0430\u0439\u0442. \u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E-\u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F (\u041A\u041F\u0422) \u2014 \u0437\u043E\u043B\u043E\u0442\u043E\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0442\u0440\u0435\u0432\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0438 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438 \u2014 \u0432\u044B\u044F\u0432\u043B\u044F\u0435\u0442 \u0438 \u043F\u0435\u0440\u0435\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u043D\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F, \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u043C\u043E\u0434\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u044F \u0434\u0435\u0437\u0430\u0434\u0430\u043F\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u043E\u0431\u044B\u0447\u043D\u043E \u0437\u0430 12\u201320 \u0441\u0435\u0430\u043D\u0441\u043E\u0432. \u0413\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F, \u0432 \u0447\u0430\u0441\u0442\u043D\u043E\u0441\u0442\u0438 \u043A\u043B\u0438\u0435\u043D\u0442-\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043F\u043E\u0434\u0445\u043E\u0434 \u0420\u043E\u0434\u0436\u0435\u0440\u0441\u0430, \u0441\u043E\u0437\u0434\u0430\u0435\u0442 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0443\u044E \u0441\u0440\u0435\u0434\u0443 \u0447\u0435\u0440\u0435\u0437 \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E\u0435 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u044D\u043C\u043F\u0430\u0442\u0438\u044E \u0438 \u0438\u0441\u043A\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0434\u043B\u044F \u0441\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0441\u0430\u043C\u043E\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044E. \u0411\u0438\u043E\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0430\u043D\u0442\u0438\u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0430\u043D\u0442\u044B (\u0421\u0418\u041E\u0417\u0421, \u043F\u043E\u0432\u044B\u0448\u0430\u044E\u0449\u0438\u0435 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0441\u0435\u0440\u043E\u0442\u043E\u043D\u0438\u043D\u0430), \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0442\u0440\u0435\u0432\u043E\u0436\u043D\u044B\u0435 \u043F\u0440\u0435\u043F\u0430\u0440\u0430\u0442\u044B (\u0431\u0435\u043D\u0437\u043E\u0434\u0438\u0430\u0437\u0435\u043F\u0438\u043D\u044B), \u0430\u043D\u0442\u0438\u043F\u0441\u0438\u0445\u043E\u0442\u0438\u043A\u0438 (\u0431\u043B\u043E\u043A\u0430\u0442\u043E\u0440\u044B \u0434\u043E\u0444\u0430\u043C\u0438\u043D\u0430), \u0441\u0442\u0430\u0431\u0438\u043B\u0438\u0437\u0430\u0442\u043E\u0440\u044B \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F (\u043B\u0438\u0442\u0438\u0439) \u0438 \u042D\u0421\u0422 \u0434\u043B\u044F \u0440\u0435\u0437\u0438\u0441\u0442\u0435\u043D\u0442\u043D\u043E\u0439 \u043A \u043B\u0435\u0447\u0435\u043D\u0438\u044E \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438. \u0413\u043B\u0430\u0432\u0430 \u0442\u0430\u043A\u0436\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u0443\u044E \u0442\u0435\u0440\u0430\u043F\u0438\u044E, \u0441\u0435\u043C\u0435\u0439\u043D\u0443\u044E \u0442\u0435\u0440\u0430\u043F\u0438\u044E \u0438 \u0432\u0430\u0436\u043D\u043E\u0441\u0442\u044C \u043D\u0430\u0443\u0447\u043D\u043E-\u043E\u0431\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u2014 \u043F\u043E\u0434\u0431\u043E\u0440\u0430 \u0442\u0435\u0440\u0430\u043F\u0435\u0432\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u043E\u0434\u0445\u043E\u0434\u0430 \u043A \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u043C\u0443 \u0434\u0438\u0430\u0433\u043D\u043E\u0437\u0443 \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0439, \u043A\u043B\u0438\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 \u0438 \u043F\u0440\u0435\u0434\u043F\u043E\u0447\u0442\u0435\u043D\u0438\u0439 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u0430.",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u0562\u0578\u0582\u056A\u0578\u0582\u0574\u0568 \u0562\u0561\u0566\u0574\u0561\u0569\u056B\u057E \u0571\u0587\u0565\u0580 \u0567 \u0568\u0576\u0564\u0578\u0582\u0576\u0578\u0582\u0574, \u0578\u0580\u0578\u0576\u0581\u056B\u0581 \u0575\u0578\u0582\u0580\u0561\u0584\u0561\u0576\u0579\u0575\u0578\u0582\u0580\u0568 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0567 \u0570\u0578\u0563\u0565\u056F\u0561\u0576 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u057A\u0561\u057F\u0573\u0561\u057C\u0576\u0565\u0580\u056B \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0575\u0561\u056C \u057F\u0561\u0580\u0562\u0565\u0580 \u057F\u0565\u057D\u0561\u056F\u0561\u0576 \u057F\u0565\u057D\u0561\u056F\u0565\u057F\u0576\u0565\u0580\u056B \u057E\u0580\u0561: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0570\u0561\u0574\u0565\u0574\u0561\u057F\u0578\u0582\u0574 \u0567 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u0587\u057F\u056B\u056F \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u0587 \u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574 \u0564\u0580\u0561\u0576\u0581 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0540\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0561\u056F\u0561\u0576 \u0587 \u0570\u0578\u0563\u0565\u0564\u056B\u0576\u0561\u0574\u056B\u056F \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576\u0565\u0580\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0565\u0576 \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576 \u0570\u0561\u056F\u0561\u0574\u0561\u0580\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0561\u0566\u0561\u057F \u0561\u057D\u0578\u0581\u056B\u0561\u0581\u056B\u0561\u0575\u056B, \u0565\u0580\u0561\u0566\u0576\u0565\u0580\u056B \u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0569\u0565\u0580\u0561\u057A\u0587\u057F\u056B\u056F \u0583\u0578\u056D\u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E\u055D \u0561\u057C\u0561\u057B\u0561\u0580\u056F\u0565\u056C\u0578\u057E \u0565\u0580\u056F\u0561\u0580\u0561\u056A\u0561\u0574\u056F\u0565\u057F, \u056B\u0576\u057D\u0561\u0575\u0569\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0562\u0578\u0582\u056A\u0578\u0582\u0574: \u053F\u0578\u0563\u0576\u056B\u057F\u056B\u057E-\u057E\u0561\u0580\u0584\u0561\u0575\u056B\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576 (CBT)\u055D \u0561\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0570\u0561\u0574\u0561\u0580 \u0578\u057D\u056F\u0565 \u057D\u057F\u0561\u0576\u0564\u0561\u0580\u057F\u0568 \u2014 \u0570\u0561\u0575\u057F\u0576\u0561\u0562\u0565\u0580\u0578\u0582\u0574 \u0587 \u057E\u0565\u0580\u0561\u056F\u0561\u057C\u0578\u0582\u0581\u0578\u0582\u0574 \u0567 \u056D\u0565\u0572\u0561\u0569\u0575\u0578\u0582\u0580\u057E\u0561\u056E \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568\u055D \u0574\u056B\u0561\u056A\u0561\u0574\u0561\u0576\u0561\u056F \u0583\u0578\u0583\u0578\u056D\u0565\u056C\u0578\u057E \u0561\u0576\u0570\u0561\u0580\u0574\u0561\u0580\u057E\u0578\u0572\u0561\u056F\u0561\u0576 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568 (\u057D\u0578\u057E\u0578\u0580\u0561\u0562\u0561\u0580 12-\u056B\u0581 20 \u057D\u0565\u0561\u0576\u057D\u0576\u0565\u0580\u0578\u0582\u0574): \u0540\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576, \u0574\u0561\u057D\u0576\u0561\u057E\u0578\u0580\u0561\u057A\u0565\u057D \u054C\u0578\u057B\u0565\u0580\u057D\u056B \u0570\u0561\u0573\u0561\u056D\u0578\u0580\u0564\u0561\u056F\u0565\u0576\u057F\u0580\u0578\u0576 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0568, \u0561\u057A\u0561\u0570\u0578\u057E\u0578\u0582\u0574 \u0567 \u0561\u057B\u0561\u056F\u0581\u0578\u0572 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u055D \u0561\u0576\u057E\u0565\u0580\u0561\u057A\u0561\u0570 \u0564\u0580\u0561\u056F\u0561\u0576 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584\u056B, \u0567\u0574\u057A\u0561\u057F\u056B\u0561\u0575\u056B \u0587 \u0561\u0576\u056F\u0565\u0572\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u056B\u057B\u0578\u0581\u0578\u057E\u055D \u056B\u0576\u0584\u0576\u0561\u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574\u0568 \u056D\u0569\u0561\u0576\u0565\u056C\u0578\u0582 \u0576\u057A\u0561\u057F\u0561\u056F\u0578\u057E\u0589 \u053F\u0565\u0576\u057D\u0561\u0562\u056A\u0577\u056F\u0561\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576\u0565\u0580\u0568 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0565\u0576 \u0570\u0561\u056F\u0561\u0564\u0565\u057A\u0580\u0565\u057D\u0561\u0576\u057F\u0576\u0565\u0580 (SSRI-\u0576\u0565\u0580, \u0578\u0580\u0578\u0576\u0584 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u0565\u0576 \u057D\u0565\u0580\u0578\u057F\u0578\u0576\u056B\u0576\u0568), \u0570\u0561\u056F\u0561\u057F\u0561\u0563\u0576\u0561\u057A\u0561\u0575\u056B\u0576 \u0564\u0565\u0572\u0561\u0574\u056B\u057B\u0578\u0581\u0576\u0565\u0580 (\u0562\u0565\u0576\u0566\u0578\u0564\u056B\u0561\u0566\u0565\u057A\u056B\u0576\u0576\u0565\u0580), \u0570\u0561\u056F\u0561\u057A\u057D\u056B\u056D\u0578\u057F\u056B\u056F \u0574\u056B\u057B\u0578\u0581\u0576\u0565\u0580 (\u0564\u0578\u0586\u0561\u0574\u056B\u0576\u056B \u0562\u056C\u0578\u056F\u0561\u057F\u0578\u0580\u0576\u0565\u0580), \u057F\u0580\u0561\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0561\u0575\u0578\u0582\u0576\u0561\u0581\u0578\u0582\u0581\u056B\u0579\u0576\u0565\u0580 (\u056C\u056B\u0569\u056B\u0578\u0582\u0574) \u0587 \u0537\u0547\u0539 (ECT)\u055D \u0562\u0578\u0582\u056A\u0574\u0561\u0576 \u0576\u056F\u0561\u057F\u0574\u0561\u0574\u0562 \u056F\u0561\u0575\u0578\u0582\u0576 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0564\u0565\u057A\u0584\u0578\u0582\u0574: \u0533\u056C\u0578\u0582\u056D\u0568 \u0576\u0561\u0587 \u0576\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561, \u0568\u0576\u057F\u0561\u0576\u0565\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561 \u0587 \u0561\u057A\u0561\u0581\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u057A\u0580\u0561\u056F\u057F\u056B\u056F\u0561\u0575\u056B \u056F\u0561\u0580\u0587\u0578\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568\u055D \u0562\u0578\u0582\u056A\u0574\u0561\u0576 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574\u0568 \u0570\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0565\u0581\u0576\u0565\u056C\u0578\u057E \u056F\u0578\u0576\u056F\u0580\u0565\u057F \u0561\u056D\u057F\u0578\u0580\u0578\u0577\u0574\u0561\u0576\u0568\u055D \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0561\u057A\u0561\u0581\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u056B, \u056F\u056C\u056B\u0576\u056B\u056F\u0561\u056F\u0561\u0576 \u0583\u0578\u0580\u0571\u0561\u0584\u0576\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0570\u056B\u057E\u0561\u0576\u0564\u056B \u0576\u0561\u056D\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u057E\u0580\u0561:",az:"Psixoloji poz\u011Funluqlar\u0131n m\xFCalic\u0259si, h\u0259r biri psixi x\u0259st\u0259likl\u0259rin s\u0259b\u0259bl\u0259ri haqq\u0131nda f\u0259rqli n\u0259z\u0259ri perspektivl\u0259r\u0259 \u0259saslanan bir \xE7ox formaya malikdir. Bu f\u0259sil \u0259sas m\xFCalic\u0259vi (terapevtik) yana\u015Fmalar\u0131 m\xFCqayis\u0259 edir v\u0259 onlar\u0131n effektivliyini qiym\u0259tl\u0259ndirir. Psixoanalitik v\u0259 psixodinamik terapiyalar s\u0259rb\u0259st assosiasiya, yuxu analizi v\u0259 terapevtik m\xFCnasib\u0259t vasit\u0259sil\u0259 \u015F\xFCuralt\u0131 m\xFCnaqi\u015F\u0259l\u0259ri ara\u015Fd\u0131raraq, uzunm\xFCdd\u0259tli, daxili anlay\u0131\u015Fa \u0259saslanan m\xFCalic\u0259 t\u0259klif edir. Kognitiv-Davran\u0131\u015F Terapiyas\u0131 (CBT) \u2014 narahatl\u0131q v\u0259 depressiya \xFC\xE7\xFCn q\u0131z\u0131l standart \u2014 ad\u0259t\u0259n 12 - 20 seansda z\u0259r\u0259rli davran\u0131\u015Flar\u0131 d\u0259yi\u015Fdir\u0259rk\u0259n t\u0259hrif olunmu\u015F d\xFC\u015F\xFCnc\u0259 n\xFCmun\u0259l\u0259rini m\xFC\u0259yy\u0259nl\u0259\u015Fdirir v\u0259 yenid\u0259n qurur. Humanist terapiya, x\xFCsusil\u0259 d\u0259 Rogersin m\xFC\u015Ft\u0259ri y\xF6n\xFCml\xFC yana\u015Fmas\u0131, \xF6z\xFCn\xFC k\u0259\u015Ff etm\u0259yi asanla\u015Fd\u0131rmaq \xFC\xE7\xFCn \u015F\u0259rtsiz m\xFCsb\u0259t qiym\u0259t, empatiya v\u0259 s\u0259mimiyy\u0259t vasit\u0259sil\u0259 d\u0259st\u0259kl\u0259yici m\xFChit yarad\u0131r. Biotibbi m\xFCalic\u0259l\u0259r\u0259 antidepressantlar (serotonini art\u0131ran SSRI-lar), narahatl\u0131q \u0259leyhin\u0259 d\u0259rmanlar (benzodiazepinl\u0259r), antipsixotikl\u0259r (dofamin blokerl\u0259ri), \u0259hval-ruhiyy\u0259 stabilizatorlar\u0131 (litium) v\u0259 m\xFCalic\u0259y\u0259 dir\u0259ni\u015F g\xF6st\u0259r\u0259n depressiya \xFC\xE7\xFCn EST daxildir. F\u0259sil h\u0259m\xE7inin qrup terapiyas\u0131n\u0131, ail\u0259 terapiyas\u0131n\u0131 v\u0259 s\xFCbuta \u0259saslanan t\u0259cr\xFCb\u0259nin \u0259h\u0259miyy\u0259tini \u2014 t\u0259dqiqat s\xFCbutlar\u0131na, klinik t\u0259cr\xFCb\u0259y\u0259 v\u0259 x\u0259st\u0259nin se\xE7iml\u0259rin\u0259 \u0259sas\u0259n m\xFCalic\u0259 yana\u015Fmas\u0131n\u0131n x\xFCsusi diaqnoza uy\u011Funla\u015Fd\u0131r\u0131lmas\u0131n\u0131 \u0259hat\u0259 edir."},keyPoints:{en:["Psychoanalytic/Psychodynamic therapy: explores unconscious conflicts through free association, dream analysis, and transference. Long-term, insight-oriented. Less empirically supported than CBT.","Cognitive-Behavioral Therapy (CBT): identifies and changes distorted thinking patterns and maladaptive behaviors. The gold standard for anxiety and depression with strong evidence. Short-term (12\u201320 sessions).","Beck's cognitive therapy targets cognitive distortions: all-or-nothing thinking, catastrophizing, overgeneralization, mind reading, and personalization.","Humanistic therapy (Rogers's client-centered): provides unconditional positive regard, empathy, and genuineness. The therapist creates a supportive environment for self-exploration.","Biomedical therapies: Antidepressants (SSRIs increase serotonin), Anti-anxiety meds (benzodiazepines), Antipsychotics (block dopamine), Mood stabilizers (lithium for bipolar). ECT (electroconvulsive therapy) remains effective for severe, treatment-resistant depression.","Group therapy and family therapy leverage social support and address relationship dynamics. More cost-effective and can reduce isolation. Self-help groups (AA model) provide peer support.","Evidence-based practice: combining the best research evidence, clinical expertise, and patient preferences. Not all therapies are equally effective for all disorders \u2014 matching treatment to diagnosis matters."],ka:["\u10E4\u10E1\u10D8\u10E5\u10DD\u10D0\u10DC\u10D0\u10DA\u10D8\u10E2\u10D8\u10D9\u10E3\u10E0\u10D8/\u10E4\u10E1\u10D8\u10E5\u10DD\u10D3\u10D8\u10DC\u10D0\u10DB\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0: \u10D8\u10D9\u10D5\u10DA\u10D4\u10D5\u10E1 \u10D0\u10E0\u10D0\u10EA\u10DC\u10DD\u10D1\u10D8\u10D4\u10E0 \u10D9\u10DD\u10DC\u10E4\u10DA\u10D8\u10E5\u10E2\u10D4\u10D1\u10E1 \u10D7\u10D0\u10D5\u10D8\u10E1\u10E3\u10E4\u10D0\u10DA\u10D8 \u10D0\u10E1\u10DD\u10EA\u10D8\u10D0\u10EA\u10D8\u10D4\u10D1\u10D8\u10D7, \u10E1\u10D8\u10D6\u10DB\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D0\u10DC\u10D0\u10DA\u10D8\u10D6\u10D8\u10D7\u10D0 \u10D3\u10D0 \u10E2\u10E0\u10D0\u10DC\u10E1\u10E4\u10D4\u10E0\u10D8\u10D7. \u10D2\u10E0\u10EB\u10D4\u10DA\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8\u10D0, \u10DD\u10E0\u10D8\u10D4\u10DC\u10E2\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8\u10D0 \u10D8\u10DC\u10E1\u10D0\u10D8\u10E2\u10D6\u10D4. \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10E3\u10DA\u10D0\u10D3 \u10DC\u10D0\u10D9\u10DA\u10D4\u10D1\u10D0\u10D3 \u10D2\u10D0\u10DB\u10E7\u10D0\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8, \u10D5\u10D8\u10D3\u10E0\u10D4 CBT.","\u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0-\u10D1\u10D8\u10F0\u10D4\u10D5\u10D8\u10DD\u10E0\u10E3\u10DA\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 (CBT): \u10D0\u10D5\u10DA\u10D4\u10DC\u10E1 \u10D3\u10D0 \u10EA\u10D5\u10DA\u10D8\u10E1 \u10D3\u10D0\u10DB\u10D0\u10EE\u10D8\u10DC\u10EF\u10D4\u10D1\u10E3\u10DA \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10E4\u10DD\u10E0\u10DB\u10D4\u10D1\u10E1 \u10D3\u10D0 \u10DB\u10D0\u10D5\u10DC\u10D4 \u10E5\u10EA\u10D4\u10D5\u10D4\u10D1\u10E1. \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1 \u10DD\u10E5\u10E0\u10DD\u10E1 \u10E1\u10E2\u10D0\u10DC\u10D3\u10D0\u10E0\u10E2\u10E1 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D0\u10D3\u10D2\u10D4\u10DC\u10E1, \u10DB\u10E7\u10D0\u10E0\u10D8 \u10E1\u10D0\u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10DD \u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10D7. \u10DB\u10DD\u10D9\u10DA\u10D4\u10D5\u10D0\u10D3\u10D8\u10D0\u10DC\u10D8 (12-20 \u10E1\u10D4\u10E1\u10D8\u10D0).","\u10D1\u10D4\u10D9\u10D8\u10E1 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 \u10D2\u10D0\u10DB\u10D8\u10D6\u10DC\u10E3\u10DA\u10D8\u10D0 \u10D9\u10DD\u10D2\u10DC\u10D8\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D8\u10E1\u10D9\u10DD\u10E0\u10E2\u10D4\u10D1\u10D8\u10E1\u10D9\u10D4\u10DC: \u201E\u10E7\u10D5\u10D4\u10DA\u10D0\u10E4\u10D4\u10E0\u10D8 \u10D0\u10DC \u10D0\u10E0\u10D0\u10E4\u10D4\u10E0\u10D8\u201C \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0, \u10D9\u10D0\u10E2\u10D0\u10E1\u10E2\u10E0\u10DD\u10E4\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0, \u10D2\u10D0\u10D3\u10D0\u10ED\u10D0\u10E0\u10D1\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D2\u10D0\u10DC\u10D6\u10DD\u10D2\u10D0\u10D3\u10D4\u10D1\u10D0, \u10D0\u10D6\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D9\u10D8\u10D7\u10EE\u10D5\u10D0 \u10D3\u10D0 \u10DE\u10D4\u10E0\u10E1\u10DD\u10DC\u10D0\u10DA\u10D8\u10D6\u10D0\u10EA\u10D8\u10D0.","\u10F0\u10E3\u10DB\u10D0\u10DC\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 (\u10E0\u10DD\u10EF\u10D4\u10E0\u10E1\u10D8\u10E1 \u10D9\u10DA\u10D8\u10D4\u10DC\u10E2\u10D6\u10D4 \u10EA\u10D4\u10DC\u10E2\u10E0\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8): \u10E3\u10D6\u10E0\u10E3\u10DC\u10D5\u10D4\u10DA\u10E7\u10DD\u10E4\u10E1 \u10E3\u10DE\u10D8\u10E0\u10DD\u10D1\u10DD \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0 \u10D3\u10D0\u10DB\u10DD\u10D9\u10D8\u10D3\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D0\u10E1, \u10D4\u10DB\u10DE\u10D0\u10D7\u10D8\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10D2\u10E3\u10DA\u10EC\u10E0\u10E4\u10D4\u10DA\u10DD\u10D1\u10D0\u10E1. \u10D7\u10D4\u10E0\u10D0\u10DE\u10D4\u10D5\u10E2\u10D8 \u10E5\u10DB\u10DC\u10D8\u10E1 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10DB\u10ED\u10D4\u10E0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10D7\u10D5\u10D8\u10D7\u10E8\u10D4\u10DB\u10D4\u10EA\u10DC\u10D4\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1.","\u10D1\u10D8\u10DD\u10E1\u10D0\u10DB\u10D4\u10D3\u10D8\u10EA\u10D8\u10DC\u10DD \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0: \u10D0\u10DC\u10E2\u10D8\u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D0\u10DC\u10E2\u10D4\u10D1\u10D8 (SSRI \u10D6\u10E0\u10D3\u10D8\u10E1 \u10E1\u10D4\u10E0\u10DD\u10E2\u10DD\u10DC\u10D8\u10DC\u10E1), \u10E8\u10E4\u10DD\u10D7\u10D5\u10D8\u10E1 \u10E1\u10D0\u10EC\u10D8\u10DC\u10D0\u10D0\u10E6\u10DB\u10D3\u10D4\u10D2\u10DD \u10DB\u10D4\u10D3\u10D8\u10D9\u10D0\u10DB\u10D4\u10DC\u10E2\u10D4\u10D1\u10D8 (\u10D1\u10D4\u10DC\u10D6\u10DD\u10D3\u10D8\u10D0\u10D6\u10D4\u10DE\u10D8\u10DC\u10D4\u10D1\u10D8), \u10D0\u10DC\u10E2\u10D8\u10E4\u10E1\u10D8\u10E5\u10DD\u10E2\u10D8\u10D9\u10D4\u10D1\u10D8 (\u10D1\u10DA\u10DD\u10D9\u10D0\u10D5\u10E1 \u10D3\u10DD\u10E4\u10D0\u10DB\u10D8\u10DC\u10E1), \u10D2\u10D0\u10DC\u10EC\u10E7\u10DD\u10D1\u10D8\u10E1 \u10E1\u10E2\u10D0\u10D1\u10D8\u10DA\u10D8\u10D6\u10D0\u10E2\u10DD\u10E0\u10D4\u10D1\u10D8 (\u10DA\u10D8\u10D7\u10D8\u10E3\u10DB\u10D8 \u10D1\u10D8\u10DE\u10DD\u10DA\u10D0\u10E0\u10E3\u10DA\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1). ECT (\u10D4\u10DA\u10D4\u10E5\u10E2\u10E0\u10DD\u10D9\u10DD\u10DC\u10D5\u10E3\u10DA\u10E1\u10D8\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0) \u10E0\u10E9\u10D4\u10D1\u10D0 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8 \u10DB\u10EB\u10D8\u10DB\u10D4, \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10E0\u10D4\u10D6\u10D8\u10E1\u10E2\u10D4\u10DC\u10E2\u10E3\u10DA\u10D8 \u10D3\u10D4\u10DE\u10E0\u10D4\u10E1\u10D8\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1.","\u10EF\u10D2\u10E3\u10E4\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 \u10D3\u10D0 \u10DD\u10EF\u10D0\u10EE\u10E3\u10E0\u10D8 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 \u10E1\u10DD\u10EA\u10D8\u10D0\u10DA\u10E3\u10E0 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10ED\u10D4\u10E0\u10D0\u10E1 \u10D3\u10D0 \u10DB\u10D8\u10DB\u10D0\u10E0\u10D7\u10E3\u10DA\u10D8\u10D0 \u10E3\u10E0\u10D7\u10D8\u10D4\u10E0\u10D7\u10DD\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D8\u10DC\u10D0\u10DB\u10D8\u10D9\u10D8\u10E1\u10D9\u10D4\u10DC. \u10E3\u10E4\u10E0\u10DD \u10D4\u10D9\u10DD\u10DC\u10DD\u10DB\u10D8\u10E3\u10E0\u10D8\u10D0 \u10D3\u10D0 \u10E8\u10D4\u10E3\u10EB\u10DA\u10D8\u10D0 \u10E8\u10D4\u10D0\u10DB\u10EA\u10D8\u10E0\u10DD\u10E1 \u10D8\u10D6\u10DD\u10DA\u10D0\u10EA\u10D8\u10D0. \u10D7\u10D5\u10D8\u10D7\u10D3\u10D0\u10EE\u10DB\u10D0\u10E0\u10D4\u10D1\u10D8\u10E1 \u10EF\u10D2\u10E3\u10E4\u10D4\u10D1\u10D8 (AA \u10DB\u10DD\u10D3\u10D4\u10DA\u10D8) \u10E3\u10D6\u10E0\u10E3\u10DC\u10D5\u10D4\u10DA\u10E7\u10DD\u10E4\u10E1 \u10D7\u10D0\u10DC\u10D0\u10E1\u10EC\u10DD\u10E0\u10D7\u10D0 \u10DB\u10EE\u10D0\u10E0\u10D3\u10D0\u10ED\u10D4\u10E0\u10D0\u10E1.","\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D6\u10D4 \u10D3\u10D0\u10E4\u10E3\u10EB\u10DC\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10D0: \u10E1\u10D0\u10E3\u10D9\u10D4\u10D7\u10D4\u10E1\u10DD \u10D9\u10D5\u10DA\u10D4\u10D5\u10D8\u10E1 \u10DB\u10E2\u10D9\u10D8\u10EA\u10D4\u10D1\u10E3\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1, \u10D9\u10DA\u10D8\u10DC\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D4\u10E5\u10E1\u10DE\u10D4\u10E0\u10E2\u10D8\u10D6\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10DE\u10D0\u10EA\u10D8\u10D4\u10DC\u10E2\u10D8\u10E1 \u10DE\u10E0\u10D4\u10E4\u10D4\u10E0\u10D4\u10DC\u10EA\u10D8\u10D4\u10D1\u10D8\u10E1 \u10D9\u10DD\u10DB\u10D1\u10D8\u10DC\u10D0\u10EA\u10D8\u10D0. \u10E7\u10D5\u10D4\u10DA\u10D0 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 \u10D4\u10E0\u10D7\u10DC\u10D0\u10D8\u10E0\u10D0\u10D3 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8 \u10D0\u10E0 \u10D0\u10E0\u10D8\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0 \u10D0\u10E8\u10DA\u10D8\u10DA\u10DD\u10D1\u10D8\u10E1\u10D7\u10D5\u10D8\u10E1 \u2014 \u10DB\u10DC\u10D8\u10E8\u10D5\u10DC\u10D4\u10DA\u10DD\u10D5\u10D0\u10DC\u10D8\u10D0 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D3\u10D8\u10D0\u10D2\u10DC\u10DD\u10D6\u10D6\u10D4 \u10DB\u10DD\u10E0\u10D2\u10D4\u10D1\u10D0."],ru:["\u041F\u0441\u0438\u0445\u043E\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F/\u043F\u0441\u0438\u0445\u043E\u0434\u0438\u043D\u0430\u043C\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F: \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442\u044B \u0447\u0435\u0440\u0435\u0437 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0435 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u0438, \u0430\u043D\u0430\u043B\u0438\u0437 \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u0439 \u0438 \u043F\u0435\u0440\u0435\u043D\u043E\u0441. \u0414\u043E\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u0430\u044F, \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u043D\u0430 \u0438\u043D\u0441\u0430\u0439\u0442. \u041C\u0435\u043D\u0435\u0435 \u044D\u043C\u043F\u0438\u0440\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u0431\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0430, \u0447\u0435\u043C \u041A\u041F\u0422.","\u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u043E-\u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F (\u041A\u041F\u0422): \u0432\u044B\u044F\u0432\u043B\u044F\u0435\u0442 \u0438 \u0438\u0437\u043C\u0435\u043D\u044F\u0435\u0442 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u043D\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438 \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F \u0438 \u0434\u0435\u0437\u0430\u0434\u0430\u043F\u0442\u0438\u0432\u043D\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435. \u0417\u043E\u043B\u043E\u0442\u043E\u0439 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0442\u0440\u0435\u0432\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0438 \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438 \u0441 \u0432\u0435\u0441\u043A\u0438\u043C\u0438 \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u043C\u0438. \u041A\u0440\u0430\u0442\u043A\u043E\u0441\u0440\u043E\u0447\u043D\u0430\u044F (12\u201320 \u0441\u0435\u0430\u043D\u0441\u043E\u0432).","\u041A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F \u0411\u0435\u043A\u0430 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0430 \u043D\u0430 \u043A\u043E\u0433\u043D\u0438\u0442\u0438\u0432\u043D\u044B\u0435 \u0438\u0441\u043A\u0430\u0436\u0435\u043D\u0438\u044F: \u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \xAB\u0432\u0441\u0435 \u0438\u043B\u0438 \u043D\u0438\u0447\u0435\u0433\u043E\xBB, \u043A\u0430\u0442\u0430\u0441\u0442\u0440\u043E\u0444\u0438\u0437\u0430\u0446\u0438\u044F, \u0441\u0432\u0435\u0440\u0445\u043E\u0431\u043E\u0431\u0449\u0435\u043D\u0438\u0435, \u0447\u0442\u0435\u043D\u0438\u0435 \u043C\u044B\u0441\u043B\u0435\u0439 \u0438 \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F.","\u0413\u0443\u043C\u0430\u043D\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F (\u043A\u043B\u0438\u0435\u043D\u0442-\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F \u0420\u043E\u0434\u0436\u0435\u0440\u0441\u0430): \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0438\u0432\u0430\u0435\u0442 \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E\u0435 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u044D\u043C\u043F\u0430\u0442\u0438\u044E \u0438 \u0438\u0441\u043A\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C. \u0422\u0435\u0440\u0430\u043F\u0435\u0432\u0442 \u0441\u043E\u0437\u0434\u0430\u0435\u0442 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0443\u044E \u0441\u0440\u0435\u0434\u0443 \u0434\u043B\u044F \u0441\u0430\u043C\u043E\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F.","\u0411\u0438\u043E\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F: \u0430\u043D\u0442\u0438\u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0430\u043D\u0442\u044B (\u0421\u0418\u041E\u0417\u0421 \u043F\u043E\u0432\u044B\u0448\u0430\u044E\u0442 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0441\u0435\u0440\u043E\u0442\u043E\u043D\u0438\u043D\u0430), \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u0442\u0440\u0435\u0432\u043E\u0436\u043D\u044B\u0435 \u043F\u0440\u0435\u043F\u0430\u0440\u0430\u0442\u044B (\u0431\u0435\u043D\u0437\u043E\u0434\u0438\u0430\u0437\u0435\u043F\u0438\u043D\u044B), \u0430\u043D\u0442\u0438\u043F\u0441\u0438\u0445\u043E\u0442\u0438\u043A\u0438 (\u0431\u043B\u043E\u043A\u0438\u0440\u0443\u044E\u0442 \u0434\u043E\u0444\u0430\u043C\u0438\u043D), \u0441\u0442\u0430\u0431\u0438\u043B\u0438\u0437\u0430\u0442\u043E\u0440\u044B \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u044F (\u043B\u0438\u0442\u0438\u0439 \u043F\u0440\u0438 \u0431\u0438\u043F\u043E\u043B\u044F\u0440\u043D\u043E\u043C \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435). \u042D\u0421\u0422 (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u0441\u0443\u0434\u043E\u0440\u043E\u0436\u043D\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F) \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u043F\u0440\u0438 \u0442\u044F\u0436\u0435\u043B\u043E\u0439, \u0440\u0435\u0437\u0438\u0441\u0442\u0435\u043D\u0442\u043D\u043E\u0439 \u043A \u043B\u0435\u0447\u0435\u043D\u0438\u044E \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438.","\u0413\u0440\u0443\u043F\u043F\u043E\u0432\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F \u0438 \u0441\u0435\u043C\u0435\u0439\u043D\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u0443\u044E \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0443 \u0438 \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0442\u0441\u044F \u0434\u0438\u043D\u0430\u043C\u0438\u043A\u043E\u0439 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0439. \u0411\u043E\u043B\u0435\u0435 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B \u0438 \u043C\u043E\u0433\u0443\u0442 \u0443\u043C\u0435\u043D\u044C\u0448\u0438\u0442\u044C \u0438\u0437\u043E\u043B\u044F\u0446\u0438\u044E. \u0413\u0440\u0443\u043F\u043F\u044B \u0441\u0430\u043C\u043E\u043F\u043E\u043C\u043E\u0449\u0438 (\u043C\u043E\u0434\u0435\u043B\u044C \u0410\u043D\u043E\u043D\u0438\u043C\u043D\u044B\u0445 \u0410\u043B\u043A\u043E\u0433\u043E\u043B\u0438\u043A\u043E\u0432) \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0443 \u0440\u0430\u0432\u043D\u044B\u0445.","\u0414\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430: \u0441\u043E\u0447\u0435\u0442\u0430\u043D\u0438\u0435 \u043B\u0443\u0447\u0448\u0438\u0445 \u043D\u0430\u0443\u0447\u043D\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445, \u043A\u043B\u0438\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 \u0438 \u043F\u0440\u0435\u0434\u043F\u043E\u0447\u0442\u0435\u043D\u0438\u0439 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u0430. \u041D\u0435 \u0432\u0441\u0435 \u0432\u0438\u0434\u044B \u0442\u0435\u0440\u0430\u043F\u0438\u0438 \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u043E \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u044B \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0440\u0430\u0441\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432 \u2014 \u043F\u043E\u0434\u0431\u043E\u0440 \u043B\u0435\u0447\u0435\u043D\u0438\u044F \u043A \u0434\u0438\u0430\u0433\u043D\u043E\u0437\u0443 \u0438\u043C\u0435\u0435\u0442 \u0440\u0435\u0448\u0430\u044E\u0449\u0435\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435."],hy:["\u0540\u0578\u0563\u0565\u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0561\u056F\u0561\u0576/\u0540\u0578\u0563\u0565\u0564\u056B\u0576\u0561\u0574\u056B\u056F \u0569\u0565\u0580\u0561\u057A\u056B\u0561. \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0561\u0576\u0563\u056B\u057F\u0561\u056F\u0581\u0561\u056F\u0561\u0576 \u056F\u0578\u0576\u0586\u056C\u056B\u056F\u057F\u0576\u0565\u0580\u0568 \u0561\u0566\u0561\u057F \u0561\u057D\u0578\u0581\u056B\u0561\u0581\u056B\u0561\u0576\u0565\u0580\u056B, \u0565\u0580\u0561\u0566\u0576\u0565\u0580\u056B \u057E\u0565\u0580\u056C\u0578\u0582\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u057F\u0580\u0561\u0576\u057D\u0586\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E: \u0535\u0580\u056F\u0561\u0580\u0561\u056A\u0561\u0574\u056F\u0565\u057F, \u056B\u0576\u057D\u0561\u0575\u0569\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E: \u0537\u0574\u057A\u056B\u0580\u056B\u056F\u0578\u0580\u0565\u0576 \u057A\u0561\u056F\u0561\u057D \u0561\u057A\u0561\u0581\u0578\u0582\u0581\u057E\u0561\u056E \u0567, \u0584\u0561\u0576 CBT-\u0568:","\u053F\u0578\u0563\u0576\u056B\u057F\u056B\u057E-\u057E\u0561\u0580\u0584\u0561\u0575\u056B\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561 (CBT). \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574 \u0587 \u0583\u0578\u056D\u0578\u0582\u0574 \u0567 \u0561\u0572\u0573\u0561\u057F\u057E\u0561\u056E \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0561\u0576 \u0585\u0580\u056B\u0576\u0561\u0579\u0561\u0583\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0587 \u0561\u0576\u0562\u0561\u0580\u0565\u0576\u057A\u0561\u057D\u057F \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568: \u0531\u0576\u0570\u0561\u0576\u0563\u057D\u057F\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0570\u0561\u0574\u0561\u0580 \u0578\u057D\u056F\u0565 \u057D\u057F\u0561\u0576\u0564\u0561\u0580\u057F\u055D \u0561\u0574\u0578\u0582\u0580 \u0561\u057A\u0561\u0581\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u0578\u057E: \u053F\u0561\u0580\u0573\u0561\u056A\u0561\u0574\u056F\u0565\u057F (12\u201320 \u057D\u0565\u0561\u0576\u057D):","\u0532\u0565\u0584\u056B \u056F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576 \u0569\u056B\u0580\u0561\u056D\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u0567 \u056F\u0578\u0563\u0576\u056B\u057F\u056B\u057E \u0561\u0572\u0561\u057E\u0561\u0572\u0578\u0582\u0574\u0576\u0565\u0580\u0568\u055D \xAB\u0561\u0574\u0565\u0576 \u056B\u0576\u0579 \u056F\u0561\u0574 \u0578\u0579\u056B\u0576\u0579\xBB \u0574\u057F\u0561\u056E\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u056F\u0561\u057F\u0561\u057D\u057F\u0580\u0578\u0586\u056B\u0566\u0561\u0581\u056B\u0561, \u0563\u0565\u0580\u0568\u0576\u0564\u0570\u0561\u0576\u0580\u0561\u0581\u0578\u0582\u0574, \u0574\u057F\u0584\u0565\u0580\u056B \u0568\u0576\u0569\u0565\u0580\u0581\u0578\u0582\u0574 \u0587 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576\u0561\u0581\u0578\u0582\u0574:","\u0540\u0578\u0582\u0574\u0561\u0576\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u0569\u0565\u0580\u0561\u057A\u056B\u0561 (\u054C\u0578\u057B\u0565\u0580\u057D\u056B \u0570\u0561\u0573\u0561\u056D\u0578\u0580\u0564\u0561\u056F\u0565\u0576\u057F\u0580\u0578\u0576 \u0574\u0578\u057F\u0565\u0581\u0578\u0582\u0574). \u0561\u057A\u0561\u0570\u0578\u057E\u0578\u0582\u0574 \u0567 \u0561\u0576\u057E\u0565\u0580\u0561\u057A\u0561\u0570 \u0564\u0580\u0561\u056F\u0561\u0576 \u057E\u0565\u0580\u0561\u0562\u0565\u0580\u0574\u0578\u0582\u0576\u0584, \u0567\u0574\u057A\u0561\u057F\u056B\u0561 \u0587 \u0561\u0576\u056F\u0565\u0572\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576: \u0539\u0565\u0580\u0561\u057A\u0587\u057F\u0568 \u057D\u057F\u0565\u0572\u056E\u0578\u0582\u0574 \u0567 \u0561\u057B\u0561\u056F\u0581\u0578\u0572 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580 \u056B\u0576\u0584\u0576\u0561\u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0574\u0561\u0576 \u0570\u0561\u0574\u0561\u0580:","\u053F\u0565\u0576\u057D\u0561\u0562\u056A\u0577\u056F\u0561\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576\u0565\u0580\u055D \u0570\u0561\u056F\u0561\u0564\u0565\u057A\u0580\u0565\u057D\u0561\u0576\u057F\u0576\u0565\u0580 (SSRI-\u0576\u0565\u0580\u0568 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0576\u0578\u0582\u0574 \u0565\u0576 \u057D\u0565\u0580\u0578\u057F\u0578\u0576\u056B\u0576\u0568), \u0570\u0561\u056F\u0561\u057F\u0561\u0563\u0576\u0561\u057A\u0561\u0575\u056B\u0576 \u0564\u0565\u0572\u0561\u0574\u056B\u057B\u0578\u0581\u0576\u0565\u0580 (\u0562\u0565\u0576\u0566\u0578\u0564\u056B\u0561\u0566\u0565\u057A\u056B\u0576\u0576\u0565\u0580), \u0570\u0561\u056F\u0561\u057A\u057D\u056B\u056D\u0578\u057F\u056B\u056F \u0574\u056B\u057B\u0578\u0581\u0576\u0565\u0580 (\u0561\u0580\u0563\u0565\u056C\u0561\u0583\u0561\u056F\u0578\u0582\u0574 \u0565\u0576 \u0564\u0578\u0586\u0561\u0574\u056B\u0576\u0568), \u057F\u0580\u0561\u0574\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u056F\u0561\u0575\u0578\u0582\u0576\u0561\u0581\u0578\u0582\u0581\u056B\u0579\u0576\u0565\u0580 (\u056C\u056B\u0569\u056B\u0578\u0582\u0574\u055D \u0565\u0580\u056F\u0562\u0587\u0565\u057C \u056D\u0561\u0576\u0563\u0561\u0580\u0574\u0561\u0576 \u0564\u0565\u057A\u0584\u0578\u0582\u0574): ECT-\u0576 (\u0567\u056C\u0565\u056F\u057F\u0580\u0578\u0581\u0576\u0581\u0578\u0582\u0574\u0561\u0575\u056B\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561) \u0574\u0576\u0578\u0582\u0574 \u0567 \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u056E\u0561\u0576\u0580, \u0562\u0578\u0582\u056A\u0574\u0561\u0576 \u0576\u056F\u0561\u057F\u0574\u0561\u0574\u0562 \u056F\u0561\u0575\u0578\u0582\u0576 \u0564\u0565\u057A\u0580\u0565\u057D\u056B\u0561\u0575\u056B \u0564\u0565\u057A\u0584\u0578\u0582\u0574:","\u053D\u0574\u0562\u0561\u0575\u056B\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576 \u0587 \u0568\u0576\u057F\u0561\u0576\u0565\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0574 \u0565\u0576 \u057D\u0578\u0581\u056B\u0561\u056C\u0561\u056F\u0561\u0576 \u0561\u057B\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0561\u0576\u0564\u0580\u0561\u0564\u0561\u057C\u0576\u0578\u0582\u0574 \u0570\u0561\u0580\u0561\u0562\u0565\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0564\u056B\u0576\u0561\u0574\u056B\u056F\u0561\u0575\u056B\u0576: \u0531\u057E\u0565\u056C\u056B \u056E\u0561\u056D\u057D\u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0567 \u0587 \u056F\u0561\u0580\u0578\u0572 \u0567 \u0576\u057E\u0561\u0566\u0565\u0581\u0576\u0565\u056C \u0574\u0565\u056F\u0578\u0582\u057D\u0561\u0581\u0578\u0582\u0574\u0568: \u053B\u0576\u0584\u0576\u0585\u0563\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u056D\u0574\u0562\u0565\u0580\u0568 (AA \u0574\u0578\u0564\u0565\u056C) \u0561\u057A\u0561\u0570\u0578\u057E\u0578\u0582\u0574 \u0565\u0576 \u0570\u0561\u057D\u0561\u056F\u0561\u056F\u0561\u056F\u056B\u0581\u0576\u0565\u0580\u056B \u0561\u057B\u0561\u056F\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576:","\u0531\u057A\u0561\u0581\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u056B \u057E\u0580\u0561 \u0570\u056B\u0574\u0576\u057E\u0561\u056E \u057A\u0580\u0561\u056F\u057F\u056B\u056F\u0561. \u056C\u0561\u057E\u0561\u0563\u0578\u0582\u0575\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0561\u056F\u0561\u0576 \u200B\u200B\u0561\u057A\u0561\u0581\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u056B, \u056F\u056C\u056B\u0576\u056B\u056F\u0561\u056F\u0561\u0576 \u0583\u0578\u0580\u0571\u0561\u0584\u0576\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u0570\u056B\u057E\u0561\u0576\u0564\u0576\u0565\u0580\u056B \u0576\u0561\u056D\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0570\u0561\u0574\u0561\u056F\u0581\u0578\u0582\u0574: \u0532\u0578\u056C\u0578\u0580 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576\u0565\u0580\u0568 \u0570\u0561\u057E\u0561\u057D\u0561\u0580\u0561\u057A\u0565\u057D \u0561\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u057E\u0565\u057F \u0579\u0565\u0576 \u0562\u0578\u056C\u0578\u0580 \u056D\u0561\u0576\u0563\u0561\u0580\u0578\u0582\u0574\u0576\u0565\u0580\u056B \u0570\u0561\u0574\u0561\u0580. \u056F\u0561\u0580\u0587\u0578\u0580 \u0567 \u0562\u0578\u0582\u056A\u0578\u0582\u0574\u0568 \u0570\u0561\u0574\u0561\u057A\u0561\u057F\u0561\u057D\u056D\u0561\u0576\u0565\u0581\u0576\u0565\u056C \u0561\u056D\u057F\u0578\u0580\u0578\u0577\u0574\u0561\u0576\u0568:"],az:["Psixoanalitik/Psixodinamik terapiya: azad assosiasiya, yuxu analizi v\u0259 transfer vasit\u0259sil\u0259 \u015F\xFCuralt\u0131 m\xFCnaqi\u015F\u0259l\u0259ri ara\u015Fd\u0131r\u0131r. Uzunm\xFCdd\u0259tli, daxili anlay\u0131\u015F y\xF6n\xFCml\xFC. CBT-d\u0259n (KDT) daha az empirik olaraq d\u0259st\u0259kl\u0259nir.","Kognitiv-Davran\u0131\u015F Terapiyas\u0131 (CBT): t\u0259hrif olunmu\u015F d\xFC\u015F\xFCnc\u0259 t\u0259rzini v\u0259 uy\u011Funsuz davran\u0131\u015F\u0131 m\xFC\u0259yy\u0259n edir v\u0259 d\u0259yi\u015Fir. G\xFCcl\xFC s\xFCbutlarla narahatl\u0131q v\u0259 depressiya \xFC\xE7\xFCn q\u0131z\u0131l standart. Q\u0131sam\xFCdd\u0259tli (12\u201320 seans).",'Beck-in kognitiv terapiyas\u0131 kognitiv t\u0259hrifl\u0259ri (yan\u0131lg\u0131lar\u0131) h\u0259d\u0259fl\u0259yir: "ya ham\u0131, ya he\xE7 n\u0259" d\xFC\u015F\xFCnc\u0259si, f\u0259lak\u0259tl\u0259\u015Fdirm\u0259, h\u0259ddind\u0259n art\u0131q \xFCmumil\u0259\u015Fdirm\u0259, beyin oxuma v\u0259 f\u0259rdil\u0259\u015Fdirm\u0259.',"Humanist terapiya (Rogers-in m\xFC\u015Ft\u0259riy\u0259 \u0259saslanan terapiya): qeyd-\u015F\u0259rtsiz m\xFCsb\u0259t yana\u015Fma, empatiya v\u0259 s\u0259mimiyy\u0259t t\u0259min edir. Terapevt \xF6z\xFCn\xFC k\u0259\u015Ff etm\u0259k \xFC\xE7\xFCn d\u0259st\u0259kl\u0259yici bir m\xFChit yarad\u0131r.","Biotibbi m\xFCalic\u0259l\u0259r: Antidepressantlar (SSRI serotonini art\u0131r\u0131r), narahatl\u0131q \u0259leyhin\u0259 d\u0259rmanlar (benzodiazepinl\u0259r), Antipsixotikl\u0259r (dofaminin qar\u015F\u0131s\u0131n\u0131 al\u0131r), \u018Fhval stabilizatorlar\u0131 (bipolyar \xFC\xE7\xFCn litium). EST (elektrokonvulsiv terapiya) \u015Fidd\u0259tli, m\xFCalic\u0259y\u0259 davaml\u0131 depressiya \xFC\xE7\xFCn effektiv olaraq qal\u0131r.","Qrup terapiyas\u0131 v\u0259 ail\u0259 terapiyas\u0131 sosial d\u0259st\u0259kd\u0259n istifad\u0259 edir v\u0259 m\xFCnasib\u0259t dinamikas\u0131n\u0131 idar\u0259 edir. Daha q\u0259na\u0259tcildir v\u0259 izolyasiyan\u0131 azalda bil\u0259r. \xD6z-\xF6z\xFCn\u0259 k\xF6m\u0259k qruplar\u0131 (AA modeli) h\u0259mya\u015F\u0131dlar\u0131n d\u0259st\u0259yini t\u0259min edir.","S\xFCbuta \u0259saslanan t\u0259cr\xFCb\u0259: \u0259n yax\u015F\u0131 t\u0259dqiqat s\xFCbutlar\u0131n\u0131n, klinik t\u0259cr\xFCb\u0259nin v\u0259 x\u0259st\u0259 se\xE7iml\u0259rinin birl\u0259\u015Fdirilm\u0259si. B\xFCt\xFCn terapiyalar b\xFCt\xFCn x\u0259st\u0259likl\u0259r \xFC\xE7\xFCn eyni d\u0259r\u0259c\u0259d\u0259 effektiv deyil \u2014 m\xFCalic\u0259ni diaqnoza uy\u011Funla\u015Fd\u0131rmaq \xF6n\u0259mlidir."]},funFact:{en:"Talking to a therapist actually changes your brain. Brain scans show that CBT produces measurable changes in activity in the prefrontal cortex and amygdala \u2014 the same regions affected by antidepressant medication.",ka:"\u10D7\u10D4\u10E0\u10D0\u10DE\u10D4\u10D5\u10E2\u10D7\u10D0\u10DC \u10E1\u10D0\u10E3\u10D1\u10D0\u10E0\u10D8 \u10E0\u10D4\u10D0\u10DA\u10E3\u10E0\u10D0\u10D3 \u10EA\u10D5\u10DA\u10D8\u10E1 \u10D7\u10E5\u10D5\u10D4\u10DC\u10E1 \u10E2\u10D5\u10D8\u10DC\u10E1. \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB CBT \u10EA\u10D5\u10DA\u10D8\u10E1 \u10D0\u10E5\u10E2\u10D8\u10D5\u10DD\u10D1\u10D0\u10E1 \u10DE\u10E0\u10D4\u10E4\u10E0\u10DD\u10DC\u10E2\u10D0\u10DA\u10E3\u10E0 \u10E5\u10D4\u10E0\u10E5\u10E1\u10D0 \u10D3\u10D0 \u10D0\u10DB\u10D8\u10D2\u10D3\u10D0\u10DA\u10D0\u10E8\u10D8.",ru:"\u0420\u0430\u0437\u0433\u043E\u0432\u043E\u0440 \u0441 \u0442\u0435\u0440\u0430\u043F\u0435\u0432\u0442\u043E\u043C \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u043C\u0435\u043D\u044F\u0435\u0442 \u0432\u0430\u0448 \u043C\u043E\u0437\u0433. \u0421\u043A\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043C\u043E\u0437\u0433\u0430 \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u041A\u041F\u0422 \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 \u0438\u0437\u043C\u0435\u0440\u0438\u043C\u044B\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u0432 \u043F\u0440\u0435\u0444\u0440\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u043A\u043E\u0440\u0435 \u0438 \u043C\u0438\u043D\u0434\u0430\u043B\u0435\u0432\u0438\u0434\u043D\u043E\u043C \u0442\u0435\u043B\u0435.",hy:"\u0539\u0565\u0580\u0561\u057A\u0587\u057F\u056B \u0570\u0565\u057F \u056D\u0578\u057D\u0565\u056C\u0576 \u056B\u0580\u0561\u056F\u0561\u0576\u0578\u0582\u0574 \u0583\u0578\u056D\u0578\u0582\u0574 \u0567 \u0571\u0565\u0580 \u0578\u0582\u0572\u0565\u0572\u0568: \u0548\u0582\u0572\u0565\u0572\u056B \u057D\u056F\u0561\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0574\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 CBT-\u0576 \u0579\u0561\u0583\u0565\u056C\u056B \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580 \u0567 \u0561\u057C\u0561\u057B\u0561\u0581\u0576\u0578\u0582\u0574 \u0576\u0561\u056D\u0561\u0573\u0561\u056F\u0561\u057F\u0561\u0575\u056B\u0576 \u056F\u0565\u0572\u0587\u0578\u0582\u0574 \u0587 \u0561\u0574\u056B\u0563\u0564\u0561\u056C\u0561\u0575\u0578\u0582\u0574:",az:"Terapevt il\u0259 dan\u0131\u015Fmaq \u0259slind\u0259 beyninizi d\u0259yi\u015Fir. Beyin skanlar\u0131 g\xF6st\u0259rir ki, CBT prefrontal korteks v\u0259 amiqdalada \xF6l\xE7\xFCl\u0259 bil\u0259n d\u0259yi\u015Fiklikl\u0259r yarad\u0131r."},realWorld:{en:"Teletherapy (online therapy) exploded during COVID-19 and research shows it's nearly as effective as in-person therapy for most conditions. This massively expanded access to mental health care, especially in rural areas.",ka:"\u10E2\u10D4\u10DA\u10D4\u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0 (\u10DD\u10DC\u10DA\u10D0\u10D8\u10DC \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0) COVID-19-\u10D8\u10E1 \u10D3\u10E0\u10DD\u10E1 \u10D2\u10D0\u10D8\u10D6\u10D0\u10E0\u10D3\u10D0 \u10D3\u10D0 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10D8 \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D8\u10E1 \u10D7\u10D8\u10D7\u10E5\u10DB\u10D8\u10E1 \u10D8\u10E1\u10D4\u10D7\u10D8\u10D5\u10D4 \u10D4\u10E4\u10D4\u10E5\u10E2\u10E3\u10E0\u10D8\u10D0, \u10E0\u10DD\u10D2\u10DD\u10E0\u10EA \u10DE\u10D8\u10E0\u10D8\u10E1\u10DE\u10D8\u10E0 \u10D7\u10D4\u10E0\u10D0\u10DE\u10D8\u10D0.",ru:"\u0422\u0435\u043B\u0435\u0442\u0435\u0440\u0430\u043F\u0438\u044F (\u043E\u043D\u043B\u0430\u0439\u043D-\u0442\u0435\u0440\u0430\u043F\u0438\u044F) \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u0430 \u0448\u0438\u0440\u043E\u043A\u043E\u0435 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0432\u043E \u0432\u0440\u0435\u043C\u044F COVID-19, \u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442, \u0447\u0442\u043E \u043E\u043D\u0430 \u043F\u043E\u0447\u0442\u0438 \u0442\u0430\u043A \u0436\u0435 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u0430, \u043A\u0430\u043A \u0438 \u043E\u0447\u043D\u0430\u044F \u0442\u0435\u0440\u0430\u043F\u0438\u044F.",hy:"\u054F\u0565\u056C\u0565\u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576 (\u0561\u057C\u0581\u0561\u0576\u0581 \u0569\u0565\u0580\u0561\u057A\u056B\u0561) \u057A\u0561\u0575\u0569\u0565\u0581 COVID-19-\u056B \u056A\u0561\u0574\u0561\u0576\u0561\u056F, \u0587 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0565\u0576 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0561\u0575\u0576 \u0563\u0580\u0565\u0569\u0565 \u0576\u0578\u0582\u0575\u0576\u0584\u0561\u0576 \u0561\u0580\u0564\u0575\u10E3\u10DC\u0561\u057E\u0565\u057F \u0567, \u0578\u0580\u0584\u0561\u0576 \u0561\u0576\u0570\u0561\u057F\u0561\u056F\u0561\u0576 \u0569\u0565\u0580\u0561\u057A\u056B\u0561\u0576:",az:"Teleterapiya (onlayn terapiya) COVID-19 zaman\u0131 s\xFCr\u0259tl\u0259 artd\u0131 v\u0259 ara\u015Fd\u0131rmalar g\xF6st\u0259rir ki, o, \u0259ks\u0259r hallarda \xFCz-\xFCz\u0259 terapiya q\u0259d\u0259r effektivdir."}},16:{title:{en:"Applied Psychology",ka:"\u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10D7\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0",ru:"\u041F\u0440\u0438\u043A\u043B\u0430\u0434\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F",hy:"\u053F\u056B\u0580\u0561\u057C\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576",az:"Pozitiv Psixologiya"},description:{en:"Psychology in the real world: work, education, law, and everyday life.",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10E0\u10D4\u10D0\u10DA\u10E3\u10E0 \u10E1\u10D0\u10DB\u10E7\u10D0\u10E0\u10DD\u10E8\u10D8: \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD, \u10D2\u10D0\u10DC\u10D0\u10D7\u10DA\u10D4\u10D1\u10D0, \u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10D0\u10DA\u10D8 \u10D3\u10D0 \u10E7\u10DD\u10D5\u10D4\u10DA\u10D3\u10E6\u10D8\u10E3\u10E0\u10D8 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D0.",ru:"\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u043C\u0438\u0440\u0435: \u0440\u0430\u0431\u043E\u0442\u0430, \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435, \u043F\u0440\u0430\u0432\u043E \u0438 \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u0430\u044F \u0436\u0438\u0437\u043D\u044C.",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056B\u0580\u0561\u056F\u0561\u0576 \u0561\u0577\u056D\u0561\u0580\u0570\u0578\u0582\u0574. \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584, \u056F\u0580\u0569\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u056B\u0580\u0561\u057E\u0578\u0582\u0576\u0584 \u0587 \u0561\u057C\u0585\u0580\u0575\u0561 \u056F\u0575\u0561\u0576\u0584:",az:"Xo\u015Fb\u0259xtlik, Flow, Minn\u0259tdarl\u0131q."},keyTopics:{en:["Industrial-Organizational Psychology","Educational Psychology","Forensic Psychology","Positive Psychology"],ka:["\u10D8\u10DC\u10D3\u10E3\u10E1\u10E2\u10E0\u10D8\u10E3\u10DA-\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0","\u10D2\u10D0\u10DC\u10D0\u10D7\u10DA\u10D4\u10D1\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0","\u10E1\u10D0\u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10DD \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0","\u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0"],ru:["\u041F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E-\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F","\u041F\u0435\u0434\u0430\u0433\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F","\u0421\u0443\u0434\u0435\u0431\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F","\u041F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F"],hy:["\u0531\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u0562\u0565\u0580\u0561\u056F\u0561\u0576-\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u0579\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u053F\u0580\u0569\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0534\u0561\u057F\u0561\u0562\u056A\u0577\u056F\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576","\u0534\u0580\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576"],az:["S\u0259naye-T\u0259\u015Fkilati Psixologiya","T\u0259hsil Psixologiyas\u0131","M\u0259hk\u0259m\u0259 Psixologiyas\u0131","Pozitiv Psixologiya"]},summary:{en:"Psychology applies to virtually every area of human life, translating scientific findings into practical solutions for real-world problems. This chapter surveys the major applied subfields that demonstrate psychology's broad impact. Industrial-Organizational (I/O) psychology applies psychological principles to the workplace \u2014 covering hiring practices (structured interviews outperform unstructured ones), training design, employee motivation, leadership styles, job satisfaction, and reducing turnover. Educational psychology studies how people learn in formal settings, applying Piaget, Vygotsky's zone of proximal development, and Carol Dweck's growth mindset research showing that believing intelligence is malleable improves academic performance. Forensic psychology sits at the intersection of psychology and law, addressing criminal profiling, eyewitness testimony reliability, jury selection, and risk assessment. Health psychology promotes healthy behaviors through change models and addresses treatment adherence and chronic pain management. The chapter also covers positive psychology (Seligman's study of flourishing, including flow, grit, and character strengths), environmental psychology (how spaces affect behavior and well-being), and cross-cultural psychology (how individualistic and collectivistic cultures shape behavior, cognition, and emotion).",ka:"\u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10D2\u10D0\u10DB\u10DD\u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10D0 \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D8\u10E1 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D7\u10D8\u10D7\u10E5\u10DB\u10D8\u10E1 \u10E7\u10D5\u10D4\u10DA\u10D0 \u10E1\u10E4\u10D4\u10E0\u10DD\u10E8\u10D8, \u10D0\u10E5\u10EA\u10D4\u10D5\u10E1 \u10E0\u10D0 \u10E1\u10D0\u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10DD \u10DB\u10D8\u10E6\u10EC\u10D4\u10D5\u10D4\u10D1\u10E1 \u10E0\u10D4\u10D0\u10DA\u10E3\u10E0 \u10E1\u10D0\u10DB\u10E7\u10D0\u10E0\u10DD\u10E8\u10D8 \u10D0\u10E0\u10E1\u10D4\u10D1\u10E3\u10DA\u10D8 \u10DE\u10E0\u10DD\u10D1\u10DA\u10D4\u10DB\u10D4\u10D1\u10D8\u10E1 \u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10E3\u10DA \u10D2\u10D0\u10D3\u10D0\u10EC\u10E7\u10D5\u10D4\u10E2\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D0\u10D3. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10DB\u10D8\u10DB\u10DD\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D8\u10D7 \u10E5\u10D5\u10D4\u10E1\u10E4\u10D4\u10E0\u10DD\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10E4\u10D0\u10E0\u10D7\u10DD \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1. \u10D8\u10DC\u10D3\u10E3\u10E1\u10E2\u10E0\u10D8\u10E3\u10DA-\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 (I/O) \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D4\u10D1\u10E1 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10D0\u10D3\u10D2\u10D8\u10DA\u10D6\u10D4 \u2014 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D3\u10D0\u10E5\u10D8\u10E0\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10DE\u10E0\u10D0\u10E5\u10E2\u10D8\u10D9\u10D0\u10E1 (\u10E1\u10E2\u10E0\u10E3\u10E5\u10E2\u10E3\u10E0\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D8\u10E3\u10D4\u10D1\u10D8 \u10D0\u10EF\u10DD\u10D1\u10D4\u10D1\u10E1 \u10D0\u10E0\u10D0\u10E1\u10E2\u10E0\u10E3\u10E5\u10E2\u10E3\u10E0\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10E1), \u10E2\u10E0\u10D4\u10DC\u10D8\u10DC\u10D2\u10D8\u10E1 \u10D3\u10D8\u10D6\u10D0\u10D8\u10DC\u10E1, \u10D7\u10D0\u10DC\u10D0\u10DB\u10E8\u10E0\u10DD\u10DB\u10D4\u10DA\u10D7\u10D0 \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1, \u10DA\u10D8\u10D3\u10D4\u10E0\u10DD\u10D1\u10D8\u10E1 \u10E1\u10E2\u10D8\u10DA\u10D4\u10D1\u10E1, \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD\u10D7\u10D8 \u10D9\u10DB\u10D0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D9\u10D0\u10D3\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D4\u10DC\u10D0\u10D3\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1. \u10E1\u10D0\u10D2\u10D0\u10DC\u10DB\u10D0\u10DC\u10D0\u10D7\u10DA\u10D4\u10D1\u10DA\u10DD \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10E1\u10EC\u10D0\u10D5\u10DA\u10DD\u10D1\u10E1, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10E1\u10EC\u10D0\u10D5\u10DA\u10DD\u10D1\u10D4\u10DC \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10E4\u10DD\u10E0\u10DB\u10D0\u10DA\u10E3\u10E0 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E8\u10D8, \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 \u10DE\u10D8\u10D0\u10DF\u10D4\u10E1, \u10D5\u10D8\u10D2\u10DD\u10E2\u10E1\u10D9\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E3\u10D0\u10EE\u10DA\u10DD\u10D4\u10E1\u10D8 \u10D6\u10DD\u10DC\u10D8\u10E1 \u10D3\u10D0 \u10D9\u10D4\u10E0\u10DD\u10DA \u10D3\u10D5\u10D4\u10D9\u10D8\u10E1 \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E1, \u10E0\u10DD\u10DB\u10D4\u10DA\u10D8\u10EA \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8\u10E1 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10D3\u10DD\u10D1\u10D8\u10E1 \u10E0\u10EC\u10DB\u10D4\u10DC\u10D0 \u10D0\u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D4\u10D1\u10E1 \u10D0\u10D9\u10D0\u10D3\u10D4\u10DB\u10D8\u10E3\u10E0 \u10DB\u10DD\u10E1\u10EC\u10E0\u10D4\u10D1\u10D0\u10E1. \u10E1\u10D0\u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10DD \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10EC\u10D0\u10E0\u10DB\u10DD\u10D0\u10D3\u10D2\u10D4\u10DC\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10D9\u10D5\u10D4\u10D7\u10D0\u10E1, \u10D2\u10D0\u10DC\u10D8\u10EE\u10D8\u10DA\u10D0\u10D5\u10E1 \u10D9\u10E0\u10D8\u10DB\u10D8\u10DC\u10D0\u10DA\u10E3\u10E0 \u10DE\u10E0\u10DD\u10E4\u10D8\u10DA\u10E1, \u10DB\u10DD\u10EC\u10DB\u10D4\u10D7\u10D0 \u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10E1\u10D0\u10DC\u10D3\u10DD\u10DD\u10D1\u10D0\u10E1, \u10DC\u10D0\u10E4\u10D8\u10EA \u10DB\u10E1\u10D0\u10EF\u10E3\u10DA\u10D7\u10D0 \u10E8\u10D4\u10E0\u10E9\u10D4\u10D5\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10E0\u10D8\u10E1\u10D9\u10D8\u10E1 \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D0\u10E1. \u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 \u10EE\u10D4\u10DA\u10E1 \u10E3\u10EC\u10E7\u10DD\u10D1\u10E1 \u10EF\u10D0\u10DC\u10E1\u10D0\u10E6 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10D4\u10E8\u10D5\u10D4\u10DD\u10D1\u10D8\u10D7 \u10D3\u10D0 \u10D4\u10EE\u10D4\u10D1\u10D0 \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E0\u10D4\u10DF\u10D8\u10DB\u10D8\u10E1 \u10D3\u10D0\u10EA\u10D5\u10D0\u10E1 \u10D3\u10D0 \u10E5\u10E0\u10DD\u10DC\u10D8\u10D9\u10E3\u10DA\u10D8 \u10E2\u10D9\u10D8\u10D5\u10D8\u10DA\u10D8\u10E1 \u10DB\u10D0\u10E0\u10D7\u10D5\u10D0\u10E1. \u10D4\u10E1 \u10D7\u10D0\u10D5\u10D8 \u10D0\u10E1\u10D4\u10D5\u10D4 \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10E1 (\u10E1\u10D4\u10DA\u10D8\u10D2\u10DB\u10D0\u10DC\u10D8\u10E1 \u10D0\u10E7\u10D5\u10D0\u10D5\u10D4\u10D1\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0, \u10DB\u10D0\u10D7 \u10E8\u10DD\u10E0\u10D8\u10E1 \u10DC\u10D0\u10D9\u10D0\u10D3\u10D8, \u10E1\u10D8\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4 \u10D3\u10D0 \u10EE\u10D0\u10E1\u10D8\u10D0\u10D7\u10D8\u10E1 \u10E1\u10D8\u10EB\u10DA\u10D8\u10D4\u10E0\u10D4), \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10E1 (\u10E0\u10DD\u10D2\u10DD\u10E0 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10E1 \u10E1\u10D8\u10D5\u10E0\u10EA\u10D4\u10D4\u10D1\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10D9\u10D4\u10D7\u10D8\u10DA\u10D3\u10E6\u10D4\u10DD\u10D1\u10D0\u10D6\u10D4) \u10D3\u10D0 \u10D9\u10E0\u10DD\u10E1-\u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10E3\u10DA \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10E1 (\u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10E1 \u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10E3\u10D0\u10DA\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D3\u10D0 \u10D9\u10DD\u10DA\u10D4\u10E5\u10E2\u10D8\u10D5\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D4\u10D1\u10D8 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1, \u10D9\u10DD\u10D2\u10DC\u10D8\u10EA\u10D8\u10D0\u10E1 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10E1).",ru:"\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u043F\u0440\u0438\u043C\u0435\u043D\u0438\u043C\u0430 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043A \u043B\u044E\u0431\u043E\u0439 \u0441\u0444\u0435\u0440\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0439 \u0436\u0438\u0437\u043D\u0438, \u0432\u043E\u043F\u043B\u043E\u0449\u0430\u044F \u043D\u0430\u0443\u0447\u043D\u044B\u0435 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u044F \u0432 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043C\u0438\u0440\u0430. \u0412 \u044D\u0442\u043E\u0439 \u0433\u043B\u0430\u0432\u0435 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u043F\u0440\u0438\u043A\u043B\u0430\u0434\u043D\u044B\u0435 \u043F\u043E\u0434\u043E\u0442\u0440\u0430\u0441\u043B\u0438, \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u044E\u0449\u0438\u0435 \u0448\u0438\u0440\u043E\u043A\u043E\u0435 \u0432\u043B\u0438\u044F\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438. \u0418\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u0430\u043B\u044C\u043D\u043E-\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F (\u0418/\u041E) \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u043F\u0440\u0438\u043C\u0435\u043D\u044F\u0435\u0442 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B \u043D\u0430 \u0440\u0430\u0431\u043E\u0447\u0435\u043C \u043C\u0435\u0441\u0442\u0435 \u2014 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443 \u043D\u0430\u0439\u043C\u0430 (\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0438\u043D\u0442\u0435\u0440\u0432\u044C\u044E \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0442 \u043D\u0435\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435), \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F, \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044E \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u043A\u043E\u0432, \u0441\u0442\u0438\u043B\u0438 \u043B\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u0430, \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u043E\u0439 \u0438 \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u0435 \u0442\u0435\u043A\u0443\u0447\u0435\u0441\u0442\u0438 \u043A\u0430\u0434\u0440\u043E\u0432. \u041F\u0435\u0434\u0430\u0433\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0438\u0437\u0443\u0447\u0430\u0435\u0442, \u043A\u0430\u043A \u043B\u044E\u0434\u0438 \u0443\u0447\u0430\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0430\u043B\u044C\u043D\u043E\u0439 \u043E\u0431\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0435, \u043F\u0440\u0438\u043C\u0435\u043D\u044F\u044F \u0438\u0434\u0435\u0438 \u041F\u0438\u0430\u0436\u0435, \u0437\u043E\u043D\u0443 \u0431\u043B\u0438\u0436\u0430\u0439\u0448\u0435\u0433\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0412\u044B\u0433\u043E\u0442\u0441\u043A\u043E\u0433\u043E \u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u041A\u044D\u0440\u043E\u043B \u0414\u0443\u044D\u043A \u043E\u0431 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0435 \u043D\u0430 \u0440\u043E\u0441\u0442, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0435, \u0447\u0442\u043E \u0432\u0435\u0440\u0430 \u0432 \u043F\u043B\u0430\u0441\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 \u0443\u043B\u0443\u0447\u0448\u0430\u0435\u0442 \u0430\u043A\u0430\u0434\u0435\u043C\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0443\u0441\u043F\u0435\u0432\u0430\u0435\u043C\u043E\u0441\u0442\u044C. \u0421\u0443\u0434\u0435\u0431\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043D\u0430 \u0441\u0442\u044B\u043A\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438 \u0438 \u043F\u0440\u0430\u0432\u0430, \u0437\u0430\u043D\u0438\u043C\u0430\u044F\u0441\u044C \u0443\u0433\u043E\u043B\u043E\u0432\u043D\u044B\u043C \u043F\u0440\u043E\u0444\u0438\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435\u043C, \u043D\u0430\u0434\u0435\u0436\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0445 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0438\u0439, \u043E\u0442\u0431\u043E\u0440\u043E\u043C \u043F\u0440\u0438\u0441\u044F\u0436\u043D\u044B\u0445 \u0438 \u043E\u0446\u0435\u043D\u043A\u043E\u0439 \u0440\u0438\u0441\u043A\u043E\u0432. \u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F \u043F\u0440\u043E\u0434\u0432\u0438\u0433\u0430\u0435\u0442 \u0437\u0434\u043E\u0440\u043E\u0432\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043C\u043E\u0434\u0435\u043B\u0438 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 \u0438 \u0440\u0435\u0448\u0430\u0435\u0442 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B \u0441\u043E\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u044F \u0440\u0435\u0436\u0438\u043C\u0430 \u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0445\u0440\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0431\u043E\u043B\u044C\u044E. \u0413\u043B\u0430\u0432\u0430 \u0442\u0430\u043A\u0436\u0435 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u0443\u044E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044E (\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0446\u0432\u0435\u0442\u0430\u043D\u0438\u044F \u0421\u0435\u043B\u0438\u0433\u043C\u0430\u043D\u0430, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u043F\u043E\u0442\u043E\u043A, \u0442\u0432\u0435\u0440\u0434\u043E\u0441\u0442\u044C \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0430 \u0438 \u0441\u0438\u043B\u044C\u043D\u044B\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438), \u044D\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044E (\u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0438 \u0431\u043B\u0430\u0433\u043E\u043F\u043E\u043B\u0443\u0447\u0438\u0435) \u0438 \u043A\u0440\u043E\u0441\u0441-\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u0443\u044E \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044E (\u043A\u0430\u043A \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0438 \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u0441\u043A\u0438\u0435 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u044E\u0442 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u043A\u043E\u0433\u043D\u0438\u0446\u0438\u0438 \u0438 \u044D\u043C\u043E\u0446\u0438\u0438).",hy:"\u0540\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u056B\u0580\u0561\u057C\u057E\u0578\u0582\u0574 \u0567 \u0574\u0561\u0580\u0564\u056F\u0561\u0575\u056B\u0576 \u056F\u0575\u0561\u0576\u0584\u056B \u0563\u0580\u0565\u0569\u0565 \u0562\u0578\u056C\u0578\u0580 \u0578\u056C\u0578\u0580\u057F\u0576\u0565\u0580\u0578\u0582\u0574\u055D \u0563\u056B\u057F\u0561\u056F\u0561\u0576 \u0562\u0561\u0581\u0561\u0570\u0561\u0575\u057F\u0578\u0582\u0574\u0576\u0565\u0580\u0568 \u057E\u0565\u0580\u0561\u056E\u0565\u056C\u0578\u057E \u056B\u0580\u0561\u056F\u0561\u0576 \u0561\u0577\u056D\u0561\u0580\u0570\u056B \u056D\u0576\u0564\u056B\u0580\u0576\u0565\u0580\u056B \u0563\u0578\u0580\u056E\u0576\u0561\u056F\u0561\u0576 \u056C\u0578\u0582\u056E\u0578\u0582\u0574\u0576\u0565\u0580\u056B: \u0531\u0575\u057D \u0563\u056C\u0578\u0582\u056D\u0568 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567 \u0570\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u056F\u056B\u0580\u0561\u057C\u0561\u056F\u0561\u0576 \u0565\u0576\u0569\u0561\u0578\u056C\u0578\u0580\u057F\u0576\u0565\u0580\u0568, \u0578\u0580\u0578\u0576\u0584 \u0581\u0578\u0582\u0575\u0581 \u0565\u0576 \u057F\u0561\u056C\u056B\u057D \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u056C\u0561\u0575\u0576 \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0531\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u0562\u0565\u0580\u0561\u056F\u0561\u0576-\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u0579\u0561\u056F\u0561\u0576 (I/O) \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056F\u056B\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0576\u0565\u0580 \u0561\u0577\u056D\u0561\u057F\u0561\u057E\u0561\u0575\u0580\u0578\u0582\u0574\u055D \u0568\u0576\u0564\u0563\u0580\u056F\u0565\u056C\u0578\u057E \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u0568\u0576\u0564\u0578\u0582\u0576\u0574\u0561\u0576 \u057A\u0580\u0561\u056F\u057F\u056B\u056F\u0561\u0576 (\u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0561\u0575\u056B\u0576 \u0570\u0561\u0580\u0581\u0561\u0566\u0580\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u0568 \u0563\u0565\u0580\u0561\u0566\u0561\u0576\u0581\u0578\u0582\u0574 \u0565\u0576 \u0578\u0579 \u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0561\u0575\u056B\u0576\u0576\u0565\u0580\u056B\u0576), \u057E\u0565\u0580\u0561\u057A\u0561\u057F\u0580\u0561\u057D\u057F\u0574\u0561\u0576 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574\u0568, \u0561\u0577\u056D\u0561\u057F\u0561\u056F\u056B\u0581\u0576\u0565\u0580\u056B \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576, \u0561\u057C\u0561\u057B\u0576\u0578\u0580\u0564\u0578\u0582\u0569\u0575\u0561\u0576 \u0578\u0573\u0565\u0580\u0568, \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u0562\u0561\u057E\u0561\u0580\u0561\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0570\u0578\u057D\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0576\u057E\u0561\u0566\u0565\u0581\u0578\u0582\u0574\u0568: \u053F\u0580\u0569\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0574\u0561\u0580\u0564\u056B\u056F \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0574 \u057A\u0561\u0577\u057F\u0578\u0576\u0561\u056F\u0561\u0576 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0565\u0580\u0578\u0582\u0574\u055D \u056F\u056B\u0580\u0561\u057C\u0565\u056C\u0578\u057E \u054A\u056B\u0561\u056A\u0565\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u054E\u056B\u0563\u0578\u057F\u057D\u056F\u0578\u0582 \u0574\u0565\u0580\u0571\u0561\u056F\u0561 \u0566\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576 \u0563\u0578\u057F\u056B\u0576 \u0587 \u0554\u0565\u0580\u0578\u056C \u0534\u0578\u0582\u0565\u0584\u056B \u0566\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576 \u0574\u057F\u0561\u056E\u0565\u056C\u0561\u056F\u0565\u0580\u057A\u056B \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0578\u0580\u0568 \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0562\u0561\u0576\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0571\u0587\u0561\u057E\u0578\u0580\u0574\u0561\u0576 \u0570\u0561\u057E\u0561\u057F\u0568 \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u0578\u0582\u0574 \u0567 \u0561\u056F\u0561\u0564\u0565\u0574\u056B\u0561\u056F\u0561\u0576 \u0561\u057C\u0561\u057B\u0561\u0564\u056B\u0574\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568: \u0534\u0561\u057F\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0563\u057F\u0576\u057E\u0578\u0582\u0574 \u0567 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u056B\u0580\u0561\u057E\u0578\u0582\u0576\u0584\u056B \u0570\u0561\u057F\u0574\u0561\u0576 \u056F\u0565\u057F\u0578\u0582\u0574, \u0578\u0580\u0576 \u0566\u0562\u0561\u0572\u057E\u0578\u0582\u0574 \u0567 \u0584\u0580\u0565\u0561\u056F\u0561\u0576 \u057A\u0580\u0578\u0586\u056B\u056C\u0561\u057E\u0578\u0580\u0574\u0561\u0574\u0562, \u0561\u056F\u0561\u0576\u0561\u057F\u0565\u057D\u0576\u0565\u0580\u056B \u0581\u0578\u0582\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0570\u0578\u0582\u057D\u0561\u056C\u056B\u0578\u0582\u0569\u0575\u0561\u0574\u0562, \u0565\u0580\u0564\u057E\u0575\u0561\u056C \u0561\u057F\u0565\u0576\u0561\u056F\u0561\u056C\u0576\u0565\u0580\u056B \u0568\u0576\u057F\u0580\u0578\u0582\u0569\u0575\u0561\u0574\u0562 \u0587 \u057C\u056B\u057D\u056F\u056B \u0563\u0576\u0561\u0570\u0561\u057F\u0574\u0561\u0574\u0562: \u0531\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u056D\u0569\u0561\u0576\u0578\u0582\u0574 \u0567 \u0561\u057C\u0578\u0572\u057B \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568 \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0578\u0564\u0565\u056C\u0576\u0565\u0580\u056B \u0574\u056B\u057B\u0578\u0581\u0578\u057E \u0587 \u0578\u0582\u0577\u0561\u0564\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0564\u0561\u0580\u0571\u0576\u0578\u0582\u0574 \u0562\u0578\u0582\u056A\u0574\u0561\u0576 \u0570\u0565\u057F\u0587\u0578\u0572\u0561\u056F\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576\u0576 \u0578\u0582 \u0584\u0580\u0578\u0576\u056B\u056F \u0581\u0561\u057E\u056B \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0574\u0561\u0576\u0568: \u0533\u056C\u0578\u0582\u056D\u0576 \u0568\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0576\u0561\u0587 \u0564\u0580\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 (\u054D\u0565\u056C\u056B\u0563\u0574\u0561\u0576\u056B \u0562\u0561\u0580\u0563\u0561\u057E\u0561\u0573\u0574\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0576\u0565\u0580\u0561\u057C\u0575\u0561\u056C \u0570\u0578\u057D\u0584\u0568, \u0570\u0561\u0574\u0561\u057C\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0562\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u0578\u0582\u056A\u0565\u0572 \u056F\u0578\u0572\u0574\u0565\u0580\u0568), \u0567\u056F\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 (\u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u057F\u0561\u0580\u0561\u056E\u0584\u0576\u0565\u0580\u0576 \u0561\u0566\u0564\u0578\u0582\u0574 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0587 \u0562\u0561\u0580\u0565\u056F\u0565\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561) \u0587 \u0574\u0577\u0561\u056F\u0578\u0582\u0569\u0561\u0575\u056B\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 (\u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0561\u0576\u0570\u0561\u057F\u0561\u057A\u0561\u0577\u057F \u0587 \u056F\u0578\u056C\u0565\u056F\u057F\u056B\u057E\u056B\u057D\u057F \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u0576\u0565\u0580\u0568 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E, \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0570\u0578\u0582\u0575\u0566\u0565\u0580):",az:"Psixologiya elmi tap\u0131nt\u0131lar\u0131 real d\xFCnya probleml\u0259ri \xFC\xE7\xFCn praktiki h\u0259ll yollar\u0131na \xE7evir\u0259r\u0259k, insan h\u0259yat\u0131n\u0131n dem\u0259k olar ki, h\u0259r bir sah\u0259sin\u0259 t\u0259tbiq olunur. Bu f\u0259sil psixologiyan\u0131n geni\u015F t\u0259sirini n\xFCmayi\u015F etdir\u0259n \u0259sas t\u0259tbiqi alt sah\u0259l\u0259ri ara\u015Fd\u0131r\u0131r. S\u0259naye-T\u0259\u015Fkilati (I/O) psixologiyas\u0131 i\u015F yerind\u0259 psixoloji prinsipl\u0259ri t\u0259tbiq edir \u2014 i\u015F\u0259g\xF6t\xFCrm\u0259 t\u0259cr\xFCb\u0259l\u0259rini (strukturla\u015Fd\u0131r\u0131lm\u0131\u015F m\xFCsahib\u0259l\u0259r strukturla\u015Fd\u0131r\u0131lmam\u0131\u015Flardan \xFCst\xFCnd\xFCr), t\u0259lim dizayn\u0131n\u0131, i\u015F\xE7il\u0259rin motivasiyas\u0131n\u0131, liderlik \xFCslublar\u0131n\u0131, i\u015F m\u0259mnuniyy\u0259tini v\u0259 i\u015F\xE7i kadr ax\u0131m\u0131n\u0131n azald\u0131lmas\u0131n\u0131 \u0259hat\u0259 edir. T\u0259hsil psixologiyas\u0131 Pyaejnin, V\u0131qotskinin yax\u0131n inki\u015Faf z\u0259minini v\u0259 Kerol Dweckin intellektin d\u0259yi\u015Fk\u0259n oldu\u011Funa inanma\u011F\u0131n akademik performans\u0131 yax\u015F\u0131la\u015Fd\u0131rd\u0131\u011F\u0131n\u0131 g\xF6st\u0259r\u0259n inki\u015Faf d\xFC\u015F\xFCnc\u0259 t\u0259rzini t\u0259tbiq ed\u0259r\u0259k, insanlar\u0131n formal m\xFChitl\u0259rd\u0259 nec\u0259 \xF6yr\u0259ndikl\u0259rini \xF6yr\u0259nir. M\u0259hk\u0259m\u0259 psixologiyas\u0131 psixologiya v\u0259 h\xFCququn k\u0259si\u015Fm\u0259sind\u0259 yerl\u0259\u015Fir, cinay\u0259tkarlar\u0131n profill\u0259\u015Fdirilm\u0259si, \u015Fahid ifad\u0259l\u0259rinin etibarl\u0131l\u0131\u011F\u0131, andl\u0131lar hey\u0259tinin se\xE7imi v\u0259 riskin qiym\u0259tl\u0259ndirilm\u0259sini ara\u015Fd\u0131r\u0131r. Sa\u011Flaml\u0131q psixologiyas\u0131 d\u0259yi\u015Fiklik modell\u0259ri vasit\u0259sil\u0259 sa\u011Flam davran\u0131\u015Flar\u0131 t\u0259\u015Fviq edir v\u0259 tibbi m\xFCalic\u0259y\u0259 sadiqlik v\u0259 xroniki a\u011Fr\u0131lar\u0131n idar\u0259 olunmas\u0131na m\xFCraci\u0259t edir. F\u0259sil h\u0259m\xE7inin pozitiv psixologiyan\u0131 (Seligman\u0131n \xE7i\xE7\u0259kl\u0259nm\u0259 il\u0259 ba\u011Fl\u0131 t\u0259dqiqat\u0131, o c\xFCml\u0259d\u0259n ax\u0131n, \u0259zmkar xasiyy\u0259t v\u0259 xarakterin g\xFCcl\xFC t\u0259r\u0259fl\u0259ri), \u0259traf m\xFChit psixologiyas\u0131n\u0131 (m\u0259kanlar\u0131n davran\u0131\u015Fa v\u0259 rifaha nec\u0259 t\u0259sir etdiyini) v\u0259 m\u0259d\u0259niyy\u0259tl\u0259raras\u0131 psixologiyan\u0131 (f\u0259rdiyy\u0259t\xE7i v\u0259 kollektivist m\u0259d\u0259niyy\u0259tl\u0259rin davran\u0131\u015F\u0131, idrak\u0131 v\u0259 duy\u011Fular\u0131 nec\u0259 formala\u015Fd\u0131rd\u0131\u011F\u0131n\u0131) \u0259hat\u0259 edir."},keyPoints:{en:["Industrial-Organizational (I/O) Psychology: applies psychological principles to the workplace. Covers hiring (structured interviews beat unstructured), training design, motivation, leadership, job satisfaction, and reducing turnover.","Educational Psychology: studies how people learn in educational settings. Applies Piaget, Vygotsky (zone of proximal development), and learning styles research. Growth mindset (Dweck): believing intelligence is malleable improves academic performance.","Forensic Psychology: intersection of psychology and law. Includes criminal profiling, eyewitness testimony research, jury selection, competency evaluations, and risk assessment for reoffending.","Health Psychology: promotes healthy behaviors and prevents illness. Covers behavior change models (stages of change), adherence to medical treatment, chronic pain management, and the mind-body connection.","Positive Psychology (Seligman): the scientific study of what makes life worth living. Focuses on strengths, virtues, and optimal functioning rather than pathology. Key concepts: flow (Csikszentmihalyi), grit (Duckworth), gratitude, and character strengths.","Environmental Psychology: how physical environments affect behavior and well-being. Includes workspace design, urban planning, crowding effects, and noise pollution impacts.","Cross-cultural psychology: understanding how culture shapes behavior, cognition, and emotion. Individualistic cultures (US, Western Europe) emphasize personal achievement; collectivistic cultures (East Asia, Latin America) emphasize group harmony."],ka:["\u10D8\u10DC\u10D3\u10E3\u10E1\u10E2\u10E0\u10D8\u10E3\u10DA-\u10DD\u10E0\u10D2\u10D0\u10DC\u10D8\u10D6\u10D0\u10EA\u10D8\u10E3\u10DA\u10D8 (I/O) \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0: \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10E3\u10E0\u10D8 \u10DE\u10E0\u10D8\u10DC\u10EA\u10D8\u10DE\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DB\u10DD\u10E7\u10D4\u10DC\u10D4\u10D1\u10D0 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10D0\u10D3\u10D2\u10D8\u10DA\u10D6\u10D4. \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D3\u10D0\u10E5\u10D8\u10E0\u10D0\u10D5\u10D4\u10D1\u10D0\u10E1 (\u10E1\u10E2\u10E0\u10E3\u10E5\u10E2\u10E3\u10E0\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10D8 \u10D8\u10DC\u10E2\u10D4\u10E0\u10D5\u10D8\u10E3\u10D4\u10D1\u10D8 \u10EF\u10DD\u10D1\u10D8\u10D0 \u10D0\u10E0\u10D0\u10E1\u10E2\u10E0\u10E3\u10E5\u10E2\u10E3\u10E0\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10E1), \u10E2\u10E0\u10D4\u10DC\u10D8\u10DC\u10D2\u10D8\u10E1 \u10D3\u10D8\u10D6\u10D0\u10D8\u10DC\u10E1, \u10DB\u10DD\u10E2\u10D8\u10D5\u10D0\u10EA\u10D8\u10D0\u10E1, \u10DA\u10D8\u10D3\u10D4\u10E0\u10DD\u10D1\u10D0\u10E1, \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD\u10D7\u10D8 \u10D9\u10DB\u10D0\u10E7\u10DD\u10E4\u10D8\u10DA\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D9\u10D0\u10D3\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D3\u10D4\u10DC\u10D0\u10D3\u10DD\u10D1\u10D8\u10E1 \u10E8\u10D4\u10DB\u10EA\u10D8\u10E0\u10D4\u10D1\u10D0\u10E1.","\u10E1\u10D0\u10D2\u10D0\u10DC\u10DB\u10D0\u10DC\u10D0\u10D7\u10DA\u10D4\u10D1\u10DA\u10DD \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0: \u10E1\u10EC\u10D0\u10D5\u10DA\u10DD\u10D1\u10E1 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10E1\u10EC\u10D0\u10D5\u10DA\u10DD\u10D1\u10D4\u10DC \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 \u10E1\u10D0\u10D2\u10D0\u10DC\u10DB\u10D0\u10DC\u10D0\u10D7\u10DA\u10D4\u10D1\u10DA\u10DD \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E8\u10D8. \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 \u10DE\u10D8\u10D0\u10DF\u10D4\u10E1, \u10D5\u10D8\u10D2\u10DD\u10E2\u10E1\u10D9\u10D8\u10E1 (\u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D8\u10E1 \u10E3\u10D0\u10EE\u10DA\u10DD\u10D4\u10E1\u10D8 \u10D6\u10DD\u10DC\u10D0) \u10D3\u10D0 \u10E1\u10EC\u10D0\u10D5\u10DA\u10D8\u10E1 \u10E1\u10E2\u10D8\u10DA\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10E1. \u10D6\u10E0\u10D3\u10D8\u10E1 \u10D0\u10D6\u10E0\u10DD\u10D5\u10DC\u10D4\u10D1\u10D0 (\u10D3\u10D5\u10D4\u10D9\u10D8): \u10E0\u10EC\u10DB\u10D4\u10DC\u10D0, \u10E0\u10DD\u10DB \u10D8\u10DC\u10E2\u10D4\u10DA\u10D4\u10E5\u10E2\u10D8 \u10D2\u10D0\u10DC\u10D5\u10D8\u10D7\u10D0\u10E0\u10D4\u10D1\u10D0\u10D3\u10D8\u10D0, \u10D0\u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D4\u10D1\u10E1 \u10D0\u10D9\u10D0\u10D3\u10D4\u10DB\u10D8\u10E3\u10E0 \u10DB\u10DD\u10E1\u10EC\u10E0\u10D4\u10D1\u10D0\u10E1.","\u10E1\u10D0\u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10DD \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0: \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10E1\u10D0\u10DB\u10D0\u10E0\u10D7\u10DA\u10D8\u10E1 \u10D2\u10D0\u10D3\u10D0\u10D9\u10D5\u10D4\u10D7\u10D0. \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10D9\u10E0\u10D8\u10DB\u10D8\u10DC\u10D0\u10DA\u10E3\u10E0 \u10DE\u10E0\u10DD\u10E4\u10D8\u10DA\u10E1, \u10DB\u10DD\u10EC\u10DB\u10D4\u10D7\u10D0 \u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D4\u10D1\u10E1, \u10DC\u10D0\u10E4\u10D8\u10EA \u10DB\u10E1\u10D0\u10EF\u10E3\u10DA\u10D7\u10D0 \u10E8\u10D4\u10E0\u10E9\u10D4\u10D5\u10D0\u10E1, \u10D9\u10DD\u10DB\u10DE\u10D4\u10E2\u10D4\u10DC\u10EA\u10D8\u10D8\u10E1 \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D0\u10E1 \u10D3\u10D0 \u10D2\u10D0\u10DC\u10DB\u10D4\u10DD\u10E0\u10D4\u10D1\u10D8\u10D7\u10D8 \u10D3\u10D0\u10DC\u10D0\u10E8\u10D0\u10E3\u10DA\u10D8\u10E1 \u10E0\u10D8\u10E1\u10D9\u10D8\u10E1 \u10E8\u10D4\u10E4\u10D0\u10E1\u10D4\u10D1\u10D0\u10E1.","\u10EF\u10D0\u10DC\u10DB\u10E0\u10D7\u10D4\u10DA\u10DD\u10D1\u10D8\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0: \u10EE\u10D4\u10DA\u10E1 \u10E3\u10EC\u10E7\u10DD\u10D1\u10E1 \u10EF\u10D0\u10DC\u10E1\u10D0\u10E6 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1 \u10D3\u10D0 \u10D3\u10D0\u10D0\u10D5\u10D0\u10D3\u10D4\u10D1\u10D4\u10D1\u10D8\u10E1 \u10DE\u10E0\u10D4\u10D5\u10D4\u10DC\u10EA\u10D8\u10D0\u10E1. \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E5\u10EA\u10D4\u10D5\u10D8\u10E1 \u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10DB\u10DD\u10D3\u10D4\u10DA\u10D4\u10D1\u10E1 (\u10EA\u10D5\u10DA\u10D8\u10DA\u10D4\u10D1\u10D8\u10E1 \u10D4\u10E2\u10D0\u10DE\u10D4\u10D1\u10D8), \u10E1\u10D0\u10DB\u10D4\u10D3\u10D8\u10EA\u10D8\u10DC\u10DD \u10DB\u10D9\u10E3\u10E0\u10DC\u10D0\u10DA\u10DD\u10D1\u10D8\u10E1\u10D0\u10D3\u10DB\u10D8 \u10DB\u10D8\u10DB\u10D3\u10D4\u10D5\u10E0\u10DD\u10D1\u10D0\u10E1, \u10E5\u10E0\u10DD\u10DC\u10D8\u10D9\u10E3\u10DA\u10D8 \u10E2\u10D9\u10D8\u10D5\u10D8\u10DA\u10D8\u10E1 \u10DB\u10D0\u10E0\u10D7\u10D5\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10E1\u10EE\u10D4\u10E3\u10DA\u10D8\u10E1\u10D0 \u10D3\u10D0 \u10D2\u10DD\u10DC\u10D4\u10D1\u10D8\u10E1 \u10D9\u10D0\u10D5\u10E8\u10D8\u10E0\u10E1.","\u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0 (\u10E1\u10D4\u10DA\u10D8\u10D2\u10DB\u10D0\u10DC\u10D8): \u10DB\u10D4\u10EA\u10DC\u10D8\u10D4\u10E0\u10E3\u10DA\u10D8 \u10E8\u10D4\u10E1\u10EC\u10D0\u10D5\u10DA\u10D0 \u10D8\u10DB\u10D8\u10E1\u10D0, \u10D7\u10E3 \u10E0\u10D0 \u10EE\u10D3\u10D8\u10E1 \u10EA\u10EE\u10DD\u10D5\u10E0\u10D4\u10D1\u10D0\u10E1 \u10E6\u10D8\u10E0\u10D4\u10D1\u10E3\u10DA\u10E1. \u10E4\u10DD\u10D9\u10E3\u10E1\u10D8\u10E0\u10D3\u10D4\u10D1\u10D0 \u10EB\u10DA\u10D8\u10D4\u10E0 \u10DB\u10EE\u10D0\u10E0\u10D4\u10D4\u10D1\u10D6\u10D4, \u10E1\u10D0\u10D7\u10DC\u10DD\u10D4\u10D1\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10DD\u10DE\u10E2\u10D8\u10DB\u10D0\u10DA\u10E3\u10E0 \u10E4\u10E3\u10DC\u10E5\u10EA\u10D8\u10DD\u10DC\u10D8\u10E0\u10D4\u10D1\u10D0\u10D6\u10D4, \u10D5\u10D8\u10D3\u10E0\u10D4 \u10DE\u10D0\u10D7\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0\u10D6\u10D4. \u10EB\u10D8\u10E0\u10D8\u10D7\u10D0\u10D3\u10D8 \u10EA\u10DC\u10D4\u10D1\u10D4\u10D1\u10D8\u10D0: \u10DC\u10D0\u10D9\u10D0\u10D3\u10D8 (\u10E9\u10D8\u10E5\u10E1\u10D4\u10DC\u10E2\u10DB\u10D8\u10F0\u10D0\u10D8), \u10E1\u10D8\u10DB\u10E2\u10D9\u10D8\u10EA\u10D4 (\u10D3\u10D0\u10E5\u10D5\u10DD\u10E0\u10D7\u10D8), \u10DB\u10D0\u10D3\u10DA\u10D8\u10D4\u10E0\u10D4\u10D1\u10D0 \u10D3\u10D0 \u10EE\u10D0\u10E1\u10D8\u10D0\u10D7\u10D8\u10E1 \u10E1\u10D8\u10EB\u10DA\u10D8\u10D4\u10E0\u10D4.","\u10D2\u10D0\u10E0\u10D4\u10DB\u10DD\u10E1 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0: \u10E0\u10DD\u10D2\u10DD\u10E0 \u10DB\u10DD\u10E5\u10DB\u10D4\u10D3\u10D4\u10D1\u10E1 \u10E4\u10D8\u10D6\u10D8\u10D9\u10E3\u10E0\u10D8 \u10D2\u10D0\u10E0\u10D4\u10DB\u10DD \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1\u10D0 \u10D3\u10D0 \u10D9\u10D4\u10D7\u10D8\u10DA\u10D3\u10E6\u10D4\u10DD\u10D1\u10D0\u10D6\u10D4. \u10DB\u10DD\u10D8\u10EA\u10D0\u10D5\u10E1 \u10E1\u10D0\u10DB\u10E3\u10E8\u10D0\u10DD \u10E1\u10D8\u10D5\u10E0\u10EA\u10D8\u10E1 \u10D3\u10D8\u10D6\u10D0\u10D8\u10DC\u10E1, \u10E3\u10E0\u10D1\u10D0\u10DC\u10E3\u10DA \u10D3\u10D0\u10D2\u10D4\u10D2\u10DB\u10D0\u10E0\u10D4\u10D1\u10D0\u10E1, \u10D2\u10D0\u10D3\u10D0\u10E2\u10D5\u10D8\u10E0\u10D7\u10E3\u10DA\u10DD\u10D1\u10D8\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D4\u10D1\u10E1\u10D0 \u10D3\u10D0 \u10EE\u10DB\u10D0\u10E3\u10E0\u10D8\u10E1 \u10D3\u10D0\u10D1\u10D8\u10DC\u10EB\u10E3\u10E0\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10D5\u10DA\u10D4\u10DC\u10D0\u10E1.","\u10D9\u10E0\u10DD\u10E1-\u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10E3\u10DA\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D0: \u10D8\u10DB\u10D8\u10E1 \u10D2\u10D0\u10D2\u10D4\u10D1\u10D0, \u10D7\u10E3 \u10E0\u10DD\u10D2\u10DD\u10E0 \u10D0\u10E7\u10D0\u10DA\u10D8\u10D1\u10D4\u10D1\u10E1 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D0 \u10E5\u10EA\u10D4\u10D5\u10D0\u10E1, \u10D9\u10DD\u10D2\u10DC\u10D8\u10EA\u10D8\u10D0\u10E1 \u10D3\u10D0 \u10D4\u10DB\u10DD\u10EA\u10D8\u10D4\u10D1\u10E1. \u10D8\u10DC\u10D3\u10D8\u10D5\u10D8\u10D3\u10E3\u10D0\u10DA\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D4\u10D1\u10D8 (\u10D0\u10E8\u10E8, \u10D3\u10D0\u10E1\u10D0\u10D5\u10DA\u10D4\u10D7 \u10D4\u10D5\u10E0\u10DD\u10DE\u10D0) \u10EE\u10D0\u10D6\u10E1 \u10E3\u10E1\u10D5\u10D0\u10DB\u10D4\u10DC \u10DE\u10D8\u10E0\u10DD\u10D5\u10DC\u10E3\u10DA \u10DB\u10D8\u10E6\u10EC\u10D4\u10D5\u10D4\u10D1\u10E1; \u10D9\u10DD\u10DA\u10D4\u10E5\u10E2\u10D8\u10D5\u10D8\u10E1\u10E2\u10E3\u10E0\u10D8 \u10D9\u10E3\u10DA\u10E2\u10E3\u10E0\u10D4\u10D1\u10D8 (\u10D0\u10E6\u10DB\u10DD\u10E1\u10D0\u10D5\u10DA\u10D4\u10D7 \u10D0\u10D6\u10D8\u10D0, \u10DA\u10D0\u10D7\u10D8\u10DC\u10E3\u10E0\u10D8 \u10D0\u10DB\u10D4\u10E0\u10D8\u10D9\u10D0) \u10EE\u10D0\u10D6\u10E1 \u10E3\u10E1\u10D5\u10D0\u10DB\u10D4\u10DC \u10EF\u10D2\u10E3\u10E4\u10E3\u10E0 \u10F0\u10D0\u10E0\u10DB\u10DD\u10DC\u10D8\u10D0\u10E1."],ru:["\u0418\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u0430\u043B\u044C\u043D\u043E-\u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F (\u0418/\u041E) \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F: \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 \u043D\u0430 \u0440\u0430\u0431\u043E\u0447\u0435\u043C \u043C\u0435\u0441\u0442\u0435. \u041E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443 \u043D\u0430\u0439\u043C\u0430 (\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0441\u043E\u0431\u0435\u0441\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u043B\u0443\u0447\u0448\u0435 \u043D\u0435\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0445), \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044E \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F, \u043C\u043E\u0442\u0438\u0432\u0430\u0446\u0438\u044E, \u043B\u0438\u0434\u0435\u0440\u0441\u0442\u0432\u043E, \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u043E\u0439 \u0438 \u0441\u043D\u0438\u0436\u0435\u043D\u0438\u0435 \u0442\u0435\u043A\u0443\u0447\u0435\u0441\u0442\u0438 \u043A\u0430\u0434\u0440\u043E\u0432.","\u041F\u0435\u0434\u0430\u0433\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F: \u0438\u0437\u0443\u0447\u0430\u0435\u0442, \u043A\u0430\u043A \u043B\u044E\u0434\u0438 \u0443\u0447\u0430\u0442\u0441\u044F \u0432 \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0441\u0440\u0435\u0434\u0435. \u041F\u0440\u0438\u043C\u0435\u043D\u044F\u0435\u0442 \u0442\u0435\u043E\u0440\u0438\u0438 \u041F\u0438\u0430\u0436\u0435, \u0412\u044B\u0433\u043E\u0442\u0441\u043A\u043E\u0433\u043E (\u0437\u043E\u043D\u0430 \u0431\u043B\u0438\u0436\u0430\u0439\u0448\u0435\u0433\u043E \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F) \u0438 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u0442\u0438\u043B\u0435\u0439 \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F. \u0423\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0430 \u043D\u0430 \u0440\u043E\u0441\u0442 (\u0414\u0443\u044D\u043A): \u0432\u0435\u0440\u0430 \u0432 \u0442\u043E, \u0447\u0442\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442 \u043F\u043B\u0430\u0441\u0442\u0438\u0447\u0435\u043D, \u0443\u043B\u0443\u0447\u0448\u0430\u0435\u0442 \u0430\u043A\u0430\u0434\u0435\u043C\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0443\u0441\u043F\u0435\u0432\u0430\u0435\u043C\u043E\u0441\u0442\u044C.","\u0421\u0443\u0434\u0435\u0431\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F: \u043F\u0435\u0440\u0435\u0441\u0435\u0447\u0435\u043D\u0438\u0435 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438 \u0438 \u043F\u0440\u0430\u0432\u0430. \u0412\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u043A\u0440\u0438\u043C\u0438\u043D\u0430\u043B\u044C\u043D\u043E\u0435 \u043F\u0440\u043E\u0444\u0438\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435, \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0445 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0438\u0439, \u043E\u0442\u0431\u043E\u0440 \u043F\u0440\u0438\u0441\u044F\u0436\u043D\u044B\u0445, \u043E\u0446\u0435\u043D\u043A\u0443 \u0432\u043C\u0435\u043D\u044F\u0435\u043C\u043E\u0441\u0442\u0438 \u0438 \u043E\u0446\u0435\u043D\u043A\u0443 \u0440\u0438\u0441\u043A\u0430 \u0440\u0435\u0446\u0438\u0434\u0438\u0432\u0430.","\u041F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F: \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u0435\u0442 \u0437\u0434\u043E\u0440\u043E\u0432\u043E\u043C\u0443 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044E \u0438 \u043F\u0440\u0435\u0434\u043E\u0442\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0437\u043D\u0438. \u041E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u043C\u043E\u0434\u0435\u043B\u0438 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F (\u0441\u0442\u0430\u0434\u0438\u0438 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F), \u043F\u0440\u0438\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043B\u0435\u0447\u0435\u043D\u0438\u044E, \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0445\u0440\u043E\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0431\u043E\u043B\u044C\u044E \u0438 \u0441\u0432\u044F\u0437\u044C \u043C\u0435\u0436\u0434\u0443 \u0434\u0443\u0448\u043E\u0439 \u0438 \u0442\u0435\u043B\u043E\u043C.","\u041F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F (\u0421\u0435\u043B\u0438\u0433\u043C\u0430\u043D): \u043D\u0430\u0443\u0447\u043D\u043E\u0435 \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u0436\u0438\u0437\u043D\u044C \u0441\u0442\u043E\u044F\u0449\u0435\u0439. \u041E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0430 \u043D\u0430 \u0441\u0438\u043B\u044C\u043D\u044B\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0434\u043E\u0431\u0440\u043E\u0434\u0435\u0442\u0435\u043B\u0438 \u0438 \u043E\u043F\u0442\u0438\u043C\u0430\u043B\u044C\u043D\u043E\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435, \u0430 \u043D\u0435 \u043D\u0430 \u043F\u0430\u0442\u043E\u043B\u043E\u0433\u0438\u0438. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438: \u043F\u043E\u0442\u043E\u043A (\u0427\u0438\u043A\u0441\u0435\u043D\u0442\u043C\u0438\u0445\u0430\u0439\u0438), \u0442\u0432\u0435\u0440\u0434\u043E\u0441\u0442\u044C \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0430 (\u0414\u0430\u043A\u0432\u043E\u0440\u0442), \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u043D\u043E\u0441\u0442\u044C \u0438 \u0441\u0438\u043B\u044C\u043D\u044B\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438.","\u042D\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F: \u043A\u0430\u043A \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0441\u0440\u0435\u0434\u0430 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0438 \u0431\u043B\u0430\u0433\u043E\u043F\u043E\u043B\u0443\u0447\u0438\u0435. \u0412\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0434\u0438\u0437\u0430\u0439\u043D \u0440\u0430\u0431\u043E\u0447\u0435\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430, \u0433\u043E\u0440\u043E\u0434\u0441\u043A\u043E\u0435 \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435, \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u0441\u043A\u0443\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0438 \u0432\u043B\u0438\u044F\u043D\u0438\u0435 \u0448\u0443\u043C\u043E\u0432\u043E\u0433\u043E \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F.","\u041A\u0440\u043E\u0441\u0441-\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u0430\u044F \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u044F: \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u0430 \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0438 \u044D\u043C\u043E\u0446\u0438\u0438. \u0418\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B (\u0421\u0428\u0410, \u0417\u0430\u043F\u0430\u0434\u043D\u0430\u044F \u0415\u0432\u0440\u043E\u043F\u0430) \u043F\u043E\u0434\u0447\u0435\u0440\u043A\u0438\u0432\u0430\u044E\u0442 \u043B\u0438\u0447\u043D\u044B\u0435 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F; \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u0438\u0441\u0442\u0441\u043A\u0438\u0435 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B (\u0412\u043E\u0441\u0442\u043E\u0447\u043D\u0430\u044F \u0410\u0437\u0438\u044F, \u041B\u0430\u0442\u0438\u043D\u0441\u043A\u0430\u044F \u0410\u043C\u0435\u0440\u0438\u043A\u0430) \u043F\u043E\u0434\u0447\u0435\u0440\u043A\u0438\u0432\u0430\u044E\u0442 \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u0443\u044E \u0433\u0430\u0440\u043C\u043E\u043D\u0438\u044E."],hy:["\u0531\u0580\u0564\u0575\u0578\u0582\u0576\u0561\u0562\u0565\u0580\u0561\u056F\u0561\u0576-\u056F\u0561\u0566\u0574\u0561\u056F\u0565\u0580\u057A\u0579\u0561\u056F\u0561\u0576 (I/O) \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u056F\u056B\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0561\u056F\u0561\u0576 \u057D\u056F\u0566\u0562\u0578\u0582\u0576\u0584\u0576\u0565\u0580 \u0561\u0577\u056D\u0561\u057F\u0561\u057E\u0561\u0575\u0580\u0578\u0582\u0574: \u0538\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u0568\u0576\u0564\u0578\u0582\u0576\u0578\u0582\u0574\u0568 (\u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0561\u0575\u056B\u0576 \u0570\u0561\u0580\u0581\u0561\u0566\u0580\u0578\u0582\u0575\u0581\u0576\u0565\u0580\u0568 \u0563\u0565\u0580\u0561\u0566\u0561\u0576\u0581\u0578\u0582\u0574 \u0565\u0576 \u0578\u0579 \u056F\u0561\u057C\u0578\u0582\u0581\u057E\u0561\u056E\u0584\u0561\u0575\u056B\u0576\u0576\u0565\u0580\u056B\u0576), \u057E\u0565\u0580\u0561\u057A\u0561\u057F\u0580\u0561\u057D\u057F\u0574\u0561\u0576 \u0576\u0561\u056D\u0561\u0563\u056E\u0578\u0582\u0574\u0568, \u0574\u0578\u057F\u056B\u057E\u0561\u0581\u056B\u0561\u0576, \u0561\u057C\u0561\u057B\u0576\u0578\u0580\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u056B \u0562\u0561\u057E\u0561\u0580\u0561\u0580\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0561\u0577\u056D\u0561\u057F\u0561\u056F\u056B\u0581\u0576\u0565\u0580\u056B \u0570\u0578\u057D\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0576\u057E\u0561\u0566\u0565\u0581\u0578\u0582\u0574\u0568:","\u053F\u0580\u0569\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0574 \u0567, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0565\u0576 \u0574\u0561\u0580\u0564\u056B\u056F \u057D\u0578\u057E\u0578\u0580\u0578\u0582\u0574 \u056F\u0580\u0569\u0561\u056F\u0561\u0576 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0578\u0582\u0574: \u053F\u056B\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u054A\u056B\u0561\u056A\u0565\u056B \u057F\u0565\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u054E\u056B\u0563\u0578\u057F\u057D\u056F\u056B\u0576 (\u0574\u0565\u0580\u0571\u0561\u056F\u0561 \u0566\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576 \u0563\u0578\u057F\u056B\u0576) \u0587 \u0578\u0582\u057D\u0578\u0582\u0581\u0574\u0561\u0576 \u0578\u0573\u0565\u0580\u0568: \u0536\u0561\u0580\u0563\u0561\u0581\u0574\u0561\u0576 \u0574\u057F\u0561\u056E\u0565\u056C\u0561\u056F\u0565\u0580\u057A (\u0534\u0578\u0582\u0565\u0584): \u056B\u0576\u057F\u0565\u056C\u0565\u056F\u057F\u056B \u0583\u0578\u0583\u0578\u056D\u0561\u056F\u0561\u0576 \u056C\u056B\u0576\u0565\u056C\u0578\u0582 \u0570\u0561\u057E\u0561\u057F\u0568 \u0562\u0561\u0580\u0565\u056C\u0561\u057E\u0578\u0582\u0574 \u0567 \u0561\u056F\u0561\u0564\u0565\u0574\u056B\u0561\u056F\u0561\u0576 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u0568:","\u0534\u0561\u057F\u0561\u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0587 \u056B\u0580\u0561\u057E\u0578\u0582\u0576\u0584\u056B \u0570\u0561\u057F\u0578\u0582\u0574: \u0546\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0584\u0580\u0565\u0561\u056F\u0561\u0576 \u057A\u0580\u0578\u0586\u056B\u056C\u0561\u057E\u0578\u0580\u0578\u0582\u0574, \u0561\u056F\u0561\u0576\u0561\u057F\u0565\u057D\u0576\u0565\u0580\u056B \u0581\u0578\u0582\u0581\u0574\u0578\u0582\u0576\u0584\u0576\u0565\u0580\u056B \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u0565\u0580\u0564\u057E\u0575\u0561\u056C \u0561\u057F\u0565\u0576\u0561\u056F\u0561\u056C\u0576\u0565\u0580\u056B \u0568\u0576\u057F\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576, \u056B\u0580\u0561\u057E\u0561\u057D\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574 \u0587 \u056F\u0580\u056F\u0576\u0561\u056F\u056B \u0570\u0561\u0576\u0581\u0561\u0563\u0578\u0580\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u057C\u056B\u057D\u056F\u056B \u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574:","\u0531\u057C\u0578\u0572\u057B\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u056D\u0569\u0561\u0576\u0578\u0582\u0574 \u0567 \u0561\u057C\u0578\u0572\u057B \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568 \u0587 \u056F\u0561\u0576\u056D\u0578\u0582\u0574 \u0570\u056B\u057E\u0561\u0576\u0564\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u0568: \u0538\u0576\u0564\u0563\u0580\u056F\u0578\u0582\u0574 \u0567 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0561\u0576 \u0574\u0578\u0564\u0565\u056C\u0576\u0565\u0580\u0568 (\u0583\u0578\u0583\u0578\u056D\u0578\u0582\u0569\u0575\u0561\u0576 \u0583\u0578\u0582\u056C\u0565\u0580), \u0562\u056A\u0577\u056F\u0561\u056F\u0561\u0576 \u0562\u0578\u0582\u056A\u0574\u0561\u0576\u0568 \u0570\u0565\u057F\u0587\u0565\u056C\u0568, \u0584\u0580\u0578\u0576\u056B\u056F \u0581\u0561\u057E\u056B \u056F\u0561\u057C\u0561\u057E\u0561\u0580\u0578\u0582\u0574\u0568 \u0587 \u0574\u056B\u057F\u0584-\u0574\u0561\u0580\u0574\u056B\u0576 \u056F\u0561\u057A\u0568:","\u0534\u0580\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u054D\u0565\u056C\u056B\u0563\u0574\u0561\u0576). \u0563\u056B\u057F\u0561\u056F\u0561\u0576 \u0578\u0582\u057D\u0578\u0582\u0574\u0576\u0561\u057D\u056B\u0580\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0561\u0575\u0576 \u0574\u0561\u057D\u056B\u0576, \u0569\u0565 \u056B\u0576\u0579\u0576 \u0567 \u056F\u0575\u0561\u0576\u0584\u0576 \u0561\u0580\u056A\u0565\u0584\u0561\u057E\u0578\u0580 \u0564\u0561\u0580\u0571\u0576\u0578\u0582\u0574: \u053F\u0565\u0576\u057F\u0580\u0578\u0576\u0561\u0576\u0578\u0582\u0574 \u0567 \u0578\u0582\u056A\u0565\u0572 \u056F\u0578\u0572\u0574\u0565\u0580\u056B, \u0561\u057C\u0561\u0584\u056B\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u056B \u0587 \u0585\u057A\u057F\u056B\u0574\u0561\u056C \u0563\u0578\u0580\u056E\u0578\u0582\u0576\u0565\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561, \u0561\u0575\u056C \u0578\u0579 \u0569\u0565 \u057A\u0561\u0569\u0578\u056C\u0578\u0563\u056B\u0561\u0575\u056B: \u0540\u056B\u0574\u0576\u0561\u056F\u0561\u0576 \u0570\u0561\u057D\u056F\u0561\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576\u0565\u0580\u055D \u0570\u0578\u057D\u0584 (\u0549\u056B\u056F\u057D\u0565\u0576\u0569\u0574\u056B\u0570\u0561\u0575\u056B), \u057F\u0578\u056F\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576 (\u0534\u0561\u0584\u057E\u0578\u0580\u0569), \u0565\u0580\u0561\u056D\u057F\u0561\u0563\u056B\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576 \u0587 \u0562\u0576\u0561\u057E\u0578\u0580\u0578\u0582\u0569\u0575\u0561\u0576 \u0578\u0582\u056A\u0565\u0572 \u056F\u0578\u0572\u0574\u0565\u0580:","\u0537\u056F\u0578\u056C\u0578\u0563\u056B\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u0586\u056B\u0566\u056B\u056F\u0561\u056F\u0561\u0576 \u0574\u056B\u057B\u0561\u057E\u0561\u0575\u0580\u0576 \u0561\u0566\u0564\u0578\u0582\u0574 \u057E\u0561\u0580\u0584\u0561\u0563\u056E\u056B \u0587 \u0562\u0561\u0580\u0565\u056F\u0565\u0581\u0578\u0582\u0569\u0575\u0561\u0576 \u057E\u0580\u0561: \u0546\u0565\u0580\u0561\u057C\u0578\u0582\u0574 \u0567 \u0561\u0577\u056D\u0561\u057F\u0561\u0576\u0584\u0561\u0575\u056B\u0576 \u057F\u0561\u0580\u0561\u056E\u0584\u056B \u0564\u056B\u0566\u0561\u0575\u0576\u0568, \u0584\u0561\u0572\u0561\u0584\u0561\u0577\u056B\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568, \u0563\u0565\u0580\u0562\u0576\u0561\u056F\u0565\u0581\u0574\u0561\u0576 \u0570\u0565\u057F\u0587\u0561\u0576\u0584\u0576\u0565\u0580\u0568 \u0587 \u0561\u0572\u0574\u0578\u0582\u056F\u056B \u0561\u0572\u057F\u0578\u057F\u057E\u0561\u056E\u0578\u0582\u0569\u0575\u0561\u0576 \u0561\u0566\u0564\u0565\u0581\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:","\u0544\u056B\u057B\u0574\u0577\u0561\u056F\u0578\u0582\u0569\u0561\u0575\u056B\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576. \u0570\u0561\u057D\u056F\u0561\u0576\u0561\u056C, \u0569\u0565 \u056B\u0576\u0579\u057A\u0565\u057D \u0567 \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u0568 \u0571\u0587\u0561\u057E\u0578\u0580\u0578\u0582\u0574 \u057E\u0561\u0580\u0584\u0561\u0563\u056B\u056E\u0568, \u0573\u0561\u0576\u0561\u0579\u0578\u0572\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0587 \u0570\u0578\u0582\u0575\u0566\u0565\u0580\u0568: \u0531\u0576\u0570\u0561\u057F\u0561\u057A\u0561\u0577\u057F\u0561\u056F\u0561\u0576 \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u0576\u0565\u0580\u0568 (\u0531\u0544\u0546, \u0531\u0580\u0587\u0574\u057F\u0575\u0561\u0576 \u0535\u057E\u0580\u0578\u057A\u0561) \u0568\u0576\u0564\u0563\u056E\u0578\u0582\u0574 \u0565\u0576 \u0561\u0576\u0571\u0576\u0561\u056F\u0561\u0576 \u0576\u057E\u0561\u0573\u0578\u0582\u0574\u0576\u0565\u0580\u0568, \u056F\u0578\u056C\u0565\u056F\u057F\u056B\u057E\u056B\u057D\u057F\u0561\u056F\u0561\u0576 \u0574\u0577\u0561\u056F\u0578\u0582\u0575\u0569\u0576\u0565\u0580\u0568 (\u0531\u0580\u0587\u0565\u056C\u0575\u0561\u0576 \u0531\u057D\u056B\u0561, \u053C\u0561\u057F\u056B\u0576\u0561\u056F\u0561\u0576 \u0531\u0574\u0565\u0580\u056B\u056F\u0561) \u0577\u0565\u0577\u057F\u0578\u0582\u0574 \u0565\u0576 \u056D\u0574\u0562\u0561\u0575\u056B\u0576 \u0576\u0565\u0580\u0564\u0561\u0577\u0576\u0561\u056F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568:"],az:["S\u0259naye-T\u0259\u015Fkilati (I/O) Psixologiya: psixoloji prinsipl\u0259rin i\u015F yerin\u0259 t\u0259tbiqi. \u0130\u015F\u0259 q\u0259bul (strukturla\u015Fd\u0131r\u0131lm\u0131\u015F m\xFCsahib\u0259l\u0259r strukturla\u015Fd\u0131r\u0131lmam\u0131\u015Fdan \xFCst\xFCnd\xFCr), t\u0259limin dizayn\u0131, motivasiya, liderlik, i\u015F m\u0259mnuniyy\u0259ti v\u0259 kadr d\xF6vriyy\u0259sinin azald\u0131lmas\u0131n\u0131 \u0259hat\u0259 edir.","T\u0259hsil Psixologiyas\u0131: insanlar\u0131n t\u0259hsil m\xFChitind\u0259 nec\u0259 \xF6yr\u0259ndikl\u0259rini \xF6yr\u0259nir. Pyaejeni, V\u0131qotskini (yax\u0131n inki\u015Faf m\u0259rh\u0259l\u0259si) v\u0259 \xF6yr\u0259nm\u0259 \xFCslublar\u0131 \xFCzr\u0259 t\u0259dqiqatlar\u0131 t\u0259tbiq edir. \u0130nki\u015Faf d\xFC\u015F\xFCnc\u0259si (Dweck): z\u0259kan\u0131n d\u0259yi\u015F\u0259 bil\u0259c\u0259yin\u0259 inanmaq akademik performans\u0131 yax\u015F\u0131la\u015Fd\u0131r\u0131r.","M\u0259hk\u0259m\u0259 Psixologiyas\u0131: psixologiya v\u0259 h\xFCququn k\u0259si\u015Fm\u0259si. Cinay\u0259t profili, \u015Fahid ifad\u0259l\u0259rinin t\u0259dqiqi, andl\u0131lar hey\u0259tinin se\xE7imi, s\u0259lahiyy\u0259t qiym\u0259tl\u0259ndirm\u0259l\u0259ri v\u0259 t\u0259krar cinay\u0259t riskinin qiym\u0259tl\u0259ndirilm\u0259sini ehtiva edir.","Sa\u011Flaml\u0131q Psixologiyas\u0131: sa\u011Flam davran\u0131\u015Flar\u0131 t\u0259\u015Fviq edir v\u0259 x\u0259st\u0259likl\u0259rin qar\u015F\u0131s\u0131n\u0131 al\u0131r. Davran\u0131\u015F d\u0259yi\u015Fikliyi modell\u0259ri (d\u0259yi\u015Fm\u0259 m\u0259rh\u0259l\u0259l\u0259ri), tibbi m\xFCalic\u0259y\u0259 riay\u0259t etm\u0259, xroniki a\u011Fr\u0131n\u0131n idar\u0259 edilm\u0259si v\u0259 a\u011F\u0131l-b\u0259d\u0259n \u0259laq\u0259sini \u0259hat\u0259 edir.","Pozitiv Psixologiya (Seligman): h\u0259yat\u0131 ya\u015Fama\u011Fa d\u0259y\u0259r ed\u0259n \u015Feyl\u0259rin elmi \xF6yr\u0259nilm\u0259si. Patologiyadan daha \xE7ox g\xFCcl\xFC t\u0259r\u0259fl\u0259r\u0259, f\u0259zil\u0259tl\u0259r\u0259 v\u0259 optimal f\u0259aliyy\u0259t\u0259 diqq\u0259t yetirir. \u018Fsas anlay\u0131\u015Flar: ax\u0131n (Csikszentmihalyi), d\xF6z\xFCml\xFCl\xFCk (Duckworth), minn\u0259tdarl\u0131q v\u0259 xarakter g\xFCc\xFC.","\u018Ftraf m\xFChit psixologiyas\u0131: fiziki m\xFChitin davran\u0131\u015Fa v\u0259 rifaha nec\u0259 t\u0259sir etdiyi. \u0130\u015F sah\u0259sinin dizayn\u0131, \u015F\u0259h\u0259r planla\u015Fd\u0131rmas\u0131, izdiham\u0131n t\u0259sirl\u0259ri v\u0259 s\u0259s-k\xFCy \xE7irkl\u0259nm\u0259sinin t\u0259sirl\u0259rini \u0259hat\u0259 edir.","M\u0259d\u0259niyy\u0259tl\u0259raras\u0131 psixologiya: m\u0259d\u0259niyy\u0259tin davran\u0131\u015F\u0131, idrak\u0131 v\u0259 duy\u011Fular\u0131 nec\u0259 formala\u015Fd\u0131rd\u0131\u011F\u0131n\u0131 anlamaq. F\u0259rdi m\u0259d\u0259niyy\u0259tl\u0259r (AB\u015E, Q\u0259rbi Avropa) \u015F\u0259xsi nailiyy\u0259tl\u0259ri vur\u011Fulay\u0131r; kollektivist m\u0259d\u0259niyy\u0259tl\u0259r (\u015E\u0259rqi Asiya, Lat\u0131n Amerikas\u0131) qrup harmoniyas\u0131n\u0131 vur\u011Fulay\u0131r."]},funFact:{en:'The "IKEA effect" (discovered by behavioral economists using psychological research) shows that people value things they built themselves 63% more than identical pre-built items \u2014 even when their creation is objectively worse!',ka:"\u201EIKEA-\u10E1 \u10D4\u10E4\u10D4\u10E5\u10E2\u10D8\u201C \u10D0\u10E9\u10D5\u10D4\u10DC\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB \u10D0\u10D3\u10D0\u10DB\u10D8\u10D0\u10DC\u10D4\u10D1\u10D8 63%-\u10D8\u10D7 \u10DB\u10D4\u10E2\u10D0\u10D3 \u10D0\u10E4\u10D0\u10E1\u10D4\u10D1\u10D4\u10DC \u10D8\u10DB \u10DC\u10D8\u10D5\u10D7\u10D4\u10D1\u10E1, \u10E0\u10DD\u10DB\u10DA\u10D4\u10D1\u10D8\u10EA \u10D7\u10D0\u10D5\u10D0\u10D3 \u10D0\u10D0\u10EC\u10E7\u10D5\u10D4\u10E1.",ru:"\xAB\u042D\u0444\u0444\u0435\u043A\u0442 IKEA\xBB \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u043B\u044E\u0434\u0438 \u0446\u0435\u043D\u044F\u0442 \u0432\u0435\u0449\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u043D\u0438 \u0441\u043E\u0431\u0440\u0430\u043B\u0438 \u0441\u0430\u043C\u0438, \u043D\u0430 63% \u0431\u043E\u043B\u044C\u0448\u0435, \u0447\u0435\u043C \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u044B\u0435 \u0433\u043E\u0442\u043E\u0432\u044B\u0435 \u0438\u0437\u0434\u0435\u043B\u0438\u044F.",hy:"\xABIKEA-\u056B \u0567\u0586\u0565\u056F\u057F\u0568\xBB \u0581\u0578\u0582\u0575\u0581 \u0567 \u057F\u0561\u056C\u056B\u057D, \u0578\u0580 \u0574\u0561\u0580\u0564\u056B\u056F 63%-\u0578\u057E \u0561\u057E\u0565\u056C\u056B \u0562\u0561\u0580\u0571\u0580 \u0565\u0576 \u0563\u0576\u0561\u0570\u0561\u057F\u0578\u0582\u0574 \u056B\u0580\u0565\u0576\u0581 \u0571\u0565\u057C\u0584\u0578\u057E \u057A\u0561\u057F\u0580\u0561\u057D\u057F\u0561\u056E \u056B\u0580\u0565\u0580\u0568:",az:'"IKEA effekti" g\xF6st\u0259rir ki, insanlar \xF6zl\u0259rinin d\xFCz\u0259ltdikl\u0259ri \u0259\u015Fyalara haz\u0131r olanlardan 63% daha \xE7ox d\u0259y\u0259r verirl\u0259r.'},realWorld:{en:`Seligman's positive psychology research is used by the U.S. Army's Comprehensive Soldier Fitness program, training 1.1 million soldiers in resilience skills. Schools worldwide now teach "character strengths" and "growth mindset" as part of their curriculum.`,ka:"\u10E1\u10D4\u10DA\u10D8\u10D2\u10DB\u10D0\u10DC\u10D8\u10E1 \u10DE\u10DD\u10D6\u10D8\u10E2\u10D8\u10E3\u10E0\u10D8 \u10E4\u10E1\u10D8\u10E5\u10DD\u10DA\u10DD\u10D2\u10D8\u10D8\u10E1 \u10D9\u10D5\u10DA\u10D4\u10D5\u10D0\u10E1 \u10D0\u10E8\u10E8-\u10E1 \u10D0\u10E0\u10DB\u10D8\u10D0 \u10D8\u10E7\u10D4\u10DC\u10D4\u10D1\u10E1 \u10EF\u10D0\u10E0\u10D8\u10E1\u10D9\u10D0\u10EA\u10D4\u10D1\u10D8\u10E1 \u10D2\u10D0\u10DB\u10EB\u10DA\u10D4\u10DD\u10D1\u10D8\u10E1 \u10D2\u10D0\u10E1\u10D0\u10E3\u10DB\u10EF\u10DD\u10D1\u10D4\u10E1\u10D4\u10D1\u10DA\u10D0\u10D3.",ru:"\u0418\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u043E\u0439 \u043F\u0441\u0438\u0445\u043E\u043B\u043E\u0433\u0438\u0438 \u0421\u0435\u043B\u0438\u0433\u043C\u0430\u043D\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0430\u0440\u043C\u0438\u0435\u0439 \u0421\u0428\u0410 \u0434\u043B\u044F \u043F\u043E\u0432\u044B\u0448\u0435\u043D\u0438\u044F \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u0438 \u0441\u043E\u043B\u0434\u0430\u0442.",hy:"\u054D\u0565\u056C\u056B\u0563\u0574\u0561\u0576\u056B \u0564\u0580\u0561\u056F\u0561\u0576 \u0570\u0578\u0563\u0565\u0562\u0561\u0576\u0578\u0582\u0569\u0575\u0561\u0576 \u0570\u0565\u057F\u0561\u0566\u0578\u057F\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0576 \u0585\u0563\u057F\u0561\u0563\u0578\u0580\u056E\u057E\u0578\u0582\u0574 \u0567 \u0531\u0544\u0546 \u0562\u0561\u0576\u0561\u056F\u056B \u056F\u0578\u0572\u0574\u056B\u0581 \u0566\u056B\u0576\u057E\u0578\u0580\u0576\u0565\u0580\u056B \u0573\u056F\u0578\u0582\u0576\u0578\u0582\u0569\u0575\u0578\u0582\u0576\u0568 \u0562\u0561\u0580\u0571\u0580\u0561\u0581\u0576\u0565\u056C\u0578\u0582 \u0570\u0561\u0574\u0561\u0580:",az:"Seligman-\u0131n pozitiv psixologiya ara\u015Fd\u0131rmas\u0131 AB\u015E ordusu t\u0259r\u0259find\u0259n \u0259sg\u0259rl\u0259rin d\xF6z\xFCml\xFCl\xFCk bacar\u0131qlar\u0131n\u0131 art\u0131rmaq \xFC\xE7\xFCn istifad\u0259 olunur."}}};function s(e,n,r){let i=t[e];if(!i)return"";let a=i[n];return a[r]??a.en}export{s as a};
